insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('がんばることも\\n必要だけど\\nお休みも大切だよね', 1, 1, 3, 0, 0, 100202, 2, 93);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい～♪\\n騎士クンは\\nこういうのって好き？', 1, 1, 3, 0, 0, 100202, 3, 94);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦う前にもこうやって\\n落ち着けたら\\nいいのに', 1, 1, 3, 0, 0, 100202, 4, 95);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…！\\nよ、良かったら\\n一緒に…！', 1, 1, 3, 0, 0, 100202, 5, 96);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンと一緒に\\n冒険するなら\\n体力がないと…！', 1, 1, 3, 0, 0, 100202, 6, 97);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近服のサイズが\\n合わないんだけど…\\n食べ過ぎなのかな？', 1, 1, 3, 0, 0, 100202, 7, 98);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…やっぱり\\n月刊恋愛指南は\\nためになる…', 1, 1, 3, 0, 0, 100202, 8, 99);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('装備の手入れでも\\nしようかな…', 1, 1, 1, 0, 0, 100301, 1, 101);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次に鍛えるべきは\\n肉体面か精神面か\\nどちらにしよう…？', 1, 1, 1, 0, 0, 100301, 2, 102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ツムギが作ってくれた\\nこの服…一体\\nいつサイズを…？', 1, 1, 1, 0, 0, 100301, 3, 103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間なんていらない\\nそう思ってた頃も\\nあったな…', 1, 1, 1, 0, 0, 100301, 4, 104);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('考えごとをしていると\\nつい部屋中を\\n歩いてしまうな', 1, 1, 1, 0, 0, 100301, 5, 105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼は\\nどこまで強くなるのか\\n私も負けられないな', 4, 1, 1, 0, 0, 100301, 101, 106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が一本を取られる\\nなんてね…願い事は\\nもう決まったのかな？', 8, 1, 1, 0, 0, 100301, 102, 107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、キミだったのか\\n人の気配がしたから\\n誰かと思ったよ', 1, 1, 2, 0, 0, 100301, 1, 108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('斬りかかるつもりなら\\nちゃんとかかってきて\\n…呼んだだけ？', 1, 1, 2, 0, 0, 100301, 2, 109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに？\u3000私に相談？\\n戦いについてなら\\n喜んで', 1, 1, 2, 0, 0, 100301, 3, 110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今のが突き？\\n軽い！\u3000もっと鋭く！\\nさあ、もう一回！', 1, 1, 2, 0, 0, 100301, 4, 111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっ！\u3000ど、どこを\\n触ってるの！？\\n…油断した', 4, 1, 2, 0, 0, 100301, 101, 112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミにはこれからも\\n私のそばに…\\nいや、なんでもない', 8, 1, 2, 0, 0, 100301, 102, 113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう\\n今日も充実した\\n一日にしていこう', 1, 1, 2, 0, 1, 100301, 1, 114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ\\nお茶の時間か\\nキミも一緒にどう？', 1, 1, 2, 0, 2, 100301, 2, 115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遅くまで大変だね\\nまだ仕事があるなら\\n手伝おうか？', 1, 1, 2, 0, 3, 100301, 3, 116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦いを経てもなお\\n美しくあるように…\\nこれでよし♪', 1, 1, 3, 0, 0, 100301, 1, 117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦ってばかりで\\n休まないと、また\\nユイに怒られるな', 1, 1, 3, 0, 0, 100301, 2, 118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒヨリみたいに\\n練習相手に…\\nいや、やめておこう', 1, 1, 3, 0, 0, 100301, 3, 119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはいい…\\n戦いの前の精神統一に\\nもってこいじゃないか', 1, 1, 3, 0, 0, 100301, 4, 120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時々は落ち着いた\\n時間を過ごすのも\\n悪くない…', 1, 1, 3, 0, 0, 100301, 5, 121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼に負けないよう\\n私も更に強くなろう\\n共に戦うために！', 1, 1, 3, 0, 0, 100301, 6, 122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事は大切だけど\\n食べ過ぎには\\n注意しておこう…', 1, 1, 3, 0, 0, 100301, 7, 123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユイ…！\\nこ、こんな本を\\n読んでいたのか…！', 1, 1, 3, 0, 0, 100301, 8, 124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海だけじゃなくて\\n川でも釣りがしたいな\\n道具も新調しよう', 1, 1, 1, 0, 0, 100302, 1, 126);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ツムギが作ってくれた\\nこの服…一体\\nいつサイズを…？', 1, 1, 1, 0, 0, 100302, 2, 127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼は\\nどこまで強くなるのか\\n私も負けられないな', 1, 1, 1, 0, 0, 100302, 3, 128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ修行の\\n内容を新しくしよう\\nより厳しいものにね', 1, 1, 1, 0, 0, 100302, 4, 129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強くなって…誰にも\\n妨げられない自由な\\n生き方がしたい', 1, 1, 1, 0, 0, 100302, 5, 130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさか風邪を引くとは\\n彼の看病のおかげで\\nすっかり良く\\nなったけど', 8, 1, 1, 0, 0, 100302, 101, 131);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が一本を取られる\\nなんてね…願い事は\\nもう決まったのかな？', 8, 1, 1, 0, 0, 100302, 102, 132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\nなんでもない？\\nそれなら良かった', 1, 1, 2, 0, 0, 100302, 1, 133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんまり突っつくと\\nお返しするよ？\\n覚悟は出来てる？', 1, 1, 2, 0, 0, 100302, 2, 134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、今度また\\n釣りに行かない？\\n大きいのを狙おう', 1, 1, 2, 0, 0, 100302, 3, 135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('修行がしたいの？\\nそれを早く言ってよ\\nすぐに出発しよう！', 1, 1, 2, 0, 0, 100302, 4, 136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひょっとして\\n今のも一本だなんて\\n言わないよね？', 8, 1, 2, 0, 0, 100302, 101, 137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミにはこれからも\\n私のそばに…\\nいや、なんでもない', 8, 1, 2, 0, 0, 100302, 102, 138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は仕事？\\nそれとも修行？\\n良ければ付き合うよ', 1, 1, 2, 0, 1, 100302, 1, 139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休息も時には\\n必要だと、仲間から\\n教わったよ', 1, 1, 2, 0, 2, 100302, 2, 140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遅くまで大変だね\\nまだ仕事があるなら\\n手伝おうか？', 1, 1, 2, 0, 3, 100302, 3, 141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('髪の長さを少し\\n変えてみようかな…\\nわ、私は何を…！', 1, 1, 3, 0, 0, 100302, 1, 142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休息があってこそ\\n万全な状態で\\n戦えるんだ', 1, 1, 3, 0, 0, 100302, 2, 143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒヨリみたいに\\n練習相手に…\\nいや、やめておこう', 1, 1, 3, 0, 0, 100302, 3, 144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体と同様に\\n心もほぐれるね…\\nはぁ…', 1, 1, 3, 0, 0, 100302, 4, 145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休む時は休む\\nヒヨリもそろそろ\\n覚えて欲しいな…', 1, 1, 3, 0, 0, 100302, 5, 146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼に負けないよう\\n私も更に強くなろう\\n共に戦うために！', 1, 1, 3, 0, 0, 100302, 6, 147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('修行のせいか\\n最近食べる量が\\n増えてきたような…', 1, 1, 3, 0, 0, 100302, 7, 148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユイ…！\\nこ、こんな本を\\n読んでいたのか…！', 1, 1, 3, 0, 0, 100302, 8, 149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お宝の予感！\\n部屋中を\\n探検しちゃうぞ～', 1, 1, 1, 0, 0, 100401, 1, 151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落とし穴…どこに\\n作ったんだっけ？', 1, 1, 1, 0, 0, 100401, 2, 152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うえ～ん！\\n…嘘泣きしたら\\n相手は油断するかな', 1, 1, 1, 0, 0, 100401, 3, 153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハニートラップって\\nすごく甘いお菓子で\\nイタズラするのかな？', 1, 1, 1, 0, 0, 100401, 4, 154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かくれんぼする人\\nこの指、と～まれ！', 1, 1, 1, 0, 0, 100401, 5, 155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギ以外の人に\\nイタズラされちゃ\\nダメだよ！', 4, 1, 1, 0, 0, 100401, 101, 156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギと遊ぶ？\\nミソギに遊ばれる？', 8, 1, 1, 0, 0, 100401, 102, 157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいこと思いついた！\\nい、イタズラとかじゃ\\nないよ～', 1, 1, 2, 0, 0, 100401, 1, 158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うわっ！？\\n\u3000にいちゃんが、\\nミソギにイタズラ？', 1, 1, 2, 0, 0, 100401, 2, 159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんの\\n通りそうなところに\\nバナナの皮を…', 1, 1, 2, 0, 0, 100401, 3, 160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんのオデコと\\nホッペと鼻と目と耳に\\n落書きを…', 1, 1, 2, 0, 0, 100401, 4, 161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ、ミソギ探検隊の\\n基地にしようよ！', 4, 1, 2, 0, 0, 100401, 101, 162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だ～れだ…って？\\nにいちゃんの声くらい\\nわかるよ！\\n大好きだもん♪', 8, 1, 2, 0, 0, 100401, 102, 163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃん、おはよ！\\n目覚まし時計を\\n止めておいたのに、\\nよく起きられたね～♪', 1, 1, 2, 0, 1, 100401, 1, 164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんが\\n昼寝したら、\\nイタズラし放題♪', 1, 1, 2, 0, 2, 100401, 2, 165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の探検も\\nおもしろそう！\\nねぇ出かけちゃダメ？', 1, 1, 2, 0, 3, 100401, 3, 166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラには\\nお色気も必要…\\nうん、完璧！', 1, 1, 3, 0, 0, 100401, 1, 167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('座ったら、ブーッって\\nいう音が出たら、\\nおもしろいな～♪', 1, 1, 3, 0, 0, 100401, 2, 168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい！\\nミソギ探検隊の\\nマスコットにしよう♪', 1, 1, 3, 0, 0, 100401, 3, 169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸うとくしゃみが\\n止まらなくなるお香を\\nここに…くしゅっ！', 1, 1, 3, 0, 0, 100401, 4, 170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にひひ…イタズラの\\n証拠、ここで\\n燃やしちゃおう～！', 1, 1, 3, 0, 0, 100401, 5, 171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探検家は\\n体力勝負だよー！', 1, 1, 3, 0, 0, 100401, 6, 172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなに分けて\\nあげようかな～\\n激辛ソースも\\n入れちゃうけどね！', 1, 1, 3, 0, 0, 100401, 7, 173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう所に\\n宝の地図が\\n隠れてるんだよね～', 1, 1, 3, 0, 0, 100401, 8, 174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お宝の予感！\\n部屋中を\\n探検しちゃうぞ～', 1, 1, 1, 0, 0, 100402, 1, 176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ、探検に出たい！\\nじっとしてなんか\\nいられないよ～！', 1, 1, 1, 0, 0, 100402, 2, 177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うえ～ん！\\n…嘘泣きしたら\\n相手は油断するかな', 1, 1, 1, 0, 0, 100402, 3, 178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハニートラップって\\nすごく甘いお菓子で\\nイタズラするのかな？', 1, 1, 1, 0, 0, 100402, 4, 179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かくれんぼする人\\nこの指、と～まれ！', 1, 1, 1, 0, 0, 100402, 5, 180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんのオデコと\\nホッペと鼻と目と耳に\\n落書きを…', 8, 1, 1, 0, 0, 100402, 101, 181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんが喜ぶ\\nイタズラ、何かない\\nかな～？', 8, 1, 1, 0, 0, 100402, 102, 182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギがしかけた\\nイタズラ\\n見つけられるかな？', 1, 1, 2, 0, 0, 100402, 1, 183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探検する？\\n冒険する？\\nそれとも…\\nイタズラされる？', 1, 1, 2, 0, 0, 100402, 2, 184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('将来の夢は探検家！\\n探したい物はないけど', 1, 1, 2, 0, 0, 100402, 3, 185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんに宿題！\\n落とし穴を10個\\n掘ること！', 1, 1, 2, 0, 0, 100402, 4, 186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だ～れだ…って？\\nにいちゃんの声くらい\\nわかるよ！\\n大好きだもん♪', 8, 1, 2, 0, 0, 100402, 101, 187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ、ミソギ探検隊の\\n基地にしようよ！', 8, 1, 2, 0, 0, 100402, 102, 188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃん\\n探検に行こうよ！\\n今からなら遭難しても\\n夜には帰れるよ！', 1, 1, 2, 0, 1, 100402, 1, 189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんが昼寝したら\\nイタズラし放題♪', 1, 1, 2, 0, 2, 100402, 2, 190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の探検も\\nおもしろそう！\\nねぇ出かけちゃダメ？', 1, 1, 2, 0, 3, 100402, 3, 191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラには\\nお色気も必要…\\nうん、完璧！', 1, 1, 3, 0, 0, 100402, 1, 192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゆっくりまったりして\\n次のイタズラを\\n考えよ～！', 1, 1, 3, 0, 0, 100402, 2, 193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい！\\nミソギ探検隊の\\nマスコットにしよう♪', 1, 1, 3, 0, 0, 100402, 3, 194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸うとくしゃみが\\n止まらなくなるお香を\\nここに…くしゅっ！', 1, 1, 3, 0, 0, 100402, 4, 195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にひひ…イタズラの\\n証拠、ここで\\n燃やしちゃおう～！', 1, 1, 3, 0, 0, 100402, 5, 196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探検家は\\n体力勝負だよー！', 1, 1, 3, 0, 0, 100402, 6, 197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探検のおやつに\\nぴったりかも～！', 1, 1, 3, 0, 0, 100402, 7, 198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう所に\\n宝の地図が\\n隠れてるんだよね～', 1, 1, 3, 0, 0, 100402, 8, 199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('音楽は全部好きだけど\\n一番好きなのは\\nやっぱりジャズかな', 1, 1, 1, 0, 0, 100601, 1, 201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、はぁ…\\n一人でもいっぱい\\nしないと…\\n特訓…', 1, 1, 1, 0, 0, 100601, 2, 202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんには\\nもっと自信を\\n持ってほしいなぁ', 1, 1, 1, 0, 0, 100601, 3, 203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんのマネ\\nしちゃおうかな？', 1, 1, 1, 0, 0, 100601, 4, 204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('双子って、\\n好みのタイプも\\n似ちゃうのかな？', 1, 1, 1, 0, 0, 100601, 5, 205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと私は\\n相性抜群です♪', 4, 1, 1, 0, 0, 100601, 101, 206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう待ちきれない…\\nお兄ちゃん、\\n早く帰って来て！', 8, 1, 1, 0, 0, 100601, 102, 207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんっ…着替えよう\\nと思ったのに\\nお兄ちゃんのエッチ！', 1, 1, 2, 0, 0, 100601, 1, 208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ、お兄ちゃん！\\n今日は何を\\nするんですか？', 1, 1, 2, 0, 0, 100601, 2, 209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなところ\\n触っちゃダメ♪', 1, 1, 2, 0, 0, 100601, 3, 210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、イジワル\\nしないでください…', 1, 1, 2, 0, 0, 100601, 4, 211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、もっと\\n上級編のテクニック、\\n教えてくださいね！', 4, 1, 2, 0, 0, 100601, 101, 212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コーチ、\\n今日も特訓\\nお願いします！', 8, 1, 2, 0, 0, 100601, 102, 213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n昨夜は楽しかった\\nですね、うふふ♪', 1, 1, 2, 0, 1, 100601, 1, 214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな明るい時間から\\nす、するんですか…\\n二人っきりの特訓…', 1, 1, 2, 0, 2, 100601, 2, 215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はこれからですよ\\nお兄ちゃん♪', 1, 1, 2, 0, 3, 100601, 3, 216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界一、かわいく\\nなるんだから♪', 1, 1, 3, 0, 0, 100601, 1, 217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい♪\\nもう立てないよ～', 1, 1, 3, 0, 0, 100601, 2, 218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\nアカリのライバル\\nだね', 1, 1, 3, 0, 0, 100601, 3, 219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…気持ちいい、\\n私、このままダメに\\nなっちゃいそう…', 1, 1, 3, 0, 0, 100601, 4, 220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…アカリ、\\nとろけちゃう…', 1, 1, 3, 0, 0, 100601, 5, 221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…はぁはぁ、\\n私…もう…ダメ\\n限界です…！', 1, 1, 3, 0, 0, 100601, 6, 222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、おいしい～\\nけど食べ過ぎは美容に\\nよくないですよね', 1, 1, 3, 0, 0, 100601, 7, 223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この楽譜、\\nサックスで吹いて\\nみたいなぁ♪', 1, 1, 3, 0, 0, 100601, 8, 224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このごろ一人でいると\\nお兄ちゃんのこと\\nばかり考えちゃう…', 1, 1, 1, 0, 0, 100602, 1, 226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、はぁ…もっと\\nいっぱいしなくちゃ\\n…練習', 1, 1, 1, 0, 0, 100602, 2, 227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお部屋、なんだか\\n落ち着きます…\\nお兄ちゃんが\\nいるから？', 1, 1, 1, 0, 0, 100602, 3, 228);
