insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('双子って、\\n好みのタイプも\\n似ちゃうのかな？', 1, 1, 1, 0, 0, 100602, 5, 230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか世界でいちばん\\nかわいくなって\\nお兄ちゃんと…', 8, 1, 1, 0, 0, 100602, 101, 231);
