insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、イジワル\\nしないでください…', 1, 1, 2, 0, 0, 100602, 4, 236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんといると\\nわ、私…ドキドキ\\nしてきちゃう…', 8, 1, 2, 0, 0, 100602, 101, 237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コーチ、\\n今日も特訓\\nお願いします！', 8, 1, 2, 0, 0, 100602, 102, 238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n昨夜は楽しかった\\nですね、うふふ♪', 1, 1, 2, 0, 1, 100602, 1, 239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに\\n食べてもらいたいなぁ\\n手作りのお昼ごはん', 1, 1, 2, 0, 2, 100602, 2, 240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お風呂入ってきますね\\nそのあとは…\\n二人でい～っぱい\\n遊びましょうね', 1, 1, 2, 0, 3, 100602, 3, 241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんのマネ\\nしちゃおうかな？', 1, 1, 3, 0, 0, 100602, 1, 242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい♪\\nもう立てないよ～', 1, 1, 3, 0, 0, 100602, 2, 243);
