insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…気持ちいい、\\n私、このままダメに\\nなっちゃいそう…', 1, 1, 3, 0, 0, 100602, 4, 245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い…\\nまるでお兄ちゃんが\\n隣にいる時みたい', 1, 1, 3, 0, 0, 100602, 5, 246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('汗をかくと\\n気持ちいいですよね', 1, 1, 3, 0, 0, 100602, 6, 247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんの特訓に\\n付き合うために\\nたっぷり\\n食べておかないと♪', 1, 1, 3, 0, 0, 100602, 7, 248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この楽譜\\nサックスで吹いて\\nみたいなぁ♪', 1, 1, 3, 0, 0, 100602, 8, 249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリン、プリン、\\nプリン、プリン、\\nプリン、プリン～♪', 1, 1, 1, 0, 0, 100701, 1, 251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ら～め～し～や～\\nなの～♪', 1, 1, 1, 0, 0, 100701, 2, 252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンがないなら\\n死んだほうがマシなの\\nあ、もう死んでたの～', 1, 1, 1, 0, 0, 100701, 3, 253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊の正体見たり、\\nミヤコなの～', 1, 1, 1, 0, 0, 100701, 4, 254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミヤコがいきなり\\n消えたら、みんな\\n驚くかもなの～♪', 1, 1, 1, 0, 0, 100701, 5, 255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツがいて、\\nプリンもある。\\nきっとここが天国なの', 4, 1, 1, 0, 0, 100701, 101, 256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツはプリンセス\\nナイトじゃなくて\\nプリンナイトなの～', 8, 1, 1, 0, 0, 100701, 102, 257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('姿を消して、オマエを\\n見張ってやるの～\\nむふふ～♪', 1, 1, 2, 0, 0, 100701, 1, 258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし成仏した先に\\nプリンがなかったら\\n地獄なの～…', 1, 1, 2, 0, 0, 100701, 2, 259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('右にプリン左にプリン\\n後ろにもプリン♪\\n前にはオマエなの～！', 1, 1, 2, 0, 0, 100701, 3, 260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('死んだ人には\\nお供え物をするの～\\nミヤコにも、プリンを\\n毎日お供えするの～', 1, 1, 2, 0, 0, 100701, 4, 261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさんオマエと\\n遊べて、\\n成仏しそうなくらい\\nうれしいの～！', 4, 1, 2, 0, 0, 100701, 101, 262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエのこと\\n気に入ったからずっと\\nとり憑いてやるの～', 8, 1, 2, 0, 0, 100701, 102, 263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～\u3000眠いの…\\n二度目の二度寝を\\nするの…', 1, 1, 2, 0, 1, 100701, 1, 264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯はプリンなの\\n３時のおやつも、\\nプリンなの～', 1, 1, 2, 0, 2, 100701, 2, 265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ディナーは豪華に、\\nプリンのフルコース\\nなの～♪', 1, 1, 2, 0, 3, 100701, 3, 266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体が透けちゃうから\\nうまく使えないの～', 1, 1, 3, 0, 0, 100701, 1, 267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まったりなの～\\nあとはプリンがあれば\\n完璧なの～', 1, 1, 3, 0, 0, 100701, 2, 268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('む～…かわいいけど\\nプリンは分けて\\nあげないの～', 1, 1, 3, 0, 0, 100701, 3, 269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は～\u3000いい気分なの…\\n成仏しそうなの…', 1, 1, 3, 0, 0, 100701, 4, 270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、もしかして\\nミヤコ、ここで\\n火葬されちゃうの？', 1, 1, 3, 0, 0, 100701, 5, 271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊には、体力も\\n筋力も関係ないの～！', 1, 1, 3, 0, 0, 100701, 6, 272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぱくぱくモグモグ…\\nミヤコ、幽霊だけど、\\nお腹はすくの～', 1, 1, 3, 0, 0, 100701, 7, 273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンの写真集が\\nあればいいのに\\nなの～', 1, 1, 3, 0, 0, 100701, 8, 274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うらめしや～…\\n裏の飯より\\nプリンがいいの～', 1, 1, 1, 0, 0, 100702, 1, 276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリン♪\u3000プリン♪\\nプリン♪\u3000なの～♪\u3000', 1, 1, 1, 0, 0, 100702, 2, 277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界中のケーキ屋が\\nプリンのおいしさを\\n競い合えばいいの～！\\n審査員はミヤコなの～', 1, 1, 1, 0, 0, 100702, 3, 278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('買ってきたプリンには\\n全部ミヤコの名前を\\n書いておくの～', 1, 1, 1, 0, 0, 100702, 4, 279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンがないなら\\n死んだほうがマシなの\\nあ、もう死んでたの～ ', 1, 1, 1, 0, 0, 100702, 5, 280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツがいて\\nプリンもある\\nきっとここが天国なの', 8, 1, 1, 0, 0, 100702, 101, 281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツはプリンセス\\nナイトじゃなくて\\nプリンナイトなの～', 8, 1, 1, 0, 0, 100702, 102, 282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('右にプリン左にプリン\\n後ろにもプリン♪\\n前にはオマエなの～！', 1, 1, 2, 0, 0, 100702, 1, 283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし成仏した先に\\nプリンがなかったら\\n地獄なの～…', 1, 1, 2, 0, 0, 100702, 2, 284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はオマエと\\nプリンを買いに行くの\\n強制なの～\u3000', 1, 1, 2, 0, 0, 100702, 3, 285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('死んだ人には\\nお供え物をするの～\\nミヤコにも、プリンを\\n毎日お供えするの～', 1, 1, 2, 0, 0, 100702, 4, 286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさんオマエと\\n遊べて\\n成仏しそうなくらい\\nうれしいの～！ ', 8, 1, 2, 0, 0, 100702, 101, 287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミヤコのプリン\\nオマエにだったら\\n分けてあげるの～ ', 8, 1, 2, 0, 0, 100702, 102, 288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～\u3000眠いの…\\n二度目の二度寝を\\nするの… ', 1, 1, 2, 0, 1, 100702, 1, 289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ら～め～し～や～\\n…明るい時間だと\\n驚かせないの～ ', 1, 1, 2, 0, 2, 100702, 2, 290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゅ～どろどろ～ん☆\\n真っ暗なうちに\\nいたずらしまくるの～♪', 1, 1, 2, 0, 3, 100702, 3, 291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体が透けちゃうから\\nうまく使えないの～ ', 1, 1, 3, 0, 0, 100702, 1, 292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着くの～\\nいまプリン食べたら\\nきっといつもより\\nおいしいの～♪ ', 1, 1, 3, 0, 0, 100702, 2, 293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('む～…かわいいけど\\nプリンは分けて\\nあげないの～\u3000', 1, 1, 3, 0, 0, 100702, 3, 294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は～\u3000いい気分なの…\\n成仏しそうなの…', 1, 1, 3, 0, 0, 100702, 4, 295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、もしかして\\nミヤコ、ここで\\n火葬されちゃうの？ ', 1, 1, 3, 0, 0, 100702, 5, 296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊には、体力も\\n筋力も関係ないの～！\u3000', 1, 1, 3, 0, 0, 100702, 6, 297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいの～\\nプリン味だったら\\nもっとおいしいの～ ', 1, 1, 3, 0, 0, 100702, 7, 298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンの写真集が\\nあればいいのに\\nなの～ ', 1, 1, 3, 0, 0, 100702, 8, 299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし太陽が滅んでも\\nボクの美しさで大地を\\n照らしてあげる！', 1, 1, 1, 0, 0, 100801, 1, 301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、この部屋には\\nボクの肖像画や\\n彫像が必要だね', 1, 1, 1, 0, 0, 100801, 2, 302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美の女神と愛の女神が\\nボクを作る時、本気\\n出しちゃったんだね♪', 1, 1, 1, 0, 0, 100801, 3, 303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの誕生とともに\\n全ての美しさは過去の\\n遺物になったんだよ！', 1, 1, 1, 0, 0, 100801, 4, 304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うわっ昨日より可愛く\\nなってる。明日は\\nどうなっちゃう\\nのかな？', 1, 1, 1, 0, 0, 100801, 5, 305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このボクがいるだけで\\nあの人への\\nおもてなしだよね', 4, 1, 1, 0, 0, 100801, 101, 306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの可愛さは、\\nふふ…あの人の\\nためのものさ', 8, 1, 1, 0, 0, 100801, 102, 307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ～、ボクって\\n可愛い？\\nふふ、知ってる☆', 1, 1, 2, 0, 0, 100801, 1, 308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呼んだ？\\n可愛いボクと話したい\\n気持ちはわかるよ', 1, 1, 2, 0, 0, 100801, 2, 309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、ボクに触ると\\nキミも美しく\\nなっちゃうかもよ？', 1, 1, 2, 0, 0, 100801, 3, 310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかな、\\n今日のボク。\\n美しい？\u3000可愛い？\\nねえ、どっち？', 1, 1, 2, 0, 0, 100801, 4, 311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人も今、\\n可愛いボクのこと\\n考えてるかな…', 4, 1, 2, 0, 0, 100801, 101, 312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美しい…\\nキミの瞳に写るボクは\\nより一層きれいだ', 8, 1, 2, 0, 0, 100801, 102, 313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美しいボクの\\n美しい一日が\\n始まるよ！', 1, 1, 2, 0, 1, 100801, 1, 314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さーて、午後からも\\n可愛く美しく\\n華麗に優雅に♪', 1, 1, 2, 0, 2, 100801, 2, 315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バラの花びら\\nいっぱい浮かべた\\nお風呂に入ってから\\n寝ようっと♪', 1, 1, 2, 0, 3, 100801, 3, 316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鏡よ、鏡。この世で\\n一番可愛いボクに\\nお似合いの人はだれ？', 1, 1, 3, 0, 0, 100801, 1, 317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが座ったソファは\\n「美しいソファ」に\\nランクアップした！', 1, 1, 3, 0, 0, 100801, 2, 318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、可愛い！\\n…まあ、ボクほど\\nじゃないけどさ！', 1, 1, 3, 0, 0, 100801, 3, 319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服を羽織るように\\n香りをまとうボク…\\n美しい、美しすぎる！', 1, 1, 3, 0, 0, 100801, 4, 320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気安く触ったら\\n火傷する…\\n炎はボクに似ているね', 1, 1, 3, 0, 0, 100801, 5, 321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動は苦手なのに\\n運動するボクの姿は\\n可愛いなんて…罪♪', 1, 1, 3, 0, 0, 100801, 6, 322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが食べると、\\n食べ物まで\\n可愛いなあ…', 1, 1, 3, 0, 0, 100801, 7, 323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが触った瞬間に、\\nこの本は美を\\n携えてしまうんだ', 1, 1, 3, 0, 0, 100801, 8, 324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの美しさは\\nみんなのために\\nあるんだよ！', 1, 1, 1, 0, 0, 100802, 1, 326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、この部屋には\\nボクの肖像画や\\n彫像が必要だね', 1, 1, 1, 0, 0, 100802, 2, 327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ以上美しくなると\\nボクをめぐって\\n大陸中で戦争が\\n始まっちゃう！', 1, 1, 1, 0, 0, 100802, 3, 328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの誕生とともに\\n全ての美しさは過去の\\n遺物になったんだよ！', 1, 1, 1, 0, 0, 100802, 4, 329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの可愛さについて\\nみんな話し合わない\\nのかな…？', 1, 1, 1, 0, 0, 100802, 5, 330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このボクがいるだけで\\nあの人への\\nおもてなしだよね', 8, 1, 1, 0, 0, 100802, 101, 331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人も今\\n可愛いボクのこと\\n考えてるかな…', 8, 1, 1, 0, 0, 100802, 102, 332);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美の女神と愛の女神が\\nボクを作る時、本気\\n出しちゃったんだね♪', 1, 1, 2, 0, 0, 100802, 1, 333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの美しさに嫉妬\\nしたって意味ないよね\\n次元が違うんだから', 1, 1, 2, 0, 0, 100802, 2, 334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの化粧品使う？\\n一緒に可愛くなろうよ', 1, 1, 2, 0, 0, 100802, 3, 335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクがいるだけで\\nこの部屋は美の神殿♪\\nランドソルの新たな\\n観光名所になるね！', 1, 1, 2, 0, 0, 100802, 4, 336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呼んだ？\\n可愛いボクと話したい\\n気持ちはわかるよ', 8, 1, 2, 0, 0, 100802, 101, 337);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美しい…\\nキミの瞳に写るボクは\\nより一層綺麗だ', 8, 1, 2, 0, 0, 100802, 102, 338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝日と共に\\nボクの美しさも\\n周りを照らすよ', 1, 1, 2, 0, 1, 100802, 1, 339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクの美しさを\\n維持するために\\nお昼ご飯食べなくちゃ', 1, 1, 2, 0, 2, 100802, 2, 340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バラの花びらいっぱい\\n浮かべたお風呂に\\n入ってから\\n寝ようっと♪', 1, 1, 2, 0, 3, 100802, 3, 341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鏡よ、鏡。この世で\\n一番可愛いボクに\\nお似合いの人はだれ？', 1, 1, 3, 0, 0, 100802, 1, 342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが座ったソファは\\n「美しいソファ」に\\nランクアップした！', 1, 1, 3, 0, 0, 100802, 2, 343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛いものを\\n可愛いって言える\\nボクって可愛いよね！', 1, 1, 3, 0, 0, 100802, 3, 344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服を羽織るように\\n香りをまとうボク…\\n美しい、美しすぎる！', 1, 1, 3, 0, 0, 100802, 4, 345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷えは美容の大敵\\nなんだから！\\nここ、ボクの場所ね！', 1, 1, 3, 0, 0, 100802, 5, 346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動は苦手なのに\\n運動するボクの姿は\\n可愛いなんて…罪♪', 1, 1, 3, 0, 0, 100802, 6, 347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが食べると\\n食べ物まで\\n可愛いなあ…', 1, 1, 3, 0, 0, 100802, 7, 348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが触った瞬間に\\nこの本は美を\\n携えてしまうんだ', 1, 1, 3, 0, 0, 100802, 8, 349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「第１０部２０章\\n終焉戦争、開幕」\\n…これでよし！', 1, 1, 1, 0, 0, 100901, 1, 351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度シグルドに\\n私の魔法を一つ\\n伝授してやるか', 1, 1, 1, 0, 0, 100901, 2, 352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでは風が\\n吹いてこないな…\\n換気したい！', 1, 1, 1, 0, 0, 100901, 3, 353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、ナナカに\\nこの間借りた本を\\n返さないと…', 1, 1, 1, 0, 0, 100901, 4, 354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まずは包帯をとって\\n手から龍の形の\\n炎を出して…', 1, 1, 1, 0, 0, 100901, 5, 355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルド…\\n今頃何処で何を\\nしているのだろう…', 4, 1, 1, 0, 0, 100901, 101, 356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、彼の姿が\\nまぶしく見える…\\nどうして…？', 8, 1, 1, 0, 0, 100901, 102, 357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('辞書を知らないか？\\n…探している\\n理由は聞くな', 1, 1, 2, 0, 0, 100901, 1, 358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ！\\n貴様の技にも\\n名前をつけてやろう！', 1, 1, 2, 0, 0, 100901, 2, 359);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私に触れても力を\\n奪われないのは\\n貴様くらいだぞ？', 1, 1, 2, 0, 0, 100901, 3, 360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何事だ？\\nまさか我が瞳に\\n魅入られたのか？', 1, 1, 2, 0, 0, 100901, 4, 361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴様がそばにいると\\nとても安心できる…\\n…不思議だ', 4, 1, 2, 0, 0, 100901, 101, 362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、いきなり目の前に\\n現れるな！\u3000ドキドキ\\nするだろうがぁ！', 8, 1, 2, 0, 0, 100901, 102, 363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「覚醒」めたか…\\n行くぞ、悪を討つ\\n戦いに出発だ！', 1, 1, 2, 0, 1, 100901, 1, 364);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼間は「ヤツら」も\\n襲ってはこない…\\n束の間の休息だ', 1, 1, 2, 0, 2, 100901, 2, 365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうした？\u3000夜はまだ\\nこれから…ふぁ…\\nね、眠くなどないぞ！', 1, 1, 2, 0, 3, 100901, 3, 366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か足りないな…\\n暗黒騎士の紋章を\\n作ろうかな', 1, 1, 3, 0, 0, 100901, 1, 367);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くっ…！\\n私を眠りの国へ\\n誘うつもりか！', 1, 1, 3, 0, 0, 100901, 2, 368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このようなものに\\n懐柔されるものか！\\n…されるものか！', 1, 1, 3, 0, 0, 100901, 3, 369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを使えば\\nもっとそれっぽい\\n雰囲気が出そうだ', 1, 1, 3, 0, 0, 100901, 4, 370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これが我らの求めた\\n安寧か…\\n悪くない…', 1, 1, 3, 0, 0, 100901, 5, 371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この程度\\n前世での激闘に\\n比べれば…！', 1, 1, 3, 0, 0, 100901, 6, 372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近金欠でな…\\nいやぁありがたい…', 1, 1, 3, 0, 0, 100901, 7, 373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにも\\n前世の記憶が\\n眠っていたとは…', 1, 1, 3, 0, 0, 100901, 8, 374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「第１３部１章\\n閃光のシグルド」\\n…ついに登場だな', 1, 1, 1, 0, 0, 100902, 1, 376);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何故だ…何故\\nこうもあっさり金欠に\\n逆戻りするのだ！？', 1, 1, 1, 0, 0, 100902, 2, 377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やはり転生者という\\n設定はカッコイイ…\\n天才だな、私！', 1, 1, 1, 0, 0, 100902, 3, 378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、ナナカに\\nこの間借りた本を\\n返さないと…', 1, 1, 1, 0, 0, 100902, 4, 379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ今日の分の\\n魔力を溜めないと\\nまた魔力切れが…', 1, 1, 1, 0, 0, 100902, 5, 380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近奴がそばに\\nいるだけで、鼓動が\\n早くなるのは何故だ？', 1, 1, 1, 0, 0, 100902, 101, 381);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シ、シグルド…！\\nだめだ…妄想でも\\n上手く言えない…', 8, 1, 1, 0, 0, 100902, 102, 382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだ？\u3000新たな\\n賞金の情報を\\n持ってきたのか？', 8, 1, 2, 0, 0, 100902, 1, 383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('名乗りやポーズは\\nその強度で相手を\\n圧倒する技術だ', 1, 1, 2, 0, 0, 100902, 2, 384);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいか、魔法の\\n詠唱中は絶対に\\n声をかけるなよ？', 1, 1, 2, 0, 0, 100902, 3, 385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おお、ちょうど今\\n貴様専用の設定集を\\n作成中だぞ！', 1, 1, 2, 0, 0, 100902, 4, 386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴様がそばにいると\\nとても安心できる…\\n…不思議だ', 1, 1, 2, 0, 0, 100902, 101, 387);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、いきなり目の前に\\n現れるな！\u3000ドキドキ\\nするだろうがぁ！', 8, 1, 2, 0, 0, 100902, 102, 388);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かしのせいか\\nまだ眠気が…いや！\\nこれは組織の罠だ！', 8, 1, 2, 0, 1, 100902, 1, 389);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('平穏な時に\\n出来るだけ魔力を\\n溜めておかねば…', 1, 1, 2, 0, 2, 100902, 2, 390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜になると、力が\\n増した気分になるな\\n…なりませんか？', 1, 1, 2, 0, 3, 100902, 3, 391);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か足りないな…\\n暗黒騎士の紋章を\\n作ろうかな', 1, 1, 3, 0, 0, 100902, 1, 392);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、おのれ\\nヒュプノス…\\n私は負けないぞ…', 1, 1, 3, 0, 0, 100902, 2, 393);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くっくっくっ…\\n貴様は特別団員に\\nしてやろう', 1, 1, 3, 0, 0, 100902, 3, 394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを使えば\\nもっとそれっぽい\\n雰囲気が出そうだ', 1, 1, 3, 0, 0, 100902, 4, 395);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これが我らの求めた\\n安寧か…\\n悪くない…', 1, 1, 3, 0, 0, 100902, 5, 396);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新たな戦いに備えて\\n魔力だけでなく\\n体力も鍛えねば！', 1, 1, 3, 0, 0, 100902, 6, 397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事は魔力に\\n変換する体力の\\n元になるのだ！', 1, 1, 3, 0, 0, 100902, 7, 398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フフフ…\\nこれを覚えれば\\nもっと強く…！', 1, 1, 3, 0, 0, 100902, 8, 399);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんほんまに\\nはんなりしてて、\\n王子はんって感じやわ', 1, 1, 1, 0, 0, 101001, 1, 401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この絵本の王子はん、\\n王子はんみたいで\\nええなぁ♪', 1, 1, 1, 0, 0, 101001, 2, 402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちがガラスの靴を\\n落としたら、王子はん\\n見つけてくれるやろか', 1, 1, 1, 0, 0, 101001, 3, 403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホマホ王国\\n次期国王の王子はん\\n…見てみたいわ～', 1, 1, 1, 0, 0, 101001, 4, 404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんのために\\n糸を紡いで、\\n編み物でもしまひょか', 1, 1, 1, 0, 0, 101001, 5, 405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホ姫と王子はん、\\n絵本の世界より\\nベストカップルや', 4, 1, 1, 0, 0, 101001, 101, 406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんと\\n一緒にいると\\n胸がせわしのー\\nうごいてかなん', 8, 1, 1, 0, 0, 101001, 102, 407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちら並んでたら\\nお雛様みたいに\\n見えると思いまへん？', 1, 1, 2, 0, 0, 101001, 1, 408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんを\\n国に連れて帰ったら\\nみんな大歓迎して\\nくれるやろなぁ', 1, 1, 2, 0, 0, 101001, 2, 409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんは、\\n絵本から出てきた人\\nみたいやね～', 1, 1, 2, 0, 0, 101001, 3, 410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの話し方\\nのんびりしてます\\nやろか？', 1, 1, 2, 0, 0, 101001, 4, 411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホ姫の手は\\nつべたいから、\\n王子はんが温めて？', 4, 1, 2, 0, 0, 101001, 101, 412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちがもし悪い魔法に\\nかかったら、王子はん\\n口づけしてくれはる？', 8, 1, 2, 0, 0, 101001, 102, 413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は小鳥はんも\\nおなかがすいてるから\\nよう飛び回りはるねえ', 1, 1, 2, 0, 1, 101001, 1, 414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お茶請けはお大福が\\nよろしおすけど\\nクッキーもええなあ', 1, 1, 2, 0, 2, 101001, 2, 415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うち、普段から\\n夢見がちやけど…\\nほんに眠い時間やわぁ', 1, 1, 2, 0, 3, 101001, 3, 416);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんに\\n会いに行くなら、\\nおめかしせな\\nあかんなぁ', 1, 1, 3, 0, 0, 101001, 1, 417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はんなりした\\nええお椅子やわぁ\\nほっこりしますなあ', 1, 1, 3, 0, 0, 101001, 2, 418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かいらしもんが\\nいっぱいで、\\nマホマホ王国みたい\\nやわぁ', 1, 1, 3, 0, 0, 101001, 3, 419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地ええどす。まるで\\nお花畑にいるようやね', 1, 1, 3, 0, 0, 101001, 4, 420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかどす。\\n心まであったかく\\nなりますわぁ', 1, 1, 3, 0, 0, 101001, 5, 421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁはぁ、お姫はんは\\n激しい運動は\\nしぃひんもんどす～', 1, 1, 3, 0, 0, 101001, 6, 422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…あんまり\\n速う食べられへんけど\\n美味しいわぁ', 1, 1, 3, 0, 0, 101001, 7, 423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵本、絵本～\\n幸せやわぁ♪', 1, 1, 3, 0, 0, 101001, 8, 424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんにとって\\n自慢の姫になるえ～', 1, 1, 1, 0, 0, 101002, 1, 426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャの馬車に\\nガラスの靴…\\n欲しいなぁ', 1, 1, 1, 0, 0, 101002, 2, 427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちがガラスの靴を\\n落としたら、王子はん\\n見つけてくれるやろか', 1, 1, 1, 0, 0, 101002, 3, 428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホマホ王国\\n次期国王の王子はん\\n…見てみたいわ～', 1, 1, 1, 0, 0, 101002, 4, 429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほんまなぁ\\nこの絵本が面白いんよ\\n王子はんに\\n読んであげよ', 1, 1, 1, 0, 0, 101002, 5, 430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホ姫と王子はん\\n絵本の世界より\\nベストカップルや', 8, 1, 1, 0, 0, 101002, 101, 431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんと\\n一緒にいると\\n胸がせわしのー\\nうごいてかなん', 8, 1, 1, 0, 0, 101002, 102, 432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには、王子はんの\\n好きな絵本も\\n知りたいな～', 1, 1, 2, 0, 0, 101002, 1, 433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんを\\n国に連れて帰ったら\\nみんな大歓迎して\\nくれるやろなぁ', 1, 1, 2, 0, 0, 101002, 2, 434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そのうち、王子はんの\\nお国にも連れてって\\nもらえますやろか？', 1, 1, 2, 0, 0, 101002, 3, 435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵本読むんも\\nええなぁ…', 1, 1, 2, 0, 0, 101002, 4, 436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちがもし悪い魔法に\\nかかったら、王子はん\\n口づけしてくれはる？', 8, 1, 2, 0, 0, 101002, 101, 437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちら並んでたら\\nお雛様みたいに\\n見えると思いまへん？', 8, 1, 2, 0, 0, 101002, 102, 438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は小鳥はんも\\nおなかがすいてるから\\nよう飛び回りはるねえ', 1, 1, 2, 0, 1, 101002, 1, 439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホマホ王国では\\nこの時分は\\nみんなお昼寝\\nしてたんよ', 1, 1, 2, 0, 2, 101002, 2, 440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜に飛んだり鳴いたり\\nする鳥はんもおるんよ\\n昼は寝てはるんかねぇ', 1, 1, 2, 0, 3, 101002, 3, 441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんに\\n会いに行くなら\\nおめかしせな\\nあかんなぁ', 1, 1, 3, 0, 0, 101002, 1, 442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんも一緒に\\nゆっくりしていっても\\nええんよ？', 1, 1, 3, 0, 0, 101002, 2, 443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かいらしい子やねぇ\\nうちとお友だちに\\nなってくれるん？', 1, 1, 3, 0, 0, 101002, 3, 444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('癒しアイテムって\\nほんま、好っきゃわぁ', 1, 1, 3, 0, 0, 101002, 4, 445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちのお城にも\\nほしいわぁ。帰ったら\\nさっそく準備せな\\nあかんなぁ', 1, 1, 3, 0, 0, 101002, 5, 446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の中で運動\\nできるのも、なかなか\\n面白いもんやわぁ', 1, 1, 3, 0, 0, 101002, 6, 447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいひいわ～\\nマホマホ王国には\\nない味やわぁ', 1, 1, 3, 0, 0, 101002, 7, 448);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり知識を\\n身につけんと\\n魔法も使えへん\\nからなぁ', 1, 1, 3, 0, 0, 101002, 8, 449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('１、２、３、４…\\nあれ？\u3000いま、\\n何段目まで\\n編んだっけ？', 1, 1, 1, 0, 0, 101101, 1, 451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやつのケーキは\\n苺かチョコ…\\nどっちも食べよう！', 1, 1, 1, 0, 0, 101101, 2, 452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、いけない！\\n縫い針落としちゃった', 1, 1, 1, 0, 0, 101101, 3, 453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ケーキをクレープで\\n巻いたら…\\n大ヒット商品の予感！', 1, 1, 1, 0, 0, 101101, 4, 454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「どうだ！妹暮らし」\\nってことわざ\\nなかったっけ？', 1, 1, 1, 0, 0, 101101, 5, 455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに、\\nお洋服でも\\n作ろうかな？', 4, 1, 1, 0, 0, 101101, 101, 456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここがお兄ちゃんの\\n部屋…\\nドキドキしちゃう～', 8, 1, 1, 0, 0, 101101, 102, 457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、おにいちゃん\\n一緒に、スイーツでも\\n食べにいかない？', 1, 1, 2, 0, 0, 101101, 1, 458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリームついてた！？\\nさっき食べた、\\nケーキかも…！', 1, 1, 2, 0, 0, 101101, 2, 459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強、見てくれるん\\nですか？\u3000やった～♪', 1, 1, 2, 0, 0, 101101, 3, 460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服がほつれてますよ？\\n直してあげます！', 1, 1, 2, 0, 0, 101101, 4, 461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私をお嫁さんに\\nしたいなら、予約は\\nお早目に、ですよ♪', 4, 1, 2, 0, 0, 101101, 101, 462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇねぇお兄ちゃん！\\n…えへへ、\\n呼んでみただけ♪', 8, 1, 2, 0, 0, 101101, 102, 463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も１日\\n勉強がんばります！\\n…少しは遊ぼうかな', 1, 1, 2, 0, 1, 101101, 1, 464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼休憩に\\n甘いものが\\n食べたいです～', 1, 1, 2, 0, 2, 101101, 2, 465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねむいです～\\nでももうちょっと\\n勉強しないと～…', 1, 1, 2, 0, 3, 101101, 3, 466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服、かわいい♪\\n今度作って\\nみよっと～！', 1, 1, 3, 0, 0, 101101, 1, 467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強で疲れたから\\n休憩しよ～っと', 1, 1, 3, 0, 0, 101101, 2, 468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\n私が服を作って\\nあげよっか？', 1, 1, 3, 0, 0, 101101, 3, 469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスできます～\\nお兄ちゃんが隣に\\nいるみたい！', 1, 1, 3, 0, 0, 101101, 4, 470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('のんびりしたら、\\nまた勉強しよっと！', 1, 1, 3, 0, 0, 101101, 5, 471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動すると勉強も\\nはかどるよね！', 1, 1, 3, 0, 0, 101101, 6, 472);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいし～！\\nお兄ちゃんにも\\nおすそ上げしますね！', 1, 1, 3, 0, 0, 101101, 7, 473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんの記憶を\\n戻す方法、どこかに\\n書いてないかな？', 1, 1, 3, 0, 0, 101101, 8, 474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ケーキの食べ過ぎで\\nお腹が…うぅ、\\n因果横暴だよー…', 1, 1, 1, 0, 0, 101102, 1, 476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('１、２、３、４…\\nあれ？\u3000いま、\\n何段目まで\\n編んだっけ？', 1, 1, 1, 0, 0, 101102, 2, 477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、いけない！\\n縫い針落としちゃった', 1, 1, 1, 0, 0, 101102, 3, 478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('笑う時には服着ます！', 1, 1, 1, 0, 0, 101102, 4, 479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「どうだ！妹暮らし」\\nってことわざ\\nなかったっけ？', 1, 1, 1, 0, 0, 101102, 5, 480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに、\\nお洋服でも\\n作ろうかな？', 8, 1, 1, 0, 0, 101102, 101, 481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんが帰って\\nきたら、何して遊ぼう\\nかな～？', 8, 1, 1, 0, 0, 101102, 102, 482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強、見てくれるん\\nですか？\u3000やった～♪', 1, 1, 2, 0, 0, 101102, 1, 483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリームついてた！？\\nさっき食べた、\\nケーキかも…！', 1, 1, 2, 0, 0, 101102, 2, 484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃん！\\nそろそろ、おやつに\\nしませんか？', 1, 1, 2, 0, 0, 101102, 3, 485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強は…\\n明日にしようっと', 1, 1, 2, 0, 0, 101102, 4, 486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('妹だけど、大人な\\nレディですからね！', 8, 1, 2, 0, 0, 101102, 101, 487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な、ナデナデとか\\n恥ずかしいな～', 8, 1, 2, 0, 0, 101102, 102, 488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も１日\\n勉強がんばります！\\n…少しは遊ぼうかな', 1, 1, 2, 0, 1, 101102, 1, 489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼休憩に\\n甘いものが\\n食べたいです～', 1, 1, 2, 0, 2, 101102, 2, 490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんは\\n夜強いんですね\\n私は眠くて…', 1, 1, 2, 0, 3, 101102, 3, 491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服装や髪形が変わると\\n気分も変わるよね', 1, 1, 3, 0, 0, 101102, 1, 492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで寝ちゃったら\\n受験勉強が～…\\nぐーー', 1, 1, 3, 0, 0, 101102, 2, 493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\n私が服を作って\\nあげよっか？', 1, 1, 3, 0, 0, 101102, 3, 494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いまならどんな試験も\\n合格できそうです！', 1, 1, 3, 0, 0, 101102, 4, 495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('のんびりしたら\\nまた勉強しよっと！', 1, 1, 3, 0, 0, 101102, 5, 496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんを\\n守るためには\\n毎日、鍛えなくちゃ！', 1, 1, 3, 0, 0, 101102, 6, 497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいし～！\\nお兄ちゃんにも\\nおすそ上げしますね！', 1, 1, 3, 0, 0, 101102, 7, 498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本の服\\nかわいいなぁ♪\\n私に作れるかな？', 1, 1, 3, 0, 0, 101102, 8, 499);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、今なら\\nどこでだって\\n眠れちゃいそう…', 1, 1, 1, 0, 0, 101201, 1, 501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさん寝すぎて、\\n夢の中か現実か\\nわかんなく\\nなっちゃうんだよね～', 1, 1, 1, 0, 0, 101201, 2, 502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…はっ！？\\nね、寝てないよ？\\nホントだよっ', 1, 1, 1, 0, 0, 101201, 3, 503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐっすり眠って\\nパワーを\\nフルチャージっ☆', 1, 1, 1, 0, 0, 101201, 4, 504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし、超能力のことが\\nバレたら…ブルブル', 1, 1, 1, 0, 0, 101201, 5, 505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テレパシーで\\nキミの心を覗けたら\\n…なんてね！', 4, 1, 1, 0, 0, 101201, 101, 506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミを抱き枕に…\\nじょ、冗談冗談！', 8, 1, 1, 0, 0, 101201, 102, 507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、なになに？\\n一緒にお昼寝する？', 1, 1, 2, 0, 0, 101201, 1, 508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('忘れ物しちゃった。\\nま、いっか！\\nえ、ダメ？', 1, 1, 2, 0, 0, 101201, 2, 509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおっ、相談ごと？\\nなにかな\\nなにかな～？', 1, 1, 2, 0, 0, 101201, 3, 510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、もしかして\\nキミにも仲良しになる\\n超能力があるのかも！', 1, 1, 2, 0, 0, 101201, 4, 511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむ～…どう？\\nテレパシーで、私の\\n気持ちを送ったよ！', 4, 1, 2, 0, 0, 101201, 101, 512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えっ？\u3000私とキミとの\\n相性？\u3000むむ～…\\nうん、バッチリだよ☆', 8, 1, 2, 0, 0, 101201, 102, 513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだこんな時間？\\nベッドに行って、\\n二度寝しなくちゃ～', 1, 1, 2, 0, 1, 101201, 1, 514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度なお昼寝は\\n健康にいいんだって！\\n８時間くらいかな？', 1, 1, 2, 0, 2, 101201, 2, 515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなにお昼寝しても\\n夜は眠いんだ～', 1, 1, 2, 0, 3, 101201, 3, 516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、また寝癖…\\nいっつも\\n寝てるからかなぁ？', 1, 1, 3, 0, 0, 101201, 1, 517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休み、一休み…\\nどうせなら百休み\\nくらいしようかな…', 1, 1, 3, 0, 0, 101201, 2, 518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ…可愛い！\\nシオリンに\\n届けてあげたい！', 1, 1, 3, 0, 0, 101201, 3, 519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～…気分爽快！\\nそれじゃ、おやすみ～\\n…すやぁ…', 1, 1, 3, 0, 0, 101201, 4, 520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい…\\nはっ！\u3000ダメダメ！\\nまた寝るとこだった！', 1, 1, 3, 0, 0, 101201, 5, 521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眠くならないように、\\n運動しよっと！', 1, 1, 3, 0, 0, 101201, 6, 522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹いっぱいになると\\n眠くなるよね～', 1, 1, 3, 0, 0, 101201, 7, 523);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('睡眠学習って\\n本を読みながら\\n寝るんだっけ？', 1, 1, 3, 0, 0, 101201, 8, 524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、今なら\\nどこでだって\\n眠れちゃいそう…', 1, 1, 1, 0, 0, 101202, 1, 526);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっといっぱい\\n超能力使えたら\\nいいのにな～', 1, 1, 1, 0, 0, 101202, 2, 527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえねえ、\\n今から人助け、\\n付き合ってほしいなー', 1, 1, 1, 0, 0, 101202, 3, 528);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐっすり眠って\\nパワーを\\nフルチャージっ☆', 1, 1, 1, 0, 0, 101202, 4, 529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人助け、頑張ったら\\nなんだか、眠く…\\n…はっ、ダメダメ！', 1, 1, 1, 0, 0, 101202, 5, 530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒なら、\\nなんだって出来る！\\n間違いない！', 8, 1, 1, 0, 0, 101202, 101, 531);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミを抱き枕に…\\nじょ、冗談冗談！', 8, 1, 1, 0, 0, 101202, 102, 532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('忘れ物しちゃった\\nま、いっか！\\nえ、ダメ？', 1, 1, 2, 0, 0, 101202, 1, 533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに？\u3000困ってる？\\nちょうど良かった！\\n今は体力満タンだよ☆', 1, 1, 2, 0, 0, 101202, 2, 534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒に\\nお出かけしたいなー\\nデートしよっ！', 1, 1, 2, 0, 0, 101202, 3, 535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うんうん、そうだねっ\\n困ってる人がいたら\\n見過ごせないよねっ！', 1, 1, 2, 0, 0, 101202, 4, 536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむ～…どう？\\nテレパシーで、私の\\n気持ちを送ったよ！', 8, 1, 2, 0, 0, 101202, 101, 537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～だんだん眠く…\\nねぇ一緒に寝よ？', 8, 1, 2, 0, 0, 101202, 102, 538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミって早起きだね！\\n私は寝ようかな～', 1, 1, 2, 0, 1, 101202, 1, 539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度なお昼寝は\\n健康にいいんだって！\\n８時間くらいかな？', 1, 1, 2, 0, 2, 101202, 2, 540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなにお昼寝しても\\n夜は眠いんだ～', 1, 1, 2, 0, 3, 101202, 3, 541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、また寝癖…\\nいっつも\\n寝てるからかなぁ？', 1, 1, 3, 0, 0, 101202, 1, 542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休み、一休み…\\nどうせなら百休み\\nくらいしようかな…', 1, 1, 3, 0, 0, 101202, 2, 543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ…可愛い！\\nシオリンに\\n届けてあげたい！', 1, 1, 3, 0, 0, 101202, 3, 544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～…気分爽快！\\nそれじゃ、おやすみ～\\n…すやぁ…', 1, 1, 3, 0, 0, 101202, 4, 545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう～ん、なんだか\\nいつもより眠ーく\\nなってきたよ…', 1, 1, 3, 0, 0, 101202, 5, 546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よーし\\n困ってる人のために\\nパワーアップ☆', 1, 1, 3, 0, 0, 101202, 6, 547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べてすぐ寝ると\\n牛になるんだっけ？\\nまぁ、いいかぁ～', 1, 1, 3, 0, 0, 101202, 7, 548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('睡眠学習って\\n本を読みながら\\n寝るんだっけ？', 1, 1, 3, 0, 0, 101202, 8, 549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('モデルは楽しいよ！\\nファンの子みんな\\n応援してくれるしー！', 1, 1, 1, 0, 0, 101601, 1, 551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のおやつは\\n駄菓子に決定～！\\nいただきまーす！', 1, 1, 1, 0, 0, 101601, 2, 552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー、今日のおやつは\\n何にしよう？\\nやっぱアメ玉かな！', 1, 1, 1, 0, 0, 101601, 3, 553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで撮影会、\\nしようかな～♪', 1, 1, 1, 0, 0, 101601, 4, 554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('７かける８はぁ\\n７＋７＋７＋７＋…\\nん、何個数えたっけ？', 1, 1, 1, 0, 0, 101601, 5, 555);
