insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好きなことして\\nヒデサイもいて\\nうちって超～\\nリア充だよね♪', 8, 1, 1, 0, 0, 101601, 102, 557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの写真撮るの？\\nどんなポーズ？', 1, 1, 2, 0, 0, 101601, 1, 558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネイルの勉強中～♪\\nうまくなったら、\\nヒデサイにしてあげる', 1, 1, 2, 0, 0, 101601, 2, 559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宿題見てくんない？\\nひとりじゃムリ～', 1, 1, 2, 0, 0, 101601, 3, 560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みてこのネイル♪\\n超エモくな～い？\\nヒデサイもする～？', 1, 1, 2, 0, 0, 101601, 4, 561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい美容液で\\n肌まじスベスベ～\\nヒデサイも\\n触ってみる？', 4, 1, 2, 0, 0, 101601, 101, 562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイと会ってると\\n顔熱くなるんだよね\\n熱なんかないのに…', 8, 1, 2, 0, 0, 101601, 102, 563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きとか\\nつらたんだよねー\\n昼すぎまで寝てたい', 1, 1, 2, 0, 1, 101601, 1, 564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('撮影にむけて\\nダイエットちうだから\\nお昼ぬいてるんだー', 1, 1, 2, 0, 2, 101601, 2, 565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたー\\nでもこの時間に\\n食べたら絶対に\\n太るやつだよねー', 1, 1, 2, 0, 3, 101601, 3, 566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなシーンにも合う\\nきれいめわがまま\\nちゃんとコーデだよ♪', 1, 1, 3, 0, 0, 101601, 1, 567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっち疲れたかも？\\nガン寝しちゃおっかな', 1, 1, 3, 0, 0, 101601, 2, 568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃわたーん☆\\n君もおしゃれしよっか', 1, 1, 3, 0, 0, 101601, 3, 569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいにおいじゃん！\\nこれと同じにおいの\\n香水ないかな？', 1, 1, 3, 0, 0, 101601, 4, 570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったまるー\\nこれ、サイツヨに\\n癒しじゃない？', 1, 1, 3, 0, 0, 101601, 5, 571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あはは、なんか\\nウォーキングの練習\\nしてるみたーい！', 1, 1, 3, 0, 0, 101601, 6, 572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体形維持しないと\\nいけないけど\\nついつい食べちゃう！', 1, 1, 3, 0, 0, 101601, 7, 573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('全然読めない～\\nそだ、ヒデサイに\\n読んでもらおっと！', 1, 1, 3, 0, 0, 101601, 8, 574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ\\n仕事の時間だ～\\n出かける準備\\nしよっと！', 1, 1, 1, 0, 0, 101602, 1, 576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のおやつは\\n駄菓子に決定～！\\nいただきまーす！', 1, 1, 1, 0, 0, 101602, 2, 577);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイを見習って\\nうちも少し勉強して\\nみよっかな…\u3000', 1, 1, 1, 0, 0, 101602, 3, 578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体形維持とか\\n気にしてるんだよ～', 1, 1, 1, 0, 0, 101602, 4, 579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('７かける８はぁ\\n７＋７＋７＋７＋…\\nん、何個数えたっけ？', 1, 1, 1, 0, 0, 101602, 5, 580);
