insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっさー\\n踊ってると、どんどん\\n楽しくなるさー！', 1, 1, 1, 0, 0, 101701, 1, 601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお菓子、でーじ\\nおいしいねー！\\nキミも食べる？', 1, 1, 1, 0, 0, 101701, 2, 602);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハイターイ！\u3000元気な\\nあいさつが一番さ～！', 1, 1, 1, 0, 0, 101701, 3, 603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あまった食材があれば\\nチャンプルーにして\\n食べたいさー！ ', 1, 1, 1, 0, 0, 101701, 4, 604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ、みんなで歌って\\n踊るさ～♪', 1, 1, 1, 0, 0, 101701, 5, 605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日、最高に幸せさ～\\nキミのおかげだねー', 4, 1, 1, 0, 0, 101701, 101, 606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミへの気持ちを\\n踊りで表現\\nしてみるさ～', 8, 1, 1, 0, 0, 101701, 102, 607);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海でひと泳ぎ\\nしたいさ～\\nキミもどう？', 1, 1, 2, 0, 0, 101701, 1, 608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あぎひゃっ！\\n急に声かけたら、\\nビックリするさ～', 1, 1, 2, 0, 0, 101701, 2, 609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('踊りなら、\\n私が手とり足とり\\n教えてあげるさ～！', 1, 1, 2, 0, 0, 101701, 3, 610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('空手の型の\\n練習するさー\\nキミもどう？', 1, 1, 2, 0, 0, 101701, 4, 611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よ～し、手をつないで\\n踊るさ～！\\n恥ずかしがること\\nないさ～', 4, 1, 2, 0, 0, 101701, 101, 612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒だから、\\n毎日楽しいこと\\nばっかりさー', 8, 1, 2, 0, 0, 101701, 102, 613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハイターイ！\\n今日も一日、\\nがんばるさー！', 1, 1, 2, 0, 1, 101701, 1, 614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午後も頑張るために\\nお昼ご飯は\\nてびちにするさー！', 1, 1, 2, 0, 2, 101701, 2, 615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('故郷では見えない星が\\n見られるんだねえ。\\nなんか不思議さぁ', 1, 1, 2, 0, 3, 101701, 3, 616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夢中で踊ってたら、\\n髪の毛ぼさぼさに\\nなってるさ～！？', 1, 1, 3, 0, 0, 101701, 1, 617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よく食べてよく踊って\\nよく休む。\\nそれが元気の秘訣さ～', 1, 1, 3, 0, 0, 101701, 2, 618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゅらかーぎーねー！\\nキミはどこから\\n来たのー？', 1, 1, 3, 0, 0, 101701, 3, 619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～、って\\n私もカオリだったさ！\\nなんだか照れるね☆', 1, 1, 3, 0, 0, 101701, 4, 620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('故郷はあんまり暖房を\\n使わなかったから、\\n新鮮さー！', 1, 1, 3, 0, 0, 101701, 5, 621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('汗をかくのは\\n気持ちいいさー！\\nどんどん行くよー！', 1, 1, 3, 0, 0, 101701, 6, 622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、おいしいさ～\\nゴーヤっぽいものを\\n混ぜたいさ～', 1, 1, 3, 0, 0, 101701, 7, 623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおー、故郷の民話！\\nこんなとこで見るとは\\n懐かしいさぁ～！', 1, 1, 3, 0, 0, 101701, 8, 624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('焦らなくても\\nなんくるないさ～\\nなるようになるさ～', 1, 1, 1, 0, 0, 101702, 1, 626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ、みんなで歌って\\n踊るさ～♪', 1, 1, 1, 0, 0, 101702, 2, 627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元気がないときは\\n私のところに来るさー', 1, 1, 1, 0, 0, 101702, 3, 628);
