insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はあ…\\nすてきな小説だった～\\nキュンキュンしちゃう', 1, 1, 1, 0, 0, 101801, 1, 651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお部屋\\n女の子ばかりね。\\n魔族の女子校を\\n思い出しちゃう♪', 1, 1, 1, 0, 0, 101801, 2, 652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次のテスト\\n恋愛小説から\\n出題したら\\nダメかしら…？', 1, 1, 1, 0, 0, 101801, 3, 653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キンコンカンコ～ン♪\\n授業をはじめま～す', 1, 1, 1, 0, 0, 101801, 4, 654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はー…\\nちょっと肩が\\nこっちゃった…', 1, 1, 1, 0, 0, 101801, 5, 655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、あの子のこと\\n無意識に特別扱い\\nしちゃってるかな…', 4, 1, 1, 0, 0, 101801, 101, 656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物語だと生徒が先生を\\n好きになるのにな…\\n逆の場合は…', 8, 1, 1, 0, 0, 101801, 102, 657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あん！\u3000見ちゃダメよ\\n明日のテストの問題を\\n作ってるとこなの！', 1, 1, 2, 0, 0, 101801, 1, 658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強勉強で\\n疲れたよね？\\n膝枕してあげる！', 1, 1, 2, 0, 0, 101801, 2, 659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テストがんばったね～\\nご褒美に先生が\\n特別な授業\\nしてあげるね？', 1, 1, 2, 0, 0, 101801, 3, 660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院の外でも\\n私は君の先生よ\\nなんでも聞いてね♪', 1, 1, 2, 0, 0, 101801, 4, 661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今読んでるのは\\nヒロインが年下の子と\\n恋に落ちる話…あ、\\n深い意味はないのよ～', 4, 1, 2, 0, 0, 101801, 101, 662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('生徒は全員可愛いけど\\n君は少し特別…\\nみんなには内緒よ？', 8, 1, 2, 0, 0, 101801, 102, 663);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学校に\\n遅刻しないように\\n早く準備しないとね', 1, 1, 2, 0, 1, 101801, 1, 664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の子といっしょに\\nお弁当を食べるの、\\n夢なんだ～', 1, 1, 2, 0, 2, 101801, 2, 665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日の予習はやった？\\n先生も手伝うから\\n寝る前にやりましょ♪', 1, 1, 2, 0, 3, 101801, 3, 666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして…\\n少し露出多いかしら？', 1, 1, 3, 0, 0, 101801, 1, 667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスすると\\nα波が出て、勉強が\\nはかどるんですって', 1, 1, 3, 0, 0, 101801, 2, 668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\u3000あなたも\\n私の生徒になる？', 1, 1, 3, 0, 0, 101801, 3, 669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院にもこういう\\n安らぐ設備が\\n必要かしらね？', 1, 1, 3, 0, 0, 101801, 4, 670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ寒いわぁ\\n誰か隣に\\n来てくれたら…', 1, 1, 3, 0, 0, 101801, 5, 671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動部の顧問も\\nできるかしら？', 1, 1, 3, 0, 0, 101801, 6, 672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学校の給食でも\\n食べたいわぁ～', 1, 1, 3, 0, 0, 101801, 7, 673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい参考書を\\n見つけちゃった♪', 1, 1, 3, 0, 0, 101801, 8, 674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の生徒に\\n不良なんていないわ\\nみーんないい子♪', 1, 1, 1, 0, 0, 101802, 1, 676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお部屋\\n女の子ばかりね\\n魔族の女子校を\\n思い出しちゃう♪', 1, 1, 1, 0, 0, 101802, 2, 677);
