insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわふわ～モコモコ～\\n気持ちいい～♪\\nミミもゴロゴロ～ン♪', 1, 1, 3, 0, 0, 102002, 2, 743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ～かわいい～♪\\nミミ、幸せ～♪\\n抱きついていいかな？', 1, 1, 3, 0, 0, 102002, 3, 744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいにおい～♪\\nお鼻ピクピク♪\\nうさぎさんも喜ぶよ～♪', 1, 1, 3, 0, 0, 102002, 4, 745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～♪\\nぬくぬく～♪\\nポカポカ～♪', 1, 1, 3, 0, 0, 102002, 5, 746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁはぁ…\\nふえ～ミミ\\n疲れちゃうよ～！', 1, 1, 3, 0, 0, 102002, 6, 747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむ♪\u3000いっぱい\\n食べて、はやく\\nおっきくなりたいな～', 1, 1, 3, 0, 0, 102002, 7, 748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミね！\\nこのお話だーい好き！', 1, 1, 3, 0, 0, 102002, 8, 749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぅぅ…\\n部屋のどこにいたら\\nいいんだろう…', 1, 1, 1, 0, 0, 102101, 1, 751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お外より\\nお部屋の中の方が\\n落ち着くな…', 1, 1, 1, 0, 0, 102101, 2, 752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クッキー焼いたら\\nみんな食べてくれる\\nかなぁ…', 1, 1, 1, 0, 0, 102101, 3, 753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あめんぼあかいな\\nあいうえお！', 1, 1, 1, 0, 0, 102101, 4, 754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お芝居には\\n人間観察が大事…\\nじーーーーーー…', 1, 1, 1, 0, 0, 102101, 5, 755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんを見ると、\\n顔が赤くなっちゃうの\\n…な、なんでかな？', 4, 1, 1, 0, 0, 102101, 101, 756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('れ、恋愛劇…\\nお、お兄ちゃんと\\n練習…', 8, 1, 1, 0, 0, 102101, 102, 757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、この本、とっても\\nおもしろいんですよ♪', 1, 1, 2, 0, 0, 102101, 1, 758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、一緒に遊んで\\nくれるんですか？\\nや、やったぁ～♪', 1, 1, 2, 0, 0, 102101, 2, 759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソルには\\n慣れましたか？\\nわ、私はまだ…', 1, 1, 2, 0, 0, 102101, 3, 760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、お兄ちゃん、\\nお、お話の練習に\\n付き合って欲しいです', 1, 1, 2, 0, 0, 102101, 4, 761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リボンがかわいい？\\nほ、ほぇぇぇ～～\\nは、恥ずかしいですぅ', 4, 1, 2, 0, 0, 102101, 101, 762);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん…♪\\nえへへ、呼んでみた\\nだけです…♪', 8, 1, 2, 0, 0, 102101, 102, 763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は一日、\\n恥ずかしがらずに\\n過ごせるかなあ…？', 1, 1, 2, 0, 1, 102101, 1, 764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯、どうぞ♪\\nわ、私、お料理、\\nうまくなったかな？', 1, 1, 2, 0, 2, 102101, 2, 765);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんが\\n帰ってくるまで、\\nがんばって\\n起きてました', 1, 1, 2, 0, 3, 102101, 3, 766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い女の子に変身！\\n出来ますように…♪', 1, 1, 3, 0, 0, 102101, 1, 767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかで\\nあったかくて…\\nお兄ちゃんみたい♪', 1, 1, 3, 0, 0, 102101, 2, 768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子を相手に、\\n演技の練習～', 1, 1, 3, 0, 0, 102101, 3, 769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リボンや服に\\n染み込ませておこう。\\nいつでもいい匂い♪', 1, 1, 3, 0, 0, 102101, 4, 770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ。\\nぽっかぽかです…', 1, 1, 3, 0, 0, 102101, 5, 771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁはぁ…\\nふひぃ…\\nはうぅぅぅ～～', 1, 1, 3, 0, 0, 102101, 6, 772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…えへへ、\\n美味しいものを\\n食べてると幸せです', 1, 1, 3, 0, 0, 102101, 7, 773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戯曲を読んで\\n自分が演じるところを\\n想像するの…', 1, 1, 3, 0, 0, 102101, 8, 774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいものを\\nこうして並べて…\\nはぁ…落ちつくぅ♪', 1, 1, 1, 0, 0, 102102, 1, 776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～、この部屋は\\n時間がゆったりと\\n流れてるみたい', 1, 1, 1, 0, 0, 102102, 2, 777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この台本、感動…\\n涙が止まらないよぉ\\nいつか演じてみたいな', 1, 1, 1, 0, 0, 102102, 3, 778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お芝居には\\n人間観察が大事…\\nじーーーーーー…', 1, 1, 1, 0, 0, 102102, 4, 779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あえいうえおあお\\nかけきくけ、かっ…\\nむ、難しいですぅぅ', 1, 1, 1, 0, 0, 102102, 5, 780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、お腹が空いた時は\\n言ってくださいね\\nが、頑張って\\n作ります！', 8, 1, 1, 0, 0, 102102, 101, 781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('れ、恋愛劇…\\nお、お兄ちゃんと\\n練習…', 8, 1, 1, 0, 0, 102102, 102, 782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、この本、とっても\\nおもしろいんですよ♪', 1, 1, 2, 0, 0, 102102, 1, 783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと\\nいっぱい話せた日は、\\n嬉しくなっちゃいます', 1, 1, 2, 0, 0, 102102, 2, 784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か私にできる事\\n…そうだ！\\nお掃除しますね！', 1, 1, 2, 0, 0, 102102, 3, 785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、ちょっとずつ、\\n自分に自信が\\nついてきたかもです…', 1, 1, 2, 0, 0, 102102, 4, 786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リボンがかわいい？\\nほ、ほぇぇぇ～～\\nは、恥ずかしいですぅ', 8, 1, 2, 0, 0, 102102, 101, 787);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん…♪\\nえへへ、呼んでみた\\nだけです…♪', 8, 1, 2, 0, 0, 102102, 102, 788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\n声出しして、お芝居の\\n練習しなくちゃ', 1, 1, 2, 0, 1, 102102, 1, 789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お茶にしますか？\\nクッキー焼いたので、\\nよかったら…', 1, 1, 2, 0, 2, 102102, 2, 790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝る前に\\n台本を読むと、\\n覚えやすいんです', 1, 1, 2, 0, 3, 102102, 3, 791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い女の子に変身！\\n出来ますように…♪', 1, 1, 3, 0, 0, 102102, 1, 792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぅ…\\nフッカフカァ…\\n癒されちゃいます…', 1, 1, 3, 0, 0, 102102, 2, 793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子を相手に\\n演技の練習～', 1, 1, 3, 0, 0, 102102, 3, 794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リボンや服に\\n染み込ませておこう\\nいつでもいい匂い♪', 1, 1, 3, 0, 0, 102102, 4, 795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ\\nぽっかぽかです…', 1, 1, 3, 0, 0, 102102, 5, 796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、演劇には\\nた、体力も重要\\nだから～', 1, 1, 3, 0, 0, 102102, 6, 797);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('残さず\\n食べますね…！', 1, 1, 3, 0, 0, 102102, 7, 798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戯曲を読んで\\n自分が演じるところを\\n想像するの…', 1, 1, 3, 0, 0, 102102, 8, 799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、人見知りを\\n治すための練習に\\n付き合ってくれない？', 1, 1, 1, 0, 0, 102201, 1, 801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリみたいに\\nかわいくなるには、\\nどうすればいいのかな', 1, 1, 1, 0, 0, 102201, 2, 802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レアカードをゲット！\\nねえねえ、\\nすごいでしょ！？', 1, 1, 1, 0, 0, 102201, 3, 803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ア、アイツと同じ\\n部屋にいるのよね…\\nって、だから何よ！？', 1, 1, 1, 0, 0, 102201, 4, 804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽しいゲームって\\nやめどきが\\n見つからないわ', 1, 1, 1, 0, 0, 102201, 5, 805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっと女の子らしく\\nなったらアイツも\\n嬉しいかな…って、\\n何考えてるの！？', 4, 1, 1, 0, 0, 102201, 101, 806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ…最近、\\nアイツを見るとなんか\\nドキドキするのよね', 8, 1, 1, 0, 0, 102201, 102, 807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゲームに負けた罰\\nだからって、\\nくすぐるのは…\\nあはは…ダメだって！', 1, 1, 2, 0, 0, 102201, 1, 808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタと話すのは割と\\n緊張しないのよね\\n…なんでかな', 1, 1, 2, 0, 0, 102201, 2, 809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('待ちきれない…\\n新作ゲームの発売日が\\n待ちきれない…', 1, 1, 2, 0, 0, 102201, 3, 810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタは人見知り\\nしないタチよね？\\nいいなあ～…', 1, 1, 2, 0, 0, 102201, 4, 811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ア、アンタってさ\\n好きな人とかい…\\nなな、何でもない！', 4, 1, 2, 0, 0, 102201, 101, 812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタと…そ、その\\nこうして話してるのも\\nわわ、悪くないわね！', 8, 1, 2, 0, 0, 102201, 102, 813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおおおはよう！\\n…よし！\u3000ちゃんと\\nあいさつできたわ！', 1, 1, 2, 0, 1, 102201, 1, 814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にごはんとか…\\nううん、やっぱいい！\\nなんでもないからっ！', 1, 1, 2, 0, 2, 102201, 2, 815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はこれからよ！\\n朝まで\\nゲームするからね！', 1, 1, 2, 0, 3, 102201, 3, 816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリみたいに\\n可愛くなるのは\\n難しいかな', 1, 1, 3, 0, 0, 102201, 1, 817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝っ転がりながら\\nゲームができれば\\n気分が良さそう', 1, 1, 3, 0, 0, 102201, 2, 818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い…けど、\\n私には似合わないかな', 1, 1, 3, 0, 0, 102201, 3, 819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はあ、リラックスして\\nゲームができるわ', 1, 1, 3, 0, 0, 102201, 4, 820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん…暖かくて、\\n寝落ちしちゃいそう', 1, 1, 3, 0, 0, 102201, 5, 821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゲーム感覚でやると、\\n体動かすのも\\n楽しいわね', 1, 1, 3, 0, 0, 102201, 6, 822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゲームは頭使うから\\nそのぶん\\n栄養がいるのよ', 1, 1, 3, 0, 0, 102201, 7, 823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ、なるほど\\n友だちを作るには\\n笑顔が大事っと…', 1, 1, 3, 0, 0, 102201, 8, 824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ、今日は\\n何のゲームで\\n遊ぼうかな？', 1, 1, 1, 0, 0, 102202, 1, 826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にゲームができる\\n人がいるっていうのも\\n新鮮だな…', 1, 1, 1, 0, 0, 102202, 2, 827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レアカードをゲット！\\nすごいでしょ！？', 1, 1, 1, 0, 0, 102202, 3, 828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリってどうやって\\n友達作ってるんだろ？\\nコツがあるのかな…', 1, 1, 1, 0, 0, 102202, 4, 829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽しいゲームって\\nやめどきが\\n見つからないわ', 1, 1, 1, 0, 0, 102202, 5, 830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ…最近\\nアイツを見るとなんか\\nドキドキするのよね', 8, 1, 1, 0, 0, 102202, 101, 831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、ねえ\\nもう少しその…\\n一緒にゲームしない？', 8, 1, 1, 0, 0, 102202, 102, 832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、人見知りを\\n治すための練習に\\n付き合ってくれない？', 1, 1, 2, 0, 0, 102202, 1, 833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('欲しいゲームが\\n見つからなくて…\\n探すの手伝って！', 1, 1, 2, 0, 0, 102202, 2, 834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、見て！\\n新しいゲームを\\n買って来たの！', 1, 1, 2, 0, 0, 102202, 3, 835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゲームに負けた罰\\nだからって、くすぐる\\nのは…あ、あはは！\\nだ、ダメだって！', 1, 1, 2, 0, 0, 102202, 4, 836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ア、アンタってさ\\n好きな人とかい…\\nなな、何でもない！', 8, 1, 2, 0, 0, 102202, 101, 837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あのさ…\\nもう少し、そこに\\nいてくれてもいいわよ', 8, 1, 2, 0, 0, 102202, 102, 838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおおおはよう！\\n…よし！\u3000ちゃんと\\nあいさつできたわ！', 1, 1, 2, 0, 1, 102202, 1, 839);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にごはんとか…\\nううん、やっぱいい！\\nなんでもないからっ！', 1, 1, 2, 0, 2, 102202, 2, 840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はこれからよ！\\n朝まで\\nゲームするからね！', 1, 1, 2, 0, 3, 102202, 3, 841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっと女の子らしく\\nなったらアイツも\\n嬉しいかな…って、\\n何考えてるの！？', 1, 1, 3, 0, 0, 102202, 1, 842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふああ…\\n徹夜明けには\\n辛い誘惑だな…', 1, 1, 3, 0, 0, 102202, 2, 843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い…けど、\\n私には似合わないかな', 1, 1, 3, 0, 0, 102202, 3, 844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうのに詳しいと\\n女の子っぽく\\n見えたりするのかな', 1, 1, 3, 0, 0, 102202, 4, 845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒い日は\\nここでゲームするのが\\n最高のぜいたくよね', 1, 1, 3, 0, 0, 102202, 5, 846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近ゲームばかりだし\\nたまにはいいかな？', 1, 1, 3, 0, 0, 102202, 6, 847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゲームは頭使うから\\nそのぶん\\n栄養がいるのよ', 1, 1, 3, 0, 0, 102202, 7, 848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ、なるほど\\n友だちを作るには\\n笑顔が大事っと…', 1, 1, 3, 0, 0, 102202, 8, 849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じゃんけんぽん！\\nあっち向いてほい！\\nあ～ん、負けたぁ\\n\u3000『勝ったぜ！』', 1, 1, 1, 0, 0, 102301, 1, 851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちがいれば、\\nなんでも出来ちゃうよ', 1, 1, 1, 0, 0, 102301, 2, 852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('発声練習しよっと\\nぷうきち\\nフルスイ～ング！', 1, 1, 1, 0, 0, 102301, 3, 853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで、ぷうきち\\nフルスイングは、\\nまずいかな～？', 1, 1, 1, 0, 0, 102301, 4, 854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋、ぷうきちを\\n置く場所はないのかな', 1, 1, 1, 0, 0, 102301, 5, 855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんって…\\nちょっとぷうきちに\\n似てるかも♪', 4, 1, 1, 0, 0, 102301, 101, 856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんにも、\\nぷうきちのこと\\n好きになって\\nもらいたいな～', 8, 1, 1, 0, 0, 102301, 102, 857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやつは、\\n私とぷうきちの\\n二人分用意してね♪', 1, 1, 2, 0, 0, 102301, 1, 858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちが、お腹\\nペコペコだって～\\n何かちょうだい！', 1, 1, 2, 0, 0, 102301, 2, 859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『アヤネに手出したら\\n…坊ちゃんでも、\\n分かってんな？』', 1, 1, 2, 0, 0, 102301, 3, 860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちとの\\n連携を磨いてるの！\\nもっと仲良くなるよ！', 1, 1, 2, 0, 0, 102301, 4, 861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特別だからね？\\nもっと触っていいよ\\n…ぷうきちのこと', 4, 1, 2, 0, 0, 102301, 101, 862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんのこと、\\n「ぷう兄」って\\n呼ぼうかな？', 8, 1, 2, 0, 0, 102301, 102, 863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんって\\n朝早いんだね～\\n私はまだ眠いよ～', 1, 1, 2, 0, 1, 102301, 1, 864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～…ぷうきちと\\nお昼寝してくるね…', 1, 1, 2, 0, 2, 102301, 2, 865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちと\\nおしゃべりしてたら\\nもうこんな時間…', 1, 1, 2, 0, 3, 102301, 3, 866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『座り心地がいいな』\\nぷうきちは座れない\\nでしょ？', 1, 1, 3, 0, 0, 102301, 2, 868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい～！\\nぷうきちのお友達に\\nしちゃおうかな？', 1, 1, 3, 0, 0, 102301, 3, 869);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいニオイ～♪\\nぷうきちも\\n気に入ったみたい！', 1, 1, 3, 0, 0, 102301, 4, 870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽわぽわする～\\nぷうきちも\\n気持ちいい？', 1, 1, 3, 0, 0, 102301, 5, 871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい～\\nぷうきちも\\n食べてみる？', 1, 1, 3, 0, 0, 102301, 7, 873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきち！\\nこの本、読んで～！', 1, 1, 3, 0, 0, 102301, 8, 874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうして失敗ばっかり\\nこうなったら\\n腹を切るしか～！', 1, 1, 1, 0, 0, 102501, 1, 901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あれ？\u3000あれ？\\nお部屋の中で迷子に\\nなっちゃいました～', 1, 1, 1, 0, 0, 102501, 2, 902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたら転ばなく\\nなるんでしょうか？', 1, 1, 1, 0, 0, 102501, 3, 903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わわわわ～～っ\\nふう…\\nきゃ、きゃあっ！', 1, 1, 1, 0, 0, 102501, 4, 904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私のドジで、\\nこのお部屋を\\n壊しちゃったら\\nどうしましょう～～', 1, 1, 1, 0, 0, 102501, 5, 905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい料理で\\nお出迎えしなくちゃ！', 4, 1, 1, 0, 0, 102501, 101, 906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一生懸命\\nご奉仕しますよ～♪', 8, 1, 1, 0, 0, 102501, 102, 907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('耳かきしましょうか？\\nえ？\u3000こわい？', 1, 1, 2, 0, 0, 102501, 1, 908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お疲れでしたら、\\nお昼寝しませんか？\\n膝枕もしますよ？', 1, 1, 2, 0, 0, 102501, 2, 909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかえりなさいませ\\nご主人さま♪', 1, 1, 2, 0, 0, 102501, 3, 910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すみません\\nすみません\\nすみません～～', 1, 1, 2, 0, 0, 102501, 4, 911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メイドの私が、\\nこんな気持ちを持って\\nいいんでしょうか…', 4, 1, 2, 0, 0, 102501, 101, 912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私のこと、\\n専属メイドと思って\\n頼ってくださいね', 8, 1, 2, 0, 0, 102501, 102, 913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\n今日も一日がんば…\\nきゃ、きゃあ！', 1, 1, 2, 0, 1, 102501, 1, 914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはん…\\n失敗しちゃいましたぁ\\nお、おやつでリベンジします！', 1, 1, 2, 0, 2, 102501, 2, 915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日の目標は\\nドジをしないです！\\nき、昨日の目標も\\nドジをしないでした', 1, 1, 2, 0, 3, 102501, 3, 916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、メイド服が\\nほつれてる\\n後でお裁縫しなくちゃ', 1, 1, 3, 0, 0, 102501, 1, 917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩が終わったら\\nお洗濯にお料理に\\nお掃除もしないと！', 1, 1, 3, 0, 0, 102501, 2, 918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\nあとでお洗濯\\nしてあげますね', 1, 1, 3, 0, 0, 102501, 3, 919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\nお嬢様のお部屋にも\\n置いてあげたいです', 1, 1, 3, 0, 0, 102501, 4, 920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでお洗濯ものを\\n乾かしましょうか', 1, 1, 3, 0, 0, 102501, 5, 921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あわわわっ…\\nこ、転びそうです～！', 1, 1, 3, 0, 0, 102501, 6, 922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これくらい\\nおいしいものを\\n作ってみたいです～', 1, 1, 3, 0, 0, 102501, 7, 923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物語のメイドさんって\\n御主人さまを好きに\\nなるんですよね…', 1, 1, 3, 0, 0, 102501, 8, 924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('失敗したら、この\\nお部屋追い出され\\nちゃうかも～？', 1, 1, 1, 0, 0, 102502, 1, 926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あれ？\u3000あれ？\\nお部屋の中で迷子に\\nなっちゃいました～', 1, 1, 1, 0, 0, 102502, 2, 927);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうやったら、立派な\\nメイドになれるのかな', 1, 1, 1, 0, 0, 102502, 3, 928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('塩にはＳマーク\\n砂糖にはＳマーク\\n…あ、あれ！？', 1, 1, 1, 0, 0, 102502, 4, 929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご用があれば\\nなんでも言って\\nくださいね', 1, 1, 1, 0, 0, 102502, 5, 930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('迷惑をかけすぎて…\\n嫌われちゃったら\\nどうしましょう', 8, 1, 1, 0, 0, 102502, 101, 931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メイドの私が\\nこんな気持ちを持って\\nいいんでしょうか…\u3000', 8, 1, 1, 0, 0, 102502, 102, 932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おでかけですか？\\nいってらっしゃいませ\\nご主人さま♪', 1, 1, 2, 0, 0, 102502, 1, 933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうして失敗ばっかり\\nこうなったら\\n腹を切るしか～！', 1, 1, 2, 0, 0, 102502, 2, 934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、またなにか\\nやっちゃいましたか？', 1, 1, 2, 0, 0, 102502, 3, 935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいお茶っ葉が\\n手に入りました～♪\\n一緒に飲みませんか？', 1, 1, 2, 0, 0, 102502, 4, 936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('転んだふりであの人に\\n…って！\\nなんでもないですよ！', 8, 1, 2, 0, 0, 102502, 101, 937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、できることなら\\nなんでもやりますよ\\nあなたのためですから', 8, 1, 2, 0, 0, 102502, 102, 938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\n今日も一日がんば…\\nう、うわあ！', 1, 1, 2, 0, 1, 102502, 1, 939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはん…\\n失敗しちゃいましたぁ\\nお、おやつでリベンジします！', 1, 1, 2, 0, 2, 102502, 2, 940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日の目標は\\nドジをしないです！\\nき、昨日の目標も\\nドジをしないでした', 1, 1, 2, 0, 3, 102502, 3, 941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、メイド服が\\nほつれてる\\n後でお裁縫しなくちゃ', 1, 1, 3, 0, 0, 102502, 1, 942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい座り心地です～\\nこれならお嬢さまも\\nゆったりできますね♪', 1, 1, 3, 0, 0, 102502, 2, 943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\nあとでお洗濯\\nしてあげますね', 1, 1, 3, 0, 0, 102502, 3, 944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\nお嬢様のお部屋にも\\n置いてあげたいです', 1, 1, 3, 0, 0, 102502, 4, 945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かいですけど\\n…私が火に近づいて\\n大丈夫でしょうか！？', 1, 1, 3, 0, 0, 102502, 5, 946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動しようとすると\\nいつも怪我するん\\nですよね…', 1, 1, 3, 0, 0, 102502, 6, 947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなに美味しいもの\\nメイドの私には\\nもったいないです～！', 1, 1, 3, 0, 0, 102502, 7, 948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物語のメイドさんって\\n御主人さまを好きに\\nなるんですよね…', 1, 1, 3, 0, 0, 102502, 8, 949);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの方と私だけの\\n部屋にしたいですわ', 1, 1, 1, 0, 0, 102701, 1, 951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの方は私のもの…\\n眼も耳も鼻も口も髪も\\n首も胸も腰も手も脚も\\nぬくもりも心も…！', 1, 1, 1, 0, 0, 102701, 2, 952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運命とは決して\\n抗えないもの…\\nクスクス…クスクス', 1, 1, 1, 0, 0, 102701, 3, 953);
