insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この薬は起床時就寝前\\n食前食後食間に、毎日\\n服用してください。\\n惚れ薬ですわ', 1, 1, 2, 0, 0, 102701, 2, 959);
