insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇあんた、どこか\\n安いお店知らない？', 1, 1, 2, 0, 0, 102801, 1, 1008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたし、エレガントに\\n振る舞えてる？\\n…そう？\u3000嬉しい♪', 1, 1, 2, 0, 0, 102801, 2, 1009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい働いて遊んで\\nよく休んでまた働く。\\nそれが健全な生活よね', 1, 1, 2, 0, 0, 102801, 3, 1010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒に部屋の\\n整頓でもする？\\nハマると楽しいわよ♪', 1, 1, 2, 0, 0, 102801, 4, 1011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたがいると\\n子供たちも喜ぶわ♪\\nもちろんあたしもね！', 4, 1, 2, 0, 0, 102801, 101, 1012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、あんた今、幸せ？\\n何びっくりしてるのよ\\n大事なことじゃないの', 8, 1, 2, 0, 0, 102801, 102, 1013);
