insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午後のティータイム\\nとかどう？\\n良いカフェがあるの♪', 1, 1, 2, 0, 2, 102801, 2, 1015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ、エレガントな夜を\\n楽しみましょ。\\nモダンな音楽でも\\nかけましょうか？', 1, 1, 2, 0, 3, 102801, 3, 1016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レディたるもの\\n身嗜みはしっかりとね\\n見本にならないと♪', 1, 1, 3, 0, 0, 102801, 1, 1017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで仕事は一段落ね\\nちょっと休憩…', 1, 1, 3, 0, 0, 102801, 2, 1018);
