insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('面倒な用事は午前中に\\n片づけてしまうのが\\n時間の使い方のコツよ', 1, 1, 2, 0, 1, 102802, 1, 1039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランチにして午後の\\n仕事に備えましょ！\\nやることは一杯よ♪', 1, 1, 2, 0, 2, 102802, 2, 1040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ～\\nもうこんな時間\\n子供たちは\\nもう寝たかしら', 1, 1, 2, 0, 3, 102802, 3, 1041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('忙しい時こそ\\n身だしなみは隙なく\\nぴしっとね！', 1, 1, 3, 0, 0, 102802, 1, 1042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで仕事は一段落ね\\nちょっと休憩…', 1, 1, 3, 0, 0, 102802, 2, 1043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふふ\\nずっと眺めてたく\\nなっちゃうわね', 1, 1, 3, 0, 0, 102802, 3, 1044);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋中がいい香り…\\nなんだかすごい贅沢\\nしてる気分♪', 1, 1, 3, 0, 0, 102802, 4, 1045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風邪を引かないように\\n身体を温めなくちゃ', 1, 1, 3, 0, 0, 102802, 5, 1046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっ！\u3000家の中でも\\n効率的に\\nトレーニングよ！', 1, 1, 3, 0, 0, 102802, 6, 1047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり食べて\\n栄養補給、栄養補給！', 1, 1, 3, 0, 0, 102802, 7, 1048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知識から過去を学んで\\n未来に活かすわよ', 1, 1, 3, 0, 0, 102802, 8, 1049);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い子が\\nいっぱいいるなぁ…\\n誰か私とユニット\\n組んでくれないかな？', 1, 1, 1, 0, 0, 102901, 1, 1051);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度のライブ会場、\\nいつもより大きいから\\n楽しみなんだ～！', 1, 1, 1, 0, 0, 102901, 2, 1052);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新曲の衣装、もうすぐ\\n出来あがるんだって！\\n楽しみだな～', 1, 1, 1, 0, 0, 102901, 3, 1053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼とデュエット\\nしてみたいな～♪', 1, 1, 1, 0, 0, 102901, 4, 1054);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キラキラ無病息災、\\nドキドキ一日一善…\\n作詞って難しい～', 1, 1, 1, 0, 0, 102901, 5, 1055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ファンはもちろん\\n大事だけど…\\n彼のことは、もっと\\n大切にしたいな…', 4, 1, 1, 0, 0, 102901, 101, 1056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('写真集見なくても、\\n本物がここに\\nいるのにな～', 8, 1, 1, 0, 0, 102901, 102, 1057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('握手会の練習、\\n付き合ってくれない？', 1, 1, 2, 0, 0, 102901, 1, 1058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('写真集のポーズ\\n練習中～！\\nど、どうかな？', 1, 1, 2, 0, 0, 102901, 2, 1059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何て書いてあるか\\n読めないって？\\nもー！\\nこれは私のサイン！', 1, 1, 2, 0, 0, 102901, 3, 1060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、次のライブ\\n観に来てくれる？\\nいい席とっとくから！', 1, 1, 2, 0, 0, 102901, 4, 1061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、台本読むの\\nつきあってくれる？\\n恋人役に\\nなってほしいんだ', 4, 1, 2, 0, 0, 102901, 101, 1062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新曲、聞いてくれた？\\nキミとのことを\\nテーマにしたんだよ。\\nどこかは秘密だけど♪', 8, 1, 2, 0, 0, 102901, 102, 1063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の発声練習に\\n行くけど、キミも\\n一緒に来ない？', 1, 1, 2, 0, 1, 102901, 1, 1064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この時間は\\nお腹すくけど…\\n水着撮影があるから\\nお昼抜いてるんだ', 1, 1, 2, 0, 2, 102901, 2, 1065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の帳が二人を包み\\n…こういう方向性の\\n歌詞も悪くないなぁ。', 1, 1, 2, 0, 3, 102901, 3, 1066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身だしなみオッケー！\\nアイドルはいつでも\\n完璧でいなくちゃ！', 1, 1, 3, 0, 0, 102901, 1, 1067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…\\nこんな姿、ファンには\\n見せられないな～', 1, 1, 3, 0, 0, 102901, 2, 1068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい～♪\\nこれは強力な\\nライバル登場かな！', 1, 1, 3, 0, 0, 102901, 3, 1069);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ステキな香り～♪\\n歌詞のイメージが\\n浮かんできそう！', 1, 1, 3, 0, 0, 102901, 4, 1070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体も暖まったし！\\nダンスレッスンに\\n行こうかな♪', 1, 1, 3, 0, 0, 102901, 5, 1071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ベストタイム更新！\\nライブに向けて\\n体力つけないと…', 1, 1, 3, 0, 0, 102901, 6, 1072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('太っちゃったら\\nどうしよう…？\\nでも手が止まらない～', 1, 1, 3, 0, 0, 102901, 7, 1073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ステキなお話…\\n新曲の作詞の\\n参考になりそう♪', 1, 1, 3, 0, 0, 102901, 8, 1074);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお部屋すてき！\\nファンに追われた時の\\n隠れ家にピッタリね！', 1, 1, 1, 0, 0, 102902, 1, 1076);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろイメチェン\\nしてみようかな…\\nそれともこの路線で\\nもう少し…？', 1, 1, 1, 0, 0, 102902, 2, 1077);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんながくれた\\nファンレター…\\n私の大事な宝物…', 1, 1, 1, 0, 0, 102902, 3, 1078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼とデュエット\\nしてみたいな～♪', 1, 1, 1, 0, 0, 102902, 4, 1079);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('疾風怒濤、威風堂々\\n獅子奮迅、唯我独尊…\\nラブソングの作詞って\\n難しいな～', 1, 1, 1, 0, 0, 102902, 5, 1080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ファンはもちろん\\n大事だけど…\\n彼のことは、もっと\\n大切にしたいな…', 8, 1, 1, 0, 0, 102902, 101, 1081);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トップアイドルの\\nさらに先…\\n彼とならその景色も\\n見られるかな', 8, 1, 1, 0, 0, 102902, 102, 1082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新曲の衣装、もうすぐ\\n出来あがるんだって！\\n楽しみだな～', 1, 1, 2, 0, 0, 102902, 1, 1083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルノゾミだけ\\nじゃなくて、私の事も\\nちゃんと見てね？', 1, 1, 2, 0, 0, 102902, 2, 1084);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミに響かないなら\\nファンにも響くわけ\\nないよ！\u3000練習練習！', 1, 1, 2, 0, 0, 102902, 3, 1085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('衣装のスカートは\\n鉄壁なんだよ！\\n残念でした～', 1, 1, 2, 0, 0, 102902, 4, 1086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新曲、聞いてくれた？\\nキミとのことを\\nテーマにしたんだよ\\nどこかは秘密だけど♪', 8, 1, 2, 0, 0, 102902, 101, 1087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、私がトップ\\nアイドルになっても\\nちゃんと隣にいてね\\n遠くに行かないでね？', 8, 1, 2, 0, 0, 102902, 102, 1088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の発声練習に\\n行くけど、キミも\\n一緒に来ない？', 1, 1, 2, 0, 1, 102902, 1, 1089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはん行かない？\\n誰にも知られてない\\nお店があるんだけど！', 1, 1, 2, 0, 2, 102902, 2, 1090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の帳が二人を包み\\n…こういう方向性の\\n歌詞も悪くないなぁ', 1, 1, 2, 0, 3, 102902, 3, 1091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身だしなみオッケー！\\nアイドルはいつでも\\n完璧でいなくちゃ！', 1, 1, 3, 0, 0, 102902, 1, 1092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…\\nこんな姿、ファンには\\n見せられないな～', 1, 1, 3, 0, 0, 102902, 2, 1093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい～♪\\nこれは強力な\\nライバル登場かな！', 1, 1, 3, 0, 0, 102902, 3, 1094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなのイメージする\\nアイドルの香りは\\nこんな感じかな～', 1, 1, 3, 0, 0, 102902, 4, 1095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体も暖まったし！\\nダンスレッスンに\\n行こうかな♪', 1, 1, 3, 0, 0, 102902, 5, 1096);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ベストタイム更新！\\nライブに向けて\\n体力つけないと…', 1, 1, 3, 0, 0, 102902, 6, 1097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('太っちゃったら\\nどうしよう…？\\nでも手が止まらない～', 1, 1, 3, 0, 0, 102902, 7, 1098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この恋愛小説ステキ！\\n私もアイドルじゃ\\nなかったら…', 1, 1, 3, 0, 0, 102902, 8, 1099);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手裏剣の数が\\n合わないデス！\\nどこかに落とした\\nデスか…？', 1, 1, 1, 0, 0, 103001, 1, 1101);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クセモノ、隠れても\\nむだデス！\\n…気のせいデシタ', 1, 1, 1, 0, 0, 103001, 2, 1102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('金は天下の\\nマワリモノ！\\nところで、\\nどういう意味デス？', 1, 1, 1, 0, 0, 103001, 3, 1103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむ、アクダイカンの\\n気配がするデース', 1, 1, 1, 0, 0, 103001, 4, 1104);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クニトリ合戦、\\n楽しみデース！', 1, 1, 1, 0, 0, 103001, 5, 1105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンと\\n出会えて、\\nワタシは果報者デス！', 4, 1, 1, 0, 0, 103001, 101, 1106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、ショーグンの\\nそばにいると\\nドキドキするデス…', 8, 1, 1, 0, 0, 103001, 102, 1107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんでも\\n命令するデス！\\nショーグンの命は\\n絶対デス！', 1, 1, 2, 0, 0, 103001, 1, 1108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、ショーグン、\\n出陣はいつで\\nゴザルデス！？', 1, 1, 2, 0, 0, 103001, 2, 1109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ、さすが\\nショーグンデス…\\nいつの間に背後を！？', 1, 1, 2, 0, 0, 103001, 3, 1110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('出陣の合図に\\n備えるデス！\\nほら貝は\\nどこデスか！？', 1, 1, 2, 0, 0, 103001, 4, 1111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見つめられると\\nドキドキするデス…\\n新しい忍法デスか？', 4, 1, 2, 0, 0, 103001, 101, 1112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグン！\\nえへへ…これからも\\nおそばに置いて\\nクダサイね？', 8, 1, 2, 0, 0, 103001, 102, 1113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようデス！\\n今日も一日\\n忍法日和デス！', 1, 1, 2, 0, 1, 103001, 1, 1114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろお腹\\n空いてきたデス。\\n昼ごはんにするデス！', 1, 1, 2, 0, 2, 103001, 2, 1115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日もきっと\\nいい日デスよ、\\nショーグン！', 1, 1, 2, 0, 3, 103001, 3, 1116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょんまげに\\nしてみるのも\\n面白いかもデス！', 1, 1, 3, 0, 0, 103001, 1, 1117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よくて\\n眠くなってきマス…\\nもしやテキコクの\\n罠デスか！？', 1, 1, 3, 0, 0, 103001, 2, 1118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを変わり身の\\n術に…かわいそう\\nだから止めるデス', 1, 1, 3, 0, 0, 103001, 3, 1119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワビサビというもの\\nデスね！\\n素晴らしいデス！', 1, 1, 3, 0, 0, 103001, 4, 1120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身体を暖めて\\nイクサに向かうデス！', 1, 1, 3, 0, 0, 103001, 5, 1121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アクロバットな忍法を\\n使うには、体を\\n鍛えないと危険デス！', 1, 1, 3, 0, 0, 103001, 6, 1122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、\\n美味しいデス…\\n幸せデス～', 1, 1, 3, 0, 0, 103001, 7, 1123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…\\nＢＵＳＨＩＤＯ…\\nデスか？', 1, 1, 3, 0, 0, 103001, 8, 1124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふんふ～ん\\n武器の手入れは\\n念入りにしマスよ～', 1, 1, 1, 0, 0, 103002, 1, 1126);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クセモノ、隠れても\\nむだデス！\\n…気のせいデシタ', 1, 1, 1, 0, 0, 103002, 2, 1127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('金は天下の\\nマワリモノ！\\nところで\\nどういう意味デス？', 1, 1, 1, 0, 0, 103002, 3, 1128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむ、アクダイカンの\\n気配がするデース', 1, 1, 1, 0, 0, 103002, 4, 1129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クニトリ合戦\\n楽しみデース！', 1, 1, 1, 0, 0, 103002, 5, 1130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、ショーグンの\\nそばにいると\\nドキドキするデス…', 8, 1, 1, 0, 0, 103002, 101, 1131);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンの身は\\n何があってもワタシが\\n守るデス！', 8, 1, 1, 0, 0, 103002, 102, 1132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、ショーグン\\n出陣はいつで\\nゴザルデス！？', 1, 1, 2, 0, 0, 103002, 1, 1133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イクサの前に\\nホネ休めも大事デスよ\\nゆっくりするデース！', 1, 1, 2, 0, 0, 103002, 2, 1134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ、さすがショーグン\\nデス…いつの間に\\n背後を！？', 1, 1, 2, 0, 0, 103002, 3, 1135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒に忍法考える\\nデス！\\nショーグン用の\\n忍法も必要デスね！', 1, 1, 2, 0, 0, 103002, 4, 1136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見つめられると\\nドキドキするデス…\\n新しい忍法デスか？', 8, 1, 2, 0, 0, 103002, 101, 1137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグン！\\nえへへ…これからも\\nおそばに置いて\\nクダサイね？', 8, 1, 2, 0, 0, 103002, 102, 1138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい朝デス！\\nトーゴク風の朝ゴハン\\n作るデス！', 1, 1, 2, 0, 1, 103002, 1, 1139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうお昼デス\\nお昼寝するデスか？', 1, 1, 2, 0, 2, 103002, 2, 1140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろおネム\\nデース…\\n一緒に寝るデス？', 1, 1, 2, 0, 3, 103002, 3, 1141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服の乱れは心の乱れ\\nデス！\u3000きっちり\\nしないといけないデス', 1, 1, 3, 0, 0, 103002, 1, 1142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よくて眠く\\nなってきマス…\\nもしやテキコクの\\n罠デスか！？', 1, 1, 3, 0, 0, 103002, 2, 1143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを変わり身の\\n術に…かわいそう\\nだから止めるデス', 1, 1, 3, 0, 0, 103002, 3, 1144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワビサビというもの\\nデスね！\\n素晴らしいデス！', 1, 1, 3, 0, 0, 103002, 4, 1145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身体を暖めてイクサに\\n向かうデス！', 1, 1, 3, 0, 0, 103002, 5, 1146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンのお役に\\n立つため、修行\\nあるのみデス！', 1, 1, 3, 0, 0, 103002, 6, 1147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味しいデス…\\n酢昆布を和えて\\nみたいデス', 1, 1, 3, 0, 0, 103002, 7, 1148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物事を知って\\n来たるべきイクサに\\n活かすデス', 1, 1, 3, 0, 0, 103002, 8, 1149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、そろそろ\\n子離れを…しない？\\nそうですか…', 1, 1, 1, 0, 0, 103101, 1, 1151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父は、いつも男性に\\nきびしいですね', 1, 1, 1, 0, 0, 103101, 2, 1152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('占ってほしい人は、\\nいつでも言って\\nください', 1, 1, 1, 0, 0, 103101, 3, 1153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの手相は…\\nて、手を握るのって\\n緊張しますね', 1, 1, 1, 0, 0, 103101, 4, 1154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋、風水的にも\\n運気が上がりそうです', 1, 1, 1, 0, 0, 103101, 5, 1155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人とのこと占って\\nみようかな…\\n好き…嫌い…\\n好き♪…き、嫌い', 4, 1, 1, 0, 0, 103101, 101, 1156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私との相性ですか？\\nそれなら占う必要は\\nありませんよ…\\nふふっ♪', 8, 1, 1, 0, 0, 103101, 102, 1157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女難の相が\\n出ていますね…\\n気をつけてください', 1, 1, 2, 0, 0, 103101, 1, 1158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のあなたの運勢は\\n大きょ…\\n大吉です', 1, 1, 2, 0, 0, 103101, 2, 1159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父と散歩中です。\\n毎日決まったコースを\\n散歩させないと、\\nストレスが溜まるので', 1, 1, 2, 0, 0, 103101, 3, 1160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小僧！\\nシノブに触るとは\\nいい度胸じゃねぇか！', 1, 1, 2, 0, 0, 103101, 4, 1161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたに触られると、\\n動悸が早くなります\\nもしかして心霊現象？', 4, 1, 2, 0, 0, 103101, 101, 1162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もたくさんの幽霊\\nに慕われていますね。\\n素敵です', 8, 1, 2, 0, 0, 103101, 102, 1163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n今日の運勢を\\n占いましょうか？', 1, 1, 2, 0, 1, 103101, 1, 1164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のラッキー\\nアイテムはドクロです\\n良ければ父を\\nお貸ししましょうか？', 1, 1, 2, 0, 2, 103101, 2, 1165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のあなたの運気は\\n最高潮でした。\\nもうすぐ今日は\\n終わりますが', 1, 1, 2, 0, 3, 103101, 3, 1166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん。\\nいつも、身だしなみに\\n気を使ってるけど、\\nあまり変わってないよ', 1, 1, 3, 0, 0, 103101, 1, 1167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休みしましょう。\\n憑かれて疲れました', 1, 1, 3, 0, 0, 103101, 2, 1168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい…\\n付喪神が宿らないかな', 1, 1, 3, 0, 0, 103101, 3, 1169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、\\nリラックスし過ぎると\\n成仏しちゃうよ？', 1, 1, 3, 0, 0, 103101, 4, 1170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいいです…\\n極楽浄土みたい…', 1, 1, 3, 0, 0, 103101, 5, 1171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁはぁ…\\nお、お父さん、\\n代わりに運動して…', 1, 1, 3, 0, 0, 103101, 6, 1172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さんも\\n食べたいの？\\n死んでるのに？', 1, 1, 3, 0, 0, 103101, 7, 1173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本…\\nもしかして予言書？', 1, 1, 3, 0, 0, 103101, 8, 1174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいる幽霊は\\nみんな幸せそうです', 1, 1, 1, 0, 0, 103102, 1, 1176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さんが\\n女の子ばかりに\\n声をかけるので\\n困っています', 1, 1, 1, 0, 0, 103102, 2, 1177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('成仏はうれしいこと\\nです…でも友達が\\n減るのは寂しいですね', 1, 1, 1, 0, 0, 103102, 3, 1178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊に好かれる人は\\n素敵な方です\\nもちろん、あなたも', 1, 1, 1, 0, 0, 103102, 4, 1179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、そろそろ\\n子離れを…しない？\\nそうですか…', 1, 1, 1, 0, 0, 103102, 5, 1180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('生きている人に\\n好かれるには、\\nどうすればいい\\nのでしょう？', 8, 1, 1, 0, 0, 103102, 101, 1181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、どうしたら\\nあの人のことを\\n認めてくれますか？', 8, 1, 1, 0, 0, 103102, 102, 1182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋、風水的にも\\n運気が上がりそうです', 1, 1, 2, 0, 0, 103102, 1, 1183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シノブには指一本\\n触れさせん！\\nガブッ！！', 1, 1, 2, 0, 0, 103102, 2, 1184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの手相は…\\nて、手を握るのって\\n緊張しますね', 1, 1, 2, 0, 0, 103102, 3, 1185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラップ音？\\nいえ、父のいびきです', 1, 1, 2, 0, 0, 103102, 4, 1186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私との相性ですか？\\nそれなら占う必要は\\nありませんよ…\\nふふっ♪', 8, 1, 2, 0, 0, 103102, 101, 1187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('前世って信じますか？\\n私とあなたは\\nもしかすると…', 8, 1, 2, 0, 0, 103102, 102, 1188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のラッキー\\nアイテムはドクロです\\n良ければ父を\\nお貸ししましょうか？', 1, 1, 2, 0, 1, 103102, 1, 1189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明るい時間は\\nあまり得意では\\nないんです…', 1, 1, 2, 0, 2, 103102, 2, 1190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜のお散歩に\\n行きませんか？\\n知り合いの幽霊に\\n挨拶して回るんです', 1, 1, 2, 0, 3, 103102, 3, 1191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん\\nいつも、身だしなみに\\n気を使ってるけど\\nあまり変わってないよ', 1, 1, 3, 0, 0, 103102, 1, 1192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うとうと…\\nあれ…\\n走馬灯が見える…', 1, 1, 3, 0, 0, 103102, 2, 1193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい…\\nお父さんみたい…', 1, 1, 3, 0, 0, 103102, 3, 1194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん\\nリラックスし過ぎると\\n成仏しちゃうよ？', 1, 1, 3, 0, 0, 103102, 4, 1195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('快適です…\\n幽霊もどんどん\\n集まってきますね…', 1, 1, 3, 0, 0, 103102, 5, 1196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁはぁ…\\nお、お父さん、\\n代わりに運動して…', 1, 1, 3, 0, 0, 103102, 6, 1197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さんの分も、\\n私が食べるね', 1, 1, 3, 0, 0, 103102, 7, 1198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本の占い\\n私の占いと違う…', 1, 1, 3, 0, 0, 103102, 8, 1199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私だって、一人で\\n買い物ぐらい\\nできますわ…きっと', 1, 1, 1, 0, 0, 103201, 1, 1201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ新しい\\n案件を始めないと\\nいけませんわね', 1, 1, 1, 0, 0, 103201, 2, 1202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一日も早く、\\n一人前の商人に\\nなりたいものです', 1, 1, 1, 0, 0, 103201, 3, 1203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('平和を買うのには\\nどれほどのお金が\\n必要なのかしら？', 1, 1, 1, 0, 0, 103201, 4, 1204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここももう少し広いと\\n落ち着くのですけど。\\n改築しませんこと？', 1, 1, 1, 0, 0, 103201, 5, 1205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの方はお金で雇った\\nわけではないのに\\n私といてくださる…', 4, 1, 1, 0, 0, 103201, 101, 1206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえ私が間違っても\\nきっとあの方が\\n正してくれますわ…', 8, 1, 1, 0, 0, 103201, 102, 1207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と、庶民向けの\\nお店へ一緒に\\n参りませんか？', 1, 1, 2, 0, 0, 103201, 1, 1208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('資産運用？\\nお幾らほど\\n増やしたいのです？', 1, 1, 2, 0, 0, 103201, 2, 1209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんぶり勘定だとよく\\n言われるのですが…\\n例えが小さすぎます！', 1, 1, 2, 0, 0, 103201, 3, 1210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お金で解決するのは\\n悪いことでは\\nありませんわよね？', 1, 1, 2, 0, 0, 103201, 4, 1211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('その、よろしければ\\n私とお散歩など\\nいかがです？', 4, 1, 2, 0, 0, 103201, 101, 1212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしあなたさまが\\n道に迷われるなら、\\n私もお供いたします！', 8, 1, 2, 0, 0, 103201, 102, 1213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きは三ルピの徳と\\n申しますが…\\nもっとお得ですわね', 1, 1, 2, 0, 1, 103201, 1, 1214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食は町の屋台で\\n立ったまま食べて\\nみたいですわ！', 1, 1, 2, 0, 2, 103201, 2, 1215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よろしければ\\nお休み前のミルクを\\n御一緒にいかが？', 1, 1, 2, 0, 3, 103201, 3, 1216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だらしない身なりでは\\n取引相手に信用して\\nいただけませんものね', 1, 1, 3, 0, 0, 103201, 1, 1217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この感触と安らぎ…\\n素晴らしい\\n費用対効果ですわ…', 1, 1, 3, 0, 0, 103201, 2, 1218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何の見返りも求めず\\nただひたすら愛でて\\nいたいのです！', 1, 1, 3, 0, 0, 103201, 3, 1219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('目に見えないものに\\nお金をかけるのが\\n真の贅沢ですわ！', 1, 1, 3, 0, 0, 103201, 4, 1220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰ひとり寒い思いを\\nしない町にするために\\n私にできる事は…', 1, 1, 3, 0, 0, 103201, 5, 1221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('健康はお金では\\n買えませんが\\n運動器具は別ですわ！', 1, 1, 3, 0, 0, 103201, 6, 1222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなか\\n美味ですわ\\nシェフはどちらに？', 1, 1, 3, 0, 0, 103201, 7, 1223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('経済の仕組みを\\nしっかりと\\n学ばなくては…', 1, 1, 3, 0, 0, 103201, 8, 1224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ新しい\\n案件を始めないと\\nいけませんわね', 1, 1, 1, 0, 0, 103202, 1, 1226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ええと、これは\\nおいくらで買ったん\\nでしたっけ？', 1, 1, 1, 0, 0, 103202, 2, 1227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お金を見せたら\\n態度が変わる人は\\n信用できませんわ', 1, 1, 1, 0, 0, 103202, 3, 1228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('地図が読めずとも\\n道に迷わない方って\\nいらっしゃるのですね', 1, 1, 1, 0, 0, 103202, 4, 1229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この狭さも\\n慣れれば\\n快適ですわ♪', 1, 1, 1, 0, 0, 103202, 5, 1230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの方はお金で雇った\\nわけではないのに\\n私といてくださる…', 8, 1, 1, 0, 0, 103202, 101, 1231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえ私が間違っても\\nきっとあの方が\\n正してくれますわ…', 8, 1, 1, 0, 0, 103202, 102, 1232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一人前の商人に\\n相応しい居振る舞いを\\nしたいものですわ', 1, 1, 2, 0, 0, 103202, 1, 1233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幼い頃\\nお店屋さんごっこを\\nなさいましたか？', 1, 1, 2, 0, 0, 103202, 2, 1234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('資産運用？\\nお幾らほど\\n増やしたいのです？', 1, 1, 2, 0, 0, 103202, 3, 1235);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度一緒に…\\nパーティにでも\\n行きませんこと？', 1, 1, 2, 0, 0, 103202, 4, 1236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('その、よろしければ\\n私とお散歩など\\nいかがです？', 8, 1, 2, 0, 0, 103202, 101, 1237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたさまの優しさは\\nお金には\\n代えられませんわね', 8, 1, 2, 0, 0, 103202, 102, 1238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なぜだか\\n眠り足りないような\\n感じがしますわ…', 1, 1, 2, 0, 1, 103202, 1, 1239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食は町の屋台で\\n立ったまま食べて\\nみたいですわ！', 1, 1, 2, 0, 2, 103202, 2, 1240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よろしければ\\nお休み前のミルクを\\n御一緒にいかが？', 1, 1, 2, 0, 3, 103202, 3, 1241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドレスは汚れていない\\nようですが…やだ\\n髪がほつれてますわ！', 1, 1, 3, 0, 0, 103202, 1, 1242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういったものに\\n腰を沈めると…\\nき、気が緩んで…', 1, 1, 3, 0, 0, 103202, 2, 1243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何の見返りも求めず\\nただひたすら愛でて\\nいたいのです！', 1, 1, 3, 0, 0, 103202, 3, 1244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りは質のいいものと\\nそうでないものが\\nはっきり分かりますわ', 1, 1, 3, 0, 0, 103202, 4, 1245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰ひとり寒い思いを\\nしない町にするために\\n私にできる事は…', 1, 1, 3, 0, 0, 103202, 5, 1246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('目標は遠くに\\n置いた方が励みに\\nなりますわ！', 1, 1, 3, 0, 0, 103202, 6, 1247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなか\\n美味ですわ\\nシェフはどちらに？', 1, 1, 3, 0, 0, 103202, 7, 1248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('商人って、物語では\\n悪役にされやすいの\\nですね…', 1, 1, 3, 0, 0, 103202, 8, 1249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('家の中のものを使って\\n物ボケ、考えるべ！', 1, 1, 1, 0, 0, 103301, 1, 1251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日の日課…それは\\n炊事、洗濯、大喜利\\nだべ！', 1, 1, 1, 0, 0, 103301, 2, 1252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちに塀ができたら、\\nへー、って言いたい！', 1, 1, 1, 0, 0, 103301, 3, 1253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オラが作る料理は\\nこの後スタッフで\\n美味しくいただくべよ', 1, 1, 1, 0, 0, 103301, 4, 1254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エリザベスも\\n連れてきてぇ～', 1, 1, 1, 0, 0, 103301, 5, 1255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんも、\\nエリザベスと同じ位\\nめんこいべ♪', 4, 1, 1, 0, 0, 103301, 101, 1256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オラとあんちゃん、\\n息がぴったりに\\nなってきたべ…！', 8, 1, 1, 0, 0, 103301, 102, 1257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おぉ！\u3000そんな急に\\nツッコまれたら、\\nびっくらこくべやー！', 1, 1, 2, 0, 0, 103301, 1, 1258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネタはオラが書くけど\\nあんちゃんが\\n書きたかったら\\n書いてもいいんだぞ？', 1, 1, 2, 0, 0, 103301, 2, 1259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃん、オラには\\n容赦なんかせずに\\nツッコんでくれて\\nいいから！', 1, 1, 2, 0, 0, 103301, 3, 1260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('押すなよ、\\n絶対押すなよ\\n…なんて\\n言ってないべさ？', 1, 1, 2, 0, 0, 103301, 4, 1261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう…あんちゃんに\\nツッコまれたくて\\nうずうずしてきたべ～', 4, 1, 2, 0, 0, 103301, 101, 1262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('将来的には夫婦漫才\\nってのも…あ、ひ、\\nひとりごとだべさ～！', 8, 1, 2, 0, 0, 103301, 102, 1263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\u3000一緒に\\n牛の乳しぼりいくべ？', 1, 1, 2, 0, 1, 103301, 1, 1264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼だ～腹が減っては\\n笑いはできぬ～！', 1, 1, 2, 0, 2, 103301, 2, 1265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もよく働いたべ！\\nさ、今からは\\nお笑いの練習だ～！', 1, 1, 2, 0, 3, 103301, 3, 1266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞台に上がる前に\\n身なりは整えねぇと\\nだめだべ～！', 1, 1, 3, 0, 0, 103301, 1, 1267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナイスなイスに\\n座りたい、\\nなんちゃって！', 1, 1, 3, 0, 0, 103301, 2, 1268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('めんこいのは、\\nスベっても許される\\nからずるいべな～？', 1, 1, 3, 0, 0, 103301, 3, 1269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('必要以上に\\n癒されちまうべや～', 1, 1, 3, 0, 0, 103301, 4, 1270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかだ…\\nウケた会場みてぇだ', 1, 1, 3, 0, 0, 103301, 5, 1271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お笑い芸人は、\\n体が資本だべさ～！', 1, 1, 3, 0, 0, 103301, 6, 1272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nボケることも\\n忘れちまう美味さだ～', 1, 1, 3, 0, 0, 103301, 7, 1273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネタ作りのヒントが\\n載ってねぇか探すべ', 1, 1, 3, 0, 0, 103301, 8, 1274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ今日も張り切って\\n漫才の練習するべさ！', 1, 1, 1, 0, 0, 103302, 1, 1276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋でも、商品\\n売っていいんだべか？', 1, 1, 1, 0, 0, 103302, 2, 1277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眼鏡を頭の上に乗せて\\n「メガネメガネ～」\\nって言う練習した方が\\nいいべか？', 1, 1, 1, 0, 0, 103302, 3, 1278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('漫才を持ち時間に\\n収めるには、何度も\\n練習するしかねぇべ', 1, 1, 1, 0, 0, 103302, 4, 1279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エリザベスも\\n連れてきてぇ～', 1, 1, 1, 0, 0, 103302, 5, 1280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう…あんちゃんに\\nツッコまれたくて\\nうずうずしてきたべ～', 8, 1, 1, 0, 0, 103302, 101, 1281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんに\\n採れたての食材を\\n食わしてやりてぇ～', 8, 1, 1, 0, 0, 103302, 102, 1282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('押すなよ\\n絶対押すなよ\\n…なんて\\n言ってないべさ？', 1, 1, 2, 0, 0, 103302, 1, 1283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃん、百連\\nツッコミ特訓だ～！', 1, 1, 2, 0, 0, 103302, 2, 1284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃん、オラには\\n容赦なんかせずに\\nツッコんでくれて\\nいいから！', 1, 1, 2, 0, 0, 103302, 3, 1285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「なんでだべ～！」\\nって言いながら\\nツッコむといいべ！', 1, 1, 2, 0, 0, 103302, 4, 1286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あはは～あんちゃんの\\nツッコミはやっぱり\\n気持ちいいなぁ～', 8, 1, 2, 0, 0, 103302, 101, 1287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('将来的には夫婦漫才\\nってのも…あ、ひ\\nひとりごとだべさ～！', 8, 1, 2, 0, 0, 103302, 102, 1288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\n今日もいい\\nネタ作り日和だ！', 1, 1, 2, 0, 1, 103302, 1, 1289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼だな\\nご飯を食べたら、\\nネタの練習するべ！', 1, 1, 2, 0, 2, 103302, 2, 1290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間だべ\\nネタ作りは\\n明日にするべ…', 1, 1, 2, 0, 3, 103302, 3, 1291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…衣装、\\nずれてねぇべか？', 1, 1, 3, 0, 0, 103302, 1, 1292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナイスなイスに\\n座りたい\\nなんちゃって！', 1, 1, 3, 0, 0, 103302, 2, 1293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はう～\\nなまらめんこいべや～', 1, 1, 3, 0, 0, 103302, 3, 1294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('必要以上に\\n癒されちまうべや～', 1, 1, 3, 0, 0, 103302, 4, 1295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('笑いをとることを\\n忘れるほど\\nあったけぇべ～', 1, 1, 3, 0, 0, 103302, 5, 1296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさん運動して\\n動きでも笑いがとれる\\nように頑張るべ～！', 1, 1, 3, 0, 0, 103302, 6, 1297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nボケることも\\n忘れちまう美味さだ～', 1, 1, 3, 0, 0, 103302, 7, 1298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幅広く教養を\\n身につけて\\nいいネタ作るべ！', 1, 1, 3, 0, 0, 103302, 8, 1299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('通りにいる\\nカップル…爆発\\nすればいいのに…', 1, 1, 1, 0, 0, 103401, 1, 1301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、仕事なんて\\nしないで、\\n飲んでたいな～', 1, 1, 1, 0, 0, 103401, 2, 1302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は一日、\\n外に出ない！\\nもう決めたわ！', 1, 1, 1, 0, 0, 103401, 3, 1303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いた…\\nけど、外に出るのは\\n面倒だなぁ', 1, 1, 1, 0, 0, 103401, 4, 1304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ…頭がガンガン\\nする…昨日、\\n飲み過ぎたかな…', 1, 1, 1, 0, 0, 103401, 5, 1305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('デートとか…\\n誘っても嫌がられ\\nないかな…？', 4, 1, 1, 0, 0, 103401, 101, 1306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして運命の\\n相手だったり…\\nするのかな', 8, 1, 1, 0, 0, 103401, 102, 1307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり一杯目が\\n一番おいしいわ～！\\n…え、見てた！？', 1, 1, 2, 0, 0, 103401, 1, 1308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頼れるお姉さんだって\\nところ、もっと見せて\\nあげるからね', 1, 1, 2, 0, 0, 103401, 2, 1309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、一緒に買い物に\\n行かない？\u3000その…\\nの、飲み物とか…', 1, 1, 2, 0, 0, 103401, 3, 1310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひっく、うふふ…\\nもっとお姉さんと\\nお話しようよ～', 1, 1, 2, 0, 0, 103401, 4, 1311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('極力人付き合いは\\nしない主義なんだけど\\nキミは例外かも…', 4, 1, 2, 0, 0, 103401, 101, 1312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか…\\nキミと一緒に飲めたら\\n楽しいだろうな', 8, 1, 2, 0, 0, 103401, 102, 1313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう…朝は\\nちょっとつらいな…\\n低血圧なのよ…', 1, 1, 2, 0, 1, 103401, 1, 1314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっひるー♪\\nなに食べよっかな～♪', 1, 1, 2, 0, 2, 103401, 2, 1315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…\\n眠る前にちょっと\\n一杯…冗談よ', 1, 1, 2, 0, 3, 103401, 3, 1316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう…\\n髪がボサボサ…\\nちゃんとしなきゃ…', 1, 1, 3, 0, 0, 103401, 1, 1317);
