insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ＢＢ団の活動日…\\nまだかな…\\nうふふふっ', 4, 1, 1, 0, 0, 104001, 101, 1406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっともっとあの人の\\nそばで、一緒に友達を\\n作っていきたいな…', 8, 1, 1, 0, 0, 104001, 102, 1407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、こんにちは！\\n今日もＢＢ団で\\nお世話になります！', 1, 1, 2, 0, 0, 104001, 1, 1408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…私の友達作りの\\n練習方法、間違って\\nませんよね…？', 1, 1, 2, 0, 0, 104001, 2, 1409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、今度、\\n森に一緒に木の苗を\\n植えに行きませんか？', 1, 1, 2, 0, 0, 104001, 3, 1410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人とお話するのって、\\n私、大好きです！\\n友達ふやすぞ～！', 1, 1, 2, 0, 0, 104001, 4, 1411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと話してると、\\nまるで私がぼっちじゃ\\nないみたいです！', 4, 1, 2, 0, 0, 104001, 101, 1412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('友達もほしいけど…\\nあなたに会えたことが\\n私の一番の幸せです', 8, 1, 2, 0, 0, 104001, 102, 1413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます！\\n今日もＢＢ団、\\nがんばるぞー！', 1, 1, 2, 0, 1, 104001, 1, 1414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか、お腹が\\n空いてきました。\\nお昼ごはんー♪', 1, 1, 2, 0, 2, 104001, 2, 1415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう眠いかもです…\\n明日は友達、\\nできるといいなあ…', 1, 1, 2, 0, 3, 104001, 3, 1416);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私がもっと\\n可愛ければ、\\n友達できるかなあ？', 1, 1, 3, 0, 0, 104001, 1, 1417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…のんびり\\nしすぎないように\\n気を付けなきゃです', 1, 1, 3, 0, 0, 104001, 2, 1418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいなあ。\\nこの子とも\\n友達になりたい…', 1, 1, 3, 0, 0, 104001, 3, 1419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りです…\\n精神統一して\\n友達のイメトレ…', 1, 1, 3, 0, 0, 104001, 4, 1420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('灯りを見てると、\\n心がなごみます～', 1, 1, 3, 0, 0, 104001, 5, 1421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nおいしいです…！\\nみなさんもぜひ！', 1, 1, 3, 0, 0, 104001, 6, 1422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいです…\\n私に友達がいたら、\\n分けてあげたいな', 1, 1, 3, 0, 0, 104001, 7, 1423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('友達作りの\\n参考になりそうなこと\\n書いてないかな～？', 1, 1, 3, 0, 0, 104001, 8, 1424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('友達作りは、焦らず\\n慌てず、じっくりと…', 1, 1, 1, 0, 0, 104002, 1, 1426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひとつ屋根の下\\nって感じ…\\nいいですねえ…', 1, 1, 1, 0, 0, 104002, 2, 1427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('煮汁、煮汁が\\n噴きこぼれて\\nいませんか～', 1, 1, 1, 0, 0, 104002, 3, 1428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、みなさんと\\nピクニックとか…\\nいってみたいな', 1, 1, 1, 0, 0, 104002, 4, 1429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼっちでもいい\\nたくましく育てば\\n…なんて', 1, 1, 1, 0, 0, 104002, 5, 1430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、毎日あの人の\\nこと考えちゃいます\\nどうしてだろう…', 8, 1, 1, 0, 0, 104002, 101, 1431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっともっとあの人の\\nそばで、一緒に友達を\\n作っていきたいな…', 8, 1, 1, 0, 0, 104002, 102, 1432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ！\u3000ＢＢ団の活動\\nですか？\u3000嬉しくて\\n飛び跳ねちゃいます！', 1, 1, 2, 0, 0, 104002, 1, 1433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたとのお話で友達\\n作りの練習になるなら\\n一石二鳥です！', 1, 1, 2, 0, 0, 104002, 2, 1434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私少しは人と話しても\\nテンパらなくなって\\nきましたかね…？', 1, 1, 2, 0, 0, 104002, 3, 1435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの、友達作りの\\n新しい作戦\\n考えてみたんですっ！', 1, 1, 2, 0, 0, 104002, 4, 1436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたとお話する時の\\nこの気持ち、私の宝物\\nなんです…えへへ', 8, 1, 2, 0, 0, 104002, 101, 1437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('友達もほしいけど…\\nあなたに会えたことが\\n私の一番の幸せです', 8, 1, 2, 0, 0, 104002, 102, 1438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ですね！\\nこんないい朝は\\n友達作りのチャンス！', 1, 1, 2, 0, 1, 104002, 1, 1439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…そろそろお腹\\nすきませんか？\\nお昼ごはんは…', 1, 1, 2, 0, 2, 104002, 2, 1440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう眠いかもです…\\n明日は友達\\nできるといいなあ…', 1, 1, 2, 0, 3, 104002, 3, 1441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私…見た目\\nそこまで変じゃ\\nないですよね…？', 1, 1, 3, 0, 0, 104002, 1, 1442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほわあ～…\\nふかふかって\\nいいものですね～', 1, 1, 3, 0, 0, 104002, 2, 1443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子みたいな\\nあいくるしさを\\n目指したいです！', 1, 1, 3, 0, 0, 104002, 3, 1444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('灯りを見てると\\n心がなごみます～', 1, 1, 3, 0, 0, 104002, 4, 1445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬくぬくで、なんだか\\n眠くなっちゃいますね', 1, 1, 3, 0, 0, 104002, 5, 1446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身体を鍛えて\\nみなさんを\\n守ります！', 1, 1, 3, 0, 0, 104002, 6, 1447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nおいしいです…！\\nみなさんもぜひ！', 1, 1, 3, 0, 0, 104002, 7, 1448);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('友達作りの\\n参考になりそうなこと\\n書いてないかな～？', 1, 1, 3, 0, 0, 104002, 8, 1449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('唱喚の歌は、みだりに\\n歌っていいものでは\\nないんです', 1, 1, 1, 0, 0, 104201, 1, 1451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでアイドルの\\n練習は、さすがに\\n迷惑ですよね？', 1, 1, 1, 0, 0, 104201, 2, 1452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('練習してもあんまり\\n疲れなくなった…\\nアイドルのおかげかな', 1, 1, 1, 0, 0, 104201, 3, 1453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人々の平和を守る旅に\\n同行してくれる人を\\n探していて…', 1, 1, 1, 0, 0, 104201, 4, 1454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あとで曲を復習して\\nおかないと…', 1, 1, 1, 0, 0, 104201, 5, 1455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('踊りを見られるのは\\nまだ恥ずかしいけど\\nあの人になら…', 4, 1, 1, 0, 0, 104201, 101, 1456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('浜辺で曲を書こうと\\n思うんですけど…\\n一緒に行きませんか？', 8, 1, 1, 0, 0, 104201, 102, 1457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつも応援ありがとう\\nございます♪\u3000これは\\nあ、握手の練習です！', 1, 1, 2, 0, 0, 104201, 1, 1458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、もう練習の時間？\\nごめんなさい\\nすぐ準備します！', 1, 1, 2, 0, 0, 104201, 2, 1459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('守るべき人たちに\\n笑顔でいてもらうのも\\n大切なんですね', 1, 1, 2, 0, 0, 104201, 3, 1460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌える曲を増やそうと\\n思って。どんな曲が\\n聞きたいですか？', 1, 1, 2, 0, 0, 104201, 4, 1461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('～～♪\u3000あれ？\\n今私、歌ってました？\\n気づきませんでした', 4, 1, 2, 0, 0, 104201, 101, 1462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…歌って欲しい？\\n喜んで♪\\nどの歌にしましょう？', 8, 1, 2, 0, 0, 104201, 102, 1463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\n少し歌の練習を\\nしてきますね', 1, 1, 2, 0, 1, 104201, 1, 1464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうお昼なんですか？\\n練習に夢中で\\n気づきませんでした', 1, 1, 2, 0, 2, 104201, 2, 1465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日の予定は…\\nアイドルはやることが\\n多いみたいで…', 1, 1, 2, 0, 3, 104201, 3, 1466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見た目については\\n前よりも気をつけてと\\nノゾミに言われてます', 1, 1, 3, 0, 0, 104201, 1, 1467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌の調子をよくする\\nためには休息も\\n必要ですよね…', 1, 1, 3, 0, 0, 104201, 2, 1468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子たちを\\n相手に練習して\\nみようかな…♪', 1, 1, 3, 0, 0, 104201, 3, 1469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…疲れてるのかな\\n落ち着けているのが\\n自分でもわかります', 1, 1, 3, 0, 0, 104201, 4, 1470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいると\\n穏やかな旋律が\\n浮かんできます…', 1, 1, 3, 0, 0, 104201, 5, 1471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌うためには\\n体力づくりは\\n欠かせません', 1, 1, 3, 0, 0, 104201, 6, 1472);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌った後は\\nお腹が空いて\\nしまうんです', 1, 1, 3, 0, 0, 104201, 7, 1473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('音楽について\\n理論も勉強\\nしないと…', 1, 1, 3, 0, 0, 104201, 8, 1474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌うことの楽しさ\\n分かってきました\\nもっと歌いたいな…', 1, 1, 1, 0, 0, 104202, 1, 1476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('練習してもあんまり\\n疲れなくなった…\\nアイドルのおかげかな', 1, 1, 1, 0, 0, 104202, 2, 1477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('精霊も強くなったし\\nもっとたくさんの人を\\n守りたいです', 1, 1, 1, 0, 0, 104202, 3, 1478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、よく頭の中に\\n歌が浮かんできます\\n不思議な感覚…', 1, 1, 1, 0, 0, 104202, 4, 1479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽譜を買いました\\n思いついた歌を\\n書き留めておくために', 1, 1, 1, 0, 0, 104202, 5, 1480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('浜辺で曲を書こうと\\n思うんですけど…\\n一緒に行きませんか？', 8, 1, 1, 0, 0, 104202, 101, 1481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の中にある\\n私だけの歌…\\n作ってみようかな？', 8, 1, 1, 0, 0, 104202, 102, 1482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('守るべき人たちに\\n笑顔でいてもらうのも\\n大切なんですね', 1, 1, 2, 0, 0, 104202, 1, 1483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌える曲を増やそうと\\n思って。どんな曲が\\n聞きたいですか？', 1, 1, 2, 0, 0, 104202, 2, 1484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔物退治ですか！？\\n…違います？\\n良かった…', 1, 1, 2, 0, 0, 104202, 3, 1485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつも応援ありがとう\\nございます♪\u3000これは\\nあ、握手の練習です！', 1, 1, 2, 0, 0, 104202, 4, 1486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…歌って欲しい？\\n喜んで♪\\nどの歌にしましょう？', 8, 1, 2, 0, 0, 104202, 101, 1487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('～～♪\u3000あれ？\\n今私、歌ってました？\\n気づきませんでした', 8, 1, 2, 0, 0, 104202, 102, 1488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呼吸を深く、大きく…\\nこれでちゃんと\\n目が覚めますよ', 1, 1, 2, 0, 1, 104202, 1, 1489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し休んだら\\n午後の練習に\\n行ってきますね', 1, 1, 2, 0, 2, 104202, 2, 1490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('曲を作っていたら\\nもうこんな時間…\\nおやすみなさい', 1, 1, 2, 0, 3, 104202, 3, 1491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見た目については\\n前よりも気をつけてと\\nノゾミに言われてます', 1, 1, 3, 0, 0, 104202, 1, 1492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ～…♪\\nよく体がほぐれます…\\nいい歌が歌えそうです', 1, 1, 3, 0, 0, 104202, 2, 1493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいと思う\\n気持ちを、歌にしても\\nいいかも知れませんね', 1, 1, 3, 0, 0, 104202, 3, 1494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…疲れてるのかな\\n落ち着けているのが\\n自分でもわかります', 1, 1, 3, 0, 0, 104202, 4, 1495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいると\\n穏やかな旋律が\\n浮かんできます…', 1, 1, 3, 0, 0, 104202, 5, 1496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっと体力をつけて\\n最高のライブを\\nファンに届けます！', 1, 1, 3, 0, 0, 104202, 6, 1497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これでも一応\\n体形には気をつけて\\n食べてるんですよ？', 1, 1, 3, 0, 0, 104202, 7, 1498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('読書は歌に\\n新しい風を\\n吹き込んでくれます', 1, 1, 3, 0, 0, 104202, 8, 1499);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('店の新メニューでも\\n考えるかな', 1, 1, 1, 0, 0, 104301, 1, 1501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの店から、\\n出前を届けようか？', 1, 1, 1, 0, 0, 104301, 2, 1502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パトロール、\\nパトロール…\\nここは異常なしかな？', 1, 1, 1, 0, 0, 104301, 3, 1503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹へったら食う！\\n悩んだら寝る！\\nそれが一番だろ？', 1, 1, 1, 0, 0, 104301, 4, 1504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('のんびりし過ぎるのも\\n…性に合わねぇな', 1, 1, 1, 0, 0, 104301, 5, 1505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろあいつ、\\n腹すかしてるん\\nじゃないかな？', 4, 1, 1, 0, 0, 104301, 101, 1506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の献立は…\\nあいつの好きなものに\\nしてやるか', 8, 1, 1, 0, 0, 104301, 102, 1507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強くなりたいなら、\\nあたしがビシバシ\\n鍛えてやるよ', 1, 1, 2, 0, 0, 104301, 1, 1508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('天気がいい日は\\n外で運動したく\\nならねぇか？', 1, 1, 2, 0, 0, 104301, 2, 1509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹減ったか？\u3000なんか\\n作ってやろうか？', 1, 1, 2, 0, 0, 104301, 3, 1510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000なんだよ、\\n相談事か？\\nなんでも言ってくれ', 1, 1, 2, 0, 0, 104301, 4, 1511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前が好きな飯って\\nなんだ？\\n今度、作ってやるよ', 4, 1, 2, 0, 0, 104301, 101, 1512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前って不思議だよな\\n一緒にいるとなんだか\\n…なんでもねーよ', 8, 1, 2, 0, 0, 104301, 102, 1513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい朝だな！\\n体を動かしたい気分だ\\n付き合ってくれるか', 1, 1, 2, 0, 1, 104301, 1, 1514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯もう食ったか？\\nまだなら、あたしが\\nなんか作ってやるよ', 1, 1, 2, 0, 2, 104301, 2, 1515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日中たっぷり動いたら\\nそのぶん夜はしっかり\\n休んどけよな', 1, 1, 2, 0, 3, 104301, 3, 1516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('た、たまにはその…\\nかわいい格好とか\\nしても…', 1, 1, 3, 0, 0, 104301, 1, 1517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ、\\n一休みすっかなぁ～', 1, 1, 3, 0, 0, 104301, 2, 1518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うっ！\u3000か、かわいい\\nじゃねぇか', 1, 1, 3, 0, 0, 104301, 3, 1519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へー\u3000いい匂いだな\\nあいつもこういうの\\n好きなのかな…', 1, 1, 3, 0, 0, 104301, 4, 1520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ〜！\\n温かいと、つい\\nウトウトしちまうな', 1, 1, 3, 0, 0, 104301, 5, 1521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オラオラオラーーー！\\n燃えるぜーーー！', 1, 1, 3, 0, 0, 104301, 6, 1522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい味してるぜ！\\nうちの店でも\\n出してみたいな', 1, 1, 3, 0, 0, 104301, 7, 1523);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('文字を読んでると\\nどうしても眠く\\nなっちまうんだよなぁ', 1, 1, 3, 0, 0, 104301, 8, 1524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パトロール終了～\\n本日も異常なしっと！', 1, 1, 1, 0, 0, 104302, 1, 1526);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの店から\\n出前を届けようか？', 1, 1, 1, 0, 0, 104302, 2, 1527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつ、早く\\n帰ってこないかな', 1, 1, 1, 0, 0, 104302, 3, 1528);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつ\\n腹すかせてないと\\nいいんだけど…', 1, 1, 1, 0, 0, 104302, 4, 1529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('のんびりし過ぎるのも\\n…性に合わねぇな', 1, 1, 1, 0, 0, 104302, 5, 1530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつの事を思うと\\n胸があったかくなる？\\nなんだコレ…？', 8, 1, 1, 0, 0, 104302, 101, 1531);
