insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのさ…できれば\\nもっとそばに…いや\\nなんでもねぇ忘れろ！', 8, 1, 2, 0, 0, 104302, 101, 1537);
