insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ～♪\\n疲れがとれるな～', 1, 1, 3, 0, 0, 104302, 2, 1543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うっ！\u3000か、かわいい\\nじゃねぇか', 1, 1, 3, 0, 0, 104302, 3, 1544);
