insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理だけじゃなく\\n経営術とかも\\n学んどかねぇと…', 1, 1, 3, 0, 0, 104302, 8, 1549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近なにも\\nしてくれません…\\n焦らしてるんですね', 1, 1, 1, 0, 0, 104501, 1, 1551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐふふ、じゅるり…\\nい、いけない、また\\nいつの間にかよだれが', 1, 1, 1, 0, 0, 104501, 2, 1552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好きな武器といえば\\n剣より槍より\\nやっぱり鞭…ぐふふ', 1, 1, 1, 0, 0, 104501, 3, 1553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「無数の触手が\\nクウカの柔肌に\\n食い込み」…ぐふふ', 1, 1, 1, 0, 0, 104501, 4, 1554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしドＳさんが\\nＭに転じたらと思うと\\n身の毛がよだちます！', 1, 1, 1, 0, 0, 104501, 5, 1555);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんを登場\\nさせるだけで、妄想に\\n無限の広がりが！', 4, 1, 1, 0, 0, 104501, 101, 1556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ…\\nジロジロ見てたの\\n気づいちゃいました？', 8, 1, 1, 0, 0, 104501, 102, 1557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('視線を感じると\\n思ったら…やはり\\nドＳさんでしたか', 1, 1, 2, 0, 0, 104501, 1, 1558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は\\nどんなヒドイことを\\nしてくれるんですか？\\nぐふふふ', 1, 1, 2, 0, 0, 104501, 2, 1559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつの間にそこに！？\\nまさかクウカを監視\\nしていたのですか！？', 1, 1, 2, 0, 0, 104501, 3, 1560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカに触るつもり\\nですか？\u3000触るつもり\\nなのですねっ！？', 1, 1, 2, 0, 0, 104501, 4, 1561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカにナニをする\\nつもりですか…\\n期待してしまいます！', 4, 1, 2, 0, 0, 104501, 101, 1562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんの視界に入る\\nだけでドキドキが…\\nこれが恋！？', 8, 1, 2, 0, 0, 104501, 102, 1563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます。\\n朝からお盛んですね？\\nぐふふ…', 1, 1, 2, 0, 1, 104501, 1, 1564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにも日の高い\\nうちからドＳさんは…\\nじゅるり', 1, 1, 2, 0, 2, 104501, 2, 1565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はこれから、\\nですよ…\\nぐふ、ぐふふふ…', 1, 1, 2, 0, 3, 104501, 3, 1566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キレイにおめかし\\nしたのに力ずくで…\\nぐふふふ', 1, 1, 3, 0, 0, 104501, 1, 1567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ソファの背にクウカを\\n押し付けて…ぐふふ\\nいいですね\\nソファドン', 1, 1, 3, 0, 0, 104501, 2, 1568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「見た目とは裏腹に\\nそれは激しく攻め\\nたてて」…ぐふふふ', 1, 1, 3, 0, 0, 104501, 3, 1569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りを吸ったクウカの\\n頬は紅潮し目はうるみ\\nもはや抗う力も…！', 1, 1, 3, 0, 0, 104501, 4, 1570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、身体が\\n火照って…\\nぐふ、ぐふふ…', 1, 1, 3, 0, 0, 104501, 5, 1571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、はぁ、こうして\\nクウカの体力を\\n奪ってから…ぐふふ', 1, 1, 3, 0, 0, 104501, 6, 1572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食欲が満たされたら\\nつ、次はやはり…！\\nそうなのですね！？', 1, 1, 3, 0, 0, 104501, 7, 1573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本の下に、\\nそういう本を\\nカムフラージュ？', 1, 1, 3, 0, 0, 104501, 8, 1574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「ドＳさんと踊り子\\n乱舞の一夜」…\\n次の日記はこれで…', 1, 1, 1, 0, 0, 104502, 1, 1576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近なにも\\nしてくれません…\\n焦らしてるんですね', 1, 1, 1, 0, 0, 104502, 2, 1577);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、妄想が\\n足りません…\\n禁断症状がっ…！', 1, 1, 1, 0, 0, 104502, 3, 1578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしドＳさんが\\nＭに転じたらと思うと\\n身の毛がよだちます！', 1, 1, 1, 0, 0, 104502, 4, 1579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどんなドＳを\\nされるのか、想像する\\nだけで…ぐふふふ', 1, 1, 1, 0, 0, 104502, 5, 1580);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じっとしてると\\nドＳさんのことばかり\\n考えてしまいますね', 8, 1, 1, 0, 0, 104502, 101, 1581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('妄想が止まらなくて\\nクウカどうにかなって\\nしまいそうです！', 8, 1, 1, 0, 0, 104502, 102, 1582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんといると体が\\n火照って…クウカは\\nいやらしい子です！', 1, 1, 2, 0, 0, 104502, 1, 1583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ…\\nジロジロ見てたの\\n気づいちゃいました？', 1, 1, 2, 0, 0, 104502, 2, 1584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんのおかげで\\n新しい扉が開けそう\\nです…じゅるり', 1, 1, 2, 0, 0, 104502, 3, 1585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いやー！\u3000ドＳさんに\\n襲われ…襲って\\nくれないんですか？', 1, 1, 2, 0, 0, 104502, 4, 1586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカはドＳさんに\\n身も心も堕とされて\\nしまったのですね', 8, 1, 2, 0, 0, 104502, 101, 1587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんがお望みなら\\nクウカは\\nどんなことだって！', 8, 1, 2, 0, 0, 104502, 102, 1588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝だからこそ\\nできる妄想が\\nあります…ぐふふ', 1, 1, 2, 0, 1, 104502, 1, 1589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな日の高いうち\\nからドＳさんは…\\nじゅるり', 1, 1, 2, 0, 2, 104502, 2, 1590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今夜は一晩中…\\nなんですね？\\nぐふふ…', 1, 1, 2, 0, 3, 104502, 3, 1591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('意外と難しいんですよ\\n正しい亀甲縛りと\\nいうものは…', 1, 1, 3, 0, 0, 104502, 1, 1592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くつろいで油断\\nしているスキに何を\\nされるのでしょう！？', 1, 1, 3, 0, 0, 104502, 2, 1593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「見た目とは裏腹に\\nそれは激しく攻め\\nたてて」…ぐふふふ', 1, 1, 3, 0, 0, 104502, 3, 1594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは禁断の香り…\\nああっ一段階上の\\n妄想が開花するうぅ！', 1, 1, 3, 0, 0, 104502, 4, 1595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああっ、暖気がまるで\\nロウソクのように\\nクウカを攻めますっ！', 1, 1, 3, 0, 0, 104502, 5, 1596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('激しい攻めを受けきる\\nためには、鍛えないと\\nいけないのですね', 1, 1, 3, 0, 0, 104502, 6, 1597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにいっぱい\\n入りません…\\nお腹にっ！', 1, 1, 3, 0, 0, 104502, 7, 1598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんな本も\\nよく見ると\\nいやらしいです…！', 1, 1, 3, 0, 0, 104502, 8, 1599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この前遊んだ猫、\\nモッフモフ\\nだったにゃあ…♪', 1, 1, 1, 0, 0, 104601, 1, 1601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほっぺやお腹が、\\n肉球ぐらいぷにぷに…\\nこれはまずいにゃ…', 1, 1, 1, 0, 0, 104601, 2, 1602);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大きな仕事が\\n決まったにゃ！\\n腕が鳴るにゃ～♪', 1, 1, 1, 0, 0, 104601, 3, 1603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやつのたい焼き、\\nつぶあんとこしあん、\\nどっちに\\nしようかにゃ？', 1, 1, 1, 0, 0, 104601, 4, 1604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うにゃー…\\nもうちょっとお昼寝\\nしたかったにゃ…\\nむにゃむにゃ…', 1, 1, 1, 0, 0, 104601, 5, 1605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミに呼ばれると、\\n猫まっしぐらな気分に\\nなっちゃうにゃ♪', 4, 1, 1, 0, 0, 104601, 101, 1606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミのおかげで\\nギルドの仕事も\\n大成功だにゃ♪\\nありがとにゃ♪', 8, 1, 1, 0, 0, 104601, 102, 1607);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うずうず…その指、\\nじゃれついても\\nいいかにゃ？', 1, 1, 2, 0, 0, 104601, 1, 1608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃ？\u3000あたしに何か\\nご入り用かにゃ？\\nお安くしとくにゃ～♪', 1, 1, 2, 0, 0, 104601, 2, 1609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、なんだか\\n退屈にゃ～\\n遊んで、遊んで～？', 1, 1, 2, 0, 0, 104601, 3, 1610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素早い動きのコツ？\\nタダじゃ教えて\\nあげられないにゃ～♪', 1, 1, 2, 0, 0, 104601, 4, 1611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなにあたしを\\nなでたいにゃ？\\nキミならなでさせて\\nあげてもいいかにゃー', 4, 1, 2, 0, 0, 104601, 101, 1612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃあ、ねえねえ、\\n一緒にゴロゴロ\\nしようにゃあ？', 8, 1, 2, 0, 0, 104601, 102, 1613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい朝にゃ！\\n顔を洗ってくるにゃ！', 1, 1, 2, 0, 1, 104601, 1, 1614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むーん、そろそろ\\nお昼…猫たちにも\\n猫缶を…', 1, 1, 2, 0, 2, 104601, 2, 1615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…眠いにゃ…\\n猫は布団で\\n丸くなるにゃ', 1, 1, 2, 0, 3, 104601, 3, 1616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('客商売では、\\n外見のチェックも\\n欠かせないのにゃ！', 1, 1, 3, 0, 0, 104601, 1, 1617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うにゃ～！\\nお昼寝に\\nぴったりにゃ', 1, 1, 3, 0, 0, 104601, 2, 1618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ…量産したら\\n子どもにバカ売れ\\nしそうだにゃ！', 1, 1, 3, 0, 0, 104601, 3, 1619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この灯り、まるで\\n猫みたいな\\n癒し効果にゃ！', 1, 1, 3, 0, 0, 104601, 4, 1620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃあ、\\nあったかいと猫は丸く\\nなっちゃうのにゃあ…', 1, 1, 3, 0, 0, 104601, 5, 1621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本当は外で\\n運動したいん\\nだけどにゃ', 1, 1, 3, 0, 0, 104601, 6, 1622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むーん、\\n美味しいにゃー！\\nたい焼きに\\n匹敵するにゃ！', 1, 1, 3, 0, 0, 104601, 7, 1623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…猫の\\nしつけ方は、と…', 1, 1, 3, 0, 0, 104601, 8, 1624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいネコの置物を\\nゲットしたにゃ！\\nどこに飾ろうか\\nにゃ～♪', 1, 1, 1, 0, 0, 104602, 1, 1626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事の交渉がうまく\\n行ったにゃ～♪\\nいい気分だにゃ～♪', 1, 1, 1, 0, 0, 104602, 2, 1627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねこじゃらしには\\n食いついちゃうにゃ\\nびしっ！\u3000びしっ！', 1, 1, 1, 0, 0, 104602, 3, 1628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほっぺやお腹が、肉球\\nぐらいぷにぷに…\\nこれはまずいにゃ…', 1, 1, 1, 0, 0, 104602, 4, 1629);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっきのたいやき\\nおいしかったにゃ♪\\nごろごろごろ…', 1, 1, 1, 0, 0, 104602, 5, 1630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手作りのたい焼き\\nあいつは食べて\\nくれるかにゃ…？', 8, 1, 1, 0, 0, 104602, 101, 1631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつには、いつか\\nたっぷり恩返しが\\nしたいにゃ…', 8, 1, 1, 0, 0, 104602, 102, 1632);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃーに？\u3000あたしの\\nことがそんなに気に\\nなるのかにゃ？', 1, 1, 2, 0, 0, 104602, 1, 1633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしのこと…\\nしっかり捕まえ\\nといてにゃ？', 1, 1, 2, 0, 0, 104602, 2, 1634);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの力が\\n必要かにゃ？\u3000猫の手\\n貸してあげるにゃ♪', 1, 1, 2, 0, 0, 104602, 3, 1635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たいやきとクレープを\\n合わせれば…\\n新しい商売のニオイが\\nするにゃ…！', 1, 1, 2, 0, 0, 104602, 4, 1636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃあ、ねえねえ\\n一緒にゴロゴロ\\nしようにゃあ？', 8, 1, 2, 0, 0, 104602, 101, 1637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒にいると\\n楽しくなってつい\\nじゃれちゃうにゃ！', 8, 1, 2, 0, 0, 104602, 102, 1638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい朝にゃ！\\n顔を洗ってくるにゃ！', 1, 1, 2, 0, 1, 104602, 1, 1639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろおっひる～\\nにゃーんか\\n食べたい…', 1, 1, 2, 0, 2, 104602, 2, 1640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、眠くなって\\nきたにゃ。あたしは\\n夜行性じゃないのにゃ', 1, 1, 2, 0, 3, 104602, 3, 1641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃにゃ…\\n髪が乱れてるにゃ', 1, 1, 3, 0, 0, 104602, 1, 1642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっかふかにゃ～\\n猫がねころん\\nじゃうにゃ', 1, 1, 3, 0, 0, 104602, 2, 1643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、猫と匹敵する\\nぐらいかわいいにゃ！', 1, 1, 3, 0, 0, 104602, 3, 1644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫でもこわくない\\n優しい灯りにゃ！', 1, 1, 3, 0, 0, 104602, 4, 1645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽっかぽか\\nしあわせな気分にゃ～', 1, 1, 3, 0, 0, 104602, 5, 1646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('雨の日でも運動\\nできるのは、濡れ\\nなくて便利だにゃ！', 1, 1, 3, 0, 0, 104602, 6, 1647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味しいにゃ～！\\nこれ、朝昼晩\\n食べたいにゃ！', 1, 1, 3, 0, 0, 104602, 7, 1648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本を読んで\\n猫の気持ちを\\n勉強するのにゃ！', 1, 1, 3, 0, 0, 104602, 8, 1649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('内職手伝える人\\nいないかしら？', 1, 1, 1, 0, 0, 104801, 1, 1651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の依頼は、\\nこういう計画で…\\nうん、完璧ね！', 1, 1, 1, 0, 0, 104801, 2, 1652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の特売セールに\\n向けて、しっかり\\n準備しないと！', 1, 1, 1, 0, 0, 104801, 3, 1653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('配達の後に売り子\\n次に採取のバイト…\\nうん、効率的ね', 1, 1, 1, 0, 0, 104801, 4, 1654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一日に受ける\\nバイトの数、もう少し\\n増やしたいわね', 1, 1, 1, 0, 0, 104801, 5, 1655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('師匠として\\n頼りにされたいし\\nもっと頑張らなきゃ！', 4, 1, 1, 0, 0, 104801, 101, 1656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の子と効率的に\\n仲良くなる方法…\\nこればっかりは難題ね', 8, 1, 1, 0, 0, 104801, 102, 1657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、\\nちょうどよかった\\n今から一緒に\\nバイトでもどう？', 1, 1, 2, 0, 0, 104801, 1, 1658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('相談事かしら？\\nそれくらいなら\\n無料でいいわよ', 1, 1, 2, 0, 0, 104801, 2, 1659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('背後の気配なら\\nすぐ分かるわ\\n試してみる？', 1, 1, 2, 0, 0, 104801, 3, 1660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('道具やお金の管理は\\n大丈夫？\u3000手伝うから\\nいつでも言って', 1, 1, 2, 0, 0, 104801, 4, 1661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇ができたから\\n働きたいけど…\\nキミとの時間も大切ね', 4, 1, 2, 0, 0, 104801, 101, 1662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、あの…\\n私はキミにとって…\\nいや、何でもないわ', 8, 1, 2, 0, 0, 104801, 102, 1663);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\n今日も朝から\\nバイトよ！', 1, 1, 2, 0, 1, 104801, 1, 1664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼時ね。\\n少し休憩したら、\\nまた働くわよ！', 1, 1, 2, 0, 2, 104801, 2, 1665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間！\\n明日もバイトで\\n朝早いのよ…', 1, 1, 2, 0, 3, 104801, 3, 1666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('接客業の依頼が\\nある時は、外見も\\nキレイにしないとね', 1, 1, 3, 0, 0, 104801, 1, 1667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～バイトで\\n疲れたから癒される～', 1, 1, 3, 0, 0, 104801, 2, 1668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを内職で\\n作ったら\\n儲かるかしら？', 1, 1, 3, 0, 0, 104801, 3, 1669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リフレッシュできたわ\\nこれでまた、バリバリ\\n働けるわね！', 1, 1, 3, 0, 0, 104801, 4, 1670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風邪を引いたら効率が\\n落ちちゃうから、\\n暖めないと！', 1, 1, 3, 0, 0, 104801, 5, 1671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('働き続けるには\\n健康第一！\u3000それには\\n運動が一番よ', 1, 1, 3, 0, 0, 104801, 6, 1672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\n腹が減っては\\n戦ができぬ、よ！', 1, 1, 3, 0, 0, 104801, 7, 1673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日々絶えず学んで、\\n生活に活かすのよ！', 1, 1, 3, 0, 0, 104801, 8, 1674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('家計簿をつけなきゃ！\\n覚えている時に\\nやっておかないとね', 1, 1, 1, 0, 0, 104802, 1, 1676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の依頼は\\nこういう計画で…\\nうん、完璧ね！', 1, 1, 1, 0, 0, 104802, 2, 1677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドの経費\\nあとちょっとだけ\\n削れそうね…', 1, 1, 1, 0, 0, 104802, 3, 1678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少しでも時給のいい\\nバイトがしたいけど\\nなかなか\\n出会えないのよ', 1, 1, 1, 0, 0, 104802, 4, 1679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度のバイトも\\nなかなか大変そう\\nね…腕が鳴るわ', 1, 1, 1, 0, 0, 104802, 5, 1680);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の子と効率的に\\n仲良くなる方法…\\nこればっかりは難題ね', 8, 1, 1, 0, 0, 104802, 101, 1681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、どうしたんだろ？\\n仕事中もずっと\\n彼のこと考えてる…', 8, 1, 1, 0, 0, 104802, 102, 1682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この間はヘルプに\\n来てくれてありがとう\\n頼んで正解だったわ', 1, 1, 2, 0, 0, 104802, 1, 1683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見つけた！\u3000ちょうど\\n頼みたいことが\\nあるんだけど、いい？', 1, 1, 2, 0, 0, 104802, 2, 1684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今から\\n休憩するところなの\\n一緒にどう？', 1, 1, 2, 0, 0, 104802, 3, 1685);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000どうしたの？\\n私のことが\\n気になるの？', 1, 1, 2, 0, 0, 104802, 4, 1686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…たまには甘えても\\nいい？\u3000私だって\\n弱る時はあるのよ', 8, 1, 2, 0, 0, 104802, 101, 1687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇ができたから\\n働きたいけど…\\nキミとの時間も大切ね', 8, 1, 2, 0, 0, 104802, 102, 1688);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\nいい朝ね。一緒に\\nランニングでもいく？', 1, 1, 2, 0, 1, 104802, 1, 1689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼時ね\\n少し休憩したら\\nまた働くわよ！', 1, 1, 2, 0, 2, 104802, 2, 1690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間！\\n明日もバイトで\\n朝早いのよ…', 1, 1, 2, 0, 3, 104802, 3, 1691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女の子らしく…\\nどうも忘れちゃう\\nのよね', 1, 1, 3, 0, 0, 104802, 1, 1692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで少し\\n休んだら\\nまたバイトよ！', 1, 1, 3, 0, 0, 104802, 2, 1693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを内職で\\n作ったら\\n儲かるかしら？', 1, 1, 3, 0, 0, 104802, 3, 1694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事から帰ってきて\\nこういうのがあると\\n素敵ね', 1, 1, 3, 0, 0, 104802, 4, 1695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり身体を\\n温めて、血流を\\nよくしなくっちゃ', 1, 1, 3, 0, 0, 104802, 5, 1696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで休憩中も\\n無駄なく\\n鍛えられるわ♪', 1, 1, 3, 0, 0, 104802, 6, 1697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…よく\\n食べて、よく働く！\\nそれが私のモットーよ', 1, 1, 3, 0, 0, 104802, 7, 1698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日々絶えず学んで\\n生活に活かすのよ！', 1, 1, 3, 0, 0, 104802, 8, 1699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし、お料理と\\nお掃除とお洗濯と\\n買い物しようかな？', 1, 1, 1, 0, 0, 104901, 1, 1701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうして歩いていれば\\n弟くんが声をかけて\\nくれるはず…', 1, 1, 1, 0, 0, 104901, 2, 1702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんがどんな生活を\\nしてるのか調べるのも\\nお姉ちゃんの務め！', 1, 1, 1, 0, 0, 104901, 3, 1703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん、\\n弟くんのにおい…\\n近くにいるね？', 1, 1, 1, 0, 0, 104901, 4, 1704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんの痕跡を\\n部屋中に\\n残しちゃおっと♪', 1, 1, 1, 0, 0, 104901, 5, 1705);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋を、\\n私と弟くんの\\n愛の巣に…', 4, 1, 1, 0, 0, 104901, 101, 1706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～…弟くん\\n禁断症状だよ～', 8, 1, 1, 0, 0, 104901, 102, 1707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの部屋は\\nお姉ちゃんの\\n部屋だよね～', 1, 1, 2, 0, 0, 104901, 1, 1708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいこいいこ～♪\\nどう、お姉ちゃんの\\nナデナデは？', 1, 1, 2, 0, 0, 104901, 2, 1709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('姉と弟の外出は\\nデートって\\nいうのかな？', 1, 1, 2, 0, 0, 104901, 3, 1710);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう！\\nイタズラする子には\\nお姉ちゃんチョップ！', 1, 1, 2, 0, 0, 104901, 4, 1711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんが\\nぎゅ～ってして\\nあげるね♪', 4, 1, 2, 0, 0, 104901, 101, 1712);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あのね…\\nたまにはお姉ちゃんも\\n甘えていい？', 8, 1, 2, 0, 0, 104901, 102, 1713);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着替えは？\u3000荷物は？\\nお出かけの準備は\\nお姉ちゃんが手伝うね', 1, 1, 2, 0, 1, 104901, 1, 1714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('出かけるなら\\n明るいうちに\\n帰ってくるんだよ！', 1, 1, 2, 0, 2, 104901, 2, 1715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ起きてるの？\\nそれじゃあ、\\nお姉ちゃんも\\n夜更かししちゃお☆', 1, 1, 2, 0, 3, 104901, 3, 1716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいなお姉ちゃん\\n好きだよね♪', 1, 1, 3, 0, 0, 104901, 1, 1717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにお姉ちゃんの\\n匂いを、た～っぷり\\n残しておこうっと♪', 1, 1, 3, 0, 0, 104901, 2, 1718);
