insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんがどんな生活を\\nしてるのか調べるのも\\nお姉ちゃんの務め！', 1, 1, 1, 0, 0, 104902, 4, 1729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はっ！\\n弟くんが困ってる\\n気がする！', 1, 1, 1, 0, 0, 104902, 5, 1730);
