insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの手作りなら\\nもっとおいしくなると\\n思うんだけどなぁ～', 1, 1, 3, 0, 0, 104902, 7, 1748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんをきちんと\\n教育するために\\nお姉ちゃんは勉強を\\nかかさないのだ☆', 1, 1, 3, 0, 0, 104902, 8, 1749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、エレガントで\\n大人なお部屋ね！\\nアタシにぴったり！', 1, 1, 1, 0, 0, 105001, 1, 1751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身長とバスト以外は\\n完璧な大人\\nなのになぁ～', 1, 1, 1, 0, 0, 105001, 2, 1752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシの大人コーデで\\nあいつも夢中ね♪', 1, 1, 1, 0, 0, 105001, 3, 1753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝顔の観察したら\\n理系女子になれる\\nかしら？', 1, 1, 1, 0, 0, 105001, 4, 1754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レディは、どんな時も\\nおしとやかに…って\\nアタシも騒ぎたいー！', 1, 1, 1, 0, 0, 105001, 5, 1755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人っぽい子が\\n多いわね…アタシも\\n負けてられないわ！', 4, 1, 1, 0, 0, 105001, 101, 1756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシが待ってる\\nなんて、アイツは\\n幸せものよねー', 8, 1, 1, 0, 0, 105001, 102, 1757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わーい、アメだー♪\\n食べる食べるー♪', 1, 1, 2, 0, 0, 105001, 1, 1758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('熱いハニーラテが\\n飲みたーい！\\n淹れてー淹れてー！', 1, 1, 2, 0, 0, 105001, 2, 1759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なによ？\u3000もしかして\\n好きな子にイタズラ\\nしたくなるってやつ？', 1, 1, 2, 0, 0, 105001, 3, 1760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシに合う服\\n雑誌で探そうっと！\\nサイズじゃないわ、\\nデザインとかの話よ！', 1, 1, 2, 0, 0, 105001, 4, 1761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねーねー！\\nアタシ、かわいい？\\nかわいいわよね？', 4, 1, 2, 0, 0, 105001, 101, 1762);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これから出かけるの？\\nしっかりアタシを\\nエスコートしてね！', 8, 1, 2, 0, 0, 105001, 102, 1763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝のスキンケアは\\n大事なの！', 1, 1, 2, 0, 1, 105001, 1, 1764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたー\\nダイエット\\nやめちゃおうかなー', 1, 1, 2, 0, 2, 105001, 2, 1765);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エイジングケアを\\nしないとねー', 1, 1, 2, 0, 3, 105001, 3, 1766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この角度のほうが\\n大人っぽく見えるかな\\nそれともこっちかしら', 1, 1, 3, 0, 0, 105001, 1, 1767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ！\u3000これ雑誌で\\n見たことあるわ～\\nだからきっと\\nオシャレなのよ！', 1, 1, 3, 0, 0, 105001, 2, 1768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい♪\u3000けど\\n大人はこんなもの…\\nでも、かわいいし～！', 1, 1, 3, 0, 0, 105001, 3, 1769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オシャレ～♪\\n大人なレディって\\n感じよね♪', 1, 1, 3, 0, 0, 105001, 4, 1770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかーい♪\\nここで宿題\\nしようかしら？', 1, 1, 3, 0, 0, 105001, 5, 1771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動したら成長\\nしないかしら？\\n背とか胸とか…', 1, 1, 3, 0, 0, 105001, 6, 1772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べすぎると\\n太っちゃうな…\\nでも、おいしいし～っ', 1, 1, 3, 0, 0, 105001, 7, 1773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おもしろーい！\\n…でも絵本って\\n子供っぽいかしら？', 1, 1, 3, 0, 0, 105001, 8, 1774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レディは、どんな時も\\nおしとやかに…って\\nアタシも騒ぎたいー！', 1, 1, 1, 0, 0, 105002, 1, 1776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('恋人にするなら\\nイケメンか\\nただイケよね～', 1, 1, 1, 0, 0, 105002, 2, 1777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう少し背が欲しいな\\n…もっと牛乳を\\n飲まなくちゃ！', 1, 1, 1, 0, 0, 105002, 3, 1778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝顔の観察したら\\n理系女子になれる\\nかしら？', 1, 1, 1, 0, 0, 105002, 4, 1779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これは補習の\\nお知らせプリント！\\nアイツに見つかる前に\\n隠さなくちゃ！', 1, 1, 1, 0, 0, 105002, 5, 1780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツおっそいなー\\n別に会いたいわけじゃ\\nないけど…\\n来ないと気になる…', 8, 1, 1, 0, 0, 105002, 101, 1781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシが待ってる\\nなんて、アイツは\\n幸せものよねー ', 8, 1, 1, 0, 0, 105002, 102, 1782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なーに？\\nアタシに甘えたいの？', 1, 1, 2, 0, 0, 105002, 1, 1783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシに合う服\\n雑誌で探そうっと！\\nサイズじゃないわ\\nデザインとかの話よ！', 1, 1, 2, 0, 0, 105002, 2, 1784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭撫でないで！\\nお子様みたいに\\nあつかわないでって\\n言ってるのに～！', 1, 1, 2, 0, 0, 105002, 3, 1785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('壁ドンの練習…\\nあれ？\u3000壁ドンって\\n男がするんだっけ？', 1, 1, 2, 0, 0, 105002, 4, 1786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねーねー！\\nアタシ、かわいい？\\nかわいいわよね？', 8, 1, 2, 0, 0, 105002, 101, 1787);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これから出かけるの？\\nしっかりアタシを\\nエスコートしてね！', 8, 1, 2, 0, 0, 105002, 102, 1788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レディの朝は\\n忙しいのよ', 1, 1, 2, 0, 1, 105002, 1, 1789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたー\\nダイエット\\nやめちゃおうかなー', 1, 1, 2, 0, 2, 105002, 2, 1790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エイジングケアを\\nしないとねー', 1, 1, 2, 0, 3, 105002, 3, 1791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身だしなみチェック\\nオッケー！\u3000これで\\nいつアイツが来ても\\n大丈夫ね！', 1, 1, 3, 0, 0, 105002, 1, 1792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ！\u3000これ雑誌で\\n見たことあるわ～\\nだからきっと\\nオシャレなのよ！', 1, 1, 3, 0, 0, 105002, 2, 1793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしがもっと\\nオシャレにかわいく\\nしてあげようか？', 1, 1, 3, 0, 0, 105002, 3, 1794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オシャレ～♪\\n大人なレディって\\n感じよね♪', 1, 1, 3, 0, 0, 105002, 4, 1795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかーい♪\\nここで宿題\\nしようかしら？', 1, 1, 3, 0, 0, 105002, 5, 1796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動したら成長\\nしないかしら？\\n背とか胸とか…', 1, 1, 3, 0, 0, 105002, 6, 1797);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レディは、食べ物にも\\n気を使うのよ', 1, 1, 3, 0, 0, 105002, 7, 1798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おもしろーい！\\n…でも絵本って\\n子供っぽいかしら？', 1, 1, 3, 0, 0, 105002, 8, 1799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法と科学\\nどっちも極めて\\nみせるわ', 1, 1, 1, 0, 0, 105101, 1, 1801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事も片付いたし\\n部屋で\\n実験実験…♪', 1, 1, 1, 0, 0, 105101, 2, 1802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまった治療代の\\n請求書を\\nまとめないと…', 1, 1, 1, 0, 0, 105101, 3, 1803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新薬が出来たし\\nすぐに試したいけど…\\n実験台がいないわ', 1, 1, 1, 0, 0, 105101, 4, 1804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋にこもりすぎると\\n曜日の感覚が\\nなくなるわね', 1, 1, 1, 0, 0, 105101, 5, 1805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子の記憶を\\n取り戻せる薬…\\n作れないものかしら', 4, 1, 1, 0, 0, 105101, 101, 1806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好意に気づいて貰える\\n薬って、どうすれば\\n作れるのかしら', 8, 1, 1, 0, 0, 105101, 102, 1807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、ヒマなら\\n薬草の整理を\\n手伝って', 1, 1, 2, 0, 0, 105101, 1, 1808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして実験に\\n付き合ってくれるの？\\nえ？\u3000違う？', 1, 1, 2, 0, 0, 105101, 2, 1809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('具合が悪い？\\nなら診てあげる\\nまずは触診から…', 1, 1, 2, 0, 0, 105101, 3, 1810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('植物に興味あるの？\\nなら教えてあげるわ\\n色々とね…', 1, 1, 2, 0, 0, 105101, 4, 1811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの傍にいるだけで\\n高揚しちゃうのは\\n何故かしら…？', 4, 1, 2, 0, 0, 105101, 101, 1812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私はおしおきする\\n側のことが多いけど…\\nキミにはされたいかも', 8, 1, 2, 0, 0, 105101, 102, 1813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼までに調合用の\\n花を集めたいの\\n手伝ってくれる？', 1, 1, 2, 0, 1, 105101, 1, 1814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、もうお昼？\\nそろそろ一息\\n入れましょうか', 1, 1, 2, 0, 2, 105101, 2, 1815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜も更けて来たわね\\n私は朝まで実験だけど\\n見学していく？', 1, 1, 2, 0, 3, 105101, 3, 1816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('医者たるもの\\nいつだって\\n清潔に…♪', 1, 1, 3, 0, 0, 105101, 1, 1817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいわねこれ\\n仮眠の時に\\n使わせてもらうわ', 1, 1, 3, 0, 0, 105101, 2, 1818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬいぐるみなら\\n動物も…', 1, 1, 3, 0, 0, 105101, 3, 1819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\n仕事場にも\\n置いてみようかしら', 1, 1, 3, 0, 0, 105101, 4, 1820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいると\\nついウトウト\\nしちゃうわ…', 1, 1, 3, 0, 0, 105101, 5, 1821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('座ってる時間が多いと\\n運動不足になるし\\nたまにはいいわね', 1, 1, 3, 0, 0, 105101, 6, 1822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('研究していると\\nつい食べるのを\\n忘れちゃうのよね', 1, 1, 3, 0, 0, 105101, 7, 1823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実験もいいけど\\nいつか成果を\\n本にしないと…', 1, 1, 3, 0, 0, 105101, 8, 1824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('徹夜はツラいけど\\n集中すると時間の\\n感覚がなくなって…', 1, 1, 1, 0, 0, 105102, 1, 1826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('痛みに悶える顔って\\nどうしてあんなに\\n興奮するのかしら？', 1, 1, 1, 0, 0, 105102, 2, 1827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼に罵られたら\\nどんな気分かしら\\n意外と快感かも？', 1, 1, 1, 0, 0, 105102, 3, 1828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毒を薄めると\\n薬になるのって\\n今でも不思議だわ', 1, 1, 1, 0, 0, 105102, 4, 1829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('綺麗なバラには\\nトゲがあるけど\\n魅力の一つよね', 1, 1, 1, 0, 0, 105102, 5, 1830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カレをさりげなく\\n惚れさせる方法を\\n研究するわよ…♪', 8, 1, 1, 0, 0, 105102, 101, 1831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好意に気づいて貰える\\n薬って、どうすれば\\n作れるのかしら', 8, 1, 1, 0, 0, 105102, 102, 1832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('構って欲しいの？\\nじゃあ、君の体を\\n調べさせて？', 1, 1, 2, 0, 0, 105102, 1, 1833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実験に付き合って\\n大丈夫よ、試すのは\\nただの栄養剤だから', 1, 1, 2, 0, 0, 105102, 2, 1834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('欲しい薬が\\nあったら言ってね\\n調合してみるから', 1, 1, 2, 0, 0, 105102, 3, 1835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おしおきされたいの？\\nキミにだったら\\nいつでもしてあげる', 1, 1, 2, 0, 0, 105102, 4, 1836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの傍にいるだけで\\n高揚しちゃうのは\\n何故かしら…？', 8, 1, 2, 0, 0, 105102, 101, 1837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私はおしおきする\\n側のことが多いけど…\\nキミにはされたいかも', 8, 1, 2, 0, 0, 105102, 102, 1838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝しか取れない\\n植物があるの\\n採取しに行くわよ', 1, 1, 2, 0, 1, 105102, 1, 1839);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼時ってやけに\\n眠たくなるわよね\\n…調べたくなるわ', 1, 1, 2, 0, 2, 105102, 2, 1840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日くらいは\\nゆっくり眠りたいわ\\n…キミと一緒にね', 1, 1, 2, 0, 3, 105102, 3, 1841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身なりについて\\n研究するのも\\n楽しそうね', 1, 1, 3, 0, 0, 105102, 1, 1842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休息に必要な道具は\\n妥協せずに選ぶ！\\nこれだけは譲れないわ', 1, 1, 3, 0, 0, 105102, 2, 1843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにはこういう\\n可愛らしいものに\\n触れないとね♪', 1, 1, 3, 0, 0, 105102, 3, 1844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\n仕事場にも\\n置いてみようかしら', 1, 1, 3, 0, 0, 105102, 4, 1845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事がなかったら\\nこのまますーっと\\n眠りたいのに…', 1, 1, 3, 0, 0, 105102, 5, 1846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動しないと\\n体型の維持が…', 1, 1, 3, 0, 0, 105102, 6, 1847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度な食事も\\n大切よね', 1, 1, 3, 0, 0, 105102, 7, 1848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさか私が\\n恋愛読本を読む\\n日が来るなんて…', 1, 1, 3, 0, 0, 105102, 8, 1849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぺっぺっ！\\n…い、いけないっ！', 1, 1, 1, 0, 0, 105201, 1, 1851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっけな～い！\\nひづめで床に傷が！', 1, 1, 1, 0, 0, 105201, 2, 1852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('太っちゃったかも～！\\n伐採でダイエット\\nしなくっちゃ！', 1, 1, 1, 0, 0, 105201, 3, 1853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きちんと生活すると\\n毛づやが良くなる\\nみたいなのよね～', 1, 1, 1, 0, 0, 105201, 4, 1854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんな、体重\\nどれくらいなのかな？', 1, 1, 1, 0, 0, 105201, 5, 1855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体力なら自信\\nあるんだけど…\\n恋にはちょっぴり\\n臆病になっちゃう', 4, 1, 1, 0, 0, 105201, 101, 1856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか人間の女の子\\nみたいなデート、\\nしてみたいな～♪', 8, 1, 1, 0, 0, 105201, 102, 1857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私ね「どこにでもいる\\n普通の女の子」って\\n言葉が憧れなんだ～♪', 1, 1, 2, 0, 0, 105201, 1, 1858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チャームポイント？\\n自分では分からない\\nけど…まつげかなぁ？', 1, 1, 2, 0, 0, 105201, 2, 1859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リマリマ～♪\\nはっ！？\\nわ、私ったら今何を？', 1, 1, 2, 0, 0, 105201, 3, 1860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('力仕事ならまかせて！', 1, 1, 2, 0, 0, 105201, 4, 1861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人間になりたいな～\\nそれか、あなたが\\n私みたいな姿に…♪', 4, 1, 2, 0, 0, 105201, 101, 1862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しょうがないなあ、\\nこんなにモフらせるの\\nあなただけだよ？', 8, 1, 2, 0, 0, 105201, 102, 1863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今朝は寝癖がひどいわ\\nしっぽの辺りとか～', 1, 1, 2, 0, 1, 105201, 1, 1864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランチは\\nおしゃれなカフェで\\nしてみたいな～♪', 1, 1, 2, 0, 2, 105201, 2, 1865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お肌のケアに\\nパックしながら\\n寝ようかな～', 1, 1, 2, 0, 3, 105201, 3, 1866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やだっ、\\nまた寝ぐせついてる！\\n直さないと！', 1, 1, 3, 0, 0, 105201, 1, 1867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミシッっていった！\\n私、重すぎるかも！？', 1, 1, 3, 0, 0, 105201, 2, 1868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ！\u3000あなたも\\n美人さんね～♪', 1, 1, 3, 0, 0, 105201, 3, 1869);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、まったり…\\n四足歩行しちゃい\\nそうだわ…', 1, 1, 3, 0, 0, 105201, 4, 1870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い♪\\n…私、毛皮だから\\n暑すぎるかも', 1, 1, 3, 0, 0, 105201, 5, 1871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な、なんだか野生に\\n帰っちゃいそう！', 1, 1, 3, 0, 0, 105201, 6, 1872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぱくぱく、もぐもぐ、\\nぺっぺっ…\\nやだ、はしたない！', 1, 1, 3, 0, 0, 105201, 7, 1873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃーーー！\\nこの恋愛小説\\nとっても\\nドキドキしちゃう～', 1, 1, 3, 0, 0, 105201, 8, 1874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵ね～、居るだけで\\n女子力があがりそうな\\nお部屋だわ～', 1, 1, 1, 0, 0, 105202, 1, 1876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、大丈夫かしら？\\n他の子に怖がられたり\\nしないかな…？', 1, 1, 1, 0, 0, 105202, 2, 1877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('動物苑…って\\n嫌なギルド名ね…', 1, 1, 1, 0, 0, 105202, 3, 1878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好き、嫌い、好き…\\nあっ！\u3000うっかりして\\n花占いのお花\\n食べちゃった！', 1, 1, 1, 0, 0, 105202, 4, 1879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ、女の子らしい\\nものでいっぱいね～！\\nときめいちゃうわ～♪', 1, 1, 1, 0, 0, 105202, 5, 1880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体力なら自信\\nあるんだけど…\\n恋にはちょっぴり\\n臆病になっちゃう', 8, 1, 1, 0, 0, 105202, 101, 1881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人が\\n来てくれるまで薪割り\\nでもしてよっかな？', 8, 1, 1, 0, 0, 105202, 102, 1882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にお出かけ？\\nうれしいけど…\\n心の準備が！\\nはわわわ！', 1, 1, 2, 0, 0, 105202, 1, 1883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\n急に抱きついてきて…\\n癒されたいの？', 1, 1, 2, 0, 0, 105202, 2, 1884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぺっぺっ！\\n…い、いけないっ！', 1, 1, 2, 0, 0, 105202, 3, 1885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メタモルアップルを\\nここで食べたら、\\nみんな驚くわよね', 1, 1, 2, 0, 0, 105202, 4, 1886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しょうがないなあ、\\nこんなにモフらせるの\\nあなただけだよ？', 8, 1, 2, 0, 0, 105202, 101, 1887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人間になりたいな～\\nそれか、あなたが\\n私みたいな姿に…♪', 8, 1, 2, 0, 0, 105202, 102, 1888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今朝は寝癖がひどいわ\\nしっぽの辺りとか～', 1, 1, 2, 0, 1, 105202, 1, 1889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ダイエット中だから\\nお昼は抜いてるの～', 1, 1, 2, 0, 2, 105202, 2, 1890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お肌のケアに\\nパックしながら\\n寝ようかな～', 1, 1, 2, 0, 3, 105202, 3, 1891);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんとかわいく\\nしてないと刈られ…\\n狩られちゃうもんね！', 1, 1, 3, 0, 0, 105202, 1, 1892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミシッっていった！\\n私、重すぎるかも！？', 1, 1, 3, 0, 0, 105202, 2, 1893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ！\u3000あなたも\\n美人さんね～♪', 1, 1, 3, 0, 0, 105202, 3, 1894);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～\\n森の中にいるみたいに\\nとっても落ち着く～', 1, 1, 3, 0, 0, 105202, 4, 1895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵～♪\u3000…\\nきゃっ！\u3000私の毛が\\nたいへんなことに～！', 1, 1, 3, 0, 0, 105202, 5, 1896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な、なんだか野生に\\n帰っちゃいそう！', 1, 1, 3, 0, 0, 105202, 6, 1897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何を食べるかより\\n誰と食べるかが\\n大事なのよね', 1, 1, 3, 0, 0, 105202, 7, 1898);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃーーー！\\nこの恋愛小説\\nとっても\\nドキドキしちゃう～', 1, 1, 3, 0, 0, 105202, 8, 1899);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァイスフリューゲル\\nを盛り上げる方法、\\n共に語らおう！', 1, 1, 1, 0, 0, 105301, 1, 1901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私は子供ではない…！\\nが、お菓子は\\nいただこう！', 1, 1, 1, 0, 0, 105301, 2, 1902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋はきちんと\\n片づけておかなくては\\n部屋の汚れは\\n心の汚れだ', 1, 1, 1, 0, 0, 105301, 3, 1903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむむ…明日\\n目が覚めたら、身長が\\n伸びていないものか…', 1, 1, 1, 0, 0, 105301, 4, 1904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子が常備されて\\nいる部屋。そんな\\nものが、私の好みだ…', 1, 1, 1, 0, 0, 105301, 5, 1905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつとの新たな\\n鍛錬が\\n待ち遠しいな…！', 4, 1, 1, 0, 0, 105301, 101, 1906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、あいつと\\n過ごしていて、毎日が\\n充実しているな…', 8, 1, 1, 0, 0, 105301, 102, 1907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('軍人の本分は日々の\\n研鑽にあるからな。\\n今日も鍛錬に\\n行かないか？', 1, 1, 2, 0, 0, 105301, 1, 1908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日牛乳を飲んでいる\\nのだが、なかなか背が\\n伸びないものだな…', 1, 1, 2, 0, 0, 105301, 2, 1909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公にも、飴をくれて\\nやろうか？\\nあまいぞ～！\\n美味しいぞ～！', 1, 1, 2, 0, 0, 105301, 3, 1910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私ともっと高く、\\n共に飛ぼう！', 1, 1, 2, 0, 0, 105301, 4, 1911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公は、本当に頼りに\\nなる男だな…いや、\\nふとそう思っただけだ', 4, 1, 2, 0, 0, 105301, 101, 1912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公と共にいられる\\nことは私の喜びだ。\\nこれからも\\nよろしく頼むぞ', 8, 1, 2, 0, 0, 105301, 102, 1913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ、いい朝だ。\\n本国の夜明けを\\n思い出してしまうな！', 1, 1, 2, 0, 1, 105301, 1, 1914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ昼食に\\nするか。腹が減っては\\n戦はできないからな', 1, 1, 2, 0, 2, 105301, 2, 1915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわああ…私は子供\\nではないが…眠い時は\\n眠いのだ…', 1, 1, 2, 0, 3, 105301, 3, 1916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身だしなみは、心の\\n在りようを映すから\\n気をつけなくてはな', 1, 1, 3, 0, 0, 105301, 1, 1917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう…軍人たるもの\\n常日頃、油断は\\nできないのだが…\\nお、落ち着くな…', 1, 1, 3, 0, 0, 105301, 2, 1918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ…このかわいさ…\\n本国に持って\\n帰りたい…', 1, 1, 3, 0, 0, 105301, 3, 1919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このともし火、戦いに\\n明け暮れる我らの心を\\n癒すものだな…', 1, 1, 3, 0, 0, 105301, 4, 1920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はあ～、ぽかぽか…\\nい、いや！\\n気を緩めないぞっ！', 1, 1, 3, 0, 0, 105301, 5, 1921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うおおおおおっ！\\n鍛錬、鍛錬、\\n鍛錬っ！！', 1, 1, 3, 0, 0, 105301, 6, 1922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつ戦いになっても\\n困らぬように、\\n腹八分目に\\nしておくのだ！', 1, 1, 3, 0, 0, 105301, 7, 1923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを読んで、新たな\\n戦術を編み出すぞっ！', 1, 1, 3, 0, 0, 105301, 8, 1924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには掃除でも\\nするか。部屋が\\n綺麗になるのは\\n喜ばしいことだ', 1, 1, 1, 0, 0, 105302, 1, 1926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の中では\\n剣を振り回せないのが\\n玉に瑕だな…', 1, 1, 1, 0, 0, 105302, 2, 1927);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子が常備されて\\nいる部屋。そんな\\nものが、私の好みだ…', 1, 1, 1, 0, 0, 105302, 3, 1928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日牛乳を飲んでいる\\nのだが、なかなか背が\\n伸びないものだな…', 1, 1, 1, 0, 0, 105302, 4, 1929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('家庭を守れない者が\\n国を守れるはずが\\nない。この部屋も\\n私が守るぞ！', 1, 1, 1, 0, 0, 105302, 5, 1930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつは今頃、何を\\nしているのだろうな…\\nふふっ', 8, 1, 1, 0, 0, 105302, 101, 1931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと会える日が\\nこんなにも待ち遠しく\\nなるとはな…', 8, 1, 1, 0, 0, 105302, 102, 1932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('軍人の本分は日々の\\n研鑽にあるからな\\n今日も鍛錬に\\n行かないか？', 1, 1, 2, 0, 0, 105302, 1, 1933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おお、今日も鍛錬の\\n時間だったか！\\nすまないな\\nすぐ行く！', 1, 1, 2, 0, 0, 105302, 2, 1934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私は子供ではない！\\nが…たまには童心に\\n帰りたい時もある…', 1, 1, 2, 0, 0, 105302, 3, 1935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公にも、飴を\\nくれてやろうか？\\nあまいぞ～！\\n美味しいぞ～！', 1, 1, 2, 0, 0, 105302, 4, 1936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と歩きたいのか…？\\nそうだな。二人で\\n散歩でも行こうか', 8, 1, 2, 0, 0, 105302, 101, 1937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公と共にいられる\\nことは私の喜びだ\\nこれからも\\nよろしく頼むぞ', 8, 1, 2, 0, 0, 105302, 102, 1938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ、いい朝だ\\n本国の夜明けを\\n思い出してしまうな！', 1, 1, 2, 0, 1, 105302, 1, 1939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ昼時だな\\n鍛錬の手を緩めて\\n昼食にするか', 1, 1, 2, 0, 2, 105302, 2, 1940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝る前に…あと少し\\nだけ、鍛錬を…', 1, 1, 2, 0, 3, 105302, 3, 1941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァイス\\nフリューゲルの一員と\\nして恥ずかしくないよう\\n身なりを整えなくては', 1, 1, 3, 0, 0, 105302, 1, 1942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう…軍人たるもの\\n常日頃、油断は\\nできないのだが…\\nお、落ち着くな…', 1, 1, 3, 0, 0, 105302, 2, 1943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ…このかわいさ…\\n本国に持って\\n帰りたい…', 1, 1, 3, 0, 0, 105302, 3, 1944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このともし火\\n戦いに明け暮れる\\n我らの心を\\n癒すものだな…', 1, 1, 3, 0, 0, 105302, 4, 1945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はあ～、ぽかぽか…\\nい、いや！\\n気を緩めないぞっ！', 1, 1, 3, 0, 0, 105302, 5, 1946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うおおおおおっ！\\n鍛錬、鍛錬\\n鍛錬っ！！', 1, 1, 3, 0, 0, 105302, 6, 1947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつ戦いになっても\\n困らぬように\\n腹八分目に\\nしておくのだ！', 1, 1, 3, 0, 0, 105302, 7, 1948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ…脳細胞が\\n活性化してきたぞ\\n読書は大事だな', 1, 1, 3, 0, 0, 105302, 8, 1949);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちの騎空艇\\nどんなデザインに\\nしよう…？', 1, 1, 1, 0, 0, 105701, 1, 1951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('団員募集の\\nポスター\\n作ろうっと♪', 1, 1, 1, 0, 0, 105701, 2, 1952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父さん…\\n今頃どこで\\n何してるんだろ？', 1, 1, 1, 0, 0, 105701, 3, 1953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎空艇に乗って、\\n誰もいったことがない\\n場所を見つけたいな', 1, 1, 1, 0, 0, 105701, 4, 1954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父さん以上の\\n世界一の\\n騎空士になりたい！', 1, 1, 1, 0, 0, 105701, 5, 1955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間と行く空の旅…\\n何度想像しても\\nドキドキするなぁ', 4, 1, 1, 0, 0, 105701, 101, 1956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父さん…\\n私にもね、大切な\\n仲間ができたよ', 8, 1, 1, 0, 0, 105701, 102, 1957);
