insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このふかふかの優しさ\\n主さまのようです', 1, 1, 3, 0, 0, 105902, 2, 2143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\n主さまにそっくり♪', 1, 1, 3, 0, 0, 105902, 3, 2144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この心地よさ…\\n主さまのようです♪', 1, 1, 3, 0, 0, 105902, 4, 2145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで洗濯物を\\n乾かせるでしょうか\u3000', 1, 1, 3, 0, 0, 105902, 5, 2146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁっはぁっはぁっ\\n…すべては\\n主さまのため…', 1, 1, 3, 0, 0, 105902, 6, 2147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('都会の味…\\nとてもおいしいです\\n…もぐもぐもぐ', 1, 1, 3, 0, 0, 105902, 7, 2148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('都会のことを\\n学ばないと…\\nふむふむ', 1, 1, 3, 0, 0, 105902, 8, 2149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～…あっ\\n見られちゃい\\nましたか？', 1, 1, 2, 0, 0, 190801, 1, 2151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスの\\n使い心地は\\nどうですか？', 1, 1, 2, 0, 0, 190801, 2, 2152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご用があれば\\nなんでも言って\\nくださいね～♪', 1, 1, 2, 0, 0, 190801, 3, 2153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ときどきみなさんと\\nクエストに行きたいな\\nって思っちゃいます', 1, 1, 2, 0, 0, 190801, 4, 2154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます！\\nお掃除の方、\\nはじめていきますね', 1, 1, 2, 0, 1, 190801, 1, 2155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('皆さん、お昼ごはんの\\nご要望がありましたら\\n用意致しますよ♪', 1, 1, 2, 0, 2, 190801, 2, 2156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは夜でも\\nにぎやかですね', 1, 1, 2, 0, 3, 190801, 3, 2157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…\\n少しうとうと\\nしてしまった', 1, 1, 1, 0, 0, 104701, 1, 2158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('室内だし兜を脱ぐか\\n…いや\\nやはりやめておこう', 1, 1, 1, 0, 0, 104701, 2, 2159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋にいると\\n鎧が蒸し暑くなるが\\n我慢せねば…', 1, 1, 1, 0, 0, 104701, 3, 2160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事が門番だからか\\n部屋にいても\\nじっとしてしまう…', 1, 1, 1, 0, 0, 104701, 4, 2161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年と会話したことを\\n思いだすと\\n自然と楽しくなるな', 1, 1, 1, 0, 0, 104701, 5, 2162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年のことを考えると\\n顔がにやけてしまう', 4, 1, 1, 0, 0, 104701, 101, 2163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年は今頃\\n平和に過ごせて\\nいるかな…', 8, 1, 1, 0, 0, 104701, 102, 2164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000悪いが\\n兜は脱がないぞ', 1, 1, 2, 0, 0, 104701, 1, 2165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と遊びたいのか？\\nそう言われても\\n何をしていいやら…', 1, 1, 2, 0, 0, 104701, 2, 2166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鎧が重くないかって？\\n大丈夫。けっこう\\n鍛えているからな', 1, 1, 2, 0, 0, 104701, 3, 2167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年、寒くはないか？\\nいや自分がこうなので\\n人が薄着に見えてね', 1, 1, 2, 0, 0, 104701, 4, 2168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君といると、兜の中が\\nいつもより暑いんだ', 4, 1, 2, 0, 0, 104701, 101, 2169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私としゃべりたい？\\n物好きだな\\nでも、嬉しいよ', 8, 1, 2, 0, 0, 104701, 102, 2170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早いな少年\\nえ？\u3000私の仕事に\\n合わせてくれたのか', 1, 1, 2, 0, 1, 104701, 1, 2171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食の誘い？\\n嬉しいけど\\n人前では食べないんだ', 1, 1, 2, 0, 2, 104701, 2, 2172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王宮騎士団の\\n日報を書かなければ…\\n『何事もなし』、と', 1, 1, 2, 0, 3, 104701, 3, 2173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鎧を着ているから\\n感触が分かりづらい\\nのが残念だ…', 1, 1, 3, 0, 0, 104701, 2, 2175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいいな…\\n私には似合わないが\\nぎゅ…ってしよう', 1, 1, 3, 0, 0, 104701, 3, 2176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い香りだ…\\n普段はどうしても\\n鉄くさくなるからな', 1, 1, 3, 0, 0, 104701, 4, 2177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わかっていたけど\\n鎧を着たまま暖炉に\\nあたると暑い…', 1, 1, 3, 0, 0, 104701, 5, 2178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兜を脱がずに食べる\\nうん、段々コツが\\n掴めてきた…', 1, 1, 3, 0, 0, 104701, 7, 2180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兜があっても\\n意外と本くらいは\\n難なく読めるんだ', 1, 1, 3, 0, 0, 104701, 8, 2181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('居心地よくて\\nゴロゴロしちゃうよ～\\n…いつも通りだね', 1, 1, 1, 0, 0, 102601, 1, 2183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドングリの木\\n近くに生えてない？', 1, 1, 1, 0, 0, 102601, 2, 2184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('快適な寝床があれば\\nそれだけで幸せだねぇ', 1, 1, 1, 0, 0, 102601, 3, 2185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしと一緒に\\nだらけてくれる人が\\nいそうだねぇ', 1, 1, 1, 0, 0, 102601, 4, 2186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここなら牧場よりも\\n速く配達が\\n届きそうだね～', 1, 1, 1, 0, 0, 102601, 5, 2187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんパン買ったし\\nあいつにも\\n分けてあげよう', 4, 1, 1, 0, 0, 102601, 101, 2188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと一緒に\\nだらけられたら\\n最高に幸せだね', 8, 1, 1, 0, 0, 102601, 102, 2189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドングリでも\\nつまみながら\\n一緒にゲームしようよ', 1, 1, 2, 0, 0, 102601, 1, 2190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('横になりたいから\\n枕になっておくれよ～\\nあんたあったかいしさ', 1, 1, 2, 0, 0, 102601, 2, 2191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドングリあげるから\\nあんパン買ってきて～', 1, 1, 2, 0, 0, 102601, 3, 2192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～\\n疲れちゃったよ～\\nおんぶして運んで～', 1, 1, 2, 0, 0, 102601, 4, 2193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたといると\\nリア充って\\n感じがするよ', 4, 1, 2, 0, 0, 102601, 101, 2194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたが一生\\n世話してくれたら\\n人生安泰なんだけどね', 8, 1, 2, 0, 0, 102601, 102, 2195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわ～っ…\\nおはよう…あたしは\\nまだ眠いよ', 1, 1, 2, 0, 1, 102601, 1, 2196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろお昼寝でも\\nしたい気分だねぇ', 1, 1, 2, 0, 2, 102601, 2, 2197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('徹夜でゲームするけど\\nあんたもどうだい？\\nあたしは強いよ', 1, 1, 2, 0, 3, 102601, 3, 2198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ…だめだこれ。\\n気持ち良くて\\n落ちそう…', 1, 1, 3, 0, 0, 102601, 2, 2200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいものに\\n囲まれて寝るのも\\nよさそうだねぇ…', 1, 1, 3, 0, 0, 102601, 3, 2201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心身ともに\\nリラックスした状態で\\nぐうたら出来そうだね', 1, 1, 3, 0, 0, 102601, 4, 2202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふい～…\\nごくらくごくらく…\\n暖かいねぇ', 1, 1, 3, 0, 0, 102601, 5, 2203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べてすぐ寝ると\\n牛になるって\\n本当なのかな？', 1, 1, 3, 0, 0, 102601, 7, 2205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おー！\u3000この本なら\\nあたしも居眠りせずに\\n読めそうだよ', 1, 1, 3, 0, 0, 102601, 8, 2206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソル…\\nおっきな街だなぁ…', 1, 1, 1, 0, 0, 106301, 1, 2208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ロザリア…\\nきっと、いるよね？', 1, 1, 1, 0, 0, 106301, 2, 2209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、弓の練習\\nサボっちゃってるな…', 1, 1, 1, 0, 0, 106301, 3, 2210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の私は\\n森番じゃなくて\\n家番だよ！', 1, 1, 1, 0, 0, 106301, 4, 2211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとだけ\\n慣れてきたかも？', 1, 1, 1, 0, 0, 106301, 5, 2212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか、\\nあの人と一緒に…', 4, 1, 1, 0, 0, 106301, 101, 2213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…なんか最近、\\nあの人のこと\\nばっかり…', 8, 1, 1, 0, 0, 106301, 102, 2214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしよかったら\\n街に出かけない？', 1, 1, 2, 0, 0, 106301, 1, 2215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋、\\n妖精さんも\\n気に入るかも！', 1, 1, 2, 0, 0, 106301, 2, 2216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は\\nなににしよっか？', 1, 1, 2, 0, 0, 106301, 3, 2217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はどこ行く？', 1, 1, 2, 0, 0, 106301, 4, 2218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには二人で…\\nな、なんちゃって！', 4, 1, 2, 0, 0, 106301, 101, 2219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、\\nずっと楽しいんだ！\\nあなたのおかげかな', 8, 1, 2, 0, 0, 106301, 102, 2220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\n今日も一緒に\\n頑張ろうね！', 1, 1, 2, 0, 1, 106301, 1, 2221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はどうする？\\nあなたのオススメに\\n連れて行って欲しいな', 1, 1, 2, 0, 2, 106301, 2, 2222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソルは\\n夜でも賑やかだね！', 1, 1, 2, 0, 3, 106301, 3, 2223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁっ！\\nすっごく\\nふわふわだよ！', 1, 1, 3, 0, 0, 106301, 2, 2225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわい～！\\nぎゅってしたく\\nなっちゃうかも！', 1, 1, 3, 0, 0, 106301, 3, 2226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん\\nなんか…いい匂い？', 1, 1, 3, 0, 0, 106301, 4, 2227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すっごいなー\\nあったかいなー！', 1, 1, 3, 0, 0, 106301, 5, 2228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁっ、おいしい！\\nもっと食べたい\\nかも…！', 1, 1, 3, 0, 0, 106301, 7, 2230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、文字は苦手…\\nでも、頑張らないと\\nだよね…！', 1, 1, 3, 0, 0, 106301, 8, 2231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にんじんとピーマンを\\n食べないでいい方法\\nないかな…', 1, 1, 1, 0, 0, 103601, 1, 2233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カップケーキが\\n食べたいな…', 1, 1, 1, 0, 0, 103601, 2, 2234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('予習が終わりました！\\nさて、次は復習を\\nしないと…', 1, 1, 1, 0, 0, 103601, 3, 2235);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人の部屋にいる\\n私って…もしかして\\nふしんしゃなんじゃ？', 1, 1, 1, 0, 0, 103601, 4, 2236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の人は、みんな\\nへんたいだと\\n聞きました…', 1, 1, 1, 0, 0, 103601, 5, 2237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人に、一緒に\\n遊んでほしいけど…\\nな、なんていえば？', 4, 1, 1, 0, 0, 103601, 101, 2238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早く大人になりたいな\\n…あの人と同じくらい', 8, 1, 1, 0, 0, 103601, 102, 2239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼ、防犯魔石を\\n鳴らしますよ！？', 1, 1, 2, 0, 0, 103601, 1, 2240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へんたい！？\u3000…\\nあ、あなたでしたか～\\nやっぱりへんたーい！', 1, 1, 2, 0, 0, 103601, 2, 2241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ宿題です\\nやっておいて\\nくださいね', 1, 1, 2, 0, 0, 103601, 3, 2242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、遅刻ですよ\\n待っていたんですから', 1, 1, 2, 0, 0, 103601, 4, 2243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にらめっこですか？\\nあ、あなたの前で変顔\\nするのはちょっと…', 4, 1, 2, 0, 0, 103601, 101, 2244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…何歳まで\\n子供だと思いますか？', 8, 1, 2, 0, 0, 103601, 102, 2245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('顔を洗って、着替えて\\n朝ごはんを食べて、\\n歯を磨いて…', 1, 1, 2, 0, 1, 103601, 1, 2246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('て、鉄棒の練習！？\u3000\\nほ、他のことを\\nしませんか？', 1, 1, 2, 0, 2, 103601, 2, 2247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、眠くないです\\n子供ではありません\\nから…ふわぁ', 1, 1, 2, 0, 3, 103601, 3, 2248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひと休みしよっと\\n………うん、\\nひと休みおしまい♪', 1, 1, 3, 0, 0, 103601, 2, 2250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つ、つぶらな瞳には\\n弱いんです', 1, 1, 3, 0, 0, 103601, 3, 2251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスできますね\\n集中力も\\n上がりそうです', 1, 1, 3, 0, 0, 103601, 4, 2252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいと\\n眠くなっちゃうな…\\n勉強しなくちゃなのに', 1, 1, 3, 0, 0, 103601, 5, 2253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ピーマンもこれくらい\\nおいしければ\\nいいのに…', 1, 1, 3, 0, 0, 103601, 7, 2255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本、むずかしい\\n…もっと勉強\\nがんばらなくちゃ', 1, 1, 3, 0, 0, 103601, 8, 2256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はみんなに\\nなにを読んで\\nあげようかしら', 1, 1, 1, 0, 0, 101501, 1, 2258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちと同じ\\n目線で考えるのが\\n大事よね', 1, 1, 1, 0, 0, 101501, 2, 2259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お天気が良い日は\\nみんなでお散歩に\\n行きたいわね～', 1, 1, 1, 0, 0, 101501, 3, 2260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鬼ごっこにかくれんぼ\\n…みんなは\\nどっちが好きかしら', 1, 1, 1, 0, 0, 101501, 4, 2261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お遊戯会の配役、\\n考え出すと\\n大変だわ～', 1, 1, 1, 0, 0, 101501, 5, 2262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼は優しいから、\\nきっと良い\\nお父さんになるわね', 4, 1, 1, 0, 0, 101501, 101, 2263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼には私がいないと\\n…っていうのは少し\\n過保護すぎるかしら？', 8, 1, 1, 0, 0, 101501, 102, 2264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('保育園の行事を\\n考えてるんだけど…\\n良い案ないかしら？', 1, 1, 2, 0, 0, 101501, 1, 2265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、子どもたちと\\nおやつを作るから、\\n食べに来てね', 1, 1, 2, 0, 0, 101501, 2, 2266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よかったら一緒に\\n絵本を作らない？', 1, 1, 2, 0, 0, 101501, 3, 2267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたはいつも元気ね\\n先生も見習わないと♪', 1, 1, 2, 0, 0, 101501, 4, 2268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先生は\\nずーっと、ずーっと、\\nあなたの味方だからね', 4, 1, 2, 0, 0, 101501, 101, 2269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたみたいな\\nいい子をお世話できて\\n先生は幸せものだわ', 8, 1, 2, 0, 0, 101501, 102, 2270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう～\\nちゃんと朝ごはんは\\n食べた？', 1, 1, 2, 0, 1, 101501, 1, 2271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼寝の時間ね♪\\nあなたも一緒に\\n寝ましょうか', 1, 1, 2, 0, 2, 101501, 2, 2272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すっかり真っ暗ね。\\n今日も一日、\\nよくできました♪', 1, 1, 2, 0, 3, 101501, 3, 2273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかねぇ♪\\n年甲斐もなく、\\n飛び跳ねちゃいそう', 1, 1, 3, 0, 0, 101501, 2, 2275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらあら、かわいい！\\n保育園のみんなに\\n見せてあげたいわ', 1, 1, 3, 0, 0, 101501, 3, 2276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね～\\n保育園にも\\n置こうかしら', 1, 1, 3, 0, 0, 101501, 4, 2277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒い日は、ここで\\n子どもたちに絵本を\\n読んであげましょ♪', 1, 1, 3, 0, 0, 101501, 5, 2278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味しい～♪\\n遠足に持っていったら\\nみんな喜びそう', 1, 1, 3, 0, 0, 101501, 7, 2280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなが\\n楽しめる読み聞かせの\\n方法特集♪\u3000素敵ねぇ', 1, 1, 3, 0, 0, 101501, 8, 2281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界の前に、\\nこの部屋を征服\\nしてやろう♪', 1, 1, 1, 0, 0, 104401, 1, 2283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('拠点とはやはり\\n斯くあるべきじゃの', 1, 1, 1, 0, 0, 104401, 2, 2284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属の物はわらわの物\\n故に、この部屋は\\nわらわの部屋じゃな！', 1, 1, 1, 0, 0, 104401, 3, 2285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('永く眠っている間に\\n随分と世界は変わった\\nようじゃな…', 1, 1, 1, 0, 0, 104401, 4, 2286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うるさいのう～\\nまったく、近頃の\\n若いもんは…', 1, 1, 1, 0, 0, 104401, 5, 2287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あやつが来てから\\n動悸が治まらぬ…\\n如何ような病で\\nあろうかの…', 4, 1, 1, 0, 0, 104401, 101, 2288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属よ、どこに行った\\nのじゃ？\\nわらわの世話を\\n許可するのじゃ', 8, 1, 1, 0, 0, 104401, 102, 2289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いずれ世界は\\n我が手中に収まる\\nふふふ、\\n楽しみじゃのう', 1, 1, 2, 0, 0, 104401, 1, 2290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属よ、わらわから\\n離れてはならんぞ！\\n子供に戻ってしまう\\nではないか！', 1, 1, 2, 0, 0, 104401, 2, 2291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トマトジュースが\\n欲しいのじゃ！\\n野菜ジュースでは\\nダメだぞ！', 1, 1, 2, 0, 0, 104401, 3, 2292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('蚊にくわれたぞ！\\nわらわの血を吸う\\nとは～！', 1, 1, 2, 0, 0, 104401, 4, 2293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こら、頭をなでるな\\nお主はこの姿でも\\n子供扱いするのか？', 4, 1, 2, 0, 0, 104401, 101, 2294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お主が望むなら世界の\\n半分をくれてやっても\\n良いのじゃぞ？', 8, 1, 2, 0, 0, 104401, 102, 2295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝早くから感心じゃの\\nさすがわらわの\\n眷属じゃ', 1, 1, 2, 0, 1, 104401, 1, 2296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('太陽は苦手じゃ…\\nこの部屋の中で\\n過ごそうぞ', 1, 1, 2, 0, 2, 104401, 2, 2297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜も更けてきた！\\nわらわ達の時間は\\nこれからじゃ～♪', 1, 1, 2, 0, 3, 104401, 3, 2298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よい座り心地じゃ\\nわらわの玉座としよう', 1, 1, 3, 0, 0, 104401, 2, 2300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛いではないか\\nわらわの眷属に\\nしてやろうかのう', 1, 1, 3, 0, 0, 104401, 3, 2301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ、良い気持ちじゃ\\nこれを作った者、\\n褒めてつかわすぞ', 1, 1, 3, 0, 0, 104401, 4, 2302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたたかい…\\n身も心も\\n浄化されるようじゃ', 1, 1, 3, 0, 0, 104401, 5, 2303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼のわらわが、\\nこのようなもの…\\nうまい♪', 1, 1, 3, 0, 0, 104401, 7, 2305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このまま大人の姿を\\n保つ方法…どこかに\\n書いてないかのう', 1, 1, 3, 0, 0, 104401, 8, 2306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いろんな人がいて\\nいろんな服を着てて…\\n目の保養になります♪', 1, 1, 1, 0, 0, 105401, 1, 2308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レイ様への新作\\nどんな服にしよう…\\n方向性が絞れない～！', 1, 1, 1, 0, 0, 105401, 2, 2309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('忘れないうちに\\n隠し糸のメンテナンス\\nやっておこうっと！', 1, 1, 1, 0, 0, 105401, 3, 2310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むっ！\u3000あの人の\\nスリーサイズは…\\nほほう…なるほど♪', 1, 1, 1, 0, 0, 105401, 4, 2311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ノゾミさんの\\n衣装はああして\\nチカさんのは…', 1, 1, 1, 0, 0, 105401, 5, 2312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私がアイドル…\\n…実感ないけど\\n精一杯やってみよう', 4, 1, 1, 0, 0, 105401, 101, 2313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさか私が\\nアイドルになるなんて\\n思ってなかったです', 8, 1, 1, 0, 0, 105401, 102, 2314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんですかぁ？\\n衣装作りで疲れて\\n眠いんですぅ…', 1, 1, 2, 0, 0, 105401, 1, 2315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーっ！\u3000また\\n服がほつれてる…\\nしょうがないですね', 1, 1, 2, 0, 0, 105401, 2, 2316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はっ！\u3000ちょうど今\\n新しいデザインが\\n思い浮かびました！', 1, 1, 2, 0, 0, 105401, 3, 2317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇そうですね？\\n時間あるなら仕事\\n手伝ってください！', 1, 1, 2, 0, 0, 105401, 4, 2318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしました？\\n新しい服が\\n欲しくなりましたか？', 4, 1, 2, 0, 0, 105401, 101, 2319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんのおかげで\\nカルミナでも\\n頑張れてますよ！', 8, 1, 2, 0, 0, 105401, 102, 2320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます…\\nなんで朝って毎日\\nやってくるんでしょう', 1, 1, 2, 0, 1, 105401, 1, 2321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空きましたね\\n騎士さんはちゃんと\\n御飯食べましたか？', 1, 1, 2, 0, 2, 105401, 2, 2322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の方が\\n作業が捗るのは\\n私だけですかね？', 1, 1, 2, 0, 3, 105401, 3, 2323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このふかふか具合\\nいい素材を\\n使ってますね', 1, 1, 3, 0, 0, 105401, 2, 2325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小さくて可愛い♪\\nそうだ！\u3000レイ様の\\nぬいぐるみを…！', 1, 1, 3, 0, 0, 105401, 3, 2326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう時くらい\\n何も考えずに\\nリラックスしないと♪', 1, 1, 3, 0, 0, 105401, 4, 2327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('炎を使った服って\\nカッコ良いかも…\\nでも材料がな～…', 1, 1, 3, 0, 0, 105401, 5, 2328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何をするにも\\n食事は大切！\\n体力が資本です！', 1, 1, 3, 0, 0, 105401, 7, 2330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私もいつか\\nデザインを\\nまとめて本に…', 1, 1, 3, 0, 0, 105401, 8, 2331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またお魚を\\n捕りにいこうかな♪', 1, 1, 1, 0, 0, 107501, 1, 2333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろみんなも\\nお腹が空くころ\\nじゃないですか～？', 1, 1, 1, 0, 0, 107501, 2, 2334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここなら、\\n日焼けの心配は\\nありませんね！', 1, 1, 1, 0, 0, 107501, 3, 2335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お刺身に焼き貝…\\nお腹が魚介類を\\n求めてますっ！', 1, 1, 1, 0, 0, 107501, 4, 2336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐのも食べるのも\\n大得意です！', 1, 1, 1, 0, 0, 107501, 5, 2337);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人と二人で\\n浜辺を散歩…\\n素敵ですねぇ', 4, 1, 1, 0, 0, 107501, 101, 2338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人に水着を\\n褒めてもらえたら、\\nすごく嬉しいなぁ', 8, 1, 1, 0, 0, 107501, 102, 2339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには釣りじゃなく\\n一緒に素潜りでも\\n行きませんか？', 1, 1, 2, 0, 0, 107501, 1, 2340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の子に水着を\\n見られるのって\\n少し緊張しちゃいます', 1, 1, 2, 0, 0, 107501, 2, 2341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスの\\nみんなとも、\\n海に行きたいですね！', 1, 1, 2, 0, 0, 107501, 3, 2342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの水着、\\n私が選んであげます！', 1, 1, 2, 0, 0, 107501, 4, 2343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぎの練習なら\\n付き合いますよ！\\n手取り足取り♪', 4, 1, 2, 0, 0, 107501, 101, 2344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿が好きなら\\nいくらでも\\n着てあげますよぉ♪', 8, 1, 2, 0, 0, 107501, 102, 2345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の海も\\n幻想的で\\nいいですよねぇ～！', 1, 1, 2, 0, 1, 107501, 1, 2346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はみんなで、\\n海鮮バーベキューとか\\nどうでしょう！', 1, 1, 2, 0, 2, 107501, 2, 2347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海は星が\\nきれいですよ！\\n見に行きましょう！', 1, 1, 2, 0, 3, 107501, 3, 2348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぎ疲れたので\\nちょっと休憩です～', 1, 1, 3, 0, 0, 107501, 2, 2350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたにも、\\n可愛い水着を\\n着せてあげたいです', 1, 1, 3, 0, 0, 107501, 3, 2351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか、\\nリゾート気分です…', 1, 1, 3, 0, 0, 107501, 4, 2352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふい～、泳ぎで冷えた\\n身体を暖めましょう～', 1, 1, 3, 0, 0, 107501, 5, 2353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいひ～です～\\nこれ、海水浴にも\\n持っていきたいですね', 1, 1, 3, 0, 0, 107501, 7, 2355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('南国のフルーツ図鑑\\n…じゅるり…', 1, 1, 3, 0, 0, 107501, 8, 2356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ～♪\u3000おいしそ…\\nか、かわいいですね～', 1, 1, 3, 0, 0, 107501, 10, 2358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これくらい大きな貝…\\n食べたいな～\\n食べたいな～～', 1, 1, 3, 0, 0, 107501, 11, 2359);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好で\\n部屋をうろつくのは\\n不思議な感じがします', 1, 1, 1, 0, 0, 107601, 1, 2360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('南国の果実を使って\\n主さまにデザートを\\nお作りしましょう', 1, 1, 1, 0, 0, 107601, 2, 2361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの水着ですし\\nこれから定期的に\\n海水浴に行きたいです', 1, 1, 1, 0, 0, 107601, 3, 2362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の生き物も、\\n森の生き物に負けず\\n可愛かったです…', 1, 1, 1, 0, 0, 107601, 4, 2363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クロールの練習なら、\\n部屋でもできそうです', 1, 1, 1, 0, 0, 107601, 5, 2364);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまに、水着姿を\\n褒めていただけた…\\nえへへ♪', 4, 1, 1, 0, 0, 107601, 101, 2365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着で主さまの\\nお世話をしたら、\\n喜びますでしょうか…', 8, 1, 1, 0, 0, 107601, 102, 2366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お疲れでしたら\\nわたくしの膝を\\nお使いくださいね', 1, 1, 2, 0, 0, 107601, 1, 2367);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま、海の家で\\nつかうおこづかいを\\n渡しておきますね', 1, 1, 2, 0, 0, 107601, 2, 2368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の美しさは、\\n森とはちがう\\n魅力がありました', 1, 1, 2, 0, 0, 107601, 3, 2369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この髪飾りですか？\\n造花ですから\\n水の中も平気です', 1, 1, 2, 0, 0, 107601, 4, 2370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着でくっついて\\n眠ると、いつもより\\n密着して暖かいです', 4, 1, 2, 0, 0, 107601, 101, 2371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はじめての海が、\\n主さまと一緒で\\n幸せです♪', 8, 1, 2, 0, 0, 107601, 102, 2372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます。\\n泳ぎに行く準備は\\n万端です', 1, 1, 2, 0, 1, 107601, 1, 2373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午後は泳ぐのをやめて\\nスイカ割りなど\\nいかがでしょう？', 1, 1, 2, 0, 2, 107601, 2, 2374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜も更けてきました…\\n波の音を聞きながら\\n少しお話しませんか？', 1, 1, 2, 0, 3, 107601, 3, 2375);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あぅ…この家具には、\\n人をダメにする魔法が\\nかけられています…', 1, 1, 3, 0, 0, 107601, 2, 2377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ♪\\nあなたも、海水浴に\\n行きますか？', 1, 1, 3, 0, 0, 107601, 3, 2378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…\\nきっと主さまも\\n気に入ります', 1, 1, 3, 0, 0, 107601, 4, 2379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは暖かいです…\\n後ほど主さまと一緒に\\nあたりましょう', 1, 1, 3, 0, 0, 107601, 5, 2380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳いだ後の食事は\\n一段と美味しく\\n感じます', 1, 1, 3, 0, 0, 107601, 7, 2382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('深海魚の生態…\\nこれは主さまにも\\nお伝えしなくては…', 1, 1, 3, 0, 0, 107601, 8, 2383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('顔立ちが、主さまに\\n似ております…\\nかわいらしい♪', 1, 1, 3, 0, 0, 107601, 10, 2385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかですね\\n主さまのようです♪', 1, 1, 3, 0, 0, 107601, 11, 2386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お掃除、お掃除\\nふんふふ～ん☆\\nあ、聞かれてました？', 1, 1, 1, 0, 0, 107701, 1, 2387);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日焼けには回復魔法が\\n効きますよ。どうして\\n逃げるんですか～！', 1, 1, 1, 0, 0, 107701, 2, 2388);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はドジを\\nしませんように！', 1, 1, 1, 0, 0, 107701, 3, 2389);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('接客業を極めれば\\nメイドとして\\n成長できるかも？', 1, 1, 1, 0, 0, 107701, 4, 2390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着って\\n動きやすいんですけど\\n人の目が気になります', 1, 1, 1, 0, 0, 107701, 5, 2391);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人の気持ちを知る\\n魔法とかあれば…\\nな、なんでもないです', 4, 1, 1, 0, 0, 107701, 101, 2392);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着でご奉仕したら、\\nあの人は喜ぶかな？', 8, 1, 1, 0, 0, 107701, 102, 2393);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑いのでしたら、\\n私が魔法で涼しく…\\nえ？\u3000いらない？', 1, 1, 2, 0, 0, 107701, 1, 2394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か御用ですか？\\n特にないのでしたら、\\nお話ししましょう♪', 1, 1, 2, 0, 0, 107701, 2, 2395);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿でも\\nメイドはメイドです\\nご奉仕しますよ！', 1, 1, 2, 0, 0, 107701, 3, 2396);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっ！\u3000あ、危うく\\n転ぶところでした…\\n…きゃうっ！', 1, 1, 2, 0, 0, 107701, 4, 2397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしましたか？\\nあなたの御用なら、\\n喜んでお受けしますよ', 4, 1, 2, 0, 0, 107701, 101, 2398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿をあなたに\\n見られると、\\nドキドキしちゃいます', 8, 1, 2, 0, 0, 107701, 102, 2399);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は暑くてやる気が\\n出ない？\u3000でしたら、\\nえぇい、元気になぁれ', 1, 1, 2, 0, 1, 107701, 1, 2400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹がぺこぺこなら、\\nお昼は海の家で\\n食べましょう♪', 1, 1, 2, 0, 2, 107701, 2, 2401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の浜辺でお散歩も\\nいいですね。たくさん\\n転びそうですけど…', 1, 1, 2, 0, 3, 107701, 3, 2402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩しながら、\\nお掃除すれば\\n一石二鳥です！', 1, 1, 3, 0, 0, 107701, 2, 2404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいにすれば\\nかわいさも倍増\\nですよ～♪', 1, 1, 3, 0, 0, 107701, 3, 2405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵な香りです～\\n救護院に置けば、\\nみんな喜ぶかも～', 1, 1, 3, 0, 0, 107701, 4, 2406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいですね…\\nはっ！\u3000いけません！\\nメイドがサボるなんて', 1, 1, 3, 0, 0, 107701, 5, 2407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理のできない\\nメイドなんて…\\nはぐはぐ、おいしい♪', 1, 1, 3, 0, 0, 107701, 7, 2409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿で接客をすると\\n売り上げが倍になる\\n…本当ですか、これ', 1, 1, 3, 0, 0, 107701, 8, 2410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ♪\\n南の島まで\\n乗せてください！', 1, 1, 3, 0, 0, 107701, 10, 2412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか、\\n人魚姫に\\nなった気分です♪', 1, 1, 3, 0, 0, 107701, 11, 2413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなで過ごす\\n休日っていいわよね…\\nずっと続かないかな', 1, 1, 1, 0, 0, 107801, 1, 2414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に浮輪でぷかぷか\\n浮かぶのって\\n癖になりそう', 1, 1, 1, 0, 0, 107801, 2, 2415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーチにいると\\n日焼けが心配だわ', 1, 1, 1, 0, 0, 107801, 3, 2416);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿って楽よね。\\n室内だとちょっと\\n落ち着かないけど…', 1, 1, 1, 0, 0, 107801, 4, 2417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、泳ぎの練習なんて\\nしないからね！', 1, 1, 1, 0, 0, 107801, 5, 2418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽しすぎて立場を\\n忘れそう…あんたの\\nせいなんだから！', 4, 1, 1, 0, 0, 107801, 101, 2419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなで遊んで\\n美味しいもの食べて\\nほんっとに楽しいっ♪', 8, 1, 1, 0, 0, 107801, 102, 2420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マジであっついわね…\\nよっし！\u3000海に入って\\n涼みましょ！', 1, 1, 2, 0, 0, 107801, 1, 2421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シャワー浴びたばかり\\nなのに…また、遊び\\nたくなってきたわ！', 1, 1, 2, 0, 0, 107801, 2, 2422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遊び足りないって？\\nしょうがないわね…\\n付き合ってあげるわ♪', 1, 1, 2, 0, 0, 107801, 3, 2423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一応伝えておくけど\\n猫って水が苦手なの！\\nわかった！？', 1, 1, 2, 0, 0, 107801, 4, 2424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしと話したいの？\\nふふ。\\nまぁ、いいわよ。\\nほら隣に座りなさい', 4, 1, 2, 0, 0, 107801, 101, 2425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなに楽しいの\\n初めてかも…\\nずっと続けばいいのに', 8, 1, 2, 0, 0, 107801, 102, 2426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は、早起きしたのは、\\n楽しみで眠れなかった\\nからじゃないわよ！', 1, 1, 2, 0, 1, 107801, 1, 2427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食後のストレッチ\\n終わり！\u3000さあ、\\nビーチが待ってるわ！', 1, 1, 2, 0, 2, 107801, 2, 2428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海に散歩に\\n行こうかな～\\nあんたも来なさいよ☆', 1, 1, 2, 0, 3, 107801, 3, 2429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海ではしゃぎすぎて\\n疲れたわ…ちょっと\\n休もうかしら？', 1, 1, 3, 0, 0, 107801, 2, 2431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな魔物がいたら\\n操るのも楽しいかも', 1, 1, 3, 0, 0, 107801, 3, 2432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃう～♪\\nまるで南国にいる\\n気分ね♪', 1, 1, 3, 0, 0, 107801, 4, 2433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかぁい♪\\n身体が冷えてきたから\\n丁度いいわ！', 1, 1, 3, 0, 0, 107801, 5, 2434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動後のご飯って\\nなんでこんなに\\n美味しいんだろ♪', 1, 1, 3, 0, 0, 107801, 7, 2436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなカナヅチでも、\\n絶対必ず泳げる方法、\\n書いてないかしら？', 1, 1, 3, 0, 0, 107801, 8, 2437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたもあたしが\\n操ってあげる！\\nなんてね～♪', 1, 1, 3, 0, 0, 107801, 10, 2439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リゾートリゾートっ\\nのんびりしましょ♪', 1, 1, 3, 0, 0, 107801, 11, 2440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここなら思う存分\\nデスクワークに\\n励めるわね！', 1, 1, 1, 0, 0, 108001, 1, 2441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('武器のメンテナンスも\\nしっかりしないと\\n最高効率は望めないわ', 1, 1, 1, 0, 0, 108001, 2, 2442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('準備をしっかり整えて\\nもっともっと\\n稼がなくちゃね！', 1, 1, 1, 0, 0, 108001, 3, 2443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し休んだら\\n次のバイトに\\n行ってくるわね！', 1, 1, 1, 0, 0, 108001, 4, 2444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好でここに\\nいるのって\\n気恥ずかしいわね…', 1, 1, 1, 0, 0, 108001, 5, 2445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミが望むなら\\n今日のバイト\\n休んでもいいわよ？', 4, 1, 1, 0, 0, 108001, 101, 2446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミだけね…\\n私のことをここまで\\n理解してくれるのは', 8, 1, 1, 0, 0, 108001, 102, 2447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('普段と違う格好\\nだからって\\nそんなに見ないでよ…', 1, 1, 2, 0, 0, 108001, 1, 2448);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミを立派な\\nバイト戦士にするのが\\n師匠としての役目よね', 1, 1, 2, 0, 0, 108001, 2, 2449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ次のバイトに\\n行かないと…\\nキミも一緒に来る？', 1, 1, 2, 0, 0, 108001, 3, 2450);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('効率は大事だけど\\nゆっくりするのも\\n悪くないわね', 1, 1, 2, 0, 0, 108001, 4, 2451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒の時間が楽しくて\\nバイトのことを\\n忘れちゃいそうね', 4, 1, 2, 0, 0, 108001, 101, 2452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒なら\\nどんなミッションも\\n楽勝ね！', 8, 1, 2, 0, 0, 108001, 102, 2453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう、いい朝ね！\\n今日もめいっぱい\\n稼ぐわよ！', 1, 1, 2, 0, 1, 108001, 1, 2454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうお昼だったのね…\\n内職のバイトに\\n集中しすぎちゃったわ', 1, 1, 2, 0, 2, 108001, 2, 2455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スケジュールは、と…\\nこういう管理の徹底が\\n効率を生み出すのよ♪', 1, 1, 2, 0, 3, 108001, 3, 2456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり働いて休む…\\n最高効率にまた一歩\\n近づいたわね', 1, 1, 3, 0, 0, 108001, 2, 2458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なごんじゃうわね…\\nよぉし、次のバイトも\\n頑張らないと！', 1, 1, 3, 0, 0, 108001, 3, 2459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね…\\n働く意欲が\\n湧いてくるわ', 1, 1, 3, 0, 0, 108001, 4, 2460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身体が冷えたから\\n助かるわ…冷えは\\n女の天敵だもの', 1, 1, 3, 0, 0, 108001, 5, 2461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海のバイトは\\n体力勝負よ\\nエネルギーはしっかり\\n摂取しないとね！', 1, 1, 3, 0, 0, 108001, 7, 2463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('座学も大切ね\\nもっと知識を\\n身につけないと…', 1, 1, 3, 0, 0, 108001, 8, 2464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の楽園みたいね…\\n今だけは効率を\\n忘れちゃいそう…', 1, 1, 3, 0, 0, 108001, 10, 2466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着くわ…\\n海とひとつになった\\n気分ね！', 1, 1, 3, 0, 0, 108001, 11, 2467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと休憩にゃ～\\n潮風は体に\\n良くないにゃ～', 1, 1, 1, 0, 0, 107901, 1, 2468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫グッズで\\n海の家を飾りたいにゃ', 1, 1, 1, 0, 0, 107901, 2, 2469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の幸は美味しいけど\\n水はイヤだにゃ…', 1, 1, 1, 0, 0, 107901, 3, 2470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('開店にゃ！\\nこのたい焼きなら\\nきっと大繁盛にゃ！', 1, 1, 1, 0, 0, 107901, 4, 2471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海と言えば水着にゃ\\n似合ってるかにゃ？', 1, 1, 1, 0, 0, 107901, 5, 2472);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミが頼むなら\\n手伝ってあげても\\nいいにゃ', 4, 1, 1, 0, 0, 107901, 101, 2473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの宝は\\nここにあるにゃ～', 8, 1, 1, 0, 0, 107901, 102, 2474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃ？\\nそんなに見つめても\\n何も出ないにゃ', 1, 1, 2, 0, 0, 107901, 1, 2475);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今からキミを\\nあたしの相棒に\\n任命するにゃ！', 1, 1, 2, 0, 0, 107901, 2, 2476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これから\\n開店の準備にゃ\\nキミも手伝って\\nくれるのかにゃ？', 1, 1, 2, 0, 0, 107901, 3, 2477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の家で出す\\n新しいメニューを\\n考え中なのにゃ～', 1, 1, 2, 0, 0, 107901, 4, 2478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒なら\\n売上げナンバーワンに\\nなれるにゃ！', 4, 1, 2, 0, 0, 107901, 101, 2479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒にいると\\n楽しくて、もっと\\nいたくなるにゃ', 8, 1, 2, 0, 0, 107901, 102, 2480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようにゃ！\\n今日も頑張って\\nいくにゃー！', 1, 1, 2, 0, 1, 107901, 1, 2481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたにゃ～…\\nお魚、ちょっとだけ、\\nつまみ食いするにゃ', 1, 1, 2, 0, 2, 107901, 2, 2482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日の準備は万端にゃ\\nいつでも\\n出発できるにゃ', 1, 1, 2, 0, 3, 107901, 3, 2483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このふかふか具合\\nまるで子猫の\\n毛並みのようにゃ～', 1, 1, 3, 0, 0, 107901, 2, 2485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃにゃ～\\nなんてかわいさにゃ～', 1, 1, 3, 0, 0, 107901, 3, 2486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この匂い…\\nもう少し香ばしいと\\nいいかもしれないにゃ', 1, 1, 3, 0, 0, 107901, 4, 2487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃ～…\\nあったかくて\\nぬくぬくだにゃ～', 1, 1, 3, 0, 0, 107901, 5, 2488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('働くにはまず体力にゃ\\nしっかり食べて\\nスタミナアップ\\nだにゃ!', 1, 1, 3, 0, 0, 107901, 7, 2490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nここにお宝が\\n眠ってるんだにゃ', 1, 1, 3, 0, 0, 107901, 8, 2491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シードレイクにゃ！\\n本物は怖かったけど、\\nぬいぐるみなら\\nかわいいにゃ～', 1, 1, 3, 0, 0, 107901, 10, 2493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貝なのにふかふかの\\nクッションにゃ！\\n屋台の前にも\\n置いてみたいにゃあ', 1, 1, 3, 0, 0, 107901, 11, 2494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人の家って、道場とは\\n違った香りがするね', 1, 1, 1, 0, 0, 103701, 1, 2495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと退屈だね…\\nあの人をからかいに\\n行こうかな♪', 1, 1, 1, 0, 0, 103701, 2, 2496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('普通の女の子みたいに\\n遊びたいって思う\\nこともあるんだよね', 1, 1, 1, 0, 0, 103701, 3, 2497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('剣の手入れを怠らない\\nようにしないと。\\nいざという時、困るし', 1, 1, 1, 0, 0, 103701, 4, 2498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっと\\n上手く立ち回って\\n出世したいな', 1, 1, 1, 0, 0, 103701, 5, 2499);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかえりなさい！\\nふふ、なんだか奥さん\\nになった気分だよ♪', 4, 1, 1, 0, 0, 103701, 101, 2500);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('恥ずかしくて、あなた\\nを見られないよ…\\n私らしくないなぁ…', 8, 1, 1, 0, 0, 103701, 102, 2501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、お話好きなんだ。\\nどうせなら楽しい話を\\nしたいな♪', 1, 1, 2, 0, 0, 103701, 1, 2502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女の子っぽい子と、\\n男勝りな子、あなたは\\nどっちが好き？', 1, 1, 2, 0, 0, 103701, 2, 2503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ見回りの\\n時間かな。あなたも\\n一緒に行く？', 1, 1, 2, 0, 0, 103701, 3, 2504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('構って欲しいのかな？\\nそれじゃ一緒に\\nランニングに行こうか', 1, 1, 2, 0, 0, 103701, 4, 2505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('二人で出かけるなら、\\n手を繋がないとね。\\nあはは、冗談冗談♪', 4, 1, 2, 0, 0, 103701, 101, 2506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、あなた♪\\nおや、顔が真っ赤だ！\\n…ふふ、私も、かな？', 8, 1, 2, 0, 0, 103701, 102, 2507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私は朝から鍛錬だよ。\\n慣れてるけど大変だ。\\nお互いに頑張ろうね', 1, 1, 2, 0, 1, 103701, 1, 2508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鍛錬でお腹ぺこぺこ。\\nお昼ごはんが\\n楽しみだね', 1, 1, 2, 0, 2, 103701, 2, 2509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日見回りと\\n鍛錬を頑張ったよ。\\nあなたもお疲れさま', 1, 1, 2, 0, 3, 103701, 3, 2510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いざという時のため\\nにも、休憩は大事だね', 1, 1, 3, 0, 0, 103701, 2, 2512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうものには\\n今まで\\n縁がなかったけど。\\nうん、可愛いね♪', 1, 1, 3, 0, 0, 103701, 3, 2513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('精神統一に通じる\\nものがあるね。\\nふぅ、癒されるなぁ', 1, 1, 3, 0, 0, 103701, 4, 2514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいなぁ。\\nたまにはのんびり\\nしようか', 1, 1, 3, 0, 0, 103701, 5, 2515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鍛錬後はすごくお腹が\\n空くんだよね。\\nう～ん、おいしい♪', 1, 1, 3, 0, 0, 103701, 7, 2517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('剣術書だけで強くなる\\nには飛びぬけた才能と\\n努力が必要だよね', 1, 1, 3, 0, 0, 103701, 8, 2518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正義の刃で\\n悪を挫く！\\n…キマったッス♪', 1, 1, 1, 0, 0, 100501, 1, 2520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローの\\n秘密特訓を\\n始めるッスよ～！', 1, 1, 1, 0, 0, 100501, 2, 2521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正義の味方目指して\\n今日も明日も\\n全力ッスよ♪', 1, 1, 1, 0, 0, 100501, 3, 2522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一日一善！\\nヒーローだったら\\n当たり前ッス♪', 1, 1, 1, 0, 0, 100501, 4, 2523);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうッスか\\nこのポーズ！\\nイイ感じッスか？', 1, 1, 1, 0, 0, 100501, 5, 2524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('た、たまには\\nよく頑張ったねって\\n褒めてほしいッス…', 4, 1, 1, 0, 0, 100501, 101, 2525);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分を信じてくれる\\nあんたと一緒なら\\n何でもやれるッス！', 8, 1, 1, 0, 0, 100501, 102, 2526);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おつかれッス♪\\n冒険の準備は\\nばっちりッスよ！', 1, 1, 2, 0, 0, 100501, 1, 2527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたんッスか？\\n…はっ！\u3000もしや敵が\\n迫ってるんスかっ！？', 1, 1, 2, 0, 0, 100501, 2, 2528);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('べ、別に\\n頭を撫でてほしいとか\\n思ってないッスよ？', 1, 1, 2, 0, 0, 100501, 3, 2529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スーパーヒーロー\\nトラタイガーは\\n絶対無敵ッス！', 1, 1, 2, 0, 0, 100501, 4, 2530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと自分で\\n正義の心を燃やして\\n悪を一網打尽ッス！', 4, 1, 2, 0, 0, 100501, 101, 2531);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと一緒だと\\n幸せな気持ちに\\nなるんッス…♪', 8, 1, 2, 0, 0, 100501, 102, 2532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、早いッスね～♪\\n今日も一日一善\\nよろしくッス！', 1, 1, 2, 0, 1, 100501, 1, 2533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休みしながら\\nヒーローについて\\n語り合うッスよ～！', 1, 1, 2, 0, 2, 100501, 2, 2534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜のパトロールで\\n一緒に平和を\\n守るッス！', 1, 1, 2, 0, 3, 100501, 3, 2535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅぅ…\\n落ち着くッスね\\n戦士の休息ッス♪', 1, 1, 3, 0, 0, 100501, 2, 2537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くぅぅ、可愛いッス…\\nヒーローが守るべき\\n愛らしさッスね！', 1, 1, 3, 0, 0, 100501, 3, 2538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんスかこの香り？\\nすぅぅ…ふぅぅ…\\n力がみなぎるッス！', 1, 1, 3, 0, 0, 100501, 4, 2539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('優しい光ッスね…\\nヒーローの優しさ\\nそのものッス！', 1, 1, 3, 0, 0, 100501, 5, 2540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あむあむあむ…\\nんぅう、元気が溢れて\\n止まらないッス！', 1, 1, 3, 0, 0, 100501, 7, 2542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トラタイガーのお話は\\n笑いあり涙ありで\\n超おすすめッス！', 1, 1, 3, 0, 0, 100501, 8, 2543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハッピーハロウィン\\nお父さん、お菓子は…\\n食べられないね', 1, 1, 1, 0, 0, 108101, 1, 2545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トリックオアトリート\\nお菓子をくれないと\\n不吉な占いをします', 1, 1, 1, 0, 0, 108101, 2, 2546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、あなたの後ろで\\n霊のみなさんが\\n踊り始めました', 1, 1, 1, 0, 0, 108101, 3, 2547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('霊感がいつも以上に\\n冴えているので\\n占いの調子も良好です', 1, 1, 1, 0, 0, 108101, 4, 2548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父はハロウィンが\\n大好きだそうです\\n大胆な格好をする子が\\n多いので…', 1, 1, 1, 0, 0, 108101, 5, 2549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたは霊たちにも\\n大人気ですよね\\n私も見てほしいな…', 4, 1, 1, 0, 0, 108101, 101, 2550);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンの賑やかさ\\n今は好きです…\\nあなたといられるので', 8, 1, 1, 0, 0, 108101, 102, 2551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('霊のみなさんとの\\nダンスパーティー…\\n楽しみです', 1, 1, 2, 0, 0, 108101, 1, 2552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、元気だね\\nえ？\u3000ここは色んな\\n女の子に会えて幸せ？', 1, 1, 2, 0, 0, 108101, 2, 2553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンのお菓子\\n食べすぎちゃったな…\\nでも、美味しかった…', 1, 1, 2, 0, 0, 108101, 3, 2554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの女難の相…\\n悪化していますね\\nお祓いが必要かも', 1, 1, 2, 0, 0, 108101, 4, 2555);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの、霊のみなさんが\\nあなたと踊りたいと…\\nえっと、私も…', 4, 1, 2, 0, 0, 108101, 101, 2556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと手を繋ぐと\\n胸が苦しくなります\\nでも、繋ぎたいな…', 8, 1, 2, 0, 0, 108101, 102, 2557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハッピーハロウィン…\\n父が元気なので\\n今日の運気は良好です', 1, 1, 2, 0, 1, 108101, 1, 2558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('父はお昼寝中です\\n本当に寝ているかは\\n私にも分かりませんが', 1, 1, 2, 0, 2, 108101, 2, 2559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、\\nもう眠っちゃったの？\\n…眠れるんだったっけ', 1, 1, 2, 0, 3, 108101, 3, 2560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着きますね…\\n霊のみなさんも\\n喜んでいます', 1, 1, 3, 0, 0, 108101, 2, 2562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つん、つん。ふふっ♪\\n癒やされます…', 1, 1, 3, 0, 0, 108101, 3, 2563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('精神が研ぎ澄まされる\\n香りですね…\\n占いが捗ります', 1, 1, 3, 0, 0, 108101, 4, 2564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいね\\nお父さん…\\nえ？\u3000分からない？', 1, 1, 3, 0, 0, 108101, 5, 2565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('霊のみなさんは\\n食べられないので…\\n私がいただきます', 1, 1, 3, 0, 0, 108101, 7, 2567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さんを元に戻す\\n手掛かり…\\n書かれていないかな？', 1, 1, 3, 0, 0, 108101, 8, 2568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、お菓子が沢山…', 1, 1, 3, 0, 0, 108101, 12, 2570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('無料でプリンが\\nもらえるなんて、\\nハロウィンはすごいの', 1, 1, 1, 0, 0, 108201, 1, 2572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('生きてるときも、\\nミヤコはハロウィンが\\n好きだった気がするの', 1, 1, 1, 0, 0, 108201, 2, 2573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなに仮装を\\n見せつけて、\\nプリンをもらうの～', 1, 1, 1, 0, 0, 108201, 3, 2574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この仮装で、\\nみんなに恐怖を\\n教えてやるの！', 1, 1, 1, 0, 0, 108201, 4, 2575);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アオーン、アオーン！\\nミヤコ、狼女に\\nなりきってるの～', 1, 1, 1, 0, 0, 108201, 5, 2576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツに秘密で、\\nパーティーの\\n飾り付けをするの♪', 4, 1, 1, 0, 0, 108201, 101, 2577);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツが狼男の\\n仮装をすれば、\\nおそろいなの～', 8, 1, 1, 0, 0, 108201, 102, 2578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンをくれなきゃ、\\nオマエをカボチャに\\nしてやるの～', 1, 1, 2, 0, 0, 108201, 1, 2579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンは幽霊でも\\n参加できるから\\n楽しいの～！', 1, 1, 2, 0, 0, 108201, 2, 2580);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンがないなら\\nカボチャプリンを\\n食べればいいの！', 1, 1, 2, 0, 0, 108201, 3, 2581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンの可能性は\\n無限大なの～', 1, 1, 2, 0, 0, 108201, 4, 2582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエの隣で\\nプリンを食べると、\\nいつもより美味しいの', 4, 1, 2, 0, 0, 108201, 101, 2583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエが死んでも、\\nミヤコはずーっと\\n一緒にいてやるの～', 8, 1, 2, 0, 0, 108201, 102, 2584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ごはんは\\nカボチャプリンなの！\\nハロウィンっぽいの～', 1, 1, 2, 0, 1, 108201, 1, 2585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランチは豪華に\\nプリンアラモードなの', 1, 1, 2, 0, 2, 108201, 2, 2586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜は幽霊たちと\\nハロウィンするの！\\nオマエも来るの！', 1, 1, 2, 0, 3, 108201, 3, 2587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊にも休息は\\n必要なの！\\nプリンもってこいなの', 1, 1, 3, 0, 0, 108201, 2, 2589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエもミヤコの\\nパーティーに\\n招待してあげるの～', 1, 1, 3, 0, 0, 108201, 3, 2590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('癒されるの～\\nまるで天国なの～', 1, 1, 3, 0, 0, 108201, 4, 2591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでなら、\\n焼きプリンが\\n作れるの！', 1, 1, 3, 0, 0, 108201, 5, 2592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹が減っては\\nハロウィンは\\nできぬなの！', 1, 1, 3, 0, 0, 108201, 7, 2594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('丸ごとカボチャ\\nプリン特集！？\\n美味しそうなの～♪', 1, 1, 3, 0, 0, 108201, 8, 2595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子がたくさんで、\\nミヤコはとっても\\nハッピーなの♪', 1, 1, 3, 0, 0, 108201, 12, 2597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔女以外にも、\\n色々な仮装を\\nしてみたいわね', 1, 1, 1, 0, 0, 108301, 1, 2599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チョコやアメよりも、\\nアタシに相応しい\\nスイーツがあるはず…', 1, 1, 1, 0, 0, 108301, 2, 2600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子の食べ過ぎは、\\nお母さんに\\n怒られるかも…', 1, 1, 1, 0, 0, 108301, 3, 2601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好で学院に\\n行ったら、\\nみんな驚くかしら', 1, 1, 1, 0, 0, 108301, 4, 2602);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人のレディは、\\nどういうハロウィンを\\n過ごすべきかしら…？', 1, 1, 1, 0, 0, 108301, 5, 2603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子、アイツの分も\\nとっといてあげよ！\\n大人の余裕ってやつね', 4, 1, 1, 0, 0, 108301, 101, 2604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツを魅了する\\n魔法とかないかしら？', 8, 1, 1, 0, 0, 108301, 102, 2605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おしゃれスイーツを\\nくれなきゃ\\nイタズラするわよ！', 1, 1, 2, 0, 0, 108301, 1, 2606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシの大人センスで\\nアンタに似合う仮装を\\n選んであげるわ！', 1, 1, 2, 0, 0, 108301, 2, 2607);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不気味よねぇ…\\nジャックオーランタン\\nこ、怖くないわよ？', 1, 1, 2, 0, 0, 108301, 3, 2608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンが楽しくて\\n宿題やり忘れてたわ…\\nて、手伝って～！', 1, 1, 2, 0, 0, 108301, 4, 2609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子をもらうのも\\nアンタと一緒なら\\n恥ずかしくないわ！', 4, 1, 2, 0, 0, 108301, 101, 2610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシのエスコートを\\n任せられるのは、\\nアンタだけなんだから', 8, 1, 2, 0, 0, 108301, 102, 2611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝食はオシャレに\\nグリーンスムージー！\\n…に、にがぁ', 1, 1, 2, 0, 1, 108301, 1, 2612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼下がりはカフェで\\n優雅なティータイム\\n…憧れるわ～', 1, 1, 2, 0, 2, 108301, 2, 2613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンナイトの\\nはじまりよ！\\n街に繰り出しましょ！', 1, 1, 2, 0, 3, 108301, 3, 2614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あう～、お菓子の\\n食べすぎで\\n動けな～い', 1, 1, 3, 0, 0, 108301, 2, 2616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタも仮装する？\\nいまよりもーっと\\nかわいくなるわよ！', 1, 1, 3, 0, 0, 108301, 3, 2617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人な香りに\\n包まれてる～♪', 1, 1, 3, 0, 0, 108301, 4, 2618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカね～♪\\n…ああー！\\nチョコが溶けてる！', 1, 1, 3, 0, 0, 108301, 5, 2619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい～♪\\n…じゃなくて！\\nび、美味ですわ～', 1, 1, 3, 0, 0, 108301, 7, 2621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服かわい～♪\\nって、なにこの値段！\\nお小遣い何年分よ！？', 1, 1, 3, 0, 0, 108301, 8, 2622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、お菓子なんかで\\n喜ぶほど、子供じゃ…', 1, 1, 3, 0, 0, 108301, 12, 2624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどんな策で団長を\\nからかってみようか…', 1, 1, 1, 0, 0, 107101, 1, 2626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('む？\\n血の臭いがするな\\n祭りの時間か☆', 1, 1, 1, 0, 0, 107101, 2, 2627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('平和に飼い殺される\\n前に、混沌の愛を\\n育みたいね', 1, 1, 1, 0, 0, 107101, 3, 2628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本気を出した団長と\\nいつか手加減なしに\\n殺り合いたいな', 1, 1, 1, 0, 0, 107101, 4, 2629);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おばさん呼ばわりする\\n新米騎士の小娘を\\n懲らしめてやろうか', 1, 1, 1, 0, 0, 107101, 5, 2630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('胸を触られるまで\\n誓約のことなど\\nすっかり忘れていたな', 4, 1, 1, 0, 0, 107101, 101, 2631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさかこのワタシが\\nプロポーズするとはな\\n…笑えるじゃないか', 8, 1, 1, 0, 0, 107101, 102, 2632);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('面白い暇つぶしを\\n思いついたんだ\\n戯れに付き合え☆', 1, 1, 2, 0, 0, 107101, 1, 2633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('退屈で死にそうだ\\n愉しい話題を\\nワタシに提供してくれ', 1, 1, 2, 0, 0, 107101, 2, 2634);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだ、暇なのか？\\n心躍ることでも探しに\\n出かけようではないか', 1, 1, 2, 0, 0, 107101, 3, 2635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このワタシを愉快に\\nさせてくれる事でも\\nあったのか？', 1, 1, 2, 0, 0, 107101, 4, 2636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシに求婚した男の\\n数だと？\\nいちいち覚えてないな', 4, 1, 2, 0, 0, 107101, 101, 2637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最強無敵の女と\\n結婚できるんだ\\n誇りに思えよ☆', 8, 1, 2, 0, 0, 107101, 102, 2638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにか愉快なことが\\n起こりそうな朝だ☆\\nワクワクするね', 1, 1, 2, 0, 1, 107101, 1, 2639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーむ、腹がすいたな\\n愉快なことで\\nこの空腹を満たしたい', 1, 1, 2, 0, 2, 107101, 2, 2640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからは大人の\\n時間だ。愉しみ方を\\n知りたいのかい？', 1, 1, 2, 0, 3, 107101, 3, 2641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このワタシとした事が\\n穏やかな気分に\\nなってしまうとは…', 1, 1, 3, 0, 0, 107101, 2, 2643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い姿をしたものが\\n惨たらしい\\n醜態を晒すのを\\n想像してしまう', 1, 1, 3, 0, 0, 107101, 3, 2644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('悪くはない香りだ\\nだが、ワタシは血の\\n臭いを嗅ぎたいぞ☆', 1, 1, 3, 0, 0, 107101, 4, 2645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬるい、ぬるすぎる！\\n地獄の業火には\\nほど遠い熱さだ！', 1, 1, 3, 0, 0, 107101, 5, 2646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシの腕前に\\n勝るとも劣らない\\nなかなかの味だ', 1, 1, 3, 0, 0, 107101, 7, 2648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('意中の男性を絶対に\\n落とす方法…？\\nく、下らんっ！', 1, 1, 3, 0, 0, 107101, 8, 2649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日はあの釣り場に\\n行くとしようかな\\nあの子も誘ってみるか', 1, 1, 1, 0, 0, 105601, 1, 2651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷはーっ！\\n体を動かしたあとの\\n一杯は格別だね', 1, 1, 1, 0, 0, 105601, 2, 2652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('天気が良いと\\n昼寝か釣りかで\\n迷っちまうな…', 1, 1, 1, 0, 0, 105601, 3, 2653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大物が釣れたときの\\n快感は、他じゃ\\n味わえないね', 1, 1, 1, 0, 0, 105601, 4, 2654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふあぁ～…\\n昼寝でもするか', 1, 1, 1, 0, 0, 105601, 5, 2655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ…\\nあの子、見た目より\\n根性あるんだね', 4, 1, 1, 0, 0, 105601, 101, 2656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子が強くなるには\\nどんな魚を食べさせて\\nあげればいいのやら…', 8, 1, 1, 0, 0, 105601, 102, 2657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('姉御って呼ぶんじゃ\\nないよ。からかうと\\nタダじゃおかないよ', 1, 1, 2, 0, 0, 105601, 1, 2658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('釣りのコツ？\\n何事も経験が大事だ\\n今から行くかい？', 1, 1, 2, 0, 0, 105601, 2, 2659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたのさ？\\n助太刀が必要かい？\\nアタシにまかせときな', 1, 1, 2, 0, 0, 105601, 3, 2660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('困ってる人がいたら\\nまた力を貸しておくれ\\n頼りにしてるよ', 1, 1, 2, 0, 0, 105601, 4, 2661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにか困りごとかい？\\nどうやら昼寝は\\nまた今度だね', 4, 1, 2, 0, 0, 105601, 101, 2662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よしよし！\\nお人好しのお前さんを\\n労ってあげるよ', 8, 1, 2, 0, 0, 105601, 102, 2663);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう、お前さん\\n魚屋は早起きでなきゃ\\nつとまらないよ？', 1, 1, 2, 0, 1, 105601, 1, 2664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯かい？\u3000今朝\\n仕入れた魚があるんだ\\n食べてみるかい？', 1, 1, 2, 0, 2, 105601, 2, 2665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜釣りにぴったりの\\n月が出てるよ\\nいい釣りが出来そうだ', 1, 1, 2, 0, 3, 105601, 3, 2666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コイツに座って\\nのんびり釣りが\\nできりゃいいのにな', 1, 1, 3, 0, 0, 105601, 2, 2668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よしよし…♪\\nおっと、かわいい物も\\nつい抱きしめちまうな', 1, 1, 3, 0, 0, 105601, 3, 2669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで魚の臭いを\\n消せれば、猫も\\n寄らなくなるのかね', 1, 1, 3, 0, 0, 105601, 4, 2670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冬場の釣りも\\nこれくらい暖かけりゃ\\nいいんだけどね', 1, 1, 3, 0, 0, 105601, 5, 2671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹が減っては\\n釣りもできぬ、ってな\\nまずは腹ごしらえだ', 1, 1, 3, 0, 0, 105601, 7, 2673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へぇ…こんな魚が\\nいたとは…いつか\\n釣りたいもんだね', 1, 1, 3, 0, 0, 105601, 8, 2674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('流石に室内で\\n魔法ぶっぱしたら\\n怒られるよねぇ', 1, 1, 1, 0, 0, 101301, 1, 2676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('可愛い女の子が\\nたくさんいる！\\nここは楽園か！？', 1, 1, 1, 0, 0, 101301, 2, 2677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなに漫画とか\\n勧めてみようかな！\\n布教用のがあるし！', 1, 1, 1, 0, 0, 101301, 3, 2678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ、私一人の\\n部屋じゃないから\\n色々自重せねば！', 1, 1, 1, 0, 0, 101301, 4, 2679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「ぬるぽ」\\n…くっ、\\n誰も反応なしか！', 1, 1, 1, 0, 0, 101301, 5, 2680);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどの漫画を\\n貸そうかなー♪', 4, 1, 1, 0, 0, 101301, 101, 2681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の定期巡回で\\nとっておきの店に\\n連れてってあげよう！', 8, 1, 1, 0, 0, 101301, 102, 2682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君に似合いそうな\\n衣装を買ったよ！\\n君もいざ魔法少女に！', 1, 1, 2, 0, 0, 101301, 1, 2683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ！\\n暇なら定期巡回に\\nレッツラゴー！', 1, 1, 2, 0, 0, 101301, 2, 2684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦闘だけじゃなくて、\\n日常にも役立つ\\n魔法を習得したいね！', 1, 1, 2, 0, 0, 101301, 3, 2685);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新魔法思いついた！\\n私って天才！？', 1, 1, 2, 0, 0, 101301, 4, 2686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('決め台詞は超大事！\\n君の決め台詞も\\n私が考えてあげよう！', 4, 1, 2, 0, 0, 101301, 101, 2687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私ってもしやリア充？\\n…そんなバカな！\\n非リア代表のはずが！', 8, 1, 2, 0, 0, 101301, 102, 2688);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよー…\\n徹夜で本読んでたから\\nまだ眠い～', 1, 1, 2, 0, 1, 101301, 1, 2689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯食べて、\\n午後の定期巡回も\\n頑張りましょー！', 1, 1, 2, 0, 2, 101301, 2, 2690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜からが、\\nオタ活本番でしょ！', 1, 1, 2, 0, 3, 101301, 3, 2691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふいー！\\nくつろいで本を読む！\\n最高だねー！', 1, 1, 3, 0, 0, 101301, 2, 2693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君、可愛いね～♪\\n魔法少女の\\n使い魔みたい！', 1, 1, 3, 0, 0, 101301, 3, 2694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い匂いに\\n釣られてしまった…\\nまさか、孔明の罠！？', 1, 1, 3, 0, 0, 101301, 4, 2695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かいけど、\\nここで本を読むのは\\nちょっち危ないかな', 1, 1, 3, 0, 0, 101301, 5, 2696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウマ―！\\nこれの詳細きぼんぬ！', 1, 1, 3, 0, 0, 101301, 7, 2698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、古代語の本！？\\n現代語でおk…', 1, 1, 3, 0, 0, 101301, 8, 2699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふふっ♪\\n次はどんな悪戯を\\nしてやろうかしら♪', 1, 1, 1, 0, 0, 190901, 1, 2701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幻影湖の霧を吸った\\n人間たちの\\nリアクションって、\\nサイコーよねぇ～♪', 1, 1, 1, 0, 0, 190901, 2, 2702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('室内だけとはいえ…\\n自由に動けるって、\\nやっぱりいいわ～♪', 1, 1, 1, 0, 0, 190901, 3, 2703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('改めて見ると良い\\n部屋ね…悪戯とか\\nしやすそうだしぃ♪', 1, 1, 1, 0, 0, 190901, 4, 2704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私を封じていた部屋\\nなのに…急に居心地が\\n良くなったわね♪', 1, 1, 1, 0, 0, 190901, 5, 2705);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたの頭、座り心地\\n良いわね…私専用の\\n椅子にしてあげる♪', 1, 1, 2, 0, 0, 190901, 1, 2706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外は大変みたいねぇ…\\nまあ、私は好き勝手に\\nやらせてもらうわ♪', 1, 1, 2, 0, 0, 190901, 2, 2707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('顔に落書された？\\n誰か知らないけど、\\n悪いことする奴も\\nいるものねぇ～♪', 1, 1, 2, 0, 0, 190901, 3, 2708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フィオのやつ…\\nどこをウロチョロ\\nしてるのかしら？', 1, 1, 2, 0, 0, 190901, 4, 2709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人間の朝は大変ねぇ…\\n私はその様を見ながら\\nゆっくりするわね♪', 1, 1, 2, 0, 1, 190901, 1, 2710);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～私も、お日様を\\n浴びながら、お外を\\nお散歩したーい！', 1, 1, 2, 0, 2, 190901, 2, 2711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この暗さ…閉じ込め\\nられていた時を\\n思い出すわね…', 1, 1, 2, 0, 3, 190901, 3, 2712);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('悪戯しすぎて\\n疲れたから、ちょっと\\n休憩しよっと♪', 1, 1, 3, 0, 0, 190901, 2, 2714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ガイド妖精たる私が、\\nこんな造形物に\\n惹かれる…わけが……\\nかわいい♪', 1, 1, 3, 0, 0, 190901, 3, 2715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香りを囮にして、\\n周りに悪戯を仕込む…\\n完璧ね♪', 1, 1, 3, 0, 0, 190901, 4, 2716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不思議ねぇ…私は\\n温度とか関係ないのに\\n離れられないわ', 1, 1, 3, 0, 0, 190901, 5, 2717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事の必要がない体…\\nつまり、食べたければ\\n食べていいのよね～♪', 1, 1, 3, 0, 0, 190901, 7, 2719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へぇ…最近はこんな\\n悪戯もあるのねぇ…\\nあいつで試さないと♪', 1, 1, 3, 0, 0, 190901, 8, 2720);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\n歌で幸せを\\n届けます…！', 1, 1, 1, 0, 0, 108401, 1, 2722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと出会えたのは\\n偶然ではなくて…\\nクリスマスの奇跡だと\\n思うんです', 1, 1, 1, 0, 0, 108401, 2, 2723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスは華やかで\\nつい子供のように\\nはしゃいでしまいます', 1, 1, 1, 0, 0, 108401, 3, 2724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('曲が書けるのは\\nあなたが側に\\nいてくれるからです…', 1, 1, 1, 0, 0, 108401, 4, 2725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('感動を与えられる歌…\\nあなたと一緒になら\\n生み出せるはず…', 1, 1, 1, 0, 0, 108401, 5, 2726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスの幸せを\\nあなたと\\n感じ合えたらな…', 4, 1, 1, 0, 0, 108401, 101, 2727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの幸せを願った\\nクリスマスソング…\\nいつか披露しますね', 8, 1, 1, 0, 0, 108401, 102, 2728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みなさんの笑顔を\\n守りたいから…\\n私は歌い続けます', 1, 1, 2, 0, 0, 108401, 1, 2729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌を届ける\\nサンタさんに\\nなりたいな…', 1, 1, 2, 0, 0, 108401, 2, 2730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お暇でしたら\\nクリスマスのお祝いを\\nしませんか？', 1, 1, 2, 0, 0, 108401, 3, 2731);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ステージに立つ前に\\n喉を整えないと…\\n発声練習は念入りに…', 1, 1, 2, 0, 0, 108401, 4, 2732);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まわりはかわいい子\\nばっかりだけど…\\nこの服なら\\nアピールになるかな？', 4, 1, 2, 0, 0, 108401, 101, 2733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌でならいくらでも\\nあの人への気持ちを\\n込められるのに…', 8, 1, 2, 0, 0, 108401, 102, 2734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\n幸せな歌で世界が\\n包まれますように…', 1, 1, 2, 0, 1, 108401, 1, 2735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お茶を飲みながら\\n好きな音楽を\\n語り合いませんか？', 1, 1, 2, 0, 2, 108401, 2, 2736);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、寝かしつけの\\n子守唄を\\nお望みですか？', 1, 1, 2, 0, 3, 108401, 3, 2737);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかですね\\n心地良すぎて\\n眠ってしまいそう…', 1, 1, 3, 0, 0, 108401, 2, 2739);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵…\\n優しい歌みたいに\\n気持ちが落ち着く…', 1, 1, 3, 0, 0, 108401, 3, 2740);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('インスピレーションが\\n溢れてくる…\\nいい曲が書けそう…', 1, 1, 3, 0, 0, 108401, 4, 2741);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この光みたいに\\n灯火になるような\\n歌を歌いたい…', 1, 1, 3, 0, 0, 108401, 5, 2742);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('喉の健康のためにも\\n食事はしっかり\\nとるようにしています', 1, 1, 3, 0, 0, 108401, 7, 2744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物語には\\n曲作りのヒントが\\n詰まっているんです', 1, 1, 3, 0, 0, 108401, 8, 2745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵が飛び出してくる\\nなんて…精霊が宿って\\nいるのでしょうか？', 1, 1, 3, 0, 0, 108401, 14, 2747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、可愛い…♪\\nちょっとだけ触っても\\nいいですよね…？', 1, 1, 3, 0, 0, 108401, 15, 2748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスでも、\\n演劇の練習は\\nしっかりやらないと！', 1, 1, 1, 0, 0, 108501, 1, 2749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あうぅ…\\nクリスマスの準備が\\n終わらないよぅ…', 1, 1, 1, 0, 0, 108501, 2, 2750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アヤネちゃんが\\n摘み食いしないように\\n見ておかないと…', 1, 1, 1, 0, 0, 108501, 3, 2751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サンタさんみたいに、\\n皆に笑顔で接する…\\nうぅ…私には無理ぃ…', 1, 1, 1, 0, 0, 108501, 4, 2752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいお洋服～♪\\nスズメお姉ちゃんに\\nお礼をいわないと♪', 1, 1, 1, 0, 0, 108501, 5, 2753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんの為に、\\nプレゼントを\\n用意しないと♪', 4, 1, 1, 0, 0, 108501, 101, 2754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマス…\\n恋人の日…ひゃわっ！\\nわ、私ってば何を…！', 8, 1, 1, 0, 0, 108501, 102, 2755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリー\\nクリスマスです、\\nお兄ちゃん♪', 1, 1, 2, 0, 0, 108501, 1, 2756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そ、そんなに\\n見られると…\\n恥ずかしいよぉ…', 1, 1, 2, 0, 0, 108501, 2, 2757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃわぁっ！？\\n急に触られると、\\n驚くからやめてぇ…', 1, 1, 2, 0, 0, 108501, 3, 2758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ…クリスマスの\\n準備を手伝って\\nくれるんですか？', 1, 1, 2, 0, 0, 108501, 4, 2759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと\\n過ごすクリスマス、\\n楽しみですぅ…♪', 4, 1, 2, 0, 0, 108501, 101, 2760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスはその…\\n二人で…あうぅ…\\nなんでもないですぅ…', 8, 1, 2, 0, 0, 108501, 102, 2761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう…パーティーが\\n楽しみで、あんまり\\n眠れなかったよぅ…', 1, 1, 2, 0, 1, 108501, 1, 2762);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ケーキを食べられなく\\nなっちゃうから、\\nお昼は軽めにしないと', 1, 1, 2, 0, 2, 108501, 2, 2763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと眠いけど…\\n今日は少しだけ\\n夜更かししたいです♪', 1, 1, 2, 0, 3, 108501, 3, 2764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかぁ…\\nクリスマスの準備中に\\n眠くなっちゃいますぅ', 1, 1, 3, 0, 0, 108501, 2, 2766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子と一緒に\\nおままごとしたいな♪', 1, 1, 3, 0, 0, 108501, 3, 2767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂い…♪\\nみんなで\\nアロマパーティー\\nしたいなぁ…♪', 1, 1, 3, 0, 0, 108501, 4, 2768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬっくぬく…♪\\nもう、ここから\\n離れたくないよぉ…♪', 1, 1, 3, 0, 0, 108501, 5, 2769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむはむ…♪\\nクリスマスのお料理\\nより美味しいかも～♪', 1, 1, 3, 0, 0, 108501, 7, 2771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごい…\\nクリスマスの\\n演劇って、\\nこんなにあるんだ…', 1, 1, 3, 0, 0, 108501, 8, 2772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごい…まるで、\\nクリスマスの演劇を\\n観てるようですぅ…♪', 1, 1, 3, 0, 0, 108501, 14, 2774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっても可愛いです♪\\nお芝居の相手役に\\nしたいなぁ…♪', 1, 1, 3, 0, 0, 108501, 15, 2775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘ぁいケーキも、\\nデッカイ七面鳥も、\\nぜーんぶ私のだー♪', 1, 1, 1, 0, 0, 108601, 1, 2776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日が\\nクリスマスだったら\\nいいのにな～♪', 1, 1, 1, 0, 0, 108601, 2, 2777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントはあるし、\\n料理は美味しいし、\\nクリスマス最高ー♪', 1, 1, 1, 0, 0, 108601, 3, 2778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでぷうきちの\\nクリスマス一発芸♪\\n『無茶ぶりするな！』', 1, 1, 1, 0, 0, 108601, 4, 2779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちがいつもより\\n重いかも…太ったの？\\n『衣装の重さだよ！』', 1, 1, 1, 0, 0, 108601, 5, 2780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんが\\n一緒にいてくれると\\nクリスマス楽しいね♪', 4, 1, 1, 0, 0, 108601, 101, 2781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに抱きつく\\nと、なんだかドキドキ\\nする…なんでかな？', 8, 1, 1, 0, 0, 108601, 102, 2782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス♪\\nプレゼントは、\\nいつでも受付中だよ♪', 1, 1, 2, 0, 0, 108601, 1, 2783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このクマさん耳\\n可愛いでしょ♪\\nぷうきちと\\nお揃いなんだー♪', 1, 1, 2, 0, 0, 108601, 2, 2784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん…私、\\n甘ぁいケーキが\\n食べたいなぁ…♪', 1, 1, 2, 0, 0, 108601, 3, 2785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスぷうきちは\\nぬくぬく感が凄いよ！\\nお兄ちゃんもさわる？', 1, 1, 2, 0, 0, 108601, 4, 2786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…お兄ちゃんの\\n手は、大きくて、\\n暖かくて大好き～♪', 4, 1, 2, 0, 0, 108601, 101, 2787);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年のクリスマスも、\\nこうやって\\nお兄ちゃんに\\n甘えていたいな～♪', 8, 1, 2, 0, 0, 108601, 102, 2788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あれぇ…\\n私のケーキはぁ…？\\n『ちゃんと起きろ』', 1, 1, 2, 0, 1, 108601, 1, 2789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はデッカイ\\n七面鳥が食べたーい♪\\n『夜まで我慢しろ』', 1, 1, 2, 0, 2, 108601, 2, 2790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『もう寝る時間だぞ』\\nサンタさんが来る\\nまで起きてるぅ…', 1, 1, 2, 0, 3, 108601, 3, 2791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このふかふか具合…\\nぷうきち！\\n負けてられないよ！', 1, 1, 3, 0, 0, 108601, 2, 2793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子、\\nすっごくかわいい～♪\\n『ライバル登場か！』', 1, 1, 3, 0, 0, 108601, 3, 2794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い匂い…あっ！\\nぷうきちにこの\\n匂いを移せば…！\\n『匂い袋にするな』', 1, 1, 3, 0, 0, 108601, 4, 2795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い♪\\nえへへ、ぷうきちも\\nあっためてあげる♪', 1, 1, 3, 0, 0, 108601, 5, 2796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきち！\u3000これ、\\nとってもおいしいよ♪\\n『食べすぎるなよ』', 1, 1, 3, 0, 0, 108601, 7, 2798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、大人の私なら、\\nこれぐらい…読め…\\n『無理するな…』', 1, 1, 3, 0, 0, 108601, 8, 2799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵が飛び出す…\\nぷうきちに絵本を\\n入れれば、イタズラに\\n使えるかも…♪', 1, 1, 3, 0, 0, 108601, 14, 2801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、可愛いけど…\\nぷうきちサンタの方が\\n可愛いんだからぁ…！', 1, 1, 3, 0, 0, 108601, 15, 2802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物も慣れると\\n動きやすいものさ', 1, 1, 1, 0, 0, 108901, 1, 2803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鼻緒が緩んでしまった\\n下駄で修業は\\n無理があったかな…', 1, 1, 1, 0, 0, 108901, 2, 2804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小腹が空いた…\\nユイが作った餅、\\nまだ食べられるかな？', 1, 1, 1, 0, 0, 108901, 3, 2805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服装も変わったし\\nいつもと違う戦い方を\\n想定しないと…', 1, 1, 1, 0, 0, 108901, 4, 2806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ヒヨリは動きすぎて\\n着崩れしてないか\\n心配だ', 1, 1, 1, 0, 0, 108901, 5, 2807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからもずっと\\n仲間と、彼と\\n一緒に…', 4, 1, 1, 0, 0, 108901, 101, 2808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('願いを叶えるために\\nもっと自分を\\n鍛えていかないと！', 8, 1, 1, 0, 0, 108901, 102, 2809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭の飾りがずれてた？\\nそうか、直してくれて\\nありがとう', 1, 1, 2, 0, 0, 108901, 1, 2810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物がそんなに\\n珍しい？\\nキミも着てみる？\\n…冗談だよ', 1, 1, 2, 0, 0, 108901, 2, 2811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('肩掛けの触り心地が\\n気に入った？\\nならもっと触る？', 1, 1, 2, 0, 0, 108901, 3, 2812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、この刀？\\n釣り仲間に見繕って\\nもらったんだ', 1, 1, 2, 0, 0, 108901, 4, 2813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミといると\\n気持ちが段々と\\n安らいでいくよ', 4, 1, 2, 0, 0, 108901, 101, 2814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミは私の行く先を\\n照らしてくれる\\n光のような存在だよ', 8, 1, 2, 0, 0, 108901, 102, 2815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう\\n朝の修行を始めるけど\\nキミもどう？', 1, 1, 2, 0, 1, 108901, 1, 2816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この時間に軽く\\n休憩をとるといい\\n能率がよくなるよ', 1, 1, 2, 0, 2, 108901, 2, 2817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう夜か…\\n明日もまた頑張ろう\\nそれじゃ、おやすみ', 1, 1, 2, 0, 3, 108901, 3, 2818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…疲れていたのかな\\nもう少しで眠る\\nところだった…', 1, 1, 3, 0, 0, 108901, 2, 2820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、正月衣装を\\n着せてやるのも\\nよさそうだ', 1, 1, 3, 0, 0, 108901, 3, 2821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…いい香りだ\\n慌ただしい日々から\\n心が解放される', 1, 1, 3, 0, 0, 108901, 4, 2822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この心地よさ…\\n寝てしまわないよう\\n気をつけないと', 1, 1, 3, 0, 0, 108901, 5, 2823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいけど\\n帯がきつくなる前に\\n手を止めよう…', 1, 1, 3, 0, 0, 108901, 7, 2825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外を出歩くのも\\nいいけど、中で\\n読書もありだな', 1, 1, 3, 0, 0, 108901, 8, 2826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…騎士クンって\\nおせち料理で\\n何が好きなんだろう？', 1, 1, 1, 0, 0, 108801, 1, 2828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物でお掃除や\\nお洗濯するの\\n慣れてきた♪', 1, 1, 1, 0, 0, 108801, 2, 2829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年は\\nどんな福袋を\\n買おうかな…♪', 1, 1, 1, 0, 0, 108801, 3, 2830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お餅に使う調味料\\nみんなで違うから\\n色々用意しなきゃ', 1, 1, 1, 0, 0, 108801, 4, 2831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほっぺがお餅みたいに\\nぷにぷに…\\n食べ過ぎちゃった…', 1, 1, 1, 0, 0, 108801, 5, 2832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年も、再来年も\\nみんなで一緒に\\n新年を迎えたいな', 4, 1, 1, 0, 0, 108801, 101, 2833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お願いです…\\nいつかこの気持ちが\\n伝わりますように…', 8, 1, 1, 0, 0, 108801, 102, 2834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('髪飾りが落ちそう？\\nじゃあ…騎士クン\\nつけ直してくれる？', 1, 1, 2, 0, 0, 108801, 1, 2835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物が着たいの？\\nじゃあ今度一緒に\\n買いに…行く？', 1, 1, 2, 0, 0, 108801, 2, 2836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、騎士クン\\nお雑煮のお餅\\nいくつ入れたい？', 1, 1, 2, 0, 0, 108801, 3, 2837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外、寒かったよね？\\nはいこれ。熱い甘粥\\n飲むと温まるよ', 1, 1, 2, 0, 0, 108801, 4, 2838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年は騎士クンと…\\nえっ？\u3000騎士クン！？\\nな、なんでもないよ！', 4, 1, 2, 0, 0, 108801, 101, 2839);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンの願い事\\nわたしが\\n叶えてあげたいな…', 8, 1, 2, 0, 0, 108801, 102, 2840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう\\n太陽の光に当たると\\n元気が出るよ', 1, 1, 2, 0, 1, 108801, 1, 2841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはん\\n作らなきゃ…\\n騎士クンも食べる？', 1, 1, 2, 0, 2, 108801, 2, 2842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一日が終わるのは\\nあっという間だよね\\n一年も同じなのかな？', 1, 1, 2, 0, 3, 108801, 3, 2843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…\\n帯も少し\\nゆるめちゃおう…', 1, 1, 3, 0, 0, 108801, 2, 2845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月用に\\n着物を縫って\\nあげたいな', 1, 1, 3, 0, 0, 108801, 3, 2846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これでお肌が\\n保湿出来たら\\nいいのになぁ', 1, 1, 3, 0, 0, 108801, 4, 2847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～…\\nぬくぬくしてて\\n動きたくないよ～', 1, 1, 3, 0, 0, 108801, 5, 2848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…冬眠しないのに\\n熊さんみたいに\\n食べちゃいそう', 1, 1, 3, 0, 0, 108801, 7, 2850);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年末年始は\\n告白のチャンス…\\nむ、無理無理！', 1, 1, 3, 0, 0, 108801, 8, 2851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんな忙しそう…\\n待っててね、\\nすぐ助けるから！', 1, 1, 1, 0, 0, 108701, 1, 2853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユイちゃんと\\nレイさん…よし！\\nどっちも手伝おう！', 1, 1, 1, 0, 0, 108701, 2, 2854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、着崩れてる！\\nわわっ、どうしよ！\\n帯が結べないよー！', 1, 1, 1, 0, 0, 108701, 3, 2855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初詣楽しみー！\\n出店はどこから\\n行こうかな？', 1, 1, 1, 0, 0, 108701, 4, 2856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月だし\\nみんなで楽しく\\n遊んじゃおー！', 1, 1, 1, 0, 0, 108701, 5, 2857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…\\n騎士くんはお正月\\n何してるんだろ…', 4, 1, 1, 0, 0, 108701, 101, 2858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ううぅー…\\n騎士くんを見てると\\nドキってなっちゃう…', 8, 1, 1, 0, 0, 108701, 102, 2859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしから\\nおいしそうな匂い？\\nくんくん…ソースだ！', 1, 1, 2, 0, 0, 108701, 1, 2860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヘアピンが…\\n拾ってくれたんだ！\\nありがとう騎士くん！', 1, 1, 2, 0, 0, 108701, 2, 2861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('髪飾りがかわいい？\\n耳の近く触りたい？\\n…優しくね？\u3000', 1, 1, 2, 0, 0, 108701, 3, 2862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('グローブで食べるの\\n大変そう？\u3000特訓して\\n今はお箸も使えるよ！', 1, 1, 2, 0, 0, 108701, 4, 2863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えっ、ほっぺが赤い？\\nそうかな…？\\n気のせい気のせい！', 4, 1, 2, 0, 0, 108701, 101, 2864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くんといるとね…\\nなんでもない！\\nまだ内緒っ！', 8, 1, 2, 0, 0, 108701, 102, 2865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよー！\\n今日も明るく元気に\\nがんばろー！', 1, 1, 2, 0, 1, 108701, 1, 2866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいてない？\\n一緒にご飯食べよ！\\n何にしようかなー♪', 1, 1, 2, 0, 2, 108701, 2, 2867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もいっぱい\\nがんばったー！\\nいつも？\u3000…そう？', 1, 1, 2, 0, 3, 108701, 3, 2868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩休憩♪\\nちょっと休んで\\nガンガン動くぞー！', 1, 1, 3, 0, 0, 108701, 2, 2870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい♪\\nでも、壊しそうで\\nちょっと怖い…', 1, 1, 3, 0, 0, 108701, 3, 2871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁー♪\\nいい香りー…\\n気分スッキリ♪', 1, 1, 3, 0, 0, 108701, 4, 2872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほっこりしてて\\nぬくぬく…\\n丸まりたい…', 1, 1, 3, 0, 0, 108701, 5, 2873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ど、どうしよう…！\\n手が、止まんないよ！', 1, 1, 3, 0, 0, 108701, 7, 2875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へー…お年玉って\\n昔はお餅だったんだ\\n…今のほうがいいね', 1, 1, 3, 0, 0, 108701, 8, 2876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘いチョコの香りを\\n漂わせて…ふふっ\\nこれで準備万端ですわ', 1, 1, 1, 0, 0, 109001, 1, 2878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここを私のチョコで\\n埋め尽くしますわ', 1, 1, 1, 0, 0, 109001, 2, 2879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エプロンを着て\\nあの方を待つ私…\\nまるで…クスクス', 1, 1, 1, 0, 0, 109001, 3, 2880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キッチンはどこかしら\\n今のうちに作って\\nおきたいものが…', 1, 1, 1, 0, 0, 109001, 4, 2881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのお方を私のチョコ\\nなしでは生きられない\\n体に…ふふっ\\n冗談ですわ…', 1, 1, 1, 0, 0, 109001, 5, 2882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このチョコは運命の味\\n一口食べれば私の虜…\\nそれも運命ですわ…', 4, 1, 1, 0, 0, 109001, 101, 2883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私ともあろうものが\\nなんだかドキドキして\\nきましたわ…', 8, 1, 1, 0, 0, 109001, 102, 2884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなた様。私に\\n隠しているものなど\\nありませんよね…？', 1, 1, 2, 0, 0, 109001, 1, 2885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の手作りチョコです\\n味の方にも自信\\nありますのよ？', 1, 1, 2, 0, 0, 109001, 2, 2886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し苦いのは\\nチョコがビターなだけ\\nお気になさらず…', 1, 1, 2, 0, 0, 109001, 3, 2887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('解毒薬はどこに\\nいれたかしら…？', 1, 1, 2, 0, 0, 109001, 4, 2888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運命で結ばれている\\nあなた様と私…\\nチョコも特別でないと\\nいけませんわ', 4, 1, 2, 0, 0, 109001, 101, 2889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チョコを食べた後は\\nメインディッシュ…\\nさぁ、私を召し上がれ', 8, 1, 2, 0, 0, 109001, 102, 2890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('目覚めのチョコですわ\\nすっきり目が覚めます\\nしばらく眠れなく\\nなりますけど…', 1, 1, 2, 0, 1, 109001, 1, 2891);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやつのチョコですわ\\nデザートにどうぞ\\n空腹を感じなく\\nなりますわ…クスクス', 1, 1, 2, 0, 2, 109001, 2, 2892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お夜食のチョコですわ\\nとてもよく眠れます\\nさ、溶けてしまう前に', 1, 1, 2, 0, 3, 109001, 3, 2893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この心地良さ…\\n参考になりますわ\\n次の薬は…クスクス', 1, 1, 3, 0, 0, 109001, 2, 2895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この中、何か\\n入りそうですわね\\n…チョコレート、とか', 1, 1, 3, 0, 0, 109001, 3, 2896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…この香りと\\n同じものを調合して\\n私も持っていたい', 1, 1, 3, 0, 0, 109001, 4, 2897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この暖かさ…\\nチョコが溶けないよう\\n気を付けなくては', 1, 1, 3, 0, 0, 109001, 5, 2898);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい味をしていますわ\\n私も腕を磨きましょう\\n料理と、調合の腕を…', 1, 1, 3, 0, 0, 109001, 7, 2900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強になりますわ\\n知識はいくらあっても\\n困りませんもの\\n特に、人体の知識は…', 1, 1, 3, 0, 0, 109001, 8, 2901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんのことを\\n考えると\\nあっという間に時間が\\n過ぎちゃう…', 1, 1, 1, 0, 0, 109101, 1, 2903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんの\\n元気の源は、弟くんの\\n喜ぶ顔なんだから♪', 1, 1, 1, 0, 0, 109101, 2, 2904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんと会ったら\\nまずは抱きしめて\\nそれからそれから…', 1, 1, 1, 0, 0, 109101, 3, 2905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のお姉ちゃんは\\n昨日のお姉ちゃんより\\nいいお姉ちゃんだよ♪', 1, 1, 1, 0, 0, 109101, 4, 2906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くん、もっと\\nお姉ちゃんに\\n甘えてもいいのに♪', 1, 1, 1, 0, 0, 109101, 5, 2907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんのチョコ\\n食べさせてあげたい…', 4, 1, 1, 0, 0, 109101, 101, 2908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドキドキしてきた…\\nお姉ちゃんなのに\\nどうしてかなぁ…', 8, 1, 1, 0, 0, 109101, 102, 2909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんを\\n好きなだけ\\n触っていいよ♪', 1, 1, 2, 0, 0, 109101, 1, 2910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなにお姉ちゃんの\\nチョコが欲しいの？\\n食いしん坊さん♪', 1, 1, 2, 0, 0, 109101, 2, 2911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナデナデするのは\\nお姉ちゃんの仕事！', 1, 1, 2, 0, 0, 109101, 3, 2912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ありがとうなんて…\\nお姉ちゃんとして\\n当たり前だよ♪', 1, 1, 2, 0, 0, 109101, 4, 2913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたのかなっ？\\nお姉ちゃんはいつでも\\n弟くんのそばにいるよ', 4, 1, 2, 0, 0, 109101, 101, 2914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チョコを作ったよ\\n隠し味は、たくさんの\\n弟くんへの愛情♪', 8, 1, 2, 0, 0, 109101, 102, 2915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよ。お姉ちゃんが\\n顔を洗うの\\n手伝ってあげるね♪', 1, 1, 2, 0, 1, 109101, 1, 2916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご飯を食べたら\\n眠たくなるよね…\\nお姉ちゃんと寝る？', 1, 1, 2, 0, 2, 109101, 2, 2917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ眠くなった？\\nお姉ちゃんが添い寝\\nしてあげるね♪', 1, 1, 2, 0, 3, 109101, 3, 2918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この気持ちよさは\\nお姉ちゃんも太鼓判♪', 1, 1, 3, 0, 0, 109101, 2, 2920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このかわいさは\\nお姉ちゃんも大満足♪', 1, 1, 3, 0, 0, 109101, 3, 2921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り、チョコに\\n使えるかな…？', 1, 1, 3, 0, 0, 109101, 4, 2922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんと一緒に\\nぬくぬくしたいな…♪', 1, 1, 3, 0, 0, 109101, 5, 2923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごくおいしいねっ♪\\nあとで運動しなきゃ…', 1, 1, 3, 0, 0, 109101, 7, 2925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本を読んでる\\n知的なお姉ちゃん\\n素敵でしょ♪', 1, 1, 3, 0, 0, 109101, 8, 2926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシって…\\nここにいても\\nいいのか…？', 1, 1, 1, 0, 0, 106101, 1, 2928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんとした建物に\\nいるのが久しぶりで\\nそわそわする…', 1, 1, 1, 0, 0, 106101, 2, 2929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで天楼覇断剣\\n出す練習したら\\nアイツら怒るかな？', 1, 1, 1, 0, 0, 106101, 3, 2930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスか…\\nこういう隠れ家\\n欲しかったんだよな', 1, 1, 1, 0, 0, 106101, 4, 2931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('めちゃくちゃ暇だ…\\n…なんかやること\\nないのか？', 1, 1, 1, 0, 0, 106101, 5, 2932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなが早く\\nアタシのこと\\n思い出さないかな', 4, 1, 1, 0, 0, 106101, 101, 2933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツはいいヤツだし\\n戦う時はアタシも\\n協力してやるか！', 8, 1, 1, 0, 0, 106101, 102, 2934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんはいらん！\\nノウェムでいい！\\n分かったか？', 1, 1, 2, 0, 0, 106101, 1, 2935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうした？\\n戦うのか！？\\n…なんだ、違うのか', 1, 1, 2, 0, 0, 106101, 2, 2936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身長のことは\\nあんまり言うな！\\n気にしてるからな！', 1, 1, 2, 0, 0, 106101, 3, 2937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシの戦い方は\\nなんでもアリだ！\\nだから見習うなよ？', 1, 1, 2, 0, 0, 106101, 4, 2938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエとの思い出か…\\n敵として戦ってばっか\\nだったな！', 4, 1, 2, 0, 0, 106101, 101, 2939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエやオクトーと\\n一緒に、あちこち\\nいってみたいんだ！', 8, 1, 2, 0, 0, 106101, 102, 2940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よっ！\u3000おはよう！\\n朝だぞー！\\n起きてるかー？', 1, 1, 2, 0, 1, 106101, 1, 2941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹減ったー！\\n飯食うぞ、飯！\\nオマエも行くよな？', 1, 1, 2, 0, 2, 106101, 2, 2942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…\\nまだ起きてんのか？\\n元気だなオマエ…', 1, 1, 2, 0, 3, 106101, 3, 2943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぃ～…\\n極楽極楽…', 1, 1, 3, 0, 0, 106101, 2, 2945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいオマエ！\\n寝技の練習に\\n付き合ってもらうぞ', 1, 1, 3, 0, 0, 106101, 3, 2946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…\\nたまにはこういうのも\\n悪くないかもな', 1, 1, 3, 0, 0, 106101, 4, 2947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あー…\\nもっと前にコイツと\\n出会いたかった…', 1, 1, 3, 0, 0, 106101, 5, 2948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('VRでも飯はうまい！\\n腹が減るのはちゃんと\\n生きてる気がするな', 1, 1, 3, 0, 0, 106101, 7, 2950);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強は大事だな！\\nうん！…だめだ！\\n全然わからん！', 1, 1, 3, 0, 0, 106101, 8, 2951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探偵というのは\\n謎を追い求める\\n生き物なのさっ！', 1, 1, 1, 0, 0, 101401, 1, 2953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('事件のオチは\\n往々にして\\n取るに足らないものさ', 1, 1, 1, 0, 0, 101401, 2, 2954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('読書で得る知識が\\n探偵の\\n血肉になるんだよ', 1, 1, 1, 0, 0, 101401, 3, 2955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この前の\\n捜査資料…\\nどこにあったかな？', 1, 1, 1, 0, 0, 101401, 4, 2956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんな小さな謎も\\n私にとっては\\n宝石みたいなものさ！', 1, 1, 1, 0, 0, 101401, 5, 2957);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんと一緒だと\\nよい発想が浮かぶ…\\nどうしてだろうね？', 4, 1, 1, 0, 0, 101401, 101, 2958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんの好きな\\nタイプって…\\nす、推理してみるっ！', 8, 1, 1, 0, 0, 101401, 102, 2959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('珈琲、淹れたてだよ\\n一杯どうだい？', 1, 1, 2, 0, 0, 101401, 1, 2960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('事件の考察を\\nまとめてみたんだけど\\n聞いてくれるかな？', 1, 1, 2, 0, 0, 101401, 2, 2961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小さな違和感を\\n見逃さない…\\n探偵の心得だよ', 1, 1, 2, 0, 0, 101401, 3, 2962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('機能的な手帳とペン…\\nこの仕事には\\n欠かせないね！', 1, 1, 2, 0, 0, 101401, 4, 2963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんに\\n珈琲…\\n淹れてほしいなぁ～', 4, 1, 2, 0, 0, 101401, 101, 2964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんは\\n私にとって\\n最高の相棒だよ☆', 8, 1, 2, 0, 0, 101401, 102, 2965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝はいいひらめきが\\n得られるんだ…\\nさあ捜査を始めよう！', 1, 1, 2, 0, 1, 101401, 1, 2966);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休みしたら\\n推理の答え合わせを\\nしてみようか？', 1, 1, 2, 0, 2, 101401, 2, 2967);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の張りこみかい？\\nなら私も\\n同行させてほしいな！', 1, 1, 2, 0, 3, 101401, 3, 2968);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('脳を酷使した後は\\nゆっくり休む…\\nこれも仕事だよ？', 1, 1, 3, 0, 0, 101401, 2, 2970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この愛らしさ…\\n要捜査対象だね！', 1, 1, 3, 0, 0, 101401, 3, 2971);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('思考が活性化される\\n素敵な香りだね…', 1, 1, 3, 0, 0, 101401, 4, 2972);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くぅ、心地よすぎる…\\n今だけは捜査も\\n一休みだね♪', 1, 1, 3, 0, 0, 101401, 5, 2973);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい食べて\\nいっぱい考える\\n探偵の本分だね！', 1, 1, 3, 0, 0, 101401, 7, 2975);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探偵だからね\\nミステリには\\n一家言あるんだ', 1, 1, 3, 0, 0, 101401, 8, 2976);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩、素敵だなぁ…\\nもっと近づければ\\nいいのに…', 1, 1, 1, 0, 0, 105501, 1, 2978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩がいた部屋！\\n私には刺激が強い…', 1, 1, 1, 0, 0, 105501, 2, 2979);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩を観察しやすい\\n場所はあるかな…', 1, 1, 1, 0, 0, 105501, 3, 2980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バ、バイト代出たし、\\nせ、先輩をご飯とかに\\n誘いたい…な', 1, 1, 1, 0, 0, 105501, 4, 2981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今頃先輩は\\nあの辺かな…？\\n見に行ってみよう！', 1, 1, 1, 0, 0, 105501, 5, 2982);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と先輩の出会いって\\n思い返すと少女漫画\\nみたい…えへへ', 4, 1, 1, 0, 0, 105501, 101, 2983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩になら\\n観察されてもいいなぁ', 8, 1, 1, 0, 0, 105501, 102, 2984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイト先に新しい子が\\n入って来たんです…\\nわ、私、先輩です♪', 1, 1, 2, 0, 0, 105501, 1, 2985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩…？\\nえっと、あの、その、\\nあわわわわ…！', 1, 1, 2, 0, 0, 105501, 2, 2986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…えへへ～\\nせ、先輩から\\n話しかけてくれました', 1, 1, 2, 0, 0, 105501, 3, 2987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ま、また…\\n先輩と一緒に\\nバイトしたい…です', 1, 1, 2, 0, 0, 105501, 4, 2988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と先輩が同じ空間に\\n…ゆ、夢みたいです', 4, 1, 2, 0, 0, 105501, 101, 2989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩のそばに\\n居られて、私\\n今、とっても\\n幸せです…', 8, 1, 2, 0, 0, 105501, 102, 2990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩…！\\nおひゃっ！\\nおはようございます！', 1, 1, 2, 0, 1, 105501, 1, 2991);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩ランチに\\n行きましょう！\\nよし、練習はバッチリ', 1, 1, 2, 0, 2, 105501, 2, 2992);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、せ、先輩。\\nえと、そ、外…\\nもう真っ暗ですねぇ', 1, 1, 2, 0, 3, 105501, 3, 2993);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、ここで先輩も\\n休んだり…はっ！\\nわ、私ったらなにを！', 1, 1, 3, 0, 0, 105501, 2, 2995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいですねー\\n君も一緒に、\\n先輩を観察する？', 1, 1, 3, 0, 0, 105501, 3, 2996);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここから先輩の\\n香りがすればなあ', 1, 1, 3, 0, 0, 105501, 4, 2997);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩と一緒に\\nぬくぬくできたら\\n最高なんだけどなぁ', 1, 1, 3, 0, 0, 105501, 5, 2998);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいし～\\nこれは\\n先輩も好きな味かな', 1, 1, 3, 0, 0, 105501, 7, 3000);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('す、好きな人に\\n近づく方法…', 1, 1, 3, 0, 0, 105501, 8, 3001);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の力は、大切な\\n人たちを護るために\\n役立てたいんだ', 1, 1, 1, 0, 0, 109201, 1, 3003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいな景色と\\n美味しいご飯！\\nこの世界も素敵だね', 1, 1, 1, 0, 0, 109201, 2, 3004);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この世界のみんなとも\\nもっと仲良く\\nなりたいな！', 1, 1, 1, 0, 0, 109201, 3, 3005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わー！\\nあれもこれも\\n気になっちゃうな！', 1, 1, 1, 0, 0, 109201, 4, 3006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかりしなきゃって\\n思ってても、\\nグレアといるとつい\\n甘えちゃうんだよね～', 1, 1, 1, 0, 0, 109201, 5, 3007);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('違う世界でも\\n友だちができて、\\nすごくうれしいよ！', 4, 1, 1, 0, 0, 109201, 101, 3008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなとも一緒に\\n授業とか受けたいな～\\n絶対楽しそうだもん！', 8, 1, 1, 0, 0, 109201, 102, 3009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歩き方がきれい？\\nえへへ、そうかな…？', 1, 1, 2, 0, 0, 109201, 1, 3010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強は好きだよ！\\n知識が増えていくのは\\nやっぱり楽しいから', 1, 1, 2, 0, 0, 109201, 2, 3011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちの国マナリアは\\n人々の間に魔法が\\n伝えられた、その\\n始まりの地なんだ！', 1, 1, 2, 0, 0, 109201, 3, 3012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋にも、\\nもっとたくさん本棚が\\n増えないかな～…？', 1, 1, 2, 0, 0, 109201, 4, 3013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたも魔法、\\n覚えてみる？\\n私、教えるよ！', 4, 1, 2, 0, 0, 109201, 101, 3014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お茶の時間に\\nしたいな～…\\n一緒にどう？', 8, 1, 2, 0, 0, 109201, 102, 3015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようっ！\\n今日も素敵な\\n一日にしようね！', 1, 1, 2, 0, 1, 109201, 1, 3016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯は\\nちゃんと食べた？\\n午後も頑張ろうね！', 1, 1, 2, 0, 2, 109201, 2, 3017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つい本の続きが\\n気になって、夜更かし\\nしちゃうんだよね～…', 1, 1, 2, 0, 3, 109201, 3, 3018);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、気持ちいい～…\\nちょっとだけ\\n眠っちゃおうかな…', 1, 1, 3, 0, 0, 109201, 2, 3020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、これ可愛い！\\nグレアにも見せて\\nあげたいな', 1, 1, 3, 0, 0, 109201, 3, 3021);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～！\\nなんだか気持ちが\\n落ち着くね', 1, 1, 3, 0, 0, 109201, 4, 3022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あぁ、あったかくて\\n幸せ～♪\u3000身体が\\nポカポカしてきたよ！', 1, 1, 3, 0, 0, 109201, 5, 3023);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これ美味し～！\\n止められないよー！', 1, 1, 3, 0, 0, 109201, 7, 3025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふん…\\n…はっ！\u3000む、夢中に\\nなっちゃってた…', 1, 1, 3, 0, 0, 109201, 8, 3026);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい建物に入ると\\n必ず一度は迷子に\\nなっちゃうですよ…', 1, 1, 1, 0, 0, 109301, 1, 3028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやつはどこですか？\\nお腹が空いて\\nきちゃったですぅ', 1, 1, 1, 0, 0, 109301, 2, 3029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宿題、７つぐらい\\n出しそびれたですけど\\nまあ大丈夫ですぅ！', 1, 1, 1, 0, 0, 109301, 3, 3030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不思議なこと\\nばかりですけど…\\nまぁ大丈夫です！\\nこれもせいしゅんです', 1, 1, 1, 0, 0, 109301, 4, 3031);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにか面白そうなもの\\nないですかね～？', 1, 1, 1, 0, 0, 109301, 5, 3032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここのみんなとも\\nもうお友だちですぅ！', 4, 1, 1, 0, 0, 109301, 101, 3033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おなかが減ったです…', 8, 1, 1, 0, 0, 109301, 102, 3034);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごはんも美味しいし\\nここはいいところです\\nルゥは幸せですぅ！', 1, 1, 2, 0, 0, 109301, 1, 3035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法の話ですか？\\nそれはアンせんぱいに\\n聞いてほしいですぅ…', 1, 1, 2, 0, 0, 109301, 2, 3036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたもお勉強\\n苦手ですか？', 1, 1, 2, 0, 0, 109301, 3, 3037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルゥの帽子、\\nかわいいです？\\nお気に入りですぅ♪', 1, 1, 2, 0, 0, 109301, 4, 3038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お友だちいっぱいで、\\nルゥはうれしいです♪', 4, 1, 2, 0, 0, 109301, 101, 3039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にお勉強…！？\\nぐえぇ、イヤですぅ！', 8, 1, 2, 0, 0, 109301, 102, 3040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ですねぇ…ふわわ…\\nルゥはまだ夢の中に\\nいたいですぅ…', 1, 1, 2, 0, 1, 109301, 1, 3041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午後もいっぱい\\n遊ぶですよ～！', 1, 1, 2, 0, 2, 109301, 2, 3042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜ふかしって\\nドキドキするです！\\nせいしゅんですぅ！', 1, 1, 2, 0, 3, 109301, 3, 3043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかですぅ～♪\\nおひるねが\\nしたくなるですぅ！', 1, 1, 3, 0, 0, 109301, 2, 3045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これふかふかですぅ！\\n机でうとうとする時の\\n枕によさそうですぅ', 1, 1, 3, 0, 0, 109301, 3, 3046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁぁ、いいにおい…\\nなんだか気持ちが\\nよくなってきたですぅ', 1, 1, 3, 0, 0, 109301, 4, 3047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽっかぽかですぅ～！\\nあったまったら\\nまた遊びにいくですぅ', 1, 1, 3, 0, 0, 109301, 5, 3048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、おいしいですぅ！\\n全部ルゥに\\nくださいですぅ！', 1, 1, 3, 0, 0, 109301, 7, 3050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本は…読むと、\\nすぐ眠気がぁ…\\n…ぐぅ…', 1, 1, 3, 0, 0, 109301, 8, 3051);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ピアノ…\\nどこかにないかな？', 1, 1, 1, 0, 0, 109401, 1, 3053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…\\n落ち着くな…', 1, 1, 1, 0, 0, 109401, 2, 3054);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マナリアはいつも\\n賑やかなんだ…', 1, 1, 1, 0, 0, 109401, 3, 3055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんな…\\n今頃何してるかな？', 1, 1, 1, 0, 0, 109401, 4, 3056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさか違う世界に\\n来ちゃうなんて…\\nびっくりだよね…', 1, 1, 1, 0, 0, 109401, 5, 3057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人と話すのは\\n得意じゃないな…', 4, 1, 1, 0, 0, 109401, 101, 3058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここのみんなと一緒に\\n学院に通えたら…\\nちょっと面白いかも', 8, 1, 1, 0, 0, 109401, 102, 3059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり、私の翼や\\n尻尾…気になる？', 1, 1, 2, 0, 0, 109401, 1, 3060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一番得意なのは、\\nやっぱり炎魔法かな…\\n加減は難しいけど…', 1, 1, 2, 0, 0, 109401, 2, 3061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の故郷は竜の国…\\n険しい山脈を\\n越えた先にあるんだ', 1, 1, 2, 0, 0, 109401, 3, 3062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アン…？\\nあっ、ご、ごめんね！\\n間違えちゃった…', 1, 1, 2, 0, 0, 109401, 4, 3063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふん…ふん…♪\\n…わっ！\\n今の、聞いてた…？\\nは、恥ずかしい…', 4, 1, 2, 0, 0, 109401, 101, 3064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私に手伝えること、\\nなにかある…？\\nなんでも言ってね', 8, 1, 2, 0, 0, 109401, 102, 3065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の空気って\\nすごく\\n静かで透き通ってて…\\nなんだか落ち着くよね', 1, 1, 2, 0, 1, 109401, 1, 3066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院食堂のランチも\\n美味しいけど…\\nここのご飯も好きかな', 1, 1, 2, 0, 2, 109401, 2, 3067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろベッドに\\n行かないとだね\\n…寝相、今夜こそ\\n気を付けよう…！', 1, 1, 2, 0, 3, 109401, 3, 3068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('羽を伸ばしたく\\nなっちゃうね…ふふ', 1, 1, 3, 0, 0, 109401, 2, 3070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ、私が持つには\\nかわいすぎるかな…\\nでも、素敵だね', 1, 1, 3, 0, 0, 109401, 3, 3071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\nこれ、\\nアンも好きそう…', 1, 1, 3, 0, 0, 109401, 4, 3072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火を見ていると\\n少し落ち着くんだ…\\nへ、変かな？', 1, 1, 3, 0, 0, 109401, 5, 3073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ、美味しい…！\\nこれ、どうやって\\n作ったのかな…？', 1, 1, 3, 0, 0, 109401, 7, 3075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本…アンにも\\n見せてあげたら\\n喜ぶかな、ふふっ', 1, 1, 3, 0, 0, 109401, 8, 3076);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物はきれいですが\\n歩きにくいです…\\nいっそ脱いで…ぐふふ', 1, 1, 1, 0, 0, 109501, 1, 3078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、いけません\\n着物がはだけて…はっ\\nもしやドＳさんが…！', 1, 1, 1, 0, 0, 109501, 2, 3079);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋は妄想する\\nのにうってつけです…\\nぐふふ…じゅるり', 1, 1, 1, 0, 0, 109501, 3, 3080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('扇をゆっくりと開く\\nこの感触…なぜだか\\n艶めかしさを感じます', 1, 1, 1, 0, 0, 109501, 4, 3081);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「マッサージをすると\\n言いながらドＳさんの\\n手は次第に」…ぐふふ', 1, 1, 1, 0, 0, 109501, 5, 3082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ドＳさんの視線を\\n思い出しながら踊りの\\n練習です…イイ！', 4, 1, 1, 0, 0, 109501, 101, 3083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よいではないか\\nよいではないか～\\nいけませんご堪忍を～', 8, 1, 1, 0, 0, 109501, 102, 3084);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ～れ～～～！\\nドＳさんもお好きな人\\nですねぇ…ぐふふ', 1, 1, 2, 0, 0, 109501, 1, 3085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこにいてもドＳさん\\nの気配を感じ取れる\\nようになりました…', 1, 1, 2, 0, 0, 109501, 2, 3086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな場所で\\nなんというプレイを！\\n…妄想でした', 1, 1, 2, 0, 0, 109501, 3, 3087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカを押し倒して\\nそのまま…じゅるり\\nああっ、着物が…！', 1, 1, 2, 0, 0, 109501, 4, 3088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんは優しいです\\n優しいのにドＳとは\\nさすが人格破綻者…！', 4, 1, 2, 0, 0, 109501, 101, 3089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんの考えている\\nことが伝わってきます\\nはい…クウカ脱ぎます', 8, 1, 2, 0, 0, 109501, 102, 3090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眩しい朝日がクウカの\\n体を焦がします\\n…それもイイ！', 1, 1, 2, 0, 1, 109501, 1, 3091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼のランチは\\nクウカがいいだなんて\\n大胆過ぎです…じゅる', 1, 1, 2, 0, 2, 109501, 2, 3092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…今夜のドＳさんは\\n大胆です…ぐふふ…\\nはっ、視線が…！？', 1, 1, 2, 0, 3, 109501, 3, 3093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この心地良さ、\\n心が休まりすぎて\\n体が疼いてきます…！', 1, 1, 3, 0, 0, 109501, 2, 3095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごく愛らしいです…\\n妄想も出てこない\\nくらい…じゅるり', 1, 1, 3, 0, 0, 109501, 3, 3096);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香りに包まれて\\nいると、いい気持ちに\\nなって…いきますぅ…', 1, 1, 3, 0, 0, 109501, 4, 3097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「熱を帯びた体は\\nどうしようもなく\\n誰かを求め…」ぐふふ', 1, 1, 3, 0, 0, 109501, 5, 3098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹が膨らんで\\nいきます…それは\\nまるで…ぐふふ', 1, 1, 3, 0, 0, 109501, 7, 3100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカの探している\\nジャンルはどこに\\nありますかね？', 1, 1, 3, 0, 0, 109501, 8, 3101);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カチョーフーゲツは\\nトーゴクの心を\\n表した言葉デスね', 1, 1, 1, 0, 0, 109601, 1, 3103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オー！\u3000新しい忍法を\\n思いついたデス！\\nさっそく試すデス！', 1, 1, 1, 0, 0, 109601, 2, 3104);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トーゴクの天気には\\n槍が降る日も\\nあるそうデス…', 1, 1, 1, 0, 0, 109601, 3, 3105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('我がショーグンは\\n永遠にフメツデース\\nいざ出陣デース！', 1, 1, 1, 0, 0, 109601, 4, 3106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('壁に耳あり\\n障子に…ん？\\nメアリーって誰デス？', 1, 1, 1, 0, 0, 109601, 5, 3107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンがいれば\\nワタシはどんな\\n忍法も使いこなせマス', 4, 1, 1, 0, 0, 109601, 101, 3108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不届き者はどこで\\nゴザルデス？\u3000忍法で\\n退治してくれヨウ！', 8, 1, 1, 0, 0, 109601, 102, 3109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグン！\u3000新しい\\n忍法を覚えたデス！\\n見てほしいデース！', 1, 1, 2, 0, 0, 109601, 1, 3110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッツ手裏剣道デス！\\n投げてソウロウで\\nゴザルデース！', 1, 1, 2, 0, 0, 109601, 2, 3111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふりかかる火の粉は\\nワタシが払うデス！\\nバンバン！', 1, 1, 2, 0, 0, 109601, 3, 3112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっておきの忍法が\\n吹き荒れるデス！\\nよそ見はダメデスヨ？', 1, 1, 2, 0, 0, 109601, 4, 3113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンは\\n何階建てのお城を\\n建てたいデスか？', 4, 1, 2, 0, 0, 109601, 101, 3114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テンシュカクから\\n平和な城下町を\\n眺めてみたいデス…', 8, 1, 2, 0, 0, 109601, 102, 3115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございマス！\\n本日はオヒガラモヨク\\n良い日になりそうデス', 1, 1, 2, 0, 1, 109601, 1, 3116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたデース…\\nショーグンもご飯に\\nしまショウ！', 1, 1, 2, 0, 2, 109601, 2, 3117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('闇討ちに遭わぬよう\\n夜は気を付けて\\n歩くデスよー？', 1, 1, 2, 0, 3, 109601, 3, 3118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('天下分け目の\\n戦いに備えて…\\nマッタリデース', 1, 1, 3, 0, 0, 109601, 2, 3120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('口寄せの術で\\n召喚したいくらい\\nかわいいデース', 1, 1, 3, 0, 0, 109601, 3, 3121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂いデ～ス\\n香り玉の開発の\\n参考になりそうデスね', 1, 1, 3, 0, 0, 109601, 4, 3122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシの懐よりも\\nゾーリが暖まりマス…\\nライバル出現デス…！', 1, 1, 3, 0, 0, 109601, 5, 3123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹が減っては\\n戦はできぬデース！\\n天下統一に向けて\\n腹ごしらえデス！', 1, 1, 3, 0, 0, 109601, 7, 3125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ムム、暗号文デス！？\\n解読には時間が\\nかかりそうデース…', 1, 1, 3, 0, 0, 109601, 8, 3126);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('掃除も終わりましたし\\nそろそろ、食事の\\n準備をしなくては', 1, 1, 1, 0, 0, 109701, 1, 3128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('異世界の演劇…\\n許されるならば、\\n観てみたいです', 1, 1, 1, 0, 0, 109701, 2, 3129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こちらの世界には、\\nマヨネーズが普通に\\n存在するのですね…', 1, 1, 1, 0, 0, 109701, 3, 3130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こちらの世界は食材も\\n面白い物が多いですね\\nなにかレシピを\\n考えてみましょうか', 1, 1, 1, 0, 0, 109701, 4, 3131);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みょんみょんみょん…\\n魔法の練習は\\nこれぐらいですね', 1, 1, 1, 0, 0, 109701, 5, 3132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('倒木の撤去で思わぬ\\n収入となりました\\nサレン様に\\nお渡ししておかないと', 4, 1, 1, 0, 0, 109701, 101, 3133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理を美味しく\\n召し上がって頂けると\\nメイド冥利につきます', 8, 1, 1, 0, 0, 109701, 102, 3134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お出かけでしたら、\\nレムも同行\\nさせてくださいね', 1, 1, 2, 0, 0, 109701, 1, 3135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レムにできること\\nでしたら、なんでも\\nお申し付けください', 1, 1, 2, 0, 0, 109701, 2, 3136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じーー。いえ、\\nその髪の長さが少し、\\nとても少し、かなり\\n少し気になったもので', 1, 1, 2, 0, 0, 109701, 3, 3137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鉄球ですか？\\nあれは護身用ですので\\n問題はありませんよ？', 1, 1, 2, 0, 0, 109701, 4, 3138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('計算の勉強は\\n進んでおりますか？\\nレムでよろしければ、\\nいつでもお教えします', 4, 1, 2, 0, 0, 109701, 101, 3139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はもっと、大きな\\n魔物料理に挑戦します\\nワイバーンの姿焼き\\nなんてどうでしょうか', 8, 1, 2, 0, 0, 109701, 102, 3140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n朝食の準備が\\nできておりますので、\\n食卓におこしください', 1, 1, 2, 0, 1, 109701, 1, 3141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食の時間ですね\\n何か食べたいものは\\nありますか？', 1, 1, 2, 0, 2, 109701, 2, 3142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝ないのか、ですか？\\nメイドの就寝は、\\n屋敷で最後と\\n決まっておりますので', 1, 1, 2, 0, 3, 109701, 3, 3143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんわり…\\nこのふんわりさは、\\n鬼をも黙らせます…', 1, 1, 3, 0, 0, 109701, 2, 3145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ…異世界でも\\nかわいいものは\\n共通なのですね', 1, 1, 3, 0, 0, 109701, 3, 3146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よい香りですね\\n魔女教の悪臭とは\\n大違いです', 1, 1, 3, 0, 0, 109701, 4, 3147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬくぬくです…はっ！\\nこれはいけません！\\n人を…いえ、\\n鬼をだめにします！', 1, 1, 3, 0, 0, 109701, 5, 3148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむはむ…美味しい！\\nこの味を再現できたら\\n褒めてもらえる\\nかもしれません…！', 1, 1, 3, 0, 0, 109701, 7, 3150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵がいっぱい…\\n異世界の本は\\nとても面白いですね', 1, 1, 3, 0, 0, 109701, 8, 3151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('異世界であろうと、\\nラムのやるべきことは\\n変わらないわ\\nまずは休憩するわよ', 1, 1, 1, 0, 0, 109801, 1, 3153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マヨネーズがある\\nということは、\\nバルスの故郷が近い\\nのかもしれないわね', 1, 1, 1, 0, 0, 109801, 2, 3154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この世界では、バルス\\nの言う言葉が使われる\\nときがあるのね\\n忌々しいかぎりだわ', 1, 1, 1, 0, 0, 109801, 3, 3155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラムたち以外にも\\nメイドが居るのね\\nラムが…いえ、\\n仕事を押しつけるわ', 1, 1, 1, 0, 0, 109801, 4, 3156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…千里眼で視るかぎり\\n周囲に異変はないわね\\n危険がないなら、\\nあとはレムに任せるわ', 1, 1, 1, 0, 0, 109801, 5, 3157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ラムもまた、\\n「お姉ちゃん」って\\n呼ばれる日が\\nくるのかしらね', 4, 1, 1, 0, 0, 109801, 101, 3158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハッ！\u3000ラムが作る\\n蒸かし芋は完璧ね\\n…気が向いたら、また\\n作ってやろうかしら', 8, 1, 1, 0, 0, 109801, 102, 3159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラムに構う暇が\\nあるなら働きなさい\\nそうすれば、\\nラムが楽をできるわ', 1, 1, 2, 0, 0, 109801, 1, 3160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラムに何かを\\n期待しても無駄よ\\nラムに命令できるのは\\nロズワール様だけだわ', 1, 1, 2, 0, 0, 109801, 2, 3161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇なら買い物に\\n付き合いなさい\\n荷物を\\n持たせてあげるわ', 1, 1, 2, 0, 0, 109801, 3, 3162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラムになんの用？\\nふざけた内容なら\\nねじ切るわよ', 1, 1, 2, 0, 0, 109801, 4, 3163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そういえば、あなたは\\n記憶喪失だったわね…\\n思い出す努力をなさい\\n…家族が悲しむわよ', 4, 1, 2, 0, 0, 109801, 101, 3164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('蒸かし芋が欲しい？\\n随分と厚かましいわね\\n…まだ残りがあるから\\n好きに食べなさい', 8, 1, 2, 0, 0, 109801, 102, 3165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だらしない顔ね\\n顔を洗って\\nしゃんとなさい', 1, 1, 2, 0, 1, 109801, 1, 3166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹が空く時間ね\\nラムの昼食を\\n用意させてあげるわ', 1, 1, 2, 0, 2, 109801, 2, 3167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メイドが寝るのは\\n屋敷で最後…\\nラムが寝るために、\\nさっさと寝なさい', 1, 1, 2, 0, 3, 109801, 3, 3168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ここから動かない\\nという、誓いを\\n立てたくなるわね', 1, 1, 3, 0, 0, 109801, 2, 3170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…かわいいわね\\nもちろん、\\nラムほどではないけど', 1, 1, 3, 0, 0, 109801, 3, 3171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…香炉かしら？\\nこちらの世界にも\\n質のよい物があるのね', 1, 1, 3, 0, 0, 109801, 4, 3172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見つけてしまったの\\nかもしれないわ…\\nラムの楽園を！', 1, 1, 3, 0, 0, 109801, 5, 3173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…はむっ\\nラムの蒸かし芋ほど\\nではないけど、\\nなかなかいけるわね', 1, 1, 3, 0, 0, 109801, 7, 3175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('異世界ならではの\\n面白い内容もあるわね\\nとても興味深いわ', 1, 1, 3, 0, 0, 109801, 8, 3176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえパック、\\nにゃんにゃか\\nにゃかにゃんしよっか', 1, 1, 1, 0, 0, 109901, 1, 3178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時間もあるし、\\nこっちの世界の石で\\n石積みしようかな', 1, 1, 1, 0, 0, 109901, 2, 3179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私もお姉さんだし、\\nサレンさんを\\n見習わないと…うん！\\n私、すごーく頑張る！', 1, 1, 1, 0, 0, 109901, 3, 3180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この世界は、銀髪で\\nハーフエルフでも受け\\n入れてくれるのね…\\nなんだか嬉しいな', 1, 1, 1, 0, 0, 109901, 4, 3181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のご飯…\\nピーマルは\\n入ってないわよね…？', 1, 1, 1, 0, 0, 109901, 5, 3182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('また、みんなで\\n一緒に買い物に\\n行きたいな', 4, 1, 1, 0, 0, 109901, 101, 3183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パック以外から\\n家族って呼ばれたの\\n初めて…ふふっ♪\\nちょっと嬉しいかも！', 8, 1, 1, 0, 0, 109901, 102, 3184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今からパックの\\n毛繕いをするけど…\\n一緒にする？', 1, 1, 2, 0, 0, 109901, 1, 3185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私も何かお手伝いを…\\nあ、そうだ！\\n料理とかどうかな！', 1, 1, 2, 0, 0, 109901, 2, 3186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、ここで\\n歌の練習って、\\nしてもいいかな？', 1, 1, 2, 0, 0, 109901, 3, 3187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あ、ごめんなさい！\\n話しかけられるのって\\nあまり慣れてなくて…', 1, 1, 2, 0, 0, 109901, 4, 3188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごーく頑張るから、\\nこれからも勉強を\\n手伝ってね', 4, 1, 2, 0, 0, 109901, 101, 3189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せーの、びくとりー！\\nふふっ…また、一緒に\\nラジーオタイソー\\nしようね♪', 8, 1, 2, 0, 0, 109901, 102, 3190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんと起きてる？\\nふふっ…よかった。\\nあ、べ、別に心配した\\nわけじゃないからね？', 1, 1, 2, 0, 1, 109901, 1, 3191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯が楽しみね♪\\nあ、こっちの世界って\\nまよねーずはあるの？', 1, 1, 2, 0, 2, 109901, 2, 3192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝る時間よ。\\n夜更かししたら、\\nめっ！\u3000だからね！', 1, 1, 2, 0, 3, 109901, 3, 3193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強も終わったし…\\nちょっ、ちょっとだけ\\n休んでもいいよね…？', 1, 1, 3, 0, 0, 109901, 2, 3195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…！\\nパックのかわいさに\\n匹敵するかも…！', 1, 1, 3, 0, 0, 109901, 3, 3196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い香り…\\nロズワールの屋敷にも\\nこういうのって\\nあるのかな？', 1, 1, 3, 0, 0, 109901, 4, 3197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\nずっとここに…はっ！\\nダメダメ！\u3000王選の\\nために勉強しないと！', 1, 1, 3, 0, 0, 109901, 5, 3198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ…これ美味しい！\\nこっちの世界は色んな\\n食べ物があるのね。', 1, 1, 3, 0, 0, 109901, 7, 3200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知らないことが\\nいっぱい書いてある…\\n異世界の本って、\\n面白いのね', 1, 1, 3, 0, 0, 109901, 8, 3201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海ってマジ最高！\\nビーチの撮影も\\n超楽しいしー♪', 1, 1, 1, 0, 0, 110001, 1, 3203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('20パーって何パ？\\n今度ヒデサイに\\n聞いてみよっ！', 1, 1, 1, 0, 0, 110001, 2, 3204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の思い出を\\nヒデサイと一緒に\\n作りたいな～', 1, 1, 1, 0, 0, 110001, 3, 3205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テンションあがる\\n水着ゲットして\\n超ラッキーだよ～♪', 1, 1, 1, 0, 0, 110001, 4, 3206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩が終わったら\\n撮影にもどらないと！\\n気合入れてこ♪', 1, 1, 1, 0, 0, 110001, 5, 3207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイとビーチで\\nパーティーしたいな～\\n超楽しそうだよね！', 4, 1, 1, 0, 0, 110001, 101, 3208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイといると\\n楽しくてうれしくて…\\nカレシってこんな感じ\\nなのかなぁ？', 8, 1, 1, 0, 0, 110001, 102, 3209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見て見て～！\\n夏らしいネイルに\\nしてみたんだ～♪', 1, 1, 2, 0, 0, 110001, 1, 3210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイ～\\nこの水着どうかな？\\nイケてるっしょ♪', 1, 1, 2, 0, 0, 110001, 2, 3211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿の写真？\\nもちいいよ！\\nかわいく撮ってね！', 1, 1, 2, 0, 0, 110001, 3, 3212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちだって\\n夏の海みたいに\\nキラキラしちゃうよ！', 1, 1, 2, 0, 0, 110001, 4, 3213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイとうちの\\nフィーリングって\\nめっちゃエモいよね♪', 4, 1, 2, 0, 0, 110001, 101, 3214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねーねーヒデサイ！\\n一緒に泳ぎにいこっ！\\nほら、手繋いで♪', 8, 1, 2, 0, 0, 110001, 102, 3215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着オッケー！\\nネイルもばっちり！\\n朝から遊んじゃおー♪', 1, 1, 2, 0, 1, 110001, 1, 3216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼食べたら\\n昼寝して\\nリフレッシュしよー♪', 1, 1, 2, 0, 2, 110001, 2, 3217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着ってマジで\\n最強かも…このまま\\nお風呂にも入れるし♪', 1, 1, 2, 0, 3, 110001, 3, 3218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マジ気持ちいいー♪\\nおに癒やされるん\\nですけど～！', 1, 1, 3, 0, 0, 110001, 2, 3220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やばばばばー！\\nかわいすぎだってば！\\nマジらぶだよ～♪', 1, 1, 3, 0, 0, 110001, 3, 3221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、この香り超好き！\\nモデル仲間に\\n教えたげよ～♪', 1, 1, 3, 0, 0, 110001, 4, 3222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い♪\\n夏の太陽みたい！', 1, 1, 3, 0, 0, 110001, 5, 3223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マジ美味しいねこれ♪\\nビーチで\\n流行っちゃうかも！', 1, 1, 3, 0, 0, 110001, 7, 3225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏のために\\n最新ファッションを\\n勉強ちう！', 1, 1, 3, 0, 0, 110001, 8, 3226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにコレもにカワ～♪\\nなんて生き物？\\nヒデサイ知ってる？', 1, 1, 3, 0, 0, 110001, 10, 3228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うわっ超フカフカ～\\nなんかうち眠く\\nなってきちゃった…', 1, 1, 3, 0, 0, 110001, 11, 3229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の家でのんびり\\n過ごしましょう\\n熱中症には注意してね', 1, 1, 1, 0, 0, 110101, 1, 3230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、どうやったら\\n泳げるように\\nなれるのかしら～', 1, 1, 1, 0, 0, 110101, 2, 3231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で日焼け止めを\\n塗らないと、あとで\\n大変なことになるわよ', 1, 1, 1, 0, 0, 110101, 3, 3232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('久しぶりに水着を\\n着たんだけど\\n変じゃなかったかな…', 1, 1, 1, 0, 0, 110101, 4, 3233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('波の音って落ち着くわ\\n授業中に聞いたら\\nみんな寝ちゃうかも？', 1, 1, 1, 0, 0, 110101, 5, 3234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海が楽しいって\\n思えたのも\\nあの子のおかげね', 4, 1, 1, 0, 0, 110101, 101, 3235);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子と二人で海に\\n来られてよかったわ\\n一日があっという間ね', 8, 1, 1, 0, 0, 110101, 102, 3236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男の子と海だなんて\\n少女漫画みたいで\\n憧れてたの～', 1, 1, 2, 0, 0, 110101, 1, 3237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みの宿題は\\nちゃんとやった？\\n遊んでばかりではダメ', 1, 1, 2, 0, 0, 110101, 2, 3238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼の海と夜の海\\nどっちが好き？\u3000私は\\n君といる海が一番よ', 1, 1, 2, 0, 0, 110101, 3, 3239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう、疲れたわ～\\n冷たいジュースで\\n元気回復ね！', 1, 1, 2, 0, 0, 110101, 4, 3240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で見た君の背中\\nすごく大きく見えたわ\\nやっぱり男の子なのね', 4, 1, 2, 0, 0, 110101, 101, 3241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君と一緒に見た\\n夜の海…\\n忘れられそうにないわ', 8, 1, 2, 0, 0, 110101, 102, 3242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('準備ができたら\\n海に出かけようよ\\n今日も楽しみましょう', 1, 1, 2, 0, 1, 110101, 1, 3243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、もうお昼？\\n海の家でランチに\\nしましょ♪', 1, 1, 2, 0, 2, 110101, 2, 3244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海岸についてきて\\nくれる？\u3000暗がりは\\n一人じゃ怖くて…', 1, 1, 2, 0, 3, 110101, 3, 3245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐ練習をしたら\\n疲れちゃったわ～\\nちょっと一休み…', 1, 1, 3, 0, 0, 110101, 2, 3247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいわね～\\n浮き輪に乗せて\\n海に浮かべたいわ～', 1, 1, 3, 0, 0, 110101, 3, 3248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この匂い…\\nなんだか夏の海を\\n思い出すわ～', 1, 1, 3, 0, 0, 110101, 4, 3249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海風で冷えない\\nように、しっかりと\\n身体を暖めましょうね', 1, 1, 3, 0, 0, 110101, 5, 3250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で遊ぶ前に\\nしっかり食べて\\n体力つけましょう', 1, 1, 3, 0, 0, 110101, 7, 3252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休み中でも\\nしっかりお勉強\\nしないと！', 1, 1, 3, 0, 0, 110101, 8, 3253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子に乗れば\\n海の上でも\\nすいすい進めるかしら', 1, 1, 3, 0, 0, 110101, 10, 3255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーナスの誕生！\\n…なんちゃって\\nはしゃぎすぎかしら？', 1, 1, 3, 0, 0, 110101, 11, 3256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の海には商機が\\nあるはず…\\nのがす手はないわね♪', 1, 1, 1, 0, 0, 110301, 1, 3257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしが作った\\n日焼け止め…\\nこれは売れそうね！', 1, 1, 1, 0, 0, 110301, 2, 3258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちのために\\n浮き輪を用意して\\nおかないと…', 1, 1, 1, 0, 0, 110301, 3, 3259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海っていいわよね！\\nみんなで羽を伸ばしに\\n行きたいわ！', 1, 1, 1, 0, 0, 110301, 4, 3260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('波の音を聞いて\\nのんびりするのも\\n悪くないわね…', 1, 1, 1, 0, 0, 110301, 5, 3261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ただの砂遊びも\\nあんたと一緒なら\\n楽しいから不思議ね…', 4, 1, 1, 0, 0, 110301, 101, 3262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたがあたしの\\nなんであれ、大切な\\n存在ではあるのよね…', 8, 1, 1, 0, 0, 110301, 102, 3263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の海って\\nすごい人よね…\\n迷子にならないでよ？', 1, 1, 2, 0, 0, 110301, 1, 3264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼんやり海に浮かんで\\n波に揺られるのも\\n悪くないわよ？', 1, 1, 2, 0, 0, 110301, 2, 3265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーチで子どもたちと\\n一緒に砂のお城を\\n作りたいわ♪', 1, 1, 2, 0, 0, 110301, 3, 3266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で食べる\\n焼きそばパン…\\nいいかもしれないわね', 1, 1, 2, 0, 0, 110301, 4, 3267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの水着\\n似合ってる？\\nそう、ありがとう♪', 4, 1, 2, 0, 0, 110301, 101, 3268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたが居ると\\nうれしい…って、\\n子どもたちが\\n言ってたわ！', 8, 1, 2, 0, 0, 110301, 102, 3269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の浜辺って\\nいいわよね\\n散歩しに行きたいわ', 1, 1, 2, 0, 1, 110301, 1, 3270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の家のご飯って\\nなんであんなに\\nおいしいのかしら♪', 1, 1, 2, 0, 2, 110301, 2, 3271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海って、\\nロマンチックよね。\\nずっと眺めてたいわ…', 1, 1, 2, 0, 3, 110301, 3, 3272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やわらかくて\\n気持ちいい…\\nこのまま寝ちゃいそう', 1, 1, 3, 0, 0, 110301, 2, 3274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に一緒に入れる\\nぬいぐるみとか\\nないかしら？', 1, 1, 3, 0, 0, 110301, 3, 3275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏らしい\\nいい香りね…\\nなんの香りかしら？', 1, 1, 3, 0, 0, 110301, 4, 3276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\n濡れた体を乾かすには\\nちょうどいいわね♪', 1, 1, 3, 0, 0, 110301, 5, 3277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳いだ後の食事は\\n普段の何倍も\\nおいしく感じるわね！', 1, 1, 3, 0, 0, 110301, 7, 3279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行く前にいろいろ\\n調べなきゃね。備え\\nあれば憂いなしよ！', 1, 1, 3, 0, 0, 110301, 8, 3280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の守り神？\\nずいぶんかわいらしい\\n神様ね♪', 1, 1, 3, 0, 0, 110301, 10, 3282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このぐらい\\n大きな貝があったら\\n食費も浮くかしら？', 1, 1, 3, 0, 0, 110301, 11, 3283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('浜辺で食うものって\\nなんであんなに\\nうまいのかな～', 1, 1, 1, 0, 0, 110401, 1, 3284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いてて…\\nちょっと日焼け\\nしすぎたかな', 1, 1, 1, 0, 0, 110401, 2, 3285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂浜で走ると\\nいいトレーニングに\\nなるんだぜ', 1, 1, 1, 0, 0, 110401, 3, 3286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏ならではの\\n料理…か\\n何がいいかな…', 1, 1, 1, 0, 0, 110401, 4, 3287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりここは\\n涼しくて快適だな', 1, 1, 1, 0, 0, 110401, 5, 3288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぎの練習だったら\\nいつでも付き合って\\nやるからな！', 4, 1, 1, 0, 0, 110401, 101, 3289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着で部屋の中に\\nいるのって\\n変な感じだな…', 8, 1, 1, 0, 0, 110401, 102, 3290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うおっ！\\nきゅ、急に\\n触るなって…\\nびっくりした', 1, 1, 2, 0, 0, 110401, 1, 3291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、砂がついてた？\\n払ってくれたのか\\nありがとよ', 1, 1, 2, 0, 0, 110401, 2, 3292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏バテしてないか？\\nここで休んでけよ', 1, 1, 2, 0, 0, 110401, 3, 3293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…そう見られると\\n照れるっていうか…', 1, 1, 2, 0, 0, 110401, 4, 3294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カキ氷とか\\n食いたくないか？\\n氷、削ってやるよ', 4, 1, 2, 0, 0, 110401, 101, 3295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おまえと\\n夏の思い出ができて\\nよかったよ', 8, 1, 2, 0, 0, 110401, 102, 3296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう…\\n朝一番で泳ぐの\\nやっぱ気持ちいいな', 1, 1, 2, 0, 1, 110401, 1, 3297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一番あちぃ時間だ\\n水分補給は\\nこまめにな！', 1, 1, 2, 0, 2, 110401, 2, 3298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もお疲れ\\n明日のパトロールも\\nよろしくな', 1, 1, 2, 0, 3, 110401, 3, 3299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぎ疲れたからな\\n少し休憩だ…', 1, 1, 3, 0, 0, 110401, 2, 3301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…\\nいや、なんでもねぇ！', 1, 1, 3, 0, 0, 110401, 3, 3302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り落ち着くな\\nこういうのも\\n悪くねーかも…', 1, 1, 3, 0, 0, 110401, 4, 3303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったけえ…！\\n泳ぎ終わった後って\\nけっこう体冷えてよ…', 1, 1, 3, 0, 0, 110401, 5, 3304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で食べると\\nまた一味違うよな', 1, 1, 3, 0, 0, 110401, 7, 3306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏のサバイバル特集…\\nちょっと読んでみるか', 1, 1, 3, 0, 0, 110401, 8, 3307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へー！\u3000こいつ、\\nよくできてんな！\\nいいなあ、実物も\\n乗れたらいいのに', 1, 1, 3, 0, 0, 110401, 10, 3309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわ…！\\nいや、じゃなくて\\nあ、あたしがここに\\n寝ていいのか…？', 1, 1, 3, 0, 0, 110401, 11, 3310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('故郷の花を飾っても\\nいいかな～？\\n部屋が楽しくなるよ～', 1, 1, 1, 0, 0, 110501, 1, 3311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着で歩いてると\\n泳ぎたくなるさ～\\n我慢できないさ～！', 1, 1, 1, 0, 0, 110501, 2, 3312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏が眩しいのは\\nてぃーだがにこにこ\\n笑ってるからさ～！', 1, 1, 1, 0, 0, 110501, 3, 3313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぎ疲れたら\\n涼しい木陰で\\nお昼寝するさ～', 1, 1, 1, 0, 0, 110501, 4, 3314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クロールも\\n犬かきも\\n大得意さ～！', 1, 1, 1, 0, 0, 110501, 5, 3315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか歌いたい\\n気分さ～\\nキミもどう～？', 4, 1, 1, 0, 0, 110501, 101, 3316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の近くに住んで\\nキミと歌って踊って\\nそれが理想さ～！', 8, 1, 1, 0, 0, 110501, 102, 3317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私とキミ\\nどっちがたくさん\\n泳げるか\\n競争するさ～！', 1, 1, 2, 0, 0, 110501, 1, 3318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミも三線に興味が\\nあるのかな～？\\n私が教えるさ～！', 1, 1, 2, 0, 0, 110501, 2, 3319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('嫌なことがあっても\\n私と歌って踊れば\\nなんくるないさー！', 1, 1, 2, 0, 0, 110501, 3, 3320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには時間を忘れて\\n私とのーんびり\\n海を眺めるさ～', 1, 1, 2, 0, 0, 110501, 4, 3321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぶるぶるぶるっ！\\n毛が濡れちゃっても\\nへっちゃらさ～！', 4, 1, 2, 0, 0, 110501, 101, 3322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐ前は準備体操～！\\n背中押してあげるから\\nしっかりやるさ～！', 8, 1, 2, 0, 0, 110501, 102, 3323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の浜辺は\\nちゅらさんよ～\\n一緒に歩こうよー！', 1, 1, 2, 0, 1, 110501, 1, 3324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯は\\n決まったかな～？\\n私はタコライスさ～！', 1, 1, 2, 0, 2, 110501, 2, 3325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('星と波音の中で\\n三線鳴らすのも\\nオツなものさ～', 1, 1, 2, 0, 3, 110501, 3, 3326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうどよかったさー\\nゆっくり休んだら\\nまた泳ぎに行くさ～！', 1, 1, 3, 0, 0, 110501, 2, 3328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂浜に飾って\\nおきたいさ～\\nきっとかわいいさ～！', 1, 1, 3, 0, 0, 110501, 3, 3329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…はあ\\n癒されるさ…\\n故郷の夏の匂いさ～', 1, 1, 3, 0, 0, 110501, 4, 3330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおー…！\\n濡れた髪が\\nみるみる乾いてくさ～', 1, 1, 3, 0, 0, 110501, 5, 3331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～！\u3000これ、\\n海で食べたら\\nもっとおいしいさ～', 1, 1, 3, 0, 0, 110501, 7, 3333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の生物図鑑ね～\\nこの前みかけた魚も\\n載ってるかな～？', 1, 1, 3, 0, 0, 110501, 8, 3334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ～！\u3000みてみて！\\n背中に乗れるさー！\\nキミと一緒に\\n乗りたいさ～！', 1, 1, 3, 0, 0, 110501, 10, 3336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかさ～\\n海の底の\\n人魚になった気分さ～', 1, 1, 3, 0, 0, 110501, 11, 3337);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人が\\nわたしの騎士だったら\\nいいのにな…', 12, 1, 1, 0, 0, 105801, 103, 3338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたのおかげで\\nわたしの心はいつも\\nお腹いっぱいです♪', 12, 1, 2, 0, 0, 105801, 103, 3339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('許されるのならば、\\n今すぐにでも、\\n主さまのおそばに\\n行きたいです…', 12, 1, 1, 0, 0, 105901, 103, 3340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま…\\nお慕いしております…\\nいつまでも、おそばに\\n居させてください…', 12, 1, 2, 0, 0, 105901, 103, 3341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんか最近、\\nあいつのことしか\\n考えてない…\\nあたし…どうしよう…', 12, 1, 1, 0, 0, 106001, 103, 3342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そ、外に行くなら、\\n連れていきなさいよね\\nその…あたしが\\n守ってあげるから…', 12, 1, 2, 0, 0, 106001, 103, 3343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の中は涼しくて\\n気持ちええどすなぁ\\n天国やわぁ', 1, 1, 1, 0, 0, 110601, 1, 3344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クラゲはんって\\nフリルいっぱいの\\nドレスみたいやねぇ', 1, 1, 1, 0, 0, 110601, 2, 3345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外でセミはんが\\n元気に鳴いてはるねぇ\\n今日もええ天気やわぁ', 1, 1, 1, 0, 0, 110601, 3, 3346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こないに暑いと\\n海に入って\\n涼みたくなるわぁ', 1, 1, 1, 0, 0, 110601, 4, 3347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか\\nマホマホ王国にも\\n海の家作りまひょ♪', 1, 1, 1, 0, 0, 110601, 5, 3348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちも\\n付き合いますえ\\n泳ぎの練習しまひょ♪', 4, 1, 1, 0, 0, 110601, 101, 3349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの里帰り\\n王子はんも一緒に\\n来まへんか？', 8, 1, 1, 0, 0, 110601, 102, 3350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんは日焼けより\\n色白美人の方が\\n好きでっしゃろか？', 1, 1, 2, 0, 0, 110601, 1, 3351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちと一緒に\\n浮き輪で海、\\nプカプカしまへん？', 1, 1, 2, 0, 0, 110601, 2, 3352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日が落ちたら\\n線香花火\\nやりたいわぁ♪', 1, 1, 2, 0, 0, 110601, 3, 3353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('木陰でのんびり\\nお昼寝…\\n最高やね～', 1, 1, 2, 0, 0, 110601, 4, 3354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お祭ではぐれても\\n王子はんなら見つけて\\nくれはります？', 4, 1, 2, 0, 0, 110601, 101, 3355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽しい夏やわぁ\\nずっとこんな日が\\nつづくとええね', 8, 1, 2, 0, 0, 110601, 102, 3356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちにしては早起き？\\n暑くて目が早う\\n覚めてもうたんどす', 1, 1, 2, 0, 1, 110601, 1, 3357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼は冷たい\\nおそうめんとか\\nどうでっしゃろ', 1, 1, 2, 0, 2, 110601, 2, 3358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜は星がきれいやね\\n二人で浜辺でも\\n行きまへんか？', 1, 1, 2, 0, 3, 110601, 3, 3359);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、遊び疲れた\\n身体にちょうどええ\\nほっこり具合やわぁ', 1, 1, 3, 0, 0, 110601, 2, 3361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かいらしい子は\\nみーんな\\nマホマホ王国の\\n住人どすえ♪', 1, 1, 3, 0, 0, 110601, 3, 3362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…\\n南国にいる気分やねぇ\\n癒されるわぁ～', 1, 1, 3, 0, 0, 110601, 4, 3363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで\\n冷えた身体も\\nポカポカやねぇ', 1, 1, 3, 0, 0, 110601, 5, 3364);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外はまだ暑いやろうし\\nバテんよう\\nしっかり食べんとね', 1, 1, 3, 0, 0, 110601, 7, 3366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の中にもお城が\\nあるんやねぇ\\n行ってみたいわぁ', 1, 1, 3, 0, 0, 110601, 8, 3367);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子、ふかふかやね\\nこのままマホマホ王国\\n乗せてってくれはる？', 1, 1, 3, 0, 0, 110601, 10, 3369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人魚姫になっても\\n最後は王子はんと\\nハッピーエンド\\nどすえ～', 1, 1, 3, 0, 0, 110601, 11, 3370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('真似したくなる\\n人がここには\\n大勢いますね', 1, 1, 1, 0, 0, 107001, 1, 3371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('偽物を一人\\n紛れこませました\\n…冗談です', 1, 1, 1, 0, 0, 107001, 2, 3372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('動物に変身して\\nその辺りを\\n散歩してきます', 1, 1, 1, 0, 0, 107001, 3, 3373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('失った記憶は\\nどの程度回復するの\\nでしょうね', 1, 1, 1, 0, 0, 107001, 4, 3374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人や物だけでなく\\nいずれは世界すら\\n真似てみせます', 1, 1, 1, 0, 0, 107001, 5, 3375);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次は彼に\\nどんなことを\\n教えましょうか…', 4, 1, 1, 0, 0, 107001, 101, 3376);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知識はともかく\\n私の力はまだ\\n必要なようですね', 8, 1, 1, 0, 0, 107001, 102, 3377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしました？\\n…何でもない？\\n…そうですか', 1, 1, 2, 0, 0, 107001, 1, 3378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('退屈しています\\n芸でもして\\n楽しませなさい', 1, 1, 2, 0, 0, 107001, 2, 3379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('研究のためです\\n少し話し相手に\\nなりなさい', 1, 1, 2, 0, 0, 107001, 3, 3380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か真似して欲しい？\\n私の能力を何だと\\n思っているのですか', 1, 1, 2, 0, 0, 107001, 4, 3381);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴方にはまだ色々と\\n教えるべきことが\\nありますね', 4, 1, 2, 0, 0, 107001, 101, 3382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('随分多くの女性と\\n知り合いなのですね\\n驚きました', 8, 1, 2, 0, 0, 107001, 102, 3383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…\\nおはようございます\\n…まだ朝ですよ', 1, 1, 2, 0, 1, 107001, 1, 3384);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事にします\\n…どうしました？\\n早く持ってきなさい', 1, 1, 2, 0, 2, 107001, 2, 3385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早く寝なさい\\n夜更かしすると\\n背が伸びませんよ？', 1, 1, 2, 0, 3, 107001, 3, 3386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マサキより\\n座り心地は\\nいいですね', 1, 1, 3, 0, 0, 107001, 2, 3388);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('意外に複雑な\\n構造ですね', 1, 1, 3, 0, 0, 107001, 3, 3389);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('真似るなら\\n香りまで\\n再現しなくては', 1, 1, 3, 0, 0, 107001, 4, 3390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('発火現象の\\n模倣…なかなか\\n難しいものです', 1, 1, 3, 0, 0, 107001, 5, 3391);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('偽物や分身を作るには\\nエネルギーが\\n必要不可欠なのです', 1, 1, 3, 0, 0, 107001, 7, 3393);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇つぶしには\\nちょうどよさそうです\\n…', 1, 1, 3, 0, 0, 107001, 8, 3394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院かぁ…\\n友達の作り方の\\n授業はないかな？', 1, 1, 1, 0, 0, 110701, 1, 3396);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院でぼっちに\\nなったときのために、\\n避難場所を\\n探しておかないと…', 1, 1, 1, 0, 0, 110701, 2, 3397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼっちの私が学院…\\nな、なんだか\\n目まいがしてきました', 1, 1, 1, 0, 0, 110701, 3, 3398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クラスメイトに\\n話しかける練習…\\nむ、難しすぎます…！', 1, 1, 1, 0, 0, 110701, 4, 3399);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('目指せ友達100人…\\n無理かな…10人…\\nや、やっぱり一人！', 1, 1, 1, 0, 0, 110701, 5, 3400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと学院生活が\\n送れるなんて、\\nとっても\\nうれしいです！', 4, 1, 1, 0, 0, 110701, 101, 3401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…\\n学院でも、\\nあなたと一緒に\\n居られてうれしいな♪', 8, 1, 1, 0, 0, 110701, 102, 3402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('が、学院ってあんなに\\n人が居るんですね…\\n友達作りのイメトレを\\nやり直さないと！', 1, 1, 2, 0, 0, 110701, 1, 3403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私にとって\\n部活動とはＢＢ団！\\n今日もたくさん\\n活動しましょうね！', 1, 1, 2, 0, 0, 110701, 2, 3404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休み時間は寝たふり…\\nご飯はおトイレ…\\nぼっち対策は完璧です', 1, 1, 2, 0, 0, 110701, 3, 3405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院で友達を作る\\n勉強は完璧ですよ！\\n購買部でパンを買って\\n渡すんですよね！', 1, 1, 2, 0, 0, 110701, 4, 3406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院でも、\\nBB団の活動を\\nしていきましょうね♪', 4, 1, 2, 0, 0, 110701, 101, 3407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼっちに学院生活は\\n厳しいですね…でも、\\nあなたと一緒なら\\n乗りこえられそうです', 8, 1, 2, 0, 0, 110701, 102, 3408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\nあの…一緒に学院に\\n行ってくれませんか？', 1, 1, 2, 0, 1, 110701, 1, 3409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ですね！\\n言ってくれれば、\\nパンでもお握りでも\\n買ってきますよ！', 1, 1, 2, 0, 2, 110701, 2, 3410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もぼっち…\\nいつか友達と一緒に、\\nパジャマパーティー\\nしたいなぁ…', 1, 1, 2, 0, 3, 110701, 3, 3411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森とは違う\\n心地良さが…このまま\\n眠っちゃいそうです…', 1, 1, 3, 0, 0, 110701, 2, 3413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい…この子を、\\n話す練習の相手役に\\nしてみようかな？', 1, 1, 3, 0, 0, 110701, 3, 3414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\nいつ友達ができても\\nいいように、私の\\n部屋にも置こうかな', 1, 1, 3, 0, 0, 110701, 4, 3415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これは…\\nぼっちで\\n日陰者の私には\\n暖かすぎます！', 1, 1, 3, 0, 0, 110701, 5, 3416);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい…！\\nお弁当にして、学院に\\n持っていけないかな？', 1, 1, 3, 0, 0, 110701, 7, 3418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院の授業に\\nついていくためにも、\\n勉強しておこうかな…', 1, 1, 3, 0, 0, 110701, 8, 3419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんた、何してんの。\\nいいけど、なんでも', 1, 1, 1, 0, 0, 110801, 1, 3421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('邪魔。どいて。\\nいや怒ってないし。\\nコレがフツーだから', 1, 1, 1, 0, 0, 110801, 2, 3422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいけど、\\n散らかしめの部屋だと\\n片付けたくなるよね…', 1, 1, 1, 0, 0, 110801, 3, 3423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇なときは明日の\\nコーデ考えてるよ。\\n考えるのはタダだし', 1, 1, 1, 0, 0, 110801, 4, 3424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昔よくシオリン\\n構いすぎてハツネに\\n文句言われたなァ…', 1, 1, 1, 0, 0, 110801, 5, 3425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんかさ。あんたって\\n謎に女子トモ多いよね\\n…いいけど、べつに', 4, 1, 1, 0, 0, 110801, 101, 3426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ。あのさあ。\\nあんた弁当で好きな\\n具とかってあんの', 8, 1, 1, 0, 0, 110801, 102, 3427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ？\u3000何。なんか用。\\nや、ないならないで\\nいいけど、べつに', 1, 1, 2, 0, 0, 110801, 1, 3428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごめ、ちょっと\\n黙っててくんない。\\n明日の試験ヤバだから', 1, 1, 2, 0, 0, 110801, 2, 3429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歩き方が静か？\\n癖になってるんだよね\\n足音を殺すの', 1, 1, 2, 0, 0, 110801, 3, 3430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの血液型？\\n大雑把のОだけど。\\nなんか文句あんの', 1, 1, 2, 0, 0, 110801, 4, 3431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃんっ！\\nや、だからさ…急に\\n話しかけんなっての', 4, 1, 2, 0, 0, 110801, 101, 3432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な、何…あんまジッと\\n見ないでくんない…\\nなんか、その、ハズい', 8, 1, 2, 0, 0, 110801, 102, 3433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きは得意な方だと\\n思うけど。昔から\\nそれがデフォだったし', 1, 1, 2, 0, 1, 110801, 1, 3434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな時間か…\\n昼ごはん\\nサクッと作っちゃお', 1, 1, 2, 0, 2, 110801, 2, 3435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ？\u3000夜遊び？\\nはッ…そんなん\\n５歳で卒業したっての', 1, 1, 2, 0, 3, 110801, 3, 3436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーヤバじゃんコレ…\\nふかついてる場合\\nじゃないっつーのに…', 1, 1, 3, 0, 0, 110801, 2, 3438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだこれ\\nかわいいかよ', 1, 1, 3, 0, 0, 110801, 3, 3439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふーん。\\nこの匂い…\\nなんかいいじゃん', 1, 1, 3, 0, 0, 110801, 4, 3440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖炉はアドじゃん。\\n煮物、焼き物、蒸し物\\nいろいろ作れそう', 1, 1, 3, 0, 0, 110801, 5, 3441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何コレ\\n食べ物困んないじゃん\\nうちにも一台くんない', 1, 1, 3, 0, 0, 110801, 7, 3443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本かァー…んー\\n学校の勉強だけで\\nいいかなァ…', 1, 1, 3, 0, 0, 110801, 8, 3444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラってなにを\\nしたらいいのかな？', 1, 1, 1, 0, 0, 111101, 1, 3446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カップケーキ\\n上手に作れました\\n食べてくれるかな…', 1, 1, 1, 0, 0, 111101, 2, 3447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人、\\nお菓子くれるかな？\\nくれなかったら…ふふ', 1, 1, 1, 0, 0, 111101, 3, 3448);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オバケ…いないよね？\\n怖くなんてないけど！', 1, 1, 1, 0, 0, 111101, 4, 3449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンは\\n楽しいけどオバケの\\nお祭りなんだよね…', 1, 1, 1, 0, 0, 111101, 5, 3450);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃ～、にゃお～！\\nちゃんと怖いかな？\\n早く帰ってこないかな', 4, 1, 1, 0, 0, 111101, 101, 3451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人のことだから\\nお菓子欲しがるよね…\\n準備はバッチリです♪', 8, 1, 1, 0, 0, 111101, 102, 3452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ。猫さんのお耳\\nよく出来てるでしょ？', 1, 1, 2, 0, 0, 111101, 1, 3453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('触りましたね？\\nイタズラしましたね？\\nへんた～い！', 1, 1, 2, 0, 0, 111101, 2, 3454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フー！\u3000頭を撫でたら\\n怒りますよ！\u3000あれ？\\n猫みたいでした？', 1, 1, 2, 0, 0, 111101, 3, 3455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃっ！\u3000も、もう、\\n脅かさないでください\\n怖くありませんけど！', 1, 1, 2, 0, 0, 111101, 4, 3456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子ですか？\\nありがとうございます\\nハッピーハロウィン♪', 4, 1, 2, 0, 0, 111101, 101, 3457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゴロゴロ…\\nね、猫さんの真似です\\n…似てましたか？', 8, 1, 2, 0, 0, 111101, 102, 3458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ、お菓子作りを\\n始めますよ。下準備は\\n大事ですからね！', 1, 1, 2, 0, 1, 111101, 1, 3459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今、つまみ食い\\nしましたね！？\u3000あっ\\nおやつの時間でしたか', 1, 1, 2, 0, 2, 111101, 2, 3460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ、ハロウィンの\\n始まりです…ふぁ…\\nね、眠くありません！', 1, 1, 2, 0, 3, 111101, 3, 3461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと疲れたかも…\\nパーティの時間まで\\nひと休みしなきゃ', 1, 1, 3, 0, 0, 111101, 2, 3463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私も今、こんな感じ\\nなのかな？\u3000こんなに\\nかわいいといいなぁ', 1, 1, 3, 0, 0, 111101, 3, 3464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘い匂いがいっぱい…\\nお菓子の香りかな？', 1, 1, 3, 0, 0, 111101, 4, 3465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('温かくなると、\\n丸まりたくなって…\\n…猫になっちゃう！？', 1, 1, 3, 0, 0, 111101, 5, 3466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニンジンもこれくらい\\nおいしければ\\nいいのに…', 1, 1, 3, 0, 0, 111101, 7, 3468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンの本、\\nオバケがたくさん\\n載ってて怖いかも…', 1, 1, 3, 0, 0, 111101, 8, 3469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味しそうなお菓子が\\nいっぱい…これなら\\nイタズラされませんね', 1, 1, 3, 0, 0, 111101, 12, 3471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさんいたずら\\nできるから\\nハロウィン大好き！', 1, 1, 1, 0, 0, 111201, 1, 3473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンだから\\nいつもよりすごい\\nいたずらしたいな～！', 1, 1, 1, 0, 0, 111201, 2, 3474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャを綺麗に\\nくり抜いてすごく怖い\\nランタン作っちゃお！', 1, 1, 1, 0, 0, 111201, 3, 3475);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子がたくさんで\\nどれから食べるか\\n迷っちゃうな～！', 1, 1, 1, 0, 0, 111201, 4, 3476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうすればみんなを\\nびっくりさせられる\\nかな～？', 1, 1, 1, 0, 0, 111201, 5, 3477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャ見てたら\\nお腹空いて来たな～\\nお菓子食べちゃお♪', 4, 1, 1, 0, 0, 111201, 101, 3478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんには\\n特別ないたずらを\\n用意してあげるね！', 8, 1, 1, 0, 0, 111201, 102, 3479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャにクラッカー\\nを仕掛けて…わっ！？\\nみ、見ちゃダメだよ！', 1, 1, 2, 0, 0, 111201, 1, 3480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000なぁに？\\nお菓子ほしいの？\\nもう、しかたないな～', 1, 1, 2, 0, 0, 111201, 2, 3481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんの\\n面白い仮装が\\n見てみたいな～！', 1, 1, 2, 0, 0, 111201, 3, 3482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子くれたお礼に\\nとびっきりの\\nいたずらしちゃうね！', 1, 1, 2, 0, 0, 111201, 4, 3483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんは\\nハロウィンでも最高の\\nいたずら相手だよ！', 4, 1, 2, 0, 0, 111201, 101, 3484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんと一緒に\\nハロウィンパレード\\n歩きたいな～！', 8, 1, 2, 0, 0, 111201, 102, 3485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようにいちゃん！\\n仮装して出かける\\n準備しなきゃ！', 1, 1, 2, 0, 1, 111201, 1, 3486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すいたな～\\nもらったお菓子\\n食べちゃだめかな？', 1, 1, 2, 0, 2, 111201, 2, 3487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさんいたずらして\\nもうクタクタ～\\nミソギもう寝るね…', 1, 1, 2, 0, 3, 111201, 3, 3488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やわらか～い…\\nここでひと休みして\\nまたいたずらしよう！', 1, 1, 3, 0, 0, 111201, 2, 3490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいもので\\n油断させてわっ！\\nってするのどうかな？', 1, 1, 3, 0, 0, 111201, 3, 3491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいにお～い！\\nいたずらのアイデアが\\nわいてくるよ！', 1, 1, 3, 0, 0, 111201, 4, 3492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もらったお菓子\\nあったかくしたら\\nおいしいかな～？', 1, 1, 3, 0, 0, 111201, 5, 3493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子ばっかりじゃ\\n飽きちゃうもんね！\\nご飯も食べよう！', 1, 1, 3, 0, 0, 111201, 7, 3495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本のなかに\\nいたずらのヒント\\nないかな～？', 1, 1, 3, 0, 0, 111201, 8, 3496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子がたくさん！\\n一人で食べていいの？\\nやっぱりだめか～！', 1, 1, 3, 0, 0, 111201, 12, 3498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お勉強は順調ですよ\\nやっぱりお兄ちゃんの\\nおかげなんでしょうか', 12, 1, 1, 0, 0, 101101, 103, 3500);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんとの\\n思い出の場所\\nまた行きましょうね', 12, 1, 2, 0, 0, 101101, 103, 3501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ～♪\\nハロウィンの\\nミイラさんうさぎさん\\nぴょんぴょ～ん！', 1, 1, 1, 0, 0, 111301, 1, 3502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('るんたった～\\nハロウィンハロウィン\\n楽しいな～♪', 1, 1, 1, 0, 0, 111301, 2, 3503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンって\\nどんなお菓子を\\nもらえるのかな～？', 1, 1, 1, 0, 0, 111301, 3, 3504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子をもらう\\n練習をしなくちゃ！\\nトリックオア\\nトリート～♪', 1, 1, 1, 0, 0, 111301, 4, 3505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんと\\nハロウィンするの\\nミミ楽しみだな～♪', 1, 1, 1, 0, 0, 111301, 5, 3506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんと\\nいっしょにお菓子を\\n食べたいな～', 4, 1, 1, 0, 0, 111301, 101, 3507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんと\\n毎日ハロウィン\\nできたらいいな～♪', 8, 1, 1, 0, 0, 111301, 102, 3508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ～\\nおにいちゃん！\\nハッピーハロウィン♪', 1, 1, 2, 0, 0, 111301, 1, 3509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんも\\nいっしょに\\nハロウィンパレード\\nしようね～！', 1, 1, 2, 0, 0, 111301, 2, 3510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミイラさんうさぎさん\\nだぞ～…えへへ\\nミミこわかったかな？', 1, 1, 2, 0, 0, 111301, 3, 3511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃん！\\nハロウィンのお菓子\\nおいしいね～♪', 1, 1, 2, 0, 0, 111301, 4, 3512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんと\\nいっしょなら\\nおばけさんも\\nこわくないよ！', 4, 1, 2, 0, 0, 111301, 101, 3513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミね\\nハロウィンも\\nおにいちゃんも\\nだ～いすき♪', 8, 1, 2, 0, 0, 111301, 102, 3514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おひさまさんも\\nハロウィンの\\nおようふく\\n着たいかな～？', 1, 1, 2, 0, 1, 111301, 1, 3515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえねえおにいちゃん\\nお昼ごはんはもらった\\nお菓子でもい～い？', 1, 1, 2, 0, 2, 111301, 2, 3516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだハロウィン…？\\nうぅん…眠くないよぅ\\nでもちょっと…ふぁ～', 1, 1, 2, 0, 3, 111301, 3, 3517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか～♪\\nおばけさんが\\n中にいるのかな～？', 1, 1, 3, 0, 0, 111301, 2, 3519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、かわいい～♪\\nミミといっしょに\\nあそぼ～！', 1, 1, 3, 0, 0, 111301, 3, 3520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ～\\nミミ、このにおい\\nだ～いすき♪', 1, 1, 3, 0, 0, 111301, 4, 3521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいね～♪\\nおばけさんも\\nポカポカしてるかな？', 1, 1, 3, 0, 0, 111301, 5, 3522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい～♪\\nおにいちゃんも\\n食べようよー！', 1, 1, 3, 0, 0, 111301, 7, 3524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本\\nおにいちゃんと\\nいっしょに\\n読みたいな～', 1, 1, 3, 0, 0, 111301, 8, 3525);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハッピーハロウィン♪\\nえへへ、お菓子が\\nいっぱいだね～！', 1, 1, 3, 0, 0, 111301, 12, 3527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ、好きだよ。\\nみんな優しいから…', 1, 1, 1, 0, 0, 111401, 1, 3529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんかさみしいな', 1, 1, 1, 0, 0, 111401, 2, 3530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知らない人怖いな', 1, 1, 1, 0, 0, 111401, 3, 3531);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お部屋おっきいねー', 1, 1, 1, 0, 0, 111401, 4, 3532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナね…\\nお昼寝したいかも', 1, 1, 1, 0, 0, 111401, 5, 3533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいさん！\\n今日は何して遊ぶの？', 4, 1, 1, 0, 0, 111401, 101, 3534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのね、\\nお料理教えてほしい！', 8, 1, 1, 0, 0, 111401, 102, 3535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、おにいさんだ！', 1, 1, 2, 0, 0, 111401, 1, 3536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナは元気だよ！\\nいいこだもん！', 1, 1, 2, 0, 0, 111401, 2, 3537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は何しようかな', 1, 1, 2, 0, 0, 111401, 3, 3538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナと遊んでよ！', 1, 1, 2, 0, 0, 111401, 4, 3539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねーねー、\\nルナとお出かけして！', 4, 1, 2, 0, 0, 111401, 101, 3540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいさんと、\\n遊びたいなー！', 8, 1, 2, 0, 0, 111401, 102, 3541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ！\\nなんかまぶしいね！', 1, 1, 2, 0, 1, 111401, 1, 3542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナ、お腹空いたな', 1, 1, 2, 0, 2, 111401, 2, 3543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこに行こうかな？', 1, 1, 2, 0, 3, 111401, 3, 3544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナ、これ好きだな', 1, 1, 3, 0, 0, 111401, 2, 3546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい！\u3000好き！', 1, 1, 3, 0, 0, 111401, 3, 3547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんかいい匂い！', 1, 1, 3, 0, 0, 111401, 4, 3548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいねー', 1, 1, 3, 0, 0, 111401, 5, 3549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ\\nおいしいね', 1, 1, 3, 0, 0, 111401, 7, 3551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ルナ、\\n眠くなっちゃう…', 1, 1, 3, 0, 0, 111401, 8, 3552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ。あの人と\\nランドソルでデート\\nできたらうれしいな♪', 12, 1, 1, 0, 0, 105201, 103, 3554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたとなら\\nどんなことだって\\nできる気がするわ♪', 12, 1, 2, 0, 0, 105201, 103, 3555);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーあ、退屈だな\\nカレでも探しに\\nいこうかな', 1, 1, 1, 0, 0, 106501, 1, 3556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この前のケンカは\\n最高に燃えたなぁ\\n…拳が疼いてきたぜ', 1, 1, 1, 0, 0, 106501, 2, 3557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一体、この世界は\\nどうなっちまったって\\nいうんだ…？', 1, 1, 1, 0, 0, 106501, 3, 3558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう仕事の時間か\\nボスも人使いが荒いぜ\\n…ま、いいけどさ！', 1, 1, 1, 0, 0, 106501, 4, 3559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オレたち以外に\\nドラゴン族はあと何人\\nいるんだろうな…', 1, 1, 1, 0, 0, 106501, 5, 3560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カレの真剣な顔\\n面白かったな\\nまた遊びたいぜ', 4, 1, 1, 0, 0, 106501, 101, 3561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしてカレがそばに\\nいると、腹の底から\\n力が湧いてくるんだ？', 8, 1, 1, 0, 0, 106501, 102, 3562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よっす！\\nなんかオイシイ話でも\\nあったりしない？', 1, 1, 2, 0, 0, 106501, 1, 3563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なあ、オレと遊ぼうぜ\\n心配すんなよ。危ない\\nことはよしとくからさ', 1, 1, 2, 0, 0, 106501, 2, 3564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうした。オレに\\nケンカ売ろうってか？\\n…ははは、冗談だよ！', 1, 1, 2, 0, 0, 106501, 3, 3565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうど退屈してた\\nところだ、特訓に\\n付き合ってくれよ', 1, 1, 2, 0, 0, 106501, 4, 3566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ったくよぉ…\\nオレがかわいいなんて\\n冗談はもうよせよ？', 4, 1, 2, 0, 0, 106501, 101, 3567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の仕事も一緒に\\n来るだろ？\u3000断っても\\n連れて行くけどな！', 8, 1, 2, 0, 0, 106501, 102, 3568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\u3000今日の\\n予定はまずケンカして\\nで、その後もケンカだ', 1, 1, 2, 0, 1, 106501, 1, 3569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よっす！\\n腹ごしらえが済んだら\\nオレと遊ぼうぜ！', 1, 1, 2, 0, 2, 106501, 2, 3570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜は危ないから\\nあんま出歩くな？\\n…だから面白えんだろ', 1, 1, 2, 0, 3, 106501, 3, 3571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次のケンカに備えて\\n今は休んでおくか…\\n全力で暴れたいからな', 1, 1, 3, 0, 0, 106501, 2, 3573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボスの飼ってる\\nラーゴが、中に\\n入ってるんじゃ？', 1, 1, 3, 0, 0, 106501, 3, 3574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、たぎる匂いが\\nする…ひと暴れ\\nしたくなってきた！', 1, 1, 3, 0, 0, 106501, 4, 3575);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおぉ…\\nオレの拳もなんだか\\n熱くなってきたぜ…！', 1, 1, 3, 0, 0, 106501, 5, 3576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつでも全力で\\nケンカするために\\n力を蓄えないとな', 1, 1, 3, 0, 0, 106501, 7, 3578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりな…オレが\\n知ってる地図とは\\nまるで違ってやがる', 1, 1, 3, 0, 0, 106501, 8, 3579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁプレゼントで\\n埋め尽くしてやろう！\\n大いに喜ぶがいいよ！', 1, 1, 1, 0, 0, 111501, 1, 3581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス☆\\n聖夜の宴だ\\n派手に楽しむとしよう', 1, 1, 1, 0, 0, 111501, 2, 3582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('煙突から入る？\\nいいや、ワタシは\\nいつでも正面からさ♪', 1, 1, 1, 0, 0, 111501, 3, 3583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サンタクロースの\\nお出ましだ！\\n歓迎するがいいよ♪', 1, 1, 1, 0, 0, 111501, 4, 3584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('飾り付けが足りん！\\nワタシが演出して\\nやろうじゃないか！', 1, 1, 1, 0, 0, 111501, 5, 3585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人の喜ぶ顔を見るのも\\n悪くはないな…おっと\\nワタシらしくないな☆', 4, 1, 1, 0, 0, 111501, 101, 3586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントはまだか？\\nワタシを喜ばせたら\\nお返しは弾むぞ♪', 8, 1, 1, 0, 0, 111501, 102, 3587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシを呼んだか？\\n退屈な要件だったら\\n覚悟しておくことだ', 1, 1, 2, 0, 0, 111501, 1, 3588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだ？\\nワタシへの挑戦か？\\nよし、受けた♪', 1, 1, 2, 0, 0, 111501, 2, 3589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっと、当たらんよ\\nワタシの乱数聖域は\\n絶対だからな…♪', 1, 1, 2, 0, 0, 111501, 3, 3590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだ、オマエも\\n暇なのか？\\n奇遇だな、ワタシもさ', 1, 1, 2, 0, 0, 111501, 4, 3591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにか愉しいことでも\\nしようじゃないか\\nさぁ、何をする？', 4, 1, 2, 0, 0, 111501, 101, 3592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうもワタシに\\n気安く触れるのは\\nオマエくらいだよ…♪', 8, 1, 2, 0, 0, 111501, 102, 3593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝だろうと関係ない！\\nさぁ愉しく苛烈に\\n騒ごうじゃないか♪', 1, 1, 2, 0, 1, 111501, 1, 3594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('調子の出てくる時間だ\\nしっかりワタシを\\n愉しませてくれよ♪', 1, 1, 2, 0, 2, 111501, 2, 3595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眠いなどと言わせんぞ\\nまだまだ一日は\\n終わらんからな！', 1, 1, 2, 0, 3, 111501, 3, 3596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい具合じゃないか\\nこのまま持って帰って\\nしまおうか…♪', 1, 1, 3, 0, 0, 111501, 2, 3598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなか愛らしい\\n造形をしているな？\\nワタシには負けるがな', 1, 1, 3, 0, 0, 111501, 3, 3599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほう、悪くない香りだ\\n戦いの匂いをうまく\\n隠してくれそうだ…♪', 1, 1, 3, 0, 0, 111501, 4, 3600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体が温まってくると\\nひと暴れしたくなるな', 1, 1, 3, 0, 0, 111501, 5, 3601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシの舌は厳しいぞ\\n…ふーむ、なるほど\\n認めざるをえんな', 1, 1, 3, 0, 0, 111501, 7, 3603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスティーナさんは\\n知識の収集も\\n欠かさないんだよ', 1, 1, 3, 0, 0, 111501, 8, 3604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは驚いたな\\nだがもっと、もっとだ\\nワタシを退屈させるな', 1, 1, 3, 0, 0, 111501, 14, 3606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな戯れだって\\n軽くこなしてしまう\\nクリスティーナさんさ', 1, 1, 3, 0, 0, 111501, 15, 3607);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\nさあ、パーティーを\\n盛り上げるよ！', 1, 1, 1, 0, 0, 111601, 1, 3608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('衣装一つで全然\\n気分が違うね！\\n最高のクリスマスに\\nなりそうだよ！', 1, 1, 1, 0, 0, 111601, 2, 3609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ツリーのてっぺんの\\n星って、なんだか\\n欲しくなるんだよね', 1, 1, 1, 0, 0, 111601, 3, 3610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('めいっぱい\\nクリスマスを楽しむよ\\n遊びだって本気\\nなんだからね！', 1, 1, 1, 0, 0, 111601, 4, 3611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('赤、白、緑、金\\nクリスマスカラー\\nってお洒落だよね', 1, 1, 1, 0, 0, 111601, 5, 3612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('雪、降らないかな？\\nホワイトクリスマス\\nってちょっと\\n憧れるなぁ', 4, 1, 1, 0, 0, 111601, 101, 3613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと過ごすこの\\n楽しい時間がずーっと\\n続けばいいのにな', 8, 1, 1, 0, 0, 111601, 102, 3614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスライブ\\nチケット用意するから\\n絶対来てよね！', 1, 1, 2, 0, 0, 111601, 1, 3615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カンパーイ！\\nジュースだけど\\nちょっと大人の\\n気分だね', 1, 1, 2, 0, 0, 111601, 2, 3616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマス衣装どう？\\nかわいいでしょ\\nあっ、どこ見てるの！', 1, 1, 2, 0, 0, 111601, 3, 3617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、後で街に\\n行こうよ\\n大きなツリーを\\n一緒に見たいんだ♪', 1, 1, 2, 0, 0, 111601, 4, 3618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、ダンスの練習に\\n付き合ってくれない？\\n大丈夫、手取り足取り\\n教えてあげるから♪', 4, 1, 2, 0, 0, 111601, 101, 3619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年のクリスマスも\\n隣にキミが\\nいてくれたら\\nうれしいのにな', 8, 1, 2, 0, 0, 111601, 102, 3620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスって朝から\\nドキドキしちゃうね\\nなんだか子どもみたい', 1, 1, 2, 0, 1, 111601, 1, 3621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パーティーの準備も\\n大分進んだね\\n一息ついて\\nランチにしよっか', 1, 1, 2, 0, 2, 111601, 2, 3622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('静かな夜だね\\n心臓の音まで\\n聞こえちゃいそう…', 1, 1, 2, 0, 3, 111601, 3, 3623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ～、この絶妙な\\n柔らかさ…\\nいい仕事してるなぁ…', 1, 1, 3, 0, 0, 111601, 2, 3625);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドル顔負けの\\nかわいさ、ズルい！\\nでもかわいい！', 1, 1, 3, 0, 0, 111601, 3, 3626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、落ち着くなぁ\\n今日はゆっくり\\n眠れそうだよ', 1, 1, 3, 0, 0, 111601, 4, 3627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬくぬく～\\nどうしよう、ここから\\n動きたくないなぁ', 1, 1, 3, 0, 0, 111601, 5, 3628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ダンスの練習もしたし\\nちょっとくらいなら\\nいいよね！', 1, 1, 3, 0, 0, 111601, 7, 3630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルといえど\\nかわいいだけじゃダメ\\n知識も必要だよね', 1, 1, 3, 0, 0, 111601, 8, 3631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('面白ーい！\\nこの演出、ライブでも\\nできないかな？', 1, 1, 3, 0, 0, 111601, 14, 3633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もふもふ～♪\\n寒い日には最高の\\n抱き心地だね！', 1, 1, 3, 0, 0, 111601, 15, 3634);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼ともっとお話し\\nしたいな…もう少し\\n補習を増やそうかしら', 12, 1, 1, 0, 0, 101801, 103, 3635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君のこともっともっと\\n教えて欲しいな。私に\\n補習授業してくれる？', 12, 1, 2, 0, 0, 101801, 103, 3636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿ならあやつも\\n子ども扱いできまい！\\n…じゃがなぜか、少し\\n物足りないような…', 1, 1, 1, 0, 0, 111701, 1, 3637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時間もあるし、\\n聖夜の宴の\\n準備をするかのう♪', 1, 1, 1, 0, 0, 111701, 2, 3638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…わらわの知る聖夜と\\n随分違うが、宴は宴\\n楽しませて\\nもらおうかのう♪', 1, 1, 1, 0, 0, 111701, 3, 3639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人の姿で\\nできること…ふむ\\n少しあやつを\\nからかってやるか♪', 1, 1, 1, 0, 0, 111701, 4, 3640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…クリスマスは\\n恋人たちの夜！？\\nち、近頃の若いもんは\\n破廉恥なのじゃ！', 1, 1, 1, 0, 0, 111701, 5, 3641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あやつがおらんと、\\n宴も物足りぬな\\n…馬鹿者が\\n早く帰ってこい…', 4, 1, 1, 0, 0, 111701, 101, 3642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰も見ておらぬな…？\\n…よし、あやつへの\\nプレゼントを\\n準備するとしようか！', 8, 1, 1, 0, 0, 111701, 102, 3643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスの\\nチキンにケーキ…\\nべ、別に楽しみになど\\nしておらぬぞ！', 1, 1, 2, 0, 0, 111701, 1, 3644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿では、わらわの\\n頭をなでるのは\\n難しかろう…べ、\\n別に残念ではないわ！', 1, 1, 2, 0, 0, 111701, 2, 3645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリー\\nクリスマスじゃ！\\nさあ、わらわのために\\n宴の準備をするのじゃ', 1, 1, 2, 0, 0, 111701, 3, 3646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなにこの衣装が\\n気になるのか？\\n…だったら、直に\\n触ってみるがよい♪', 1, 1, 2, 0, 0, 111701, 4, 3647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもと逆に、お主を\\n子ども扱いしてやるか\\nほれ、膝枕をしてやる\\nからそばに来い♪', 4, 1, 2, 0, 0, 111701, 101, 3648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…せ、聖夜の予定は\\n空けておくのじゃぞ？\\nなんでって…\\nな、なんでもじゃ！', 8, 1, 2, 0, 0, 111701, 102, 3649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう朝か…聖夜の宴が\\n楽しみで…ではなく！\\n準備のせいで、\\nあまり眠れんかったぞ', 1, 1, 2, 0, 1, 111701, 1, 3650);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ずっと雪が\\n降っておれば、\\n陽光が強いこの時間も\\n怯えずにすむのにのう', 1, 1, 2, 0, 2, 111701, 2, 3651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時は来た…\\nさあ眷属よ！\\nわらわと共に、\\n聖夜の宴を楽しもうぞ', 1, 1, 2, 0, 3, 111701, 3, 3652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い椅子ではないか\\nここから聖夜の宴を\\n眺めるのもよいかもな', 1, 1, 3, 0, 0, 111701, 2, 3654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわい…こほん\\nなかなか良い\\nデザインをしておるな', 1, 1, 3, 0, 0, 111701, 3, 3655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、良い香りじゃ\\n聖夜の宴でも\\nこれを使うとしよう', 1, 1, 3, 0, 0, 111701, 4, 3656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これが癒し…はっ！\\nあやうく浄化される\\nところであった…', 1, 1, 3, 0, 0, 111701, 5, 3657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニ、ニンニクは\\n入っておらぬよな？\\n…うむ、美味じゃ♪', 1, 1, 3, 0, 0, 111701, 7, 3659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聖夜は恋人たちの夜…\\n…き、気になるわけ\\nではないが、\\n少し調べてみるか', 1, 1, 3, 0, 0, 111701, 8, 3660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほう…これは面白い\\n魔法の使い方じゃな\\nまるで本物の\\n演劇のようじゃ', 1, 1, 3, 0, 0, 111701, 14, 3662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、この程度の\\nかわいさに誘惑される\\nわらわでは…\\nふわもこなのじゃ～♪', 1, 1, 3, 0, 0, 111701, 15, 3663);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせち料理も\\n魔物尽くしだったり\\nしないわよね！', 1, 1, 1, 0, 0, 112001, 1, 3664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初詣で何をお祈り\\nしようかしら…\\n定番でいいわよね？', 1, 1, 1, 0, 0, 112001, 2, 3665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初日の出って\\n特別な感じがして\\nいいわよね…', 1, 1, 1, 0, 0, 112001, 3, 3666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒い中並んで飲む\\n甘酒って不思議なほど\\nおいしいわよね', 1, 1, 1, 0, 0, 112001, 4, 3667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('羽根つきで勝負…\\nあいつにだったら\\n勝てるかしら？', 1, 1, 1, 0, 0, 112001, 5, 3668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年賀状になんて書こう\\n…いろいろと\\n恥ずかしくなるのよね', 4, 1, 1, 0, 0, 112001, 101, 3669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年もあいつと\\n居られること…\\n結構うれしいわ', 8, 1, 1, 0, 0, 112001, 102, 3670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何じっと\\n見てんのよ？\\nお年玉はあげないわよ', 1, 1, 2, 0, 0, 112001, 1, 3671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせち料理一緒に\\n食べる？\\n結構おいしいわよ', 1, 1, 2, 0, 0, 112001, 2, 3672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('羽根つきで負けたら\\n顔に墨塗られるのよ\\n覚悟しなさい！', 1, 1, 2, 0, 0, 112001, 3, 3673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('門松飾るから\\nちょっと手伝って\\nくれる？', 1, 1, 2, 0, 0, 112001, 4, 3674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと一緒に\\n初詣行くのも悪くない\\n…かも', 4, 1, 2, 0, 0, 112001, 101, 3675);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初詣で何をお祈り\\nしたか？\u3000うっさい！\\n内緒よ！内緒！', 8, 1, 2, 0, 0, 112001, 102, 3676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう朝なの…\\n正月くらいゆっくり\\n寝ていたいわよね…', 1, 1, 2, 0, 1, 112001, 1, 3677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせちに飽きたら\\n次は何を食べよう\\nかしら…', 1, 1, 2, 0, 2, 112001, 2, 3678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝ましょ\\nいい初夢が見られると\\nいいわね', 1, 1, 2, 0, 3, 112001, 3, 3679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好でいるのも\\nなかなか疲れるわね\\n休憩～', 1, 1, 3, 0, 0, 112001, 2, 3681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…う～ん\\n鏡餅も顔を描けば\\nかわいくなるかしら？', 1, 1, 3, 0, 0, 112001, 3, 3682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂いね\\n落ち着いて\\n眠れそう…', 1, 1, 3, 0, 0, 112001, 4, 3683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでお餅焼いたら\\n一段とおいしく\\nなりそうね', 1, 1, 3, 0, 0, 112001, 5, 3684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月に食べるものは\\nなんでもおいしく\\n感じちゃうわね！', 1, 1, 3, 0, 0, 112001, 7, 3686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔物を使わない\\nおせちを\\n調べておかなきゃ…', 1, 1, 3, 0, 0, 112001, 8, 3687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新年を気持ちよく\\n過ごせるように\\nお掃除がんばります！', 1, 1, 1, 0, 0, 112101, 1, 3689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('神殿に通っていたら\\nいつの間にか足腰が\\n鍛えられたような…', 1, 1, 1, 0, 0, 112101, 2, 3690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('神殿付近は屋台も\\nあるので、良い香りが\\n漂ってくるんですよ～', 1, 1, 1, 0, 0, 112101, 3, 3691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせちを作れるように\\nなれば、子どもたちも\\n喜んでくれるかな…？', 1, 1, 1, 0, 0, 112101, 4, 3692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コホォォォォォ…！\\nふぅ、深呼吸すると\\n落ち着きますね♪', 1, 1, 1, 0, 0, 112101, 5, 3693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お仕事以外の時も\\nあなたと…い、いえ！\\nなんでもないです！', 4, 1, 1, 0, 0, 112101, 101, 3694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと一緒だと\\nなんだかポカポカ\\nしてくるんです…', 8, 1, 1, 0, 0, 112101, 102, 3695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好をしていると\\nなんだか神殿にいる\\n気分になりますね', 1, 1, 2, 0, 0, 112101, 1, 3696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そういえば神殿で\\n甘酒をもらったんです\\nあなたも飲みますか？', 1, 1, 2, 0, 0, 112101, 2, 3697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、髪飾りが\\nズレちゃってました！\\nいけないいけない…', 1, 1, 2, 0, 0, 112101, 3, 3698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃわっ！？\\nく、くすぐったり\\nしないでください～', 1, 1, 2, 0, 0, 112101, 4, 3699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そ、そんなに\\n見つめられると\\nて、照れちゃいます…', 4, 1, 2, 0, 0, 112101, 101, 3700);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、私が考えた\\n運気上昇のおまじない\\nかけてあげますね♪', 8, 1, 2, 0, 0, 112101, 102, 3701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n神殿のお手伝いに行く\\n準備もしなきゃですね', 1, 1, 2, 0, 1, 112101, 1, 3702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼になりましたし\\nご飯は私が作…\\nえっ、ダメですか！？', 1, 1, 2, 0, 2, 112101, 2, 3703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日も早いですし\\nそろそろ寝る支度を…\\nふわぁ…', 1, 1, 2, 0, 3, 112101, 3, 3704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お掃除も終わったので\\n少し休憩を…ふわぁ…\\n急に眠気が…', 1, 1, 3, 0, 0, 112101, 2, 3706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新年を気持ちよく\\n過ごせるようこの子も\\nきれいにしましょう♪', 1, 1, 3, 0, 0, 112101, 3, 3707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('神殿のお香のような\\n香りだと落ち着いて\\n過ごせそうですよね', 1, 1, 3, 0, 0, 112101, 4, 3708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかですね～…\\n甘酒も飲んで体の\\n芯から温めましょう', 1, 1, 3, 0, 0, 112101, 5, 3709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年こそ\\n料理も上手に…\\nもぐもぐもぐもぐ…', 1, 1, 3, 0, 0, 112101, 7, 3711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('失敗続きだと\\n逆に運が良くなる…\\nほ、本当ですかぁ…？', 1, 1, 3, 0, 0, 112101, 8, 3712);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミにならもう\\nどんな私を見られても\\n大丈夫かな…♪', 12, 1, 1, 0, 0, 103401, 103, 3714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なになにどしたのぉ？\\nお姉さんが撫でたげる\\nこっちにきなさぁい♪', 12, 1, 2, 0, 0, 103401, 103, 3715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたくしの舞を\\n主さまは喜んで\\nくださるでしょうか…', 1, 1, 1, 0, 0, 111901, 1, 3716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年を越したあとに\\n食べるおそばも\\nおいしいです', 1, 1, 1, 0, 0, 111901, 2, 3717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘酒を飲むと\\n心まで温まる\\n気がいたします', 1, 1, 1, 0, 0, 111901, 3, 3718);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまのために\\n真心を込めたおせちを\\nご用意しなくては', 1, 1, 1, 0, 0, 111901, 4, 3719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おみくじを引くのは\\nドキドキしつつも\\n楽しいものです', 1, 1, 1, 0, 0, 111901, 5, 3720);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまの温もりは\\n心まで温めてくれる\\nようです', 4, 1, 1, 0, 0, 111901, 101, 3721);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うまくできなくとも\\n心を込めて精いっぱい\\n舞いましょう', 8, 1, 1, 0, 0, 111901, 102, 3722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま、この晴れ着は\\n似合っている\\nでしょうか？', 1, 1, 2, 0, 0, 111901, 1, 3723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お餅はゆっくりと\\n召し上がって\\nくださいまし', 1, 1, 2, 0, 0, 111901, 2, 3724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまのお顔の\\n福笑いなら、完璧に\\nできる気がいたします', 1, 1, 2, 0, 0, 111901, 3, 3725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまはどのような\\n初夢をご覧になった\\nのでしょう？', 1, 1, 2, 0, 0, 111901, 4, 3726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘酒の飲み過ぎは\\nいけませんよ？\\nめっ、でございます', 4, 1, 2, 0, 0, 111901, 101, 3727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('二人羽織とは\\nあんなにも暖かい\\nものなのですね…', 8, 1, 2, 0, 0, 111901, 102, 3728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n寒い季節の朝日は\\nとても美しいですね', 1, 1, 2, 0, 1, 111901, 1, 3729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしくとも\\n食べ過ぎは正月太りの\\nもとでございます', 1, 1, 2, 0, 2, 111901, 2, 3730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい夢が見られるよう\\n暖かくして\\n眠るといたしましょう', 1, 1, 2, 0, 3, 111901, 3, 3731);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか…\\nこのまま\\n寝てしまいそうです', 1, 1, 3, 0, 0, 111901, 2, 3733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと一緒に\\nお正月遊びを\\n楽しんでみたいです', 1, 1, 3, 0, 0, 111901, 3, 3734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('神殿の独特な香りを\\nおうちに持ち込むのは\\nどうでしょうか', 1, 1, 3, 0, 0, 111901, 4, 3735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風邪をひきませんよう\\n暖かくいたしましょう', 1, 1, 3, 0, 0, 111901, 5, 3736);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ過ぎは\\n正月太りの\\nもとだというのに…', 1, 1, 3, 0, 0, 111901, 7, 3738);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまのために\\n参拝の作法を\\n予習しておきましょう', 1, 1, 3, 0, 0, 111901, 8, 3739);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…この杖、変身前には\\n無いパーツがあるけど\\nこれはどこから…うん\\n考えないようにしよう', 1, 1, 1, 0, 0, 112201, 1, 3741);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フ、フリフリの\\nかわいい衣装…はっ！\\n素に戻ってはダメだ！', 1, 1, 1, 0, 0, 112201, 2, 3742);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法探偵\\nミスティ★カスミ！\\n魔法の力で捜査開始！\\n…練習終わりっと', 1, 1, 1, 0, 0, 112201, 3, 3743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪しい視線を感じる…\\nまさか、近くに\\n闇の力を持つ人が！？', 1, 1, 1, 0, 0, 112201, 4, 3744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時間もあるし、\\n魔法少女の修行を…\\nじゃ、じゃなくて！\\n探偵の仕事をしよう！', 1, 1, 1, 0, 0, 112201, 5, 3745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんとずっと\\n一緒に居られるし、\\n魔法少女も\\n案外悪くないかも♪', 4, 1, 1, 0, 0, 112201, 101, 3746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の訓練のため\\n助手くんの所に行こう\\nかな…あ、あくまで\\n訓練のためにね！', 8, 1, 1, 0, 0, 112201, 102, 3747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…髪型が急に\\n変わって驚いた？\\nき、気になるなら…\\n少し触ってみるかい？', 1, 1, 2, 0, 0, 112201, 1, 3748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんは魔法少女に\\nなりたいのかい？\\nその場合は魔法騎士…\\nいや、魔法助手とか？', 1, 1, 2, 0, 0, 112201, 2, 3749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭に浮かぶ呪文…\\n強制変身…助手くん\\n魔法少女とは\\n呪いか何かなのかな？', 1, 1, 2, 0, 0, 112201, 3, 3750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あまり触らないで\\nくれ…魔法少女になる\\nと感覚が鋭くなって、\\n耳も敏感に…ひゃう！', 1, 1, 2, 0, 0, 112201, 4, 3751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('や、やっぱりこの\\n格好は変かな…え、\\nかわいい？\u3000じゃあ…\\nいや、でも、う～ん', 4, 1, 2, 0, 0, 112201, 101, 3752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…この変身は助手くん\\nのせいでもあるんだよ\\nだから…せ、責任を\\n取ってもらうからね！', 8, 1, 2, 0, 0, 112201, 102, 3753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう助手くん\\nさあ、そろそろ\\n街のパトロールに\\n行こうじゃないか！', 1, 1, 2, 0, 1, 112201, 1, 3754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうお昼…助手くん、\\nそろそろ本業に戻ろう\\n…その顔は何かな？\\n私の本業は探偵だぞ！', 1, 1, 2, 0, 2, 112201, 2, 3755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜だけど、私は\\nもう少し仕事をするよ\\n魔法少女の強い体は\\nこんなときに便利だね', 1, 1, 2, 0, 3, 112201, 3, 3756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい…\\nこの癒しを、魔法と\\n論理の二つの観点から\\n解明したいね…', 1, 1, 3, 0, 0, 112201, 2, 3758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ダ、ダメ！！\\nここで感情のままに\\n飛びついたら、私の\\nイメージがぁ～！', 1, 1, 3, 0, 0, 112201, 3, 3759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心が安らぐ香りだね…\\n…今なら、魔法少女も\\nすんなりと受け入れ…\\nてはダメだっ！', 1, 1, 3, 0, 0, 112201, 4, 3760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\n魔法少女だろうと\\n休息は必要だし、少し\\n休んでいこうかな', 1, 1, 3, 0, 0, 112201, 5, 3761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女も探偵も、\\nやっぱり体が資本！\\n食べられるときに\\n食べておかないとね♪', 1, 1, 3, 0, 0, 112201, 7, 3763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…魔法少女\\nセリイちゃんの本は\\nどこにあるのかな？', 1, 1, 3, 0, 0, 112201, 8, 3764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女かぁ…\\nせっかくだし思う存分\\n体を動かしてみたいな', 1, 1, 1, 0, 0, 112301, 1, 3766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃん…\\nこの格好を見て\\n私って気づくかな？', 1, 1, 1, 0, 0, 112301, 2, 3767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…\\n今日はなんだか\\n調子がいいかも', 1, 1, 1, 0, 0, 112301, 3, 3768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法は便利だけど\\nあまり頼りすぎちゃ\\nダメだよね', 1, 1, 1, 0, 0, 112301, 4, 3769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっき街で小さな子に\\n声かけられちゃった\\n照れるけどうれしいな', 1, 1, 1, 0, 0, 112301, 5, 3770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人がいると\\nなんだかホッとする\\n不思議…', 4, 1, 1, 0, 0, 112301, 101, 3771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女になっても\\nあの人への気持ちは\\nずっと同じ…', 8, 1, 1, 0, 0, 112301, 102, 3772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の私…ですか？\\nはいとっても元気です\\n…あなたのおかげかも', 1, 1, 2, 0, 0, 112301, 1, 3773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よかったら魔法の\\n練習に付き合って\\nくれませんか？', 1, 1, 2, 0, 0, 112301, 2, 3774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…\\nこの格好どうですか？\\n似合ってると…いいな', 1, 1, 2, 0, 0, 112301, 3, 3775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…な、なんですか？\\nあまり見られると\\n恥ずかしいです…', 1, 1, 2, 0, 0, 112301, 4, 3776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私、あなたのそばに\\nいられたら、それで…', 4, 1, 2, 0, 0, 112301, 101, 3777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('想い人と結ばれる\\n魔法は…ひゃっ！？\\n今の聞いてましたか？', 8, 1, 2, 0, 0, 112301, 102, 3778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n今日も街の平和の\\nために頑張らなきゃ', 1, 1, 2, 0, 1, 112301, 1, 3779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹すきましたね。\\nあの…一緒にランチは\\nいかがですか？', 1, 1, 2, 0, 2, 112301, 2, 3780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、もうこんな時間…\\nふふ、まだこんなに\\n体力が余ってるのに', 1, 1, 2, 0, 3, 112301, 3, 3781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい…\\nこの気持ち良さは\\nどんな魔法も勝てない', 1, 1, 3, 0, 0, 112301, 2, 3783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何これ、かわいい…\\nお姉ちゃんにも\\n見せてあげたいな', 1, 1, 3, 0, 0, 112301, 3, 3784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～、いい香り\\n…これ、魔法で\\n出せたりしないかな？', 1, 1, 3, 0, 0, 112301, 4, 3785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い\\nえへへ…なんだか\\nお姉ちゃんみたい', 1, 1, 3, 0, 0, 112301, 5, 3786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいなぁ、これ\\n魔法少女になってから\\n食欲旺盛かも…', 1, 1, 3, 0, 0, 112301, 7, 3788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…\\n魔法少女になっても\\n読書はやめられないな', 1, 1, 3, 0, 0, 112301, 8, 3789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みらくるまほりん\\nくるりんぱ～♪\\n王子はんのために\\n花嫁修業や～♪', 12, 1, 1, 0, 0, 101001, 103, 3791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あのな王子はん\\nできたらその…\\nお姫さまだっこを\\nお願いしてもええ…？', 12, 1, 2, 0, 0, 101001, 103, 3792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりわたしたちの\\nギルドハウスの\\n居心地は最高ですね☆', 1, 1, 1, 0, 0, 180401, 1, 3793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王宮じゃできないこと\\nやっちゃいましょう♪\\n例えば、えっと～…', 1, 1, 1, 0, 0, 180401, 2, 3794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、隠しておいた\\nおやつがありました！\\nまだ食べられますね☆', 1, 1, 1, 0, 0, 180401, 3, 3795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごはんはみんなで\\n楽しく食べましょう！\\nそれが一番の\\n調味料です♪', 1, 1, 1, 0, 0, 180401, 4, 3796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりここが、\\nわたしの帰る場所です\\n…ただいま☆', 1, 1, 1, 0, 0, 180401, 5, 3797);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか物足りません\\nきっと、あの人が隣に\\nいないからですね…', 4, 1, 1, 0, 0, 180401, 101, 3798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこを見ても、大切な\\n思い出がたくさん\\n詰まっていますね♪', 8, 1, 1, 0, 0, 180401, 102, 3799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('無礼者～、なんて\\n冗談です♪\u3000どんどん\\n触っちゃってください', 1, 1, 2, 0, 0, 180401, 1, 3800);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷにぷにでしょう～？\\nい～っぱい食べるのが\\nぷにぷにの秘訣です！', 1, 1, 2, 0, 0, 180401, 2, 3801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('握手したいんですか？\\nはい、にぎにぎ～！\\nもう離しませんよ♪', 1, 1, 2, 0, 0, 180401, 3, 3802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしましたか？\\n退屈してるんでしたら\\nお散歩に行きましょう', 1, 1, 2, 0, 0, 180401, 4, 3803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごはん王子♪\\nわたしは王女ですから\\nこれでピッタリですね', 4, 1, 2, 0, 0, 180401, 101, 3804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大好きです～\\n愛してます～\\n…ほんと、ですよ♪', 8, 1, 2, 0, 0, 180401, 102, 3805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ごはんは大事です！\\n山盛りごはんを食べて\\n元気いっぱいですよ☆', 1, 1, 2, 0, 1, 180401, 1, 3806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹ぺこぺこになる\\n時間ですね～！\\nごはん特盛、一つ！', 1, 1, 2, 0, 2, 180401, 2, 3807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹いっぱい、今日は\\nよく眠れそうですね♪\\n明日もおいしい一日を', 1, 1, 2, 0, 3, 180401, 3, 3808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩休憩～♪\\nお腹を休めて、次の\\nごはんに挑みます…☆', 1, 1, 3, 0, 0, 180401, 2, 3810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいらしい\\nぬいぐるみですね～\\nキャルちゃんみたい☆', 1, 1, 3, 0, 0, 180401, 3, 3811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すんすん…この匂い\\n食欲増進の効果が\\nありそうですね…？', 1, 1, 3, 0, 0, 180401, 4, 3812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体温が上がってくると\\n眠くなっちゃいます…\\nほわぁ～', 1, 1, 3, 0, 0, 180401, 5, 3813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐもぐもぐもぐ\\nむぐむぐむぐむぐむぐ\\nはぐはぐはぐはぐはぐ', 1, 1, 3, 0, 0, 180401, 7, 3815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('教養を身に着けるには\\n読書が一番です！\\nえっと次のレシピは～', 1, 1, 3, 0, 0, 180401, 8, 3816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルらしくなる\\nコツって、何か\\nあるんでしょうか？', 1, 1, 1, 0, 0, 112401, 1, 3818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('色んな人と話すのが\\n好きなんです。つい\\n長くなっちゃって…', 1, 1, 1, 0, 0, 112401, 2, 3819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルを目指すって\\n決めてから、毎日が\\nワクワクなんです♪', 1, 1, 1, 0, 0, 112401, 3, 3820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんとストレッチ\\nしておかなくっちゃ\\nよいしょ、よいしょ…', 1, 1, 1, 0, 0, 112401, 4, 3821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リンちゃんミオちゃん\\n二人に負けないように\\n私、頑張ります！', 1, 1, 1, 0, 0, 112401, 5, 3822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の笑顔は素敵だって\\n誰かに褒められた…\\nそんな気がするんです', 4, 1, 1, 0, 0, 112401, 101, 3823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちを支えてくれる\\n誰かが、ずっと一緒に\\nいてくれたような…', 8, 1, 1, 0, 0, 112401, 102, 3824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしましたか？\\n何か困ってるのなら\\nお手伝いしますよ！', 1, 1, 2, 0, 0, 112401, 1, 3825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みなさん個性的で\\n普通じゃない人ばかり\\nいるような気が…', 1, 1, 2, 0, 0, 112401, 2, 3826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はポカポカした\\nいい天気ですね～\\nお散歩日和です！', 1, 1, 2, 0, 0, 112401, 3, 3827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今、ミルクティーを\\n淹れてたんです♪\\nあなたも飲みますか？', 1, 1, 2, 0, 0, 112401, 4, 3828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の得意なこと？\\nうーんなんでしょう…\\nあっ、肩たたきです！', 4, 1, 2, 0, 0, 112401, 101, 3829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('生・ハム・メローン！\\nあ、ライブの掛け声を\\n練習してたんですよ♪', 8, 1, 2, 0, 0, 112401, 102, 3830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます！\\n今日も一日\\n頑張りましょうね！', 1, 1, 2, 0, 1, 112401, 1, 3831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかりお昼を食べて\\n午後からも張り切って\\nいきましょうね♪', 1, 1, 2, 0, 2, 112401, 2, 3832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐっすり眠れるよう\\n早めに用事を済ませて\\nお休みしましょうね', 1, 1, 2, 0, 3, 112401, 3, 3833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと休んだら\\nレッスンの続きも\\n頑張ります！', 1, 1, 3, 0, 0, 112401, 2, 3835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ～\\nふわふわもこもこで\\nかわいいです～♪', 1, 1, 3, 0, 0, 112401, 3, 3836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスできる\\nいい香りですね～♪', 1, 1, 3, 0, 0, 112401, 4, 3837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、ポカポカです♪\\n温かい飲み物も\\nほしくなりますね', 1, 1, 3, 0, 0, 112401, 5, 3838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンしたら\\nお腹が空いちゃって…\\nぱくぱくもぐもぐ…', 1, 1, 3, 0, 0, 112401, 7, 3840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンに役立つ\\n運動の情報とか\\n載ってるでしょうか…', 1, 1, 3, 0, 0, 112401, 8, 3841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きらきらーん☆\\nよし、次のステージは\\nこれで行けるかも！', 1, 1, 1, 0, 0, 112601, 1, 3843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の元気でみんなも\\n元気になってくれたら\\nうれしいな～', 1, 1, 1, 0, 0, 112601, 2, 3844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとレッスンで\\n疲れちゃったかも…\\nでも頑張るぞっ！', 1, 1, 1, 0, 0, 112601, 3, 3845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('晩ごはん何にしよう？\\nそーだ、しぶりんにも\\n聞いてみよっと！', 1, 1, 1, 0, 0, 112601, 4, 3846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元気だから笑顔になる\\nじゃなくて\\n笑顔だから\\n元気になるんだよね～', 1, 1, 1, 0, 0, 112601, 5, 3847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('声援を聞いてる時ね\\nすごく懐かしいって\\n思うことがあるんだ', 4, 1, 1, 0, 0, 112601, 101, 3848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私を応援してくれる\\n一番大事な人が\\n隣にいた気がする…', 8, 1, 1, 0, 0, 112601, 102, 3849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なになにー？\\nミオちゃんに\\n何か用かな～？', 1, 1, 2, 0, 0, 112601, 1, 3850);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっ、やっほー！\\n元気そうだね～、キミ\\n私？\\nもちろん元気～！', 1, 1, 2, 0, 0, 112601, 2, 3851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇねぇ、ちょっと\\n遊びに行かない？\\nたまには息抜きで！', 1, 1, 2, 0, 0, 112601, 3, 3852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、この魔物料理さ\\nプリンって言い張れば\\n食べてもらえそうかな', 1, 1, 2, 0, 0, 112601, 4, 3853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ\\nいつもありがとねっ！\\nパワーもらってるよ～', 4, 1, 2, 0, 0, 112601, 101, 3854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたどうした～\\nミオちゃんの魅力に\\nメロメロなのかい？', 8, 1, 2, 0, 0, 112601, 102, 3855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっはよ～！\\n一日の始まりだし\\nテンション上げてこ！', 1, 1, 2, 0, 1, 112601, 1, 3856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いた～…\\nねぇねぇ、一緒に\\nお昼食べようよ～', 1, 1, 2, 0, 2, 112601, 2, 3857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ～…\\n眠くなってきちゃった\\nそろそろ休もっかなぁ', 1, 1, 2, 0, 3, 112601, 3, 3858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、ふっかふか～！\\nレッスンの疲れも\\n吹っ飛んじゃうね☆', 1, 1, 3, 0, 0, 112601, 2, 3860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何これ…かわいーっ！\\n早くしまむーに\\n教えてあげなきゃ！', 1, 1, 3, 0, 0, 112601, 3, 3861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すぅ～…\\nうんっ、これ私の\\n好きな香りだな～♪', 1, 1, 3, 0, 0, 112601, 4, 3862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポッカポカだね～♪\\n…あ～ん、ここから\\n動きたくないーっ！', 1, 1, 3, 0, 0, 112601, 5, 3863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、おーいしー！\\nこれはテンション\\n上がっちゃうね♪', 1, 1, 3, 0, 0, 112601, 7, 3865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nふむふむふむ…！\\n勉強になった、ブイ☆', 1, 1, 3, 0, 0, 112601, 8, 3866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんでドキドキが\\n止まらないの…？\\n騎士くんのせいだー！', 12, 1, 1, 0, 0, 100101, 103, 3868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドキドキしてるの\\nあたしだけ、かな…\\n騎士くんはどう…？', 12, 1, 2, 0, 0, 100101, 103, 3869);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンの前で\\n好きって言えるように\\n練習しないと…', 12, 1, 1, 0, 0, 100201, 103, 3870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン…大好き\\n…き、騎士クン！？\\nなんでここに！？', 12, 1, 2, 0, 0, 100201, 103, 3871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('困ったな…\\n彼が居ないだけで、\\nここまで\\n寂しいと思うなんて…', 12, 1, 1, 0, 0, 100301, 103, 3872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えっと…\\n今日は訓練じゃなくて\\nその…二人でゆっくり\\n過ごしたいな…', 12, 1, 2, 0, 0, 100301, 103, 3873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルの心構え…\\nどういう風に考えると\\nしっくりくるのかな', 1, 1, 1, 0, 0, 112501, 1, 3874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何か始めるのって\\nドキドキするよね\\nだから最近楽しいんだ', 1, 1, 1, 0, 0, 112501, 2, 3875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険者の時って毎日\\nバタバタしてたけど…\\n目標ができると違うね', 1, 1, 1, 0, 0, 112501, 3, 3876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少しお腹が空いた…\\nチョコレート一粒だけ\\n食べようかな', 1, 1, 1, 0, 0, 112501, 4, 3877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウヅキもミオも\\n頑張ってるし\\n私も負けられないね', 1, 1, 1, 0, 0, 112501, 5, 3878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンしてる時さ\\n何か、誰かが足りない\\nそう思うことがあるの', 4, 1, 1, 0, 0, 112501, 101, 3879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大事なのは笑顔…\\n誰か、大切な人から\\n言われた気がするんだ', 8, 1, 1, 0, 0, 112501, 102, 3880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの、何か用？\\n手伝えることがあれば\\nすぐに言ってね', 1, 1, 2, 0, 0, 112501, 1, 3881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('姿勢がいい？\\n普段から鍛えてるし\\n自然とそうなるのかも', 1, 1, 2, 0, 0, 112501, 2, 3882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっき散歩してたら\\n犬を見かけたんだ\\n人懐っこい子だったよ', 1, 1, 2, 0, 0, 112501, 3, 3883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今から冒険？\\nなら私も一緒に行くよ\\n前衛は任せておいて', 1, 1, 2, 0, 0, 112501, 4, 3884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今からレッスンに\\n行くつもりだったんだ\\n少し手伝ってくれる？', 4, 1, 2, 0, 0, 112501, 101, 3885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('蒼の剣を受けよ！\\nえ、何してるのって？\\nただの発声練習だけど', 8, 1, 2, 0, 0, 112501, 102, 3886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう、早いね\\n今日は依頼もないし\\nゆっくりしようかな', 1, 1, 2, 0, 1, 112501, 1, 3887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろお昼だね\\nうーん、今日は\\n何を食べよう…', 1, 1, 2, 0, 2, 112501, 2, 3888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\n明日も早いし\\nそろそろ寝なくちゃ', 1, 1, 2, 0, 3, 112501, 3, 3889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンで疲れたし\\nちょっとだけ\\n休んでおこうかな', 1, 1, 3, 0, 0, 112501, 2, 3891);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、かわいい\\nふわふわしたものって\\n撫でたくなるんだよね', 1, 1, 3, 0, 0, 112501, 3, 3892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん、いい香り…\\nこういうものがあると\\n落ち着くからいいよね', 1, 1, 3, 0, 0, 112501, 4, 3893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('温かい場所って\\n居心地がいいから\\nのんびりしちゃうよ', 1, 1, 3, 0, 0, 112501, 5, 3894);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスン頑張ったら\\nすぐお腹が空くし\\n食べておかないと…！', 1, 1, 3, 0, 0, 112501, 7, 3896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルのことを\\nもっと勉強して\\n成長しなくちゃ', 1, 1, 3, 0, 0, 112501, 8, 3897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、知りたい…\\nなんでもかんでも\\nとにかく知りたい…', 1, 1, 1, 0, 0, 111001, 1, 3899);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、眠い…\\nいつでもどこでも\\nとにかく眠い…', 1, 1, 1, 0, 0, 111001, 2, 3900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君、気を付けたまえ\\nぼーっと歩いていると\\nほわっ！\u3000転んだ…', 1, 1, 1, 0, 0, 111001, 3, 3901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミツキ師にいただいた\\n新作サプリ…丁度よい\\n被験体はいないものか', 1, 1, 1, 0, 0, 111001, 4, 3902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サレンディア救護院に\\nユニちゃん８歳として\\n潜入済みだが何か？', 1, 1, 1, 0, 0, 111001, 5, 3903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君がユニちゃんズの\\n同志であること、\\nぼくは誇りに思うぞ', 4, 1, 1, 0, 0, 111001, 101, 3904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼくは青春がしたい\\nおい、君\\nぼくと青春しないか', 8, 1, 1, 0, 0, 111001, 102, 3905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、そうだな。\\nぼくもそう思う。\\n……えっ、何が？', 1, 1, 2, 0, 0, 111001, 1, 3906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('待て、話しかけるな。\\n今の閃きをメモに…\\n…ああっ、忘れた！', 1, 1, 2, 0, 0, 111001, 2, 3907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歩き方が綺麗？\\n何を今更なこと\\n言っとるんだ君は', 1, 1, 2, 0, 0, 111001, 3, 3908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼくの血液型？\\n大らかのОだ。\\n何か異論あるかね', 1, 1, 2, 0, 0, 111001, 4, 3909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君の声は精神に\\n高揚をもたらすな…\\n波形を分析したいぞ', 4, 1, 2, 0, 0, 111001, 101, 3910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('妙だな…最近\\n君に話しかけられると\\n心拍に乱れを覚える', 8, 1, 2, 0, 0, 111001, 102, 3911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっと、朝だな。\\nそろそろ寝るか、\\n朝更かしは体に悪い', 1, 1, 2, 0, 1, 111001, 1, 3912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、昼餉時か…\\n今日のランチは\\nサプリ定食にしよう', 1, 1, 2, 0, 2, 111001, 2, 3913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう夜だな、\\nそろそろ起きるか。\\n最高の一日にするぞ！', 1, 1, 2, 0, 3, 111001, 3, 3914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほわぁ～\\n副交感神経が…\\n優位に…ふふっひ', 1, 1, 3, 0, 0, 111001, 2, 3916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいすぎるな…\\nセクシーユニには\\nミスマッチか…', 1, 1, 3, 0, 0, 111001, 3, 3917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほぁあアあァぁー…\\nいい香りー…\\nあアァあ…イイ…', 1, 1, 3, 0, 0, 111001, 4, 3918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('炎はいいぞ\\nそこには人類発展の\\nドラマがある', 1, 1, 3, 0, 0, 111001, 5, 3919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フオオー！\\n次から次へと固形食物\\n原理気になるー！', 1, 1, 3, 0, 0, 111001, 7, 3921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良書は時間を忘れる\\n…ふむ、今度\\n布団を持ってこよう', 1, 1, 3, 0, 0, 111001, 8, 3922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きらーん☆\\nハツネちゃんに\\n不可能はないのだ☆', 12, 1, 1, 0, 0, 101201, 103, 3924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒だと\\n寝ちゃうのが\\nもったいないよ～', 12, 1, 2, 0, 0, 101201, 103, 3925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちぇるーん☆', 1, 1, 2, 0, 0, 192101, 1, 3933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちぇる～ん☆\\n今日もチエルは\\nかわいいですよね～？', 1, 1, 1, 0, 0, 110901, 1, 3951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこかに楽しいもの\\n落ちてないかにゃー', 1, 1, 1, 0, 0, 110901, 2, 3952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チエルのオキニは\\n甘々カフェラテ！\\nシクヨロでぇ～す☆', 1, 1, 1, 0, 0, 110901, 3, 3953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩、ひまですよね？\\nチエル遊んであげても\\nいいですけど？', 1, 1, 1, 0, 0, 110901, 4, 3954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁー…しゅき…\\nカルミナ尊い…\\n一生すこれる…', 1, 1, 1, 0, 0, 110901, 5, 3955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩、ひまー\\nちょっとは構えよーう\\nデュクシ！デュクシ！', 4, 1, 1, 0, 0, 110901, 101, 3956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩なんか\\nおごって～！\\nてか…おごらなくても\\nいいから遊んでよ…', 8, 1, 1, 0, 0, 110901, 102, 3957);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、なんですか？\\n告白だったら\\n間に合ってますけど', 1, 1, 2, 0, 0, 110901, 1, 3958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと静かに！\\n今ヤバかわポーズの\\nイメトレ中なんです！', 1, 1, 2, 0, 0, 110901, 2, 3959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('足取りが軽やか？\\nあー…ダンスとか\\n習ってるからですかね', 1, 1, 2, 0, 0, 110901, 3, 3960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チエルの血液型？\\n大型新人のОです\\n何か問題でも？', 1, 1, 2, 0, 0, 110901, 4, 3961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩って何気に\\nいい声してますよね\\n言うことは変だけど', 4, 1, 2, 0, 0, 110901, 101, 3962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、なんですか？\\nたまにだったら\\n告白してもいいですよ', 8, 1, 2, 0, 0, 110901, 102, 3963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはちぇる～ん☆\\nハイ、ご一緒に～？', 1, 1, 2, 0, 1, 110901, 1, 3964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のランチは\\nどこで\\n映えよっかにゃー', 1, 1, 2, 0, 2, 110901, 2, 3965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんばんちぇるるん☆\\nハイ、ご一緒に～？', 1, 1, 2, 0, 3, 110901, 3, 3966);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかチエルン\\n略して、ふかルン♪', 1, 1, 3, 0, 0, 110901, 2, 3968);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいこの子と\\nかわいいチエル！\\n映ぁ～え～る～！', 1, 1, 3, 0, 0, 110901, 3, 3969);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい香り～！\\n持って帰ろっと！\\nすぅーっ…', 1, 1, 3, 0, 0, 110901, 4, 3970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マシュマロは\\n焼かない方のが\\nかわいくないです？', 1, 1, 3, 0, 0, 110901, 5, 3971);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チエル食べても\\n太らない体質\\nなんでぇ～！', 1, 1, 3, 0, 0, 110901, 7, 3973);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('読書は好きですよ\\nシンプルに楽しいし\\nギャップ萌えでしょ？', 1, 1, 3, 0, 0, 110901, 8, 3974);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなのあたしを\\n見る目が違うね\\nま、気にしないけどね', 1, 1, 1, 0, 0, 112701, 1, 3976);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も疲れた～\\nやる気ゼロだし\\nもう寝ちゃおうかな', 1, 1, 1, 0, 0, 112701, 2, 3977);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの代わりに誰か\\n働いてくれないかね', 1, 1, 1, 0, 0, 112701, 3, 3978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('労働の後に食べる\\nあんパン最高～', 1, 1, 1, 0, 0, 112701, 4, 3979);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事の合間に\\nちょっと一息いれよ\\nあ～ドングリ美味し～', 1, 1, 1, 0, 0, 112701, 5, 3980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('報酬も入ったことだし\\nあいつに何か\\n買ってあげようかな', 4, 1, 1, 0, 0, 112701, 101, 3981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の休みはあいつと\\n一日中だらだら\\nしたいな～', 8, 1, 1, 0, 0, 112701, 102, 3982);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしは褒められて\\n伸びるタイプなんだ\\nだから褒めて褒めて', 1, 1, 2, 0, 0, 112701, 1, 3983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、差し入れ？\\n気が利くねぇ\\nあんがと', 1, 1, 2, 0, 0, 112701, 2, 3984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい依頼？\\n今日はもう無理～\\n閉店で～す', 1, 1, 2, 0, 0, 112701, 3, 3985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サ、サボってないよ！\\nちょっと休憩してた\\nだけだから！', 1, 1, 2, 0, 0, 112701, 4, 3986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、一緒に\\nサボろうよ？\\n働き過ぎはよくないよ', 4, 1, 2, 0, 0, 112701, 101, 3987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたが近くにいると\\n仕事の疲れも\\n和らぐんだよね～', 8, 1, 2, 0, 0, 112701, 102, 3988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…もう起きなきゃ\\nつらい労働の\\nはじまりだ～', 1, 1, 2, 0, 1, 112701, 1, 3989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ、お昼に\\nあんパン食べ過ぎた…\\n苦しい…眠い…', 1, 1, 2, 0, 2, 112701, 2, 3990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日は仕事ないし\\nガッツリ夜ふかし\\nしちゃうよ～', 1, 1, 2, 0, 3, 112701, 3, 3991);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫みたいに\\n丸くなっちゃうよ～\\nあたしリスだけどね', 1, 1, 3, 0, 0, 112701, 2, 3993);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか～\\nあたしの尻尾と\\n互角とはやるね～', 1, 1, 3, 0, 0, 112701, 3, 3994);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんパンの香りの\\nアロマとか\\nあればいいのにな～', 1, 1, 3, 0, 0, 112701, 4, 3995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは危険な\\nあたたかさだね～\\n労働意欲が\\nなくなるよ～', 1, 1, 3, 0, 0, 112701, 5, 3996);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい働いたから\\nいっぱい食べても\\nカロリー０だよ', 1, 1, 3, 0, 0, 112701, 7, 3998);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしだってたまには\\n本くらい読むって\\n全然似合わないけどね', 1, 1, 3, 0, 0, 112701, 8, 3999);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの作った\\nオリジナルたい焼き…\\nあいつ、\\n喜んでくれるかにゃ？', 12, 1, 1, 0, 0, 104601, 103, 4001);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、お帰りにゃー♪\\nえへへ…キミに\\nお帰りって言えるのが\\nなんかうれしいにゃ♪', 12, 1, 2, 0, 0, 104601, 103, 4002);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フロンティア\\nスピリッツを\\nお見せするべ！', 1, 1, 1, 0, 0, 112801, 1, 4003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この鎧を着ると\\n気が引き締まる\\n感じがするべ', 1, 1, 1, 0, 0, 112801, 2, 4004);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('搾りたての牛乳飲んで\\n今日も一日\\nがんばるべ！', 1, 1, 1, 0, 0, 112801, 3, 4005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなに牧場の\\n乳製品を\\n味わってもらいてぇべ', 1, 1, 1, 0, 0, 112801, 4, 4006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここはいいとこだべ\\nうちの動物たちも\\n連れてきてやりてぇな', 1, 1, 1, 0, 0, 112801, 5, 4007);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなオラより\\n若ぇのに働いてて\\n立派だべな', 4, 1, 1, 0, 0, 112801, 101, 4008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場もギルドの\\nみんなもオラが\\nまとめて面倒見るべ！', 8, 1, 1, 0, 0, 112801, 102, 4009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ、今日も\\n忙しくなるべよ\\n気合入れてくべ！', 1, 1, 2, 0, 0, 112801, 1, 4010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、あんちゃん\\n丁度いいとこに！\\n一緒に街に\\n行商しに行くべ！', 1, 1, 2, 0, 0, 112801, 2, 4011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場仕事で培った力が\\n戦いでも役立つなら\\n一石二鳥だべさ！', 1, 1, 2, 0, 0, 112801, 3, 4012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('疲れた時は牧場産の\\nミルク菓子で\\n糖分補給だべ', 1, 1, 2, 0, 0, 112801, 4, 4013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、牧場の\\n新製品だべ\\n一番最初に味見\\nしてほしいべさ', 4, 1, 2, 0, 0, 112801, 101, 4014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('働きづめはよくねぇベ\\n膝枕してやっから\\nこっち来るべさ', 8, 1, 2, 0, 0, 112801, 102, 4015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁあ…\\n酪農家の朝は\\n早ぇんだべ…', 1, 1, 2, 0, 1, 112801, 1, 4016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごはんの時間だべ！\\n腹が減っては酪農も\\n戦いもできねえべ！', 1, 1, 2, 0, 2, 112801, 2, 4017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝るべ！\\n健全なお笑いは\\n健全な肉体に宿るべ！', 1, 1, 2, 0, 3, 112801, 3, 4018);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧草みたいに\\nふっかふかだべ～', 1, 1, 3, 0, 0, 112801, 2, 4020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子、目の感じが\\nエリザベスに似てるべ', 1, 1, 3, 0, 0, 112801, 3, 4021);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂いだべ～\\n疲れた体に\\nしみるべな～', 1, 1, 3, 0, 0, 112801, 4, 4022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったけぇな～\\n牧場にも\\n置いてみっかな～', 1, 1, 3, 0, 0, 112801, 5, 4023);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うまいべ！\\n生産者のこだわりを\\n感じるべさ', 1, 1, 3, 0, 0, 112801, 7, 4025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('酪農も戦いも\\nまずは知識だべ！', 1, 1, 3, 0, 0, 112801, 8, 4026);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴょん、ぴょん♪\\nこの服のおかげで、\\n体が軽いなぁ…♪', 1, 1, 1, 0, 0, 113001, 1, 4028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今の内に部屋の\\n掃除をしておこっと…\\nみんな喜んで\\nくれるといいなぁ', 1, 1, 1, 0, 0, 113001, 2, 4029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('耳と尻尾…この服、\\n本当にウサギさん\\nみたいだなぁ', 1, 1, 1, 0, 0, 113001, 3, 4030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか先輩の\\n気配がするような…\\n気のせいかな？', 1, 1, 1, 0, 0, 113001, 4, 4031);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウサギさんの真似を\\nしたら、存在感が薄い\\nとか言われないかな？\\nア、アユミだぴょん♪', 1, 1, 1, 0, 0, 113001, 5, 4032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…\\nいつもとは違う先輩が\\nたくさん見られて、\\nうれしいな♪', 4, 1, 1, 0, 0, 113001, 101, 4033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本の中の世界で先輩と\\n旅をするなんて…\\n幸せすぎて、罰が\\n当たりそうだよぉ…', 8, 1, 1, 0, 0, 113001, 102, 4034);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じ～…はっ！？\\nす、すみません！\\n話しかけてもらえる\\nなんて思ってなくて！', 1, 1, 2, 0, 0, 113001, 1, 4035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩がすぐそばに…\\nし、幸せすぎて\\n倒れそうですぅ！', 1, 1, 2, 0, 0, 113001, 2, 4036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、えっと…あの…！\\nうう…いざ先輩と\\n向き合うと\\n緊張しちゃうよぉ…', 1, 1, 2, 0, 0, 113001, 3, 4037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はうっ！？\\nしょ、正面から見る\\n先輩は、私にとって\\n神々しすぎますぅ…！', 1, 1, 2, 0, 0, 113001, 4, 4038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩…その…\\nい、一緒にご飯でも\\nどうでひゅか！\\nうう…またかんだぁ…', 4, 1, 2, 0, 0, 113001, 101, 4039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩…\\nハーブティーを\\n入れたんですが、\\n一緒にどうですか…？', 8, 1, 2, 0, 0, 113001, 102, 4040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩！\\nおはようございます！\\nえへへ、練習通りに\\nバッチリ言えたぁ♪', 1, 1, 2, 0, 1, 113001, 1, 4041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、もうお昼ですね\\n時計を持ってて\\n良かったです', 1, 1, 2, 0, 2, 113001, 2, 4042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\nお休みする\\n準備をしちゃいますね', 1, 1, 2, 0, 3, 113001, 3, 4043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ…ちょっとだけ\\n先輩の匂いがする…\\nえへへ、幸せだなぁ♪', 1, 1, 3, 0, 0, 113001, 2, 4045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…私もウサギさんの\\nぬいぐるみとして、\\n先輩のそばに…はっ！\\n私ったら何を…！', 1, 1, 3, 0, 0, 113001, 3, 4046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、いい香り…\\n先輩もこういうのが\\n好きなのかな？', 1, 1, 3, 0, 0, 113001, 4, 4047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩が隣に\\n居たら、もっと\\n暖かいのになぁ…♪', 1, 1, 3, 0, 0, 113001, 5, 4048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい…でも、\\n先輩と一緒に\\n食べたら、もっと\\nおいしいだろうな…', 1, 1, 3, 0, 0, 113001, 7, 4050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウサギさんって、穴を\\n掘ったりするんだ…\\n私も、隠れたいときに\\n掘ってみようかな？', 1, 1, 3, 0, 0, 113001, 8, 4051);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネビアさまのように\\n普段からパタパタと\\n飛んでみるのも…', 1, 1, 1, 0, 0, 180501, 1, 4053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご立派になられた\\n主さまと並べるように\\nもっと精進しなくては', 1, 1, 1, 0, 0, 180501, 2, 4054);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('月々の食費が\\n増えてしまいました\\n申し訳ございません…', 1, 1, 1, 0, 0, 180501, 3, 4055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワンワンのほうの\\n主さまは、この姿に\\n驚くでしょうか…？', 1, 1, 1, 0, 0, 180501, 4, 4056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまと離れていても\\n主さまとの絆は\\n胸に感じております…', 1, 1, 1, 0, 0, 180501, 5, 4057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このギルドハウスは\\nみなさまの帰る場所…\\nわたくしが守ります', 4, 1, 1, 0, 0, 180501, 101, 4058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんな未来が\\n待ち受けようとも\\n主さまと添い遂げます', 8, 1, 1, 0, 0, 180501, 102, 4059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おでかけですか？\\nではわたくしも\\nお供いたします', 1, 1, 2, 0, 0, 180501, 1, 4060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう二度と主さまと\\n離れたくはありません\\nいつ何時も…', 1, 1, 2, 0, 0, 180501, 2, 4061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにかお困りごと\\nでございますか？\\nわたくしに何なりと…', 1, 1, 2, 0, 0, 180501, 3, 4062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうぞゆっくりと\\n心ゆくまでくつろいで\\nくださいまし、主さま', 1, 1, 2, 0, 0, 180501, 4, 4063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この羽で主さまを\\nどこまでも遠く…\\n高くへと導きます', 4, 1, 2, 0, 0, 180501, 101, 4064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま、主さま…♪\\nおそばにいられるのが\\nうれしくて、つい…', 8, 1, 2, 0, 0, 180501, 102, 4065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n今日も一日、主さまの\\nサポートをいたします', 1, 1, 2, 0, 1, 180501, 1, 4066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も頑張っている\\n主さまに、スタンプを\\nもう一つ…ポン！', 1, 1, 2, 0, 2, 180501, 2, 4067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝付けないのでしたら\\nわたくしが子守唄を\\n歌ってさしあげます', 1, 1, 2, 0, 3, 180501, 3, 4068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか…\\nまるで主さまのような\\n柔らかさでございます', 1, 1, 3, 0, 0, 180501, 2, 4070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたも一緒に\\n主さまと遊びますか？\\n至福の時間ですよ♪', 1, 1, 3, 0, 0, 180501, 3, 4071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまの優しくて\\nくすぐったい匂いが\\nたまらなく恋しいです', 1, 1, 3, 0, 0, 180501, 4, 4072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまの心と\\n繋がったときのような\\n温もりを感じます', 1, 1, 3, 0, 0, 180501, 5, 4073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いけませんっ…！\\n元の姿に戻ると、また\\n食べてしまうのに…！', 1, 1, 3, 0, 0, 180501, 7, 4075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまに読み聞かせる\\n絵本は…妖精が主役の\\n物語にいたしましょう', 1, 1, 3, 0, 0, 180501, 8, 4076);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…彼のこと弟みたいに\\n思ってきたのに…私、\\nどうしたらいいの…？', 12, 1, 1, 0, 0, 104801, 103, 4078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よ、予定がなかったら\\nでいいんだけど…\\nその、ふ、二人で\\n訓練とか…どうかな？', 12, 1, 2, 0, 0, 104801, 103, 4079);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おめかしもしたし\\nあとはお兄ちゃんを\\n待つだけですね～♪', 1, 1, 1, 0, 0, 112901, 1, 4080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんの身の回り\\nをお片付け～、これぞ\\nデキる妹アピール！', 1, 1, 1, 0, 0, 112901, 2, 4081);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、衣装がほつれてる\\nこれくらいなら自分で\\n繕えますね…！', 1, 1, 1, 0, 0, 112901, 3, 4082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好で歩いてると\\n見慣れた景色も\\n違うものに見えますね', 1, 1, 1, 0, 0, 112901, 4, 4083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('勉強もちゃんとします\\n…でも、一人だと\\n集中力がもちません～', 1, 1, 1, 0, 0, 112901, 5, 4084);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんを大好きな\\n妹が待ってますよ～\\n…まだですかね～', 4, 1, 1, 0, 0, 112901, 101, 4085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんのために\\n掃除洗濯をする私って\\nお嫁さんみたい…\\n…えへへ～', 8, 1, 1, 0, 0, 112901, 102, 4086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おに～いちゃん！\\n縫い物、一緒に\\nやりましょうよ！', 1, 1, 2, 0, 0, 112901, 1, 4087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい妹を\\n愛でたくなりました？\\n思う存分、どうぞ♪', 1, 1, 2, 0, 0, 112901, 2, 4088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、ビックリした～\\nもう、お兄ちゃんてば\\nイタズラっ子ですね～', 1, 1, 2, 0, 0, 112901, 3, 4089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にお買い物\\n行きませんか？\\n妹とデートですよっ♪', 1, 1, 2, 0, 0, 112901, 4, 4090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん…頭を\\n撫でてくれませんか？\\nえへへ、これが一番♪', 4, 1, 2, 0, 0, 112901, 101, 4091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん大好き♪\\n何度でも言いますよ！\\nお兄ちゃん大好きっ♪', 8, 1, 2, 0, 0, 112901, 102, 4092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよ～お兄ちゃん！\\n妹モーニングコールの\\n時間ですよっ♪', 1, 1, 2, 0, 1, 112901, 1, 4093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ休憩ですね！\\n甘いお菓子で\\n元気回復しましょ～！', 1, 1, 2, 0, 2, 112901, 2, 4094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かし厳禁！\\nでも、もう少しだけ\\nお話ししたいなぁ～', 1, 1, 2, 0, 3, 112901, 3, 4095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっかふかですよ！\\nお兄ちゃんと一緒に\\n座りたいなぁ…♪', 1, 1, 3, 0, 0, 112901, 2, 4097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このぬいぐるみの\\nかわいさ…う～ん\\n負けられません…！', 1, 1, 3, 0, 0, 112901, 3, 4098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りにも気をつかって\\nパーフェクトな妹に\\nなっちゃいますから！', 1, 1, 3, 0, 0, 112901, 4, 4099);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～ぬくぬくです～\\nお兄ちゃんと一緒に\\n温まりたいなぁ…♪', 1, 1, 3, 0, 0, 112901, 5, 4100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは止まりませんね\\nもぐもぐ…いくらでも\\n食べられちゃいます', 1, 1, 3, 0, 0, 112901, 7, 4102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、デザインの\\n参考になりそう！\\n私にも作れるかなぁ', 1, 1, 3, 0, 0, 112901, 8, 4103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('退屈です…\\nなにか楽しいことは\\nないですか？', 1, 1, 1, 0, 0, 106601, 1, 4105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギャングの仕事は\\n今日はお休みです\\nのんびりするですよ', 1, 1, 1, 0, 0, 106601, 2, 4106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひうっ！\u3000あたしの\\n尻尾なんて食べても\\nおいしくないですよ？', 1, 1, 1, 0, 0, 106601, 3, 4107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう…どうやら\\n例の件はまだボスに\\nバレてないですね…', 1, 1, 1, 0, 0, 106601, 4, 4108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('下克上…いい言葉です\\nって、ボスに聞かれて\\nないですよね…？', 1, 1, 1, 0, 0, 106601, 5, 4109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか絶対ビッグに\\nなってやるです！\\nあたしを信じるです！', 4, 1, 1, 0, 0, 106601, 101, 4110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしが覚醒したら\\nきっと誰よりも\\n強くなるはずです！', 8, 1, 1, 0, 0, 106601, 102, 4111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんですか？\\n貢ぎ物なら\\nいつでも歓迎ですよ！', 1, 1, 2, 0, 0, 106601, 1, 4112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしだって\\nやる時はやるですよ！\\nその時がこないだけ！', 1, 1, 2, 0, 0, 106601, 2, 4113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しりとり勝負ですか？\\nいい度胸ですね、\\nかかってくるです！', 1, 1, 2, 0, 0, 106601, 3, 4114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんは\\nヒマそうですね…\\nうらやましいです', 1, 1, 2, 0, 0, 106601, 4, 4115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かまってほしいです？\\nまったく…いいですよ\\nしょうがないですね', 4, 1, 2, 0, 0, 106601, 101, 4116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんのことは\\nこのあたしが\\n守ってやるですよ！', 8, 1, 2, 0, 0, 106601, 102, 4117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('デキるギャングの\\n朝は早いのです…\\nふぁあ…', 1, 1, 2, 0, 1, 106601, 1, 4118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹がすいたですね\\nなにか食べにいくです\\nお兄さんのおごりで！', 1, 1, 2, 0, 2, 106601, 2, 4119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁあ…むにゅう…\\nまだ起きてるですよぉ', 1, 1, 2, 0, 3, 106601, 3, 4120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～…\\nもうここから一歩も\\n動きたくないです', 1, 1, 3, 0, 0, 106601, 2, 4122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなかいいモフりを\\nしてやがるです…\\n舎弟にしてやるですよ', 1, 1, 3, 0, 0, 106601, 3, 4123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんかおしゃれな\\n匂いがするですね…', 1, 1, 3, 0, 0, 106601, 4, 4124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふーん！\\nあたしのブレスの方が\\n火力は上ですね！', 1, 1, 3, 0, 0, 106601, 5, 4125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしに貢ぎ物とは\\nよく分かってるですね\\n食べてやるですよ', 1, 1, 3, 0, 0, 106601, 7, 4127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふーむ…\\nもっと楽しい本は\\nないですかね？', 1, 1, 3, 0, 0, 106601, 8, 4128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に眠る秘宝…\\n心躍る響きだ！\\n早く見つけたい…！', 1, 1, 1, 0, 0, 113201, 1, 4130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう～、暑いぃ…\\nかき氷を食べて\\nすっきりしたいぃ…', 1, 1, 1, 0, 0, 113201, 2, 4131);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アターック！\\nいや、もっとこう…\\nアタァーック！', 1, 1, 1, 0, 0, 113201, 3, 4132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スイカ割りで\\n目を回さない\\nコツはなんだろうか…', 1, 1, 1, 0, 0, 113201, 4, 4133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかく海に来たのだ\\n泳ぎも上手に\\nなりたいものだな', 1, 1, 1, 0, 0, 113201, 5, 4134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっふっふ…\\n疼く…疼くぞ！\\n日焼けの痕が…', 4, 1, 1, 0, 0, 113201, 101, 4135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルドと私は\\n来世でも共にある…\\nつまり我らはずっと…\\nはわわ…！', 8, 1, 1, 0, 0, 113201, 102, 4136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルド、私と共に\\n日光浴に行かないか？\\n光の力を集めよう！', 1, 1, 2, 0, 0, 113201, 1, 4137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好だからできる\\n必殺技を考えている\\n何か案はないか？', 1, 1, 2, 0, 0, 113201, 2, 4138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルド～！\\nスイカを貰ったから\\n一緒に食べよう！', 1, 1, 2, 0, 0, 113201, 3, 4139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こう日差しが強いと\\n日焼けしそうだな\\n跡になってないか…？', 1, 1, 2, 0, 0, 113201, 4, 4140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('我らの夏の黙示録\\nしっかりと記録\\nしておかねばな', 4, 1, 2, 0, 0, 113201, 101, 4141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんと日焼けどめを\\n塗ってもらうべき\\nだったかな…？\\nシ、シグルドに…！', 8, 1, 2, 0, 0, 113201, 102, 4142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝だぞシグルド！\\nさぁ、日光を浴びて\\n光の加護を得るのだ！', 1, 1, 2, 0, 1, 113201, 1, 4143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう昼食の時間か…\\n私の魔力も減ったし\\n早く補給しなければ', 1, 1, 2, 0, 2, 113201, 2, 4144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜でも我らの活動は\\n終わることはない！\\nさぁ準備を…ふわぁ…', 1, 1, 2, 0, 3, 113201, 3, 4145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で遊んでいると\\n疲れてしまうからな\\n少し休まるとしよう', 1, 1, 3, 0, 0, 113201, 2, 4147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ～、君の名前は\\n何にしまちょうかね♪\\n…はっ、見たのか！？', 1, 1, 3, 0, 0, 113201, 3, 4148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よい香りで\\n我が精神も安らぐ…', 1, 1, 3, 0, 0, 113201, 4, 4149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('別に寒くなどないぞ！\\n寒くないが、ちょっと\\n暖まりたくなってな！', 1, 1, 3, 0, 0, 113201, 5, 4150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐ…食べ過ぎた分は\\n魔力に変換されるのだ\\n…たぶん', 1, 1, 3, 0, 0, 113201, 7, 4152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…なな、なんだ！？\\nシグルドはこういう\\n趣味なのか…！？', 1, 1, 3, 0, 0, 113201, 8, 4153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむ、この乗り心地…\\nいざゆかん、\\nシードラゴンよ！', 1, 1, 3, 0, 0, 113201, 10, 4155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('疾風の冥姫の名に\\nふさわしき\\n深海の玉座よ…\\nふああ…柔らかい～', 1, 1, 3, 0, 0, 113201, 11, 4156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿でいると\\nわたしもお姫様に\\nなれた気がする…♪', 1, 1, 1, 0, 0, 180201, 1, 4157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いてきちゃった\\nまずは買い出しに…\\n…変身解かなくちゃ！', 1, 1, 1, 0, 0, 180201, 2, 4158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('胸のところが空いてて\\nスースーするの\\nまだ慣れないな…', 1, 1, 1, 0, 0, 180201, 3, 4159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('治癒魔法に使ってた\\n魔力を攻撃魔法に…\\n頭の中でも練習練習', 1, 1, 1, 0, 0, 180201, 4, 4160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何もできなかった\\nわたしから、少しは\\n変われたのかな…？', 1, 1, 1, 0, 0, 180201, 5, 4161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン…\\n今どこにいるの…？\\n…会いたいな', 4, 1, 1, 0, 0, 180201, 101, 4162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('離れてても分かるよ…\\n温かい力で騎士クンに\\n守られてるの', 8, 1, 1, 0, 0, 180201, 102, 4163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたしが戦えてるのは\\n騎士クンのおかげだよ\\nいつもありがとう！', 1, 1, 2, 0, 0, 180201, 1, 4164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いてそう…？\\n…内緒で作ったおやつ\\n騎士クンも食べる？', 1, 1, 2, 0, 0, 180201, 2, 4165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃうっ！\u3000え！？\\nせ、背中はダメ～！\\n言ってから触って～！', 1, 1, 2, 0, 0, 180201, 3, 4166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好、どうかな？\\nえ？\u3000似合ってる…？\\n本当？\u3000…うれしい！', 1, 1, 2, 0, 0, 180201, 4, 4167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい？\u3000そうだね\\nひらひらが…わたし？\\nええっ、そ、そんな！', 4, 1, 2, 0, 0, 180201, 101, 4168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン、これからも\\nずっと…わたしの\\nそばにいてください', 8, 1, 2, 0, 0, 180201, 102, 4169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝からこんなに\\n食べる日が来るなんて\\n思ってなかったよ…', 1, 1, 2, 0, 1, 180201, 1, 4170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼を作らなくちゃ\\n騎士クン、一緒に\\nお料理してみる？', 1, 1, 2, 0, 2, 180201, 2, 4171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン、もう眠い？\\n眠るまで、わたしが\\nずっとそばにいるね', 1, 1, 2, 0, 3, 180201, 3, 4172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('攻撃参加するからこそ\\n適度に体を休めるのは\\n大切だよね！', 1, 1, 3, 0, 0, 180201, 2, 4174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい…騎士クンと\\nシェフィちゃんにも\\nプレゼントしたいな', 1, 1, 3, 0, 0, 180201, 3, 4175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～…\\nあれ？\u3000お腹が空いて\\nきちゃった…！？', 1, 1, 3, 0, 0, 180201, 4, 4176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('温かい…\\n騎士クンがくれる\\n力みたい…', 1, 1, 3, 0, 0, 180201, 5, 4177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぱくっ、\\nあむ、はむっ…\\nううぅ～…やっぱり\\n手が止まらないよぉ～', 1, 1, 3, 0, 0, 180201, 7, 4179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しく覚えたいな…\\nみんなで食べられる\\n大皿向けの料理♪', 1, 1, 3, 0, 0, 180201, 8, 4180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんの愛\\nこのままじゃ\\nあふれちゃうよ…♪', 12, 1, 1, 0, 0, 104901, 103, 4182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くん♪\\n弟くんっ♪\\nおっとうっとくんっ♪', 12, 1, 2, 0, 0, 104901, 103, 4183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐのもいいけど\\n今日は砂浜で\\nのんびりしようかね', 1, 1, 1, 0, 0, 113101, 1, 4184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さてと\\nちょっくらひと泳ぎ\\n行ってくるかね', 1, 1, 1, 0, 0, 113101, 2, 4185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっついねぇ…\\nうちわがないと\\nしんどいったらないよ', 1, 1, 1, 0, 0, 113101, 3, 4186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷たすぎる飲み物で\\n体を冷やさないよう\\n気をつけないと…', 1, 1, 1, 0, 0, 113101, 4, 4187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏はあっという間だし\\n悔いがないように\\n楽しまないとね', 1, 1, 1, 0, 0, 113101, 5, 4188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きっとこの夏は\\nアタシにとって大事な\\n想い出になるね…', 4, 1, 1, 0, 0, 113101, 101, 4189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…前に比べたら\\nアタシたちの距離も\\n近づいたみたいだね', 8, 1, 1, 0, 0, 113101, 102, 4190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし暇なら\\n今日も笹舟釣り\\n一緒にどうだい？', 1, 1, 2, 0, 0, 113101, 1, 4191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前さん、釣りに\\n興味が湧いたなら今度\\n道具を見に行こうよ', 1, 1, 2, 0, 0, 113101, 2, 4192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今から砂浜に行くんだ\\nお前さんも一緒に\\n散歩するかい？', 1, 1, 2, 0, 0, 113101, 3, 4193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、日焼け跡？\\nおや…本当だ\\nすぐ焼けちまうねえ', 1, 1, 2, 0, 0, 113101, 4, 4194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっ！？\\nちょっと！\\n日焼け跡をいきなり\\n触らないでおくれ！', 4, 1, 2, 0, 0, 113101, 101, 4195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前さんは、その…\\nアタシと一緒にいて\\n楽しかったかい？', 8, 1, 2, 0, 0, 113101, 102, 4196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようさん\\n今日も砂浜に行って\\nゆっくりしようか', 1, 1, 2, 0, 1, 113101, 1, 4197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼か…\\nそうだ、よかったら\\n刺身定食、作ろうか？', 1, 1, 2, 0, 2, 113101, 2, 4198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の空を見てるとさ\\nなつかしい気持ちに\\nなるんだよね', 1, 1, 2, 0, 3, 113101, 3, 4199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度に休憩して\\n夏バテしないよう\\n気をつけないとね', 1, 1, 3, 0, 0, 113101, 2, 4201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたたちも\\n海を楽しみたいって\\n思っているのかね', 1, 1, 3, 0, 0, 113101, 3, 4202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～…香りでも\\nバカンスらしさを\\n楽しめるもんだね', 1, 1, 3, 0, 0, 113101, 4, 4203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう格好だと\\n少し冷えちまうんだよ', 1, 1, 3, 0, 0, 113101, 5, 4204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐもぐ…\\n遊んだ分、お腹が\\n空いちまってねぇ', 1, 1, 3, 0, 0, 113101, 7, 4206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ん、なんだいこの本\\n催眠…うーん読めない\\nナナカに聞いてみるか', 1, 1, 3, 0, 0, 113101, 8, 4207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へえ…\\nなかなかいい\\n乗り心地じゃないか', 1, 1, 3, 0, 0, 113101, 10, 4209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうそうハマグリって\\n竿でも釣れるんだよ\\n知ってたかい？', 1, 1, 3, 0, 0, 113101, 11, 4210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海を満喫しなきゃね\\nちょっとひと泳ぎ\\n行ってこようかな？', 1, 1, 1, 0, 0, 113301, 1, 4211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん…♪\\nいつもと違った\\n開放感～\\nなんちゃって！', 1, 1, 1, 0, 0, 113301, 2, 4212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今のナナカちゃんは\\nたぶん水属性！', 1, 1, 1, 0, 0, 113301, 3, 4213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着もバッチリ！\\nサイカワサイツヨ\\nナナカちゃ～ん☆', 1, 1, 1, 0, 0, 113301, 4, 4214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んっふっふ\\nドキ！\u3000水着だらけの\\nギルドハウス！\\nとかどうかな？', 1, 1, 1, 0, 0, 113301, 5, 4215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなに見られると\\nちょ～っと\\n恥ずかしいかも…\\nなんてねなんてね！', 4, 1, 1, 0, 0, 113301, 101, 4216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとくらい\\nドキッとしてくれても\\nいいのにな～、もう…', 8, 1, 1, 0, 0, 113301, 102, 4217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着魔法少女の\\n相方がほしいなぁ～…\\nね、君やってみない？', 1, 1, 2, 0, 0, 113301, 1, 4218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもの格好と同じ？\\nも～、わかってない！\\nセクスィー度が違う！', 1, 1, 2, 0, 0, 113301, 2, 4219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかなどうかな？\\nこのひらひらのとこが\\nかわいーかなー\\nとか思うんだけど！', 1, 1, 2, 0, 0, 113301, 3, 4220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくだから\\nギャルゲーイベント\\nごっことか\\nやってみる？', 1, 1, 2, 0, 0, 113301, 4, 4221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナナカちゃんの\\n好感度を上げたい？\\nならおでかけだー！', 4, 1, 2, 0, 0, 113301, 101, 4222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おうちで水着って\\nなんだかコスプレ\\nみたいで楽しいかも♪', 8, 1, 2, 0, 0, 113301, 102, 4223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっはよーう！\\n今日はバカンス日和！\\n海へゴーですぞ～♪', 1, 1, 2, 0, 1, 113301, 1, 4224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯どうしよ～…\\nあ、ナナカちゃんと\\nどっか食べに行く？', 1, 1, 2, 0, 2, 113301, 2, 4225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜は本を読むのが\\n捗りまくりですな～！\\n今日はなに読もっかな', 1, 1, 2, 0, 3, 113301, 3, 4226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次のイベントもあるし\\nちょっと休んで体力を\\n回復しなきゃね～', 1, 1, 3, 0, 0, 113301, 2, 4228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうマスコット\\n私にもいたらなぁ\\nいっそ作っちゃう…？', 1, 1, 3, 0, 0, 113301, 3, 4229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着魔法少女に\\n似合う香りってのも\\n考えてみよっかな♪', 1, 1, 3, 0, 0, 113301, 4, 4230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜になると急に冷えて\\n肌寒いんだよね～…', 1, 1, 3, 0, 0, 113301, 5, 4231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんまり食べると\\nお腹が出て…でも…\\nうう、止まらない～！', 1, 1, 3, 0, 0, 113301, 7, 4233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この催眠魔法の本\\n誰にもばれないように\\n保管しとかなきゃね…', 1, 1, 3, 0, 0, 113301, 8, 4234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゴーゴーゴーゴーゴー\\nナナカちゃーん♪', 1, 1, 3, 0, 0, 113301, 10, 4236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナナカちゃんの\\n誕生～\\nなんちゃって', 1, 1, 3, 0, 0, 113301, 11, 4237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ファイトファイト☆\\n一生懸命\\n応援するね！', 1, 1, 1, 0, 0, 113401, 1, 4238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんながんばってる！\\n私も応援でみんなを\\n盛り上げなきゃ！', 1, 1, 1, 0, 0, 113401, 2, 4239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし元気のない人が\\nいたら…応援で少し\\nでも元気にしたいな！', 1, 1, 1, 0, 0, 113401, 3, 4240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('がんばれ～☆\\nよし、発声練習OK！\\n応援は、声も大事！', 1, 1, 1, 0, 0, 113401, 4, 4241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかく水着なんだし\\n泳いだり潜ったりして\\n遊びたいな～！', 1, 1, 1, 0, 0, 113401, 5, 4242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チアリーダーとして\\nキミを精一杯\\n応援したいな…！', 4, 1, 1, 0, 0, 113401, 101, 4243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミへの応援\\nちゃんと\\n届いてるかな…', 8, 1, 1, 0, 0, 113401, 102, 4244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…今ね、\\nキミへの応援歌を\\n考えてたのだ～♪', 1, 1, 2, 0, 0, 113401, 1, 4245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\n元気がないなら\\n私が応援するよ☆', 1, 1, 2, 0, 0, 113401, 2, 4246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('がんばったあとは休憩\\nしなきゃね！\u3000私と\\n一緒にお昼寝する？', 1, 1, 2, 0, 0, 113401, 3, 4247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリンとおそろいの\\n水着で応援…\\nしてみたいなぁ～', 1, 1, 2, 0, 0, 113401, 4, 4248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はなにして遊ぶ？\\nキミがしたいことを\\n教えてよ！', 4, 1, 2, 0, 0, 113401, 101, 4249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミを応援\\nすることができて…\\n私、すごく幸せ…', 8, 1, 2, 0, 0, 113401, 102, 4250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミって早起き\\nなんだね！\u3000私も\\n見習わなきゃ！', 1, 1, 2, 0, 1, 113401, 1, 4251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとお疲れかな？\\nそれじゃあ\\n応援してあげるね♪', 1, 1, 2, 0, 2, 113401, 2, 4252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遅い時間まで\\nがんばってえらいね！\\nでも無理はダメだよ♪', 1, 1, 2, 0, 3, 113401, 3, 4253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとだけ休憩…\\n…あう、座り心地が\\n良すぎて…眠気が…', 1, 1, 3, 0, 0, 113401, 2, 4255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいるみんなを\\n私の応援でもっと\\n元気にするのだ～！', 1, 1, 3, 0, 0, 113401, 3, 4256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元気の出る香り～♪\\nこれもうまく応援に\\n活かせないかな～？', 1, 1, 3, 0, 0, 113401, 4, 4257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかあったまって\\n元気をチャージ\\nするのだ～☆', 1, 1, 3, 0, 0, 113401, 5, 4258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい食べて、\\nみんなを応援する\\nパワーをつけなきゃ！', 1, 1, 3, 0, 0, 113401, 7, 4260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなを元気にする\\n方法は…どこかに\\n書いてないかなぁ…？', 1, 1, 3, 0, 0, 113401, 8, 4261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、この子\\n怪獣さんみたいで\\nかわいいね～♪', 1, 1, 3, 0, 0, 113401, 10, 4263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着でこれに\\n乗ってると海にいる\\n気分になれるね！', 1, 1, 3, 0, 0, 113401, 11, 4264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごく忙しいけど\\nとても充実した気分\\nこれが青春なのかしら', 1, 1, 1, 0, 0, 113501, 1, 4265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森の静かな雰囲気も\\n海の開放的な空気も\\nどちらも素敵ね～', 1, 1, 1, 0, 0, 113501, 2, 4266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('汚れたお洗濯物は\\nみんなが頑張った証\\nなんだか愛おしいわ', 1, 1, 1, 0, 0, 113501, 3, 4267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなを見てると\\n何だか私も\\n走りたくなっちゃうわ', 1, 1, 1, 0, 0, 113501, 4, 4268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの水着だし\\n泳ぐ練習でも\\nしてみようかしら', 1, 1, 1, 0, 0, 113501, 5, 4269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんな～ファイト～！\\n応援するのも大事よね\\n練習しておかなきゃ♪', 4, 1, 1, 0, 0, 113501, 101, 4270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先生に教えられること\\nまだまだい～っぱいね\\n次は何がいいかしら♪', 8, 1, 1, 0, 0, 113501, 102, 4271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も暑くなりそうね\\nこまめな水分補給を\\n忘れないでね', 1, 1, 2, 0, 0, 113501, 1, 4272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手伝ってくれるの？\\nありがとう♪\\n先生、頼りにしてるわ', 1, 1, 2, 0, 0, 113501, 2, 4273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩はこまめに\\nとりましょうね\\n無理は厳禁よ', 1, 1, 2, 0, 0, 113501, 3, 4274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の遊びって\\nどんなのがあるの？\\n先生に教えてね', 1, 1, 2, 0, 0, 113501, 4, 4275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着は初めてだけど\\nどう？\u3000変じゃない？\\nふふ、ありがとう', 4, 1, 2, 0, 0, 113501, 101, 4276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと過ごした\\nこの夏は、きっと…\\n忘れられない思い出ね', 8, 1, 2, 0, 0, 113501, 102, 4277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう～\\n朝練前にちゃんと\\nごはん食べましょうね', 1, 1, 2, 0, 1, 113501, 1, 4278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お弁当作ってきたの\\n栄養いっぱい摂って\\n午後も頑張ろうね', 1, 1, 2, 0, 2, 113501, 2, 4279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうお休みしなきゃね\\n先生が子守唄を歌って\\nあげましょうか？', 1, 1, 2, 0, 3, 113501, 3, 4280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、いい気持ちねぇ\\n先生、少しだけ\\n休憩しちゃおうかしら', 1, 1, 3, 0, 0, 113501, 2, 4282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらかわいい♪\\nチームにもこういう\\nマスコットが欲しいわ', 1, 1, 3, 0, 0, 113501, 3, 4283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、海の香り？\\n波の音まで聞こえて\\nきちゃいそうだわ', 1, 1, 3, 0, 0, 113501, 4, 4284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ\\nこれなら濡れた水着を\\n乾かすのも簡単ね♪', 1, 1, 3, 0, 0, 113501, 5, 4285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、美味しいわね♪\\nでも、食べ過ぎは\\n禁物よ', 1, 1, 3, 0, 0, 113501, 7, 4287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先生だって日々勉強よ\\n新しいことを知るのは\\nとても楽しいわ♪', 1, 1, 3, 0, 0, 113501, 8, 4288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらあら、楽しいわね\\nみんなもきっと\\nおおはしゃぎね', 1, 1, 3, 0, 0, 113501, 10, 4290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、これで\\n夏らしい気分を\\n満喫するわよ♪', 1, 1, 3, 0, 0, 113501, 11, 4291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サンドイッチも\\n作ったし、\\nお兄ちゃんのお出迎え\\n準備は完璧だね♪', 12, 1, 1, 0, 0, 102301, 103, 4292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ、お兄ちゃんと\\nぷうきちが居てくれる\\nだけで、なんだか\\nうれしくなっちゃう♪', 12, 1, 2, 0, 0, 102301, 103, 4293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し赤くなっているな\\n日焼けなんてしたのは\\nいつ以来だろう', 1, 1, 1, 0, 0, 113601, 1, 4294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好で\\n過ごすのは\\n少し勇気がいるな…', 1, 1, 1, 0, 0, 113601, 2, 4295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑いのは平気だが\\n肌が外気に触れるの\\nにはまだ慣れないな…', 1, 1, 1, 0, 0, 113601, 3, 4296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好でも\\n堂々としていれば\\n恥ずかしくはない…\\nのかな？', 1, 1, 1, 0, 0, 113601, 4, 4297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっと…鎧姿の時と\\n重心が違うせいか\\nちょっと不安定だな', 1, 1, 1, 0, 0, 113601, 5, 4298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この水着…\\n私に似合って\\nいるのだろうか…？\\n少年には聞きづらいな', 4, 1, 1, 0, 0, 113601, 101, 4299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年との\\n海のバカンス…\\nまた行きたい\\nものだな', 8, 1, 1, 0, 0, 113601, 102, 4300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あまり見るのは\\nよしてくれ…\\n恥ずかしいじゃ\\nないか…', 1, 1, 2, 0, 0, 113601, 1, 4301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしたのかい？\\n私でよければ\\n話し相手くらいには\\nなろうじゃないか', 1, 1, 2, 0, 0, 113601, 2, 4302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっ！\\nす、すまない\\nちょっと過敏に\\nなっているようだ', 1, 1, 2, 0, 0, 113601, 3, 4303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…っくしゅん！\\nすまない\\n薄着には慣れて\\nないものでね', 1, 1, 2, 0, 0, 113601, 4, 4304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まあ、少年になら\\n見られても…\\nい、いや！\\nなんでもない！', 4, 1, 2, 0, 0, 113601, 101, 4305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私がこうして\\nゆっくりできるのは\\n少年がそばにいて\\nくれるからだよ', 8, 1, 2, 0, 0, 113601, 102, 4306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この時間なら\\nビーチにも人は\\n少ないだろうね…\\n遊びに行くかい？', 1, 1, 2, 0, 1, 113601, 1, 4307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食のお誘いかい？\\nいいよ、付き合おう', 1, 1, 2, 0, 2, 113601, 2, 4308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう夜か…\\n一日が経つのは\\nはやいものだね', 1, 1, 2, 0, 3, 113601, 3, 4309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは楽でいいな…\\nいつもは鎧姿で\\n家具を傷つけないか\\n気を使っているからね', 1, 1, 3, 0, 0, 113601, 2, 4311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん…ふわふわの\\n感触が\\nよくわかるな…', 1, 1, 3, 0, 0, 113601, 3, 4312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもは\\n鎧に匂いが\\n移ってしまうのが\\n悩みなんだよ…', 1, 1, 3, 0, 0, 113601, 4, 4313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーむ…\\n涼しいのに暖かい\\nなんだか奇妙な気分だ', 1, 1, 3, 0, 0, 113601, 5, 4314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兜を気にせず\\n食べられるのは\\n楽でいいな…', 1, 1, 3, 0, 0, 113601, 7, 4316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ…鎧がないと\\nページがめくりやすい', 1, 1, 3, 0, 0, 113601, 8, 4317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身軽でいいな…\\n鎧を着ていると\\n騎乗訓練の時\\n馬に申し訳がなくてね', 1, 1, 3, 0, 0, 113601, 10, 4319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貝をうまく使えば\\n水中でも\\n守りを固められそうだ', 1, 1, 3, 0, 0, 113601, 11, 4320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこをアジトと\\nつなげようかな～…\\nこのへんにしよっと♪', 1, 1, 1, 0, 0, 106801, 1, 4321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここってちょっと\\n変わった建物だね\\n妖精がいるでしょ？', 1, 1, 1, 0, 0, 106801, 2, 4322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('色んな人を観察できて\\n眼福眼福…♪', 1, 1, 1, 0, 0, 106801, 3, 4323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('家具の配置変更なら\\nアタシにおまかせあれ\\n…家の形は変えない？', 1, 1, 1, 0, 0, 106801, 4, 4324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新メニューどうしよう\\n思いついた人がいたら\\nアタシに教えてね！', 1, 1, 1, 0, 0, 106801, 5, 4325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年、早く帰って\\nこないかな…\\nよし、迎えに行こう！', 4, 1, 1, 0, 0, 106801, 101, 4326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('結局またあちこち\\n移動する日々だし…\\n少年に会いたいな～', 8, 1, 1, 0, 0, 106801, 102, 4327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どしたの少年？\\nお姉さんに何でも\\n相談してみな～？', 1, 1, 2, 0, 0, 106801, 1, 4328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あれをああして…\\nおや少年！\u3000ごめんね\\nすぐに気づけなくて！', 1, 1, 2, 0, 0, 106801, 2, 4329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何？\u3000クリスが\\nアタシを探してる？\\n…いないって言って！', 1, 1, 2, 0, 0, 106801, 3, 4330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よければリノちゃんと\\nシズルちゃんにも\\n顔を見せてあげて', 1, 1, 2, 0, 0, 106801, 4, 4331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年～！\\nもうヘトヘトだよ～！\\nお願い癒して～！', 4, 1, 2, 0, 0, 106801, 101, 4332);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…アタシが素直に\\n助けてって言えるのは\\n少年だけだよ', 8, 1, 2, 0, 0, 106801, 102, 4333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝だよ少年！\\n爽やかな朝の\\nクレープはいかが？', 1, 1, 2, 0, 1, 106801, 1, 4334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いたな～\\nお昼のクレープ\\n少年は食べる？', 1, 1, 2, 0, 2, 106801, 2, 4335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜までクレープは\\nやめとけ？\u3000ごめん\\nそれだけは無理…！', 1, 1, 2, 0, 3, 106801, 3, 4336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシこんなに\\nゆっくりしちゃって\\nいいんだっけ～？', 1, 1, 3, 0, 0, 106801, 2, 4338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…これ\\nネネカが変身\\nしてないよね？', 1, 1, 3, 0, 0, 106801, 3, 4339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだ…\\n解析完了\\n今度生成しようっと♪', 1, 1, 3, 0, 0, 106801, 4, 4340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('安心するな～…\\nアジトに置けないから\\n羨ましいよ', 1, 1, 3, 0, 0, 106801, 5, 4341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ物を消化するって\\n仕組み、どんなものか\\n気になる…', 1, 1, 3, 0, 0, 106801, 7, 4343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('速読できるけど\\n本を読む時くらい\\n文字にじっくり\\n浸かりたいんだよね…', 1, 1, 3, 0, 0, 106801, 8, 4344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルとして\\nみんなを元気に…！\\nアカリ、頑張ります♪', 1, 1, 1, 0, 0, 113701, 1, 4346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんと一緒に\\nお兄ちゃんを…えへへ\\nまだかな、お兄ちゃん', 1, 1, 1, 0, 0, 113701, 2, 4347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルの音色を\\n目指して、今日も\\nサックスの練習です♪', 1, 1, 1, 0, 0, 113701, 3, 4348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんとの特訓も\\n頑張らないと…\\n厳しくしてくださいね', 1, 1, 1, 0, 0, 113701, 4, 4349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいエンジェルの\\n格好、お兄ちゃんなら\\n喜んでくれますよね♪', 1, 1, 1, 0, 0, 113701, 5, 4350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルの力で\\nお兄ちゃんのハートも\\nイチコロですよ♪', 4, 1, 1, 0, 0, 113701, 101, 4351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリが一番\\n元気にしたいのは\\nお兄ちゃんですよ♪', 8, 1, 1, 0, 0, 113701, 102, 4352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん？\\n触りたいなら…\\nこことかどうですか♪', 1, 1, 2, 0, 0, 113701, 1, 4353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特訓の時間ですか？\\nアカリ、楽しみに\\nしてたんですよ♪', 1, 1, 2, 0, 0, 113701, 2, 4354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、お兄ちゃん！\\nそろそろアカリと\\n休憩…しませんか♪', 1, 1, 2, 0, 0, 113701, 3, 4355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この羽、触り心地\\nいいですか？\u3000あんっ\\nくすぐったいですよぉ', 1, 1, 2, 0, 0, 113701, 4, 4356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんも元気に\\nなりたいんですか？\\nアカリにお任せです♪', 4, 1, 2, 0, 0, 113701, 101, 4357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やんっ♪\\nお兄ちゃんったら\\nダイタンですね♪', 8, 1, 2, 0, 0, 113701, 102, 4358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、朝ですよ\\nすっごく気持ちのいい\\nお天気ですよ…♪', 1, 1, 2, 0, 1, 113701, 1, 4359);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼寝しませんか\\nお兄ちゃん？\\nアカリの膝枕で…♪', 1, 1, 2, 0, 2, 113701, 2, 4360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜ですね、お兄ちゃん\\nアカリ、なんだか胸が\\nドキドキしちゃいます', 1, 1, 2, 0, 3, 113701, 3, 4361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フカフカですね…\\n隣にお兄ちゃんが\\nいてくれたらなぁ…♪', 1, 1, 3, 0, 0, 113701, 2, 4363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ、アカリも\\nこんな風にかわいく\\nなりたいな～', 1, 1, 3, 0, 0, 113701, 3, 4364);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんが好きな\\n匂いなのかな？\\n参考にしますね！', 1, 1, 3, 0, 0, 113701, 4, 4365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体が火照ってきて\\nなんだかアカリ…\\nクラクラしちゃう…', 1, 1, 3, 0, 0, 113701, 5, 4366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむ、んぐ…あっ\\nほっぺについちゃった\\nベトベトですよぉ～', 1, 1, 3, 0, 0, 113701, 7, 4368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルって色んな\\n物語に出てきますよね\\nもっと調べなくちゃ！', 1, 1, 3, 0, 0, 113701, 8, 4369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの方の前では\\n常に気高く\\nありたいですわね', 12, 1, 1, 0, 0, 103201, 103, 4371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなに道に迷っても\\nあなたさまの元には\\n絶対に辿り着く\\n自信がありますわ', 12, 1, 2, 0, 0, 103201, 103, 4372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと一緒に\\nいるときが一番楽しい\\n一時かもしれないわ', 12, 1, 1, 0, 0, 102801, 103, 4373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかあんたと一緒に\\nサレンディア救護院を\\n切り盛り…なんてね♪', 12, 1, 2, 0, 0, 102801, 103, 4374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も\\nエンジェルとして、\\nみんなの幸せの\\nために頑張らないと', 1, 1, 1, 0, 0, 113801, 1, 4375);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかく羽が\\nついてるのに\\n飛べないのが残念だわ', 1, 1, 1, 0, 0, 113801, 2, 4376);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好、子供たちに\\n妙にウケがいいわね\\nま、悪くないけど', 1, 1, 1, 0, 0, 113801, 3, 4377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('や、やっぱりみんな\\n注目してくるわね…\\nエンジェルって珍しい\\nからしかたないか', 1, 1, 1, 0, 0, 113801, 4, 4378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルになると\\n人見知りがなおる！\\n…わけないか', 1, 1, 1, 0, 0, 113801, 5, 4379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルの活動は\\n大変だけど、自分が\\n成長してるって\\n実感がうれしいわね', 4, 1, 1, 0, 0, 113801, 101, 4380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし誰かの願いを\\nかなえられるなら\\n私はアイツの…\\nって何考えてるのよ！', 8, 1, 1, 0, 0, 113801, 102, 4381);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何ボサっとしてるの！\\nさあ、街に出て\\n人助けするわよ！', 1, 1, 2, 0, 0, 113801, 1, 4382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェリック\\nアロー！\\nなんてね…え、アンタ\\nいつから見てたのよ！', 1, 1, 2, 0, 0, 113801, 2, 4383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コラ！\\n羽は触らないで！\\n壊れたらどうするのよ', 1, 1, 2, 0, 0, 113801, 3, 4384);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルじゃなく\\nても、アンタはいつも\\n人助けしてるわよね\\n…ちょっと尊敬するわ', 1, 1, 2, 0, 0, 113801, 4, 4385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服なら他の子より\\n私を見てくれるかも…\\nって、な、何\\n見てるのよ！', 4, 1, 2, 0, 0, 113801, 101, 4386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、ねえ、もし私が\\n困ってたら、一番に\\n駆けつけて…やっぱり\\n何でもないわ！', 8, 1, 2, 0, 0, 113801, 102, 4387);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう…あ、あの、\\nエンジェルとして\\n町に行くんだけど…\\n一緒に行かない？', 1, 1, 2, 0, 1, 113801, 1, 4388);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ、いいことした\\n後のランチは\\nおいしいわね', 1, 1, 2, 0, 2, 113801, 2, 4389);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\n夜更かししてないで\\n早く寝なさいよね', 1, 1, 2, 0, 3, 113801, 3, 4390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい座り心地ね～\\nまさに天にも昇る\\n心地よさだわ～', 1, 1, 3, 0, 0, 113801, 2, 4392);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、かわいい…\\nあ、羽付けたら\\nもっとかわいく\\nなるんじゃないかな？', 1, 1, 3, 0, 0, 113801, 3, 4393);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～落ち着くわ～\\n回復アイテムみたいで\\n癒やされちゃうわ～', 1, 1, 3, 0, 0, 113801, 4, 4394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、とと…\\n危ない、羽が\\nこげちゃうところ\\nだったわ', 1, 1, 3, 0, 0, 113801, 5, 4395);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人の役に立つのって\\nすごく大変だから、\\nこれでライフ回復よ！', 1, 1, 3, 0, 0, 113801, 7, 4397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エンジェルに関する\\n本はあるかしら…あ！\\nこれ探してた攻略本！', 1, 1, 3, 0, 0, 113801, 8, 4398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっふっふ\\n吸血鬼らしく\\n驚かせてあげましょう', 1, 1, 1, 0, 0, 113901, 1, 4400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('獲物はどこですか～！\\nう～ん、もうちょっと\\n迫力が欲しいですね', 1, 1, 1, 0, 0, 113901, 2, 4401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トリックオアトリート\\n…返事がないので\\nイタズラしておきます', 1, 1, 1, 0, 0, 113901, 3, 4402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンですし\\nたまには騎士さんでも\\n誘ってあげますかね', 1, 1, 1, 0, 0, 113901, 4, 4403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マントは動きに\\nメリハリがついて\\nいいですね', 1, 1, 1, 0, 0, 113901, 5, 4404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('色んな仮装が見られて\\nやっぱりハロウィンは\\n最高ですね', 4, 1, 1, 0, 0, 113901, 101, 4405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼らしい行動って\\n噛みついたり…いや\\nそれは大胆過ぎです！', 8, 1, 1, 0, 0, 113901, 102, 4406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呼びましたか？\\n手短にお願いしますよ\\n忙しいんですから！', 1, 1, 2, 0, 0, 113901, 1, 4407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え？\u3000衣装に穴が？\\nありがとうございます\\n…よく見てるんですね', 1, 1, 2, 0, 0, 113901, 2, 4408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…吸血鬼の\\n姿でも、眠い時は\\n眠いんですよね…', 1, 1, 2, 0, 0, 113901, 3, 4409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンってライブ\\nとは違った賑やかさが\\nあってワクワクします', 1, 1, 2, 0, 0, 113901, 4, 4410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私を驚かそうとしても\\n無駄ですよ！\\nすぐ分かるんですから', 4, 1, 2, 0, 0, 113901, 101, 4411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さん、一緒に\\nハロウィンを…いいえ\\nなんでもないですっ！', 8, 1, 2, 0, 0, 113901, 102, 4412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事で寝不足だから\\n太陽がまぶしいです…\\n私、吸血鬼っぽいかも', 1, 1, 2, 0, 1, 113901, 1, 4413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯は真っ赤な…\\nトマト尽くしのお弁当\\nにしてみました', 1, 1, 2, 0, 2, 113901, 2, 4414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はハロウィンが\\n盛り上がる時間…\\n行きますよ騎士さん！', 1, 1, 2, 0, 3, 113901, 3, 4415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このフィット感\\nどうにか服作りにも\\n活かせれば…！', 1, 1, 3, 0, 0, 113901, 2, 4417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よく出来てますね…！\\nぬいぐるみの服を作る\\nのも楽しそうですね！', 1, 1, 3, 0, 0, 113901, 3, 4418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい感じですね…\\n服に合わせた香りって\\nいうのも、いいかも…', 1, 1, 3, 0, 0, 113901, 4, 4419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、温まりますね…\\nおっと、マントに火が\\n点いちゃいそうです！', 1, 1, 3, 0, 0, 113901, 5, 4420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あぁ、美味しい～\\n食べた分は、働いて\\n燃焼しますからね！', 1, 1, 3, 0, 0, 113901, 7, 4422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('伝説の吸血鬼…\\n夜を統べる者…\\nほうほう…', 1, 1, 3, 0, 0, 113901, 8, 4423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりハロウィンと\\nいえばお菓子です！\\nさぁ配りましょうか！', 1, 1, 3, 0, 0, 113901, 12, 4425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好…\\nカッコイイのに\\n動きやすくて\\n着心地も最高ッス！', 1, 1, 1, 0, 0, 114101, 1, 4427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キメポーズはこう…\\nいやこっちのほうが…\\nなやましいッス…！', 1, 1, 1, 0, 0, 114101, 2, 4428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トリックオア\\nジャスティス！\\nって言ったら何か\\nもらえるッスかね？', 1, 1, 1, 0, 0, 114101, 3, 4429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい必殺技の\\n特訓もしなくちゃ\\nいけないッスね…\\n忙しいッス！', 1, 1, 1, 0, 0, 114101, 4, 4430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分のこの姿\\nトモね～ちゃんにも\\nみせてあげるッス！', 1, 1, 1, 0, 0, 114101, 5, 4431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ホワイトタイガー\\n参上ッス！\\n今のポーズは\\nキマったッス！', 4, 1, 1, 0, 0, 114101, 101, 4432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人と一緒だと\\nほんとにヒーローに\\nなれる気がするッス！', 8, 1, 1, 0, 0, 114101, 102, 4433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうッスか？\\nこの色、自分に\\n似合ってるッスかね？', 1, 1, 2, 0, 0, 114101, 1, 4434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒマだったら\\n必殺技の特訓に\\n付き合ってもらって\\nいいッスか？', 1, 1, 2, 0, 0, 114101, 2, 4435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうどいいところに\\n来たッスね！\\nこのキメポーズ\\nどうッスか？', 1, 1, 2, 0, 0, 114101, 3, 4436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お！\u3000この格好、\\n気になるッスか？\\nじっくり見ても\\nいいッスよ♪', 1, 1, 2, 0, 0, 114101, 4, 4437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたも一緒に\\n新しい技の練習\\nどうッスか？', 4, 1, 2, 0, 0, 114101, 101, 4438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もあんたと一緒に\\nランドソルの平和を\\n守るッスよ！', 8, 1, 2, 0, 0, 114101, 102, 4439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ッス！\\n一緒に早朝特訓\\nやるッスよ！', 1, 1, 2, 0, 1, 114101, 1, 4440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼休憩ッス！\\nヒーローにも\\n休息は必要ッス！', 1, 1, 2, 0, 2, 114101, 2, 4441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('闇夜に映える\\n白い衣装で\\n平和を守るッスよ！', 1, 1, 2, 0, 3, 114101, 3, 4442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トラも狩りの時以外は\\nごろごろしてるって\\n本で読んだッスよー', 1, 1, 3, 0, 0, 114101, 2, 4444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もこもこッスね♪\\nこのかわいらしさを\\n守ってあげるのも\\nヒーローの役目ッス！', 1, 1, 3, 0, 0, 114101, 3, 4445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂いッスね…\\nリラックスして\\n瞑想するッス！', 1, 1, 3, 0, 0, 114101, 4, 4446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('燃える炎は\\nヒーローの心意気ッス\\nいつまでも\\n見てられるッスよ', 1, 1, 3, 0, 0, 114101, 5, 4447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nいっぱい食べて\\n強いヒーローに\\nなるッスよ！', 1, 1, 3, 0, 0, 114101, 7, 4449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんと勉強の本も\\n読んでるッスよ…！\\nヒーローには賢さも\\n必要らしいッス！', 1, 1, 3, 0, 0, 114101, 8, 4450);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わわっ、お菓子が\\nいっぱいッス！\\nみんなで\\n食べるッスよ！', 1, 1, 3, 0, 0, 114101, 12, 4452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシがチューシンと\\nなった今、天下統一は\\n目の前デス！', 12, 1, 1, 0, 0, 103001, 103, 4454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうショーグンってば\\nそれはセイシツに\\nすることデ～ス…', 12, 1, 2, 0, 0, 103001, 103, 4455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女幽霊…うらめしや…\\nうーん、これは\\nちょっと違う気が\\nするな…', 1, 1, 1, 0, 0, 114001, 1, 4456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何だか寒気がする…\\nま、まさか\\nこの部屋にも幽霊が？', 1, 1, 1, 0, 0, 114001, 2, 4457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンは楽しいね\\n童心に帰ったような\\n気分だよ', 1, 1, 1, 0, 0, 114001, 3, 4458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度のハロウィンは\\nユイとヒヨリを\\n誘ってみようかな', 1, 1, 1, 0, 0, 114001, 4, 4459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンのお菓子は\\nどれもかわいいね\\n…一つくらいなら\\nいいかな？', 1, 1, 1, 0, 0, 114001, 5, 4460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次は彼と\\nどんなハロウィンを\\n過ごそうかな…', 4, 1, 1, 0, 0, 114001, 101, 4461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな賑やかさも\\nいいものだね\\n彼といられるのなら\\nなおさら…', 8, 1, 1, 0, 0, 114001, 102, 4462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…いたずらしようと\\nしてない、キミ？\\nふふ、お見通しだよ', 1, 1, 2, 0, 0, 114001, 1, 4463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、私にもお菓子を？\\nありがとう…ふふ\\nうれしいものだね\\nハッピーハロウィン！', 1, 1, 2, 0, 0, 114001, 2, 4464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\n出かけるなら\\n私も同行しようか', 1, 1, 2, 0, 0, 114001, 3, 4465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好、舞踏会にも\\n出られそうだね\\n一曲、踊ってみる？', 1, 1, 2, 0, 0, 114001, 4, 4466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やるからには本気で\\nやらせてもらおう\\nトリックオア\\nトリート！', 4, 1, 2, 0, 0, 114001, 101, 4467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('他の子に目移りする\\nのも分かるが、その…\\nせっかくの特別な衣装\\n見てほしいな', 8, 1, 2, 0, 0, 114001, 102, 4468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝起きの体を\\n慣らしておこうか\\nほら、剣を取って', 1, 1, 2, 0, 1, 114001, 1, 4469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子もいいけど\\nちゃんと昼食も\\nとるんだよ', 1, 1, 2, 0, 2, 114001, 2, 4470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ、行こうか！\\nハロウィンは\\nこれからが本番だよ', 1, 1, 2, 0, 3, 114001, 3, 4471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンはまだ\\nこれからだ\\n一休みしようか', 1, 1, 3, 0, 0, 114001, 2, 4473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミたちも\\n仮装に興味は\\nあるかな？\u3000…ふふ', 1, 1, 3, 0, 0, 114001, 3, 4474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだけど\\n幽霊が集まったり\\nしないだろうか…？', 1, 1, 3, 0, 0, 114001, 4, 4475);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かい…一息ついたら\\nハロウィンの\\nパレードを\\n見に行こうかな', 1, 1, 3, 0, 0, 114001, 5, 4476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンを本気で\\n楽しむなら\\n食事もしっかり\\nとっておかないとね', 1, 1, 3, 0, 0, 114001, 7, 4478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンの\\nホラー小説か…\\nけ、結構\\n怖いものだね…？', 1, 1, 3, 0, 0, 114001, 8, 4479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子がいっぱいだ…\\nこういうのって\\n見ているだけで心が\\n躍ってしまうね', 1, 1, 3, 0, 0, 114001, 12, 4481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにかわいい\\n武器で戦えるとは…\\nすごいものだな\\n魔法少女は', 1, 1, 1, 0, 0, 114201, 1, 4483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('決めポーズの訓練も\\nしっかりやっておくか\\n…誰も見ていないな？', 1, 1, 1, 0, 0, 114201, 2, 4484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう格好は\\nユキあたりがすごく\\n似合いそうだな', 1, 1, 1, 0, 0, 114201, 3, 4485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちにサインを\\n求められてしまった…\\nこれもまた私の使命！', 1, 1, 1, 0, 0, 114201, 4, 4486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好は目立つな…\\nいや、提督とは人々の\\n視線を集めるものだ！', 1, 1, 1, 0, 0, 114201, 5, 4487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと作戦会議を\\nしておくか。あれで\\nなかなか頼れるからな', 4, 1, 1, 0, 0, 114201, 101, 4488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつには私の勇姿を\\nちゃんと見ていて\\nほしいものだな', 8, 1, 1, 0, 0, 114201, 102, 4489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一仕事終えたことだし\\n一緒に甘いものでも\\n食べに行くか？', 1, 1, 2, 0, 0, 114201, 1, 4490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪しげな気配がするな\\n貴公も警戒を\\n怠るなよ！', 1, 1, 2, 0, 0, 114201, 2, 4491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリに魔法少女の\\n本を借りたんだ\\n一緒に読まないか？', 1, 1, 2, 0, 0, 114201, 3, 4492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('巡回の時間まで\\nお茶にでもするか\\n貴公も付き合うがいい', 1, 1, 2, 0, 0, 114201, 4, 4493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公がサポートして\\nくれるのなら心強いな\\n頼りにしているぞ', 4, 1, 2, 0, 0, 114201, 101, 4494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭を撫でるな～！\\n…まったく、貴公だけ\\nだぞ、こんな風に私を\\n撫でてくるのは…', 8, 1, 2, 0, 0, 114201, 102, 4495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('起きろ貴公！\\n魔法少女の朝は\\n早いぞ！', 1, 1, 2, 0, 1, 114201, 1, 4496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほら、食後の\\nデザートだ\\nて、適度な糖分は\\n体に必要なんだ！', 1, 1, 2, 0, 2, 114201, 2, 4497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…魔法少女も…\\n眠気、には…い、いや\\n寝てないぞ！？', 1, 1, 2, 0, 3, 114201, 3, 4498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('任務や訓練で\\n疲れた体に\\nこれは効くなぁ…', 1, 1, 3, 0, 0, 114201, 2, 4500);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うむ、かわいいな\\nモーラのやつを隣に\\n並べようか', 1, 1, 3, 0, 0, 114201, 3, 4501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ、身も心も\\n安らぐ…\\nまるで魔法だな…', 1, 1, 3, 0, 0, 114201, 4, 4502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この温かさ…\\n愛と希望に\\n通じるものがある…', 1, 1, 3, 0, 0, 114201, 5, 4503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事の大切さは\\n魔法少女も軍人も\\n変わりない\\nしっかり食べるんだ！', 1, 1, 3, 0, 0, 114201, 7, 4505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の本を\\n読んでるのだが\\nわ、私もこんななのか', 1, 1, 3, 0, 0, 114201, 8, 4506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オラとあんちゃんは\\nボケもツッコミも\\nあうんの呼吸だべ♪', 12, 1, 1, 0, 0, 103301, 103, 4508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんと二人で\\nネタ合わせ…初めての\\n共同作業だべ♪', 12, 1, 2, 0, 0, 103301, 103, 4509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴっぷる！', 1, 1, 1, 0, 0, 192501, 1, 4510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴっぷるぴっぷる♪', 1, 1, 1, 0, 0, 192501, 2, 4511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴっ！', 1, 1, 1, 0, 0, 192501, 3, 4512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷっぷー', 1, 1, 1, 0, 0, 192501, 4, 4513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴぃ？', 1, 1, 1, 0, 0, 192501, 5, 4514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴっぷるんるん♪', 1, 1, 2, 0, 0, 192501, 1, 4515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷぅ！', 1, 1, 2, 0, 0, 192501, 2, 4516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴぴっ♪', 1, 1, 2, 0, 0, 192501, 3, 4517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷぅー…', 1, 1, 2, 0, 0, 192501, 4, 4518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゅ！', 1, 1, 2, 0, 1, 192501, 1, 4519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷはー', 1, 1, 2, 0, 2, 192501, 2, 4520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぴぇー', 1, 1, 2, 0, 3, 192501, 3, 4521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女になったら\\n髪型も変わるんだね\\n色々試してみようかな', 1, 1, 1, 0, 0, 114301, 1, 4531);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…煌く剣技で、\\n悪を断つ！\\nうん、今日も\\n完璧なポーズだね♪', 1, 1, 1, 0, 0, 114301, 2, 4532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミクマ流剣術で、\\n魔法少女の技に使え\\nそうなものは…よし、\\n早速試してみよっと♪', 1, 1, 1, 0, 0, 114301, 3, 4533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女になったから\\nには、サインの練習も\\nしないと…\\nよし、頑張るぞ！', 1, 1, 1, 0, 0, 114301, 4, 4534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の姿はすごく\\nかわいいけど…この\\n姿はジュンさんたちに\\n見せられないなぁ…', 1, 1, 1, 0, 0, 114301, 5, 4535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人は魔法少女\\nのこと好きなのかな？\\n…好きだったら\\nうれしいな♪', 4, 1, 1, 0, 0, 114301, 101, 4536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…やっぱり、\\nあの人がいないと\\n特訓に身が入らない…\\n早く帰ってこないかな', 8, 1, 1, 0, 0, 114301, 102, 4537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし時間があるなら、\\n私と街の見回りに\\n行かない？', 1, 1, 2, 0, 0, 114301, 1, 4538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、いいところに！\\n新しい魔法剣術を\\n編み出したから、\\n見てくれないかな？', 1, 1, 2, 0, 0, 114301, 2, 4539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の姿が気に\\nなるのは分かるけど…\\nず、ずっと見られる\\nのは照れるからやめて', 1, 1, 2, 0, 0, 114301, 3, 4540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身ポーズ中の動き、\\n少し変えた方が\\nいいかな…\\nあなたはどう思う？', 1, 1, 2, 0, 0, 114301, 4, 4541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よければ、\\n魔法少女の特訓に\\n付き合ってくれない？\\nその…二人きりでさ…', 4, 1, 2, 0, 0, 114301, 101, 4542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私…あなただけの\\n魔法少女になっても…\\nふふっ、な～んてね♪', 8, 1, 2, 0, 0, 114301, 102, 4543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もいい朝だね\\nさあ、一緒に\\n街の見回りに行こうか', 1, 1, 2, 0, 1, 114301, 1, 4544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう昼か…なにか\\n食べたいものある？\\n簡単なのでいいなら、\\n私が作ってあげるよ', 1, 1, 2, 0, 2, 114301, 2, 4545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ休もうか\\n…なんなら、添い寝\\nしてあげようか？\\nふふっ、冗談だよ♪', 1, 1, 2, 0, 3, 114301, 3, 4546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…\\n心身ともに安らぐね\\nなんだか\\n眠くなっちゃいそう', 1, 1, 3, 0, 0, 114301, 2, 4548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…これ、\\n魔法で動かせたり\\nしないかな？', 1, 1, 3, 0, 0, 114301, 3, 4549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだね\\nなんだか頭が冴えて\\nきたし、新しい技でも\\n考えようかな', 1, 1, 3, 0, 0, 114301, 4, 4550);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいな…\\nこの温もりは、\\n魔法少女の魔法でも\\n再現不可能だね…', 1, 1, 3, 0, 0, 114301, 5, 4551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これは…\\nおいしすぎて手が\\n止まらないかも', 1, 1, 3, 0, 0, 114301, 7, 4553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本の\\nキャラの動き、\\n変身ポーズの\\n参考にできるかも！', 1, 1, 3, 0, 0, 114301, 8, 4554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\nさあ、素敵な\\nパーティーを始めると\\nいたしましょう！', 1, 1, 1, 0, 0, 114401, 1, 4556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、\\nいくつになっても、\\nやはりクリスマスは、\\nワクワクしますわね♪', 1, 1, 1, 0, 0, 114401, 2, 4557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分で料理をしてみて\\nシェフたちのすごさが\\n改めて分かりましたわ', 1, 1, 1, 0, 0, 114401, 3, 4558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何事も自分で\\n体験してみると\\n新しい発見が\\nあるものですわね♪', 1, 1, 1, 0, 0, 114401, 4, 4559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やはり、クリスマスは\\n街が活発になり\\nますわね…これは、\\n絶好の商機ですわ♪', 1, 1, 1, 0, 0, 114401, 5, 4560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('他のクリスマス料理も\\n作れるようになったら\\nあのお方は食べて\\nくださるかしら…？', 4, 1, 1, 0, 0, 114401, 101, 4561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのお方に贈る\\nプレゼント…\\nこれはかなりの\\n難題ですわね…', 8, 1, 1, 0, 0, 114401, 102, 4562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\nよろしければ、一緒に\\nクリスマスの準備を\\nいたしませんか？', 1, 1, 2, 0, 0, 114401, 1, 4563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まあ、クリスマスの\\n飾りつけを手伝って\\nいただけるのですか？\\nありがとうございます', 1, 1, 2, 0, 0, 114401, 2, 4564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスに合わせて\\nあつらえた自慢の衣装\\nなのですが…その、\\nいかがでしょうか？', 1, 1, 2, 0, 0, 114401, 3, 4565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幼い頃はサンタさんが\\nいらっしゃるのを\\n待ちわびたものです\\n今は…内緒ですわ♪', 1, 1, 2, 0, 0, 114401, 4, 4566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、もしお時間が\\nあるようでしたら、\\nクリスマスの街を\\n一緒に歩きませんか？', 4, 1, 2, 0, 0, 114401, 101, 4567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年のクリスマスも\\nあのお方と一緒に\\n迎えられたら…', 8, 1, 2, 0, 0, 114401, 102, 4568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時は金なり…\\nせっかくの朝ですもの\\n時間を有効活用\\nいたしましょう！', 1, 1, 2, 0, 1, 114401, 1, 4569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼になりましたわね\\nさあ、\\nパーティーの準備を\\n進めますわよ！', 1, 1, 2, 0, 2, 114401, 2, 4570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('静かな夜ですわね…\\nもうちょっとだけ、\\nあなたさまとお話を\\nしていたい気分です', 1, 1, 2, 0, 3, 114401, 3, 4571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度な休息は\\n成功の秘訣ですわ！', 1, 1, 3, 0, 0, 114401, 2, 4573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このかわいらしさ…\\nいつまでも見て\\nいられそうですわ♪', 1, 1, 3, 0, 0, 114401, 3, 4574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人をもてなすには\\nこうしたところにも\\n気を配らないと\\nいけませんわね', 1, 1, 3, 0, 0, 114401, 4, 4575);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かい…\\nこういう憩いの\\nひと時こそ、大事に\\nしたいものですわね', 1, 1, 3, 0, 0, 114401, 5, 4576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この奥深い味わい…\\n何か隠し味など\\n使われていまして？', 1, 1, 3, 0, 0, 114401, 7, 4578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマス料理の\\nレシピも、\\nこれだけあると\\n迷ってしまいますわね', 1, 1, 3, 0, 0, 114401, 8, 4579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この絵本、とっても\\n面白いつくりですわね\\nうちの商品に\\nしたいぐらいですわ', 1, 1, 3, 0, 0, 114401, 14, 4581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これだけ大きな\\n着ぐるみ…\\n職人の技術が\\n光りますわね', 1, 1, 3, 0, 0, 114401, 15, 4582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスといえば\\nパーティーよね！\\nいっぱい飲むわよ～♪', 1, 1, 1, 0, 0, 114601, 1, 4583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私を麦しゅわだけの\\n女と思ったら\\n大間違いなんだから♪', 1, 1, 1, 0, 0, 114601, 2, 4584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスらしい\\n飲み物も結構いいわね\\n私も今度\\n作ってみようかしら', 1, 1, 1, 0, 0, 114601, 3, 4585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かい部屋で飲む\\n麦しゅわも\\nまた格別なのよね…', 1, 1, 1, 0, 0, 114601, 4, 4586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はオフの日だし\\n朝から飲んでも\\n怒られないわよね？', 1, 1, 1, 0, 0, 114601, 5, 4587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスの\\nデートスポットで\\n彼と一緒に…ってなに\\n考えてるのユカリ！？', 4, 1, 1, 0, 0, 114601, 101, 4588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('背伸びしなくても\\nありのままの自分を\\n受け入れてくれるって\\nすごく…幸せ…', 8, 1, 1, 0, 0, 114601, 102, 4589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大丈夫よ～\\n飲んでない\\n飲んでないひゃら～', 1, 1, 2, 0, 0, 114601, 1, 4590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスは\\n特別だもの\\n特別な一杯を\\n飲まないとね♪', 1, 1, 2, 0, 0, 114601, 2, 4591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマース！\\nほらほらぁ\\n乾杯しましょ♪', 1, 1, 2, 0, 0, 114601, 3, 4592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉さんの\\n頼れるところ\\n見せてあげるわね', 1, 1, 2, 0, 0, 114601, 4, 4593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何かあったら\\n頼ってくれても\\nいいんだからね？', 4, 1, 2, 0, 0, 114601, 101, 4594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…これからも\\nキミのこと…\\n頼りにしちゃうからね', 8, 1, 2, 0, 0, 114601, 102, 4595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さわやかな朝ね\\n…二日酔いがないと\\n朝ってこんなに\\n気持ちいいのね', 1, 1, 2, 0, 1, 114601, 1, 4596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼間から飲むのって\\nまた格別よね…って\\nガマン、ガマンよ…', 1, 1, 2, 0, 2, 114601, 2, 4597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間かあ…\\nあとは寝るだけだし\\nちょっとくらいは…', 1, 1, 2, 0, 3, 114601, 3, 4598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ゴロゴロするのって\\n最高ね～\\nあとは麦しゅわが\\nあればなぁ', 1, 1, 3, 0, 0, 114601, 2, 4600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私だって…\\nかわいいものは\\n好きでいいわよね？', 1, 1, 3, 0, 0, 114601, 3, 4601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んっ～…いい香りね\\n日頃の疲れが\\n取れる気がするわ', 1, 1, 3, 0, 0, 114601, 4, 4602);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカする～\\n…なんだかのどが\\nかわいてきたわね', 1, 1, 3, 0, 0, 114601, 5, 4603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…労働の\\n後のご飯はやっぱり\\nおいしいわぁ…', 1, 1, 3, 0, 0, 114601, 7, 4605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスデート\\n完全攻略マニュアル？\\n…読んでおかなくちゃ', 1, 1, 3, 0, 0, 114601, 8, 4606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、絵が飛び出して\\n見えるけど…\\n酔っ払ってるせいじゃ\\nないわよね…？', 1, 1, 3, 0, 0, 114601, 14, 4608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい手触りね～\\nウチにもほしいけど\\n麦しゅわをこぼしたら\\n大変そうだわ…', 1, 1, 3, 0, 0, 114601, 15, 4609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイの視線\\nずっと独り占め\\nしてたいな～', 12, 1, 1, 0, 0, 101601, 103, 4610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイといるだけで\\nうち、おに楽しいし！\\nヒデサイもっしょ～？', 12, 1, 2, 0, 0, 101601, 103, 4611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\nふふ、口にするだけで\\n何だか楽しくなるわね', 1, 1, 1, 0, 0, 114501, 1, 4612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもは子どもたちを\\n見守る方だけど\\n今ははしゃいでも\\nいいわよね？', 1, 1, 1, 0, 0, 114501, 2, 4613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ツリーや料理\\nそしてプレゼント！\\nいくつになっても\\nやっぱり心躍るわね♪', 1, 1, 1, 0, 0, 114501, 3, 4614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('飾り付けも料理も\\nいいセンスしてるわね\\n救護院のパーティーの\\n参考にさせてもらうわ', 1, 1, 1, 0, 0, 114501, 4, 4615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('焼きそばパンを\\nクリスマスの定番に\\nするにはどうすれば…', 1, 1, 1, 0, 0, 114501, 5, 4616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、あいつの\\n好きそうな料理だわ\\n取っといて食べさせて\\nあげようかしら♪', 4, 1, 1, 0, 0, 114501, 101, 4617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつのプレゼント\\nちょっとだけ奮発\\nしたのよね…\\n喜んでくれるかしら', 8, 1, 1, 0, 0, 114501, 102, 4618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このドレス\\n似合ってるかしら？\\n今だけは見とれても\\n許してあげるわ♪', 1, 1, 2, 0, 0, 114501, 1, 4619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見て、このケーキ！\\nおいしそうでしょ\\nたまにはこんな贅沢も\\nいいわよね♪', 1, 1, 2, 0, 0, 114501, 2, 4620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理も飲み物も\\nおいしいわね！\\nいっぱい食べて\\n元を取らないと♪', 1, 1, 2, 0, 0, 114501, 3, 4621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちと一緒に\\n雪遊び、楽しそうね\\nあんたもどう？', 1, 1, 2, 0, 0, 114501, 4, 4622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの\\nクリスマスなんだもの\\nエスコート\\nよろしくね♪', 4, 1, 2, 0, 0, 114501, 101, 4623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒い？\u3000そう…\\nなら、もっとこっち\\n来ていいわよ…？', 8, 1, 2, 0, 0, 114501, 102, 4624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほら、早く起きて？\\nパーティー用の\\n買い出しに\\n付き合ってちょうだい', 1, 1, 2, 0, 1, 114501, 1, 4625);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パーティーの料理の\\n準備をしながらお昼も\\n作っておいたわ\\n我ながらいい手際ね', 1, 1, 2, 0, 2, 114501, 2, 4626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にぎやかなパーティー\\nもいいけど、聖夜の\\n余韻を感じるのも\\n結構素敵ね', 1, 1, 2, 0, 3, 114501, 3, 4627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい座り心地だわ～\\n腕のいい職人の仕事ね\\nうちでも扱いたいわ', 1, 1, 3, 0, 0, 114501, 2, 4629);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい！\\n子どもたちに\\nプレゼントしたら\\n喜んでくれるかも', 1, 1, 3, 0, 0, 114501, 3, 4630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('華やかな香りね\\nクリスマスに\\nピッタリだわ', 1, 1, 3, 0, 0, 114501, 4, 4631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒い日にはやっぱり\\nこれよね…\\nはぁ、極楽極楽♪', 1, 1, 3, 0, 0, 114501, 5, 4632);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー、おいしいわ！\\n焼きそばパン味の\\nものも、作れない\\nかしら？', 1, 1, 3, 0, 0, 114501, 7, 4634);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにはのんびり\\n読書でも…なんだか\\nラブロマンスばかりね\\nクリスマスだから？', 1, 1, 3, 0, 0, 114501, 8, 4635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、面白いわね！\\n子どもたちの\\nプレゼントに\\nピッタリだわ', 1, 1, 3, 0, 0, 114501, 14, 4637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんないい毛並み\\n初めて見るわ…\\n一体どこで手に\\n入るのかしら？', 1, 1, 3, 0, 0, 114501, 15, 4638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシもみんなと\\n一緒に正月を\\n楽しんでいいのか？', 1, 1, 1, 0, 0, 114701, 1, 4639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年こそ、もう少し\\n身長が伸びます\\nように…', 1, 1, 1, 0, 0, 114701, 2, 4640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('げっ！\u3000お年玉が\\n全然残ってないぞ！？\\nそんな、嘘だろ…？', 1, 1, 1, 0, 0, 114701, 3, 4641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大勢で過ごす\\n正月か…初めてだけど\\n悪くないもんだな', 1, 1, 1, 0, 0, 114701, 4, 4642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー…ここじゃ\\n天楼覇断剣の\\n出番はなさそうだな', 1, 1, 1, 0, 0, 114701, 5, 4643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツらと作る\\n戦い以外の思い出も\\nもっと増やしたいな', 4, 1, 1, 0, 0, 114701, 101, 4644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなに賑やかな\\n正月は初めてだ\\n…温かくて、いいな', 8, 1, 1, 0, 0, 114701, 102, 4645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('記憶がなくったって\\n楽しい思い出は\\n新しく作れるよな？', 1, 1, 2, 0, 0, 114701, 1, 4646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早くでかけるぞ！\\nアタシはもっと\\n正月を楽しみたい！', 1, 1, 2, 0, 0, 114701, 2, 4647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なあ、オマエはもう\\nノウェムって名前\\n覚えてくれたよな？', 1, 1, 2, 0, 0, 114701, 3, 4648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服、アタシに\\n似合ってるのか？\\n…そっか。\\nありがとな！', 1, 1, 2, 0, 0, 114701, 4, 4649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエらと見た朝日は\\nきっと忘れないぞ！\\n思い出ができたな！', 4, 1, 2, 0, 0, 114701, 101, 4650);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかオクトーも\\n一緒に、みんなで\\n正月を過ごせたらな…', 8, 1, 2, 0, 0, 114701, 102, 4651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝から元気だな！\\nアタシもいっちょ\\n見習ってみるか！', 1, 1, 2, 0, 1, 114701, 1, 4652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯は何にする？\\n正月はうまいものが\\n多くて迷うよな！', 1, 1, 2, 0, 2, 114701, 2, 4653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい夜だな！\\nアタシと一緒に\\n夜更かしを楽しむか？', 1, 1, 2, 0, 3, 114701, 3, 4654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月らしく、たまには\\nゆっくりするのも\\nいいかもな…', 1, 1, 3, 0, 0, 114701, 2, 4656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだ？\\nオマエも初詣に\\n行きたいのか？', 1, 1, 3, 0, 0, 114701, 3, 4657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すーはー…\\n神殿のニオイがするな\\nいい事ありそうだ！', 1, 1, 3, 0, 0, 114701, 4, 4658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コイツがあれば\\nうまい魚が\\n焼けそうだな…', 1, 1, 3, 0, 0, 114701, 5, 4659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ううー\\n食べ過ぎて帯が\\nきつくなってきたぞ…', 1, 1, 3, 0, 0, 114701, 7, 4661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おみくじって\\n書いてあることが\\nむずかしいんだよな…', 1, 1, 3, 0, 0, 114701, 8, 4662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('困ってる人は\\nいないみたいだし…\\nちょっとここで、\\n特訓しようかな♪', 1, 1, 1, 0, 0, 180101, 1, 4664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('空が飛べるんだから\\nもっとたくさんの人を\\n助けにいけちゃう！\\n…ここじゃ飛べないや', 1, 1, 1, 0, 0, 180101, 2, 4665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('炎の翼\\nかっこいいなー！\\nこれ、もっと大きく\\nできないのかな？', 1, 1, 1, 0, 0, 180101, 3, 4666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり変身すると\\nお腹すくんだね…\\n…今ならペコさんの\\n食欲の理由が分かるよ', 1, 1, 1, 0, 0, 180101, 4, 4667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('色なんかは違うけど…\\nマントがあるから\\n騎士くんとお揃いに\\nなったみたい♪', 1, 1, 1, 0, 0, 180101, 5, 4668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…騎士くんがいないと\\nなんか調子でない…\\n早く会いたいよぉ…', 4, 1, 1, 0, 0, 180101, 101, 4669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿になると、\\n騎士くんを近くに\\n感じる…なんだろ\\nドキドキしちゃう…', 8, 1, 1, 0, 0, 180101, 102, 4670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くん騎士くん！\\n今大丈夫？\\nトレーニングメニュー\\n考えるの手伝って！', 1, 1, 2, 0, 0, 180101, 1, 4671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…うにゃっ！？\\nこ、この姿になっても\\n尻尾は触っちゃ\\nダメー！', 1, 1, 2, 0, 0, 180101, 2, 4672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして、この服が\\n気になってるの？\\nだったら、もっと\\n近くで見ていいよ♪', 1, 1, 2, 0, 0, 180101, 3, 4673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、騎士くん！\\n困ってる人がいないか\\n見回りに行くんだけど\\nついてきて欲しいな！', 1, 1, 2, 0, 0, 180101, 4, 4674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('耳に触りたいの？\\nだったら頭もなでて！\\nそしたら、好きなだけ\\n触っていいよ♪', 4, 1, 2, 0, 0, 180101, 101, 4675);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あたし、強くなって\\n騎士くんを守るよ！\\nだから…これからも\\n一緒にいていい？', 8, 1, 2, 0, 0, 180101, 102, 4676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっはよー！\\nさあさあ騎士くん！\\n今日も一緒に\\nはりきっていこー♪', 1, 1, 2, 0, 1, 180101, 1, 4677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼、お昼～♪\\n今日のご飯は何かな～\\nあ、騎士くん！\\n早くお昼食べ行こ！', 1, 1, 2, 0, 2, 180101, 2, 4678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もお疲れ様ー！\\n騎士くん、あたしが\\nマッサージしよっか？\\n結構評判なんだよ！', 1, 1, 2, 0, 3, 180101, 3, 4679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うにゃぁ…\\nこの気持ちよさ…\\n溶けちゃいそう…\\nにゃぁ…', 1, 1, 3, 0, 0, 180101, 2, 4681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい～\\nこれ、なでなで\\nしていいんだよね…？\\nよしよし…♪', 1, 1, 3, 0, 0, 180101, 3, 4682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とってもいい香り！\\n気分も落ち着くし、\\n特訓の後なんかに\\nいいかもー！', 1, 1, 3, 0, 0, 180101, 4, 4683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬくぬくだぁ…\\nなんだか、\\nふにゃふにゃに\\nなっちゃうよぉ…', 1, 1, 3, 0, 0, 180101, 5, 4684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、おいひぃ…！\\nこの姿になると\\nお腹すくし、すっごく\\n助かっちゃった！', 1, 1, 3, 0, 0, 180101, 7, 4686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本で勉強して、\\nぶんぶりょーどーの\\n超ウルトラヒヨリに\\nなっちゃうぞー！', 1, 1, 3, 0, 0, 180101, 8, 4687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年もみんなで\\nおいしいものを\\nたくさん食べたいです', 1, 1, 1, 0, 0, 111801, 1, 4689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('挑戦は大切ですよね☆\\nというわけで\\nおせちに魔物を…', 1, 1, 1, 0, 0, 111801, 2, 4690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせちは縁起物です！\\n食べれば食べるほど\\n幸せになるはずです！', 1, 1, 1, 0, 0, 111801, 3, 4691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ物がたくさん\\n入った福袋は\\nないんでしょうか…？', 1, 1, 1, 0, 0, 111801, 4, 4692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初詣で何を\\nお願いしましょう…\\n五穀豊穣？', 1, 1, 1, 0, 0, 111801, 5, 4693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずっとこうして\\n年の始まりを\\n過ごしたいですね', 4, 1, 1, 0, 0, 111801, 101, 4694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか二人きりで\\n初日の出を\\n見たいです', 8, 1, 1, 0, 0, 111801, 102, 4695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お餅おかわりです！\\nいくらでも\\n食べられますよ！', 1, 1, 2, 0, 0, 111801, 1, 4696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせちの食材を\\n取りに行きませんか？\\nいい運動です☆', 1, 1, 2, 0, 0, 111801, 2, 4697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('凧揚げって\\n難しいですね～\\n糸が絡まっちゃいます', 1, 1, 2, 0, 0, 111801, 3, 4698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一年の計は元旦にあり\\n今年一年分の\\n献立を作りましょう！', 1, 1, 2, 0, 0, 111801, 4, 4699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほらほら！\\nもっと近くで着物を\\n見ていいんですよ☆', 4, 1, 2, 0, 0, 111801, 101, 4700);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたはどんな\\n初夢を見ましたか？\\nわたしは…内緒です☆', 8, 1, 2, 0, 0, 111801, 102, 4701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年明けの朝は\\n心なしか\\n気持ちいいですね☆', 1, 1, 2, 0, 1, 111801, 1, 4702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お雑煮のあとは\\nおしるこで\\nおやつタイムです！', 1, 1, 2, 0, 2, 111801, 2, 4703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたたかくして\\n幸せな初夢を\\n見ましょうね', 1, 1, 2, 0, 3, 111801, 3, 4704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～屋台巡りを\\n満喫しました☆\\n一休み一休み', 1, 1, 3, 0, 0, 111801, 2, 4706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('縁起のいい\\nぬいぐるみを並べて\\n福を呼びましょう！', 1, 1, 3, 0, 0, 111801, 3, 4707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おしるこのアロマって\\nないんでしょうか？\\nそれなら作るしか…', 1, 1, 3, 0, 0, 111801, 4, 4708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでお餅を\\n焼いたらおいしく\\nなりそうですね～♪', 1, 1, 3, 0, 0, 111801, 5, 4709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしすぎて\\n食べる手が\\n止まりません～', 1, 1, 3, 0, 0, 111801, 7, 4711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいおせち料理の\\nヒントは…なるほど…\\nふむふむ…', 1, 1, 3, 0, 0, 111801, 8, 4712);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんとあんな\\n特訓やこんな特訓が\\nしたいなぁ、えへへ♪', 12, 1, 1, 0, 0, 100601, 103, 4714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに褒めて\\nもらうと、身体が\\nじぃーんと\\n熱くなっちゃいます♪', 12, 1, 2, 0, 0, 100601, 103, 4715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見目麗しい衣装に\\n身を包むのも\\n悪い気分では\\nありませんね', 1, 1, 1, 0, 0, 115001, 1, 4716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('縁起物で\\n験を担ぐというのも\\nたまにはよいでしょう', 1, 1, 1, 0, 0, 115001, 2, 4717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('非効率なので\\nあまり行いませんが\\n私も手料理くらいは\\n作れるのですよ', 1, 1, 1, 0, 0, 115001, 3, 4718);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('研究のためなら\\n時に遠路を超え\\n実地へ赴くことも\\n必要なのです', 1, 1, 1, 0, 0, 115001, 4, 4719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トゥンヌスの\\n突然変異…\\n大いに興味を\\nそそられますね', 1, 1, 1, 0, 0, 115001, 5, 4720);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('漁師の技法も\\n再現できたことで\\nまた一つ、仮説が\\n実証できました', 4, 1, 1, 0, 0, 115001, 101, 4721);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月くらいは\\n私ものんびりしたい\\n気持ちなのですよ\\n意外ですか？', 8, 1, 1, 0, 0, 115001, 102, 4722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('模倣に頼らずとも\\n衣装に合わせた\\n所作程度は\\nできて当然です', 1, 1, 2, 0, 0, 115001, 1, 4723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お年玉の使い道は\\n思いつきましたか\\nゆっくり考えても\\nいいのですよ', 1, 1, 2, 0, 0, 115001, 2, 4724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トランプでも花札でも\\n相手をしましょう\\n手心が必要なら\\nいつでも言いなさい', 1, 1, 2, 0, 0, 115001, 3, 4725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初詣でお祈りする\\n内容ですか\\n…ヒミツ、として\\nおきましょう', 1, 1, 2, 0, 0, 115001, 4, 4726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちでオーマ中の\\nトゥンヌスを\\n釣り上げましょうか\\n…冗談ですよ', 4, 1, 2, 0, 0, 115001, 101, 4727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見返りを求めない願い\\nそれは祈りに通じるの\\nかもしれませんね', 8, 1, 2, 0, 0, 115001, 102, 4728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…貴方がその眠たげな\\n顔を洗ってくる間に、\\n温かいお茶でも\\n淹れておきましょう', 1, 1, 2, 0, 1, 115001, 1, 4729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、本格的に\\n活動を再開します\\n貴方も同行しなさい\\n昼食は済みましたか？', 1, 1, 2, 0, 2, 115001, 2, 4730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私はもう少し\\n作業を片付けてから\\n寝ることにします\\n早く眠りなさい', 1, 1, 2, 0, 3, 115001, 3, 4731);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し休みます…\\n時間が来たら\\n起こすように', 1, 1, 3, 0, 0, 115001, 2, 4733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('贈り物を模倣して\\n潜入…試してみる\\n価値はありそうですね', 1, 1, 3, 0, 0, 115001, 3, 4734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('嗅覚から得られる\\n情報量は侮れません\\n動物の模倣において\\n注意すべき点ですよ', 1, 1, 3, 0, 0, 115001, 4, 4735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('穏やかな炎による\\nリラックス効果は\\n本能によるものかも\\nしれませんね', 1, 1, 3, 0, 0, 115001, 5, 4736);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いかなる強者でも\\n兵站、補給は\\n必要なものです', 1, 1, 3, 0, 0, 115001, 7, 4738);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらゆる学問は\\n完璧な模倣のための\\n大きな礎となります', 1, 1, 3, 0, 0, 115001, 8, 4739);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新たに得たこの力で\\n仲間と目指す未来を\\n切り拓いてみせます', 1, 1, 1, 0, 0, 115501, 1, 4741);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは、みなさまと…\\nわたくしの\\n帰る場所でございます', 1, 1, 1, 0, 0, 115501, 2, 4742);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまも精霊の召喚を\\n試してみますか？', 1, 1, 1, 0, 0, 115501, 3, 4743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま、おこづかいは\\n足りていますか？\\n遠慮は無用ですよ', 1, 1, 1, 0, 0, 115501, 4, 4744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この装束をまとうと\\n自然と背筋が伸びる\\n思いがいたします', 1, 1, 1, 0, 0, 115501, 5, 4745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('進化した精霊に\\n負けぬよう\\n修行に励みます', 4, 1, 1, 0, 0, 115501, 101, 4746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間たちといられる\\nこの幸せが、末永く\\n続きますように…', 8, 1, 1, 0, 0, 115501, 102, 4747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまのお手手は\\n大きくて温かいですね\\nぎゅっぎゅっ…ふふ♪', 1, 1, 2, 0, 0, 115501, 1, 4748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、主さまにも\\n里に伝わる昔話を\\nお話しいたしましょう', 1, 1, 2, 0, 0, 115501, 2, 4749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('里で採れた果物を\\n持って参りました\\n召し上がってください', 1, 1, 2, 0, 0, 115501, 3, 4750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('里のお土産を\\nここのみなさまに\\nお配りいたしましょう', 1, 1, 2, 0, 0, 115501, 4, 4751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間と囲む食卓…この\\n温もりは、みなさまの\\n心の温かさなのですね', 4, 1, 2, 0, 0, 115501, 101, 4752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまに名前を\\n呼んでいただくと\\n心が温かくなります♪', 8, 1, 2, 0, 0, 115501, 102, 4753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ…主さま\\n寝癖がついて\\nおりますよ？', 1, 1, 2, 0, 1, 115501, 1, 4754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の昼食は\\n里の伝統料理です\\nお口に合うでしょうか', 1, 1, 2, 0, 2, 115501, 2, 4755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまが眠れるよう\\n安らぎの風を…\\nおやすみなさいませ', 1, 1, 2, 0, 3, 115501, 3, 4756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この癒し…\\n主さまにも味わって\\nいただきたい…', 1, 1, 3, 0, 0, 115501, 2, 4758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この愛らしさ…\\n精霊たちと似たものを\\n感じます…♪', 1, 1, 3, 0, 0, 115501, 3, 4759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('精霊よ…この安らぐ\\n香りを、隅々まで\\n届けてくださいまし', 1, 1, 3, 0, 0, 115501, 4, 4760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('瞑想するのに\\nちょうどよい暖かさで\\nございます', 1, 1, 3, 0, 0, 115501, 5, 4761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('進化した精霊を\\n使役するためにも\\nよく食べて体力を…！', 1, 1, 3, 0, 0, 115501, 7, 4763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風の精霊について\\nもっと詳しく知って\\nおかなければ…', 1, 1, 3, 0, 0, 115501, 8, 4764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('儀式の時を思い出して\\n精霊に呼びかける…\\n出ておいで～♪', 1, 1, 1, 0, 0, 115601, 1, 4766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃうっ！\u3000もう…\\n急に背中を触るなんて\\nいたずら好きな精霊に\\n育てた覚えはないのに', 1, 1, 1, 0, 0, 115601, 2, 4767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('儀式用の衣装…\\nあんまり激しい動きは\\nできないよね…でも\\n戦う時は気にしない！', 1, 1, 1, 0, 0, 115601, 3, 4768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ…精霊に\\n騎士クンのそばで\\n見守っていてって\\n頼んでみようかな…', 1, 1, 1, 0, 0, 115601, 4, 4769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、こうやって、\\n楽しく精霊とお話し\\nしていられる、平穏な\\n日々が続くといいな', 1, 1, 1, 0, 0, 115601, 5, 4770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('き、きき、騎士クン！\\nわたしと、あの…！\\nうう…練習ですら\\n上手く誘えないよぉ…', 4, 1, 1, 0, 0, 115601, 101, 4771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、精霊が…\\nふふ、応援ありがとう\\nわたしの想い…いつか\\n必ず伝えるね', 8, 1, 1, 0, 0, 115601, 102, 4772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しく覚えた料理\\n作ってみたんだけど\\n騎士クンも食べない？', 1, 1, 2, 0, 0, 115601, 1, 4773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン、\\n疲れてない？\\nわたしと精霊で\\n治療するよ？', 1, 1, 2, 0, 0, 115601, 2, 4774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう、いたずらしない\\n…騎士クン！？\\nご、ごめんなさい！\\n精霊だと思って！', 1, 1, 2, 0, 0, 115601, 3, 4775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン！\\n時間が合ったら、\\n精霊と一緒に\\nお話しない？', 1, 1, 2, 0, 0, 115601, 4, 4776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…こういう服着るの\\n初めてなんだけど…\\nえっ、かわいい…？\\nあ、ありがとう…！', 4, 1, 2, 0, 0, 115601, 101, 4777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('困ったことがあったら\\n相談してね。わたし、\\n騎士クンのためなら…\\n色々できるよ、色々！', 8, 1, 2, 0, 0, 115601, 102, 4778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう騎士クン！\\n今からお外で\\n瞑想するんだけど…\\n騎士クンもどうかな？', 1, 1, 2, 0, 1, 115601, 1, 4779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼の時間だ\\nご飯ならわたしが\\n用意するから\\nゆっくりしてて', 1, 1, 2, 0, 2, 115601, 2, 4780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\n騎士クン、はいどうぞ\\n寝る前の温かいミルク\\nぐっすり眠れるよ♪', 1, 1, 2, 0, 3, 115601, 3, 4781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…うん、落ち着く\\n精霊との魔法で\\nこんな風に誰かを\\n安心させたいな', 1, 1, 3, 0, 0, 115601, 2, 4783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい…\\n精霊も気に入ってる…\\nそうだ、同じ物\\n作ってあげようかな？', 1, 1, 3, 0, 0, 115601, 3, 4784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…これ、\\nうちに置いたら、\\nお母さん喜ぶかも！', 1, 1, 3, 0, 0, 115601, 4, 4785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\nまるで誰かが\\n抱きしめてくれた\\nみたい…', 1, 1, 3, 0, 0, 115601, 5, 4786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自然の恵みに\\n感謝して…\\nいただきます♪', 1, 1, 3, 0, 0, 115601, 7, 4788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっと精霊について\\n勉強して、みんなを\\n守れるように\\nなりたいな…', 1, 1, 3, 0, 0, 115601, 8, 4789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツといると胸が\\nぎゅーっとなる…\\nこれってもしかして…', 12, 1, 1, 0, 0, 102201, 103, 4791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタとならきっと\\nどんなゲームでも…\\nそ、その、たた、\\n楽しいって思えるわ！', 12, 1, 2, 0, 0, 102201, 103, 4792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('色んな人と話したら\\n記憶探しの手がかりが\\n見つかるかも…？', 1, 1, 1, 0, 0, 106401, 1, 4793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイスクリームでも\\n作ろうかしら？\\nバニラにミントに…', 1, 1, 1, 0, 0, 106401, 2, 4794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネビアに話しかけると\\n逃げられるのよね…\\nもう、襲わないのに…', 1, 1, 1, 0, 0, 106401, 3, 4795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「コッコロさん」、\\n「コッコロさん」…\\n…間違えないように…', 1, 1, 1, 0, 0, 106401, 4, 4796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近少し太ったかも？\\nきっとおいしいもの、\\n食べ過ぎね…', 1, 1, 1, 0, 0, 106401, 5, 4797);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいると、\\nとても落ち着くわ…\\n自分の家、だものね', 4, 1, 1, 0, 0, 106401, 101, 4798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなと一緒の時間、\\nずっと記憶に残したい\\n…そう思っているのよ', 8, 1, 1, 0, 0, 106401, 102, 4799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドラゴン族って、\\nそんなに珍しいの？\\nあまり実感ないけど…', 1, 1, 2, 0, 0, 106401, 1, 4800);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理、練習してるのよ\\n…味見してもらえる？\\n期待はしないでね', 1, 1, 2, 0, 0, 106401, 2, 4801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭を叩いたら、\\n記憶が戻ったり\\nしないかしら…？\\nやらなくていいわよ？', 1, 1, 2, 0, 0, 106401, 3, 4802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('赤ちゃんみたいだった\\n時のことは、忘れて…\\nお願いだから…', 1, 1, 2, 0, 0, 106401, 4, 4803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃんっ！？\\nし、しっぽを掴むのは\\nダメよ？', 4, 1, 2, 0, 0, 106401, 101, 4804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('記憶が戻っても…\\n私は、あなたたちと\\n一緒にいたいわ', 8, 1, 2, 0, 0, 106401, 102, 4805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう。\\n寝ぐせついてるわよ？\\n…ふふっ、これでよし', 1, 1, 2, 0, 1, 106401, 1, 4806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろお昼かしら？\\nおいしいごはんを、\\nみんなで一緒に…ね', 1, 1, 2, 0, 2, 106401, 2, 4807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間ね。\\nそろそろ休みましょ？\\n…ふわぁ…', 1, 1, 2, 0, 3, 106401, 3, 4808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか、ぎゅう～…\\n…あっ、これはその…\\nストレッチしててっ…', 1, 1, 3, 0, 0, 106401, 2, 4810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あまり、興味ないわ。\\nけど…けど…\\n…か、かわいい…', 1, 1, 3, 0, 0, 106401, 3, 4811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね。\\nとっても落ち着くわ…\\n…っくしゅっ', 1, 1, 3, 0, 0, 106401, 4, 4812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷やす方が得意だけど\\nあったかいのも、\\nキライじゃないのよ', 1, 1, 3, 0, 0, 106401, 5, 4813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('別に、食いしん坊\\nじゃないのよ？\\nでも、もう一口だけ…', 1, 1, 3, 0, 0, 106401, 7, 4815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん…なるほどね。\\n勉強になるわ…', 1, 1, 3, 0, 0, 106401, 8, 4816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着の探偵か…\\nちょっと恥ずかしい\\n気がしてきたよ…', 1, 1, 1, 0, 0, 115701, 1, 4818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('依頼があれば\\n海でも山でも\\n赴くさ！', 1, 1, 1, 0, 0, 115701, 2, 4819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今のうちに\\n助手くんの秘密を…\\nわ…私はなにをっ！？', 1, 1, 1, 0, 0, 115701, 3, 4820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休暇も時には必要さ\\n海でゆっくりと…\\nむっ？\u3000事件の気配！', 1, 1, 1, 0, 0, 115701, 4, 4821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('探偵の秘密道具…\\n水着だと隠す\\n場所がない…！', 1, 1, 1, 0, 0, 115701, 5, 4822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ助手くんが\\n現れる時間かな？\\nふふっ、楽しみだね', 4, 1, 1, 0, 0, 115701, 101, 4823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('真実は私と助手くん\\n二人だからこそ\\n解き明かせるのさ', 8, 1, 1, 0, 0, 115701, 102, 4824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃああっ！？\\nわ、私の不意を突く\\nとは…やるね助手くん', 1, 1, 2, 0, 0, 115701, 1, 4825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、なにか気づいた\\nことはあるかな？\\n言ってごらん♪', 1, 1, 2, 0, 0, 115701, 2, 4826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この感触…分かった！\\n助手くんだね！\\nふふっ、やっぱり♪', 1, 1, 2, 0, 0, 115701, 3, 4827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着…どうかな？\\n探偵らしさは\\n残してるつもりだけど', 1, 1, 2, 0, 0, 115701, 4, 4828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000依頼かな？\\n助手くんの頼みなら\\nなんでもお安い御用さ', 4, 1, 2, 0, 0, 115701, 101, 4829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くん、私と海に\\n行かないかな\\n…事件じゃないよ？', 8, 1, 2, 0, 0, 115701, 102, 4830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('珈琲でも淹れて\\n目を覚ますとしよう\\n一緒に飲むかい？', 1, 1, 2, 0, 1, 115701, 1, 4831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食は済ませた？\\nなにを食べたか\\n当ててあげよう！', 1, 1, 2, 0, 2, 115701, 2, 4832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜は謎が深まる時間…\\n闇に覆い隠された真実\\n必ず暴いてみせる！', 1, 1, 2, 0, 3, 115701, 3, 4833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、推理の時間だ\\n…サボってないよ？\\n考えてるんだからね？', 1, 1, 3, 0, 0, 115701, 2, 4835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはもしや、中に\\n秘密のメッセージが？\\n…かわいいだけだね', 1, 1, 3, 0, 0, 115701, 3, 4836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、なんだか\\n頭がスッキリするね\\n…閃いた！', 1, 1, 3, 0, 0, 115701, 4, 4837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカするね…\\n助手くん\\n君もおいでよ', 1, 1, 3, 0, 0, 115701, 5, 4838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむ、はむ…んぐっ\\nた、食べてるところを\\n見つめられると～…', 1, 1, 3, 0, 0, 115701, 7, 4840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('秘密の依頼とか\\nこういう場所に\\n隠したりするよね…♪', 1, 1, 3, 0, 0, 115701, 8, 4841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはいい乗り心地だ\\n事件現場にこれで登場\\n…は、やめておこう', 1, 1, 3, 0, 0, 115701, 10, 4843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不思議な感触だね…\\nでも、いい発想が\\n生まれてきそうだ…♪', 1, 1, 3, 0, 0, 115701, 11, 4844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはあたしが\\n前へ進むために\\nあいつがくれた\\n大切な力…！', 1, 1, 1, 0, 0, 180601, 1, 4845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('チェンジ・\\nプリンセスフォーム！\\n練習練習、っと', 1, 1, 1, 0, 0, 180601, 2, 4846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうあいつに助けて\\nもらいっぱなしの\\nあたしは…\\n卒業しなきゃね', 1, 1, 1, 0, 0, 180601, 3, 4847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気ままに、お気楽に\\nあいつと冒険する…\\nそれって幸せよね', 1, 1, 1, 0, 0, 180601, 4, 4848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンセスフォーム…\\nお姫様みたいね\\nあたしがお姫様か…\\nそっかぁ…ふふ♪', 1, 1, 1, 0, 0, 180601, 5, 4849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと繋がって\\n生まれたこの絆は\\nあたしの宝物だわ', 4, 1, 1, 0, 0, 180601, 101, 4850);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしの命の使い方…\\n全て受け止めてくれた\\nあいつにだったら…', 8, 1, 1, 0, 0, 180601, 102, 4851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ～ん♪\\nプリンセスフォームの\\n天才魔法使い\\nキャル様に用かしら？', 1, 1, 2, 0, 0, 180601, 1, 4852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからは\\nあたしの力で\\nなんでもパパっと\\n解決してあげるわね！', 1, 1, 2, 0, 0, 180601, 2, 4853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔力がみなぎってる…\\nねえ、もしかして\\n今のあたしって本気で\\nすごいんじゃない？', 1, 1, 2, 0, 0, 180601, 3, 4854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身の反動で\\nお腹が空いても\\n魔物料理だけは\\nいやだからね！？', 1, 1, 2, 0, 0, 180601, 4, 4855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、あんたになら\\nあたしの心…\\n全部預けていいかも', 4, 1, 2, 0, 0, 180601, 101, 4856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと一緒に\\nいられたら、他には\\n何も…って、あああ\\nあんたいつの間に！？', 8, 1, 2, 0, 0, 180601, 102, 4857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きも悪くないわね\\n読みかけの魔導書\\n今のうちに\\n読んじゃおうかしら', 1, 1, 2, 0, 1, 180601, 1, 4858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ～お腹すいたー\\nあんたなんか\\n作りなさいよ\\n魔物料理以外でね！', 1, 1, 2, 0, 2, 180601, 2, 4859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁぁ…眠すぎて\\n今なら変身しても\\nお腹が減らない\\n自信があるわ…', 1, 1, 2, 0, 3, 180601, 3, 4860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あー♪\u3000最っ高！\\n休んで魔力を高めて…\\nあいつの役に\\n立ってあげなきゃね', 1, 1, 3, 0, 0, 180601, 2, 4862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにこれかわいい…！\\nコレクションにしたく\\nなっちゃうじゃない', 1, 1, 3, 0, 0, 180601, 3, 4863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…すごく\\nリラックスできるわ…\\nあ、いい感じの魔法\\n思いついちゃったかも', 1, 1, 3, 0, 0, 180601, 4, 4864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\n落ち着くわ…\\nあいつの手の\\nぬくもりみたいね', 1, 1, 3, 0, 0, 180601, 5, 4865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンセスフォーム…\\nこ、こんなに\\nお腹が減るのね\\n甘く見てたわ…！', 1, 1, 3, 0, 0, 180601, 7, 4867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ま、魔物料理の本！？\\n誰よこんな本\\n買ったの！\u3000って…\\n一人しかいないか', 1, 1, 3, 0, 0, 180601, 8, 4868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('憧れの舞踏会…\\n私、きちんと\\n踊れるかしら', 1, 1, 1, 0, 0, 115801, 1, 4870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アン・ドゥ・トロワ\\nアン・ドゥ・トロワ\\n練習はばっちりね♪', 1, 1, 1, 0, 0, 115801, 2, 4871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにすてきな\\nドレスを着られて\\n本当に夢みたいだわ♪', 1, 1, 1, 0, 0, 115801, 3, 4872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法はいつか解ける…\\nでも、その時間は心に\\n残り続けるわ♪', 1, 1, 1, 0, 0, 115801, 4, 4873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ガラスの靴は夢へ\\n踏み出す魔法の道具…\\n私、がんばっちゃう！', 1, 1, 1, 0, 0, 115801, 5, 4874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞踏会であなたと\\n一緒に踊れたら\\nいいのにな', 4, 1, 1, 0, 0, 115801, 101, 4875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞踏会に行く前に\\n運命の王子様には\\n出会ってるのよね', 8, 1, 1, 0, 0, 115801, 102, 4876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしら？\\n私、きちんとドレス\\n着られてる？', 1, 1, 2, 0, 0, 115801, 1, 4877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたも一緒に\\n踊ってみる？\\nしゃなりしゃなり♪', 1, 1, 2, 0, 0, 115801, 2, 4878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたにエスコート\\nされてきれいなお城を\\n歩いてみたいわ♪', 1, 1, 2, 0, 0, 115801, 3, 4879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どう？\u3000レッスンの\\n成果はきちんと\\n出てるかしら？', 1, 1, 2, 0, 0, 115801, 4, 4880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたが隣にいれば\\n私も立派なお姫様に\\n見えるかしら♪', 4, 1, 2, 0, 0, 115801, 101, 4881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私にとって\\n一番の魔法はあなたが\\nくれる勇気よ♪', 8, 1, 2, 0, 0, 115801, 102, 4882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ！\u3000今日も一日\\n立派な淑女を目指して\\nいきましょう♪', 1, 1, 2, 0, 1, 115801, 1, 4883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはん代わりに\\nメタモルアップルを\\n食べておきましょう', 1, 1, 2, 0, 2, 115801, 2, 4884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ魔法が解ける\\n時間…でも淑女の\\n心得は忘れないわ♪', 1, 1, 2, 0, 3, 115801, 3, 4885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('淑女にも休息は\\n必要よね…少しだけ\\n休ませてもらおっと', 1, 1, 3, 0, 0, 115801, 2, 4887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいものに\\n囲まれた部屋も\\n女の子の夢よね…', 1, 1, 3, 0, 0, 115801, 3, 4888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すてきな香り…\\nお花かしら？\\n森で探してみようかな', 1, 1, 3, 0, 0, 115801, 4, 4889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かい…暖炉のそばで\\nおとぎ話を聞くのも\\nいいわよね♪', 1, 1, 3, 0, 0, 115801, 5, 4890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンのために\\n栄養補給して\\nおかないと！', 1, 1, 3, 0, 0, 115801, 7, 4892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('教養を身に着ける\\nことも大切よね！\\nなになに…', 1, 1, 3, 0, 0, 115801, 8, 4893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('や、やっぱスカートは\\n落ち着かねえな…\\nなんか、\\nスースーするしよ…', 1, 1, 1, 0, 0, 115901, 1, 4895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくこんな格好\\nしてるし、いつもとは\\n違う剣術の訓練を\\nしてみるかな', 1, 1, 1, 0, 0, 115901, 2, 4896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、他の連中が\\n帰ってくる前に、\\nなんか料理でも\\n作っといてやるか', 1, 1, 1, 0, 0, 115901, 3, 4897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、こんな服着てる\\nわけだし、紅茶とか\\n楽しんじゃっても\\n変じゃないよな！', 1, 1, 1, 0, 0, 115901, 4, 4898);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし運動でも…\\nあ、あぶねえ！\\nスカートなの忘れてた\\n…誰も見てねえよな？', 1, 1, 1, 0, 0, 115901, 5, 4899);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('紅茶が切れてるな…\\nよし、あいつと一緒に\\n買い物にでも行くか♪', 4, 1, 1, 0, 0, 115901, 101, 4900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あいつがいねえと、\\nつまんねえな…ったく\\n飯用意してやるから、\\n早く帰ってこいよな…', 8, 1, 1, 0, 0, 115901, 102, 4901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、あんまり\\nジロジロ見んなよ\\n…結構、\\n恥ずかしいんだからな', 1, 1, 2, 0, 0, 115901, 1, 4902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ダンスの相手は\\n無理だが、\\n剣の訓練なら\\nいつでも付き合うぜ！', 1, 1, 2, 0, 0, 115901, 2, 4903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服に\\n触りたいのか？\\nすごい作りだし、\\n気持ちは分かるぜ', 1, 1, 2, 0, 0, 115901, 3, 4904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、いいところに！\\nクッキーを焼く\\nところだったんだが、\\nおまえも食うか？', 1, 1, 2, 0, 0, 115901, 4, 4905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おまえにもこういう服\\n似合うんじゃねえか？\\n今度あたしが\\n選んでやるよ♪', 4, 1, 2, 0, 0, 115901, 101, 4906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…おまえの前でなら、\\nこういう格好を\\nすんのも…\\nな、なんでもねえよ！', 8, 1, 2, 0, 0, 115901, 102, 4907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝の訓練を始めるか\\n時間あるなら、\\nおまえも付き合えよな', 1, 1, 2, 0, 1, 115901, 1, 4908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間か…\\n昼飯作るけど、\\nなんか\\n食いたいものあるか？', 1, 1, 2, 0, 2, 115901, 2, 4909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眠れないなら、\\nホットミルク飲むか？\\n体あったまって、\\n眠くなると思うぜ', 1, 1, 2, 0, 3, 115901, 3, 4910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと休憩して…\\nおっと、服にしわが\\nできないように\\nしねえとな', 1, 1, 3, 0, 0, 115901, 2, 4912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だ、誰も\\n見てねえよな？\\n…よ～しよしよし、\\nかわいいなおまえー♪', 1, 1, 3, 0, 0, 115901, 3, 4913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すげぇいい香りだな\\nうちの居酒屋にも…\\nいや、合わねえか', 1, 1, 3, 0, 0, 115901, 4, 4914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったけぇ…\\nちょっとだけなら、\\n寝ちまっても\\nいいよな…？', 1, 1, 3, 0, 0, 115901, 5, 4915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これうめえな！\\nたぶん材料は…よし！\\nあたしも作ってみるか', 1, 1, 3, 0, 0, 115901, 7, 4917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本は…\\n誰でも分かる作法…か\\n最低限このぐらいは\\n勉強しとくか…', 1, 1, 3, 0, 0, 115901, 8, 4918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミがおとなに\\nなっても\\nおにいちゃんとは\\nずーっといっしょ♪', 12, 1, 1, 0, 0, 102001, 103, 4920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミとくべつなだっこ\\nしてほしいな…うん！\\nおひめさまだっこ～♪', 12, 1, 2, 0, 0, 102001, 103, 4921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はにいちゃんに\\nどんなイタズラしよう\\n早く会いたいな～', 12, 1, 1, 0, 0, 100401, 103, 4922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギの特別な\\nイタズラ見てくれる？\\nいいよねっ♪', 12, 1, 2, 0, 0, 100401, 103, 4923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人になったら、\\nあの人と何しようかな\\n…楽しみだなぁ', 12, 1, 1, 0, 0, 103601, 103, 4924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭を撫でないで\\nください！\u3000もう、\\n少しだけ、ですからね', 12, 1, 2, 0, 0, 103601, 103, 4925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くるくる〜♪\\nうちのドレス\\nかわええなぁ', 1, 1, 1, 0, 0, 116001, 1, 4926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日差しは苦手やけど\\nたまにはひなたの下で\\nぽかぽかしたいわぁ', 1, 1, 1, 0, 0, 116001, 2, 4927);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外はお花が咲いてる\\n久しぶりにお花を\\n活けたいなぁ', 1, 1, 1, 0, 0, 116001, 3, 4928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花をたくさん集めて\\nギルドハウスに飾れば\\n喜んでくれはるかな', 1, 1, 1, 0, 0, 116001, 4, 4929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたたかい日は\\n紅茶を飲みながら\\nゆっくりしたいなぁ', 1, 1, 1, 0, 0, 116001, 5, 4930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お稽古事を始めるなら\\nうちに言ってな\\nどんなことも教えたる', 4, 1, 1, 0, 0, 116001, 101, 4931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちにいろんな夢を\\n見せてくれはって\\nほんま、おおきにな♪', 8, 1, 1, 0, 0, 116001, 102, 4932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はん\\n一緒におとぎの国へ\\nお散歩にいきまひょ♪', 1, 1, 2, 0, 0, 116001, 1, 4933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふんふ〜ん♪\\n今な、王子はんに\\n花冠を作ってるんよ', 1, 1, 2, 0, 0, 116001, 2, 4934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんは\\nお菓子好きどす？\\nうち、作りますわ', 1, 1, 2, 0, 0, 116001, 3, 4935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん。ドレスの柄は\\nお花とお星さま\\nどっちにしまひょか', 1, 1, 2, 0, 0, 116001, 4, 4936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんとの\\n思い出が増えるたび\\nうちの宝物も増えます', 4, 1, 2, 0, 0, 116001, 101, 4937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんと一緒なら\\nどんな場所でも\\n夢の国になりますわ', 8, 1, 2, 0, 0, 116001, 102, 4938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夢の中におりたいけど\\n王子はんに会いたくて\\n起きてもうたわ♪', 1, 1, 2, 0, 1, 116001, 1, 4939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はん一緒に\\nアフタヌーンティー\\nいかがやろか？', 1, 1, 2, 0, 2, 116001, 2, 4940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の舞踏会…\\n夢が広がるわぁ\\nもちろんお相手は…♪', 1, 1, 2, 0, 3, 116001, 3, 4941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわふわや〜\\nなんや心地よぉて\\n眠ってしまいそうや…', 1, 1, 3, 0, 0, 116001, 2, 4943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かいらしいなぁ\\n新しいお洋服でも\\n作ってあげまひょか♪', 1, 1, 3, 0, 0, 116001, 3, 4944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花やろうか…\\nリラックスできて\\nええ香りやねぇ', 1, 1, 3, 0, 0, 116001, 4, 4945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう場所で\\n絵本を読むと\\n気分が出てええなぁ♪', 1, 1, 3, 0, 0, 116001, 5, 4946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞踏会を楽しむなら\\nたくさん食べて\\nたくさん踊りまひょ', 1, 1, 3, 0, 0, 116001, 7, 4948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うち、この本好きや\\n王子さまと結ばれる\\nお姫さまのお話なんよ', 1, 1, 3, 0, 0, 116001, 8, 4949);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、宿題めんどい…\\nこれは楽しくない…\\nこんな青春いらない…', 1, 1, 1, 0, 0, 116301, 1, 4951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('奨学金の道は遠いなぁ\\nメルクリちゃんたちが\\nお金くれればいいのに', 1, 1, 1, 0, 0, 116301, 2, 4952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アオイちゃん元気かな\\nチエルに会いたくて\\n泣いてるんだろうな…', 1, 1, 1, 0, 0, 116301, 3, 4953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし鏡でも見るか…\\nうわ、顔良っ！\\nえ誰この超絶美少女！', 1, 1, 1, 0, 0, 116301, 4, 4954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワンツーワンツー♪\\nうーん…カルミナの\\n振りコピ難しいにゃー', 1, 1, 1, 0, 0, 116301, 5, 4955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩も運動してます？\\nチエルが一緒に走って\\nあげてもいいですよ？', 4, 1, 1, 0, 0, 116301, 101, 4956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年のテレフェスも\\n今から楽しみだなあ…\\nまた一緒にお化け屋敷\\n入ってくださいね', 8, 1, 1, 0, 0, 116301, 102, 4957);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちぇる～ん☆\\nフェス仕様でも\\nかわいいちえるん！', 1, 1, 2, 0, 0, 116301, 1, 4958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いま話しかけないで！\\n来年の聖学祭ライブの\\nイメトレ中なんです！', 1, 1, 2, 0, 0, 116301, 2, 4959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クロエ先輩のウェア姿\\nめっちゃカッコよ！\\n思わずおへそ触ったら\\nぶたれましたけど', 1, 1, 2, 0, 0, 116301, 3, 4960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユニ先輩の体操着姿…\\nあれはあれで実に良き\\n一生見てられますよね', 1, 1, 2, 0, 0, 116301, 4, 4961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩って体操着持って\\nないんですか？\u3000ハ？\\nチエルのを貸せと…？\\nえっ…変態かな？', 4, 1, 2, 0, 0, 116301, 101, 4962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テレフェスでは先輩も\\n地味に頑張ってました\\nね。まあ格好よかった\\nんじゃないですか…', 8, 1, 2, 0, 0, 116301, 102, 4963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはちぇる～ん☆\\nさあ今日も楽しいを\\n探しに行きますよー！', 1, 1, 2, 0, 1, 116301, 1, 4964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先輩ビッグニュース！\\n今からお昼ごはん\\nおごらせてあげます！', 1, 1, 2, 0, 2, 116301, 2, 4965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんばんちぇるるん☆\\nさあ朝まで楽しいを\\n探しに行きますよー！', 1, 1, 2, 0, 3, 116301, 3, 4966);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…ふかふか～…\\n運動の後は…眠たく…\\nなり…ま…', 1, 1, 3, 0, 0, 116301, 2, 4968);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユニ先輩に似合いそ！\\nいやクロエ先輩かな？\\nチエルは当然すぎて…', 1, 1, 3, 0, 0, 116301, 3, 4969);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やん、いい香り～！\\nまるでチエルのために\\n存在するみたい！', 1, 1, 3, 0, 0, 116301, 4, 4970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この火を使って\\n聖火リレーしましょう\\n先輩、一本抜いて！', 1, 1, 3, 0, 0, 116301, 5, 4971);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あむあむ…ちゃんと\\n食べないとユニ先輩\\nみたいになっちゃう！', 1, 1, 3, 0, 0, 116301, 7, 4973);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…ちゃんと\\n読まないとクロエ先輩\\nみたいになっちゃう！', 1, 1, 3, 0, 0, 116301, 8, 4974);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今なら書ける気がする\\n私の本当の\\n想いを込めた\\nラブソングを！', 12, 1, 1, 0, 0, 102901, 103, 4976);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('輝きを増した私を\\nいっぱい見てね！\\n…ちょ、ちょっと\\n見つめすぎだよ！', 12, 1, 2, 0, 0, 102901, 103, 4977);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テレフェスかぁー…\\nあんまいい記憶ないな\\nよし、忘れとこ', 1, 1, 1, 0, 0, 116201, 1, 4978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし鏡でも見るか…\\nふふ～ん…いいじゃん\\nあ？\u3000何見てんだコラ', 1, 1, 1, 0, 0, 116201, 2, 4979);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワンツー、ワンツー♪\\nああクソ、難しいな…\\nあ？\u3000何見てんだコラ', 1, 1, 1, 0, 0, 116201, 3, 4980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アオイ元気してるかな\\nまた絶叫したり白目\\n剥いたりしてんのかな', 1, 1, 1, 0, 0, 116201, 4, 4981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミフユねえさんが\\nバイトリーダーしてる\\n工場…うちも行くか…', 1, 1, 1, 0, 0, 116201, 5, 4982);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…今日の晩御飯\\n何にすっかなァ…\\nあんたも食べてく？', 4, 1, 1, 0, 0, 116201, 101, 4983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年のテレフェスは\\nどーなンだかねえ？\\nま、一緒にまた弟の\\n相手してやってよ', 8, 1, 1, 0, 0, 116201, 102, 4984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体操着なんてフツーに\\n着てもつまんないし？\\nその辺センス出るよね', 1, 1, 2, 0, 0, 116201, 1, 4985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('奨学金の道、遠くね？\\nアキノ先輩と仲良く\\nなった方が早いかも…', 1, 1, 2, 0, 0, 116201, 2, 4986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんた体操着は持って\\nないの。ハ？\u3000うちの\\n貸せって？\u3000いいけど\\n…いや、よくねえよ', 1, 1, 2, 0, 0, 116201, 3, 4987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃんっ！\\nや、だからさ…急に\\n話しかけんなっての', 1, 1, 2, 0, 0, 116201, 4, 4988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、なに？\u3000この服？\\nハ？\u3000似合ってる？\\n…え、聞こえなかった\\nちょ、もっかい言って', 4, 1, 2, 0, 0, 116201, 101, 4989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたもテレフェスで\\n一応は頑張ってたよね\\nま格好よかったんじゃ\\nないの。知んないけど', 8, 1, 2, 0, 0, 116201, 102, 4990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～あ…おはーす\\n昨日も寝たの遅くて\\nまだ目がショボだよ…', 1, 1, 2, 0, 1, 116201, 1, 4991);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに。あんた昼御飯\\nまだなの。じゃ、うち\\n適当になんか作ろうか', 1, 1, 2, 0, 2, 116201, 2, 4992);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜っていいよね。色々\\n見えすぎない感じとか\\n…この話したっけ？', 1, 1, 2, 0, 3, 116201, 3, 4993);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、ヤバ…運動の後に\\nこのフカついたのは…\\n秒でスヤれる…すやぁ', 1, 1, 3, 0, 0, 116201, 2, 4995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へーこんなんチエルに\\n似合いそうじゃん。\\n…いやユニ先輩かな？', 1, 1, 3, 0, 0, 116201, 3, 4996);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、なんか良さげな\\n香りじゃん。これは\\n何の…いや分かんね', 1, 1, 3, 0, 0, 116201, 4, 4997);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('熱ッ！\u3000この野郎なに\\n爆ぜてンだコラァ！\\n濡らすぞ木、てめえ！', 1, 1, 3, 0, 0, 116201, 5, 4998);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何コレよく分かんない\\nけど、今日モヤシしか\\n食ってないから助かる', 1, 1, 3, 0, 0, 116201, 7, 5000);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日、体操着だしね。\\n読書には逆アドかな。\\nうん帰ろ。いやあ残念', 1, 1, 3, 0, 0, 116201, 8, 5001);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビッグボス・イノリ様\\nふっふっふ…\\nしびれる響きです！', 1, 1, 1, 0, 0, 116501, 1, 5003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかお兄さんを\\nあたしの側近に\\nしてやるですよ！', 1, 1, 1, 0, 0, 116501, 2, 5004);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビッグボスになったら\\nみんなからたくさん\\nお菓子をもらうです！', 1, 1, 1, 0, 0, 116501, 3, 5005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふん！\\nこの服はあたしにしか\\n着こなせませんよ！', 1, 1, 1, 0, 0, 116501, 4, 5006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ばーんと立って\\nどーんと腕を組む！\\nこれがボスのポーズ！', 1, 1, 1, 0, 0, 116501, 5, 5007);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イノリ様の側近に\\n選ばれるなんて\\n名誉なことですよ！', 4, 1, 1, 0, 0, 116501, 101, 5008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('未来の側近として\\nあたしをしっかり\\n甘やかすですよ！', 8, 1, 1, 0, 0, 116501, 102, 5009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしがお兄さんを\\n立派なギャングに\\nしてあげますからね！', 1, 1, 2, 0, 0, 116501, 1, 5010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('側近たるもの\\nボスを甘やかなさいと\\nだめですよ！', 1, 1, 2, 0, 0, 116501, 2, 5011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに見てやがるです…\\nくぅ、分かりました！\\nお菓子は半分こです！', 1, 1, 2, 0, 0, 116501, 3, 5012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんも\\nあたしがボスなら\\nうれしいですよね！', 1, 1, 2, 0, 0, 116501, 4, 5013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんが側近なら\\nあたしも安心して\\n夜眠れるですよ！', 4, 1, 2, 0, 0, 116501, 101, 5014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビッグボスになったら\\nお兄さんにいい思い\\nさせてあげますから！', 8, 1, 2, 0, 0, 116501, 102, 5015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボスたるもの\\n早起きは鉄則ですよ！\\nふぁあ…', 1, 1, 2, 0, 1, 116501, 1, 5016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹が空きました…\\nご飯食べにいきますよ', 1, 1, 2, 0, 2, 116501, 2, 5017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボスたるものぉ〜…\\n夜更かしぐらい当然…\\nぐー…', 1, 1, 2, 0, 3, 116501, 3, 5018);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は〜これは人をだめに\\nしやがるやつですね\\nあたし専用です', 1, 1, 3, 0, 0, 116501, 2, 5020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはけしからん\\nかわいらしさですね\\nあたしにぴったりです', 1, 1, 3, 0, 0, 116501, 3, 5021);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('高級な香りがするです\\nボスになったら\\n部屋に置いてやるです', 1, 1, 3, 0, 0, 116501, 4, 5022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいですねぇ\\nちょっとこのまま\\n一休憩です…', 1, 1, 3, 0, 0, 116501, 5, 5023);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむはむ♪\\nボスたるもの食べねば\\n戦はできませんよ！', 1, 1, 3, 0, 0, 116501, 7, 5025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボスなら経済書ぐらい\\n…う。難しくて\\n読めねーです…', 1, 1, 3, 0, 0, 116501, 8, 5026);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたはドジな私を\\n受け入れてくれる…\\nだから、頑張れます！', 12, 1, 1, 0, 0, 102501, 103, 5028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何でも仰ってください\\nちょっぴり大胆な\\nことでも…な～んて♪', 12, 1, 2, 0, 0, 102501, 103, 5029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーあー、よし\\nのどの調子もいいし\\nはりきってガイド\\nしてくるか！', 1, 1, 1, 0, 0, 116601, 1, 5030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ、そろそろ行くか\\nガイドが\\n遅刻したんじゃ\\n話になんないからな', 1, 1, 1, 0, 0, 116601, 2, 5031);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しれっとドラゴン族が\\n旅行に来たり\\nしてくれないかな', 1, 1, 1, 0, 0, 116601, 3, 5032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たぎるガイド先…\\n火山、魔物の巣…\\nダメだ、そんなとこ\\nオレしか行けないや', 1, 1, 1, 0, 0, 116601, 4, 5033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この前行った絶景\\nスポットよかったな\\nキレイな景色を見る\\nのもいいもんだぜ', 1, 1, 1, 0, 0, 116601, 5, 5034);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、今日はカレと\\n一緒か。なんだか\\nやる気出てきたぜ！', 4, 1, 1, 0, 0, 116601, 101, 5035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カレにガイドして\\nもらったら\\nどこに行っても\\n楽しいだろうな', 8, 1, 1, 0, 0, 116601, 102, 5036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よっしゃあ！\\nどっちが上手く\\nガイドできるか\\n勝負しようぜ！', 1, 1, 2, 0, 0, 116601, 1, 5037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('飯でも食いがてら\\nおススメの店の\\n下調べでもしようぜ！', 1, 1, 2, 0, 0, 116601, 2, 5038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなかいいだろ？\\nこの格好。キミも\\n作ってもらったら\\nどうだ？', 1, 1, 2, 0, 0, 116601, 3, 5039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('普通は行けない\\n場所とか行きたいよな\\nキミならどんな\\nとこがいい？', 1, 1, 2, 0, 0, 116601, 4, 5040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ガイドの仕事は\\nキミの方が得意そうだ\\n参考にさせてもらうぜ\\nよろしくな！', 4, 1, 2, 0, 0, 116601, 101, 5041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの探してきた店\\n結構よさそうじゃん\\nそうだ、今度二人で\\n下見に行こうぜ！', 8, 1, 2, 0, 0, 116601, 102, 5042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい朝だな。絶好の\\n仕事日和だぜ！\\n今日もよろしくな！', 1, 1, 2, 0, 1, 116601, 1, 5043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よし、昼飯にしよう\\nこの後も激務だし\\n飯抜きじゃあ\\nぶっ倒れちまうからな', 1, 1, 2, 0, 2, 116601, 2, 5044);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お疲れさん！\u3000さーて\\n次はオレと遊んで\\nくれよ。まだまだ\\nいけるだろ？', 1, 1, 2, 0, 3, 116601, 3, 5045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ガイドは一日\\n歩きっぱなしだからな\\nゆっくり休ませて\\nもらうぜ', 1, 1, 3, 0, 0, 116601, 2, 5047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ、どこで\\n売ってるんだろ？\\n土産の情報も\\n仕入れとかなきゃな', 1, 1, 3, 0, 0, 116601, 3, 5048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アロマとかよく\\n分かんねえけど\\n土産にはいいかもな\\n覚えておくぜ', 1, 1, 3, 0, 0, 116601, 4, 5049);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体が温まると心も\\n熱くなるんだよな\\nいい仕事が\\nできそうだぜ', 1, 1, 3, 0, 0, 116601, 5, 5050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ放題か\\nこれはお客さんも\\n喜んでくれそうだな！', 1, 1, 3, 0, 0, 116601, 7, 5052);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へえ、こんなスポット\\nあったんだ。やっぱ\\nたまには勉強も\\nしとくもんだな', 1, 1, 3, 0, 0, 116601, 8, 5053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイト先になじめる\\nように笑顔の練習を！\\nに、にへぇ〜…', 1, 1, 1, 0, 0, 116701, 1, 5055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('働いて働いて働いて\\n…いつかその先に\\nぼっちの出口が\\n見えるのかも…！', 1, 1, 1, 0, 0, 116701, 2, 5056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイトのイメトレを\\n始めます。ポーズを\\n決めて…よし！\\n角度を変えて…よし！', 1, 1, 1, 0, 0, 116701, 3, 5057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイト仲間に入る\\nためには厳しい修業が\\n必須と聞きました…！', 1, 1, 1, 0, 0, 116701, 4, 5058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんどん技術を磨いて\\nバイト仲間として\\n認めてもらうんです！\\n目指せ職人技…！', 1, 1, 1, 0, 0, 116701, 5, 5059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人が応援して\\nくれる…だから必ず\\nバイト仲間の輪に\\n入ってみせます…！', 4, 1, 1, 0, 0, 116701, 101, 5060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人がいてくれると\\n勇気が湧いてきます…\\nぼっち卒業を夢見ても\\nいいんだ、って…♪', 8, 1, 1, 0, 0, 116701, 102, 5061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('緊張するけど\\n思い切って声をかけて\\nみます…バイト仲間に\\n入るために…！', 1, 1, 2, 0, 0, 116701, 1, 5062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼっちの私が\\nおもちゃ作りで\\n人と共同作業…！\\nか、感動です…！', 1, 1, 2, 0, 0, 116701, 2, 5063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('好きなおもちゃって\\nありますか？\u3000私は\\nもちろんマイフレンド\\nくんです！', 1, 1, 2, 0, 0, 116701, 3, 5064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が作ったおもちゃも\\n誰かの友達に\\nなってたら\\nいいなぁ…♪', 1, 1, 2, 0, 0, 116701, 4, 5065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も明日もバイト\\nですね！\u3000バイト\\n仲間ができる日が\\n楽しみです…♪', 4, 1, 2, 0, 0, 116701, 101, 5066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('脱ぼっちを目指して\\nこれからも一緒に\\n頑張りましょう！\\n目指せ、バイト仲間！', 8, 1, 2, 0, 0, 116701, 102, 5067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n今日も気合いを入れて\\nおもちゃ作りします！', 1, 1, 2, 0, 1, 116701, 1, 5068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランチの時間です…♪\\nもちろん工場の隅で\\nぼっち飯です…！', 1, 1, 2, 0, 2, 116701, 2, 5069);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…今日も\\nお疲れさまでした\\n明日も働きます～！', 1, 1, 2, 0, 3, 116701, 3, 5070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイトで頑張った日は\\nふわふわの誘惑に\\n勝てません…', 1, 1, 3, 0, 0, 116701, 2, 5072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうおもちゃの\\nアイデアも\\n素敵かも…♪', 1, 1, 3, 0, 0, 116701, 3, 5073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りがする\\nおもちゃはどうかな…\\n森の薬草を使って…', 1, 1, 3, 0, 0, 116701, 4, 5074);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽか…\\n幸せなひとときですね', 1, 1, 3, 0, 0, 116701, 5, 5075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…たくさん\\n食べて厳しいバイトを\\n乗り切ります…！', 1, 1, 3, 0, 0, 116701, 7, 5077);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…おもちゃの\\n設計図を見るのも\\n勉強になりますね！', 1, 1, 3, 0, 0, 116701, 8, 5078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん\\n次はどんなたい焼きを\\n作ろうかにゃぁ…', 1, 1, 1, 0, 0, 116801, 1, 5080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしが売る\\nたい焼きには\\n夢が詰まってるにゃ！', 1, 1, 1, 0, 0, 116801, 2, 5081);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか絶対に\\nたい焼き工場を\\n建て直してみせるにゃ', 1, 1, 1, 0, 0, 116801, 3, 5082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにたい焼き以外の\\nおやつも食べるにゃ\\nたとえば煮干しとか！', 1, 1, 1, 0, 0, 116801, 4, 5083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('悪い商売人がいたら\\nファントムキャッツに\\n知らせるにゃ！', 1, 1, 1, 0, 0, 116801, 5, 5084);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒にいると\\nたい焼きのアイデアが\\n次々出てくるにゃ♪', 4, 1, 1, 0, 0, 116801, 101, 5085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('出来ないことも\\nキミと一緒にいれば\\n出来る気がするにゃ♪', 8, 1, 1, 0, 0, 116801, 102, 5086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんにゃ～？\\nお姉さんにかまって\\nほしいのかにゃ♪', 1, 1, 2, 0, 0, 116801, 1, 5087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミ、いいところに！\\nあたしとライバル店へ\\n視察にいくにゃ！', 1, 1, 2, 0, 0, 116801, 2, 5088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…この匂い！\\nたい焼き持ってるなら\\nちょうだいにゃ♪', 1, 1, 2, 0, 0, 116801, 3, 5089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどんなたい焼きを\\n売ろうかにゃ～\\nキミの案も欲しいにゃ', 1, 1, 2, 0, 0, 116801, 4, 5090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ファントムキャッツに\\n相棒が必要にゃ\\nたとえばキミとか…', 4, 1, 2, 0, 0, 116801, 101, 5091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('相棒！\\n…ってキミのこと\\n呼んでいいかにゃ？', 8, 1, 2, 0, 0, 116801, 102, 5092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きは三文の徳にゃ\\n今日もたい焼き\\n売れますよーににゃ！', 1, 1, 2, 0, 1, 116801, 1, 5093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いたにゃ…\\n賄いのたい焼きを\\nいただくにゃ！', 1, 1, 2, 0, 2, 116801, 2, 5094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫は夜が本番にゃ\\nでもあたしは…\\nふわぁ～眠いにゃ…', 1, 1, 2, 0, 3, 116801, 3, 5095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかにゃ～\\nここで体を丸めて\\n一眠りしたいにゃ', 1, 1, 3, 0, 0, 116801, 2, 5097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…！\\n猫にも負けない\\nかわいさだにゃ…！', 1, 1, 3, 0, 0, 116801, 3, 5098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りにゃ～\\nゴロゴロのどが\\n鳴りそうだにゃ～', 1, 1, 3, 0, 0, 116801, 4, 5099);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃ～…\\nこのまま働かずに\\nまるまってたいにゃ…', 1, 1, 3, 0, 0, 116801, 5, 5100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('商売は戦いにゃ\\nたくさん食べて\\nたくさん働くにゃ！', 1, 1, 3, 0, 0, 116801, 7, 5102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ。たい焼きの\\nアレンジレシピ集…\\nためになるにゃ…', 1, 1, 3, 0, 0, 116801, 8, 5103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お芝居の前に\\nお兄ちゃんの顔を\\n見ると、とっても\\n落ち着きますぅ…♪', 12, 1, 1, 0, 0, 102101, 103, 5105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんにもっと\\n見てもらいたい…\\nだから私…\\n強くなりたいです…！', 12, 1, 2, 0, 0, 102101, 103, 5106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さらなる効率化で\\nみんなといい仕事を\\nしたいわね！', 1, 1, 1, 0, 0, 116901, 1, 5107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('他のバイトとの\\nスケジュールを\\n調整しないと…', 1, 1, 1, 0, 0, 116901, 2, 5108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時給がアップしたわ！\\n働きが認められると\\nやる気が出るわね', 1, 1, 1, 0, 0, 116901, 3, 5109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('効率的に動ければ\\n業務を追加できる…\\n燃えてきたわ！', 1, 1, 1, 0, 0, 116901, 4, 5110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('帳簿付けのコツ…\\nユカリさんに教わって\\nみようかしら', 1, 1, 1, 0, 0, 116901, 5, 5111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バイトリーダーとして\\nみんなをビシバシ\\n鍛えていくわ！', 4, 1, 1, 0, 0, 116901, 101, 5112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦いでもバイトでも\\nキミなら安心して\\n背中を預けられるわね', 8, 1, 1, 0, 0, 116901, 102, 5113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\n仕事のことなら\\nなんでも相談してね！', 1, 1, 2, 0, 0, 116901, 1, 5114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さすがは私の弟子ね\\nこれなら安心して\\n仕事を任せられるわ', 1, 1, 2, 0, 0, 116901, 2, 5115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなのお手本になる\\n働きぶりを見せないと\\nいけないわね！', 1, 1, 2, 0, 0, 116901, 3, 5116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミのこと…もっと\\n頼りにしちゃっても\\nいいのかしら…？', 1, 1, 2, 0, 0, 116901, 4, 5117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、キミも一人前の\\nバイト戦士として\\n立派に成長したわね！', 4, 1, 2, 0, 0, 116901, 101, 5118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいおもちゃの\\n企画書を作ってみたの\\nちょっと見てくれる？', 8, 1, 2, 0, 0, 116901, 102, 5119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は一番効率がいい\\n時間帯よ！\\nバリバリ働くわよ！', 1, 1, 2, 0, 1, 116901, 1, 5120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ、お昼に行きましょ\\n今日の日替わり定食は\\n何かしら…楽しみね♪', 1, 1, 2, 0, 2, 116901, 2, 5121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\nちゃんと寝て明日に\\n備えなくちゃね', 1, 1, 2, 0, 3, 116901, 3, 5122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('適度な労働と休息の\\nサイクルが最大効率を\\n生み出すのよ…ふぅ…', 1, 1, 3, 0, 0, 116901, 2, 5124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～なんて素敵な\\n抱き心地なのかしら…\\n最高効率の癒やしね♪', 1, 1, 3, 0, 0, 116901, 3, 5125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着く香りね…\\nなんだか集中力が\\nアップした気がするわ', 1, 1, 3, 0, 0, 116901, 4, 5126);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…癒されるわね…\\n仕事のオンオフの\\n切り替えは重要よね', 1, 1, 3, 0, 0, 116901, 5, 5127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('働くためには\\nエネルギーをちゃんと\\n摂っておかないと', 1, 1, 3, 0, 0, 116901, 7, 5129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('効率を上げるため\\n生産管理の勉強も\\nしておきたいわね', 1, 1, 3, 0, 0, 116901, 8, 5130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身している間に\\n色々と試しておこう\\nまずは…', 1, 1, 1, 0, 0, 180301, 1, 5132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('飛べるというのは\\n便利だな。料理が\\n暖かいうちに\\n持ち帰れる', 1, 1, 1, 0, 0, 180301, 2, 5133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンセスか…\\n柄ではないけれど\\n嫌な気はしないな', 1, 1, 1, 0, 0, 180301, 3, 5134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この力で\\n何を成すべきなのか…\\n剣に聞いてみよう', 1, 1, 1, 0, 0, 180301, 4, 5135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身したとて私は私\\n一時的に強くなろうと\\n元が弱くてはだめだ', 1, 1, 1, 0, 0, 180301, 5, 5136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身していない時でも\\n彼がそばにいると\\n力が湧いてくる…', 4, 1, 1, 0, 0, 180301, 101, 5137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の思い…\\nいつか伝えてみせるよ\\n…きっといつか！', 8, 1, 1, 0, 0, 180301, 102, 5138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何者かと戦うの？\\nそれとも修行？\\nどちらだとしても\\n付き合うよ', 1, 1, 2, 0, 0, 180301, 1, 5139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身し続けたら\\nどれだけ空腹に…\\n私は試さないからね？', 1, 1, 2, 0, 0, 180301, 2, 5140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本物のプリンセスに\\nなるのは御免だが\\nナイトがいて\\nくれるのは頼もしいよ', 1, 1, 2, 0, 0, 180301, 3, 5141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかこの力を\\n誰かを救うために…\\n戦い以外に使える時が\\nくることを願うよ', 1, 1, 2, 0, 0, 180301, 4, 5142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミに感じてほしいな\\n私に流れてくる\\nキミからの力を…\\nその…私の、思いも…', 4, 1, 2, 0, 0, 180301, 101, 5143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('思いを告げる…\\nそれがこんなにも\\n難しいなんて…\\nでも、いつか必ず…！', 8, 1, 2, 0, 0, 180301, 102, 5144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\nいい変身日和だ！\\n…ふふっ、冗談だよ', 1, 1, 2, 0, 1, 180301, 1, 5145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもより多く\\n昼食を用意しよう\\n変身が解けたら大変だ', 1, 1, 2, 0, 2, 180301, 2, 5146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一日お疲れ様\\n私もそろそろ変身を\\n解いて休むとするよ', 1, 1, 2, 0, 3, 180301, 3, 5147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変身してしまうと\\n動かずにいても\\n空腹になるのかな…？', 1, 1, 3, 0, 0, 180301, 2, 5149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私もキミたちくらい\\n可愛げがある姿に\\nなっているかな？', 1, 1, 3, 0, 0, 180301, 3, 5150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りに対する感覚も\\nいつもより鋭く\\nなっているみたいだ…', 1, 1, 3, 0, 0, 180301, 4, 5151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ありがたいな\\n少し足元が\\n冷えていたところだ', 1, 1, 3, 0, 0, 180301, 5, 5152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…！\\n持ち運べるように\\n改良できないかな？', 1, 1, 3, 0, 0, 180301, 7, 5154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('祖父に貰った\\n技法書を読んで\\n初心に帰ろう', 1, 1, 3, 0, 0, 180301, 8, 5155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最強の惚れ薬を作って\\nあのおかたの心を\\n私の思いのままに…', 1, 1, 1, 0, 0, 117001, 1, 5157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏といえば海にスイカ\\n花火に水着…\\nそして惚れ薬ですわ…', 1, 1, 1, 0, 0, 117001, 2, 5158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのおかたの心を\\n手に入れるための\\n準備を進めましょう\\nこの夏こそ確実に…', 1, 1, 1, 0, 0, 117001, 3, 5159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのおかたに近づく\\n虫どもを、どうやって\\n片付けようかしら…\\nまったく忌々しいこと', 1, 1, 1, 0, 0, 117001, 4, 5160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…クスクス\\n薬の調合を考えるのは\\n至福の時間ですわ…', 1, 1, 1, 0, 0, 117001, 5, 5161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのおかたの全てが\\n早く私のものに\\nなりますように…', 4, 1, 1, 0, 0, 117001, 101, 5162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かき氷も花火も海も…\\nあなた様がいてこそ…\\nそう、あなた様は\\n私の全てなのですわ', 8, 1, 1, 0, 0, 117001, 102, 5163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('二人だけの夏を\\n楽しみましょう…？\\n…クスクス', 1, 1, 2, 0, 0, 117001, 1, 5164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、あなた様\\n私に秘密でどこに\\n行こうとして\\nいますの…？', 1, 1, 2, 0, 0, 117001, 2, 5165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行きませんか？\\nあなた様と一緒に\\n過ごすには\\n最高の場所ですから…', 1, 1, 2, 0, 0, 117001, 3, 5166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうどいいところに\\nいらっしゃいました\\nできたての薬を…\\nさぁどうぞ…クスクス', 1, 1, 2, 0, 0, 117001, 4, 5167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の海のきらめきも\\nあなた様の存在が\\nなければ色あせて\\nしまいますわ…', 4, 1, 2, 0, 0, 117001, 101, 5168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私とあなた様は\\n結ばれる運命に\\nあるのです…\\n逃がしませんわ…', 8, 1, 2, 0, 0, 117001, 102, 5169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('起きてすぐに会いに\\n来てくださるなんて\\nようやく私の伴侶たる\\n自覚が…クスクス', 1, 1, 2, 0, 1, 117001, 1, 5170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お食事はまだですか？\\n特製の薬草ランチを\\n召し上がれ…クスクス', 1, 1, 2, 0, 2, 117001, 2, 5171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の夢を見られる薬を\\n差し上げますわ…\\nおやすみなさいませ\\nあなた様…クスクス', 1, 1, 2, 0, 3, 117001, 3, 5172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい肌触りですわ…\\n考え事にもぴったり\\n眠くなるのが\\n玉に瑕ですが…', 1, 1, 3, 0, 0, 117001, 2, 5174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういったものに\\n揮発性の薬を仕込む\\nのも一つの手ですわね', 1, 1, 3, 0, 0, 117001, 3, 5175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…開発中の\\n薬に使えそうな気が\\nしますわ…クスクス', 1, 1, 3, 0, 0, 117001, 4, 5176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのおかたの\\nぬくもりを\\n思い出しますわ…', 1, 1, 3, 0, 0, 117001, 5, 5177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味しい…この味なら\\n薬を混ぜても違和感は\\nなさそうですわ…', 1, 1, 3, 0, 0, 117001, 7, 5179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この薬の調合法…\\n今度試してみましょう\\nもちろんあのおかたに\\n飲んでいただいて…', 1, 1, 3, 0, 0, 117001, 8, 5180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('二人乗りができると\\nいいですわね…', 1, 1, 3, 0, 0, 117001, 10, 5182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかですわ…\\nあのおかたの分も\\n欲しくなります…', 1, 1, 3, 0, 0, 117001, 11, 5183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はキミと\\nいつまでも歌って\\n踊りたい気分さ～♪', 12, 1, 1, 0, 0, 101701, 103, 5184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あは～♪\\nキミの隣は、故郷より\\n落ち着くかも～…♪', 12, 1, 2, 0, 0, 101701, 103, 5185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この水着…\\n一番に弟くんに\\n見せたいな♪', 1, 1, 1, 0, 0, 117101, 1, 5186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんをこっそり\\n海に運んで…\\nサプライズしちゃお♪', 1, 1, 1, 0, 0, 117101, 2, 5187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもと違う髪型に\\nしてみたけど…\\n気に入ってくれるかな', 1, 1, 1, 0, 0, 117101, 3, 5188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海は楽しみだけど\\n日焼けしないように\\n気を付けなきゃね', 1, 1, 1, 0, 0, 117101, 4, 5189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだかな、弟くん\\n水着のお姉ちゃんが\\nお出迎えだよっ♪', 1, 1, 1, 0, 0, 117101, 5, 5190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海が見えるおうちで\\n弟くんと一緒に\\n暮らしたいなぁ～', 4, 1, 1, 0, 0, 117101, 101, 5191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの水着…\\nどんな感じかなぁ\\n…あ、想像してたら\\nドキドキして…えへへ', 8, 1, 1, 0, 0, 117101, 102, 5192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こーら、水着の\\nお姉ちゃんは\\nおさわり禁止♪\\n…なんてね？', 1, 1, 2, 0, 0, 117101, 1, 5193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なぁに？\\nふふっ、何回でも\\n呼んでいいんだよ♪', 1, 1, 2, 0, 0, 117101, 2, 5194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で迷子に\\nならないように\\n手を繋ごうね♪', 1, 1, 2, 0, 0, 117101, 3, 5195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんが\\n海の楽しみ方を\\n教えてあげるねっ！', 1, 1, 2, 0, 0, 117101, 4, 5196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、弟くん\\nどこ触ってるの？\\nも～驚いちゃったぞ♪', 4, 1, 2, 0, 0, 117101, 101, 5197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃん、海でも\\nずっとキミを見てるよ\\n…安心してね', 8, 1, 2, 0, 0, 117101, 102, 5198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ眠そうだね？\\nほら、海が待ってるよ\\n早く起きて起きて♪', 1, 1, 2, 0, 1, 117101, 1, 5199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大丈夫、疲れてない？\\n海で遊び疲れた時は\\n素直に休憩しようね', 1, 1, 2, 0, 2, 117101, 2, 5200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほら、早く寝ないと\\n明日もお姉ちゃんと\\n遊べないぞ♪', 1, 1, 2, 0, 3, 117101, 3, 5201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('だらけたお姉ちゃんは\\n弟くんには\\n見せられないな～', 1, 1, 3, 0, 0, 117101, 2, 5203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、かわいいね♪\\n弟くんが持つと\\nもっとかわいいよっ♪', 1, 1, 3, 0, 0, 117101, 3, 5204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだね…\\n一味違うお姉ちゃんに\\nなれそう…♪', 1, 1, 3, 0, 0, 117101, 4, 5205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い♪\\nほら、弟くんも\\nおいでよ♪', 1, 1, 3, 0, 0, 117101, 5, 5206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よく食べて、いつでも\\n弟くんの呼び声に\\n応える準備を…！', 1, 1, 3, 0, 0, 117101, 7, 5208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの水着の写真\\nこの辺りに隠して\\nおこうかな', 1, 1, 3, 0, 0, 117101, 8, 5209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子の背に乗って\\nお姉ちゃんと弟くんの\\n楽園へ…な～んて♪', 1, 1, 3, 0, 0, 117101, 10, 5211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海を感じる感触だね\\n弟くんとの楽しい夏を\\n思い出しちゃうな…♪', 1, 1, 3, 0, 0, 117101, 11, 5212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この夏、誰よりも\\nキラキラしてみせる！\\nだって私は\\nアイドルだから！', 1, 1, 1, 0, 0, 117201, 1, 5213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日傘にアームカバー\\n帽子にサングラス…\\n紫外線対策は完璧！', 1, 1, 1, 0, 0, 117201, 2, 5214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっておきの\\nサマーソングを\\nみんなに届けるよ！', 1, 1, 1, 0, 0, 117201, 3, 5215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんにもしないのって\\n苦手かも…\\n彼、早く来ないかな？', 1, 1, 1, 0, 0, 117201, 4, 5216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラムネって\\n夏って感じするよね\\n後で彼と飲もっと♪', 1, 1, 1, 0, 0, 117201, 5, 5217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏は恋の季節！\\n燃えるような恋…\\nいつかしたいな', 4, 1, 1, 0, 0, 117201, 101, 5218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年の夏の目標は\\n…彼との思い出を\\nいっぱい作ること！', 8, 1, 1, 0, 0, 117201, 102, 5219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の水着写真集\\n見てくれたんだ！\\nどう、かわいかった？', 1, 1, 2, 0, 0, 117201, 1, 5220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スイカ割りしたいの？\\nいいね、楽しそう！\\nみんなも誘おうよ♪', 1, 1, 2, 0, 0, 117201, 2, 5221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ、見て見て！\\n水着の映える\\nポーズ考えたんだ！', 1, 1, 2, 0, 0, 117201, 3, 5222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ライブ中に\\n花火を打ち上げたら\\n絶対盛り上がるよね！', 1, 1, 2, 0, 0, 117201, 4, 5223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近、忙しいけど…\\nキミの顔見たら\\n疲れなんて\\n消えちゃった！', 4, 1, 2, 0, 0, 117201, 101, 5224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この夏もいーっぱい\\nドキドキさせるから！\\n覚悟しててよね♪', 8, 1, 2, 0, 0, 117201, 102, 5225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外は朝から暑いね\\nけど、負けないから！\\nお仕事、頑張るぞー！', 1, 1, 2, 0, 1, 117201, 1, 5226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分へのご褒美に、\\nアイス食べちゃお♪\\nキミも一緒に食べよ！', 1, 1, 2, 0, 2, 117201, 2, 5227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の夜って\\nワクワクするね♪\\nホタル見に行こうよ！', 1, 1, 2, 0, 3, 117201, 3, 5228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…眠い…\\n仕事とかの疲れ、\\nたまってるのかな…？', 1, 1, 3, 0, 0, 117201, 2, 5230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私のぬいぐるみが\\nグッズになったら…\\n彼にかわいがって\\nもらえるかな？', 1, 1, 3, 0, 0, 117201, 3, 5231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…\\n夏限定のやつでしょ？\\nいいセンスしてるね♪', 1, 1, 3, 0, 0, 117201, 4, 5232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑～い！\\nけど…汗かいて\\n気持ちいいかも！', 1, 1, 3, 0, 0, 117201, 5, 5233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンの後のご飯は\\n特別おいしい♪\\n…もうひとつだけ\\n食べちゃおっかな', 1, 1, 3, 0, 0, 117201, 7, 5235);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、この前撮影した\\n水着グラビアだ\\nうんうん、いい感じ！', 1, 1, 3, 0, 0, 117201, 8, 5236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子、もふもふだね\\n触るのクセになりそう\\nもふもふもふもふ…', 1, 1, 3, 0, 0, 117201, 10, 5238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ、かわいい♪\\n今度のグラビア撮影で\\nこれ使ってもいい？', 1, 1, 3, 0, 0, 117201, 11, 5239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着っていいですよね\\n海に浮かぶ一輪の花\\nって感じがして！', 1, 1, 1, 0, 0, 117401, 1, 5240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分の水着を作るのも\\n誰かの水着を作るのも\\n楽しいですね♪', 1, 1, 1, 0, 0, 117401, 2, 5241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着の最終チェック！\\n伸縮性や動きやすさは\\n…いい感じですね！', 1, 1, 1, 0, 0, 117401, 3, 5242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('振り付けや衣装作りに\\n歌や踊りの練習…\\n…やることがいっぱい', 1, 1, 1, 0, 0, 117401, 4, 5243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…レイ様の水着…\\n私に作らせて\\nもらえないかなぁ～…', 1, 1, 1, 0, 0, 117401, 5, 5244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんのことは\\n気に入らないですけど\\n別に嫌いという\\nわけじゃなくて…', 4, 1, 1, 0, 0, 117401, 101, 5245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さん暇そうですね\\nに、荷物持ちとして\\n誘ってみようかな…', 8, 1, 1, 0, 0, 117401, 102, 5246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんいいところに\\nこの衣装\\nどう思います？', 1, 1, 2, 0, 0, 117401, 1, 5247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何見てるんですか？\\nもしかしてこの水着の\\n良さが分かります！？', 1, 1, 2, 0, 0, 117401, 2, 5248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('真夏でも涼しい…\\nそれも水着の良さの\\n一つですね', 1, 1, 2, 0, 0, 117401, 3, 5249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕立て屋も\\nアイドルも\\n諦めません！', 1, 1, 2, 0, 0, 117401, 4, 5250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏と言えば\\nバカンスですけど…\\n予定、あるんですか？', 4, 1, 2, 0, 0, 117401, 101, 5251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん…騎士さんを\\n海へ誘うには…って\\nなんでもないですよ！', 8, 1, 2, 0, 0, 117401, 102, 5252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふー…夏はやっぱり\\n朝が一番過ごしやすい\\nですね～！', 1, 1, 2, 0, 1, 117401, 1, 5253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑い時こそ海です！\\n体力づくりのためにも\\n泳ぎにいきますよ！', 1, 1, 2, 0, 2, 117401, 2, 5254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外で虫が鳴いてる…\\n夏って感じがして\\n風流ですねぇ…', 1, 1, 2, 0, 3, 117401, 3, 5255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し休憩です…\\nこのまま寝ないよう\\n気をつけないと…', 1, 1, 3, 0, 0, 117401, 2, 5257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…！\\nこの感動を次の\\nステージ衣装にも…！', 1, 1, 3, 0, 0, 117401, 3, 5258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りですね～\\n波の音が聞こえて\\nきそうです…', 1, 1, 3, 0, 0, 117401, 4, 5259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳いだ後は\\n少し寒いので\\nちょうどいいですね', 1, 1, 3, 0, 0, 117401, 5, 5260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏バテしないように\\n栄養はしっかり\\n取らないと！', 1, 1, 3, 0, 0, 117401, 7, 5262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次のトレンドは…\\nふむふむ、やっぱり\\nこう来ましたか…', 1, 1, 3, 0, 0, 117401, 8, 5263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('デザインはもちろん\\n触り心地も\\n最高ですね♪', 1, 1, 3, 0, 0, 117401, 10, 5265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の撮影スポットに\\n活用できそうですね\\nさっそく衣装考えて…', 1, 1, 3, 0, 0, 117401, 11, 5266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…♪\\n団長さんが初めての\\n友達で本当に良かった', 12, 1, 1, 0, 0, 104001, 103, 5267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、団長さん！\\n今日のＢＢ団の活動\\nなんですけど…二人で\\n大縄跳びしませんか！', 12, 1, 2, 0, 0, 104001, 103, 5268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装で\\nライブするのは\\n恥ずかしいな…', 1, 1, 1, 0, 0, 117301, 1, 5269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの夏だし\\n肝試しに\\n行ってみたいかも…', 1, 1, 1, 0, 0, 117301, 2, 5270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('歌もダンスも\\nより上を目指すために\\n夏合宿をしよう…！', 1, 1, 1, 0, 0, 117301, 3, 5271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の暑さにも負けない\\n熱いライブに\\nしてみせる…！', 1, 1, 1, 0, 0, 117301, 4, 5272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新曲のアイデア\\nまとめたいな…\\n少し海辺を散歩しよう', 1, 1, 1, 0, 0, 117301, 5, 5273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かき氷、食べたいな\\n…あの人は何味が\\n好きなんだろう？', 4, 1, 1, 0, 0, 117301, 101, 5274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着、似合ってるって\\n言ってもらえるかな…', 8, 1, 1, 0, 0, 117301, 102, 5275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サインして、ですか？\\nいいですけど…\\n少し照れますね…', 1, 1, 2, 0, 0, 117301, 1, 5276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し待ってください\\n今、新曲の楽譜を\\n書いているので…', 1, 1, 2, 0, 0, 117301, 2, 5277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんでしょう？\\nもしかして…\\nボイトレに興味が？', 1, 1, 2, 0, 0, 117301, 3, 5278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度のライブでは\\n夏らしい爽やかな歌を\\nファンにお届けします', 1, 1, 2, 0, 0, 117301, 4, 5279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…水鉄砲で遊ぼう？\\nふふ。楽しそうですね\\nお手柔らかに…♪', 4, 1, 2, 0, 0, 117301, 101, 5280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの声を\\n聴いていると、\\n何だか落ち着きます…', 8, 1, 2, 0, 0, 117301, 102, 5281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も暑くなりそう…\\nお互いしっかりと\\n水分補給しましょうね', 1, 1, 2, 0, 1, 117301, 1, 5282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空きましたよね\\n海の家で、\\nなにか買ってきます', 1, 1, 2, 0, 2, 117301, 2, 5283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海で月明かりと\\n波の音を楽しもうかと\\n…一緒に行きますか？', 1, 1, 2, 0, 3, 117301, 3, 5284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンだけでなく\\nリラックスすることも\\n大事、ですよね', 1, 1, 3, 0, 0, 117301, 2, 5286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、かわいい\\n精霊も負けないくらい\\nかわいいですけどね', 1, 1, 3, 0, 0, 117301, 3, 5287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏らしい爽やかで\\nいい匂い…あなたに\\nピッタリな香りですね', 1, 1, 3, 0, 0, 117301, 4, 5288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に入った後は、\\n体が冷えてしまいます\\n一緒に温まりましょう', 1, 1, 3, 0, 0, 117301, 5, 5289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイドルとして、\\n食べすぎには\\n気をつけないと…', 1, 1, 3, 0, 0, 117301, 7, 5291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏は恋の季節…\\nガンガン攻めるべし…\\nなるほど…', 1, 1, 3, 0, 0, 117301, 8, 5292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子に乗りながら\\nライブをする…\\nというのはどうですか', 1, 1, 3, 0, 0, 117301, 10, 5294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まるで人魚になった\\n気分…なんて、ふふ', 1, 1, 3, 0, 0, 117301, 11, 5295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんとして\\nシオリンにかっこいい\\nとこ見せなくっちゃ☆', 1, 1, 1, 0, 0, 118301, 1, 5296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかシオリンと\\n一緒に空を飛んで\\n空中散歩してみたいな', 1, 1, 1, 0, 0, 118301, 2, 5297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すこし眠くなってきた\\nかも…シオリンと\\nお昼寝しようかな', 1, 1, 1, 0, 0, 118301, 3, 5298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お散歩してこよっと！\\nシオリンとお出かけ\\nするのにいい場所\\n探さなくっちゃ！', 1, 1, 1, 0, 0, 118301, 4, 5299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリンに過保護って\\n言われちゃった…♪\\nそれでも心配しちゃう\\nのが姉心…だよね？', 1, 1, 1, 0, 0, 118301, 5, 5300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい日差し！\\nシオリンと彼と、\\nお昼寝したら\\n気持ちよさそ～♪', 4, 1, 1, 0, 0, 118301, 101, 5301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度天気がいい日には\\nシオリンと彼を誘って\\n一緒にお出かけ\\nしたいな～♪', 8, 1, 1, 0, 0, 118301, 102, 5302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はご機嫌なんだ♪\\nだって、シオリンの\\n調子がいいんだもん☆', 1, 1, 2, 0, 0, 118301, 1, 5303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今からシオリンと\\nピクニックに\\n行くんだ♪\u3000そうだ！\\nキミも一緒にどう？', 1, 1, 2, 0, 0, 118301, 2, 5304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、びっくりした！\\nシオリンから借りた本\\n読むのに集中\\nしてたから…', 1, 1, 2, 0, 0, 118301, 3, 5305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん？\u3000どうしたの？\\nあっ、もしかして\\nこの服、気になる？', 1, 1, 2, 0, 0, 118301, 4, 5306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリンもキミも元気\\nいっぱいだと、私も\\n元気になっちゃうよ☆', 4, 1, 2, 0, 0, 118301, 101, 5307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリンの前だけ\\nじゃなくて、キミにも\\nかっこいい私の姿を\\n見てほしいな☆', 8, 1, 2, 0, 0, 118301, 102, 5308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\u3000えへへっ\\n今日は早起きなんだ♪\\nシオリンにかっこ悪い\\nとこ見せたくないから', 1, 1, 2, 0, 1, 118301, 1, 5309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おなかすいたなぁ～…\\nシオリンと一緒に\\nおいしいもの食べに\\n行こうかな！', 1, 1, 2, 0, 2, 118301, 2, 5310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間！？\\nシオリンと一緒だと\\n時間が早く\\n過ぎていっちゃうね！', 1, 1, 2, 0, 3, 118301, 3, 5311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この快適な寝心地…！\\nシオリンにもおすすめ\\nしなきゃ…！', 1, 1, 3, 0, 0, 118301, 2, 5313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、かわいい！\\nそれにさわり心地も\\nいいし、抱き枕に\\nちょうどいいかも！', 1, 1, 3, 0, 0, 118301, 3, 5314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいにおい…♪\\nなんだかリラックス\\nできて…すやぁ…', 1, 1, 3, 0, 0, 118301, 4, 5315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽか～☆\\nシオリンと一緒に\\nぬくぬくしたら\\n気持ちよさそう♪', 1, 1, 3, 0, 0, 118301, 5, 5316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲のいい人が一緒だと\\nつい食が進んじゃうね\\nえへへ…♪', 1, 1, 3, 0, 0, 118301, 7, 5318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…この本…\\nシオリンが好きかも！\\n今度おすすめしよっと', 1, 1, 3, 0, 0, 118301, 8, 5319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃん、\\n私のために無理は\\nしてないかな…？', 1, 1, 1, 0, 0, 118401, 1, 5322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しく買った絵本…\\nこういうのなら\\nお姉ちゃんと楽しく\\n読めるよね', 1, 1, 1, 0, 0, 118401, 2, 5323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃんを\\nここに連れてきて\\nみんなで遊べないかな', 1, 1, 1, 0, 0, 118401, 3, 5324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本屋さんに行こうかな\\nみんなで読める\\n面白い本が\\nあるといいなぁ', 1, 1, 1, 0, 0, 118401, 4, 5325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには…読むだけ\\nじゃなくて、自分で\\nお話を書いて\\nみようかな…？', 1, 1, 1, 0, 0, 118401, 5, 5326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時々…お姉ちゃんと\\nあの人が似てるって\\n思うことがあります…', 4, 1, 1, 0, 0, 118401, 101, 5327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんとあの人…\\n優しくて頼もしい\\n二人に囲まれて…\\n私、幸せ者だなぁ…', 8, 1, 1, 0, 0, 118401, 102, 5328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかしましたか？\\nもしかして…あなたも\\n一緒にこの本を\\n読みたい…とか？', 1, 1, 2, 0, 0, 118401, 1, 5329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('けほっ…けほっ…\\nあっ、心配いりません\\n飲み物を飲んで\\nむせただけですから', 1, 1, 2, 0, 0, 118401, 2, 5330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好…\\n似合ってますか…？\\nえへへ、照れますね…', 1, 1, 2, 0, 0, 118401, 3, 5331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なぁに、お姉ちゃん？\\n…あっ、すみません\\n読書に集中していて…\\n間違えちゃいました…', 1, 1, 2, 0, 0, 118401, 4, 5332);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃん、時々無理\\nしちゃうから…\\nあなたも一緒だと\\n安心できます', 4, 1, 2, 0, 0, 118401, 101, 5333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんとあなたと\\n頼れる人に囲まれて\\n私は幸せものですね', 8, 1, 2, 0, 0, 118401, 102, 5334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか朝から\\n調子がいい…今日は\\nいい日になりそうです', 1, 1, 2, 0, 1, 118401, 1, 5335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくだから、\\nお姉ちゃんを誘って\\nお外でランチも\\nいいかも', 1, 1, 2, 0, 2, 118401, 2, 5336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんに心配\\nかけないように…もう\\nちょっと本を読んだら\\n寝なくちゃね', 1, 1, 2, 0, 3, 118401, 3, 5337);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんわり柔らかくて\\n気持ちいい手触り…\\nお姉ちゃんが寝るのに\\nちょうどよさそう', 1, 1, 3, 0, 0, 118401, 2, 5339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、かわいい♪\\n絵本の物語みたいに\\nおしゃべりできない\\nかな…？', 1, 1, 3, 0, 0, 118401, 3, 5340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵な落ち着く香り♪\\nなんだかお姉ちゃん\\nみたい、ふふっ', 1, 1, 3, 0, 0, 118401, 4, 5341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかくてほっと\\nするなぁ\\nここでゆっくり\\n読書しようかな', 1, 1, 3, 0, 0, 118401, 5, 5342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この味…\\nお姉ちゃんが好きそう\\n少しもらって、\\n持って行こうかな…？', 1, 1, 3, 0, 0, 118401, 7, 5344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この本みたいな、\\n心躍る大冒険も\\nお姉ちゃんと一緒なら\\nできちゃいそう', 1, 1, 3, 0, 0, 118401, 8, 5345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい部屋ね\\nここを私の分院に\\nするのもいいかも\\nしれないわね…♪', 1, 1, 1, 0, 0, 117501, 1, 5348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('珍しいカンポーが\\n手に入ったから\\n色々試してみたいわ\\n色々と、ね♪', 1, 1, 1, 0, 0, 117501, 2, 5349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服を着ると\\n自分が医者だって\\nより実感するわね\\nまあ、闇医者だけどね', 1, 1, 1, 0, 0, 117501, 3, 5350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新薬開発のために\\n薬草を採取して\\nおこうかしら', 1, 1, 1, 0, 0, 117501, 4, 5351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつ急患が来ても\\n対応できるように\\nしておきましょうか', 1, 1, 1, 0, 0, 117501, 5, 5352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子の研究資料も\\nだいぶ増えてきたわね\\nちゃんとまとめて\\nおかないと♪', 4, 1, 1, 0, 0, 117501, 101, 5353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子は大事な\\n研究対象。だから\\nいつまでも健康で\\nいてもらわないとね♪', 8, 1, 1, 0, 0, 117501, 102, 5354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('薬に興味があるの？\\nなら、今度ゆっくりと\\n教えてあげるわね', 1, 1, 2, 0, 0, 117501, 1, 5355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し時間があいたから\\n一緒に新薬の実験を\\nしましょうか♪', 1, 1, 2, 0, 0, 117501, 2, 5356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\nまさか急患…！？\\nあら、違うのね\\nならよかったわ', 1, 1, 2, 0, 0, 117501, 3, 5357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('具合が悪い時はすぐに\\n言うのよ。君には\\nいつでも健康でいて\\nほしいから', 1, 1, 2, 0, 0, 117501, 4, 5358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少し仮眠したいわね\\n肩…いいえ、膝を\\n貸してもらえる？', 4, 1, 2, 0, 0, 117501, 101, 5359);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには…君の隣なら\\n闇医者も悪い研究者も\\nお休みにするのも\\n悪くないわね♪', 8, 1, 2, 0, 0, 117501, 102, 5360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには朝の陽ざしを\\n浴びるのも…\\n悪くないわね', 1, 1, 2, 0, 1, 117501, 1, 5361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('天気がいい日は\\nいい薬草が採れるの\\n君も集めるの、\\n手伝ってくれる？', 1, 1, 2, 0, 2, 117501, 2, 5362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いけない、もうこんな\\n時間なのね\\n診察に没頭すると\\n時間感覚がなくなるわ', 1, 1, 2, 0, 3, 117501, 3, 5363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう少し固い方が\\n私好みだけど…\\n悪くない寝心地ね', 1, 1, 3, 0, 0, 117501, 2, 5365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このぬいぐるみ…\\n闇医者として\\n興味深いわね…', 1, 1, 3, 0, 0, 117501, 3, 5366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着く香りね\\n私も診察室で\\n使ってみようかしら', 1, 1, 3, 0, 0, 117501, 4, 5367);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷えは病につながるわ\\nしっかり温めて\\n体をいたわりましょ', 1, 1, 3, 0, 0, 117501, 5, 5368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい♪\\n研究のお供に\\nもってこいの\\n味だわ', 1, 1, 3, 0, 0, 117501, 7, 5370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('医学は日進月歩…\\n闇医者とはいえ\\n最新の論文には\\n目を通しておかないと', 1, 1, 3, 0, 0, 117501, 8, 5371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('白衣の天使かあ\\nまさにボクのための\\n呼び方だね', 1, 1, 1, 0, 0, 117601, 1, 5400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美しさとは\\n日々の努力が\\n作るものなんだよ', 1, 1, 1, 0, 0, 117601, 2, 5401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大変だ…\\nボクは美しく\\nなりすぎたかも', 1, 1, 1, 0, 0, 117601, 3, 5402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクのかわいさで\\n癒やされて\\nみんな健康に\\nなっちゃうね', 1, 1, 1, 0, 0, 117601, 4, 5403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんな服装をしても\\nボクの美しさは\\n変わらないね', 1, 1, 1, 0, 0, 117601, 5, 5404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからはボクも\\n美の伝道師として\\nがんばらないとね♪', 4, 1, 1, 0, 0, 117601, 101, 5405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクのかわいい笑顔を\\n近くで見る以上の\\n癒やしはないよね♪', 8, 1, 1, 0, 0, 117601, 102, 5406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どう？\u3000看護師姿の\\nボクもかわいいでしょ\\nもっと近くで見る？', 1, 1, 2, 0, 0, 117601, 1, 5407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほら！\u3000美しいボクの\\n看護師姿を見たら\\n元気でちゃうでしょ？', 1, 1, 2, 0, 0, 117601, 2, 5408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('白衣の天使のボクも\\n最高に美しいね\\n存分に癒されてよ♪', 1, 1, 2, 0, 0, 117601, 3, 5409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('具合が悪いの？\\nならボクの美しい顔を\\n処方してあげる♪', 1, 1, 2, 0, 0, 117601, 4, 5410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ今日もボクと\\n一緒に美の追求に\\n付き合ってもらうよ♪', 4, 1, 2, 0, 0, 117601, 101, 5411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい天使のボクが\\nいつもそばにいるんだ\\nキミって幸せ者だね♪', 8, 1, 2, 0, 0, 117601, 102, 5412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さすがボク\\n目が覚めるような\\n美しさでしょ？', 1, 1, 2, 0, 1, 117601, 1, 5413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美は食で作られる\\n美容にいいものを\\n食べようよ！', 1, 1, 2, 0, 2, 117601, 2, 5414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふああ…早く寝よ？\\n夜更かしは美容の\\n大敵だからね', 1, 1, 2, 0, 3, 117601, 3, 5415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう～…\\nリラックスする\\nボクも美しい', 1, 1, 3, 0, 0, 117601, 2, 5417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクが抱きしめると\\n普段よりかわいく\\n見えちゃうね♪', 1, 1, 3, 0, 0, 117601, 3, 5418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美しいボクは\\n常にいい香りを\\nしていなくちゃね', 1, 1, 3, 0, 0, 117601, 4, 5419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('光がボクを照らしてる\\nんじゃなくて、ボクが\\n光を輝かせてるのさ', 1, 1, 3, 0, 0, 117601, 5, 5420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バランスのいい食事が\\n美しいボクを\\n作るのさ', 1, 1, 3, 0, 0, 117601, 7, 5422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…なるほど\\nこうすればより美しく\\nなれるかもしれない', 1, 1, 3, 0, 0, 117601, 8, 5423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間のためなら\\nきっと…どこまでも\\n強くなれるよね', 12, 1, 1, 0, 0, 105701, 103, 5425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンセスフォーム？\\n私と同じような力を\\n持ってる人がいるの？\\n会ってみたいな～！', 12, 1, 2, 0, 0, 105701, 103, 5426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここの空気は、\\nどうもゆるすぎて…\\n落ち着きませんわね', 1, 1, 1, 0, 0, 118001, 1, 5427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('陛下のお越しになる\\n別宅としては、\\n少し警備が\\n甘すぎでは？', 1, 1, 1, 0, 0, 118001, 2, 5428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらあら？\\nサッシにホコリが！\\nちょっとネコ助！\\n掃除は念入りに！', 1, 1, 1, 0, 0, 118001, 3, 5429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつまで入り浸って\\nいるのかと、\\n秘書に叱られて\\nしまいましたわ…', 1, 1, 1, 0, 0, 118001, 4, 5430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もういっそ、\\nここに間借りして\\n仕事しようかしら…？', 1, 1, 1, 0, 0, 118001, 5, 5431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('邪魔している身ですし\\n家事くらい\\nお手伝いさせなさいな', 4, 1, 1, 0, 0, 118001, 101, 5432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本当は、意外と\\n居心地が良いのかも…\\n陛下の気持ち、\\n少し分かりましたわ', 8, 1, 1, 0, 0, 118001, 102, 5433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっ…わたくしを\\n叩いても、ホコリなど\\nあまり出ませんわよ！', 1, 1, 2, 0, 0, 118001, 1, 5434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('陛下っ？\\nなんだ…貴方でしたの\\n用件は手短にお願いね', 1, 1, 2, 0, 0, 118001, 2, 5435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('別に、好き嫌いは\\nありませんけれど…\\n魔物料理って、意外と\\n美味なものですわね', 1, 1, 2, 0, 0, 118001, 3, 5436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('言っておきますけれど\\nわたくしは商売人です\\n荒事は専門外ですわよ', 1, 1, 2, 0, 0, 118001, 4, 5437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンセスナイトの\\n能力…なにか儲け話に\\n使えませんかしらね', 4, 1, 2, 0, 0, 118001, 101, 5438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴方がたのことも、\\n少しくらいは\\n信用してないことも\\nありませんでしてよ', 8, 1, 2, 0, 0, 118001, 102, 5439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\nさ、今日もバリバリ\\n働きますわよ！', 1, 1, 2, 0, 1, 118001, 1, 5440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ですわね\\n栄養補給をしつつ\\n働きますわよ！', 1, 1, 2, 0, 2, 118001, 2, 5441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('定時ですって？\\n関係ありません！\\nわたくし、まだまだ\\n働きますわよ～っ！', 1, 1, 2, 0, 3, 118001, 3, 5442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うっ…いけませんわ\\n日頃の疲れが…\\nふわぁ…', 1, 1, 3, 0, 0, 118001, 2, 5444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もふもふ…ふふっ♪\\n…なんですのっ、\\nなにかおかしくて！？', 1, 1, 3, 0, 0, 118001, 3, 5445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りですわね\\nわたくしの執務室にも\\n置きたいくらいですわ', 1, 1, 3, 0, 0, 118001, 4, 5446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いけませんわ…\\nこんなに暖かいと\\n日頃の疲れが…ふわぁ', 1, 1, 3, 0, 0, 118001, 5, 5447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう一つ食べたら\\n仕事に戻りますわよ？\\nあと一つだけ…', 1, 1, 3, 0, 0, 118001, 7, 5449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('商人にとって\\n知識は武器ですわ\\n陛下のため、貴方も\\nもっと勉強なさい？', 1, 1, 3, 0, 0, 118001, 8, 5450);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('故郷のお菓子を\\nいろいろ作ったんだ～\\nみんなに\\n配ってくるさ～♪', 1, 1, 1, 0, 0, 117701, 1, 5452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼ってどんな仮装が\\n似合うかな～？\\nシーサーとか？', 1, 1, 1, 0, 0, 117701, 2, 5453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャチャンプルー\\n作ってみよっと！\\nきっとおいしいさ～♪', 1, 1, 1, 0, 0, 117701, 3, 5454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('視線を感じるさ～\\nもしかして幽霊？\\nおしゃべりするさ～♪', 1, 1, 1, 0, 0, 117701, 4, 5455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっき作った\\nサーターアンダギー、\\n早く彼に\\n食べてほしいさ～♪', 1, 1, 1, 0, 0, 117701, 5, 5456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼のために、\\n特別なイタズラを\\n考えとくさ～♪', 4, 1, 1, 0, 0, 117701, 101, 5457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか彼と、\\n故郷のハロウィンを\\n楽しみたいさ～♪', 8, 1, 1, 0, 0, 117701, 102, 5458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンは\\n私たちが守るさ～♪\\nさ、見回りに行こ！', 1, 1, 2, 0, 0, 117701, 1, 5459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この制服、\\nハロウィンらしくて\\n大好きさ～♪', 1, 1, 2, 0, 0, 117701, 2, 5460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラする気ね～？\\nどんなことされるのか\\n楽しみさ～♪', 1, 1, 2, 0, 0, 117701, 3, 5461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャのランタン、\\n一緒に作ろ！\\n絶対楽しいよ～♪', 1, 1, 2, 0, 0, 117701, 4, 5462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子くれるの？\\nあは～、ありがとー♪\\nもぐもぐ…\\n優しい味がするさ～♪', 4, 1, 2, 0, 0, 117701, 101, 5463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミと一緒に過ごす\\nハロウィンは、\\nドキドキとワクワクが\\n止まらないさ～♪', 8, 1, 2, 0, 0, 117701, 102, 5464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンは\\n朝から大忙しさ～！\\nお菓子作り、\\n手伝ってほしいさ～', 1, 1, 2, 0, 1, 117701, 1, 5465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お化け屋敷に行こ！\\n一緒にいっぱい\\nドキドキしようね～♪', 1, 1, 2, 0, 2, 117701, 2, 5466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここからが\\nハロウィン本番さ～！\\n幽霊たちと\\nいっぱい遊ぶさ～♪', 1, 1, 2, 0, 3, 117701, 3, 5467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと休んだら、\\nお菓子作りを\\n再開するさ～♪', 1, 1, 3, 0, 0, 117701, 2, 5469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('でーじかわいいね～♪\\nこの子に仮装させたら\\nきっと似合うさ～♪', 1, 1, 3, 0, 0, 117701, 3, 5470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子みたいに\\n甘い匂い…\\nハロウィンらしい\\nいい香りさ～♪', 1, 1, 3, 0, 0, 117701, 4, 5471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソルの秋って\\n冷えるけど…\\nこれがあれば\\n体も心もぽかぽかさ～', 1, 1, 3, 0, 0, 117701, 5, 5472);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('故郷のご飯も\\nおいしいけど、\\nこっちのご飯も\\nでーじおいしいさ～♪', 1, 1, 3, 0, 0, 117701, 7, 5474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パンプキンパイの\\nレシピは…なるほど～\\n勉強になるさ～♪', 1, 1, 3, 0, 0, 117701, 8, 5475);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('全部おいしそうで\\nどれから食べるか\\n迷っちゃうさ～♪', 1, 1, 3, 0, 0, 117701, 12, 5477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ムっ！\u3000幽霊の気配を\\n感じるデス！\\nさあ姿を現すデス！', 1, 1, 1, 0, 0, 117801, 1, 5479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ムムム…\\n妖魔の力を忍法に\\n使えないでショウか…', 1, 1, 1, 0, 0, 117801, 2, 5480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪しい妖魔を\\n成敗するデス！\\nハロウィンの平和は\\nワタシが守りマスよ！', 1, 1, 1, 0, 0, 117801, 3, 5481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシの祭囃子が\\n聞こえマスかー？\\nさあ集まるデース！\\n陽気に踊りまショウ！', 1, 1, 1, 0, 0, 117801, 4, 5482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お祭りは\\n楽しんだ者勝ちデス！\\n踊らにゃ\\nソンソンデス！', 1, 1, 1, 0, 0, 117801, 5, 5483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊になる前に\\n天下統一を\\n果たしたいデスね', 4, 1, 1, 0, 0, 117801, 101, 5484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの世に行っても\\nショーグンは\\nワタシの大事な\\nショーグンデス！', 8, 1, 1, 0, 0, 117801, 102, 5485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグン！\\n悪霊退治に\\n出かけるデース！', 1, 1, 2, 0, 0, 117801, 1, 5486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('妖魔を家来に\\nしてみるのは\\nどうデス？', 1, 1, 2, 0, 0, 117801, 2, 5487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マントを使って\\nウツセミの術の精度を\\n高めるデス！', 1, 1, 2, 0, 0, 117801, 3, 5488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンにちなんだ\\n新しい忍法…\\nすなわち妖忍法の\\n開発を急ぐデス！', 1, 1, 2, 0, 0, 117801, 4, 5489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの世でも\\nショーグンに\\nお仕えしマスよー！', 4, 1, 2, 0, 0, 117801, 101, 5490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ショーグンもワタシと\\nハロウィンパレードを\\n踊り明かしまセンか？', 8, 1, 2, 0, 0, 117801, 102, 5491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございマス！\\n天下統一に向けて\\n急いで準備するデス！', 1, 1, 2, 0, 1, 117801, 1, 5492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹減ってまセンか？\\nハロウィンスイーツで\\n休憩するデ〜ス', 1, 1, 2, 0, 2, 117801, 2, 5493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かしすると幽霊が\\nでるかもしれまセン…\\nヒュ〜ドロロロ〜…', 1, 1, 2, 0, 3, 117801, 3, 5494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もふもふなところが\\nわたあめちゃんに\\n似ていマス。わんっ！', 1, 1, 3, 0, 0, 117801, 2, 5496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬいぐるみや人形には\\n魂が宿るという\\n言い伝えがありマス…\\nマカフシギデ〜ス', 1, 1, 3, 0, 0, 117801, 3, 5497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウ〜ム…\\nなんとも怪しい\\n香りがしマスね！', 1, 1, 3, 0, 0, 117801, 4, 5498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パレードの熱気に\\n負けないくらい\\n熱いデス！', 1, 1, 3, 0, 0, 117801, 5, 5499);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ついつい食べすぎて\\nしまうのは\\n妖魔のせいデスか！？', 1, 1, 3, 0, 0, 117801, 7, 5501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トーゴク妖怪の\\n図鑑デス！\u3000個性的な\\n妖怪ばかりデスね！', 1, 1, 3, 0, 0, 117801, 8, 5502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンの甘味を\\n集めまシタよ！\\nショーグンへの\\n貢ぎ物デス！', 1, 1, 3, 0, 0, 117801, 12, 5504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼と二人で\\n買い物に…って…\\nこれってデートに\\nなっちゃうのかな！？', 12, 1, 1, 0, 0, 101301, 103, 5531);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とうっ！\u3000どうどう？\\n今の決めポーズ！\\nかっこいいよね♪', 12, 1, 2, 0, 0, 101301, 103, 5532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイとおそろの\\nハロウィンコスとか\\nしてみたいな～', 1, 1, 1, 0, 0, 117901, 1, 5533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャ料理かぁ…\\n作ったらヒデサイ\\n食べてくれるかな～', 1, 1, 1, 0, 0, 117901, 2, 5534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンスイーツ…\\nどれもおいしすぎて\\n激ヤバなんですけど！', 1, 1, 1, 0, 0, 117901, 3, 5535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('霊界ってどんなとこ\\nなんだろ～\\nわりと近所だったり？', 1, 1, 1, 0, 0, 117901, 4, 5536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服をハロウィンっぽく\\nアレンジするのも\\nたのしーよね♪', 1, 1, 1, 0, 0, 117901, 5, 5537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイと一緒に\\nハロウィンパーティー\\n…えへへ、楽しみ～', 4, 1, 1, 0, 0, 117901, 101, 5538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイといると\\nドキドキする…\\nなんでだろ～？', 8, 1, 1, 0, 0, 117901, 102, 5539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねねね、うちらも\\nハロウィンパレード\\n見に行こー？', 1, 1, 2, 0, 0, 117901, 1, 5540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンセイバーズ\\nしゅつどーう！\\nヒデサイも行こ～♪', 1, 1, 2, 0, 0, 117901, 2, 5541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マントのロゴ\\nかっこいいっしょ～？\\nカボきちってゆーんだ', 1, 1, 2, 0, 0, 117901, 3, 5542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トリックオア\\nトリート！\\nねえねえヒデサイ\\nお菓子ちょうだい♪', 1, 1, 2, 0, 0, 117901, 4, 5543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイも\\nメイクしてみる？\\nハロウィンぽいやつ♪', 4, 1, 2, 0, 0, 117901, 101, 5544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイのこと\\nうちがいつでも\\nあっためたげるね！\\n…あ！\u3000手、手の話！', 8, 1, 2, 0, 0, 117901, 102, 5545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンのイベント\\n朝からでも\\nやってるかな～？', 1, 1, 2, 0, 1, 117901, 1, 5546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャでおやつ\\n作ってみたんだ～\\nヒデサイ食べてみて！', 1, 1, 2, 0, 2, 117901, 2, 5547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンの夜って\\nやっぱテンション\\n上がるよね～♪', 1, 1, 2, 0, 3, 117901, 3, 5548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('超ふかふかしてる～\\nちょっと休憩させて\\nもらっちゃお', 1, 1, 3, 0, 0, 117901, 2, 5550);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…\\nもにカワすぎて\\nつらいんですけど～！', 1, 1, 3, 0, 0, 117901, 3, 5551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィン限定の\\nフレグランスじゃん！\\nいい匂いする～♪', 1, 1, 3, 0, 0, 117901, 4, 5552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やばばば…\\nあったかくて\\n眠くなっちゃう～', 1, 1, 3, 0, 0, 117901, 5, 5553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ食べて\\nもうひとがんばり\\nしよーっと！', 1, 1, 3, 0, 0, 117901, 7, 5555);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンっぽい\\nファッションとか\\n載ってないかなぁ？', 1, 1, 3, 0, 0, 117901, 8, 5556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子いっぱいだ～！\\nあとでヒデサイにも\\n持ってってあげよ～', 1, 1, 3, 0, 0, 117901, 12, 5558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お掃除が終わったら\\n次は書類を片付けて…\\nその次は…', 1, 1, 1, 0, 0, 118501, 1, 5560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('皆さんが冒険している\\n間の留守は私に\\nお任せください♪', 1, 1, 1, 0, 0, 118501, 2, 5561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美食殿の皆さんが\\n持ってきてくれる\\nお土産が楽しみです♪', 1, 1, 1, 0, 0, 118501, 3, 5562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネビアさんとは\\nときどき一緒にお茶\\nする仲なんです', 1, 1, 1, 0, 0, 118501, 4, 5563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスの乱れは\\nギルドの乱れ\\n整理整頓が大切です', 1, 1, 1, 0, 0, 118501, 5, 5564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵なギルドハウスの\\n管理人ができて\\nとっても幸せです♪', 4, 1, 1, 0, 0, 118501, 101, 5565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('皆さんをほんの少し\\n特別扱いしちゃう\\n私がいます', 8, 1, 1, 0, 0, 118501, 102, 5566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何かわからないことが\\nあるときは私に\\n聞いてくださいね', 1, 1, 2, 0, 0, 118501, 1, 5567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('書類を書いていると\\n落ち着きます…\\n一緒にどうですか？', 1, 1, 2, 0, 0, 118501, 2, 5568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたのまわりは\\nいつも賑やかで\\n楽しいですね♪', 1, 1, 2, 0, 0, 118501, 3, 5569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ！\u3000お頼みしたい\\nことがあって\\n探してたんです♪', 1, 1, 2, 0, 0, 118501, 4, 5570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギブアンドテイクは\\n大切です。たまには\\nお礼させてください♪', 4, 1, 2, 0, 0, 118501, 101, 5571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('陰に日向にあなたを\\n支えていきます♪\\n期待していてください', 8, 1, 2, 0, 0, 118501, 102, 5572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\n管理人として\\nがんばります♪', 1, 1, 2, 0, 1, 118501, 1, 5573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹がすきました…\\nそろそろお昼に\\nしませんか？', 1, 1, 2, 0, 2, 118501, 2, 5574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間…\\n皆さんといると一日が\\nあっという間です', 1, 1, 2, 0, 3, 118501, 3, 5575);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良質なお仕事は\\n良質な休憩から\\nです♪', 1, 1, 3, 0, 0, 118501, 2, 5577);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいものに\\n囲まれてお仕事できる\\nのは幸せですね♪', 1, 1, 3, 0, 0, 118501, 3, 5578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お仕事に集中できる\\nアロマを設置するのも\\nよさそうですね♪', 1, 1, 3, 0, 0, 118501, 4, 5579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカ温まりながら\\n書類仕事をするのも\\nいいものですね…', 1, 1, 3, 0, 0, 118501, 5, 5580);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('栄養補給しないと\\n頭が回りませんからね\\nきちんと食べましょう', 1, 1, 3, 0, 0, 118501, 7, 5582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新条例はこのように\\n活用されている、と…\\nふむふむ…', 1, 1, 3, 0, 0, 118501, 8, 5583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('会合用の資料と\\n連載のネーム…\\nどっちを片付けよう？', 1, 1, 1, 0, 0, 106701, 1, 5585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イノリちゃん、また\\nお金くすねてる…\\n帰ってきたら\\nお尻ペンペンだ♪', 1, 1, 1, 0, 0, 106701, 2, 5586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カヤちゃんの装備\\n傷むの早いなぁ〜\\nメンテしてあげないと', 1, 1, 1, 0, 0, 106701, 3, 5587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、ラーゴのご飯\\n買いに行かないと\\n今日は何がいいかな？', 1, 1, 1, 0, 0, 106701, 4, 5588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここの人たちは見てて\\n飽きない人ばっかり♪\\n漫画の参考にしよ〜', 1, 1, 1, 0, 0, 106701, 5, 5589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('また一緒に買い物にも\\n行きたいし、冒険も\\nしたいな〜…♪', 4, 1, 1, 0, 0, 106701, 101, 5590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…君は見てるだけで\\n満足なの？ ちゃんと\\n触って欲しいな…♪', 8, 1, 1, 0, 0, 106701, 102, 5591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の目が見たいの？\\nいいけど…魅了されて\\n魂が壊れちゃうよ…？\\n…冗談で〜す☆', 1, 1, 2, 0, 0, 106701, 1, 5592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラーゴがね、君に\\n遊んで欲しいって☆\\n仲良くしてあげてね', 1, 1, 2, 0, 0, 106701, 2, 5593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アシスタントの仕事\\n気に入ってくれたなら\\nまたお願いしていい？', 1, 1, 2, 0, 0, 106701, 3, 5594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が覚醒できるか？\\n見せてあげたいけど…\\nすごいことになるから\\nまた今度で♪', 1, 1, 2, 0, 0, 106701, 4, 5595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽しいトラブルが\\nあったら、とりあえず\\n声はかけて欲しいな♪', 4, 1, 2, 0, 0, 106701, 101, 5596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マッサージお願い♪\\n変なところは…\\n少しだけなら☆', 8, 1, 2, 0, 0, 106701, 102, 5597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう〜♪\\n今日も一日、一緒に\\nがんばっていこうね', 1, 1, 2, 0, 1, 106701, 1, 5598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いちゃった…\\n一緒にお昼行かない？\\nいいお店があるんだ〜', 1, 1, 2, 0, 2, 106701, 2, 5599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君、眠れないの？\\n誰かに見られてる？\\n…きっと気のせいだよ', 1, 1, 2, 0, 3, 106701, 3, 5600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっと休憩〜…\\nこのまま原稿すれば\\n疲れなくなるのかな？', 1, 1, 3, 0, 0, 106701, 2, 5602);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい〜♪\\nラーゴのお友達に\\nなってくれる？', 1, 1, 3, 0, 0, 106701, 3, 5603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り〜♪\\nこの目でどう見えるか\\n伝えられたらいいのに', 1, 1, 3, 0, 0, 106701, 4, 5604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほどほどなのが\\nちょうどいい時も\\nあるよね…♪', 1, 1, 3, 0, 0, 106701, 5, 5605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この味付け…\\nあっちでも再現\\nできるかな？', 1, 1, 3, 0, 0, 106701, 7, 5607);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、面白い♪\\nイノリちゃんの買う\\n漫画にハズレなし☆', 1, 1, 3, 0, 0, 106701, 8, 5608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私…23歳だもん\\n魔法少女だなんて\\n名乗れないわ…', 1, 1, 1, 0, 0, 119001, 1, 5610);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あん、どぅ、とろわ〜\\nみんなイイ子に\\nな〜る♪', 1, 1, 1, 0, 0, 119001, 2, 5611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ！\u3000イケナイ子の\\n気配がするわ！\\n風紀の乱れは\\n先生が許しませんっ！', 1, 1, 1, 0, 0, 119001, 3, 5612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで闇の力が\\n発動したら大変だわ！\\nやだっ…そう思ったら\\n緊張して…ダメぇ〜！', 1, 1, 1, 0, 0, 119001, 4, 5613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オイタした子はみんな\\nどうしてうれしそうに\\n私の愛のムチを\\n欲しがるのかしら…？', 1, 1, 1, 0, 0, 119001, 5, 5614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子に次は何を\\n教えてあげようかしら\\n愛？\u3000希望？\\nそれとも…♪', 4, 1, 1, 0, 0, 119001, 101, 5615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子のことを\\n考えると、愛と希望で\\n胸がいっぱいになるの', 8, 1, 1, 0, 0, 119001, 102, 5616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先生なのに闇の力を\\n持ってるのは秘密よ？\\n他の子には\\n知られたくないから…', 1, 1, 2, 0, 0, 119001, 1, 5617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('秘密の授業の内容？\\nそれは…あんなことや\\nこんなことよ♪\\nそれから、それから…', 1, 1, 2, 0, 0, 119001, 2, 5618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しーっ！\u3000私の正体が\\nルーセント学院の\\n先生だって、ここでは\\n秘密にしててね？', 1, 1, 2, 0, 0, 119001, 3, 5619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら？\u3000補習して\\nほしいの？\u3000いいわよ\\n君のお願いなら\\nなんでも聞いちゃう♪', 1, 1, 2, 0, 0, 119001, 4, 5620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イイ子にはごほうびを\\nあげなくちゃ！\\n君はなにが欲しい？\\n遠慮しちゃダメよ？', 4, 1, 2, 0, 0, 119001, 101, 5621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君との秘密が\\nまた一つ\\n増えちゃったね♪', 8, 1, 2, 0, 0, 119001, 102, 5622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\n元気に過ごしましょう\\n先生が指導してあげる', 1, 1, 2, 0, 1, 119001, 1, 5623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜まで頑張れるように\\nお昼ご飯はしっかり\\n食べましょう〜！', 1, 1, 2, 0, 2, 119001, 2, 5624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かしはダメよ？\\nイケナイ子が\\nすることです！', 1, 1, 2, 0, 3, 119001, 3, 5625);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('闇の力に振り回されて\\nもうヘトヘトよ〜\\n心も体も\\n癒されたいわ〜', 1, 1, 3, 0, 0, 119001, 2, 5627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『秘密の学び舎』に\\nこっそり連れて\\n行っちゃおうかしら♪', 1, 1, 3, 0, 0, 119001, 3, 5628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イケナイ甘い香り…\\nなんだか胸の奥が\\n熱くなってきたわ…♪', 1, 1, 3, 0, 0, 119001, 4, 5629);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やんっ♪\\n燃え上がる愛みたい♪\\n火照ってきちゃった♪', 1, 1, 3, 0, 0, 119001, 5, 5630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('生徒の見本に\\nなれるように\\n好き嫌いはしないの', 1, 1, 3, 0, 0, 119001, 7, 5632);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『学び舎に咲く禁断の\\n愛』？\u3000気になるわ…\\nううん、ダメよっ！\\nでも…ちょっとだけ…', 1, 1, 3, 0, 0, 119001, 8, 5633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次に会う時は、\\nまたあそこに一緒に…\\nえへへ…！', 12, 1, 1, 0, 0, 106301, 103, 5635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('横顔見てるの、\\nバレてないよね…？\\n…ちらっ', 12, 1, 2, 0, 0, 106301, 103, 5636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('背が少し伸びたか！？\\nあ、あいつのところへ\\n報告に行かねばっ！', 12, 1, 1, 0, 0, 105301, 103, 5637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私も貴公の隣に\\n立っていられるよう\\n日々精進していくぞ！', 12, 1, 2, 0, 0, 105301, 103, 5638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ～\\nドＭミストが\\nあふれてしまいます～', 1, 1, 1, 0, 0, 119101, 1, 5639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女として\\nクウカ頑張ります～！\\n愛と希望の妄想を…！', 1, 1, 1, 0, 0, 119101, 2, 5640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('決めポーズの練習より\\nやられポーズの練習を\\nしておきます…♪', 1, 1, 1, 0, 0, 119101, 3, 5641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('快感を溜めに溜めて\\n放つドＭビームは\\n最高ですよ～', 1, 1, 1, 0, 0, 119101, 4, 5642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はっ！\\nこれは闇の気配！\\n…クウカ自身でした', 1, 1, 1, 0, 0, 119101, 5, 5643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさん…ぐふふ…\\nクウカを縛りあげ…\\nじゅるりぃ～♪', 4, 1, 1, 0, 0, 119101, 101, 5644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんに攻められる\\nことで、クウカは進化\\nしてゆくのです～！', 8, 1, 1, 0, 0, 119101, 102, 5645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぅっ！\\nもっと激しく…！\\n情熱的に～～～！', 1, 1, 2, 0, 0, 119101, 1, 5646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカの変身シーンを\\nじっくり眺めたい！？\\nは、恥ずかしいです～', 1, 1, 2, 0, 0, 119101, 2, 5647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「本当に魔法少女か\\n確かめてやるよ…！」\\nドＳさんはそう言って\\nクウカを…ぐふふ…♪', 1, 1, 2, 0, 0, 119101, 3, 5648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛と希望の力が\\nクウカの中に…\\nこの胸の高鳴りが…？', 1, 1, 2, 0, 0, 119101, 4, 5649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃあんっ！\\nそこです～っ！\\nもっと、もっと～♪', 4, 1, 2, 0, 0, 119101, 101, 5650);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカをこんなに\\n悦ばせるのは\\nドＳさんだけです…♪', 8, 1, 2, 0, 0, 119101, 102, 5651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明るい時間に出歩くと\\n目立ちますね\\n魔法少女の衣装…', 1, 1, 2, 0, 1, 119101, 1, 5652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼の見回りです～♪\\nああ～うっかりドＭを\\n増やしてしまいました', 1, 1, 2, 0, 2, 119101, 2, 5653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜！\u3000それはクウカが\\n活性化する時間です！\\n闇の活動開始です～♪', 1, 1, 2, 0, 3, 119101, 3, 5654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気の緩んだクウカを\\nドＳさんの鋭い牙が\\n狙っています～♪', 1, 1, 3, 0, 0, 119101, 2, 5656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女のマスコット\\nにいいかもしれません\\nもっと鎖とか飾りを…', 1, 1, 3, 0, 0, 119101, 3, 5657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魅惑的な香りです～\\nドＭミストの香りに\\n似て…いや違いますね', 1, 1, 3, 0, 0, 119101, 4, 5658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火照る体…紅潮した\\nクウカの肢体を熱く\\n見つめるドＳさん…', 1, 1, 3, 0, 0, 119101, 5, 5659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食欲を満たした次は\\n何を満たせば\\nいいですかねぇ～♪', 1, 1, 3, 0, 0, 119101, 7, 5661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女がひどい目に\\n遭う物語は…\\nなさそうですね…', 1, 1, 3, 0, 0, 119101, 8, 5662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ケーキも悪くないけど\\nプリンが一番なの\\nでもせっかくだから\\n両方もらってやるの！', 1, 1, 1, 0, 0, 119901, 1, 5664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスって聞くと\\nなんだかあったかい\\n気分になるの～', 1, 1, 1, 0, 0, 119901, 2, 5665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('煙突がなくても\\nミヤコはどこからでも\\nおうちに入れるの♪', 1, 1, 1, 0, 0, 119901, 3, 5666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イブもプリン！\\nクリスマスもプリン！\\nプレゼントもプリン！', 1, 1, 1, 0, 0, 119901, 4, 5667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスツリーの\\n高いところの\\n飾りつけは、ミヤコに\\nまかせろなの～！', 1, 1, 1, 0, 0, 119901, 5, 5668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツのプレゼント\\n楽しみなの～\\nきっと最っ高に特別な\\nプリンなの～♪', 4, 1, 1, 0, 0, 119901, 101, 5669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミヤコがサンタなら\\nアイツはトナカイなの\\nつまりお似合いって\\nことなの～♪', 8, 1, 1, 0, 0, 119901, 102, 5670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミヤコ、プレゼントを\\n配りにいくの～♪\\nオマエも手伝えなの！', 1, 1, 2, 0, 0, 119901, 1, 5671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエにも飾りつけ\\nしてやるの！\\n頭にプリンを乗せると\\nかわいいの♪', 1, 1, 2, 0, 0, 119901, 2, 5672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊のミヤコが\\nいるなら、サンタも\\nいて当たり前なの～！', 1, 1, 2, 0, 0, 119901, 3, 5673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('靴下にプリンを\\n入れたらつぶれるの\\nだからプリンは直接\\nミヤコによこすの～！', 1, 1, 2, 0, 0, 119901, 4, 5674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はプリンだけじゃ\\n満足してやらないの！\\nミヤコをたくさん\\n甘やかせなの！', 4, 1, 2, 0, 0, 119901, 101, 5675);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミヤコのプリン\\nオマエになら一個…\\nうう～、一口だけ\\nあげてもいいの！', 8, 1, 2, 0, 0, 119901, 102, 5676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サンタの朝は早いの～\\nミヤコも早起きして\\nプレゼント準備したの\\nとってもえらいの♪', 1, 1, 2, 0, 1, 119901, 1, 5677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は一日中\\nみんなと遊ぶの～！\\nオマエも来いなの！', 1, 1, 2, 0, 2, 119901, 2, 5678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなが寝たら\\nチャンスなの～\\nこっそりプレゼント\\n配りにいくの♪', 1, 1, 2, 0, 3, 119901, 3, 5679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むふー、気持ちいいの\\nこういうプレゼントも\\nいいかもしれないの', 1, 1, 3, 0, 0, 119901, 2, 5681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ気に入ったの～\\nプリンとアイツの\\n次くらいなの♪', 1, 1, 3, 0, 0, 119901, 3, 5682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいにおいなの～\\nうっかり成仏\\nしちゃいそうなの…', 1, 1, 3, 0, 0, 119901, 4, 5683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここに飾っといた\\n雪だるま\\nなくなっちゃったの\\nきっと成仏したの～', 1, 1, 3, 0, 0, 119901, 5, 5684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはオマエがくれる\\nプリンとは\\n別腹なの～', 1, 1, 3, 0, 0, 119901, 7, 5686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プリンケーキ…\\nこれならミヤコにも\\n作れそうなの！\\nさっそく作るの！', 1, 1, 3, 0, 0, 119901, 8, 5687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('びっくりしたの～！\\n幽霊のミヤコを\\n驚かすなんて…\\nなかなかやるの！', 1, 1, 3, 0, 0, 119901, 14, 5689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コイツの中…\\nあったかいの～♪\\n昼寝にぴったりなの～', 1, 1, 3, 0, 0, 119901, 15, 5690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリークリスマス！\\n聖夜に笑顔を\\nお届けするべ♪', 1, 1, 1, 0, 0, 119201, 1, 5691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマス前は\\n乳製品がよく売れて\\nありがてぇけんど…\\n目が回る忙しさだ～', 1, 1, 1, 0, 0, 119201, 2, 5692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場で売る\\nクリスマスリースを\\n作っておかねぇと…', 1, 1, 1, 0, 0, 119201, 3, 5693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの動物たちにも\\nクリスマスプレゼント\\n用意しなきゃなぁ', 1, 1, 1, 0, 0, 119201, 4, 5694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスに向けた\\n限定商品とか\\n作ってみるべか？', 1, 1, 1, 0, 0, 119201, 5, 5695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんへの\\nプレゼント選び…\\nここでボケるか…？\\nやめておくべか…？', 4, 1, 1, 0, 0, 119201, 101, 5696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オラ、あんちゃんから\\n本当にたくさんの物を\\nもらってんなぁ…', 8, 1, 1, 0, 0, 119201, 102, 5697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('雪遊びがしたいべか？\\nへへっ、あんちゃん\\nには負けねぇど！', 1, 1, 2, 0, 0, 119201, 1, 5698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ディナーと一緒に\\n聖夜のお笑いライブを\\nすんのはどうだべか？\\nツッコミは任せたべ！', 1, 1, 2, 0, 0, 119201, 2, 5699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒くなってくると\\n鍋が食べたくなるべや\\nあんちゃんはどうだ？', 1, 1, 2, 0, 0, 119201, 3, 5700);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんは\\nサンタさんのこと\\n信じてるだか？', 1, 1, 2, 0, 0, 119201, 4, 5701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どでかいクリスマス\\nケーキをこさえるべ\\nあんちゃんも作るの\\n手伝ってくんろ♪', 4, 1, 2, 0, 0, 119201, 101, 5702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんが\\nオラの旦那だったら…\\nって、あんちゃん！\\n今の聞いてただか！？', 8, 1, 2, 0, 0, 119201, 102, 5703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場の朝は早いど！\\nさぁてと、まずは\\n雪かきしに行くべや', 1, 1, 2, 0, 1, 119201, 1, 5704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんちゃんも一緒に\\nお昼食べてくか？\\n採れたての冬野菜は\\nうんまいど～♪', 1, 1, 2, 0, 2, 119201, 2, 5705);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よい子は早く寝ねぇと\\nサンタさんが\\n来てくれねぇべよ？', 1, 1, 2, 0, 3, 119201, 3, 5706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうのリンリンが\\n好きそうだな…\\nプレゼント候補に\\n入れておくべ！', 1, 1, 3, 0, 0, 119201, 2, 5708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もふもふしてて\\nなまらめんこくて…\\nあぁ…癒されるべや…', 1, 1, 3, 0, 0, 119201, 3, 5709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この匂い…\\n気持ちが和むべや\\n夢心地になっちまうな', 1, 1, 3, 0, 0, 119201, 4, 5710);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったけぇところは\\n落ち着くなぁ…\\nつい眠くなっちまう', 1, 1, 3, 0, 0, 119201, 5, 5711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、この味は…！\\n…うーん、もっと\\nリアクション芸も\\n練習しねぇとな', 1, 1, 3, 0, 0, 119201, 7, 5713);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオシオって\\nどんな本読んでんだ？\\n…難しい字が\\nぎっしりだべや…', 1, 1, 3, 0, 0, 119201, 8, 5714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この仕掛け…\\nオラのコントに\\n活かせるかも\\nしんねぇな', 1, 1, 3, 0, 0, 119201, 14, 5716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この着ぐるみで\\nリマリマのモノマネを\\n練習してみるべか…？', 1, 1, 3, 0, 0, 119201, 15, 5717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっとキレイになって\\nアイツにぎゃふんと\\n言わせてやるんだから', 12, 1, 1, 0, 0, 105001, 103, 5718);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシのこと\\nどう思う？\\nかわいいって…そこは\\nキレイって言ってよね', 12, 1, 2, 0, 0, 105001, 103, 5719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハートマークの刺繍…\\nは、やりすぎですかね\\nいやちょっとくらい\\nアピールしてみても…', 1, 1, 1, 0, 0, 119301, 1, 5720);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('雪降らないかな～\\nそしたらお兄ちゃんと\\n雪だるま作ったり\\nできるのに～', 1, 1, 1, 0, 0, 119301, 2, 5721);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントを入れる\\n靴下…いくつ編んでも\\n足りません～！', 1, 1, 1, 0, 0, 119301, 3, 5722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんとの\\nクリスマスデートは\\n早い者勝ちですからね\\n負けませんよ～！', 1, 1, 1, 0, 0, 119301, 4, 5723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスだし…\\n受験勉強は今日だけ\\nお休みです♪', 1, 1, 1, 0, 0, 119301, 5, 5724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと\\nおそろいのコーデで\\nクリスマスデート…\\nしたいなぁ～！', 4, 1, 1, 0, 0, 119301, 101, 5725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに\\nプレゼントする編み物\\nこれで３着目～と♪\\nあれ、作りすぎ？', 8, 1, 1, 0, 0, 119301, 102, 5726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ、もっと近くで\\n見たくありませんか？\\n私のとっておきの\\nクリスマスコーデ♪', 1, 1, 2, 0, 0, 119301, 1, 5727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんが風邪を\\n引いたら一大事です！\\n私の編み物で暖かく\\nしてあげます♪', 1, 1, 2, 0, 0, 119301, 2, 5728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、ほっぺに\\nケーキのクリームが\\nついちゃってますよ♪\\n私がとってあげます！', 1, 1, 2, 0, 0, 119301, 3, 5729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん！\\nケーキ、あーんって\\nしてあげます！\\nほら、あーん♪', 1, 1, 2, 0, 0, 119301, 4, 5730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスは大切な\\n人と過ごすものっ！\\nお兄ちゃん…妹の予定\\n空いてますよっ！', 4, 1, 2, 0, 0, 119301, 101, 5731);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスはずっと、\\nお兄ちゃんと一緒に\\nいたい…って言ったら\\n欲張り…すぎですか？', 8, 1, 2, 0, 0, 119301, 102, 5732);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きは３本お得！\\n…クリスマスなら\\n追加で10本ぐらい\\nもらえちゃうかも！？', 1, 1, 2, 0, 1, 119301, 1, 5733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はケーキ？\\nそれとも七面鳥？\\nごちそういっぱいで\\n迷っちゃいますね～♪', 1, 1, 2, 0, 2, 119301, 2, 5734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと\\nクリスマスに夜更かし\\n…えへへ、ちょっぴり\\nドキドキしちゃう♪', 1, 1, 2, 0, 3, 119301, 3, 5735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('編み物をするには\\n絶好のくつろぎ空間\\nですね～♪', 1, 1, 3, 0, 0, 119301, 2, 5737);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんというかわいさ…\\nクリスマス\\nプレゼントに\\nもってこいですね！', 1, 1, 3, 0, 0, 119301, 3, 5738);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これがお兄ちゃんの\\nお部屋の香り…？\\nんん～！\u3000ずっと\\nかいでいたいです～♪', 1, 1, 3, 0, 0, 119301, 4, 5739);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ、あったか～い…\\n冬場はこういうのが\\nありがたいですね～♪', 1, 1, 3, 0, 0, 119301, 5, 5740);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごちそうだぁ～♪\\nほら、お兄ちゃんも\\n食べて食べてっ！', 1, 1, 3, 0, 0, 119301, 7, 5742);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスデートの\\n必勝法…こ、これは\\n読むしかないです！', 1, 1, 3, 0, 0, 119301, 8, 5743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、すごいです～！\\nこれを飾っておけば\\nクリスマスが一層\\n賑やかになりますね♪', 1, 1, 3, 0, 0, 119301, 14, 5745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぷらーいずっ！\\nリマちゃんじゃなくて\\nリノちゃんでした～！', 1, 1, 3, 0, 0, 119301, 15, 5746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミにもミソギにも\\nあの人にも頼りに\\nしてもらえるように\\nしっかりしなきゃ！', 1, 1, 1, 0, 0, 120601, 1, 5747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミはにんじんを\\n食べられてすごいな…\\n私も見習わなきゃ\\nがんばろう…！', 1, 1, 1, 0, 0, 120601, 2, 5748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギから怖い話\\n聞いちゃった…\\nうぅ…誰か一緒に\\nいてくれないかな', 1, 1, 1, 0, 0, 120601, 3, 5749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('立派な大人に\\nなれるように\\nいっぱい勉強\\nしておかなくっちゃ！', 1, 1, 1, 0, 0, 120601, 4, 5750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか…あの人の\\nあやしい視線を\\n感じるような…？', 1, 1, 1, 0, 0, 120601, 5, 5751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人に勉強を\\n教えられるように\\nしっかり予習を\\nしておこうっと…！', 4, 1, 1, 0, 0, 120601, 101, 5752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はあの人と\\n一緒に冒険できる…\\nなんだかワクワク\\nしてきちゃった…！', 8, 1, 1, 0, 0, 120601, 102, 5753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、いいとこに来て\\nくれましたね！\\nあなたに頼みたい\\nことがあるんです！', 1, 1, 2, 0, 0, 120601, 1, 5754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃあっ！？\\nへ、変なところを\\n触らないでください！', 1, 1, 2, 0, 0, 120601, 2, 5755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうですかこの格好？\\nかわいい、ですか…？\\nそ、そうですか…\\nありがとうございます', 1, 1, 2, 0, 0, 120601, 3, 5756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃあっ…！\\nすみません、勉強に\\n集中してたので\\n驚いちゃいました', 1, 1, 2, 0, 0, 120601, 4, 5757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒に勉強して立派な\\n大人になりましょうね\\n私がそばで見張ってて\\nあげます', 4, 1, 2, 0, 0, 120601, 101, 5758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ立派ではないかも\\nですけど、私よりも\\n大人なあなたのことは\\n頼りにしてますからね', 8, 1, 2, 0, 0, 120601, 102, 5759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('立派な大人は\\n朝の時間の使い方が\\n上手だと聞きました\\nあなたはどうですか？', 1, 1, 2, 0, 1, 120601, 1, 5760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミとミソギと\\nあなたと…大事な人と\\n一緒のお昼ごはんは\\nやさしい味がしますね', 1, 1, 2, 0, 2, 120601, 2, 5761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ…怖い話を\\n思い出しちゃいました\\n寝るまで一緒に\\nいてくれますか…？', 1, 1, 2, 0, 3, 120601, 3, 5762);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すごい座り心地…！\\nとっても勉強が\\nはかどりそう…！', 1, 1, 3, 0, 0, 120601, 2, 5764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子…なんだか\\nミミに似てるような\\n気がする…ふふっ♪', 1, 1, 3, 0, 0, 120601, 3, 5765);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…♪\\n勉強で疲れた\\n頭がリフレッシュ\\nできそうです', 1, 1, 3, 0, 0, 120601, 4, 5766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかだ…♪\\nミミとミソギと\\nあの人と一緒に\\nいるときみたい', 1, 1, 3, 0, 0, 120601, 5, 5767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい食べたら\\n早く大人になれたり\\nしないかな…？', 1, 1, 3, 0, 0, 120601, 7, 5769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あう…\\n知らない単語が…\\nちゃんと調べて\\n覚えなくっちゃ…！', 1, 1, 3, 0, 0, 120601, 8, 5770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うさぎさんが\\nぴょ～んぴょん♪\\nみんなえがおで\\nるんたった～♪', 1, 1, 1, 0, 0, 120401, 1, 5773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キョウカちゃんも\\nいつかにんじんさんを\\n好きになってくれたら\\nうれしいな～♪', 1, 1, 1, 0, 0, 120401, 2, 5774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のミソギちゃんの\\nイタズラ、びっくり\\nしちゃったけど\\nおもしろかったな～♪', 1, 1, 1, 0, 0, 120401, 3, 5775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このおうち、いつも\\nいろんな人がいて\\nドキドキぴょんぴょん\\nって楽しいな～♪', 1, 1, 1, 0, 0, 120401, 4, 5776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいお天気～♪\\nお外でみんなと\\nいっぱい遊びたいな♪', 1, 1, 1, 0, 0, 120401, 5, 5777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギちゃんも\\nキョウカちゃんも\\nおにいちゃんがいると\\nずっと笑顔だね～♪', 4, 1, 1, 0, 0, 120401, 101, 5778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんにはやく\\nあいたいな～♪\\nまだかな、まだかな♪', 8, 1, 1, 0, 0, 120401, 102, 5779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ♪\\nおにいちゃんに\\nなでなでされると\\nぽかぽかするね♪', 1, 1, 2, 0, 0, 120401, 1, 5780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聞いて、おにいちゃん\\nさっきね、かわいい\\nちょうちょさんに\\n会ったんだよ～♪', 1, 1, 2, 0, 0, 120401, 2, 5781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわっ…！\\nおにいちゃんの顔を\\nお絵かきしてたから\\nびっくりしちゃった♪', 1, 1, 2, 0, 0, 120401, 3, 5782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんも\\n遊びたいの？\\nそれじゃあ二人も\\n呼んで遊ぼう♪', 1, 1, 2, 0, 0, 120401, 4, 5783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんも\\nみんなも、優しい人\\nばっかりで\\nミミ幸せ～♪', 4, 1, 2, 0, 0, 120401, 101, 5784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃん♪\\n高い高いしてほしいな\\nすっごくぴょんぴょん\\nできて、好きなんだ♪', 8, 1, 2, 0, 0, 120401, 102, 5785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう～♪\\nおにいちゃん、今日は\\nおひさまみたいに\\nきらきら元気だね～♪', 1, 1, 2, 0, 1, 120401, 1, 5786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おひるごはんだね～♪\\nにんじんさんを\\nいっぱい食べて\\n元気いっぱい♪', 1, 1, 2, 0, 2, 120401, 2, 5787);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…\\n眠くなってきちゃった\\nおにいちゃん、\\n一緒に寝よう～？', 1, 1, 2, 0, 3, 120401, 3, 5788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ、気持ちいい♪\\nずっとこうやって\\n座ってたくなるね～♪', 1, 1, 3, 0, 0, 120401, 2, 5790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、かわいい～\\nぎゅ～っ、ぎゅ～っ♪\\nこれで仲よしだね\\nえへへ♪', 1, 1, 3, 0, 0, 120401, 3, 5791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいいにおい～♪\\nぴょんぴょんしたく\\nなってきちゃった♪', 1, 1, 3, 0, 0, 120401, 4, 5792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかぽかぽか♪\\nおにいちゃんも\\nきてくれたら、もっと\\nあったかくなりそう♪', 1, 1, 3, 0, 0, 120401, 5, 5793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…ごっくん♪\\nおっきくなりたいから\\nいっぱい食べるよ～♪', 1, 1, 3, 0, 0, 120401, 7, 5795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ、おもしろ～い\\nこの絵本ね、\\nキョウカちゃんから\\n教えてもらったんだ♪', 1, 1, 3, 0, 0, 120401, 8, 5796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この部屋…探索の\\nしがいがありそう！\\nついでにイタズラも\\nしかけちゃお♪', 1, 1, 1, 0, 0, 120501, 1, 5799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミってああ見えて\\n実は大胆で度胸も\\nあるよね…ちょっと\\nかっこいいな…！', 1, 1, 1, 0, 0, 120501, 2, 5800);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怖い話を聞いた時の\\nキョウカって\\n面白いんだよね～♪', 1, 1, 1, 0, 0, 120501, 3, 5801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんが\\n慣れちゃわないように\\nまた新しいイタズラを\\n考えなきゃ！', 1, 1, 1, 0, 0, 120501, 4, 5802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラもいいけど\\nミミとキョウカと\\nにいちゃんと、普通に\\n遊ぶのも楽しいなぁ♪', 1, 1, 1, 0, 0, 120501, 5, 5803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミにキョウカ、\\nそれににいちゃん！\\nみんなそろえば愉快な\\n冒険が始まりそう！', 4, 1, 1, 0, 0, 120501, 101, 5804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどんなイタズラを\\nしたら、にいちゃんは\\n喜んでくれるかな？', 8, 1, 1, 0, 0, 120501, 102, 5805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今ミソギに触ったね？\\nヤバいよにいちゃん…\\n逃げないとトラップが\\n発動しちゃうよ…！', 1, 1, 2, 0, 0, 120501, 1, 5806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わわっ！？\u3000びっくり\\nしたあ…！\u3000新しい\\nトラップを作ってて\\n気づかなかったよ～', 1, 1, 2, 0, 0, 120501, 2, 5807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お？\u3000にいちゃん、\\nイタズラする側にも\\n興味があるの？', 1, 1, 2, 0, 0, 120501, 3, 5808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんなにか用？\\nあ、もしかして…\\nミソギと遊びたく\\nなっちゃった？', 1, 1, 2, 0, 0, 120501, 4, 5809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ベストタイミングだよ\\nにいちゃん！\\n今からみんなで探検に\\n行くところなんだ！', 4, 1, 2, 0, 0, 120501, 101, 5810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんってさ\\nホントに優しいよね\\nなにしても怒らないし\\n…ありがとね♪', 8, 1, 2, 0, 0, 120501, 102, 5811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんおはよー！\\n景気づけに本日\\n一発目のイタズラ、\\nやっちゃうよ～♪', 1, 1, 2, 0, 1, 120501, 1, 5812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはんはロシアン\\nサンドイッチだよ！\\nさあ、にいちゃん！\\n好きなの選んでよ！', 1, 1, 2, 0, 2, 120501, 2, 5813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜ってなんだか\\nワクワクしてなかなか\\n眠れないんだよね\\nにいちゃんはどう？', 1, 1, 2, 0, 3, 120501, 3, 5814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この座り心地のよさ…\\nなにかのトラップに\\nうまく使えないかな？', 1, 1, 3, 0, 0, 120501, 2, 5816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうのに細工して\\nミミやキョウカを\\n驚かせると、いい反応\\nするんだよね♪', 1, 1, 3, 0, 0, 120501, 3, 5817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('においをうまく使った\\nイタズラって…\\nなにかないかな？', 1, 1, 3, 0, 0, 120501, 4, 5818);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったまりながら\\n新しいイタズラを\\n考えると、いい案が\\n出て来たりするんだ♪', 1, 1, 3, 0, 0, 120501, 5, 5819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしくてついつい\\n食べ過ぎちゃうなぁ…\\nはっ…！？\u3000これって\\nまさかトラップ…！？', 1, 1, 3, 0, 0, 120501, 7, 5821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このキョウカから\\n借りた冒険物語\\nすっごく\\nおもしろいんだよね！', 1, 1, 3, 0, 0, 120501, 8, 5822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('晴れ着を着ると\\nなんだか心が躍るね\\n足取りも軽く\\nなるってもんさ', 1, 1, 1, 0, 0, 120801, 1, 5825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月の食べ物ってのは\\n美味いもんだね\\nいくらでも\\n食べれちまうよ', 1, 1, 1, 0, 0, 120801, 2, 5826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('普段は好き勝手してる\\nアタシらも\\n正月くらいは\\n大人しくするさ', 1, 1, 1, 0, 0, 120801, 3, 5827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年越しそばに雑煮\\nこの季節は\\n温かいものが\\n体に沁みるね', 1, 1, 1, 0, 0, 120801, 4, 5828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月だからって\\nのんびりしすぎたね\\nちょっと釣りにでも\\n行こうかね', 1, 1, 1, 0, 0, 120801, 5, 5829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい正月だね\\nいつかあの子と\\n一杯やりたいもんだよ', 4, 1, 1, 0, 0, 120801, 101, 5830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大事な人と過ごす\\n正月ってのがこんなに\\n楽しいもんだとはね', 8, 1, 1, 0, 0, 120801, 102, 5831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋があったかくて\\n顔が火照っちまったよ\\nちょいと外に涼みに\\n行かないか？', 1, 1, 2, 0, 0, 120801, 1, 5832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('餅ってのは\\n何をつけてもうまいね\\nお前さんは\\nどの味が好きだい？', 1, 1, 2, 0, 0, 120801, 2, 5833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お祝いの鯛が\\n足りないって？\\nそれじゃあアタシが\\n釣ってきてやるよ', 1, 1, 2, 0, 0, 120801, 3, 5834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせちが美味いのは\\n分かるけど\\n食べ過ぎには\\n気を付けるんだよ', 1, 1, 2, 0, 0, 120801, 4, 5835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前さんのおかげで\\nいい正月を\\n迎えられたよ\\nありがとさん！', 4, 1, 2, 0, 0, 120801, 101, 5836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('慣れない晴れ着も\\nお前さんに見て\\nもらえたなら\\n着たかいがあったね', 8, 1, 2, 0, 0, 120801, 102, 5837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようさん\\n寒いのは分かるけど\\nいい加減布団から\\n出て顔洗ってきな', 1, 1, 2, 0, 1, 120801, 1, 5838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の昼飯は雑煮だ\\nアタシの郷土の味\\nしっかり味わって\\nおくれよ', 1, 1, 2, 0, 2, 120801, 2, 5839);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おや、お前さんも\\n夜ふかしかい？\\n退屈してたところさ\\n付き合っておくれよ', 1, 1, 2, 0, 3, 120801, 3, 5840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('晴れ着だと座り方にも\\n気を遣うね\\nしわになったら大変さ', 1, 1, 3, 0, 0, 120801, 2, 5842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくだし\\nこの子にも晴れ着を\\n着せてあげたいね', 1, 1, 3, 0, 0, 120801, 3, 5843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは冬の花の香り…\\n風情があって\\nいいじゃないか', 1, 1, 3, 0, 0, 120801, 4, 5844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいねぇ…\\nこんな寒い日には\\nまさに天国だよ', 1, 1, 3, 0, 0, 120801, 5, 5845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつも食べてる\\nものでも正月に\\n食べると\\n新鮮な気がするね', 1, 1, 3, 0, 0, 120801, 7, 5847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの正月休みだ\\nたまにはゆっくりと\\n本でも読もうかね', 1, 1, 3, 0, 0, 120801, 8, 5848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新年のあいさつ…\\n私も街のみんなに\\nしてみようかしら…', 1, 1, 1, 0, 0, 120701, 1, 5850);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月はゆっくり過ごす\\nのよね…ゆっくりって\\n何したらいいのかしら', 1, 1, 1, 0, 0, 120701, 2, 5851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好も\\n慣れてくれば\\n動きやすいわ', 1, 1, 1, 0, 0, 120701, 3, 5852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、今年の抱負…\\nやりたいことが\\nたくさんあるのよね', 1, 1, 1, 0, 0, 120701, 4, 5853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おせち料理\\nネビアの分も\\n用意しなくちゃね', 1, 1, 1, 0, 0, 120701, 5, 5854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ\\n正月っていいわね\\nみんな楽しそうだもの', 4, 1, 1, 0, 0, 120701, 101, 5855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新年の思い出…\\nこれからもっと作るわ\\nそれが私の抱負よ', 8, 1, 1, 0, 0, 120701, 102, 5856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は家で過ごすの？\\nあなたと一緒なら\\nきっと楽しいわね', 1, 1, 2, 0, 0, 120701, 1, 5857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どう？\u3000この格好？\\nコッコロさんは\\n褒めてくれたけど…', 1, 1, 2, 0, 0, 120701, 2, 5858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうど良かったわ\\nあなたも大掃除\\n手伝ってくれる？', 1, 1, 2, 0, 0, 120701, 3, 5859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これから料理するけど\\nお雑煮と焼き餅\\nどっちが好きかしら？', 1, 1, 2, 0, 0, 120701, 4, 5860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『今の私』にとって\\n初めての正月だもの\\nあなたと楽しまないと', 4, 1, 2, 0, 0, 120701, 101, 5861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('去年よりも今年…\\nもっと成長するからね\\n…お兄ちゃん♪', 8, 1, 2, 0, 0, 120701, 102, 5862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう\\nせっかくの正月だもの\\n朝から楽しまないとね', 1, 1, 2, 0, 1, 120701, 1, 5863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねぇ…\\n良かったら正月の遊び\\n教えてくれるかしら？', 1, 1, 2, 0, 2, 120701, 2, 5864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ～…今日が\\n終わっちゃうのが…\\nもったいないわね…', 1, 1, 2, 0, 3, 120701, 3, 5865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…お参り後だから\\n心地よすぎて眠って\\nしまいそうだわ…', 1, 1, 3, 0, 0, 120701, 2, 5867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ\\nかわいいものって\\n癒されるわね…', 1, 1, 3, 0, 0, 120701, 3, 5868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ん\\nこれが梅の香り？\\n…いい匂いね', 1, 1, 3, 0, 0, 120701, 4, 5869);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャルじゃないけど…\\nこのまま丸く\\nなりたいところね…', 1, 1, 3, 0, 0, 120701, 5, 5870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむはむっ…♪\\nせっかくの正月だもの\\n堪能しなくちゃね♪', 1, 1, 3, 0, 0, 120701, 7, 5872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ふんふん\\n帯の結び方って\\nこんなにあるのね…', 1, 1, 3, 0, 0, 120701, 8, 5873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今の私が作れる\\n最高の一曲…\\nあの人に届くといいな', 12, 1, 1, 0, 0, 104201, 103, 5875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの、歌を…\\n聞いてくれませんか？\\nあなたに贈る\\n特別な歌を', 12, 1, 2, 0, 0, 104201, 103, 5876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひい、ふう…\\nむむ、みなに配る\\nお年玉のポチ袋が\\n残りわずかなのじゃ…', 1, 1, 1, 0, 0, 120901, 1, 5877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宴の準備はわらわに\\n任せておくのじゃ！\\n支配者の手腕、\\n見せつけてくれる！', 1, 1, 1, 0, 0, 120901, 2, 5878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新年の願掛けなら\\nわらわにすればよい\\n支配者に頼むほうが\\n確実じゃろう？', 1, 1, 1, 0, 0, 120901, 3, 5879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みなからもらった\\nこの年賀状とやら…\\nわらわも\\n書いてみようかの♪', 1, 1, 1, 0, 0, 120901, 4, 5880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月飾りにもいろいろ\\n種類があるんじゃの～\\nどれも華々しくて\\nわらわ好みじゃ♪', 1, 1, 1, 0, 0, 120901, 5, 5881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あやつへのお年玉は\\nちと多めにしておくか\\n…日ごろの感謝も\\n込めてのう', 4, 1, 1, 0, 0, 120901, 101, 5882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あやつのことを想うと\\nそれだけで行く年\\n来る年が楽しみになる\\nふふ、愉快なやつじゃ', 8, 1, 1, 0, 0, 120901, 102, 5883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みなに晴れ着を\\n褒められて、とても\\nよい気分なのじゃ♪\\n次はお主の番じゃぞ？', 1, 1, 2, 0, 0, 120901, 1, 5884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お主へのお年玉は\\nいちばん最後じゃ！\\n残り物には福が宿る\\nそうじゃからのう', 1, 1, 2, 0, 0, 120901, 2, 5885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この季節は手が\\nかじかむのう…ほれ、\\nお主！\u3000わらわの手を\\nあたためるのじゃ！', 1, 1, 2, 0, 0, 120901, 3, 5886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お主のために雑煮を\\n手作りしてみたのじゃ\\n食べていくがよい♪', 1, 1, 2, 0, 0, 120901, 4, 5887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属のお主に\\n正月休みはまだ早い！\\nずっとわらわのそばに\\n控えておくのじゃ♪', 4, 1, 2, 0, 0, 120901, 101, 5888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、これほど楽しい\\n正月は初めてじゃ…\\nお主と過ごす時間は\\nいつだって特別じゃな', 8, 1, 2, 0, 0, 120901, 102, 5889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きしてわらわを\\n待っておったのか？\\nさすがはわらわの眷属\\n殊勝な心がけじゃな♪', 1, 1, 2, 0, 1, 120901, 1, 5890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事どきじゃな\\n正月の宴会料理が\\nわらわたちを\\n待っておるぞ♪', 1, 1, 2, 0, 2, 120901, 2, 5891);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜も更けてきたのう\\n冬の夜は長い…\\n心ゆくまでお主と\\n過ごせるわけじゃな♪', 1, 1, 2, 0, 3, 120901, 3, 5892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実に心地がよい♪\\nこのまま寝正月も\\n悪くないかも\\nしれぬのう', 1, 1, 3, 0, 0, 120901, 2, 5894);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛いやつじゃのう\\nわらわのそばに置いて\\nやってもよいぞ♪', 1, 1, 3, 0, 0, 120901, 3, 5895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('品のある香りじゃのう\\n寝室に置いておけば\\nなにかご利益に\\nあずかれそうじゃな', 1, 1, 3, 0, 0, 120901, 4, 5896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よい…\\nわらわはしばらく\\nここから動かぬぞ\\nお主も付き合うがよい', 1, 1, 3, 0, 0, 120901, 5, 5897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舌鼓が鳴るのう♪\\n正月の宴には\\n持ってこいの品じゃ！', 1, 1, 3, 0, 0, 120901, 7, 5899);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほう、新春にはそんな\\n習わしが…正月を\\n制するには、まだまだ\\n勉強が必要じゃのう', 1, 1, 3, 0, 0, 120901, 8, 5900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('久しぶりの我が家って\\n感じです！\u3000やっぱり\\nここが一番ですね〜！', 1, 1, 1, 0, 0, 121001, 1, 5902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ食べましょう！\\nみんなで囲める食卓を\\n心から味わいますよ☆', 1, 1, 1, 0, 0, 121001, 2, 5903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソルに\\n帰ってきた途端に\\nお腹が空きました〜！', 1, 1, 1, 0, 0, 121001, 3, 5904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ただいま☆\\n幸せ特盛りの\\nわたしの日常！', 1, 1, 1, 0, 0, 121001, 4, 5905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ようやくランドソルに\\n帰ってきたことですし\\nやっぱり魔物料理を\\nいただきましょう☆', 1, 1, 1, 0, 0, 121001, 5, 5906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人との絆を\\n守るために\\nもっともっと食べて\\n強くならなくちゃ☆', 4, 1, 1, 0, 0, 121001, 101, 5907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもありがとうって\\nあの人を思いっきり\\n抱きしめたいです☆', 8, 1, 1, 0, 0, 121001, 102, 5908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの想いは\\nこの身をかけて\\n全力で受け止めます！', 1, 1, 2, 0, 0, 121001, 1, 5909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかえりなさい☆\\nここにいるみんなも\\nあなたの帰りをずっと\\n待っていましたよ！', 1, 1, 2, 0, 0, 121001, 2, 5910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このギルドハウスで\\n冒険の疲れを\\n癒しましょう〜！', 1, 1, 2, 0, 0, 121001, 3, 5911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの想いが\\n全力全開を超える\\n力をくれました！', 1, 1, 2, 0, 0, 121001, 4, 5912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日常が続く幸せを\\nあなたと一緒に\\nかみしめたいです☆', 4, 1, 2, 0, 0, 121001, 101, 5913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぎゅ〜っ！\\nわたしたちは\\nどんなことがあっても\\nずっと一緒ですよ？', 8, 1, 2, 0, 0, 121001, 102, 5914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます！\\nあなたと過ごせる\\n幸せを、今日も\\n味わいますよ〜！', 1, 1, 2, 0, 1, 121001, 1, 5915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご飯の時間ですよー！\\nあなたも一緒に\\n食べましょうね！', 1, 1, 2, 0, 2, 121001, 2, 5916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日もあなたが隣に\\nいてくれることを\\n心から願ってますよ\\nおやすみなさい☆', 1, 1, 2, 0, 3, 121001, 3, 5917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふい〜…\\n安心できる場所で\\nくつろげるって\\n幸せですね〜…', 1, 1, 3, 0, 0, 121001, 2, 5919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じゅるり…\\n食べたくなっちゃう\\nくらい、かわいい☆', 1, 1, 3, 0, 0, 121001, 3, 5920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…おおー！\\nステーキの香り！\\nやばいですね☆', 1, 1, 3, 0, 0, 121001, 4, 5921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体がぽかぽかしてきて\\nわたしの食欲も\\n燃えてきましたよー！', 1, 1, 3, 0, 0, 121001, 5, 5922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたしの食欲に\\nついてこられますか？\\nまだまだ食べますよ！', 1, 1, 3, 0, 0, 121001, 7, 5924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これがキャルちゃんの\\n言っていた、キスで\\n目覚める王子様の\\nおとぎ話ですか〜☆', 1, 1, 3, 0, 0, 121001, 8, 5925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自分で自分を\\n分析するのも、これは\\nこれで面白い…♪', 1, 1, 1, 0, 0, 121201, 1, 5927);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強過ぎる力の扱いには\\n注意しないと…\\n七冠がいい例だね', 1, 1, 1, 0, 0, 121201, 2, 5928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年の交友関係は\\n計り知れないな…\\nアタシも含むのか！', 1, 1, 1, 0, 0, 121201, 3, 5929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('原理を徹底解明して\\n再発を防ぐぞー！\\n…誰か手伝って～！', 1, 1, 1, 0, 0, 121201, 4, 5930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは祝福にも\\n呪いにもなる…\\n忘れずにいよう', 1, 1, 1, 0, 0, 121201, 5, 5931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年が\\n目を覚ましてくれて\\n本当によかった…', 4, 1, 1, 0, 0, 121201, 101, 5932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼以外を選んでいたら\\n今回の事態は\\n乗り切れなかったな…\\nさすがだよ、少年', 8, 1, 1, 0, 0, 121201, 102, 5933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年！\u3000調子はどう？\\nクレープ食べられる？\\nっていうか食べて？', 1, 1, 2, 0, 0, 121201, 1, 5934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元気そうで何よりだ\\nまた店を手伝いに\\nきてよ。二人もキミに\\n会いたがってたしさ', 1, 1, 2, 0, 0, 121201, 2, 5935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの診察もあるし\\n今はなるべくそばに\\nいるよ。迷惑じゃ\\nなければだけど', 1, 1, 2, 0, 0, 121201, 3, 5936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり少年は\\nあちこちで人を\\n助けてる時が\\n一番輝いてるよ', 1, 1, 2, 0, 0, 121201, 4, 5937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシは大したこと\\nしてないけど\\nみんなのことは\\n褒めてあげてね', 4, 1, 2, 0, 0, 121201, 101, 5938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなを笑顔に\\nできるのは\\nやっぱり少年だね', 8, 1, 2, 0, 0, 121201, 102, 5939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やあ少年\\n朝寝坊はしてない？\\nそれじゃ、よい１日を', 1, 1, 2, 0, 1, 121201, 1, 5940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おや、少年！\\nまかないのクレープ\\n作ったけど、食べる？', 1, 1, 2, 0, 2, 121201, 2, 5941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…もう夜か…\\n研究してたら\\nあっという間だね…\\nおやすみ、少年', 1, 1, 2, 0, 3, 121201, 3, 5942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体がなまってたのか\\n前線に出ると疲れる…\\nまさか…年のせい！？', 1, 1, 3, 0, 0, 121201, 2, 5944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミたちも今の\\nアタシと同じ感じに\\nアレンジしてあげよう', 1, 1, 3, 0, 0, 121201, 3, 5945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰が置いたんだろう？\\nいい香りだねぇ…\\nうん、気に入った♪', 1, 1, 3, 0, 0, 121201, 4, 5946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何も考えてない時間も\\n実は思考にとって\\n大事なんだよね～…', 1, 1, 3, 0, 0, 121201, 5, 5947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食の大切さは\\nいつの食事からも\\n感じられるね♪', 1, 1, 3, 0, 0, 121201, 7, 5949);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ…面白い！\\n今度全巻\\n借りにこようっと', 1, 1, 3, 0, 0, 121201, 8, 5950);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聖学祭か…\\n良い記憶はないな\\nよし忘れよう', 1, 1, 1, 0, 0, 116401, 1, 5952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('健全なる精神は\\n健全なる肉体に宿る…\\nはっ、知ったことかよ', 1, 1, 1, 0, 0, 116401, 2, 5953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし鏡でも見るか…\\nえへへ、ユニだよ♪\\nよし子供料金いけるな', 1, 1, 1, 0, 0, 116401, 3, 5954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アオイ君は元気に\\nしているだろうか…\\n彼女は人一倍ぼくに\\n懐いていたからな…', 1, 1, 1, 0, 0, 116401, 4, 5955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろシズル君は\\n姉という幻想から\\n目覚めただろうか…', 1, 1, 1, 0, 0, 116401, 5, 5956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼくは来年も聖学祭に\\n行くさ…卒業しても\\n君らとは永遠だ', 4, 1, 1, 0, 0, 116401, 101, 5957);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近同志の登校率が\\n減少傾向だな…\\nまあ仕方ないのだが…\\nないのだが…', 8, 1, 1, 0, 0, 116401, 102, 5958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほわあああ！\\nおい急に話しかけるな\\n学びがこぼれる', 1, 1, 2, 0, 0, 116401, 1, 5959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この体操着、周囲から\\n大層評判が良いのだよ\\nたいそうだけにな\\nどやっ！', 1, 1, 2, 0, 0, 116401, 2, 5960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何を着ていようと\\nぼくはぼくさ\\n外見など所詮は\\n魂の識別符に過ぎん', 1, 1, 2, 0, 0, 116401, 3, 5961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('救護院のアヤネ君が\\n最近ぼくの自称年齢に\\n疑念を持ち始めてな…\\nあの熊…殺るか…', 1, 1, 2, 0, 0, 116401, 4, 5962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん？\u3000なんだね？\\nなに、用は無い？\\n用も無いのに呼ぶとは\\nもしや…これが友達！', 4, 1, 2, 0, 0, 116401, 101, 5963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服が似合ってる？\\nな、なんだね突然…\\nやめたまえよでゅふふ', 8, 1, 2, 0, 0, 116401, 102, 5964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～あ…\\n朝も更けてきたな…\\nそろそろ寝るか…', 1, 1, 2, 0, 1, 116401, 1, 5965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～あ…もう昼だ…\\n人間の起きている\\n時間ではないな…\\n早く寝なくては…', 1, 1, 2, 0, 2, 116401, 2, 5966);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、よく寝た！\\n気持ちのいい夜だな\\n今日も一日がんばるぞ', 1, 1, 2, 0, 3, 116401, 3, 5967);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほわぁ～…\\nもしやこれは都で噂の\\n人を駄目にするやつ…', 1, 1, 3, 0, 0, 116401, 2, 5969);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、愛くるしいな\\nだが似合い過ぎる…\\nぼくが持つと我ながら\\n子供にしか見えん', 1, 1, 3, 0, 0, 116401, 3, 5970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アロマか、興味深いな\\nミツキ印ポーションも\\n気化させて鼻腔から\\n吸入してみるか…', 1, 1, 3, 0, 0, 116401, 4, 5971);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んふ、んふふ…\\n火ってイイよね…\\nずっと見てられるね…', 1, 1, 3, 0, 0, 116401, 5, 5972);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('や、やめろ…\\nとめどなく固形食物を\\n生産するのはやめろ…', 1, 1, 3, 0, 0, 116401, 7, 5974);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この可愛げのない筆致\\nやはり作者は理系か！\\nぐああ目が理系になる', 1, 1, 3, 0, 0, 116401, 8, 5975);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あいつのためなら\\n無理くらいいくらでも\\nしてやるわよ', 1, 1, 1, 0, 0, 121101, 1, 5977);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿、\\n魔力の制御ムズ過ぎ…\\nま、あたしは優秀だし\\nどうとでもなるけど！', 1, 1, 1, 0, 0, 121101, 2, 5978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつのこと、\\n全部受け入れるって\\n決めたから！', 1, 1, 1, 0, 0, 121101, 3, 5979);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今なら誰だろうと\\n負ける気がしないわ\\nドラゴンでもなんでも\\nかかってこいっての！', 1, 1, 1, 0, 0, 121101, 4, 5980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('散々助けられた分、\\n今度はあたしが\\nあいつのこと助けるわ', 1, 1, 1, 0, 0, 121101, 5, 5981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつとの\\nこれまでの冒険は\\nどれも、あたしの\\n大切な思い出…', 4, 1, 1, 0, 0, 121101, 101, 5982);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしまたあいつが\\n寝たままになったら\\nなんだってするわ\\nキ…キスでも…', 8, 1, 1, 0, 0, 121101, 102, 5983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに、お腹空いたの？\\nなら、おいしいご飯を\\n食べに行きましょ♪', 1, 1, 2, 0, 0, 121101, 1, 5984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱ、\\nあんたのアホ面見ると\\n安心するわ♪', 1, 1, 2, 0, 0, 121101, 2, 5985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('【美食殿】はあんたと\\nぺコリーヌがいなきゃ\\n始まんないっての', 1, 1, 2, 0, 0, 121101, 3, 5986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃあっ！？\\n急に声かけないで！？\\n魔力が暴発しても\\n知らないわよ！', 1, 1, 2, 0, 0, 121101, 4, 5987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あんたとこうして\\nぼーっと過ごす時間、\\nまあ…嫌いじゃないわ', 4, 1, 2, 0, 0, 121101, 101, 5988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたが信じて\\n見守っててくれれば…\\nあたし、\\nなんだってできるわ', 8, 1, 2, 0, 0, 121101, 102, 5989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよ\\n早く顔洗いなさいよ、\\nこのねぼすけ♪', 1, 1, 2, 0, 1, 121101, 1, 5990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のお昼は\\nどこで食べる？\\nあんたが\\n決めていいわよ', 1, 1, 2, 0, 2, 121101, 2, 5991);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしあんたがまた\\n夢に囚われても\\nあたしが助けるわ\\n安心して寝なさいよ', 1, 1, 2, 0, 3, 121101, 3, 5992);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちいい～…♪\\nあいつもたまには\\nこうして休ませなきゃ', 1, 1, 3, 0, 0, 121101, 2, 5994);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一目惚れしたかも…！\\nこの子、\\n部屋に飾りたいわー♪', 1, 1, 3, 0, 0, 121101, 3, 5995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へぇ、あいつって\\nこういう匂いが\\n好きなのかしら…？', 1, 1, 3, 0, 0, 121101, 4, 5996);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かくて最高…♪\\n丸くなっちゃいそう…\\nうにゃあ…♪', 1, 1, 3, 0, 0, 121101, 5, 5997);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イケるわね、これ！\\nやっぱり食べるって\\n大事よねー♪', 1, 1, 3, 0, 0, 121101, 7, 5999);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ファーストキスは\\nどんな味、ね…\\nふ、ふ～ん…？\\nなるほど…', 1, 1, 3, 0, 0, 121101, 8, 6000);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お友だち…\\nできるかしら…？\\nこんなわたしでも…', 1, 1, 1, 0, 0, 118101, 1, 6002);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あまり、きょろきょろ\\nしちゃダメよね…\\n変な子だと、\\n思われてしまうわ…', 1, 1, 1, 0, 0, 118101, 2, 6003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('広い場所、\\n落ち着かない…\\nはぅ…どこにいれば…', 1, 1, 1, 0, 0, 118101, 3, 6004);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('～♪', 1, 1, 1, 0, 0, 118101, 4, 6005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('【レイジ・レギオン】\\n…またいつか、\\nみんなと…', 1, 1, 1, 0, 0, 118101, 5, 6006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…一度でいいから、\\nわたしもママって…\\nあっ、その…\\n…な、なんでもないわ', 4, 1, 1, 0, 0, 118101, 101, 6007);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここが、今のわたしに\\nとっての帰る場所…\\n…そう思っても、\\nいいのかしら…？', 8, 1, 1, 0, 0, 118101, 102, 6008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ええと…\\nお腹、空いてる？\\nおねむじゃない？', 1, 1, 2, 0, 0, 118101, 1, 6009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいると\\n邪魔かしら…？\\nならもっと隅っこに…', 1, 1, 2, 0, 0, 118101, 2, 6010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お喋り…？\\nわたしでいいの…？\\nうれしい…', 1, 1, 2, 0, 0, 118101, 3, 6011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの好きな歌…\\n教えて…？\\n練習、するから…', 1, 1, 2, 0, 0, 118101, 4, 6012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは賑やかだけど…\\nうるさいとは感じない\\nむしろ、心地いい…', 4, 1, 2, 0, 0, 118101, 101, 6013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('安心、して…\\nわたしの歌で、\\nあなたを守るから…', 8, 1, 2, 0, 0, 118101, 102, 6014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっとだけ…\\n朝は、苦手…\\n…ふぁ…', 1, 1, 2, 0, 1, 118101, 1, 6015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼は、食べた？\\n良かったら、一緒に…\\n少し…焦げてるけど…', 1, 1, 2, 0, 2, 118101, 2, 6016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眠れないのかしら…\\nじゃ、じゃあ…\\n子守歌…聴く？', 1, 1, 2, 0, 3, 118101, 3, 6017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな特等席…\\n恐縮、です…', 1, 1, 3, 0, 0, 118101, 2, 6019);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('い、今のうちに、\\nこの子でお世話の\\n練習を…', 1, 1, 3, 0, 0, 118101, 3, 6020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\n…つらい気持ちも\\n癒してくれる', 1, 1, 3, 0, 0, 118101, 4, 6021);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\nいつまでも、\\nこうしていられそう…', 1, 1, 3, 0, 0, 118101, 5, 6022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしく出来てる…\\nすごいわ…\\n見習わなくっちゃ…', 1, 1, 3, 0, 0, 118101, 7, 6024);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『赤ちゃんとママの\\nスキンシップ入門』…\\n…べ、勉強になるわ…', 1, 1, 3, 0, 0, 118101, 8, 6025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいなお部屋…！\\n立派な舞台の\\nセットみたい…♪', 1, 1, 1, 0, 0, 121301, 1, 6027);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お芝居では私が先輩\\nなんだから、しっかり\\n私がミサキちゃんを\\nエスコートしなきゃ', 1, 1, 1, 0, 0, 121301, 2, 6028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('～～♪\\n歌うお芝居も多いから\\nもっと上手く\\nなりたいな…！', 1, 1, 1, 0, 0, 121301, 3, 6029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいる人たちと\\n仲良くなりたいな…\\nそしたらきっと演技の\\n幅も広げられるよね', 1, 1, 1, 0, 0, 121301, 4, 6030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('機会があったら\\nアヤネちゃんとも\\nお芝居してみたいな♪', 1, 1, 1, 0, 0, 121301, 5, 6031);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんに褒めて\\nもらえるように\\nお芝居の練習\\nいっぱいしなきゃ…♪', 4, 1, 1, 0, 0, 121301, 101, 6032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あう…お兄ちゃんを\\n意識したら、台詞が\\n飛んじゃったよぅ…！', 8, 1, 1, 0, 0, 121301, 102, 6033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、お兄ちゃん…♪\\nお芝居の練習を\\n見てくれませんか…？', 1, 1, 2, 0, 0, 121301, 1, 6034);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いまの発声練習\\nどうでしたか？\\nひゃん…！？\\n頭は撫でないでぇ～', 1, 1, 2, 0, 0, 121301, 2, 6035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミサキちゃんも\\nお芝居、とっても\\n上達してるんですよ\\n私も負けられません♪', 1, 1, 2, 0, 0, 121301, 3, 6036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('また物語を聞かせて\\nほしい、ですか…？\\n私なんかでよければ\\nもちろんよろこんで♪', 1, 1, 2, 0, 0, 121301, 4, 6037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいお話を\\n考えてみました\\n聞いてくれますか…？\\nよかった…♪', 4, 1, 2, 0, 0, 121301, 101, 6038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか…舞台上じゃ\\nなくても、照れずに\\nお兄ちゃんに気持ちを\\n伝えてみせますね…♪', 8, 1, 2, 0, 0, 121301, 102, 6039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\nマヒルさんにもらった\\nミルク、一緒に\\n飲みませんか？', 1, 1, 2, 0, 1, 121301, 1, 6040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場のみなさんに\\nドングリパンを\\nいただきました～\\nおひとつどうぞ♪', 1, 1, 2, 0, 2, 121301, 2, 6041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝る前にまたココアを\\n飲みながら、お話を\\n聞いてもらえますか？\\nえへへ、うれしいな♪', 1, 1, 2, 0, 3, 121301, 3, 6042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お芝居の練習の\\nあとは、ここで\\nお兄ちゃんと\\nゆっくりしたいな♪', 1, 1, 3, 0, 0, 121301, 2, 6044);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も演技の\\n練習に付き合ってね♪', 1, 1, 3, 0, 0, 121301, 3, 6045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵な香り…\\nこのイメージも\\nお芝居に\\n活かせないかな…？', 1, 1, 3, 0, 0, 121301, 4, 6046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私もお芝居で\\nみんなの心を\\nぽかぽか温められる\\nようになりたいな…♪', 1, 1, 3, 0, 0, 121301, 5, 6047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞台に立つんだから\\n食べ過ぎないように\\n気をつけないと。\\nでも…おいしいなぁ♪', 1, 1, 3, 0, 0, 121301, 7, 6049);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお話、面白い…\\n脚本を書く\\n参考にもなりそう…♪', 1, 1, 3, 0, 0, 121301, 8, 6050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…♪\\n二人で見た夕日…\\nキレイでしたね…', 12, 1, 1, 0, 0, 107501, 103, 6052);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これから泳ぎの\\n練習ですか？\\n付き合いますよ♪', 12, 1, 2, 0, 0, 107501, 103, 6053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまを導くことで\\nわたくしも未知なる\\n領域へと辿り着けます', 12, 1, 1, 0, 0, 107601, 103, 6054);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さまとなら\\n海よりも深く\\n空よりも高い場所へも\\n目指せそうです', 12, 1, 2, 0, 0, 107601, 103, 6055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと二人で\\n夏の遠い海に…って\\nあたしってば\\nなに考えてるのよ！', 12, 1, 1, 0, 0, 107801, 103, 6056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしが楽しく\\n過ごせるのはあんたが\\nいてくれたからよ\\nか、感謝してるわ', 12, 1, 2, 0, 0, 107801, 103, 6057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…アタシってば\\nこんなにかわいくって\\nキレイなんて罪よね～', 1, 1, 1, 0, 0, 121401, 1, 6058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞台の衣装を\\nクリーニング\\nしとかなくちゃ…', 1, 1, 1, 0, 0, 121401, 2, 6059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('舞台映えするメイク…\\nスズナなら\\n知ってるかしら？', 1, 1, 1, 0, 0, 121401, 3, 6060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物産展の会計係と\\n山盛りの算数の宿題…\\nどっちが簡単かしら…', 1, 1, 1, 0, 0, 121401, 4, 6061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牧場と温泉の仕事に\\nお芝居の練習に…\\nちょ、ちょっと休憩～', 1, 1, 1, 0, 0, 121401, 5, 6062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お客さんの視線も\\nうれしいけど…\\nあいつも見てて\\nくれてるかしら？', 4, 1, 1, 0, 0, 121401, 101, 6063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっともっと\\nセクシーになって\\nあいつをビックリ\\nさせてやるわ♪', 8, 1, 1, 0, 0, 121401, 102, 6064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタも休憩？\\nしっかり働くために\\n休むのも大事よね', 1, 1, 2, 0, 0, 121401, 1, 6065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふん♪\u3000アタシも\\n料理ができるように\\nなったんだから！\\n簡単なのだけだけど…', 1, 1, 2, 0, 0, 121401, 2, 6066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('温泉ってお肌に\\nいいのよね？\\nもっとキレイに\\nなったらどうしよう〜', 1, 1, 2, 0, 0, 121401, 3, 6067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物産展の荷物は\\nこれでよし…っと\\nそれじゃアンタも\\n運ぶの手伝ってよね♪', 1, 1, 2, 0, 0, 121401, 4, 6068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもと違うアタシに\\n見とれちゃった？\\n仕方ないわね～♪', 4, 1, 2, 0, 0, 121401, 101, 6069);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花見って風流で\\n大人って感じ♪\\n…でもお団子も\\n忘れないでよね！', 8, 1, 2, 0, 0, 121401, 102, 6070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなに朝ごはんを\\n作ってみたら\\n喜んでくれるかしら？', 1, 1, 2, 0, 1, 121401, 1, 6071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お客さんがいっぱい\\n来る時間帯ね！\\n元気出していくわ！', 1, 1, 2, 0, 2, 121401, 2, 6072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝ないと…\\n睡眠不足はお肌の\\n大敵なんだから', 1, 1, 2, 0, 3, 121401, 3, 6073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかしてて\\n気持ちいい～♪\\n疲れが癒されるぅ…', 1, 1, 3, 0, 0, 121401, 2, 6075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子もアタシと\\nおそろいの衣装に\\nしてあげようかしら♪', 1, 1, 3, 0, 0, 121401, 3, 6076);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵な衣装で\\nいい香りを\\n身にまとう…ふふ、\\n大人のたしなみよね♪', 1, 1, 3, 0, 0, 121401, 4, 6077);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～い♪\\nここでお昼寝したら\\n気持ちよさそう…', 1, 1, 3, 0, 0, 121401, 5, 6078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お仕事がんばると\\nいつもよりお腹\\n空いちゃう～！', 1, 1, 3, 0, 0, 121401, 7, 6080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最新のトレンド\\n載ってないかしら？\\n物産展の売り物に\\n取り入れなくちゃ！', 1, 1, 3, 0, 0, 121401, 8, 6081);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪盗のこと…\\nお父さんお母さんに\\nもし知られたら\\nなんて説明しよう…', 1, 1, 1, 0, 0, 121501, 1, 6083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえ怪盗でも、人の\\n家にお邪魔するときは\\n身だしなみをしっかり\\nしないと…', 1, 1, 1, 0, 0, 121501, 2, 6084);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鍵開けって難しい…\\nうーん、もっと\\n練習しておかなくちゃ', 1, 1, 1, 0, 0, 121501, 3, 6085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('姿が見えない\\n怪盗の噂…？\\nわ、私のことじゃ\\nありませんように…！', 1, 1, 1, 0, 0, 121501, 4, 6086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('予告状って…\\n切手はどこに貼れば\\nいいんだろう…？', 1, 1, 1, 0, 0, 121501, 5, 6087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪盗活動にも\\n慣れてきたけど…\\nやっぱり先輩が\\nいないと心細いなぁ…', 4, 1, 1, 0, 0, 121501, 101, 6088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せ、先輩の心も\\nいつか盗めるかな…？\\n…わわわ、私ってば\\nなに言ってるんだろ…', 8, 1, 1, 0, 0, 121501, 102, 6089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪盗が大活躍って\\n新聞で読んだ…？\\nだっ、誰のこと\\nでしょうね…あはは', 1, 1, 2, 0, 0, 121501, 1, 6090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('尾行に潜入…\\n存在感がないのって\\n意外と役立つことも\\nあるんですね', 1, 1, 2, 0, 0, 121501, 2, 6091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せせせ、先輩っ！\\n帽子をぎゅーって\\nかぶったら、抜けなく\\nなっちゃいました…！', 1, 1, 2, 0, 0, 121501, 3, 6092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬ、盗み聞きなんて\\nしてませんよ？\\nみんなが私に気づかず\\n話し始めるだけで…', 1, 1, 2, 0, 0, 121501, 4, 6093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('秘密道具が見たい？\\nそ、それは内緒です！\\n秘密道具ですから…\\nで、でも先輩になら…', 4, 1, 2, 0, 0, 121501, 101, 6094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ\\n見つかっちゃいました\\n先輩はいつも私を\\n見つけてくれますね…', 8, 1, 2, 0, 0, 121501, 102, 6095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございまふ…\\n秘密道具のお手入れで\\n夜更かししちゃって…\\nちょっと眠たいです～', 1, 1, 2, 0, 1, 121501, 1, 6096);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪盗が昼に活動する…\\n案外そのほうが\\n意外性が\\nあるのかも…？', 1, 1, 2, 0, 2, 121501, 2, 6097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外が暗くなりましたね\\n…そろそろ怪盗の活動\\n始めましょうか？', 1, 1, 2, 0, 3, 121501, 3, 6098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここでくつろぐと\\n疲れが取れます～\\n…今日も怪盗\\nがんばろっと', 1, 1, 3, 0, 0, 121501, 2, 6100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ、かわいい…！\\n心を盗まれるって\\nこういうことかな…？', 1, 1, 3, 0, 0, 121501, 3, 6101);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵な香り…でも\\n服に香りがついたら\\n隠れてるときに\\n見つかっちゃうかな…', 1, 1, 3, 0, 0, 121501, 4, 6102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかで\\nいい気持ち…\\n夜道を歩く前に\\n温まっておこうっと…', 1, 1, 3, 0, 0, 121501, 5, 6103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怪盗活動に備えて\\n今のうちにしっかり\\n食べておかなきゃ…！', 1, 1, 3, 0, 0, 121501, 7, 6105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女の子は秘密が\\n多いほうが魅力的…？\\nそ、そうなんだ…', 1, 1, 3, 0, 0, 121501, 8, 6106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんはいつも\\nクウカの妄想の中に…\\nぐふふ、じゅるり～♪', 12, 1, 1, 0, 0, 104501, 103, 6108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やさしい触り方も\\n嫌いじゃありません…\\nは…恥ずかしいですが', 12, 1, 2, 0, 0, 104501, 103, 6109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この大怪盗さまに\\n盗めないものなんて\\nないです！\u3000たぶん！', 1, 1, 1, 0, 0, 121601, 1, 6110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしにふさわしい\\nビッグなお宝は\\nどこにあるですかね～', 1, 1, 1, 0, 0, 121601, 2, 6111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろーりそろーり…\\n気配を消せばお菓子も\\n食べ放題…にやり', 1, 1, 1, 0, 0, 121601, 3, 6112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またサボってたのが\\nバレたです…\\nボスの地獄耳～！', 1, 1, 1, 0, 0, 121601, 4, 6113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギャングで大怪盗…！\\nこの肩書の多さ！\\nまさに有能の証です！', 1, 1, 1, 0, 0, 121601, 5, 6114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんだったら…\\nお宝を山分けして\\nあげてもいいですよ', 4, 1, 1, 0, 0, 121601, 101, 6115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんはアレですよ\\n大怪盗イノリさまの\\n相棒みたいなものです', 8, 1, 1, 0, 0, 121601, 102, 6116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何事も用心深さが\\n大切ですよ。ビ…\\nビビりじゃないです！', 1, 1, 2, 0, 0, 121601, 1, 6117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬ、盗み聞き？\\nしてないですよっ？\\nぴゅーぴゅーぴゅー', 1, 1, 2, 0, 0, 121601, 2, 6118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('情報が欲しければ\\nお菓子と交換ですよ\\nさぁ、交換交換っ♪', 1, 1, 2, 0, 0, 121601, 3, 6119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しーっ！\\n今、尾行中なんです\\n話はあとで…', 1, 1, 2, 0, 0, 121601, 4, 6120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんと話してると\\n時間が速いような…？\\nこの時間泥棒！', 4, 1, 2, 0, 0, 121601, 101, 6121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうどよかった！\\nいい話があるんです\\n一口乗りませんか？', 8, 1, 2, 0, 0, 121601, 102, 6122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おてんとうさまが\\n出てやがるですね…\\n悪事がやりにくいです', 1, 1, 2, 0, 1, 121601, 1, 6123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間ですか\\nご飯にお昼寝…\\nいやー忙しいです♪', 1, 1, 2, 0, 2, 121601, 2, 6124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっふっふ！\u3000夜こそ\\n大怪盗の時間です！\\n……ふぁあ', 1, 1, 2, 0, 3, 121601, 3, 6125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…\\n警備の目がないと\\n気楽でいいですねぇ', 1, 1, 3, 0, 0, 121601, 2, 6127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くう…！\\nこのかわいさは\\n盗めないです…♪', 1, 1, 3, 0, 0, 121601, 3, 6128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('犯行現場に残ったのは\\n香水の匂いだけ…\\nふふ、おしゃれ大怪盗', 1, 1, 3, 0, 0, 121601, 4, 6129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('意外とこういう場所に\\n隠し扉があったり…\\nしないです？', 1, 1, 3, 0, 0, 121601, 5, 6130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nこの美味しさ…\\nとんでもない罠ですね', 1, 1, 3, 0, 0, 121601, 7, 6132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむむ…ちっとも\\n分からないです…\\nほとんど暗号ですよ', 1, 1, 3, 0, 0, 121601, 8, 6133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、サレンさんは\\nどこに行かれた\\nのかしら？', 1, 1, 1, 0, 0, 121701, 1, 6135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふんふーん♪\\nなんだか華やいだ\\n気分ですわ♪', 1, 1, 1, 0, 0, 121701, 2, 6136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて…次の事業は\\nどうしましょう\\n何か面白いことは…', 1, 1, 1, 0, 0, 121701, 3, 6137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おーっほっほっほ！\\nあら…楽しくて、つい\\n笑ってしまいましたわ', 1, 1, 1, 0, 0, 121701, 4, 6138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('センスがあって\\nいいお部屋ですわね\\n私も見習いたいですわ', 1, 1, 1, 0, 0, 121701, 5, 6139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サレンさんとあのお方\\n仲がいいですわね\\nも、もちろん仲がいい\\nのはよいことですわ！', 4, 1, 1, 0, 0, 121701, 101, 6140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなときでも\\n正々堂々！\\nそれが私の\\n誇りですわ！', 8, 1, 1, 0, 0, 121701, 102, 6141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、ごきげんよう\\n私、絶好調でしてよ', 1, 1, 2, 0, 0, 121701, 1, 6142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうかされましたか？\\n何かお困りごと\\nでしたら\\n是非力になりますわよ', 1, 1, 2, 0, 0, 121701, 2, 6143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにはこうして\\nゆっくりと\\nお話しするのも\\nいいものですわね', 1, 1, 2, 0, 0, 121701, 3, 6144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の事業に関して\\n考え事をしてましたの\\nよければ相談に乗って\\nくださるかしら？', 1, 1, 2, 0, 0, 121701, 4, 6145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よろしければ\\nお話しませんこと？\\nサレンさんのお話を\\n聞かせてほしいですわ', 4, 1, 2, 0, 0, 121701, 101, 6146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ…\\n先ほどサレンさんと\\nあなたさまのお話を\\nしていたところですわ', 8, 1, 2, 0, 0, 121701, 102, 6147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ！\\n今日も一日\\n全力で参りますわ！', 1, 1, 2, 0, 1, 121701, 1, 6148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はどうしましょう\\nサレンさんをお誘い\\nしてみようかしら', 1, 1, 2, 0, 2, 121701, 2, 6149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう少しだけ…\\n明日の準備をして\\nおかないと…', 1, 1, 2, 0, 3, 121701, 3, 6150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～…いいですわね\\nはっ、私としたことが\\nはしたないですわね', 1, 1, 3, 0, 0, 121701, 2, 6152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいらしいですわ\\nいくつになっても\\nぎゅっと\\nしたくなりますわね', 1, 1, 3, 0, 0, 121701, 3, 6153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落ち着きますわね\\nサレンさんはどんな\\n香りが好きなのかしら', 1, 1, 3, 0, 0, 121701, 4, 6154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、燃え盛る\\n情熱の炎…\\nいいですわね', 1, 1, 3, 0, 0, 121701, 5, 6155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このおいしさで\\n元手がゼロ…\\nすばらしい\\n商品ですわ！', 1, 1, 3, 0, 0, 121701, 7, 6157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…ふむふむ\\n新しい事業のヒントに\\nなりそうですわ', 1, 1, 3, 0, 0, 121701, 8, 6158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、と…\\n今日は何をしなくちゃ\\nいけないんだっけ？', 1, 1, 1, 0, 0, 121801, 1, 6161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やることは山積み\\nだけど、手を動かす\\nのは嫌いじゃないわ♪', 1, 1, 1, 0, 0, 121801, 2, 6162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら？\u3000アキノさんの\\n声が聞こえたような\\n気がしたんだけど…', 1, 1, 1, 0, 0, 121801, 3, 6163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アキノさんといると\\nついこっちまで笑顔に\\nなっちゃうのよね', 1, 1, 1, 0, 0, 121801, 4, 6164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弱音なんか\\nはいてられないわ\\nアキノさんに\\n笑われちゃうもの', 1, 1, 1, 0, 0, 121801, 5, 6165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気が付けばアキノさん\\nのペースだけど…\\n不思議と嫌では\\nないのよね', 4, 1, 1, 0, 0, 121801, 101, 6166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしを好敵手って\\n言ってくれる\\nアキノさんのためにも\\nしっかりしなくちゃ', 8, 1, 1, 0, 0, 121801, 102, 6167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\nアキノさんなら\\nさっきそこに\\nいなかった？', 1, 1, 2, 0, 0, 121801, 1, 6168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしなら大丈夫\\n救護院だって\\nみんなが助けて\\nくれるからね', 1, 1, 2, 0, 0, 121801, 2, 6169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さっきアキノさんが\\nあんたを探してたわよ\\nなにかしたの？', 1, 1, 2, 0, 0, 121801, 3, 6170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こう見えてヒマじゃ\\nないんだけど…\\n少しくらいなら\\n付き合ってあげるわ', 1, 1, 2, 0, 0, 121801, 4, 6171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、あんたと\\nアキノさんって…\\nううん、やっぱり\\nなんでもないわ…', 4, 1, 2, 0, 0, 121801, 101, 6172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アキノさんも誘って\\nお茶でもしない？\\n話したいことが\\nたくさんあるの♪', 8, 1, 2, 0, 0, 121801, 102, 6173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きは三文の得よ\\nいい一日を迎えるため\\n目を覚まさなきゃ', 1, 1, 2, 0, 1, 121801, 1, 6174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のお昼は…\\nアキノさんと同席する\\n予定だったわね\\nあんたもどう？', 1, 1, 2, 0, 2, 121801, 2, 6175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ…っと、だめね\\nたるんだところを\\nアキノさんに\\n見せるわけには', 1, 1, 2, 0, 3, 121801, 3, 6176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～…\\n落ち着くわね\\nこのまま\\n寝ちゃいそう…', 1, 1, 3, 0, 0, 121801, 2, 6178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('救護院の皆も\\nぬいぐるみが\\n大好きなのよ', 1, 1, 3, 0, 0, 121801, 3, 6179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね…\\nこれはアキノさんの\\n趣味かしら？', 1, 1, 3, 0, 0, 121801, 4, 6180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなに激しく\\n燃えているのに\\nあったかくて落ち着く\\nまるでアキノさんね', 1, 1, 3, 0, 0, 121801, 5, 6181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんどん出てくる…\\nこれ、救護院にも\\nほしいわね…', 1, 1, 3, 0, 0, 121801, 7, 6183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\n前にアキノさんが\\n言ってたのは\\nこのことかしら？', 1, 1, 3, 0, 0, 121801, 8, 6184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装、私には\\nちょっとかわい過ぎて\\n恥ずかしいな…', 1, 1, 1, 0, 0, 122001, 1, 6187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一部の人からは\\n海賊より海賊らしいと\\n評判の父です', 1, 1, 1, 0, 0, 122001, 2, 6188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('潮風で錆びないよう\\n武器の手入れを\\nしておきましょうか', 1, 1, 1, 0, 0, 122001, 3, 6189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宝探しのお手伝いなら\\n力になれると思います\\n父のやる気次第ですが', 1, 1, 1, 0, 0, 122001, 4, 6190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('除霊は気を遣います\\n一歩間違えると父まで\\n成仏させてしまうので', 1, 1, 1, 0, 0, 122001, 5, 6191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人と見た\\n海の景色を…ずっと\\n忘れずにいたいな', 4, 1, 1, 0, 0, 122001, 101, 6192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幽霊になっても\\n一目会えるなら…\\n私はきっとあの人に…', 8, 1, 1, 0, 0, 122001, 102, 6193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボートを漕ぐの、少し\\n上手になったんですよ\\n今度お見せしますね', 1, 1, 2, 0, 0, 122001, 1, 6194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('航海に向けた\\n買い出しが必要ですね\\n予定は空いていますか', 1, 1, 2, 0, 0, 122001, 2, 6195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呪われた財宝の\\n解呪依頼が多くて…\\nふぅ…えっと次は…', 1, 1, 2, 0, 0, 122001, 3, 6196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の航海では\\n父が明かり代わりに\\nなってくれるんです', 1, 1, 2, 0, 0, 122001, 4, 6197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('船の上では食材が\\n限られるので料理の\\nいい練習になります', 4, 1, 2, 0, 0, 122001, 101, 6198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この先もずっと\\nあなたと一緒に\\nたくさんの思い出を\\n作っていきたいです', 8, 1, 2, 0, 0, 122001, 102, 6199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人の寝顔…\\nもう少しだけ\\n眺めていたいな…', 1, 1, 2, 0, 1, 122001, 1, 6200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('船の上では\\n規則正しい生活が\\n重要ですから', 1, 1, 2, 0, 2, 122001, 2, 6201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海は幽霊が\\n見分けやすいんです\\n青白く光るので', 1, 1, 2, 0, 3, 122001, 3, 6202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に揺られるような\\n心地よさですね\\n気が休まります…', 1, 1, 3, 0, 0, 122001, 2, 6204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたも一緒に\\n海を見に行きますか？\\n…なんて。ふふっ', 1, 1, 3, 0, 0, 122001, 3, 6205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('爽やかな香りですね…\\n一面の青い海が\\n目に浮かぶようです', 1, 1, 3, 0, 0, 122001, 4, 6206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('温かい…\\n潮風で冷えた体に\\n沁みますね', 1, 1, 3, 0, 0, 122001, 5, 6207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、おいしい…\\n日持ちするなら船旅に\\n持っていこうかな…', 1, 1, 3, 0, 0, 122001, 7, 6209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンナさんに教えて\\nもらった小説は…\\nあ、これですね', 1, 1, 3, 0, 0, 122001, 8, 6210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにもしないを\\nしてるんだよ\\nあ～いそがしいそがし', 12, 1, 1, 0, 0, 102601, 103, 6212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～あんたといると\\nどこまでも気持ちよく\\nダラダラできるね～', 12, 1, 2, 0, 0, 102601, 103, 6213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暗黒騎士にして、\\n伝説の海賊でもある\\n私に不可能はないっ！', 1, 1, 1, 0, 0, 121901, 1, 6214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海賊団の船員、\\n随時募集中です…と\\nこれで新たな盟友が\\n増えるはずだ…！', 1, 1, 1, 0, 0, 121901, 2, 6215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('肩に乗せるペットが\\nほしいな。今のうちに\\nペット用品を買いに\\n行かなくては…！', 1, 1, 1, 0, 0, 121901, 3, 6216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('財宝の地図はどこで\\n売っているのだろう…\\n古本屋？\u3000古物商？', 1, 1, 1, 0, 0, 121901, 4, 6217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この海賊衣装に\\n身を包んでいると\\n前世の新たな記憶が\\nよみがえってくるな！', 1, 1, 1, 0, 0, 121901, 5, 6218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いずれはシグルドと\\n海原への冒険に\\n繰り出したいな…\\nきっと楽しいぞ！', 4, 1, 1, 0, 0, 121901, 101, 6219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('待ちわびたぞ盟友よ！\\n私と貴様あっての\\n海賊団…だからその…\\n今日はそばにいてくれ', 8, 1, 1, 0, 0, 121901, 102, 6220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルド！\u3000港町で\\nお魚のおすそ分けを\\nもらったんだ！\\n一緒に食べよう！', 1, 1, 2, 0, 0, 121901, 1, 6221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シグルドもこのコート\\n羽織ってみないか？\\nふふっ、きっとすごく\\n似合うと思うぞ！', 1, 1, 2, 0, 0, 121901, 2, 6222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海賊船の新たな\\n秘密兵器を作ったぞ！\\nシグルド、これから\\n見に来ないか！？', 1, 1, 2, 0, 0, 121901, 3, 6223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私は伝説の海賊だから\\n泳ぐのだって得意だ！\\nふ、深いところは\\n少し怖いが…', 1, 1, 2, 0, 0, 121901, 4, 6224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、いつ無人島に\\n漂着してもいいように\\n非常食は準備済みだ\\nシグルドの分もある！', 4, 1, 2, 0, 0, 121901, 101, 6225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冥風戦記の新章が\\n完成したぞ…！\\nシグルド、まずは\\n貴様に読んでほしい！', 8, 1, 2, 0, 0, 121901, 102, 6226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっ、天気明朗\\n絶好の航海日和だ！\\n早速海に繰り出そう！', 1, 1, 2, 0, 1, 121901, 1, 6227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食用に魚を\\n釣っておいたぞ！\\nふふ、いかにも\\n海賊っぽいだろう？', 1, 1, 2, 0, 2, 121901, 2, 6228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海は真っ黒で\\n少しだけ怖いな…\\nシグルド、私の\\nそばを離れるなよ…！', 1, 1, 2, 0, 3, 121901, 3, 6229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大海賊がくつろぐのに\\n相応しい逸品だ…！\\nえっと…これ、どこの\\nお店で買えますか？', 1, 1, 3, 0, 0, 121901, 2, 6231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わわ、かわいい…！\\n船室のベッドに\\n置いておきたいな…\\n連れてってはダメか？', 1, 1, 3, 0, 0, 121901, 3, 6232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おぉ、この香りは…！\\n集中力が上がりそうだ\\n海賊船の船長室に\\nぜひ置きたいな！', 1, 1, 3, 0, 0, 121901, 4, 6233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これが船乗りの\\n伝承に聞く、海原を\\nさまよう神秘の火か！\\n…暖まるな！', 1, 1, 3, 0, 0, 121901, 5, 6234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('腹が減っては\\n海賊はできぬ！\\n…小説も書けぬ！', 1, 1, 3, 0, 0, 121901, 7, 6236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女海賊と騎士はその後\\n恋に落ち…？\u3000恋愛\\nモノではないかっ！？\\nき、興味深くはあるが', 1, 1, 3, 0, 0, 121901, 8, 6237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもの山籠もりが\\nブームになるなんて…\\n人生、なにが起きるか\\n分からないなぁ', 1, 1, 1, 0, 0, 122101, 1, 6239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャンプ道具…\\nいえ、キャンプギア！\\nカッコいい響き…♪', 1, 1, 1, 0, 0, 122101, 2, 6240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッツ、ＢＢキャン！\\nこのフレーズ\\n流行るかも…？', 1, 1, 1, 0, 0, 122101, 3, 6241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャンプ仲間…\\n募集してみようかな？\\n友達も兼任で…', 1, 1, 1, 0, 0, 122101, 4, 6242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユカリさんと\\nジュンさん…元気かな\\nまた一緒に\\nキャンプしたいなぁ…', 1, 1, 1, 0, 0, 122101, 5, 6243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の取材が載った本…\\n【フォレスティエ】に\\n送らなくちゃ…♪', 4, 1, 1, 0, 0, 122101, 101, 6244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし、あの人が\\n落ち込むことが\\nあったら…その時は\\n私が力になりたいな', 8, 1, 1, 0, 0, 122101, 102, 6245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ブッシュクラフトは\\nマイフレンドくんの\\nカスタムにも\\n活かせる技術です！', 1, 1, 2, 0, 0, 122101, 1, 6246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('会話に花が咲く…\\nって言いますよね\\n私の場合、会話相手が\\nお花そのものですけど', 1, 1, 2, 0, 0, 122101, 2, 6247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服、実は…\\n昔ミサト先生に\\nこしらえてもらった\\n物なんです！', 1, 1, 2, 0, 0, 122101, 3, 6248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昔はやまびこで会話の\\n練習をしてたんです\\nほとんどオウム返しで\\n気まずかったなぁ～', 1, 1, 2, 0, 0, 122101, 4, 6249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうもマイスターです\\n…あ、すみません\\nみなさんの期待に\\n応えようと練習中で…', 4, 1, 2, 0, 0, 122101, 101, 6250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえぼっちを\\n卒業しても…\\n私は一生ＢＢ団です！', 8, 1, 2, 0, 0, 122101, 102, 6251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小鳥さんのさえずりで\\n目が覚める…\\n心地いいものですね', 1, 1, 2, 0, 1, 122101, 1, 6252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャンプといえば\\nおいしいご飯です！\\n腕を振るいますよ！', 1, 1, 2, 0, 2, 122101, 2, 6253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すっかり夜ですね…\\nおやすみの前に\\n星でも見ませんか？', 1, 1, 2, 0, 3, 122101, 3, 6254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('都会でくつろぎ…\\n自然の中でくつろぐ…\\nくつろぎ無限ループ…', 1, 1, 3, 0, 0, 122101, 2, 6256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり観察すれば\\nブッシュクラフトで\\n再現できるかも…？', 1, 1, 3, 0, 0, 122101, 3, 6257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～…やっぱり\\n木の香りを嗅ぐと\\n肩の力が抜けますねぇ', 1, 1, 3, 0, 0, 122101, 4, 6258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ…あったまります\\nなんだか心に\\nゆとりがでますね…', 1, 1, 3, 0, 0, 122101, 5, 6259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このおいしさ…！\\n今度はキャンプに\\n持っていこうかな…', 1, 1, 3, 0, 0, 122101, 7, 6261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nいろんな知識があると\\nキャンプはもっと\\n楽しくなりますよね', 1, 1, 3, 0, 0, 122101, 8, 6262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋がキャンプ用品で\\n埋まっていく…\\nキャンプ…なんて\\n恐ろしい趣味なの…？', 1, 1, 1, 0, 0, 122201, 1, 6264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事でも\\nアウトドアでも\\n頼れるお姉さんに\\nなれたらいいなぁ…', 1, 1, 1, 0, 0, 122201, 2, 6265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服、かわいい上に\\n本当に快適ね～♪\\nおしゃれにキャンプを\\n楽しめて最高だわ！', 1, 1, 1, 0, 0, 122201, 3, 6266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん〜次はどんな\\nキャンプ飯を\\n作ろうかしら？\\n彼の好物は、っと…', 1, 1, 1, 0, 0, 122201, 4, 6267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早く週末が\\n来ないかしら…\\n仕事を忘れてパーっと\\nキャンプ飲みを…！', 1, 1, 1, 0, 0, 122201, 5, 6268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいキャンプ飯の\\nレシピを覚えたわ！\\n彼も喜んで\\nくれるはず…よね♪', 4, 1, 1, 0, 0, 122201, 101, 6269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼の分の食器も\\nこっそり買い揃えちゃ\\nおうかな…そ、それは\\nさすがにまだ早いか…', 8, 1, 1, 0, 0, 122201, 102, 6270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、財団主催で\\n大規模なキャンプを\\nやってみるのも\\nいいかもしれないわね', 1, 1, 2, 0, 0, 122201, 1, 6271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ソロキャンプも\\n悪くはないけど\\n私はやっぱりキミと…\\nな、なんでもない！', 1, 1, 2, 0, 0, 122201, 2, 6272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャンプのことなら\\n私に聞いて。なんでも\\n教えてあげるから！\\n…調べた上でね！', 1, 1, 2, 0, 0, 122201, 3, 6273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャンプ場で飲む\\n最高の一杯は\\n他じゃ味わえないわ！\\nさあ、乾杯っ！', 1, 1, 2, 0, 0, 122201, 4, 6274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん、決めた！\u3000次は\\n禁しゅわキャンプ！\\nだってキミとゆっくり\\n話したいんだもん♪', 4, 1, 2, 0, 0, 122201, 101, 6275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミのおかげで\\n本当の最高の一杯が\\n味わえたわ…\\nありがとう♪', 8, 1, 2, 0, 0, 122201, 102, 6276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー、気持ちいい！\\nキャンプが趣味に\\nなってから、寝覚めが\\nよくなったわ♪', 1, 1, 2, 0, 1, 122201, 1, 6277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼は私がごちそう\\nするわ。キャンプ飯で\\n鍛えた料理の腕前を\\n披露しちゃうわよ～！', 1, 1, 2, 0, 2, 122201, 2, 6278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝ましょ？\\n明日も朝日を眺める\\nためにね。もちろん\\nコーヒー付きで♪', 1, 1, 2, 0, 3, 122201, 3, 6279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くつろぐのに\\n持ってこいね～\\nテントの中に置いても\\nよさそうだわ！', 1, 1, 3, 0, 0, 122201, 2, 6281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、かわいいわね～\\n…今度キャンプ場に\\n連れていこうかしら？', 1, 1, 3, 0, 0, 122201, 3, 6282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん、いい匂い…♪\\nキャンプ場を思い出す\\n自然の香りだわ〜', 1, 1, 3, 0, 0, 122201, 4, 6283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、温まるぅ～\\n冬のキャンプで\\n使ってみたいわね', 1, 1, 3, 0, 0, 122201, 5, 6284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい～♪\\nキャンプ飲みの\\nおつまみに\\nぴったりね！', 1, 1, 3, 0, 0, 122201, 7, 6286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へえ…こんなキャンプ\\n飯もあるんだ？\\n彼、好きだったり\\nするかな…', 1, 1, 3, 0, 0, 122201, 8, 6287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一生ついててやるの\\n幽霊の一生は\\nなっが～～～いの！', 12, 1, 1, 0, 0, 100701, 103, 6289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('む～…あんまり触ると\\nすり抜けてやるの！\\nウソなの。むふふ♪', 12, 1, 2, 0, 0, 100701, 103, 6290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー…\\n今日はベスちゃんと\\nなにして遊ぼーかなー', 1, 1, 1, 0, 0, 122301, 1, 6291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァンピィちゃんも\\nけんぞくの友だちと\\n仲良くなりたいな♪', 1, 1, 1, 0, 0, 122301, 2, 6292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('けんぞくのお部屋は\\nヴァンピィちゃんが\\n守ってあげなくちゃ！', 1, 1, 1, 0, 0, 122301, 3, 6293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お掃除するなら\\nヴァンピィちゃんも\\n手伝ってあげよー♪', 1, 1, 1, 0, 0, 122301, 4, 6294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふーん、ふーん♪\\nけんぞくってこーゆー\\nお部屋が好きなんだー', 1, 1, 1, 0, 0, 122301, 5, 6295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひまだなー\\nけんぞくをさそって\\nお散歩いこっかな♪', 4, 1, 1, 0, 0, 122301, 101, 6296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のスープに\\nけんぞくの大好物を\\n入れてあげよっと♪', 8, 1, 1, 0, 0, 122301, 102, 6297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('けんぞくー！\\nヴァンピィちゃんと\\nお出かけしよ♪', 1, 1, 2, 0, 0, 122301, 1, 6298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よしよし！\\n今日のけんぞくも\\nいい子だね♪', 1, 1, 2, 0, 0, 122301, 2, 6299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んんー…\\nやっぱりけんぞくと\\nベスちゃんは似てる？', 1, 1, 2, 0, 0, 122301, 3, 6300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いーい？\\nヴァンピィちゃんの\\nいうこと聞くのよ？', 1, 1, 2, 0, 0, 122301, 4, 6301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァンピィちゃんの\\nけんぞくだもん！\\n大切にするからね！', 4, 1, 2, 0, 0, 122301, 101, 6302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへっ！\\nやっぱりけんぞくって\\nやさしー匂いがする♪', 8, 1, 2, 0, 0, 122301, 102, 6303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよー…\\nヴァンピィちゃんは\\nもうちょっと眠るねー', 1, 1, 2, 0, 1, 122301, 1, 6304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァンピィちゃん\\nひなたぼっこ\\nだーいすき！', 1, 1, 2, 0, 2, 122301, 2, 6305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー！\u3000夜だ♪\\nヴァンピィちゃん\\n絶好調だよ！', 1, 1, 2, 0, 3, 122301, 3, 6306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わー！\\nふかふかだ！\\nきもちぃー♪', 1, 1, 3, 0, 0, 122301, 2, 6308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいー♪\\nベスちゃんに負けない\\n抱き心地！', 1, 1, 3, 0, 0, 122301, 3, 6309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…なんだろ？\\nヴァンピィちゃん\\n気に入っちゃった♪', 1, 1, 3, 0, 0, 122301, 4, 6310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいねー…\\nヴァンピィちゃん\\nずっとここにいるー…', 1, 1, 3, 0, 0, 122301, 5, 6311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はむはむ…\\nんー！\\nおいしー♪', 1, 1, 3, 0, 0, 122301, 7, 6313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴァンピィちゃん\\nこの本\\n好きなんだよねー♪', 1, 1, 3, 0, 0, 122301, 8, 6314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏といえば\\nかき氷だよね\\n近くにお店は…', 1, 1, 1, 0, 0, 122501, 1, 6316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好でいるのも\\nなじんできたし\\nちょっと鍛錬でも…', 1, 1, 1, 0, 0, 122501, 2, 6317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('動きやすいけれど…\\nいつもと違う服装は\\n少し落ち着かないな', 1, 1, 1, 0, 0, 122501, 3, 6318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の空気に\\n当てられると思わず\\n気が緩んでしまうね', 1, 1, 1, 0, 0, 122501, 4, 6319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂浜で走ると\\nいい具合に体幹を\\n鍛えられそうだ', 1, 1, 1, 0, 0, 122501, 5, 6320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('終わらない夏は\\nないけれど…\\nつい願ってしまうな', 4, 1, 1, 0, 0, 122501, 101, 6321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('胸を張って彼と\\n並び立てるよう\\n私も、もっと強く…！', 8, 1, 1, 0, 0, 122501, 102, 6322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\n行きたい場所が\\nあるなら付き合おうか', 1, 1, 2, 0, 0, 122501, 1, 6323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('快晴で風は穏やか…\\n絶好の釣り日和だね\\nさあ、出かけようか', 1, 1, 2, 0, 0, 122501, 2, 6324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の予定を\\n立ててるんだけど…\\nキミの希望も\\n聞きたいな', 1, 1, 2, 0, 0, 122501, 3, 6325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーチスポーツか…\\nキミとなら\\nいい勝負ができそうだ', 1, 1, 2, 0, 0, 122501, 4, 6326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちの夏に\\n遠慮は無用だよ\\n思いきり楽しもう！', 4, 1, 2, 0, 0, 122501, 101, 6327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかまた一緒に\\n花火を見に行こう\\n…約束だよ？', 8, 1, 2, 0, 0, 122501, 102, 6328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('潮騒の音で\\n目覚めるのも\\nいいものだね', 1, 1, 2, 0, 1, 122501, 1, 6329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今朝釣ってきた魚が\\nあるんだ。これで\\nお昼ご飯にしようか', 1, 1, 2, 0, 2, 122501, 2, 6330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜にもイベントが\\nあるみたいなんだ\\n一緒に見に行かない？', 1, 1, 2, 0, 3, 122501, 3, 6331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちが安らぐね…\\nうっかり眠って…\\nしまい…そうだ…', 1, 1, 3, 0, 0, 122501, 2, 6333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('肌触りのよさが\\nこの格好だと\\nよく分かるよ', 1, 1, 3, 0, 0, 122501, 3, 6334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海をイメージさせる\\n香りだね…\\n爽やかで落ち着くよ', 1, 1, 3, 0, 0, 122501, 4, 6335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('濡れたままだと\\n風邪を引いてしまうよ\\nほら、キミもおいで', 1, 1, 3, 0, 0, 122501, 5, 6336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏を楽しみきるには\\nエネルギーが\\n必要だからね', 1, 1, 3, 0, 0, 122501, 7, 6338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大切な人と過ごせる\\n観光スポット紹介…\\n…こ、このページは\\nもういいかな！', 1, 1, 3, 0, 0, 122501, 8, 6339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('濡らしてもいいなら\\n海に持っていって\\n乗るのもよさそうだ', 1, 1, 3, 0, 0, 122501, 10, 6341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういう名画を\\n見た気がするな…\\nこんな視点なんだね', 1, 1, 3, 0, 0, 122501, 11, 6342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着って\\n動きやすくて\\nいいよねー♪\\nいっちにーさんしー♪', 1, 1, 1, 0, 0, 122401, 1, 6343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユイちゃんにもらった\\n日焼け止め\\n塗っておいて\\nよかった～', 1, 1, 1, 0, 0, 122401, 2, 6344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだか暑いなあ…\\nせっかくだし\\nプールで泳いで\\nこようかな？', 1, 1, 1, 0, 0, 122401, 3, 6345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好で\\n出かけようとしたら\\nレイさんに\\n怒られちゃった…', 1, 1, 1, 0, 0, 122401, 4, 6346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえ水着姿でも\\n困ってる人を見たら\\n助けに行くからね！', 1, 1, 1, 0, 0, 122401, 5, 6347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バカンス楽しかった～\\nまた騎士くんと\\n一緒に行きたいな♪', 4, 1, 1, 0, 0, 122401, 101, 6348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この水着、あたしに\\n似合ってるかなあ？\\n騎士くんはどう\\n思ってるんだろ…', 8, 1, 1, 0, 0, 122401, 102, 6349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くん！\\n海に行くなら\\n準備運動\\n忘れずにね！', 1, 1, 2, 0, 0, 122401, 1, 6350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐ練習がしたいの？\\nいいよ！\u3000水着だから\\nなにかあったらすぐに\\n助けてあげるね！', 1, 1, 2, 0, 0, 122401, 2, 6351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くんの水着姿も\\nかっこよかったよ！\\nまた遊びに行こ！\\n約束ね！', 1, 1, 2, 0, 0, 122401, 3, 6352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このグローブの向日葵\\nかわいいでしょ？\\nユイちゃんが\\n選んでくれたんだ♪', 1, 1, 2, 0, 0, 122401, 4, 6353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実はこの水着\\nいつも着てる\\n服とおなじなんだ…\\nって、冗談だよ？', 4, 1, 2, 0, 0, 122401, 101, 6354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変な日焼けしてないか\\n見てもらってもいい？\\n…なし！\u3000今のなし！\\nやっぱりなしー！', 8, 1, 2, 0, 0, 122401, 102, 6355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏のお日様に\\n負けないよう\\n今日も元気いっぱい\\nがんばるぞー！', 1, 1, 2, 0, 1, 122401, 1, 6356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹減ってきちゃった\\n騎士くんはお腹\\n空いてない？\\n…聞こえちゃった♪', 1, 1, 2, 0, 2, 122401, 2, 6357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\n楽しかったー！\\n明日もまた\\n楽しもうね！', 1, 1, 2, 0, 3, 122401, 3, 6358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわあ…\\nふわふわなのが\\nいつもより\\nよくわかるよー…', 1, 1, 3, 0, 0, 122401, 2, 6360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ！\u3000水着なら\\n濡れてもいいし\\n今度洗ってあげるね♪', 1, 1, 3, 0, 0, 122401, 3, 6361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー…いい匂い♪\\nなんだか\\n身体がぽかぽか\\nしてきちゃった！', 1, 1, 3, 0, 0, 122401, 4, 6362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着だから、えっと…\\n暖か涼しい…！\\n不思議な感じー', 1, 1, 3, 0, 0, 122401, 5, 6363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('思いっきり身体を\\n動かした後だから\\nいくらでも\\n食べちゃえるよー！', 1, 1, 3, 0, 0, 122401, 7, 6365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nなるほどー\\n水着の種類って\\nそんなにあるんだぁ…', 1, 1, 3, 0, 0, 122401, 8, 6366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('乗り心地バッチリだね\\nしゅっぱつしんこー！\\nなんちゃって♪', 1, 1, 3, 0, 0, 122401, 10, 6368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、ぽよんぽよん！\\nトランポリンみたいで\\nた～のし～！', 1, 1, 3, 0, 0, 122401, 11, 6369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼のことを考えてると\\n幸せで胸が温かくなる\\n…私ったら、もう', 12, 1, 1, 0, 0, 101501, 103, 6370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふふふ\\nくすぐったいわ～♪\\nもう、イタズラっ子ね\\n次は先生の番よ～♪', 12, 1, 2, 0, 0, 101501, 103, 6371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンの汗\\n拭いてあげたいな…\\n余計なお世話かな…？', 1, 1, 1, 0, 0, 122601, 1, 6372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏バテ気味かも…\\nそうだ、今夜は\\nかば焼きにしよう♪', 1, 1, 1, 0, 0, 122601, 2, 6373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('青い空、白い雲\\n眩しい日差し…！\\n夏って好きだな…', 1, 1, 1, 0, 0, 122601, 3, 6374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒリヒリする…？\\n日に焼けちゃったかな\\nふー…ふー…', 1, 1, 1, 0, 0, 122601, 4, 6375);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花火大会があるんだ…\\n夜、浜辺…2人きり…\\nむ、無理だよ〜！', 1, 1, 1, 0, 0, 122601, 5, 6376);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着って不思議…\\n引っ込み思案が少し\\nおさまる…気がする', 4, 1, 1, 0, 0, 122601, 101, 6377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンとまた\\n海に行きたいな…\\nまた、一緒に…', 8, 1, 1, 0, 0, 122601, 102, 6378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ダ、ダイエット！？\\nしてないよ！？\\n元々これ位だよ…？', 1, 1, 2, 0, 0, 122601, 1, 6379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スイカ割りのコツ？\\nわたしは、騎士クンに\\n教わりたいな…', 1, 1, 2, 0, 0, 122601, 2, 6380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン。うちわで\\n扇いであげるね\\nどこに置いたかな…', 1, 1, 2, 0, 0, 122601, 3, 6381);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うぅ…暑いね…\\n騎士クン、温度計は\\n見ない方がいいよ～', 1, 1, 2, 0, 0, 122601, 4, 6382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じ、じっと見ないで…\\nええっと…ちょっと！\\nちょっとならいいよ…', 4, 1, 2, 0, 0, 122601, 101, 6383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え、肝試し？\\nう〜ん、うう〜ん…\\n…騎士クンとなら！', 8, 1, 2, 0, 0, 122601, 102, 6384);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう騎士クン\\n見て、あっちの空\\nもう入道雲が出てる', 1, 1, 2, 0, 1, 122601, 1, 6385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夕立、来るかなぁ…\\nもし雷が鳴ったら\\nそばにいてくれる…？', 1, 1, 2, 0, 2, 122601, 2, 6386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しー。…ほら、虫の声\\n…わ、わたしの心臓の\\n音は気にしないで…！', 1, 1, 2, 0, 3, 122601, 3, 6387);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、水着でゴロゴロ\\nするのってなんだか…\\nいけないことみたい', 1, 1, 3, 0, 0, 122601, 2, 6389);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいい～♪\\n日光浴させて\\nあげたいな♪', 1, 1, 3, 0, 0, 122601, 3, 6390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほんのり潮の香りが…\\n香ばしくて塩辛くて…\\nあ…おなか鳴っちゃう', 1, 1, 3, 0, 0, 122601, 4, 6391);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着、乾かせるかも…\\nそうだ、みんなの分も\\n持ってこよう！', 1, 1, 3, 0, 0, 122601, 5, 6392);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏バテなんてしてたら\\nみんなの足を\\n引っ張っちゃうよね\\nいただきます！', 1, 1, 3, 0, 0, 122601, 7, 6394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンの、どうして\\n海はしょっぱいの？\\nって質問の答えは…\\n分かんないよぉ～', 1, 1, 3, 0, 0, 122601, 8, 6395);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('顔は怒ってるのに\\nなんだかかわいい…\\n誰かに似てる…？', 1, 1, 3, 0, 0, 122601, 10, 6397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを枕に、ビーチで\\n騎士クンと…なんて…\\nなんて…なんて…！', 1, 1, 3, 0, 0, 122601, 11, 6398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休み、\\n毎日たのしいな～♪\\nつぎはなにしよう？', 1, 1, 1, 0, 0, 122901, 1, 6399);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自由研究、\\nなににしよっかな～？\\nプチグリフォンさんの\\nかんさつにっきとか？', 1, 1, 1, 0, 0, 122901, 2, 6400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みって、\\n給食ないから…\\nそれはちょっぴり\\nさみしいかも…？', 1, 1, 1, 0, 0, 122901, 3, 6401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂浜をはだしで歩くの\\nきもちいいよね♪\\nくすぐったいけど\\nミミ、好きなんだ～♪', 1, 1, 1, 0, 0, 122901, 4, 6402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいな貝がら\\n見つけちゃった♪\\nミミのたからもの！', 1, 1, 1, 0, 0, 122901, 5, 6403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミ、浴衣を\\n買ってもらったんだ♪\\n今度、おにいちゃんに\\n見せてあげたいな！', 4, 1, 1, 0, 0, 122901, 101, 6404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミ、おにいちゃんと\\nいっぱい夏休みの\\n思い出つくりたいな♪', 8, 1, 1, 0, 0, 122901, 102, 6405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ、おにいちゃん…\\n夏休みの宿題、\\nわかんないとこ\\nおしえてくれる…？', 1, 1, 2, 0, 0, 122901, 1, 6406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかあさんにね、\\n麦茶つくるの上手って\\nほめられたんだ～♪\\n飲んでみて♪', 1, 1, 2, 0, 0, 122901, 2, 6407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みの宿題で\\nポスターかくんだ～♪\\nおにいちゃんを\\nかいてもいい？', 1, 1, 2, 0, 0, 122901, 3, 6408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('線香花火やりたいな♪\\nミミ、長持ちさせるの\\n上手なんだよ♪', 1, 1, 2, 0, 0, 122901, 4, 6409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おにいちゃんの\\n好きな本ってなあに？\\nその本で読書感想文\\n書こうかな♪', 4, 1, 2, 0, 0, 122901, 101, 6410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海であそんだ後ね、\\nおにいちゃんに\\n髪を拭いてもらうの\\nすきなんだ～♪', 8, 1, 2, 0, 0, 122901, 102, 6411);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みって、\\nワクワクして\\n早起きしちゃうよね♪', 1, 1, 2, 0, 1, 122901, 1, 6412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ♪\u3000お昼は、\\n流しそうめんなんだ？\\nミミ、流してみたい♪', 1, 1, 2, 0, 2, 122901, 2, 6413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こわい話聞いて、\\nねむれないの…\\nねえ、おにいちゃん、\\nいっしょに寝ていい？', 1, 1, 2, 0, 3, 122901, 3, 6414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっぴりやすんだら\\nまた、いっしょに\\n海であそぼうね♪', 1, 1, 3, 0, 0, 122901, 2, 6416);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すっごくかわいいね♪\\nこの子のこと、\\n絵日記にかこうっと♪', 1, 1, 3, 0, 0, 122901, 3, 6417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…\\nスイカのにおいだね♪\\nこのにおいだいすき！', 1, 1, 3, 0, 0, 122901, 4, 6418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('およいだあとは、\\nちゃんと体を\\nあっためなくちゃね！', 1, 1, 3, 0, 0, 122901, 5, 6419);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みのご飯って\\nなんだかとくべつ\\nおいしい気がするね♪', 1, 1, 3, 0, 0, 122901, 7, 6421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の星座って\\nすっごくきれいだね♪\\nいつかみんなと\\nいっしょに見たいな♪', 1, 1, 3, 0, 0, 122901, 8, 6422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ♪\u3000この子、\\nとってもかわいいね！\\nおともだちに\\nなりたいな♪', 1, 1, 3, 0, 0, 122901, 10, 6424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミ、人魚姫に\\nなったみたい！\\nおにいちゃん、\\nとなりにすわって♪', 1, 1, 3, 0, 0, 122901, 11, 6425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿になると\\nバカンス気分を\\n味わえちゃうね！', 1, 1, 1, 0, 0, 122801, 1, 6426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行くの待ちきれ\\nなくて、もう水着に\\n着替えちゃった！', 1, 1, 1, 0, 0, 122801, 2, 6427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行ったら\\nずぶぬれ系のイタズラ\\nたくさんしかけよう！', 1, 1, 1, 0, 0, 122801, 3, 6428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の中で泳ぎの練習\\nしよう！\u3000にいちゃん\\nも水着に着替えて！', 1, 1, 1, 0, 0, 122801, 4, 6429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お日さまとお揃いの\\n水着なんだ～♪\\n似合ってるかなぁ？', 1, 1, 1, 0, 0, 122801, 5, 6430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海といえば冒険！\\n海底に眠る財宝を\\n見つけちゃおう！', 4, 1, 1, 0, 0, 122801, 101, 6431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんと一緒だと\\n部屋にいても海気分♪\\nスイカわりしよっか！', 8, 1, 1, 0, 0, 122801, 102, 6432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃん！\\n早く海に行く準備\\nしなよ～！', 1, 1, 2, 0, 0, 122801, 1, 6433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねーにいちゃん\\n何秒息止められるか\\n勝負しよーよ！', 1, 1, 2, 0, 0, 122801, 2, 6434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんはアイスと\\nかき氷どっちが好き？\\nミソギは…どっちも！', 1, 1, 2, 0, 0, 122801, 3, 6435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日焼け止めクリーム\\nキョウカに\\nもらったんだ～', 1, 1, 2, 0, 0, 122801, 4, 6436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水中メガネがあれば\\n水鉄砲くらっても\\n平気だね！', 4, 1, 2, 0, 0, 122801, 101, 6437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着なら、毎日夏休み\\n気分！\u3000にいちゃんも\\n着てみなよ～！', 8, 1, 2, 0, 0, 122801, 102, 6438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんおはよー！\\n早く顔洗って、\\nいっぱい遊んじゃお！', 1, 1, 2, 0, 1, 122801, 1, 6439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にいちゃんデザートは\\nイチゴのかき氷だよ！\\n…激辛ってバレた？', 1, 1, 2, 0, 2, 122801, 2, 6440);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は楽しかった～！\\n明日もイタズラ日和に\\nなるといいな！', 1, 1, 2, 0, 3, 122801, 3, 6441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('落とし穴の下に\\nやわらかいの置けば\\nケガしないよね！', 1, 1, 3, 0, 0, 122801, 2, 6443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいね～！\\nこの子も海に\\n連れてっちゃおうよ！', 1, 1, 3, 0, 0, 122801, 3, 6444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このにおいを利用して\\nイタズラするには…\\nにいちゃんどう思う？', 1, 1, 3, 0, 0, 122801, 4, 6445);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着を着て暖炉で\\nあったまるのって、\\n変でおもしろいね～！', 1, 1, 3, 0, 0, 122801, 5, 6446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海辺で食べる\\nお昼ごはんって最高♪\\nってことで海行こう！', 1, 1, 3, 0, 0, 122801, 7, 6448);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか海を越えて、\\n地図にも載ってない\\n場所を見つけたいな！', 1, 1, 3, 0, 0, 122801, 8, 6449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この口から水が出たら\\nみんな驚くよね！\\nぷぷ…細工しちゃお！', 1, 1, 3, 0, 0, 122801, 10, 6451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('変な音がするイタズラ\\nを仕込んどいて…\\n誰か座らないかな～♪', 1, 1, 3, 0, 0, 122801, 11, 6452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなた様と私の愛を\\n周りに見せつけて\\n差し上げましょう♪', 12, 1, 1, 0, 0, 102701, 103, 6453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('呼びましたか？\\n呼びましたね？\\nでは愛を語りましょう\\nそうしましょう', 12, 1, 2, 0, 0, 102701, 103, 6454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着で歩き回るのは\\n恥ずかしいな…\\n誰も見てないよね？', 1, 1, 1, 0, 0, 122701, 1, 6455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏はやっぱり\\nかき氷ですよね\\n何色がいいかなぁ…♪', 1, 1, 1, 0, 0, 122701, 2, 6456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人、泳げないって\\n聞きました！\\n私が教えてあげないと', 1, 1, 1, 0, 0, 122701, 3, 6457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みの宿題は\\n計画的に進めましょう\\n当たり前のことです！', 1, 1, 1, 0, 0, 122701, 4, 6458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('防犯魔石、どこに\\n着けておこうかなぁ\\n…ここにしようかな', 1, 1, 1, 0, 0, 122701, 5, 6459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海の楽しみ方は\\n予習済みです！\\nあとは実践ですね♪', 4, 1, 1, 0, 0, 122701, 101, 6460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着…きっとあの人に\\n見られちゃいますよね\\n…褒めてくれるかな…', 8, 1, 1, 0, 0, 122701, 102, 6461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('触りたいんですか？\\n…いいですよ\\n帽子くらいなら', 1, 1, 2, 0, 0, 122701, 1, 6462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏は体調管理に\\n気をつけましょう\\n私が管理してあげます', 1, 1, 2, 0, 0, 122701, 2, 6463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行くのが楽しみで\\nたまらないんですか？\\n私はそこまで…嘘です', 1, 1, 2, 0, 0, 122701, 3, 6464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもより薄着だから\\nなんだか恥ずかしい…\\nみ、見ないでください', 1, 1, 2, 0, 0, 122701, 4, 6465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へんたいふしんしゃ～\\nえっ？\u3000ああ、これは\\n海に叫ぶ練習です', 4, 1, 2, 0, 0, 122701, 101, 6466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと一緒に\\n海に行くなんて…\\nなんだか大人…えへへ', 8, 1, 2, 0, 0, 122701, 102, 6467);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\nさぁ、海に行って\\n私と運動しましょう', 1, 1, 2, 0, 1, 122701, 1, 6468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっつ～い…\\nはっ！？\u3000ダメですよ\\nシャキッとしないと！', 1, 1, 2, 0, 2, 122701, 2, 6469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日も海で\\n遊ぶために、しっかり\\nお休みしましょうね', 1, 1, 2, 0, 3, 122701, 3, 6470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏を楽しむときは\\n休憩も大事ですよね\\n計画的に、計画的に！', 1, 1, 3, 0, 0, 122701, 2, 6472);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいなぁ～\\n海のお土産屋さんに\\n売ってるかなぁ？', 1, 1, 3, 0, 0, 122701, 3, 6473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大人な香りがします\\n私も違いが分かる\\n素敵な女性になります', 1, 1, 3, 0, 0, 122701, 4, 6474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('濡れた体を\\n乾かしましょう\\nタオル、タオル…', 1, 1, 3, 0, 0, 122701, 5, 6475);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳いだ後は\\n栄養補給…だけど\\n…おなか膨らんじゃう', 1, 1, 3, 0, 0, 122701, 7, 6477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遊ぶだけじゃなくて\\nお勉強もしてますよ\\nあなたもどうですか？', 1, 1, 3, 0, 0, 122701, 8, 6478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミが喜びそう…♪\\nわ、私ははしゃいだり\\nしませんけど…っ！', 1, 1, 3, 0, 0, 122701, 10, 6480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソギがいたずらに\\n使いそう…しっかりと\\n試しておかないと！', 1, 1, 3, 0, 0, 122701, 11, 6481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしがまさか\\nここにいるなんて…\\n自分でも不思議だわ', 1, 1, 1, 0, 0, 123001, 1, 6482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昔みたいにあちこち\\n飛び回れないのって\\nちょっと不便かも', 1, 1, 1, 0, 0, 123001, 2, 6483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうして誰かと一緒に\\n暮らせるのもあいつや\\nみんなのおかげね', 1, 1, 1, 0, 0, 123001, 3, 6484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで厄介になるなら\\nあたしも家事とか\\n手伝わないと…', 1, 1, 1, 0, 0, 123001, 4, 6485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…だめ！\u3000誰かの\\n世話をせずには\\nいられないわ！', 1, 1, 1, 0, 0, 123001, 5, 6486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつたちが\\n帰ってくるところだし\\n綺麗にしないと…', 4, 1, 1, 0, 0, 123001, 101, 6487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくあたしが\\nいるっていうのに\\n少しは構いなさいよ…', 8, 1, 1, 0, 0, 123001, 102, 6488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしい店とか\\n知らないの？\\n食べに行きましょ', 1, 1, 2, 0, 0, 123001, 1, 6489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんた暇でしょ？\\nあたしのやること\\n手伝いなさい', 1, 1, 2, 0, 0, 123001, 2, 6490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コッコロたんと\\n遊んでくるから\\n留守番よろしく♪', 1, 1, 2, 0, 0, 123001, 3, 6491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらおかえり…って\\nボロボロじゃない！\\nまた人助けしてたの？', 1, 1, 2, 0, 0, 123001, 4, 6492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりあたしは\\nあんたのそばが\\n一番落ち着くみたい', 4, 1, 2, 0, 0, 123001, 101, 6493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこまでだって\\nあんたと一緒に\\nいてやるんだから', 8, 1, 2, 0, 0, 123001, 102, 6494);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…おはよう\\n…大きくなったせいか\\n朝は特に体が重いわ', 1, 1, 2, 0, 1, 123001, 1, 6495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯が食べたい？\\nしょうがないわね…\\nなんか作って\\nあげるから', 1, 1, 2, 0, 2, 123001, 2, 6496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたまだ成長期だし\\nさっさと寝なさい\\n大きくなれないわよ？', 1, 1, 2, 0, 3, 123001, 3, 6497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにはあたしも\\nゆっくりしないと\\nもたないのよ…', 1, 1, 3, 0, 0, 123001, 2, 6499);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいじゃな～い♪\\nコッコロたんに\\nプレゼントしたいわ', 1, 1, 3, 0, 0, 123001, 3, 6500);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね\\n塔にもこういうの\\n置いておこうかしら', 1, 1, 3, 0, 0, 123001, 4, 6501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('炎か…前は\\n羽が焼けそうで\\n怖かったっけ', 1, 1, 3, 0, 0, 123001, 5, 6502);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あむ…妖精に\\n体重増減の設定って\\nあったっけ…？', 1, 1, 3, 0, 0, 123001, 7, 6504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('記憶のデータと違って\\n物語はいいわね\\n結末が読めなくて', 1, 1, 3, 0, 0, 123001, 8, 6505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険のお土産\\nみんなにおすそわけ\\nせなあきまへんな', 1, 1, 1, 0, 0, 123101, 1, 6507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おとぎ話よりも\\n不思議なことが\\nあるもんやねぇ', 1, 1, 1, 0, 0, 123101, 2, 6508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険しに出かけるなら\\n動きやすい服装に\\nせななぁ', 1, 1, 1, 0, 0, 123101, 3, 6509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('地図に水筒に…\\n他に忘れもんは\\nあらへんやろか？', 1, 1, 1, 0, 0, 123101, 4, 6510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これまでの冒険のこと\\nノートに書いて\\nまとめてますんよ', 1, 1, 1, 0, 0, 123101, 5, 6511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんとの冒険は\\nどれもマホマホ王国の\\n大事な歴史や♪', 4, 1, 1, 0, 0, 123101, 101, 6512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこへ冒険するときも\\nうちと王子はんは\\n一緒どす♪', 8, 1, 1, 0, 0, 123101, 102, 6513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法で火ぃつける\\n練習してますんよ～\\nよう爆発しますけど…', 1, 1, 2, 0, 0, 123101, 1, 6514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちと王子はんで\\n冒険道具をお揃いに\\nするんもええなぁ♪', 1, 1, 2, 0, 0, 123101, 2, 6515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('テント張りも随分\\n上達したんよ\\n王子はんのおかげやね', 1, 1, 2, 0, 0, 123101, 3, 6516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランスロットたちの\\n新しい冒険衣装\\n思いついたんよ♪', 1, 1, 2, 0, 0, 123101, 4, 6517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('迷子になっても\\n王子はんと一緒なら\\nきっと大丈夫やね♪', 4, 1, 2, 0, 0, 123101, 101, 6518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんのこと、\\nきっちり守れるように\\nなってみせますえ', 8, 1, 2, 0, 0, 123101, 102, 6519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お寝坊さんは\\n布団めくって\\n起こしにいきますえ～', 1, 1, 2, 0, 1, 123101, 1, 6520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('支度が終わったら\\n今日の冒険に\\n出かけまひょか', 1, 1, 2, 0, 2, 123101, 2, 6521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうちょっと\\nおしゃべりしたいん？\\nあと少しだけやで♪', 1, 1, 2, 0, 3, 123101, 3, 6522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険で疲れた体に\\nこの癒しぱわーは\\nあきまへん…すや…', 1, 1, 3, 0, 0, 123101, 2, 6524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、あんさんも\\nうちと一緒に\\n冒険します？', 1, 1, 3, 0, 0, 123101, 3, 6525);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('虫除けのアロマは\\n冒険の必需品どす\\n忘れんようにせんと', 1, 1, 3, 0, 0, 123101, 4, 6526);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちも魔法使わんでも\\n火ぃ起こせるよう\\n練習せんとあかんなぁ', 1, 1, 3, 0, 0, 123101, 5, 6527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この料理…\\n冒険するときに\\n作ってみまひょか', 1, 1, 3, 0, 0, 123101, 7, 6529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんとの\\n愛と冒険のおとぎ話…\\nはぁ…素敵やわぁ♪', 1, 1, 3, 0, 0, 123101, 8, 6530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人との\\n最良の未来のために\\n占いも霊能力ももっと\\n精進しなきゃ', 12, 1, 1, 0, 0, 103101, 103, 6532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたともっと深く\\nつながりたいです\\n絆も、そして魂までも', 12, 1, 2, 0, 0, 103101, 103, 6533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絆の契約…\\nあやつが望むのなら\\n考えぬでもないがのう', 12, 1, 1, 0, 0, 104401, 103, 6534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんじゃ？\\nわらわの姿に\\n見惚れたかの？', 12, 1, 2, 0, 0, 104401, 103, 6535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅の荷物って多いな…\\nねぇぷうきち～\\nすこしは持ってよぉ～', 1, 1, 1, 0, 0, 123201, 1, 6536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('傘はなくてもいっか\\nぷうきちがいるし♪\\n『おいなんだと…？』', 1, 1, 1, 0, 0, 123201, 2, 6537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅先で人見知りなんか\\nしてちゃだめだよね…\\nまずはあいさつだ…！', 1, 1, 1, 0, 0, 123201, 3, 6538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おみやげはやっぱり\\nご当地ぬいぐるみ\\nだよね♪\u3000ワクワク…', 1, 1, 1, 0, 0, 123201, 4, 6539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知らない場所かぁ…\\nうぅ…考えただけで\\nすでにホームシック…', 1, 1, 1, 0, 0, 123201, 5, 6540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('野宿するってことは…\\nお兄ちゃんのマントで\\n寝るチャンスかも…！', 4, 1, 1, 0, 0, 123201, 101, 6541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなに危険な冒険も\\nお兄ちゃんと一緒なら\\n大丈夫！\u3000…だよね？', 8, 1, 1, 0, 0, 123201, 102, 6542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぷうきちのアイマスク\\nも腹巻も持ってくの！\\n旅の必需品なの～！', 1, 1, 2, 0, 0, 123201, 1, 6543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ全部背負うのって\\nけっこうむずかしいの\\n順番まちがえると大変', 1, 1, 2, 0, 0, 123201, 2, 6544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ～\\nなでなでして？\u3000帽子\\nの上からでもいいよ♪', 1, 1, 2, 0, 0, 123201, 3, 6545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『悪いが絆創膏の部分\\nはアンタッチャブルだ\\n綿が飛び出ちまう』', 1, 1, 2, 0, 0, 123201, 4, 6546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんと一緒に\\nもっともっといろんな\\n景色が見たいな！', 4, 1, 2, 0, 0, 123201, 101, 6547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅って、終わる時は\\nきっとさびしいよね…\\nお兄ちゃん、帰り道は\\n手をつないでもいい？', 8, 1, 2, 0, 0, 123201, 102, 6548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('出発が楽しみすぎて\\n寝られなかった…\\n『旅行のお約束だな』', 1, 1, 2, 0, 1, 123201, 1, 6549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁ\u3000いいお天気！\\n旅の間もずーっと\\nぴーかんだといいな♪', 1, 1, 2, 0, 2, 123201, 2, 6550);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知らない場所で寝るの\\n怖いな…寝る時だけ\\n帰ってこようかな…', 1, 1, 2, 0, 3, 123201, 3, 6551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅先にはクッションも\\nソファもないよね…\\n『俺でいいだろ』', 1, 1, 3, 0, 0, 123201, 2, 6553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬいぐるみのみんな\\n旅の無事を\\n祈ってて…！', 1, 1, 3, 0, 0, 123201, 3, 6554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅先の香りも\\n思い出に持って\\n帰れたらいいのにな～', 1, 1, 3, 0, 0, 123201, 4, 6555);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅行用に携帯用暖炉\\nがあるといいかも…！\\n『まだ荷物増やす？』', 1, 1, 3, 0, 0, 123201, 5, 6556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『もう出発だぜ？』\\nえーまってまって！\\n腹ごしらえがまだ…', 1, 1, 3, 0, 0, 123201, 7, 6558);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界ってこんなに広い\\nんだ…！\u3000はやく自分\\nの目で見てみたいな～', 1, 1, 3, 0, 0, 123201, 8, 6559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はちゃめちゃヒマ～\\nなーんか楽し～コト\\nないかなー', 1, 1, 1, 0, 0, 123301, 1, 6561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ、いートコだねー\\nこんどカリザきゅんも\\nつれてこよー', 1, 1, 1, 0, 0, 123301, 2, 6562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわゆいショタが\\n見た～い♪\\n触りた～～～い♪', 1, 1, 1, 0, 0, 123301, 3, 6563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんか服きっついなー\\nちょい太ったかー？\\nん～\\nま・気のせーっしょ♪', 1, 1, 1, 0, 0, 123301, 4, 6564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ～やべ\\nおねえちゃんに\\nメッセすんの忘れたー\\nまいっかー', 1, 1, 1, 0, 0, 123301, 5, 6565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パンケーキ食いてー\\n騎士きゅん\\n誘ってみよーっと♪', 4, 1, 1, 0, 0, 123301, 101, 6566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きょーも～\\n好きぴに囲まれて～\\nシ・ア・ワ・セ♪', 8, 1, 1, 0, 0, 123301, 102, 6567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アタシと遊ばな～い？\\nってなんか\\nナンパみスゴー\\nウケる～', 1, 1, 2, 0, 0, 123301, 1, 6568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んー？\\n今はだるいからパース\\nあとでねー', 1, 1, 2, 0, 0, 123301, 2, 6569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カリザきゅん\\n見なかった～？\\nおねえちゃんから\\n逃げるとかオシオキー', 1, 1, 2, 0, 0, 123301, 3, 6570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネイルしたいけど\\n無理なんよねー\\n爪の間にめっちゃ\\nスライム入っからさー', 1, 1, 2, 0, 0, 123301, 4, 6571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おねえちゃんに\\nかまってほし～の？\\nかわゆ～い♪', 4, 1, 2, 0, 0, 123301, 101, 6572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な～に騎士きゅん♪\\nここでイチャイチャ～\\nし・ちゃ・う～？', 8, 1, 2, 0, 0, 123301, 102, 6573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねんむ～\\nけど外から\\nショタの声したんで～\\nつい起きちった～', 1, 1, 2, 0, 1, 123301, 1, 6574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランチの後はやっぱ\\nデザートっしょー\\nベツバラってヤツ～♪', 1, 1, 2, 0, 2, 123301, 2, 6575);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな時間まで\\n起きてるコは～\\n食べちゃうぞ～♪', 1, 1, 2, 0, 3, 123301, 3, 6576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーラクー\\nいっしょーここで\\nキューケーできるわー', 1, 1, 3, 0, 0, 123301, 2, 6578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにこれ～\\nかわいいじゃ～ん\\nショタの次くらいに～', 1, 1, 3, 0, 0, 123301, 3, 6579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いーニオイする～\\nなんのニオイとかー\\nよくわかんないけどー', 1, 1, 3, 0, 0, 123301, 4, 6580);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったか～♪\\n溶けてスライム\\n戻りそ～', 1, 1, 3, 0, 0, 123301, 5, 6581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ン・ン・ン～♪\\nお・い・し～♪\\nも～っと食べるぅ～♪', 1, 1, 3, 0, 0, 123301, 7, 6583);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わ～なんかムズー\\n読めなー\\nウケるー', 1, 1, 3, 0, 0, 123301, 8, 6584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんパンって\\nお菓子に入るのかな？\\nハロウィンで\\nもらえたりしない？', 1, 1, 1, 0, 0, 123501, 1, 6586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子をくれなきゃ\\nぐうたらするぞ～！\\nハロウィン以外でも！', 1, 1, 1, 0, 0, 123501, 2, 6587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お化けになったら\\n仕事しないで\\nゴロゴロし放題\\nなのかな？', 1, 1, 1, 0, 0, 123501, 3, 6588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっと…この仮装\\n袖がすごく長いからさ\\n引っ掛けないように\\n気を付けないとね～', 1, 1, 1, 0, 0, 123501, 4, 6589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イタズラするのも\\n体力がいるよね～\\n楽にできそうなの\\n何かないかな？', 1, 1, 1, 0, 0, 123501, 5, 6590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつって\\n仮装とかするのかな？\\n似合いそうなのは\\nどんなお化けだろ？', 4, 1, 1, 0, 0, 123501, 101, 6591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずっとハロウィンなら\\nあいつと遊び放題\\nなんだけどな～', 8, 1, 1, 0, 0, 123501, 102, 6592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今の街はハロウィン\\n一色だからね～\\n人混みが大変だよ', 1, 1, 2, 0, 0, 123501, 1, 6593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この仮装、どうかな？\\n気に入ったなら\\n来年もしてあげるよ～', 1, 1, 2, 0, 0, 123501, 2, 6594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実はこの長い袖\\nドングリとかを\\nため込めるんだよね…', 1, 1, 2, 0, 0, 123501, 3, 6595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャランタンが\\nあるんなら\\nドングリランタンも\\nあっていいよね～♪', 1, 1, 2, 0, 0, 123501, 4, 6596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンでも\\nやる気があれば\\nぐうたらできる…\\nうん、いいこと言った', 4, 1, 2, 0, 0, 123501, 101, 6597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にお菓子食べよ？\\n寝転びながら堪能する\\nハロウィンスイーツは\\n最高だからね～', 8, 1, 2, 0, 0, 123501, 102, 6598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お化けは寝る時間…\\n今のあたしはお化け…\\nだから、おやすみ～…', 1, 1, 2, 0, 1, 123501, 1, 6599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼か～…\\n食後のデザートは\\nハロウィンのお菓子で\\n決まりだね～♪', 1, 1, 2, 0, 2, 123501, 2, 6600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～、寝よ…\\nお化けは夜に\\n出るものだけど\\nあたしはリスだからね', 1, 1, 2, 0, 3, 123501, 3, 6601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンを楽しむ\\nためにも、ぐっすり\\n寝とかないとね～', 1, 1, 3, 0, 0, 123501, 2, 6603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…袖から手が\\n出せないから\\nこのまま撫でよう\\nよしよし', 1, 1, 3, 0, 0, 123501, 3, 6604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスできる\\n素敵な香りだね～\\n成仏しそうだよ～', 1, 1, 3, 0, 0, 123501, 4, 6605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいね～\\nここで寝てもいい？\\n…着替えないとダメか', 1, 1, 3, 0, 0, 123501, 5, 6606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nお化けもリスも\\nお腹は空くんだよ', 1, 1, 3, 0, 0, 123501, 7, 6608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キョンシーって\\nどんなお化けなのか\\n本で調べようかな？', 1, 1, 3, 0, 0, 123501, 8, 6609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('より取り見取りだね～\\nとりあえず、これと\\nこのお菓子はキープで', 1, 1, 3, 0, 0, 123501, 12, 6611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よし、衣装もばっちり\\nハロウィンパレードへ\\n出かけよう♪', 1, 1, 1, 0, 0, 123601, 1, 6613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仮装してても\\n剣は手放せないね\\nほとんど体の一部だよ', 1, 1, 1, 0, 0, 123601, 2, 6614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見回りに誘うふりして\\n二人でパレードに\\n参加しちゃおうかな♪', 1, 1, 1, 0, 0, 123601, 3, 6615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…あれ？\u3000手錠の鍵\\n落としちゃった…？\\nやば、出かける前に\\n見つけないと…！', 1, 1, 1, 0, 0, 123601, 4, 6616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お家でコスプレも\\nこれはこれで楽しいな\\n決めポーズの練習\\nたくさんしておこう！', 1, 1, 1, 0, 0, 123601, 5, 6617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('他にも、お姫様に\\nメイドさんに学生服…\\nやりたいコスプレが\\n多すぎるよ～', 4, 1, 1, 0, 0, 123601, 101, 6618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('漫画もゲームも好き！\\n仮装するのも大好き！\\n…好きを言葉にすると\\nもっと好きになる♪', 8, 1, 1, 0, 0, 123601, 102, 6619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずっと目が合ってるね\\n見つめてくれるのは\\nいいんだけど、今日は\\n衣装を見てほしいな♪', 1, 1, 2, 0, 0, 123601, 1, 6620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トリックオアトリート\\nお菓子をくれなきゃ\\n逮捕しちゃうぞ♪', 1, 1, 2, 0, 0, 123601, 2, 6621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたにだけはこの姿\\nいつでも見せてあげる\\nふふ、なんちゃって♪', 1, 1, 2, 0, 0, 123601, 3, 6622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしたの？\\nイタズラするなら\\n隙を突かなきゃ\\nこんなふうに、ね♪', 1, 1, 2, 0, 0, 123601, 4, 6623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コスプレしてても\\n剣の稽古は休まないよ\\nちょっと相手になって\\nくれるかな？', 4, 1, 2, 0, 0, 123601, 101, 6624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっ、びっくりした\\n急に触らないでよ～\\nハロウィンだからって\\nイタズラしないでね？', 8, 1, 2, 0, 0, 123601, 102, 6625);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\n今日も朝から\\nパトロールに行こう！', 1, 1, 2, 0, 1, 123601, 1, 6626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カボチャのケーキを\\n用意してるよ！\\nデザートを食べて\\n午後も頑張ろう！', 1, 1, 2, 0, 2, 123601, 2, 6627);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暗くなってきたね\\nカボチャのランタンに\\n火を灯そうよ♪', 1, 1, 2, 0, 3, 123601, 3, 6628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか気持ちいい～\\nあっでも衣装がシワに\\nなっちゃうかも…？\\n…でも気持ちいい～', 1, 1, 3, 0, 0, 123601, 2, 6630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…かわいい\\nこの子もパレードに\\n連れて行きたいな', 1, 1, 3, 0, 0, 123601, 3, 6631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～癒される♪\\nハロウィンの見回りが\\n終わった後は、\\nまったりくつろごう', 1, 1, 3, 0, 0, 123601, 4, 6632);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで二人寄り添って\\nカボチャスープ飲もう\\n…なんて想像したら\\nポカポカしてきた…', 1, 1, 3, 0, 0, 123601, 5, 6633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パレードに参加すると\\n体力を使うから、\\nいっぱい食べておこう', 1, 1, 3, 0, 0, 123601, 7, 6635);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この絵本のお姫様\\nかわいいね\\nこの仮装もいいな♪', 1, 1, 3, 0, 0, 123601, 8, 6636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、おいしそう！\\n見回りに行く前に\\n少しつまんじゃおう♪', 1, 1, 3, 0, 0, 123601, 12, 6638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日こそは、あの人に\\n気持ちを打ち明けて…\\nそのあとは…うう\\nど、どうしよう？', 12, 1, 1, 0, 0, 103701, 103, 6640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が剣なら、あなたは\\nさしずめ私の鞘…\\nふふ、私の帰る\\n場所ってことだよ♪', 12, 1, 2, 0, 0, 103701, 103, 6641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり\\nコスプレしてると\\nテンションあがる～♪', 1, 1, 1, 0, 0, 123701, 1, 6642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャラコスにも\\n興味あるけど…\\nマジカル、ラブリー\\nどっちにしよっかな～', 1, 1, 1, 0, 0, 123701, 2, 6643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャラコスといえば\\nミスティーシャイニー\\nもいいんだよねえ…\\nうはー！\u3000悩むー！', 1, 1, 1, 0, 0, 123701, 3, 6644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスで\\n宅コスしてる人\\n実は結構\\nいるんじゃないかな～', 1, 1, 1, 0, 0, 123701, 4, 6645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コスプレだけど普段着\\nって言いはれそう…\\nって、ダメダメ！\\nオタクは節度が大事！', 1, 1, 1, 0, 0, 123701, 5, 6646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('フェスで買ってきた\\n薄い本～♪\\nギルドハウスに持って\\nきちゃおっかな～', 4, 1, 1, 0, 0, 123701, 101, 6647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ようこそ\\nコスプレ沼へ～\\nなんちゃって♪', 8, 1, 1, 0, 0, 123701, 102, 6648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうどう？\\nナナカちゃんの\\nハロウィンコスプレ\\n似合ってる？', 1, 1, 2, 0, 0, 123701, 1, 6649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィン魔法少女\\n参上カボ～！\\n…やっぱ今の語尾\\nナシで！', 1, 1, 2, 0, 0, 123701, 2, 6650);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハロウィンといえば\\nトリックオア～…\\nコスプレ！\\nなんちゃって', 1, 1, 2, 0, 0, 123701, 3, 6651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランフェスの\\n戦利品～♪\\nねえねえ\\n見たい？\u3000見たい？', 1, 1, 2, 0, 0, 123701, 4, 6652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私にしてほしい\\nコスプレがあったら\\n教えて♪\u3000君のために\\nや～ってやるぜぇ！', 4, 1, 2, 0, 0, 123701, 101, 6653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にコスプレしたい\\nならナナカちゃんは\\nいつでも大歓迎だよ♪', 8, 1, 2, 0, 0, 123701, 102, 6654);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁあ…ねむ\\nって、ありゃりゃ\u3000\\n昨日コスプレしたまま\\n寝ちゃってたかあ…', 1, 1, 2, 0, 1, 123701, 1, 6655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のお昼は\\nなんにしよ？\\nカボチャ料理に\\nしよっかな～', 1, 1, 2, 0, 2, 123701, 2, 6656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間かあ\\nそういえばオタクって\\n夜行性の人が多い\\n気がするぜぇ…', 1, 1, 2, 0, 3, 123701, 3, 6657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふっふっふ\\nこのパニエは\\n座るときはちゃんと\\nふにゃってなるのさ！', 1, 1, 3, 0, 0, 123701, 2, 6659);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いや～\\nかわいいものをみると\\n癒されますな～', 1, 1, 3, 0, 0, 123701, 3, 6660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい薄い本の匂いの\\nアロマとか…ダメ？\\n私はあの匂い、なんか\\n好きなんだよね～', 1, 1, 3, 0, 0, 123701, 4, 6661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖か～い…\\nけど近づきすぎて\\n衣装が燃えないように\\n気を付けなきゃ', 1, 1, 3, 0, 0, 123701, 5, 6662);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コス衣装のために\\n体型維持は必須だけど\\nついつい\\n食べちゃうんだよね～', 1, 1, 3, 0, 0, 123701, 7, 6664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっ、次はこの本に\\nのってるキャラのコス\\nしてみよっかな？', 1, 1, 3, 0, 0, 123701, 8, 6665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おおっ！\\nお菓子がいっぱい！\\nベルルちゃんチョコ\\n入ってないかな～？', 1, 1, 3, 0, 0, 123701, 12, 6667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むっ…\\nこの耳の手触り…\\n驚嘆に値する…！', 1, 1, 1, 0, 0, 123801, 1, 6669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('獲物を狩りまくる…\\nそんなウサギがいても\\nいいだろう？', 1, 1, 1, 0, 0, 123801, 2, 6670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワナなど怖くないぞ？\\nむしろ積極的に\\n踏んでいく性分だ', 1, 1, 1, 0, 0, 123801, 3, 6671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一匹狼ならぬ\\n一匹ウサギか\\nどっちでもかまわん♪', 1, 1, 1, 0, 0, 123801, 4, 6672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人間とて本を正せば獣\\n本能に従えばよいのだ\\n遠慮は無用さ☆', 1, 1, 1, 0, 0, 123801, 5, 6673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('脱兎のごとく…\\n逃げるものか\\n坊やを追い回すのさ♪', 4, 1, 1, 0, 0, 123801, 101, 6674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('獣の道は険しいが…\\n坊やめ、音を上げずに\\nちゃんとついてきたな\\n褒めてやるとしよう♪', 8, 1, 1, 0, 0, 123801, 102, 6675);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニンジンはいらん\\n好物は好敵手だ\\nさぁどんどんおくれ♪', 1, 1, 2, 0, 0, 123801, 1, 6676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('尻尾に触りたいだと？\\nワタシの乱数聖域を\\n崩せたらな…☆', 1, 1, 2, 0, 0, 123801, 2, 6677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('頭で考えるな\\n体に率直になれ\\n己を野放しにするのさ', 1, 1, 2, 0, 0, 123801, 3, 6678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうさモコフワさ♪\\nなで心地は最高だが\\n意外にどう猛だぞ…？', 1, 1, 2, 0, 0, 123801, 4, 6679);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシにピョンピョン\\n跳ねてほしいのか？\\nあとでじっくり、な♪', 4, 1, 2, 0, 0, 123801, 101, 6680);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシと番になるか？\\nオマエさえよければ\\nいつでもかまわんぞ☆', 8, 1, 2, 0, 0, 123801, 102, 6681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('太陽と共に目覚め\\n活動する\\nそれが獣の生き方さ☆', 1, 1, 2, 0, 1, 123801, 1, 6682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼寝をすればいい\\nワタシが周囲を\\n警戒していてやる', 1, 1, 2, 0, 2, 123801, 2, 6683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暗くなれば眠るだけさ\\nそうすれば余計な\\nストレスなどたまらん', 1, 1, 2, 0, 3, 123801, 3, 6684);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむっ！？\\n尻尾がつっかえて\\nうまく座れんな…', 1, 1, 3, 0, 0, 123801, 2, 6686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛らしさでワタシに\\n張り合おうというのか\\n５億年後に出直せ☆', 1, 1, 3, 0, 0, 123801, 3, 6687);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('野生の芳香か…\\n本能が呼び覚まされる\\nいいセンスだ♪', 1, 1, 3, 0, 0, 123801, 4, 6688);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒さも野生のうちだ\\n…とはいえ\\n温まっていくか♪', 1, 1, 3, 0, 0, 123801, 5, 6689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('悪くはないが物足りん\\nこう見えて肉食なのだ\\n肉はないのか肉は☆', 1, 1, 3, 0, 0, 123801, 7, 6691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウサギ族は地獄耳？\\nワタシとの共通点だな', 1, 1, 3, 0, 0, 123801, 8, 6692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここが私の家…\\nそれはこれからも\\nずっと変わらないわ…', 12, 1, 1, 0, 0, 106401, 103, 6694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ええと、その…今から\\nデート…じゃなくって\\n散歩でもどうかしら？\\n…ふ、二人きりで…', 12, 1, 2, 0, 0, 106401, 103, 6695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドハウスに\\nヒーロー参上！\\nみんな仲良くッスよ！', 1, 1, 1, 0, 0, 123901, 1, 6696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理もできて\\n鎧も作れる！\\nお母さんはすごいッス', 1, 1, 1, 0, 0, 123901, 2, 6697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ううう…\\nまたマントをドアに\\n挟んじゃったッス…', 1, 1, 1, 0, 0, 123901, 3, 6698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずっと鎧を着ていれば\\nジュンさんに近づける\\nかも？\u3000燃えるッス！', 1, 1, 1, 0, 0, 123901, 4, 6699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サインの練習…\\nもっとしておいた\\nほうがいいッスかね～', 1, 1, 1, 0, 0, 123901, 5, 6700);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('半人前でも\\n胸を張るッス！\\nそのうち似合う日が\\nくるッスから！', 4, 1, 1, 0, 0, 123901, 101, 6701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('種族の違いも\\n強い魂があれば\\n超えられるッス！\\n信じてるッスよ！', 8, 1, 1, 0, 0, 123901, 102, 6702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('困ったときは\\n自分を呼ぶッス！\\nあと楽しいときにも\\n呼んでほしいッス！', 1, 1, 2, 0, 0, 123901, 1, 6703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特訓でも行くッスか？\\n望むところッス！\\n目指せ、一人前！', 1, 1, 2, 0, 0, 123901, 2, 6704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいショーの台本を\\n読みこんでるッス！\\nところで…この言葉の\\n意味、分かるッスか？', 1, 1, 2, 0, 0, 123901, 3, 6705);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒミツがなくなると\\nなんか恥ずかしいッス\\nあんたはどうッスか？', 1, 1, 2, 0, 0, 123901, 4, 6706);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローは遅れて\\nやってくる…\\nあんたもそうッスね♪', 4, 1, 2, 0, 0, 123901, 101, 6707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰よりも早く\\nあんたに見せたいッス\\n一人前になった自分！', 8, 1, 2, 0, 0, 123901, 102, 6708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、今日も\\nよく眠れたッス～！\\n絶好調、間違いなし！', 1, 1, 2, 0, 1, 123901, 1, 6709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おお、もうお昼ッスか\\nどうりでお腹が空くと\\n思ったッス～えへへ', 1, 1, 2, 0, 2, 123901, 2, 6710);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パトロールのあとは\\n歯みがきに宿題に…\\n大忙しッスね、夜！', 1, 1, 2, 0, 3, 123901, 3, 6711);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにリラックス\\nできるなんて…\\n平和な証拠ッスね～', 1, 1, 3, 0, 0, 123901, 2, 6713);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('か、かわいい…♪\\nさあ、自分と握手…\\nううん、抱っこッス♪', 1, 1, 3, 0, 0, 123901, 3, 6714);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('優しい匂いッスね…♪\\nこれくらいみんなを\\n包み込めるように\\nなりたいッス～', 1, 1, 3, 0, 0, 123901, 4, 6715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひっくちゅ！\u3000うー…\\nちょっと冷えるッスね\\nぬくぬくするッス～♪', 1, 1, 3, 0, 0, 123901, 5, 6716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特訓した分、\\nいっぱい食べるッス！\\nでっかくなるッス！', 1, 1, 3, 0, 0, 123901, 7, 6718);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか自分の\\nヒミツ図鑑が出たり\\nして…いやいやいや', 1, 1, 3, 0, 0, 123901, 8, 6719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('牢獄よりは\\nマシな環境ね\\n我慢してあげるわ', 1, 1, 1, 0, 0, 106901, 1, 6721);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('退屈ね…\\nキャルでもいじって\\n暇をつぶそうかしら', 1, 1, 1, 0, 0, 106901, 2, 6722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいる連中\\n私を天気予報士と\\n勘違いしてない？', 1, 1, 1, 0, 0, 106901, 3, 6723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('音波情報が多いわね…\\nここ、もう少し静かに\\nならないの…？', 1, 1, 1, 0, 0, 106901, 4, 6724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('共同生活なんて\\n久しぶりだわ\\n…懐かしいわね', 1, 1, 1, 0, 0, 106901, 5, 6725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの子たちのギルド\\n経営が雑すぎるわ…！\\n教育が必要みたいね', 4, 1, 1, 0, 0, 106901, 101, 6726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とどめを刺される\\n準備はできているのに\\nまだなのかしら…？', 8, 1, 1, 0, 0, 106901, 102, 6727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私と戦う気になった？\\nあら、まだなのね…\\nその時を待ってるわよ', 1, 1, 2, 0, 0, 106901, 1, 6728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私というリソースは\\n有効活用しなさい\\n子守なんてごめんだわ', 1, 1, 2, 0, 0, 106901, 2, 6729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どうしてそんなに\\n頭がいいか？\\n生まれつきよ', 1, 1, 2, 0, 0, 106901, 3, 6730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('視力は権能に\\n影響しないわよ\\n当たり前じゃない', 1, 1, 2, 0, 0, 106901, 4, 6731);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたまで天気を\\n教えろですって…？\\nぶっ殺すわよ？', 4, 1, 2, 0, 0, 106901, 101, 6732);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇なら付き合いなさい\\n好きなゲームでいいわ\\nどうせ私が勝つもの', 8, 1, 2, 0, 0, 106901, 102, 6733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人生朝露…\\n悔いのない一日を\\n過ごしなさい', 1, 1, 2, 0, 1, 106901, 1, 6734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午睡はいいわよ…\\nふわぁ…眠りは思考に\\n必要不可欠なの…', 1, 1, 2, 0, 2, 106901, 2, 6735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夙興夜寝なんて\\nやめておきなさい\\n休息は大切よ', 1, 1, 2, 0, 3, 106901, 3, 6736);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私を満足させるなんて\\n大したものね…晶に\\n大量生産させるわ', 1, 1, 3, 0, 0, 106901, 2, 6738);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キャルの代わりに\\nズタズタにする物が\\n欲しかったの…♪', 1, 1, 3, 0, 0, 106901, 3, 6739);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りじゃない\\n見たことのない調合ね\\n誰が用意したの？', 1, 1, 3, 0, 0, 106901, 4, 6740);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パワーが足りないわね\\nもっとよ、もっと私を\\n寛がせなさい', 1, 1, 3, 0, 0, 106901, 5, 6741);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('栄養価はともかく\\n味のバランスは\\n悪くないわね', 1, 1, 3, 0, 0, 106901, 7, 6743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つまらない本は\\n私が書き直すわ\\nこれはどうかしら？', 1, 1, 3, 0, 0, 106901, 8, 6744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年はアカリと\\nお姉ちゃんでサンタが\\n二人…つまり幸せも\\n二倍ですね♪', 1, 1, 1, 0, 0, 124001, 1, 6746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスに向けての\\nサックス練習…\\nお兄ちゃんと一緒に\\n猛特訓です！', 1, 1, 1, 0, 0, 124001, 2, 6747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスツリーの\\n飾りつけ、完璧です♪\\nお兄ちゃんお姉ちゃん\\n喜んでくれるかな？', 1, 1, 1, 0, 0, 124001, 3, 6748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、お外が真っ白！\\n生クリームが\\nいーっぱいの\\nケーキみたいです♪', 1, 1, 1, 0, 0, 124001, 4, 6749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('煙突から入ると\\nお洋服が汚れちゃう…\\n玄関からじゃ\\nダメなのかなぁ？', 1, 1, 1, 0, 0, 124001, 5, 6750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんが来たら\\nサンタのお洋服\\nいっぱい褒めて\\nもらおっと♪', 4, 1, 1, 0, 0, 124001, 101, 6751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聖夜をお兄ちゃんと\\n過ごせたら…\\nアカリもちょっぴり\\n大人になれるかも♪', 8, 1, 1, 0, 0, 124001, 102, 6752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今のアカリは\\nサンタさんですから♪\\nなんでもお願いして\\nくださいね？', 1, 1, 2, 0, 0, 124001, 1, 6753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お外は寒いですから\\nアカリとくっついて\\nお出かけしましょ♪', 1, 1, 2, 0, 0, 124001, 2, 6754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんは\\nアカリのトナカイさん\\nですから、ずーっと\\nそばにいてください♪', 1, 1, 2, 0, 0, 124001, 3, 6755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃん、助けて！\\nアカリのカラダで\\nラッピング練習したら\\n絡まっちゃいました…', 1, 1, 2, 0, 0, 124001, 4, 6756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼント、いっぱい\\n準備できました♪\\nお兄ちゃんの分は…\\nまだヒミツでーす♪', 4, 1, 2, 0, 0, 124001, 101, 6757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリ、プレゼントは\\n大人っぽいのがいいな\\n早くお兄ちゃんに\\n追いつきたいから♪', 8, 1, 2, 0, 0, 124001, 102, 6758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\nふふ、アカリサンタは\\nいい子のお手本なので\\n早寝早起きなんです♪', 1, 1, 2, 0, 1, 124001, 1, 6759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あれ、もうお昼？\\nクリスマスナンバーの\\n練習してたら\\nもうこんな時間…', 1, 1, 2, 0, 2, 124001, 2, 6760);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冬の夜空は星が\\nキレイですね～\\nお兄ちゃん、一緒に\\n見に行きませんか？', 1, 1, 2, 0, 3, 124001, 3, 6761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、快適すぎて\\nとろけちゃいそう…\\nこういうプレゼントも\\nいいかもです…', 1, 1, 3, 0, 0, 124001, 2, 6763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やん、かわいいです♪\\nえへへ、お兄ちゃんは\\nどんなプレゼントが\\n欲しいですか～？', 1, 1, 3, 0, 0, 124001, 3, 6764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わわ、大人な香り…\\nロマンチックな\\nクリスマスが\\n過ごせそうです♪', 1, 1, 3, 0, 0, 124001, 4, 6765);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これでカラダを温めて\\nアカリの温もり…\\nお兄ちゃんに\\nおすそ分けしよっと♪', 1, 1, 3, 0, 0, 124001, 5, 6766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹がパンパンです…\\nでもこれで\\nちょっとサンタさんに\\n近づけたかも…？', 1, 1, 3, 0, 0, 124001, 7, 6768);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスイブの\\n恋人との過ごし方…？\\nはわわ、アカリには\\nまだ早いかもです…！', 1, 1, 3, 0, 0, 124001, 8, 6769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ、すごいすごい！\\n不思議な絵本ですね♪\\nこの本でお兄ちゃんに\\nイタズラしちゃお♪', 1, 1, 3, 0, 0, 124001, 14, 6771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アカリ、ホカホカに\\nなっちゃいました～♪\\n…ぎゅってしても\\nいいですよ？', 1, 1, 3, 0, 0, 124001, 15, 6772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またエンジェルになる\\nかもとは思ってたけど\\n…サンタさん要素の\\n追加は想定外だったわ', 1, 1, 1, 0, 0, 124101, 1, 6773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラフィたちがいない\\nときは私がなんとか\\nしないとね\\n一応…エンジェルだし', 1, 1, 1, 0, 0, 124101, 2, 6774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の飾りつけとか\\nするのも…あり？\\nふふ、浮かれすぎかな', 1, 1, 1, 0, 0, 124101, 3, 6775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パーティーだったら\\nみんなで大人数向けの\\nボードゲームもできる\\nかも…やったっ', 1, 1, 1, 0, 0, 124101, 4, 6776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服のモコモコ…\\n気づいたら触っちゃう\\n…やるわね、ラフィ', 1, 1, 1, 0, 0, 124101, 5, 6777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツと一緒にいると\\n人見知りとは違う\\n緊張があるのよね…\\nって今の聞いてたっ？', 4, 1, 1, 0, 0, 124101, 101, 6778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬいぐるみ…\\nいじめてないわよね？\\n…大事にしてるって？\\nそれはそれで…あうぅ', 8, 1, 1, 0, 0, 124101, 102, 6779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい子と悪い子って\\nどう見分けるのかしら\\n…まさか素直さとか？\\nだったら困る！', 1, 1, 2, 0, 0, 124101, 1, 6780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントといえば\\nやっぱりゲーム！\\n年末商戦サイコー♪', 1, 1, 2, 0, 0, 124101, 2, 6781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サンタさんはお仕事を\\n見られちゃ\\nいけないのよね？\\n…天職？', 1, 1, 2, 0, 0, 124101, 3, 6782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服は汚れ対策も\\nバッチリなのよね\\n煙突に入れるように\\n…いや私はNGよ！？', 1, 1, 2, 0, 0, 124101, 4, 6783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンタのお願い…\\n今なら一つくらい\\n聞いてあげるわよ？\\nほら、サンタ衣装だし', 4, 1, 2, 0, 0, 124101, 101, 6784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちって\\nなぜかぬいぐるみと\\n縁があるわよね\\n…ふふ', 8, 1, 2, 0, 0, 124101, 102, 6785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、おはよっ\\n…ふぅ、寝ぐせを\\n直すのが間に合って\\nよかったぁ', 1, 1, 2, 0, 1, 124101, 1, 6786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('え…一緒にごはん？\\nそ、そう…うん。OK\\nまあ、せっかくだし？', 1, 1, 2, 0, 2, 124101, 2, 6787);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この時間のゲームって\\n妙に楽しいのよね\\n…ということで、\\nちょっと遊ばない？', 1, 1, 2, 0, 3, 124101, 3, 6788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ～ダメになるぅ…\\nもうここでずっと\\nゲームしてた～い', 1, 1, 3, 0, 0, 124101, 2, 6790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントのために\\n研究は必要よね、うん\\n…はぁ、かわいい～♪', 1, 1, 3, 0, 0, 124101, 3, 6791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('集中力を高める香りも\\nあるのよね…\\n勝負をするときには\\n持ち歩こうかしら', 1, 1, 3, 0, 0, 124101, 4, 6792);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだかまったり\\nしちゃうわね…\\n時間が溶けるわ…', 1, 1, 3, 0, 0, 124101, 5, 6793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹いっぱい\\n食べられるのも\\n幸せなことよね', 1, 1, 3, 0, 0, 124101, 7, 6795);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちっちゃいときは\\nアカリと一緒に絵本を\\n読んだなぁ…懐かしい', 1, 1, 3, 0, 0, 124101, 8, 6796);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('飛び出す絵本…\\nこれでゲームブックを\\n作ったらおもしろく\\nなる気がするわ…', 1, 1, 3, 0, 0, 124101, 14, 6798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったまる…\\nモフモフ…ふわふわ…\\nちょっと休憩しても…\\nいいよね…？', 1, 1, 3, 0, 0, 124101, 15, 6799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、どうしたの？\\nもしかして、私と\\n新しい実験を\\n始めたくなった？', 12, 1, 1, 0, 0, 105101, 103, 6800);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('調子が悪いときは\\n診療所に来て\\n君は特別に、じっくり\\n診察してあげるわ♪', 12, 1, 2, 0, 0, 105101, 103, 6801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特別じゃなくても\\nまったり過ごす\\nクリスマスも\\nいいものだね', 1, 1, 1, 0, 0, 124201, 1, 6802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニットの帽子に\\nマフラーに耳当て…\\n素顔用の防寒対策を\\n整えなければ', 1, 1, 1, 0, 0, 124201, 2, 6803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('靴下が\\n見当たらなかったから\\n枕元にはかわりに\\n鎧を置いておこう', 1, 1, 1, 0, 0, 124201, 3, 6804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聖女なんて言われる程\\n素晴らしくはないけど\\n心は聖くいたいものだ\\n日々精進だね', 1, 1, 1, 0, 0, 124201, 4, 6805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兜がないから\\nイルミネーションが\\nいつもよりまぶしく\\n感じるよ', 1, 1, 1, 0, 0, 124201, 5, 6806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('皆の幸福を\\n祈願して\\nクリスマスリースを\\n飾ろうか', 4, 1, 1, 0, 0, 124201, 101, 6807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私にはかわいすぎる\\n衣装だが…開き直って\\nクリスマス気分を\\n楽しんでしまおう', 8, 1, 1, 0, 0, 124201, 102, 6808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ツリーの飾りつけ\\n手伝ってくれるかい？\\nセンスは少年に\\nお任せするよ', 1, 1, 2, 0, 0, 124201, 1, 6809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パーティーは\\n用意してる時も楽しい\\nねえ少年、この気持ち\\n分かってくれるかい？', 1, 1, 2, 0, 0, 124201, 2, 6810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんでトナカイの鼻は\\n赤いのかって？\\n無灯ソリ運転は違反で\\n取り締まられるからだ', 1, 1, 2, 0, 0, 124201, 3, 6811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トモちゃんや\\nマツリちゃんは\\nいい子だから、きっと\\nサンタさんに会えるね', 1, 1, 2, 0, 0, 124201, 4, 6812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒイラギの髪飾り\\n実は気にいってるんだ\\n少年にも\\n褒めてもらいたいな', 4, 1, 2, 0, 0, 124201, 101, 6813);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ねえ少年…そろそろ\\n見慣れてほしい\\nそんなにまじまじ\\n見つめられると照れる', 8, 1, 2, 0, 0, 124201, 102, 6814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝日に照らされて\\n街がキラキラ白銀に\\n輝いてるよ', 1, 1, 2, 0, 1, 124201, 1, 6815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯を食べて\\nちょっと散歩しようか\\n祝祭に沸く街は\\nとてもきれいだよ', 1, 1, 2, 0, 2, 124201, 2, 6816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱりクリスマスは\\n夜が本番って感じだね\\nキャンドルを灯して\\n厳かに過ごそうか', 1, 1, 2, 0, 3, 124201, 3, 6817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('鎧姿では無縁だったが\\nふかふかしていて\\n気持ちいいな…\\nふかふか…ふかふか…', 1, 1, 3, 0, 0, 124201, 2, 6819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、かわいいね\\n抱きしめると\\nあの雪の日に産まれた\\n赤ちゃんを思い出す', 1, 1, 3, 0, 0, 124201, 3, 6820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兜を脱いだおかげで\\nこの香りに出会えた\\n…クリスマスの魔法も\\n悪くないかもね', 1, 1, 3, 0, 0, 124201, 4, 6821);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('指先から体の芯まで\\n暖まるね\\nこれなら雪の日でも\\n安心だよ', 1, 1, 3, 0, 0, 124201, 5, 6822);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐ、もぐ…\\nあまり食べるところ\\n見ないでほしい', 1, 1, 3, 0, 0, 124201, 7, 6824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵なレストランの\\n特集記事が載ってる\\n聖夜に予約が取れたら\\n最高に幸せだろうね', 1, 1, 3, 0, 0, 124201, 8, 6825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ！\\n…………いや\\n驚いてなどいない', 1, 1, 3, 0, 0, 124201, 14, 6827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…頬に直接\\nふかふかを感じられる\\n温かくて気持ちいいよ', 1, 1, 3, 0, 0, 124201, 15, 6828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ピアノに読書…\\nグレアと一緒に\\nなにをしようかな～♪', 1, 1, 1, 0, 0, 124301, 1, 6829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元の世界へ戻った時\\n授業に遅れないよう\\nグレアと勉強しとこう', 1, 1, 1, 0, 0, 124301, 2, 6830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('街に魔物料理屋さんが\\nあるんだ！\u3000グレアと\\n食べに行ってみよう♪', 1, 1, 1, 0, 0, 124301, 3, 6831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかく新しい魔法を\\n覚えたし、グレアにも\\n見てもらいたいな！', 1, 1, 1, 0, 0, 124301, 4, 6832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('グレアも誘って\\nランドソルをもっと\\n探索したい！', 1, 1, 1, 0, 0, 124301, 5, 6833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちも\\nあの人を見習って\\nバイトとかしよう！', 4, 1, 1, 0, 0, 124301, 101, 6834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかあの人を\\n私たちの学院に\\n招待したいな！', 8, 1, 1, 0, 0, 124301, 102, 6835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのね！\\nこれからグレアと\\n魔法愛好会に\\n行くんだ！', 1, 1, 2, 0, 0, 124301, 1, 6836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからなにするの？\\n私たちもついて行って\\nいいかな！？', 1, 1, 2, 0, 0, 124301, 2, 6837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('グレアと一緒に\\nあなたも魔法の練習\\nしてみない？', 1, 1, 2, 0, 0, 124301, 3, 6838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('グレアとよく話すの\\nマナリアの制服\\nあなたに着せたいって', 1, 1, 2, 0, 0, 124301, 4, 6839);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('グレアのそばって\\n温かいんだ～！\\nぬくぬくだよ～♪', 4, 1, 2, 0, 0, 124301, 101, 6840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたは\\nグレアと私の友達！\\nこれからもずっと！', 8, 1, 2, 0, 0, 124301, 102, 6841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\\n今朝はグレアと一緒に\\n外を散歩してきたよ！', 1, 1, 2, 0, 1, 124301, 1, 6842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹空いたな…\\nよし、グレアと一緒に\\n魔物料理を作ろう！', 1, 1, 2, 0, 2, 124301, 2, 6843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間だね\\n明日のために\\nそろそろ寝ようかな！', 1, 1, 2, 0, 3, 124301, 3, 6844);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ～この感触…\\nグレアの尻尾みたいで\\n安らぐ～', 1, 1, 3, 0, 0, 124301, 2, 6846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぬいぐるみって\\nいいよね…私もよく\\nグレアに抱き付くんだ', 1, 1, 3, 0, 0, 124301, 3, 6847);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～…\\nグレアもこういうの\\n好きなんだよ！', 1, 1, 3, 0, 0, 124301, 4, 6848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいね～…\\nグレアにくっついてる\\n時を思い出すよ～…', 1, 1, 3, 0, 0, 124301, 5, 6849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この世界にしかない\\nおいしいものが\\nたくさんあるよね！', 1, 1, 3, 0, 0, 124301, 7, 6851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界を繋ぐ魔法の\\nヒント…本に書いて\\nないかなぁ…', 1, 1, 3, 0, 0, 124301, 8, 6852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ピアノに読書…\\n今日のアンは\\nなにをするのかな…', 1, 1, 1, 0, 0, 124401, 1, 6855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私はアンほど\\n勉強はできないから\\nちゃんと自習しないと', 1, 1, 1, 0, 0, 124401, 2, 6856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一度始めたら\\nとことん追求するのが\\nアンなんだよね…', 1, 1, 1, 0, 0, 124401, 3, 6857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…夢中になってる\\nアンを眺めてるだけで\\n一日があっという間…', 1, 1, 1, 0, 0, 124401, 4, 6858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランドソルは広いね…\\nアンと一緒にいろんな\\n場所へ行ってみたい', 1, 1, 1, 0, 0, 124401, 5, 6859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンやあの人の笑顔を\\n見てると、すごく\\n安心するんだ…', 4, 1, 1, 0, 0, 124401, 101, 6860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしあの人が私たちの\\n学院に編入したら…\\nふふ、楽しそうだね', 8, 1, 1, 0, 0, 124401, 102, 6861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンもあなたも\\nすごいな…\\nみんなとすぐに\\n仲良くなっちゃうから', 1, 1, 2, 0, 0, 124401, 1, 6862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたはこれから\\nなにをするの？\\nその…アンと一緒に\\nついていってもいい？', 1, 1, 2, 0, 0, 124401, 2, 6863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンから魔法の練習に\\n誘われた？\u3000実は私も\\n…一緒にどうかな？', 1, 1, 2, 0, 0, 124401, 3, 6864);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたがマナリアに\\n編入したら\\n楽しいのになって\\nアンとよく話すんだ…', 1, 1, 2, 0, 0, 124401, 4, 6865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こっちの世界にも\\nアンのように\\n私を受け入れてくれる\\n人たちがいるんだね…', 4, 1, 2, 0, 0, 124401, 101, 6866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元の世界へ帰る日が\\n来たとしても私たちは\\n「さよなら」より\\n「またね」がいいよね', 8, 1, 2, 0, 0, 124401, 102, 6867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう。さっき\\nランドソルの朝日を\\nアンと見てきたんだ', 1, 1, 2, 0, 1, 124401, 1, 6868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私たちは\\nこれからなんだけど\\nあなたはお昼ごはん\\n何を食べたの？', 1, 1, 2, 0, 2, 124401, 2, 6869);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ\\nアンが眠る時間だ…\\nあなたもおやすみ', 1, 1, 2, 0, 3, 124401, 3, 6870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ、疲れが取れる…\\nこの尻尾…\\nちょっと重いんだよね', 1, 1, 3, 0, 0, 124401, 2, 6872);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これ…\\nアンに見せたら\\n喜ぶだろうな…', 1, 1, 3, 0, 0, 124401, 3, 6873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り…\\nアンの感想も\\n聞いてみたいな', 1, 1, 3, 0, 0, 124401, 4, 6874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかい…\\nアンがここにいたら\\n本を読みながら\\n寝ちゃうんだろうな', 1, 1, 3, 0, 0, 124401, 5, 6875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おいしいからたくさん\\n食べれちゃうけど\\nまた尻尾…\\n大きくなっちゃうかな', 1, 1, 3, 0, 0, 124401, 7, 6877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アンがおススメ\\nしてくれた本は\\nこれかな…？', 1, 1, 3, 0, 0, 124401, 8, 6878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('凶、凶、凶…大凶？\\nなによこのおみくじ\\n自宅用だからって\\n排出率が適当すぎよ…', 1, 1, 1, 0, 0, 124701, 1, 6881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年こそ最高の新薬が\\nもはや偶然に近い\\n最小限の手間で\\n作れますように', 1, 1, 1, 0, 0, 124701, 2, 6882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('喉に詰まる前に\\n溶けてなくなるお餅…\\n最優先の研究課題だわ', 1, 1, 1, 0, 0, 124701, 3, 6883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よし、完成♪\\nミツキ特製…\\n「新解釈おせち料理」\\n医学的根拠が満載よ', 1, 1, 1, 0, 0, 124701, 4, 6884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お年玉を彼に…\\nあげるべき…？\\n色んな意味で微妙ね…', 1, 1, 1, 0, 0, 124701, 5, 6885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、今年もまた一年\\n彼のバイタルを\\n記録できるのね♪', 4, 1, 1, 0, 0, 124701, 101, 6886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年こそ\\n私の薬で彼を魔改造…\\nううん、大人の男に！', 8, 1, 1, 0, 0, 124701, 102, 6887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コマ回しのコマを\\n見てたら目が回った？\\nそう…手当は不要よ…', 1, 1, 2, 0, 0, 124701, 1, 6888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の顔で\\n福笑いを作った？\\nあら…隻眼まで\\n再現度が高いわね♪', 1, 1, 2, 0, 0, 124701, 2, 6889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('門松よし、しめ縄よし\\nこんなギルドでもね\\n一応縁起を担ぐのよ', 1, 1, 2, 0, 0, 124701, 3, 6890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本気の薬草を煮込んだ\\n本気の七草粥よ\\n色は気にしちゃダメ', 1, 1, 2, 0, 0, 124701, 4, 6891);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君が今年も健康で\\nつつがなく…実験台を\\n務められますように', 4, 1, 2, 0, 0, 124701, 101, 6892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いくつ新年を迎えても\\n俗世の垢にまみれない\\nそんな君こそが…\\n私には最高のお薬よ', 8, 1, 2, 0, 0, 124701, 102, 6893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月なんだから\\nいつまでも寝てないで\\nさぁ、実験開始よ♪', 1, 1, 2, 0, 1, 124701, 1, 6894);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カルタも双六もしたし\\nあとは実験くらいしか\\nやることがないわね', 1, 1, 2, 0, 2, 124701, 2, 6895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日頃からたいがい\\n意味深な夢を見るけど\\n初夢はまた別かしら…', 1, 1, 2, 0, 3, 124701, 3, 6896);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さすがにこの格好で\\n寝正月を敢行するのは\\nためらわれるわね', 1, 1, 3, 0, 0, 124701, 2, 6898);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('や、闇医者たる者\\nこんな愛くるしい物に\\n心奪われるわけには…', 1, 1, 3, 0, 0, 124701, 3, 6899);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お雑煮のいい香り…\\n食欲が増進されるわ\\nアロマも立派なお薬ね', 1, 1, 3, 0, 0, 124701, 4, 6900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('胸元は閉じないわよ？\\nでも時々ここで\\nこっそり暖まるの…', 1, 1, 3, 0, 0, 124701, 5, 6901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('無から有が生まれてる\\n新年早々物理の法則を\\n無視してくるのね…', 1, 1, 3, 0, 0, 124701, 7, 6903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どれもこれも読んだわ\\n新しい婚活本の\\n入荷はまだかしら…', 1, 1, 3, 0, 0, 124701, 8, 6904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼が一生懸命\\n書いてくれた年賀状\\n気持ちがこもっていて\\nすごくうれしいわ♪', 1, 1, 1, 0, 0, 124601, 1, 6906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかり丁寧に\\n大掃除したから\\nとってもいい気持ちで\\n新年を迎えられたわ♪', 1, 1, 1, 0, 0, 124601, 2, 6907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼の着物姿\\nきっと凛々しいわよね\\n想像しただけで\\n笑顔になるわ～♪', 1, 1, 1, 0, 0, 124601, 3, 6908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お雑煮は地域によって\\n違いがあるけれど\\n愛情が隠し味なのは\\nどこも一緒よね♪', 1, 1, 1, 0, 0, 124601, 4, 6909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼と凧揚げして\\n遊びたいけど\\n森では引っかかって\\nできないかしら…？', 1, 1, 1, 0, 0, 124601, 5, 6910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年も彼が素直に\\n成長できるように\\nたくさんいい子いい子\\nしてあげましょう…♪', 4, 1, 1, 0, 0, 124601, 101, 6911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵馬に彼と\\n書いた通り\\n今年もみんなが笑って\\n過ごせますように', 8, 1, 1, 0, 0, 124601, 102, 6912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('先生と初詣に\\n行きましょう〜♪\\n迷子にならないように\\n手を繋いで、ね？', 1, 1, 2, 0, 0, 124601, 1, 6913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('初売りセールいいわね\\nでも気を付けないと\\nあれこれ欲しくなって\\n買い過ぎちゃうかも…', 1, 1, 2, 0, 0, 124601, 2, 6914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風邪をひかないように\\n温かくするんですよ～\\nえ？\u3000先生、温めて？\\nふふ、甘えん坊さんね', 1, 1, 2, 0, 0, 124601, 3, 6915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたのために\\nちょっと豪華なおせち\\n用意したのよ\\nお口に合うかしら？', 1, 1, 2, 0, 0, 124601, 4, 6916);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたも着物着たい？\\nふふ、貫禄出ちゃって\\n先生ドキドキ\\nしちゃうかも…♪', 4, 1, 2, 0, 0, 124601, 101, 6917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたの成長は\\nとってもうれしいけど\\n今年もまだ、あなたの\\n先生でいたいな…♪', 8, 1, 2, 0, 0, 124601, 102, 6918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あら、起きたの？\\nお雑煮できてるから\\nちゃんとお顔\\n洗ってらっしゃいね', 1, 1, 2, 0, 1, 124601, 1, 6919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯を\\nしっかり食べて\\nみんなでかるた大会\\nしましょう〜♪', 1, 1, 2, 0, 2, 124601, 2, 6920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は～い、良い子は\\nもう寝る時間ですよ\\n素敵な初夢が\\n見られますように♪', 1, 1, 2, 0, 3, 124601, 3, 6921);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このフカフカちゃんも\\n天日干ししたいけど…\\nその前にちょっと\\n休憩しちゃおうかしら', 1, 1, 3, 0, 0, 124601, 2, 6923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ、かわいい～\\nアオイちゃんや\\nハツネちゃんも\\nきっと気に入るわね♪', 1, 1, 3, 0, 0, 124601, 3, 6924);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月は空気も\\n透き通ってるから\\nいつも以上に\\n素敵な香りに感じるわ', 1, 1, 3, 0, 0, 124601, 4, 6925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火のぬくもりに\\n抱かれていると\\n不思議と眠気が…\\nふああ…', 1, 1, 3, 0, 0, 124601, 5, 6926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛情のこもった料理は\\nおいしいだけじゃなく\\n心も満たされちゃう♪', 1, 1, 3, 0, 0, 124601, 7, 6928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月のお作法も\\nたくさんあるのね～\\n先生も日々勉強だわ～', 1, 1, 3, 0, 0, 124601, 8, 6929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('少年への感謝をどんな\\n形で伝えるべきか…\\n言葉よりも物の方が\\n良いのだろうか？', 12, 1, 1, 0, 0, 104701, 103, 6931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('話し相手になって\\nもらってもいいかな？\\n少年と一緒にいると\\nとても楽しいんだ', 12, 1, 2, 0, 0, 104701, 103, 6932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月だからって\\nギャングのボスは\\n油断できないよ～？', 1, 1, 1, 0, 0, 124501, 1, 6933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イノリちゃんがお年玉\\n欲しいんだって♪\\n悪い子だったし\\n10ルピでいいかな☆', 1, 1, 1, 0, 0, 124501, 2, 6934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月だからお雑煮を\\n作ったんだけど\\nカヤちゃんには\\n大好評だったよ♪', 1, 1, 1, 0, 0, 124501, 3, 6935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ラーゴがお餅を\\n食べたがってるけど…\\nこの子にあげるのは\\nちょっと心配かな～？', 1, 1, 1, 0, 0, 124501, 4, 6936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月は晴れ着の子が\\nやっぱり多いよね～\\n今度、私の漫画でも\\n出してみようかな？', 1, 1, 1, 0, 0, 124501, 5, 6937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君と二人っきりで\\n神殿に初詣…\\n行ってみたいな～♪', 4, 1, 1, 0, 0, 124501, 101, 6938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君とお正月を\\n過ごしていると\\n面倒なことも\\n全部忘れられそう…', 8, 1, 1, 0, 0, 124501, 102, 6939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この着物、どう思う？\\n似合ってたら\\nうれしいけどな～♪', 1, 1, 2, 0, 0, 124501, 1, 6940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('袖を引っ張ったり\\nしないでね？\\n着崩れしちゃうから♪', 1, 1, 2, 0, 0, 124501, 2, 6941);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月ならではの\\n漫画ネタってある？\\n参考にしたいんだよね', 1, 1, 2, 0, 0, 124501, 3, 6942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昔は凧あげとか\\n駒回しとかしてたけど\\n大人になるとそういう\\n機会も減るよね…', 1, 1, 2, 0, 0, 124501, 4, 6943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('君にもお年玉を\\nあげようか？\\n好きな額を言ってね☆', 4, 1, 2, 0, 0, 124501, 101, 6944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年も、再来年も…\\nこうしてみんなで\\n新年がお祝いできると\\n素敵だね～♪', 8, 1, 2, 0, 0, 124501, 102, 6945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよ～♪\\n朝ごはんは\\n焼いたお餅とか\\nどうかな？', 1, 1, 2, 0, 1, 124501, 1, 6946);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼だね～\\nおせちを用意したから\\nみんなで食べよっか', 1, 1, 2, 0, 2, 124501, 2, 6947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間だね～\\n一日中着物だったから\\n肩が凝っちゃったよ', 1, 1, 2, 0, 3, 124501, 3, 6948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このまま寝たら\\nしわになるかな？\\n着替えた方がいい？', 1, 1, 3, 0, 0, 124501, 2, 6950);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういうのって\\nラーゴのおもちゃに\\nちょうどいいかも♪', 1, 1, 3, 0, 0, 124501, 3, 6951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだけど\\n着物に移らないように\\n気をつけないとね', 1, 1, 3, 0, 0, 124501, 4, 6952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょうどいい\\n火加減だね♪\\nぽかぽかするよ～♪', 1, 1, 3, 0, 0, 124501, 5, 6953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物の時は\\nほどほどにしないと…\\n欲張ったら、お腹が\\n苦しくなるからね～', 1, 1, 3, 0, 0, 124501, 7, 6955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふーん\\nイノリちゃんは最近\\nこんな漫画を\\n読んでるんだ～♪', 1, 1, 3, 0, 0, 124501, 8, 6956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('楽園の気配は…ナシ！\\nみんな前を向いてるね\\nそうこなくっちゃ！', 1, 1, 1, 0, 0, 124801, 1, 6958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンの成果も\\nこの格好くらい\\n目に見えたら\\n分かりやすいのになぁ', 1, 1, 1, 0, 0, 124801, 2, 6959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の曲はワイルドで\\n悪い感じもいいなぁ…\\nカヤとムイミちゃん\\nみたいなイメージで！', 1, 1, 1, 0, 0, 124801, 3, 6960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私…服、着てるよね？\\nうんうん、着てる！\\nあんまり体が軽いと\\n急に焦る瞬間あるな～', 1, 1, 1, 0, 0, 124801, 4, 6961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近ファンの年齢層が\\n幅広くなってきたかも\\nこれって私…国民的\\nアイドルに近づいた？', 1, 1, 1, 0, 0, 124801, 5, 6962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パティスリーとコラボ\\nしたらどんな感じかな\\n…ノゾミンマカロン♪\\nとか？\u3000…いけるかも', 4, 1, 1, 0, 0, 124801, 101, 6963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼と一緒にいると…\\nうれしくって苦しいな\\nでも両方諦められない\\n…アイドルらしいや', 8, 1, 1, 0, 0, 124801, 102, 6964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好、チカと\\nツムギも似合うと\\n思うんだけどな～\\nキミもそう思うよね？', 1, 1, 2, 0, 0, 124801, 1, 6965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('街を歩いてたらね？\\nライブとか写真集の\\n告知イベントだって\\n思われちゃった！', 1, 1, 2, 0, 0, 124801, 2, 6966);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私が持ってた剣に\\n結んであったリボン…\\n何か気づいてくれた？\\nヒントは…色だよ♪', 1, 1, 2, 0, 0, 124801, 3, 6967);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの気配ってすごく\\n分かりやすいんだよ\\n近くにいたらすぐに\\nピンとくるんだ♪', 1, 1, 2, 0, 0, 124801, 4, 6968);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、それ…はじめて\\nキミにあげた音響盤！\\nね、一緒に聴こうよ', 4, 1, 2, 0, 0, 124801, 101, 6969);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼうっとしてたら\\nイタズラしちゃうよ♪\\nもっともっと私のこと\\n見てないとダーメ！', 8, 1, 2, 0, 0, 124801, 102, 6970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は今日のはじまり！\\n昨日よりももっと\\nいい一日にしようね♪', 1, 1, 2, 0, 1, 124801, 1, 6971);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レッスンがんばったし\\nまだお昼だし…\\nランチ大盛りにしても\\nセーフだよね！', 1, 1, 2, 0, 2, 124801, 2, 6972);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寝る前に明日の予定を\\n確認しておかないと！\\nえっと、集合場所は…', 1, 1, 2, 0, 3, 124801, 3, 6973);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一休みのつもりが\\nなが～い休憩になるの\\nあるあるだよね～', 1, 1, 3, 0, 0, 124801, 2, 6975);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ノゾミンの熱烈ハグ♪\\n…ここだけ聞いたら\\nスクープになっちゃう\\nかも？\u3000なーんて！', 1, 1, 3, 0, 0, 124801, 3, 6976);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りってなんだか\\n記憶に残るよねー\\n…こういうの私だけ？\\nみんなも同じだよね？', 1, 1, 3, 0, 0, 124801, 4, 6977);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだかライブの\\n熱気を思い出して\\nきちゃった…！\\nレッスンしよっと！', 1, 1, 3, 0, 0, 124801, 5, 6978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹が減ってたら\\nいいパフォーマンスは\\nできないもんね！\\n…んー、おいし～♪', 1, 1, 3, 0, 0, 124801, 7, 6980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい歌詞を書くには\\nしっくりくる言葉を\\n知っておかないと！', 1, 1, 3, 0, 0, 124801, 8, 6981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うだうだ悩んでる\\nヤツがいたら\\nオレのとこ連れてこい\\n背中押してやるからさ', 1, 1, 1, 0, 0, 124901, 1, 6983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近どことなく\\nファミリーの連中が\\n浮き足立ってんだよな\\n…なんでだ？', 1, 1, 1, 0, 0, 124901, 2, 6984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イノリのヤツ\\nやたらと脇腹\\nつついてきやがって…\\nくすぐったいっての', 1, 1, 1, 0, 0, 124901, 3, 6985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身軽になったのは\\nいいが…くそっ\\nどこもかしこも\\nスースーする…', 1, 1, 1, 0, 0, 124901, 4, 6986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('思い出に浸るのも\\n悪くはないが\\nやっぱ人間\\n未来に生きないとな！', 1, 1, 1, 0, 0, 124901, 5, 6987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またムイミやノゾミと\\nツルむのもいいな\\nそこにカレもいたら\\nなおいいぜ', 4, 1, 1, 0, 0, 124901, 101, 6988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('未来のことを考えると\\nなぜかいつもカレが\\n頭に浮かんじまう…\\nええい、やめだやめ！', 8, 1, 1, 0, 0, 124901, 102, 6989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょっくらオレと\\n腕相撲しねえか？\\nこの新しい力\\n試させてくれ！', 1, 1, 2, 0, 0, 124901, 1, 6990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なあ、悪いが上着\\n貸してくれないか？\\nこのカッコ、割と\\n肌寒いんだよ…', 1, 1, 2, 0, 0, 124901, 2, 6991);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっ、生まれ変わった\\n喧嘩屋にご用命か？\\nいいぜ、キミの\\n依頼なら二つ返事だ！', 1, 1, 2, 0, 0, 124901, 3, 6992);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんか悩みごとが\\nあるなら、なんでも\\n話してくれよな\\nオレとキミの仲だろ？', 1, 1, 2, 0, 0, 124901, 4, 6993);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このカッコが\\nきれいだって？\\nや、やめろよ…\\n照れくさいだろ…', 4, 1, 2, 0, 0, 124901, 101, 6994);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミがいると、なにを\\nするにも退屈しないぜ\\nだから今日も\\n付き合ってくれよな！', 8, 1, 2, 0, 0, 124901, 102, 6995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう！\u3000新しい\\n未来がやってきたぜ！\\n一秒だって時間は\\n無駄にするなよ？', 1, 1, 2, 0, 1, 124901, 1, 6996);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ昼飯に\\nしないか？\\n穴場のうまい店に\\n案内してやるからさ', 1, 1, 2, 0, 2, 124901, 2, 6997);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かしは\\n未来の前借りだ\\n体壊さないように\\nほどほどにしとけよ？', 1, 1, 2, 0, 3, 124901, 3, 6998);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お、いいなこれ\\nファミリーの\\nアジトにも\\n置いときたいぜ', 1, 1, 3, 0, 0, 124901, 2, 7000);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('べ、別にかわいいもん\\nなんて、そんなに\\n好きじゃないし…\\n嫌いでもないけどさ', 1, 1, 3, 0, 0, 124901, 3, 7001);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('嗅いだことない\\n香りだな\\nなかなか気に入った！', 1, 1, 3, 0, 0, 124901, 4, 7002);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('薄着で暖を取るのって\\n最高にぜいたくだよな\\nへへっ、堪能させて\\nもらうとするか', 1, 1, 3, 0, 0, 124901, 5, 7003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こいつはいいや\\nこのカッコだと\\n消耗が激しくて\\nやたら腹が減るからな', 1, 1, 3, 0, 0, 124901, 7, 7005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('甘辛コーデ…\\nへぇ、そんなのが\\nあるのか…\\nわ、悪くねえかもな', 1, 1, 3, 0, 0, 124901, 8, 7006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…\\nもっともっと長い時間\\n先輩と過ごせたらなぁ', 12, 1, 1, 0, 0, 105501, 103, 7008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ…♪\\n先輩が、すぐそばに\\nいてくれるなんて…\\n幸せだなぁ…♪', 12, 1, 2, 0, 0, 105501, 103, 7009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はーっはっは！\\n強くてカッコいい\\n大悪党、ここに参上！', 1, 1, 1, 0, 0, 125001, 1, 7010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなおしゃれで\\nカッコいいけど\\n今のアタシも\\n負けてないぞ！', 1, 1, 1, 0, 0, 125001, 2, 7011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギャングのアジトも\\nよかったけど\\nここも賑やかで\\n悪くないな！', 1, 1, 1, 0, 0, 125001, 3, 7012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('悪党にも休息は必要だ\\nここならゆっくり\\n休めそうだ！\\n邪魔するぞ！', 1, 1, 1, 0, 0, 125001, 4, 7013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい人がいるな…\\nアタシの悪党っぷりを\\n広めるチャンスだ！', 1, 1, 1, 0, 0, 125001, 5, 7014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいれば\\nいい思い出がたくさん\\n作れそうだな！', 4, 1, 1, 0, 0, 125001, 101, 7015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつかアタシも\\nオクトーと一緒に\\nこんなアジトを手に\\n入れてやるからな！', 8, 1, 1, 0, 0, 125001, 102, 7016);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000アタシの格好が\\n気になるのか？\\nならもっと近くで\\n見てもいいぞ！', 1, 1, 2, 0, 0, 125001, 1, 7017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おい、暇だから\\nアタシと遊べ！\\nカヤとノゾミも呼んで\\n大騒ぎするぞ！', 1, 1, 2, 0, 0, 125001, 2, 7018);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエ、前より強く\\nなってないか！？\\nくっそー！\u3000アタシも\\n負けてらんないぞー！', 1, 1, 2, 0, 0, 125001, 3, 7019);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日は特別にアタシの\\n思い出話を聞かせて\\nやる！\u3000さーて、どの\\n悪事から話そうか…', 1, 1, 2, 0, 0, 125001, 4, 7020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエとの付き合いも\\n結構長くなったよな？\\nこれからも\\nよろしく頼むぞ！', 4, 1, 2, 0, 0, 125001, 101, 7021);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエまでいなく\\nなったらアタシが困る\\n勝手にどっか\\n行くんじゃないぞ！', 8, 1, 2, 0, 0, 125001, 102, 7022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('起きろ、起きろー！\\n大悪党の朝は早いんだ\\nさっさと\\n顔洗ってこい！', 1, 1, 2, 0, 1, 125001, 1, 7023);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯どうしようか…\\nそうだ！\u3000オマエの\\nおススメに連れてけ！\\nいい店期待してるぞ！', 1, 1, 2, 0, 2, 125001, 2, 7024);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日を思い切り\\n楽しむためにも\\n早く寝とけよ！\\nまた明日な！', 1, 1, 2, 0, 3, 125001, 3, 7025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうやって座ると…\\nおお！\u3000すっごく悪党\\nっぽいぞ！', 1, 1, 3, 0, 0, 125001, 2, 7027);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オマエ、仲間に\\nなりたそうな目を\\nしてるな！', 1, 1, 3, 0, 0, 125001, 3, 7028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うん、いい匂いだ！\\n何の匂いかは全然\\n分かんないけどな！', 1, 1, 3, 0, 0, 125001, 4, 7029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('炎ってなんだか\\nカッコいいよな！\\n見てるだけで心が\\n燃えてくるぞ！', 1, 1, 3, 0, 0, 125001, 5, 7030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい食べれば\\nちょっとは\\n背が伸びるかな…？', 1, 1, 3, 0, 0, 125001, 7, 7032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐぬぅ…たまには\\n本でもと思ったけど\\nやっぱりアタシは\\nバトル担当だな！', 1, 1, 3, 0, 0, 125001, 8, 7033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お邪魔しまーす★\\nなーんてもう\\nすっかりくつろいで\\nますけどー♪', 1, 1, 1, 0, 0, 118201, 1, 7035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんの\\nギルドハウス…★\\nなんだかドキドキ\\nしちゃいます♪', 1, 1, 1, 0, 0, 118201, 2, 7036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぺんぽこりんの\\n置き場所はー…\\nま、このへんで★', 1, 1, 1, 0, 0, 118201, 3, 7037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、これは\\n壊しがいがありそ…\\nウソウソ、冗談です★', 1, 1, 1, 0, 0, 118201, 4, 7038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オトモダチでも\\n作ってみますかー\\nくすっ★', 1, 1, 1, 0, 0, 118201, 5, 7039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('退屈ですねー\\n騎士さん、構って\\nくれないかなー', 4, 1, 1, 0, 0, 118201, 101, 7040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっともっと早く\\n騎士さんに逢えてたら\\n…なんて、わたし\\nらしくないですね', 8, 1, 1, 0, 0, 118201, 102, 7041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたし一人にするの\\n不安だったりします？\\nちゃーんとイイコに\\nしてますってー★', 1, 1, 2, 0, 0, 118201, 1, 7042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お出かけします？\\nそれともおうちで\\nまったりしますー？', 1, 1, 2, 0, 0, 118201, 2, 7043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('女の子をすぐ家に\\nあげちゃうなんて…\\nふふ、やっぱり隅に\\n置けないですねー★', 1, 1, 2, 0, 0, 118201, 3, 7044);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さん騎士さーん★\\nウザ絡みしても\\nいいですかー？\\n騎士さんってばー★', 1, 1, 2, 0, 0, 118201, 4, 7045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒にゴロゴロ\\nしませんかー？\\nコイビトっぽくて\\n楽しそうですし♪', 4, 1, 2, 0, 0, 118201, 101, 7046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ★\\nこーやってあなたに\\n優しくされると…\\nときめいちゃいます♪', 8, 1, 2, 0, 0, 118201, 102, 7047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます★\\nあれれー？\\nまだおねむですかー？', 1, 1, 2, 0, 1, 118201, 1, 7048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さん、お昼は\\nもう食べましたー？\\nわたし、ラーメンが\\n食べたいでーす★', 1, 1, 2, 0, 2, 118201, 2, 7049);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、夜更かししてちゃ\\nダメですよー？\\nほらほら、お布団に\\nごーごー★', 1, 1, 2, 0, 3, 118201, 3, 7050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかのふわふわー\\nついついまーったり\\nしちゃいます★', 1, 1, 3, 0, 0, 118201, 2, 7052);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かっわいー★\\n名前はー、んー…\\nぱんぱかぷんで★', 1, 1, 3, 0, 0, 118201, 3, 7053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん★\\nうーん…\\nたぶん素敵な香り♪', 1, 1, 3, 0, 0, 118201, 4, 7054);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかーい★\\n心も体も\\nぽっかぽかですねー★', 1, 1, 3, 0, 0, 118201, 5, 7055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ★\\nんー、おいしくって\\n止まらないですねー★', 1, 1, 3, 0, 0, 118201, 7, 7057);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へー★\\nほほー★\\nふんふーん★', 1, 1, 3, 0, 0, 118201, 8, 7058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ～て時間もあるし\\nラテアートの練習でも\\nするかにゃ～♪', 1, 1, 1, 0, 0, 125101, 1, 7060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カフェの猫たちも\\n元気に働いてくれて\\nお客さんからの評判も\\n上々にゃ～♪', 1, 1, 1, 0, 0, 125101, 2, 7061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カフェのカウンターに\\nファントムキャッツの\\n目安箱を置こうかにゃ', 1, 1, 1, 0, 0, 125101, 3, 7062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんこもコーヒーも\\n原料は豆にゃ～\\nそりゃ相性いいに\\n決まってるにゃ♪', 1, 1, 1, 0, 0, 125101, 4, 7063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつの為に\\nタマキ特製ブレンドを\\n開発したいにゃ♪', 1, 1, 1, 0, 0, 125101, 5, 7064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつと働いてると\\nなぜかあっという間に\\n閉店時間が\\n来ちゃうのにゃ～', 4, 1, 1, 0, 0, 125101, 101, 7065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつといると\\n新しいアイデアが\\n溢れるほど\\n出てきちゃうのにゃ♪', 8, 1, 1, 0, 0, 125101, 102, 7066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミがコーヒーを\\n淹れてくれたのにゃ？\\nにゃはは、常温で\\n猫舌にも優しいにゃ♪', 1, 1, 2, 0, 0, 125101, 1, 7067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('料理が上手くなったら\\nカフェご飯メニューも\\n充実させたいにゃ～', 1, 1, 2, 0, 0, 125101, 2, 7068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お店の経営は大変\\nだけど、キミとなら\\n乗り越えられるって\\n確信してるにゃ！', 1, 1, 2, 0, 0, 125101, 3, 7069);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000この制服\\n似合ってるにゃ？\\nにゃはは！\u3000褒めても\\n１ルピも出ないにゃ♪', 1, 1, 2, 0, 0, 125101, 4, 7070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしが好きなのは\\n猫に好かれる人にゃ♪\\n…ん、キミ猫に懐かれ\\nまくってるにゃ…', 4, 1, 2, 0, 0, 125101, 101, 7071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミの制服姿\\nけっこーイケてるにゃ\\nあたしがお客さんなら\\n通いつめちゃうにゃ♪', 8, 1, 2, 0, 0, 125101, 102, 7072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は一杯の\\nコーヒーから始まる…\\nにゃふふん♪\\nシャレた朝だにゃ～♪', 1, 1, 2, 0, 1, 125101, 1, 7073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はたい焼きと\\nコーヒーのセットで\\nまったり休憩\\nしようにゃ～♪', 1, 1, 2, 0, 2, 125101, 2, 7074);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コーヒー淹れたにゃ\\n星空を見ながら\\n二人で飲もうにゃ…♪', 1, 1, 2, 0, 3, 125101, 3, 7075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃ～ん…ゴロゴロ\\nコーヒーと同じくらい\\n癒されるにゃ～…♪', 1, 1, 3, 0, 0, 125101, 2, 7077);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こいつかわいいにゃ～\\nうちの猫たちとも\\nいい勝負なのにゃ！', 1, 1, 3, 0, 0, 125101, 3, 7078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～いい香りだにゃ～\\nコーヒーもそうだけど\\n香りの癒し効果は\\n抜群にゃ～♪', 1, 1, 3, 0, 0, 125101, 4, 7079);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫に暖かいものは\\nまるまれと言ってる\\nようなもんにゃ…♪\\nまるまる…', 1, 1, 3, 0, 0, 125101, 5, 7080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃは～うまいにゃ♪\\nカフェの新メニューに\\n採用しちゃおう\\nかにゃ～♪', 1, 1, 3, 0, 0, 125101, 7, 7082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('にゃるほど…\\n調べれば調べるほど\\nコーヒーは\\n奥が深いのにゃ…', 1, 1, 3, 0, 0, 125101, 8, 7083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ワタシの手料理は\\n坊やの口に合うらしい\\n胃袋は討ち取ったぞ♪', 12, 1, 1, 0, 0, 107101, 103, 7085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('胸に再度触れると\\n誓約は無効になるのか\\n…だと？\u3000鋭い質問だ\\n安心しろ。ならん☆', 12, 1, 2, 0, 0, 107101, 103, 7086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ようやくこの服にも\\n慣れてきたかな？\\nふふっ、たまには\\nこういう服も悪くない', 1, 1, 1, 0, 0, 125201, 1, 7087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も店は好調だが、\\n私は軍人だからな\\n当初の目的も\\n忘れないようにしよう', 1, 1, 1, 0, 0, 125201, 2, 7088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫が近くに来ると\\nついつい見てしまうな\\n仕事が終わったら\\n遊んでやるかな♪', 1, 1, 1, 0, 0, 125201, 3, 7089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コーヒーの淹れ方が\\nうまくなってきたな♪\\nどうせならお菓子も\\n研究してみるか！', 1, 1, 1, 0, 0, 125201, 4, 7090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('利益を考えると\\n価格をあげるべきか？\\n…いや、利益よりも\\n皆の笑顔の方が大事だ', 1, 1, 1, 0, 0, 125201, 5, 7091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またあいつを\\n呼んでしまったな…\\n今度、コーヒーでも\\n淹れて労ってやるか♪', 4, 1, 1, 0, 0, 125201, 101, 7092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次に入荷するお菓子は\\nあいつの意見を聞くか\\nどんな味が好きか\\n気になるしな', 8, 1, 1, 0, 0, 125201, 102, 7093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに、コーヒーを\\n淹れてほしい？\\nふふっ♪\\n仕方のない奴だな！', 1, 1, 2, 0, 0, 125201, 1, 7094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…そうだ。\\nコーヒーと乾パンは\\n合うのではないか？\\n今度試してみよう！', 1, 1, 2, 0, 0, 125201, 2, 7095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コーヒーもいいが、\\nココアも悪くないぞ♪\\n貴公も一緒にどうだ？', 1, 1, 2, 0, 0, 125201, 3, 7096);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女に比べれば\\n大人しい服だろう？\\nだが、カフェには\\nこの服でバッチリだ！', 1, 1, 2, 0, 0, 125201, 4, 7097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公はコーヒーを\\n飲めるのかっ？それは\\nうらやましいな…', 4, 1, 2, 0, 0, 125201, 101, 7098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴公の働きぶりには\\n目を見張るものがある\\nその姿は、その…\\n結構かっこいいぞっ！', 8, 1, 2, 0, 0, 125201, 102, 7099);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さぁ、今日も一日、\\n頑張るぞっ！\\n気合いを入れて\\n開店準備だっ！', 1, 1, 2, 0, 1, 125201, 1, 7100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼は稼ぎ時だからな！\\n荒波を乗り切るため\\n貴公も一緒に\\n頑張ってくれるか？', 1, 1, 2, 0, 2, 125201, 2, 7101);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふあぁ…もう夜か\\n今日は頑張ったからな\\nはやめに休むとしよう', 1, 1, 2, 0, 3, 125201, 3, 7102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はふぅ～…\\nたまにはこうして\\nゆったりするのも\\n悪くないな…', 1, 1, 3, 0, 0, 125201, 2, 7104);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('猫もかわいいが、\\nこいつもなかなか…\\n見ていると、\\n撫でたくなるな♪', 1, 1, 3, 0, 0, 125201, 3, 7105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは良い香りだな\\nふむ、コーヒーも\\nより香り高いものが\\n作れるよう試すか！', 1, 1, 3, 0, 0, 125201, 4, 7106);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ～…\\n体を温めなければ、\\nすぐに動けないからな', 1, 1, 3, 0, 0, 125201, 5, 7107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これもうまいが、\\n私はお菓子も…\\nいや、食べすぎは\\n体に良くないな', 1, 1, 3, 0, 0, 125201, 7, 7109);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…書物は参考になるな\\n次はこのやり方を\\n試してみるかな', 1, 1, 3, 0, 0, 125201, 8, 7110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛と希望の魔法少女！\\n弟くんの平和は\\nお姉ちゃんが守るよ♪', 1, 1, 1, 0, 0, 120001, 1, 7112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の戦い方を\\n見せてあげる！\\nお姉ちゃんチョップ♪', 1, 1, 1, 0, 0, 120001, 2, 7113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('闇の力が高まってる…\\n早く弟くんを\\nギュ～ってしないと！', 1, 1, 1, 0, 0, 120001, 3, 7114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミニ弟くんを\\n部屋中に呼び出して\\n弟くんハウスに～♪', 1, 1, 1, 0, 0, 120001, 4, 7115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('決めポーズの練習でも\\nしよっかな…\\nはい、ポーズ♪', 1, 1, 1, 0, 0, 120001, 5, 7116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の力で\\n弟くんのそばに\\n瞬間移動したいなぁ', 4, 1, 1, 0, 0, 120001, 101, 7117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('禁じられた必殺技\\nその名も──\\n闇のお姉ちゃん頭突き', 8, 1, 1, 0, 0, 120001, 102, 7118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女な\\nお姉ちゃんに\\n興味津々だねっ？\\n全部教えてあげるね♪', 1, 1, 2, 0, 0, 120001, 1, 7119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('闇のお姉ちゃんとして\\n世界を弟くんのものに\\n…な～んて冗談冗談♪', 1, 1, 2, 0, 0, 120001, 2, 7120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんって魔法少女に\\nなりたがってたよね？\\n…うん。応援するね！', 1, 1, 2, 0, 0, 120001, 3, 7121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サインが欲しいの？\\nふふっ、任せて！\\n愛する弟くんへ、と♪', 1, 1, 2, 0, 0, 120001, 4, 7122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふふ～ん♪\\n魔法少女お姉ちゃんの\\nテーマソング完成っ♪', 4, 1, 2, 0, 0, 120001, 101, 7123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ、弟くんからの\\n愛と希望を感じるよ…\\n更に変身しちゃうぞ♪', 8, 1, 2, 0, 0, 120001, 102, 7124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの朝を魔法で\\n守りに来たよ！\\n希望の朝だねっ♪', 1, 1, 2, 0, 1, 120001, 1, 7125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんのお昼を魔法で\\n守りに来たよ！\\n愛のお弁当をどうぞ♪', 1, 1, 2, 0, 2, 120001, 2, 7126);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの夜を魔法で\\n守りに来たよ！\\nここからは闇の時間♪', 1, 1, 2, 0, 3, 120001, 3, 7127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法少女の一休み♪\\n愛と希望と…闇の力が\\n回復していくね～♪', 1, 1, 3, 0, 0, 120001, 2, 7129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいかわいい♪\\nお姉ちゃんの魔法で\\n増やしちゃうぞ…♪', 1, 1, 3, 0, 0, 120001, 3, 7130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…\\n弟くんと同じ…\\nくんくん、くんくん…', 1, 1, 3, 0, 0, 120001, 4, 7131);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体を温めておいて…\\nこの熱を、ぜ～んぶ\\n弟くんに伝えるよ…！', 1, 1, 3, 0, 0, 120001, 5, 7132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミニ弟くんを呼ぶには\\nいっぱい食べないと…\\n魔法ってお腹減るから', 1, 1, 3, 0, 0, 120001, 7, 7134);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんの平和を守る…\\nそのためには\\nチェックチェック…♪', 1, 1, 3, 0, 0, 120001, 8, 7135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服も、最初は\\n慣れなかったのですが\\n今ではすっかり\\n体に馴染んでおります', 1, 1, 1, 0, 0, 125301, 1, 7137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自然を守るためにも\\nお勉強は欠かせません\\n日々精進でございます', 1, 1, 1, 0, 0, 125301, 2, 7138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('採取した薬草を\\n調合しておきましょう\\nいつ必要になるか\\n分かりませんからね', 1, 1, 1, 0, 0, 125301, 3, 7139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('合宿は過酷でしたが\\nおかげでちょっと\\n力持ちになったような\\n気がいたします…♪', 1, 1, 1, 0, 0, 125301, 4, 7140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わんわんのほうの\\n主さまに、ごはんを\\nあげる時間ですね…', 1, 1, 1, 0, 0, 125301, 5, 7141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっともっと訓練や\\nお勉強を重ねて\\n主さまのお役に\\n立たなくては…', 4, 1, 1, 0, 0, 125301, 101, 7142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おや、そろそろ\\nわんわんのほうの\\n主さまをお散歩に\\n連れていく時間です', 8, 1, 1, 0, 0, 125301, 102, 7143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主さま、よろしければ\\nお散歩に行きませんか\\n今日の森は穏やかで\\n過ごしやすいかと', 1, 1, 2, 0, 0, 125301, 1, 7144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わんわんのほうの\\n主さまも、今では\\n【美食殿】の大切な\\n仲間でございます', 1, 1, 2, 0, 0, 125301, 2, 7145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森には危険が\\nいっぱいでございます\\nケガをなさらないよう\\nお気をつけください', 1, 1, 2, 0, 0, 125301, 3, 7146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もし森や動物のことで\\n気になることがあれば\\n気軽にお尋ねください', 1, 1, 2, 0, 0, 125301, 4, 7147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森へ行く前には\\n必ず装備の点検を\\nお願いいたします\\n約束ですよ、主さま？', 4, 1, 2, 0, 0, 125301, 101, 7148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森の中で主さまたちと\\nゆったり過ごす時間は\\nわたくしにとって\\n大切なひとときです', 8, 1, 2, 0, 0, 125301, 102, 7149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n朝ごはんをしっかり\\n食べて、お勤めに\\n備えましょう', 1, 1, 2, 0, 1, 125301, 1, 7150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わんわんのほうの\\n主さまにおやつを\\nあげる時間です\\nどうぞ、召し上がれ', 1, 1, 2, 0, 2, 125301, 2, 7151);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どれだけ野営に\\n慣れたとしても\\nベッドで眠れるなら\\nそうしたいところです', 1, 1, 2, 0, 3, 125301, 3, 7152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こちらなのですが\\nわんわんのほうの\\n主さまもお気に入りの\\nようです', 1, 1, 3, 0, 0, 125301, 2, 7154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わんわんのほうの\\n主さまにも、こうした\\n玩具を与えるべき\\nでしょうか…？', 1, 1, 3, 0, 0, 125301, 3, 7155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よい香りです\\n次は、自然由来の\\n香料も試しましょう', 1, 1, 3, 0, 0, 125301, 4, 7156);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖をとるのは\\n野営の時などに\\nとても大事なことで\\nございますね', 1, 1, 3, 0, 0, 125301, 5, 7157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べられる時に食べて\\nおくのも、大自然では\\n重要でございます', 1, 1, 3, 0, 0, 125301, 7, 7159);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('より知識を蓄え\\n自然の力を活用できる\\nようにいたしましょう', 1, 1, 3, 0, 0, 125301, 8, 7160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今回の「冥風戦記」も\\nなかなかよく書けたぞ\\nふふっ、シグルドも\\n喜んでくれるかな？', 12, 1, 1, 0, 0, 100901, 103, 7162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴様のためならば\\n我が真なる魔力\\nいつでも\\n解き放とうぞ！', 12, 1, 2, 0, 0, 100901, 103, 7163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃんに\\nブラッシングを\\nしてあげようかな', 1, 1, 1, 0, 0, 125401, 1, 7164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ…\\nこれがレンジャーの\\n制服ですか', 1, 1, 1, 0, 0, 125401, 2, 7165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ\\nパトロールの\\n時間だ…', 1, 1, 1, 0, 0, 125401, 3, 7166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔物について\\nもっと知りたいな\\n本を探しに行こう', 1, 1, 1, 0, 0, 125401, 4, 7167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レンジャーになって\\n体調を崩す日が\\n減った気がします…', 1, 1, 1, 0, 0, 125401, 5, 7168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本だけじゃわからない\\n世界のことを、\\nもっと知りたいです…', 4, 1, 1, 0, 0, 125401, 101, 7169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな私にも\\nできることはある…\\nそう信じています', 8, 1, 1, 0, 0, 125401, 102, 7170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの…良かったら\\n一緒に見回りへ\\n行きませんか？', 1, 1, 2, 0, 0, 125401, 1, 7171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('またあなたと一緒に\\nレンジャーの仕事が\\nできたらうれしいです', 1, 1, 2, 0, 0, 125401, 2, 7172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('けほっこほっ\\n…だ、大丈夫です\\nたまに出るだけなので', 1, 1, 2, 0, 0, 125401, 3, 7173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃん\\nあなたにも\\n懐いてきましたね', 1, 1, 2, 0, 0, 125401, 4, 7174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃんと\\n散歩に出かけようかな\\n…あの人も誘って', 4, 1, 2, 0, 0, 125401, 101, 7175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと肩を並べて\\nレンジャーの仕事が\\nできてうれしいです…', 8, 1, 2, 0, 0, 125401, 102, 7176);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\nレンジャー・シオリ\\n元気に出勤します', 1, 1, 2, 0, 1, 125401, 1, 7177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃんにも\\nお昼ごはんを\\n用意しなくちゃ', 1, 1, 2, 0, 2, 125401, 2, 7178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('明日は仕事だから\\n早起きしなくちゃ\\nおやすみなさい', 1, 1, 2, 0, 3, 125401, 3, 7179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…仕事で\\n走り回ったので\\n少し休憩します', 1, 1, 3, 0, 0, 125401, 2, 7181);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事が終わった後に\\nこうして触れていると\\n癒されますね…', 1, 1, 3, 0, 0, 125401, 3, 7182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('森の香りがします…\\n今日はよく\\n眠れそうです…', 1, 1, 3, 0, 0, 125401, 4, 7183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ニャットちゃんと\\n同じぐらい\\n暖かいです…', 1, 1, 3, 0, 0, 125401, 5, 7184);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レンジャーの仕事を\\nしていると\\nお腹が空きます', 1, 1, 3, 0, 0, 125401, 7, 7186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どんなに忙しくても\\n読書だけは\\nやめられませんね', 1, 1, 3, 0, 0, 125401, 8, 7187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様のお留守の間\\nわたくしが、兄様の\\n御家を守ります！', 1, 1, 1, 0, 0, 125801, 1, 7189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('に、に、兄様の御家…\\n招待いただいた以上は\\n失礼のないよう\\n振る舞わなくては…！', 1, 1, 1, 0, 0, 125801, 2, 7190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ…兄様の素敵な\\nお人柄が、家中から\\nにじみ出ています…♪', 1, 1, 1, 0, 0, 125801, 3, 7191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('靴を脱がずに\\n御家に上がるのに\\n慣れていなくて…あ！\\n飛べばいいのでは…！', 1, 1, 1, 0, 0, 125801, 4, 7192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここに花を生けたら\\n華やぎそうですね\\n兄様はお花…\\n好きでしょうか…？', 1, 1, 1, 0, 0, 125801, 5, 7193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずっとここにいたい…\\nなどと言ったら\\n兄様を困らせて\\nしまいますよね…', 4, 1, 1, 0, 0, 125801, 101, 7194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お料理などを作って\\n兄様を出迎えられたら\\nいいのに…料理の腕も\\n磨かなくては…！', 8, 1, 1, 0, 0, 125801, 102, 7195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このような姿で\\n失礼しております…！\\nネ、ネズミがいたので\\nつい本気を…！', 1, 1, 2, 0, 0, 125801, 1, 7196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかえりなさいませ\\nお忙しい御身をどうぞ\\n癒してくださいね', 1, 1, 2, 0, 0, 125801, 2, 7197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様の話し相手…！？\\nど、どうしましょう…\\nわたくしには面白い\\n話なんて…はうぅ…！', 1, 1, 2, 0, 0, 125801, 3, 7198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なぜか、動物などに\\n好かれる体質で…\\n迷い猫捜しのバイトの\\nお役に立てますか？', 1, 1, 2, 0, 0, 125801, 4, 7199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('に、兄様の家に来たら\\n『添い寝』をするのが\\n礼儀とリアさんが…\\n本当…でしょうか？', 4, 1, 2, 0, 0, 125801, 101, 7200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたくしはここに\\nいて…よいのですね？\\n『仲間』として…', 8, 1, 2, 0, 0, 125801, 102, 7201);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝は得意なんです\\nもし兄様が苦手なら\\nわたくしが起こして\\n差し上げますよ', 1, 1, 2, 0, 1, 125801, 1, 7202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様…昼餉を作って\\nみたのですが、失敗\\nしてしまいました…', 1, 1, 2, 0, 2, 125801, 2, 7203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふあぁ…\\nはっ！\u3000お…\\nお恥ずかしい所を…！', 1, 1, 2, 0, 3, 125801, 3, 7204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これは…！\\n人様の御家なのに\\nつい…駄目になって…\\nしまいますぅ…！', 1, 1, 3, 0, 0, 125801, 2, 7206);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('と、飛びかかっては\\nこない…ですよね…？', 1, 1, 3, 0, 0, 125801, 3, 7207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すぅ…はぁ…\\nこのかぐわしさ\\n心が洗われます…', 1, 1, 3, 0, 0, 125801, 4, 7208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんて暖かい…\\n兄様の優しくお広い\\n御心のようです…♪', 1, 1, 3, 0, 0, 125801, 5, 7209);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなに食べていたら\\nはしたない…\\nでしょうか？', 1, 1, 3, 0, 0, 125801, 7, 7211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様の本棚はまるで\\n知識の宝庫ですね\\n己の世間知らずぶりを\\n実感してしまいます', 1, 1, 3, 0, 0, 125801, 8, 7212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次の冒険に向けて\\n騎空士弁当を作ろっと\\nまずはおにぎりから！', 1, 1, 1, 0, 0, 125501, 1, 7214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法の修行しなくちゃ\\nもっともっと頼れる\\n団長になりたいから！', 1, 1, 1, 0, 0, 125501, 2, 7215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビカラちゃんを\\n遊びに誘いたいけど…\\nどういう場所が\\n好きなんだろう？', 1, 1, 1, 0, 0, 125501, 3, 7216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事を真面目に\\nしっかりこなすことが\\n騎空艇への\\n一番の近道だよね', 1, 1, 1, 0, 0, 125501, 4, 7217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいる人の中で\\n騎空団に興味ある人\\nいたりしないかな…？', 1, 1, 1, 0, 0, 125501, 5, 7218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これまでも想い出は\\nいっぱいできたけど…\\nこれからもたくさん\\n想い出を作りたいな！', 4, 1, 1, 0, 0, 125501, 101, 7219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間がいるから\\n騎空士は限界だって\\n超えられるんだね', 8, 1, 1, 0, 0, 125501, 102, 7220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装\\n魔法使いらしいでしょ\\n服に着られないよう\\n頑張らなくちゃね！', 1, 1, 2, 0, 0, 125501, 1, 7221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたとなら\\nどんな相手だって\\n怖くなんてないよ！', 1, 1, 2, 0, 0, 125501, 2, 7222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カリンさんから\\n新しい依頼が来たよ！\\n一緒に頑張ろ！', 1, 1, 2, 0, 0, 125501, 3, 7223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('操舵士になるのは\\nずいぶん難しそう…\\nいつか頼れる仲間が\\n見つかるといいな', 1, 1, 2, 0, 0, 125501, 4, 7224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手合わせしたいの？\\nいいよ、たまには\\n団長らしいところ\\n見せてあげるね！', 4, 1, 2, 0, 0, 125501, 101, 7225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ二人きりだけど…\\nこの騎空団は\\n私の宝物だよ！', 8, 1, 2, 0, 0, 125501, 102, 7226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう～…\\n昨日は遅くまで\\n魔法の研究してて…\\nふわぁ…眠いなぁ…', 1, 1, 2, 0, 1, 125501, 1, 7227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さてと、お昼休み！\\n紅茶淹れてくるから\\n一緒に飲もうよ！', 1, 1, 2, 0, 2, 125501, 2, 7228);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('遅くまでお疲れさま！\\n無理しない程度に\\nお互い頑張ろう！', 1, 1, 2, 0, 3, 125501, 3, 7229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法の研究は\\n一旦、休憩！\\n頭を休めなくちゃ', 1, 1, 3, 0, 0, 125501, 2, 7231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法みたいに\\nかわいい！\\n騎空団に入る？\\nなんてね！', 1, 1, 3, 0, 0, 125501, 3, 7232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂い…\\nそれになんだか\\n集中力が増したかも', 1, 1, 3, 0, 0, 125501, 4, 7233);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体だけじゃなくて\\n心までポカポカする…\\nなんだか魔法みたい', 1, 1, 3, 0, 0, 125501, 5, 7234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いろいろ考え事したら\\nお腹が空いちゃった！\\nいただきまーす！', 1, 1, 3, 0, 0, 125501, 7, 7236);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『摂理の彼方へ\\n至るには…』\\n…この魔導書\\n勉強になるなあ', 1, 1, 3, 0, 0, 125501, 8, 7237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こちらの服を着ると\\n冒険に出かけたく\\nなっちゃいますね', 1, 1, 1, 0, 0, 125701, 1, 7239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険者の心得その一\\n準備はできる限り\\nしっかりとこなすべし\\nなんてどうでしょう？', 1, 1, 1, 0, 0, 125701, 2, 7240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('調合に必要な素材は\\nあれとこれとそれと…\\n時間があるとついつい\\n考えちゃいますね', 1, 1, 1, 0, 0, 125701, 3, 7241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくですから\\nより良い素材を\\n自分で集めたいですね', 1, 1, 1, 0, 0, 125701, 4, 7242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このポーションが\\nみなさんの役に立つと\\nうれしいですね', 1, 1, 1, 0, 0, 125701, 5, 7243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険者の心得その二\\n危なくなった時は\\nまず逃げるべし！\\n大事なことですね', 4, 1, 1, 0, 0, 125701, 101, 7244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人の冒険は\\nいつも楽しそうで\\n元気がもらえます', 8, 1, 1, 0, 0, 125701, 102, 7245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぜひおすすめしたい\\n依頼があるんです\\nこちらをどうぞ♪', 1, 1, 2, 0, 0, 125701, 1, 7246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほしいお薬があれば\\n錬金術で作って\\nさしあげますよ', 1, 1, 2, 0, 0, 125701, 2, 7247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('依頼で気になる\\nところがあれば\\n何でもご確認ください', 1, 1, 2, 0, 0, 125701, 3, 7248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このギルドハウスに\\n錬金術の実験設備を…\\nえ？\u3000だめですか？', 1, 1, 2, 0, 0, 125701, 4, 7249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポーションをどうぞ\\n大丈夫、効果は\\n確認済みですので♪', 4, 1, 2, 0, 0, 125701, 101, 7250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('次はどんな冒険に\\n行かれるんですか？\\nいつでもお供しますよ', 8, 1, 2, 0, 0, 125701, 102, 7251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もいい一日に\\nなりそうですね\\n冒険日和といった\\nところでしょうか', 1, 1, 2, 0, 1, 125701, 1, 7252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい時間ですし\\nランチにしませんか？\\n次の冒険の\\n作戦会議も兼ねて♪', 1, 1, 2, 0, 2, 125701, 2, 7253);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜も遅いですし\\n明日の冒険のため\\n今日は早く寝ましょう', 1, 1, 2, 0, 3, 125701, 3, 7254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふう…やはり冒険は\\n事務仕事と違いますね\\n少し休憩を…', 1, 1, 3, 0, 0, 125701, 2, 7256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険は緊張の連続です\\nかわいい物で\\n心を癒しましょう', 1, 1, 3, 0, 0, 125701, 3, 7257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、この香りは…\\n素晴らしいバランスで\\n調合されていますね', 1, 1, 3, 0, 0, 125701, 4, 7258);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この火力…\\n錬金術の調合に\\n使えそうですね', 1, 1, 3, 0, 0, 125701, 5, 7259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険の際は食べられる\\n時に食べておく！\\n…とペコリーヌさんも\\nおっしゃってましたね', 1, 1, 3, 0, 0, 125701, 7, 7261);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…なるほど\\nこんな調合も\\nあるのですね…\\n奥が深いです', 1, 1, 3, 0, 0, 125701, 8, 7262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アイツどこ行った…？\\n戦うならアタシも\\n連れてけよなー！', 12, 1, 1, 0, 0, 106101, 103, 7264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も悪いヤツ退治…\\nの前に腹ごしらえだ！\\nなんか食べに行くぞ！', 12, 1, 2, 0, 0, 106101, 103, 7265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなー！\\nギルドハウスで\\nぼくと握手！', 1, 1, 1, 0, 0, 125601, 1, 7266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('種族も年齢も違うけど\\nみんな楽しそうだね！\\nやっぱりここはぼくの\\nゆ～とぴあさ！', 1, 1, 1, 0, 0, 125601, 2, 7267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハハッ！\u3000まるで\\nパーティー会場だね！\\nこれは楽しませがいが\\nあるってものだよ！', 1, 1, 1, 0, 0, 125601, 3, 7268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やぁみんな！\\nご利益満点のネズ耳は\\nいかがかな？\\nひとつ３ルピだよ！', 1, 1, 1, 0, 0, 125601, 4, 7269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにいれば\\n遊び相手に困らないね\\nかしこみかしこみ～！', 1, 1, 1, 0, 0, 125601, 5, 7270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どこか遊びに\\n行こうかな♪\\nそうだ、あの人にも\\n声をかけてみよう！', 4, 1, 1, 0, 0, 125601, 101, 7271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人といると\\nぼくまで楽しくなって\\nくるんだよね！\\n毎日パレード気分さ！', 8, 1, 1, 0, 0, 125601, 102, 7272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネズ耳の在庫が\\n切れたんだ！\\n作るのを\\n手伝ってくれるかい？', 1, 1, 2, 0, 0, 125601, 1, 7273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん？\u3000握手かい？\\nいいとも！\\nいつでも何度でも\\nしてあげるよ！', 1, 1, 2, 0, 0, 125601, 2, 7274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装に興味が\\nあるのかい？\\nきみ、なかなか\\n見る目があるね！', 1, 1, 2, 0, 0, 125601, 3, 7275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しばらくここに厄介に\\nなるつもりなんだ\\nあとで街を案内\\nしてくれるかい？', 1, 1, 2, 0, 0, 125601, 4, 7276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっておきのチーズ\\nきみと半分こだ！\\nみんなには内緒だよ？', 4, 1, 2, 0, 0, 125601, 101, 7277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きみはいてほしい時に\\nいつもそばに\\nいてくれるね\\n本当にかしこみだよ！', 8, 1, 2, 0, 0, 125601, 102, 7278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やぁ、おはよう！\\n気持ちのいい朝だね\\n今日も楽しくネズ耳\\n売りにはげもうか！', 1, 1, 2, 0, 1, 125601, 1, 7279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼だね！\\nおいしいチーズを\\n持ってきたから\\nぼくと半分こだ！', 1, 1, 2, 0, 2, 125601, 2, 7280);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\n楽しかったね！\\nいい夢が見られること\\n間違いなしさ！', 1, 1, 2, 0, 3, 125601, 3, 7281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼくにも休息は\\n必要さ！\\nリラックス〜\\nリラックス〜♪', 1, 1, 3, 0, 0, 125601, 2, 7283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼくのぬいぐるみも\\n作って売ろうかな…\\n修繕費も一気に\\n集まるかもね！', 1, 1, 3, 0, 0, 125601, 3, 7284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りだね！\\nトーゴクのお香に\\nよく似てるよ', 1, 1, 3, 0, 0, 125601, 4, 7285);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…温まるねぇ…\\nそうだ、この火で\\nチーズでも炙って\\nみようかな', 1, 1, 3, 0, 0, 125601, 5, 7286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、この味…\\nトーゴクを思い出すよ\\nどれ、もう一つ\\nいただこうか！', 1, 1, 3, 0, 0, 125601, 7, 7288);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはランドソルの\\nガイド本だね！\\nありがたく参考に\\nさせてもらうよ！', 1, 1, 3, 0, 0, 125601, 8, 7289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まさか、わらわが\\nこのような装束を\\n纏う日がくるとはな…\\n感慨深いものじゃ', 1, 1, 1, 0, 0, 126201, 1, 7291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わらわの美貌で\\nこのギルドハウスも\\nより華やかに\\nなったようじゃな', 1, 1, 1, 0, 0, 126201, 2, 7292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つまらぬ戦いで\\n晴れ着を汚しとうない\\n今日は一日\\nゆっくりするかの', 1, 1, 1, 0, 0, 126201, 3, 7293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はわらわが食事の\\n準備をして、あやつの\\n帰りを待ってやろう\\n献立は何がよいかの…', 1, 1, 1, 0, 0, 126201, 4, 7294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ユキといったか…\\n掴みどころのない\\nやつじゃが、根性は\\n認めてやるかの', 1, 1, 1, 0, 0, 126201, 5, 7295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうして、仲間と\\nのんびり過ごす時間も\\n悪くないのう♪', 4, 1, 1, 0, 0, 126201, 101, 7296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あやつを誘って\\n月を見に行こうかの\\n夜が楽しみじゃ♪', 8, 1, 1, 0, 0, 126201, 102, 7297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いかなる衣装で\\nあろうとも、わらわは\\n完璧に着こなして\\nしまうのじゃ♪', 1, 1, 2, 0, 0, 126201, 1, 7298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんじゃ？\\nわらわの姿に\\n見惚れておったとな？\\nす、素直でよいのじゃ', 1, 1, 2, 0, 0, 126201, 2, 7299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼であるわらわに\\n相応しい装束じゃろう\\nあとは真っ赤な血を\\n添えたいのう…', 1, 1, 2, 0, 0, 126201, 3, 7300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お主、疲れておるな？\\nわらわが癒してやろう\\nほれ、近う寄るのじゃ', 1, 1, 2, 0, 0, 126201, 4, 7301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お主がおるだけで\\nギルドハウスが\\n賑やかになるのう\\nある種の才能じゃな♪', 4, 1, 2, 0, 0, 126201, 101, 7302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属よ、風呂にするか\\nご飯にするか\\nそれとも、わらわに…\\nいや、忘れるのじゃ', 8, 1, 2, 0, 0, 126201, 102, 7303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝一番、わらわに\\n会いたかったとな…\\n眷属よ\\n褒めてつかわすぞ♪', 1, 1, 2, 0, 1, 126201, 1, 7304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眷属よ、わらわが\\n食事を用意したぞ\\n忌々しい太陽に負けず\\n頑張るのじゃ', 1, 1, 2, 0, 2, 126201, 2, 7305);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('眠るには惜しい夜じゃ\\n眷属よ、もうしばらく\\nわらわの傍に\\nおるがよい', 1, 1, 2, 0, 3, 126201, 3, 7306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふかじゃの♪\\n今度あやつにも\\n座らせてやろう', 1, 1, 3, 0, 0, 126201, 2, 7308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('愛いやつじゃ\\n少しばかり、わらわが\\n遊んでやろうかの', 1, 1, 3, 0, 0, 126201, 3, 7309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気品ある香りじゃのう\\nわらわの古城にも\\n一つ欲しいところじゃ', 1, 1, 3, 0, 0, 126201, 4, 7310);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よいぬくもりじゃ…\\n忌々しい太陽とは\\n大違いじゃの', 1, 1, 3, 0, 0, 126201, 5, 7311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('味付けの参考に\\nあと、もう一つだけ…\\n止まらんのじゃ…', 1, 1, 3, 0, 0, 126201, 7, 7313);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼の弱点について\\n記されておるのか…\\nふむ、眠気が\\nさめてしもうたぞ', 1, 1, 3, 0, 0, 126201, 8, 7314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このままボクが美しく\\nなり続けても、彼なら\\nきっと隣にいてくれる\\nはずだよね！', 12, 1, 1, 0, 0, 100801, 103, 7316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もっとそばに来なよ\\nボクの隣は\\nキミのための\\n特等席なんだから', 12, 1, 2, 0, 0, 100801, 103, 7317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドレスの影響かな…\\n前より黒や赤が\\n好きになったかも', 1, 1, 1, 0, 0, 126301, 1, 7318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクがいるだけで\\nここがぐんっと\\n華やかになったね♪', 1, 1, 1, 0, 0, 126301, 2, 7319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクを描いた絵画\\n今度持ってきて\\n飾ってあげようかな', 1, 1, 1, 0, 0, 126301, 3, 7320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクはボクに\\n魅了されっぱなしさ♪\\nまさに魔性の存在だよ', 1, 1, 1, 0, 0, 126301, 4, 7321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美のアドバイスを\\n聞きたい人いるかい？\\nボクがもっともっと\\n輝かせてあげるよ♪', 1, 1, 1, 0, 0, 126301, 5, 7322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人、今度はボクを\\nどう褒めるだろう？\\nもし語彙が尽きても\\n許してあげよっと♪', 4, 1, 1, 0, 0, 126301, 101, 7323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの人に似合うコーデ\\n考えてあげよっと\\n案外、なんでも\\n着こなしそうだよね♪', 8, 1, 1, 0, 0, 126301, 102, 7324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼になるなんて\\nやっぱりゴメンだね！\\n永遠の美よりも\\n大事なことがあるのさ', 1, 1, 2, 0, 0, 126301, 1, 7325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お肌にいいものは\\n大体好きだよ\\nトマトジュースとかね', 1, 1, 2, 0, 0, 126301, 2, 7326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('銀のアクセサリーが\\nボクは大好きでね\\nいつでもプレゼント\\n待ってるよ♪', 1, 1, 2, 0, 0, 126301, 3, 7327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イリヤみたいにお城に\\n住んでみたいんだ♪\\n美を統べる者に\\n相応しいでしょ？', 1, 1, 2, 0, 0, 126301, 4, 7328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今のボクがカップを\\n触ると壊しちゃうんだ\\nだからほら、キミが\\nボクに紅茶を飲ませて', 4, 1, 2, 0, 0, 126301, 101, 7329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミも美を磨けば\\nもっと輝けるはずさ！\\nボクがメイクとか\\nしてあげようか？', 8, 1, 2, 0, 0, 126301, 102, 7330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んん、まだ眠い…\\n美のためにも、\\nもうひと眠りするよ…', 1, 1, 2, 0, 1, 126301, 1, 7331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ボクにぴったりな\\n日傘を買ったんだ♪\\n散歩にでも行こうよ！', 1, 1, 2, 0, 2, 126301, 2, 7332);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜こそボクの時間！\\nさぁ、あまねく人々へ\\nボクの美を広めよう！', 1, 1, 2, 0, 3, 126301, 3, 7333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リラックスは大事だよ\\n心の余裕こそが\\n美の秘訣だからね♪', 1, 1, 3, 0, 0, 126301, 2, 7335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミもボクの\\n美の虜にしてあげる♪\\nうれしいでしょ？', 1, 1, 3, 0, 0, 126301, 3, 7336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人々を魅了するほどの\\n魔性の香り…\\nボクにふさわしいね♪', 1, 1, 3, 0, 0, 126301, 4, 7337);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷えは美の大敵さ\\nボクのように\\n美しくなりたいなら\\n体を温めるべきだよ', 1, 1, 3, 0, 0, 126301, 5, 7338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事をするボクの\\nなまめかしさ…♪\\n吸血鬼すらも\\nドキッとするだろうね', 1, 1, 3, 0, 0, 126301, 7, 7340);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('吸血鬼って\\n美しい存在だよね…\\nボクほどではないけど', 1, 1, 3, 0, 0, 126301, 8, 7341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここがナイトさんの\\nお家なんですねーっ！\\n雰囲気そっくりっ！', 1, 1, 1, 0, 0, 126401, 1, 7343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドアも壁もお菓子じゃ\\nないんですよねっ？\\n不思議ですねーっ♪', 1, 1, 1, 0, 0, 126401, 2, 7344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('失礼のないように\\n気をつけないとっ！\\nライラエルさまとも\\n約束してますからっ！', 1, 1, 1, 0, 0, 126401, 3, 7345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('向こうに帰るころには\\nお土産話がいっぱい\\nできてるといいな～♪', 1, 1, 1, 0, 0, 126401, 4, 7346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦闘用のアームの他に\\n観光用のアームも\\nあったらいいのにな～', 1, 1, 1, 0, 0, 126401, 5, 7347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ナイトさんの充填と\\nライラエルさまの充填\\nどっちも違って\\nどっちも大好きです♪', 4, 1, 1, 0, 0, 126401, 101, 7348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ナイトさんが\\nマスターになって\\nくれたら…えへへっ\\nなんでもないですっ！', 8, 1, 1, 0, 0, 126401, 102, 7349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お手伝いだったら\\n任せてくださいっ！\\nお家の移転とか\\nしちゃいますかっ？', 1, 1, 2, 0, 0, 126401, 1, 7350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こっちに来るときは\\nポポおじいさんが\\nしっかりメンテして\\nくれるんですよっ♪', 1, 1, 2, 0, 0, 126401, 2, 7351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お家の中にいるのも\\nいいですけど、お外も\\n気になります～っ！\\nお出かけしましょう♪', 1, 1, 2, 0, 0, 126401, 3, 7352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヴォルガーノさんに\\nそっくりの子猫さんを\\n見かけたんですっ！\\nご親戚ですかねっ？', 1, 1, 2, 0, 0, 126401, 4, 7353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここだけの話ですよ？\\n…実はケーブルって\\n触られると、ちょっと\\nくすぐったいんですっ', 4, 1, 2, 0, 0, 126401, 101, 7354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお家の持ち主は\\nナイトさんですよね？\\nそれじゃここでは\\nご主人さまですねっ', 8, 1, 2, 0, 0, 126401, 102, 7355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございますっ\\n今日もフルパワーで\\nがんばりましょうっ♪', 1, 1, 2, 0, 1, 126401, 1, 7356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼の時間ですねっ！\\nランチの充填、\\nお願いしまーすっ♪', 1, 1, 2, 0, 2, 126401, 2, 7357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ眠らなくて\\n大丈夫ですかっ？\\n夜ふかしさんなら\\nお付き合いしますよ♪', 1, 1, 2, 0, 3, 126401, 3, 7358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エネルギーの消費を\\n抑えるのも大切\\nですよね～っ', 1, 1, 3, 0, 0, 126401, 2, 7360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたしが触っても\\n平気なんて…！\\nかわいくて頑丈っ！\\n好きですっ！', 1, 1, 3, 0, 0, 126401, 3, 7361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('センサーによると…\\nこの香りはいい香りに\\n該当するみたいですっ\\nなるほどーっ！', 1, 1, 3, 0, 0, 126401, 4, 7362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいのって\\nいいですよねっ！\\nみなさんうれしそう\\nですしっ♪', 1, 1, 3, 0, 0, 126401, 5, 7363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これがこっちの世界の\\nごはんなんですねっ\\nおいしい気がします！', 1, 1, 3, 0, 0, 126401, 7, 7365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そーっとそーっと…\\n本を破かないように…\\n書いてある内容より\\n難しいです～っ！', 1, 1, 3, 0, 0, 126401, 8, 7366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ウィスタリア家の\\nプライベートビーチも\\nご案内しますわね♪', 1, 1, 1, 0, 0, 126701, 1, 7368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世界を巡る\\nリゾートクルーズも\\nご用意できますわよ', 1, 1, 1, 0, 0, 126701, 2, 7369);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('避暑地に専用の\\n別荘がありますの\\n今度ご招待しますわね', 1, 1, 1, 0, 0, 126701, 3, 7370);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日焼けは乙女の\\n天敵ですわね\\n備えはしっかりと…', 1, 1, 1, 0, 0, 126701, 4, 7371);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('線香花火だけでは\\n物足りませんわね\\nもっとドカーンと…', 1, 1, 1, 0, 0, 126701, 5, 7372);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルド活動も全力で！\\nバカンスも全力で！\\nそれが私ですわ！', 4, 1, 1, 0, 0, 126701, 101, 7373);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私のセンスで選んだ\\n特注の水着ですもの\\n似合って当然ですわ♪', 8, 1, 1, 0, 0, 126701, 102, 7374);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご希望ならすぐにでも\\n夏の飛空艇遊覧ツアー\\nへご招待しますわ♪', 1, 1, 2, 0, 0, 126701, 1, 7375);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏の賑やかな\\n雰囲気は好きですが…\\n暑さには参りますわね', 1, 1, 2, 0, 0, 126701, 2, 7376);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日の光を浴びるほどに\\n輝きを増す夏の私！\\n今日も絶好調ですわ♪', 1, 1, 2, 0, 0, 126701, 3, 7377);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏祭りに協力するなら\\n資金と人材、どちらも\\n用意しないとですわね', 1, 1, 2, 0, 0, 126701, 4, 7378);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたさま…その…\\nそうも見つめられると\\n照れてしまいます…', 4, 1, 2, 0, 0, 126701, 101, 7379);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('タマキさんの働く\\n海の家も訪れて\\nみたいですわね♪', 8, 1, 2, 0, 0, 126701, 102, 7380);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('港の市場が\\n賑わう頃ですわね！\\n私たちも参りますわよ', 1, 1, 2, 0, 1, 126701, 1, 7381);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷たい飲み物でも\\nご一緒にいかが？\\nうちのシェフに用意\\nさせてありますの', 1, 1, 2, 0, 2, 126701, 2, 7382);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだもう少し…\\nこの夏の夜を\\nあなたさまと…', 1, 1, 2, 0, 3, 126701, 3, 7383);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたさまも\\n良ければこちらへ\\nいらっしゃいな♪', 1, 1, 3, 0, 0, 126701, 2, 7385);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏に合わせた装いに\\n替えてみるのも\\n楽しそうですわね♪', 1, 1, 3, 0, 0, 126701, 3, 7386);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この夏めいた爽やかな\\n香り…期間限定で\\n売り出したいですわ', 1, 1, 3, 0, 0, 126701, 4, 7387);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('く…我慢です…\\nこの暑さに耐えてこそ\\n美しさにも磨きが…', 1, 1, 3, 0, 0, 126701, 5, 7388);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑い季節に働く\\nみなさまへ差し入れも\\n必要ですわね', 1, 1, 3, 0, 0, 126701, 7, 7390);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏のトレンドを\\n押さえておくのも\\n大事ですわね', 1, 1, 3, 0, 0, 126701, 8, 7391);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('上手くいけば\\nヒット商品になる\\nポテンシャルを\\n感じますわね…！', 1, 1, 3, 0, 0, 126701, 10, 7393);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この極上の肌触り…\\n言い値で買いますわ\\n一体おいくらですの？', 1, 1, 3, 0, 0, 126701, 11, 7394);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくのバカンス…\\n自由に羽を\\n伸ばすとしましょう', 1, 1, 1, 0, 0, 126601, 1, 7395);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たとえどのような\\n秘密を持とうとも\\n私には筒抜けですよ', 1, 1, 1, 0, 0, 126601, 2, 7396);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子供だましの怪談に\\n関心はありませんが…\\n霊には興味があります\\n観察対象として、ね', 1, 1, 1, 0, 0, 126601, 3, 7397);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼の絵日記…\\nあとでゆっくりと\\n読ませてもらいます', 1, 1, 1, 0, 0, 126601, 4, 7398);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('セミの鳴き声に入道雲\\nそしてクリームソーダ\\nこれでこそ夏ですね', 1, 1, 1, 0, 0, 126601, 5, 7399);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏休みの宿題でも\\n作るとしましょうか\\n彼の限界を少し超えた\\n負荷を与えるには…', 4, 1, 1, 0, 0, 126601, 101, 7400);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼と過ごす夏を\\n特別なものにしたい…\\nそれが私の望みです', 8, 1, 1, 0, 0, 126601, 102, 7401);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏だからといって\\n浮かれすぎないように\\n節度を持って\\n楽しみなさい？', 1, 1, 2, 0, 0, 126601, 1, 7402);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああ見えてもマサキは\\n私のプリンセスナイト\\nあまり侮られては\\n困りますよ？', 1, 1, 2, 0, 0, 126601, 2, 7403);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の秘密ですか？\\nまんじゅうが怖い…\\nというのはどうです？', 1, 1, 2, 0, 0, 126601, 3, 7404);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは誰かの秘密を\\n盗み聞くのに\\n最適な場所ですね\\n…ジョークですよ', 1, 1, 2, 0, 0, 126601, 4, 7405);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一緒に風鈴の音を\\nのんびり楽しもう…？\\n…別に構いませんよ\\n貴方とならば', 4, 1, 2, 0, 0, 126601, 101, 7406);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貴方に約束しましょう\\n決して忘れられない\\n夏にしてあげますよ', 8, 1, 2, 0, 0, 126601, 102, 7407);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('早起きとは感心ですね\\nでは一緒に\\n体操でもしましょうか', 1, 1, 2, 0, 1, 126601, 1, 7408);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食は流しそうめん？\\n非効率的ですね\\n…食べないとは\\n一言も言っていません', 1, 1, 2, 0, 2, 126601, 2, 7409);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…貴方が望むならば\\nいくらでも怖い話を\\nしてあげますが…\\nいかがですか？', 1, 1, 2, 0, 3, 126601, 3, 7410);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('七冠にも休息は\\n必要なのです\\nしばらくここで\\n休ませてもらいますよ', 1, 1, 3, 0, 0, 126601, 2, 7412);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なかなか気に入った…\\nというのは\\n誰にも秘密です', 1, 1, 3, 0, 0, 126601, 3, 7413);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('薫風を思わせる\\nこのさわやかな香り…\\n悪くないセンスですね', 1, 1, 3, 0, 0, 126601, 4, 7414);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏だからこそ\\n冷え対策は\\n重要なのです\\n…とはいえ暑いですね', 1, 1, 3, 0, 0, 126601, 5, 7415);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私がどのような味が\\n好きなのかは…\\n当然秘密です', 1, 1, 3, 0, 0, 126601, 7, 7417);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏を舞台にした\\n小説は数多くあります\\n彼が好きそうな本を\\n何冊か見繕いましょう', 1, 1, 3, 0, 0, 126601, 8, 7418);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('見た目も手触りも\\n完璧に覚えました\\nいつでも模倣できます', 1, 1, 3, 0, 0, 126601, 10, 7420);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ…夏らしい\\nクッションですね\\nナイトプールに\\n映えそうです', 1, 1, 3, 0, 0, 126601, 11, 7421);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('レイ様も格好良いけど\\n騎士さんもなかなか…\\nって、今の聞こえて\\nませんよねっ？', 12, 1, 1, 0, 0, 105401, 103, 7422);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんはシンプルな\\n服が似合いそうです！\\n今度、一緒に\\n見に行きましょう♪', 12, 1, 2, 0, 0, 105401, 103, 7423);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最初はどうかな～って\\n思ったけど…\\n水着姿でも案外\\n問題ないのよね…', 1, 1, 1, 0, 0, 126801, 1, 7424);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着で飲みすぎると\\nお腹が冷える、って\\n言うけど…麦しゅわ\\nなら問題ないわね！', 1, 1, 1, 0, 0, 126801, 2, 7425);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑ければ暑いほど\\nその後の麦しゅわは\\nおいしくなるのよ…', 1, 1, 1, 0, 0, 126801, 3, 7426);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('しっかりと仕事を\\nこなしてから、\\nしっかりと麦しゅわ！\\nやっぱりこれね！', 1, 1, 1, 0, 0, 126801, 4, 7427);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、デザインも\\n着心地も最高ね\\n奮発して用意して\\n正解だったわ♪', 1, 1, 1, 0, 0, 126801, 5, 7428);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('伝説の麦しゅわ、\\n飲めるものなら\\nまた飲みたいわね…', 4, 1, 1, 0, 0, 126801, 101, 7429);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('二つ名に恥じない\\n聖騎士として\\n私…飲むわ！', 8, 1, 1, 0, 0, 126801, 102, 7430);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好なら水に\\n濡れても大丈夫！\\nなんだけど、さすがに\\n書類は濡らせないわね', 1, 1, 2, 0, 0, 126801, 1, 7431);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうやってじっと\\n見られると…ちょっと\\n恥ずかしいわ…', 1, 1, 2, 0, 0, 126801, 2, 7432);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もいい天気ね\\nふふっ、あとで\\nビーチに遊びに\\n行きましょ♪', 1, 1, 2, 0, 0, 126801, 3, 7433);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着姿も慣れると\\n案外快適ね\\nそうだ、キミも\\n水着になっちゃう？', 1, 1, 2, 0, 0, 126801, 4, 7434);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('例え水着姿であろうと\\n聖騎士としての誇りは\\n忘れてないわ！', 4, 1, 2, 0, 0, 126801, 101, 7435);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミとだったら\\n麦しゅわなしでも\\n最高の夏のバカンスに\\nなると思うわ♪', 8, 1, 2, 0, 0, 126801, 102, 7436);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仕事終わりの\\n麦しゅわのために\\n今日も一日\\n頑張るわよ♪', 1, 1, 2, 0, 1, 126801, 1, 7437);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日のお昼は\\nどうしようかしら…\\nさ、さすがに昼からは\\n自重してるわよ？', 1, 1, 2, 0, 2, 126801, 2, 7438);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さ、一日の疲れを\\n洗い流すために…\\n軽～く飲むわよ！', 1, 1, 2, 0, 3, 126801, 3, 7439);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうやって\\n直に触れると\\n肌触りの良さが\\nよく分かるわ♪', 1, 1, 3, 0, 0, 126801, 2, 7441);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もかわいいわね～\\nどう？\u3000今度\\nお姉さんの一人飲みに\\n付き合わない？', 1, 1, 3, 0, 0, 126801, 3, 7442);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りね～…はっ！\\n麦しゅわの匂いの\\nアロマポットなんて\\nあったらよくない？', 1, 1, 3, 0, 0, 126801, 4, 7443);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな格好で火に\\n当たってると焙られる\\nスルメの気分が\\nちょっと分かるわ…', 1, 1, 3, 0, 0, 126801, 5, 7444);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…うん、\\n結構おつまみにも\\nむいてそうね～♪', 1, 1, 3, 0, 0, 126801, 7, 7446);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('試験に使った参考書、\\nたまには読み返して\\nおかないとね', 1, 1, 3, 0, 0, 126801, 8, 7447);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ♪\\nいい手触りね～', 1, 1, 3, 0, 0, 126801, 10, 7449);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…はふう～…\\nゴロゴロするのって\\n最高ね～', 1, 1, 3, 0, 0, 126801, 11, 7450);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん…やっぱり\\nこの水着…\\n大胆、なんじゃ…？', 1, 1, 1, 0, 0, 126901, 1, 7451);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海でもお世話って、\\nできるのかしら…？\\n浮き輪代わりになる、\\nとか…？', 1, 1, 1, 0, 0, 126901, 2, 7452);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('～♪\\nふふ…海に行く\\n準備も、楽しい…かも', 1, 1, 1, 0, 0, 126901, 3, 7453);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あうぅ…水着で\\n歩いてると…お尻…\\nすぐ食い込んじゃう…', 1, 1, 1, 0, 0, 126901, 4, 7454);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海では、はしゃいだ\\nほうがいいのよね…\\nわ、わー、い…♪\\n…こうかしら？', 1, 1, 1, 0, 0, 126901, 5, 7455);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたとなら…\\n楽しい夏の思い出、\\n作れる…気がするの…', 4, 1, 1, 0, 0, 126901, 101, 7456);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('また来年も…\\n再来年も…\\nあなたと海へ\\n行けますように…', 8, 1, 1, 0, 0, 126901, 102, 7457);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着の着方を\\n練習してるの…\\n後ろ、変じゃない…？', 1, 1, 2, 0, 0, 126901, 1, 7458);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行く支度…\\n進んでるかしら…？\\nお手伝い、する…？', 1, 1, 2, 0, 0, 126901, 2, 7459);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひ、日除けの準備は\\n万全よ…\\nずっと太陽の下に\\nいたら…溶けちゃう…', 1, 1, 2, 0, 0, 126901, 3, 7460);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳ぐ練習…\\nこ、ここでするのは\\n…さすがに変？', 1, 1, 2, 0, 0, 126901, 4, 7461);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人混みに入るのは\\nまだ不安で…\\nでも、あなたといれば\\nきっと…大丈夫…', 4, 1, 2, 0, 0, 126901, 101, 7462);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたのおかげで\\n海の楽しいところを\\nたくさん知ったわ…\\nありがとう…♪', 8, 1, 2, 0, 0, 126901, 102, 7463);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お出かけの日の朝は\\n早い、のよね…？\\nだから、ずっと\\n起きていたわ…', 1, 1, 2, 0, 1, 126901, 1, 7464);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今頃ビーチの日差しは\\n強いんでしょうね…\\nそ、想像しただけで…\\nめまいが…', 1, 1, 2, 0, 2, 126901, 2, 7465);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーチの夜といえば\\n花火って、聞いたわ…\\nバン、って言わない\\n花火…ある…？', 1, 1, 2, 0, 3, 126901, 3, 7466);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素肌にふわふわが…\\n気持ちいい…♪', 1, 1, 3, 0, 0, 126901, 2, 7468);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ…\\n一緒に海…行く？', 1, 1, 3, 0, 0, 126901, 3, 7469);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…♪\\n気分まで…\\n晴れやかになるわ…', 1, 1, 3, 0, 0, 126901, 4, 7470);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑いような…\\n寒いような…\\n不思議な気持ちに\\nなるわ…ね？', 1, 1, 3, 0, 0, 126901, 5, 7471);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('泳いだ後には\\nいっぱい食べたほうが\\n体によさそう、ね…', 1, 1, 3, 0, 0, 126901, 7, 7473);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビーチの日陰で\\n読書するのも…\\n気持ちよさそう…♪', 1, 1, 3, 0, 0, 126901, 8, 7474);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これで合ってる…？\\n遊び方わからなくて…', 1, 1, 3, 0, 0, 126901, 10, 7476);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわふわ…♪\\n海の底にいるみたい…', 1, 1, 3, 0, 0, 126901, 11, 7477);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('恥ずかしい格好で\\n室内を歩くこの快感\\nクセになりそうです…', 1, 1, 1, 0, 0, 127001, 1, 7478);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この水着…\\nどうしてかポーズを\\n決めたくなりますね…', 1, 1, 1, 0, 0, 127001, 2, 7479);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海にはどんな生き物が\\nいるのでしょう～\\n胸が高鳴ります～♪', 1, 1, 1, 0, 0, 127001, 3, 7480);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏は暑いですね…\\nクウカの体が熱いのも\\n夏のせい…ぐふふ…♪', 1, 1, 1, 0, 0, 127001, 4, 7481);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんと無人島に\\n取り残されて…という\\n妄想はかなりイイです', 1, 1, 1, 0, 0, 127001, 5, 7482);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんの\\n欲望に満ちた眼差し…\\nクウカ、受け止めます', 4, 1, 1, 0, 0, 127001, 101, 7483);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行くのが\\n楽しみです…\\nドＳさんと…ぐふふ♪', 8, 1, 1, 0, 0, 127001, 102, 7484);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('「もっと過激な水着を\\n見せてみろよ」なんて\\nいけませんドＳさん…', 1, 1, 2, 0, 0, 127001, 1, 7485);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着のままで\\n踊ればいいのですね…\\nドＳさんの望みなら！', 1, 1, 2, 0, 0, 127001, 2, 7486);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさんの熱い視線を\\n感じます…じゅるり…\\nもっと見てください…', 1, 1, 2, 0, 0, 127001, 3, 7487);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな格好のクウカを\\n放っておくなんて…\\nさすがですドＳさん！', 1, 1, 2, 0, 0, 127001, 4, 7488);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で水着といえば\\n何かが起きる予感…！\\nドＳさんの新たな攻め\\n期待していますね…！', 4, 1, 2, 0, 0, 127001, 101, 7489);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('恥ずかしいですけど\\n頑張っちゃいました\\nドＳさん…こういう\\n水着、好きですか？', 8, 1, 2, 0, 0, 127001, 102, 7490);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな朝からクウカを\\n水着に着替えさせて…\\n本当にドＳさんは\\n欲望に正直ですね！', 1, 1, 2, 0, 1, 127001, 1, 7491);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんな昼間から\\nドＳさんがヌルヌルの\\n液体をクウカに～！\\nえっ…日焼け止め？', 1, 1, 2, 0, 2, 127001, 2, 7492);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドＳさん…これから\\nクウカと夜の海を\\n見に行きませんか？\\nきっと綺麗ですよ…♪', 1, 1, 2, 0, 3, 127001, 3, 7493);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここなら妄想に\\n集中できます～♪\\nじゅるり～♪', 1, 1, 3, 0, 0, 127001, 2, 7495);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こうもかわいいと\\n妄想に登場させるのも\\n気が引けます…', 1, 1, 3, 0, 0, 127001, 3, 7496);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカを昂らせる\\nこの香り…！\\nは！\u3000ドＳさんの罠！', 1, 1, 3, 0, 0, 127001, 4, 7497);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('体を熱くさせて\\n水着を脱がそうと！？\\nテクニカルです…！', 1, 1, 3, 0, 0, 127001, 5, 7498);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クウカの口の中に\\nたくさん…♪\\n止まりません…！', 1, 1, 3, 0, 0, 127001, 7, 7500);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('読書は心が穏やかに\\nなりますね…！\\nぐふふ…穏やかに…', 1, 1, 3, 0, 0, 127001, 8, 7501);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい乗り心地です…♪\\nあっ…普通に楽しんで\\nしまいました…', 1, 1, 3, 0, 0, 127001, 10, 7503);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…\\n妄想に役立ちそうな\\n感触です…！', 1, 1, 3, 0, 0, 127001, 11, 7504);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('成長した自分に\\nあわせて、もっと\\nかっこいいポーズを\\n研究するッス！', 12, 1, 1, 0, 0, 100501, 103, 7505);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからも一緒に\\n最高のヒーローを\\n目指していくッスよ♪', 12, 1, 2, 0, 0, 100501, 103, 7506);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お父さん、娘の\\n水着姿がそんなに\\nうれしいの？', 1, 1, 1, 0, 0, 127101, 1, 7507);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('怖い話を子どもたちに\\n聞かせたら泣かれて\\nしまいました…\\n加減が難しいです…', 1, 1, 1, 0, 0, 127101, 2, 7508);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行くと父が\\n水着の女性ばかり\\n追いかけて困ります…', 1, 1, 1, 0, 0, 127101, 3, 7509);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('拾った貝殻で\\n新しい占いでも\\nはじめてみようかな', 1, 1, 1, 0, 0, 127101, 4, 7510);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('貝殻を耳に当てると\\n波の音が…あっ\\nこれはダメです\\nよくない声がします', 1, 1, 1, 0, 0, 127101, 5, 7511);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この飲み物、スーッと\\n体に沁み込んでくる…\\nあの人にも\\n教えてあげたいです', 4, 1, 1, 0, 0, 127101, 101, 7512);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強い日差しも騒がしい\\n海も苦手なのに\\nあの人となら不思議と\\n楽しく思えるんです', 8, 1, 1, 0, 0, 127101, 102, 7513);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏限定、水と氷を\\n使った特別な占いは\\nいかがですか？', 1, 1, 2, 0, 0, 127101, 1, 7514);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑い日々にはやはり\\n怪談ですね\\n厳選フルコースで\\nお聞かせします', 1, 1, 2, 0, 0, 127101, 2, 7515);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寒気がする？\u3000それは\\n霊ではなくかき氷の\\n食べ過ぎですよ', 1, 1, 2, 0, 0, 127101, 3, 7516);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日の占い、あなたの\\nラッキーパーソンは…\\n白い水着の女性です', 1, 1, 2, 0, 0, 127101, 4, 7517);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの、よければ\\n日焼け止めを塗って\\nもらえませんか？\\n背中は届かなくて…', 4, 1, 2, 0, 0, 127101, 101, 7518);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海に行きませんか？\\n二人きりで静かな\\n砂浜を散歩したいです', 8, 1, 2, 0, 0, 127101, 102, 7519);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('潮騒だけが響く朝の海\\n心が落ち着きます\\nこれから一緒に散歩に\\n行ってみませんか？', 1, 1, 2, 0, 1, 127101, 1, 7520);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不思議です。どうして\\n普通のご飯でも、海で\\n食べると特別おいしく\\n感じるのでしょう…', 1, 1, 2, 0, 2, 127101, 2, 7521);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海に行きませんか\\n今なら夜光虫が\\n見られるかも\\nしれませんよ', 1, 1, 2, 0, 3, 127101, 3, 7522);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏は知らぬ間に体力を\\n消耗しています\\n適度に休息して\\nいきましょう', 1, 1, 3, 0, 0, 127101, 2, 7524);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このぬいぐるみ…\\n大丈夫です\\n何も憑いては\\nいませんよ', 1, 1, 3, 0, 0, 127101, 3, 7525);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほのかにお線香\\nみたいな香り…\\nなんだか\\n落ち着きます', 1, 1, 3, 0, 0, 127101, 4, 7526);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人魂、鬼火\\nセントエルモの火…\\n炎を見ていると色々と\\n連想してしまいます', 1, 1, 3, 0, 0, 127101, 5, 7527);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹を壊さぬよう\\n食い合わせには\\nご注意ください', 1, 1, 3, 0, 0, 127101, 7, 7529);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはいい\\n怪談集ですね…\\nつい読みふけって\\nしまいます', 1, 1, 3, 0, 0, 127101, 8, 7530);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、こういうのに\\n乗るとなんだか\\n子どもに戻った\\nみたいですね', 1, 1, 3, 0, 0, 127101, 10, 7532);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、これは…\\nちょっとメルヘン\\n過ぎて恥ずかしい\\nですね…', 1, 1, 3, 0, 0, 127101, 11, 7533);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本当に素敵なお家…♪\\n騎士たちの人柄を\\n感じられるようで…\\n不思議と落ち着きます', 1, 1, 1, 0, 0, 126501, 1, 7534);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('調度品をつい間食…\\nという習慣がこちらの\\n世界にはないのですね\\n…気をつけないと', 1, 1, 1, 0, 0, 126501, 2, 7535);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手土産のお菓子は\\nどちらに置けば\\nよいでしょうか？', 1, 1, 1, 0, 0, 126501, 3, 7536);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まるでおとぎ話の中に\\n入ってしまったかの\\nよう…別世界とは\\nよく言ったものです', 1, 1, 1, 0, 0, 126501, 4, 7537);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お忍び…ふふっ♪\\nときめく響きです\\nなんだかお茶目で…\\n密やかな印象が', 1, 1, 1, 0, 0, 126501, 5, 7538);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわ…\\nああ、ついあくびが…\\n居心地がよすぎるのも\\n困り物ですね…ふふ♪', 4, 1, 1, 0, 0, 126501, 101, 7539);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士には不思議な力が\\nあるだけでなく\\n何者かの加護が\\nあるようですね…', 8, 1, 1, 0, 0, 126501, 102, 7540);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この『王家の装備』は\\n少し気難しいのです\\nわたし以外が触れると\\nその…ビリビリっと', 1, 1, 2, 0, 0, 126501, 1, 7541);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちに新しい\\n遊びを教わりました♪\\nにーらめっこしましょ\\nあっぷっ…ぷ～っ！', 1, 1, 2, 0, 0, 126501, 2, 7542);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('実は憧れていたのです\\n友人の家を訪ねると\\nいう経験に…ふふっ', 1, 1, 2, 0, 0, 126501, 3, 7543);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぎるどはうす…\\nぎるど活動の拠点だと\\n管理協会？\u3000の方に\\nうかがいました', 1, 1, 2, 0, 0, 126501, 4, 7544);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたは運命を\\n信じますか？\\nわたしは…信じます\\nよい運命だけですが♪', 4, 1, 2, 0, 0, 126501, 101, 7545);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしわたしが本当に\\n天使だったとしたら…\\nどうされますか？\\n…ふふ、冗談です♪', 8, 1, 2, 0, 0, 126501, 102, 7546);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パンケーキの香りで\\n目覚める朝は\\nとても良いものですよ\\nぜひともお試しを♪', 1, 1, 2, 0, 1, 126501, 1, 7547);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひと休みの時間ですね\\n食事にお昼寝…\\nすべきことを行って\\n英気を養いましょう', 1, 1, 2, 0, 2, 126501, 2, 7548);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ休まれては？\\n眠れないようであれば\\n寝物語か子守歌でも\\nふふ、遠慮は無用です', 1, 1, 2, 0, 3, 126501, 3, 7549);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すう………はっ！\\n眠ってはいませんよ？\\nいくら居心地が良い\\nからといって…ふわぁ', 1, 1, 3, 0, 0, 126501, 2, 7551);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まあ、あいらしい…♪\\nぜひわたしの寝室に\\n招待させてください', 1, 1, 3, 0, 0, 126501, 3, 7552);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんて、かぐわしい…\\nオーブンからただよう\\n焼き菓子の香りとは\\nまた異なる魅力が…', 1, 1, 3, 0, 0, 126501, 4, 7553);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みなで暖をとりながら\\n互いに語り笑い合う\\n…心休まる時間ですね', 1, 1, 3, 0, 0, 126501, 5, 7554);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食は心と体に\\nゆとりを生みます\\n…辛い食べ物の場合？\\nそれは、その…', 1, 1, 3, 0, 0, 126501, 7, 7556);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こちらの世界の知識を\\n蓄えておかなければ\\nテーブルマナーに\\nついてのページは…', 1, 1, 3, 0, 0, 126501, 8, 7557);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい色の蛍光ペン\\n買ったのよね\\nこれで勉強が\\n楽しくなるわ～♪', 1, 1, 1, 0, 0, 127201, 1, 7559);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学食のランチ、結構\\nおいしいのよね～\\n今度ペコリーヌに\\n教えてやろうかしら？', 1, 1, 1, 0, 0, 127201, 2, 7560);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふふ…扉に黒板消し\\n仕掛けてるの…あいつ\\n引っかかるかしら？', 1, 1, 1, 0, 0, 127201, 3, 7561);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部活するなら運動部も\\n悪くないかもね～\\n夕日に向かって\\n突っ走ってやるわ！', 1, 1, 1, 0, 0, 127201, 4, 7562);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('毎日窮屈な制服着て\\n学生も大変ね～\\n…ま、かわいいけど', 1, 1, 1, 0, 0, 127201, 5, 7563);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつに貸したノート\\n変な落書きとか\\nしてなかったよね…？\\n…その、相合傘とか…', 4, 1, 1, 0, 0, 127201, 101, 7564);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昨日の家庭科で\\n作ったクッキー…\\nあいつにどうやって\\n渡そうかな…？', 8, 1, 1, 0, 0, 127201, 102, 7565);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宿題教えてって？\\nしょうがないわね～\\nじゃあ一緒に\\nやりましょ', 1, 1, 2, 0, 0, 127201, 1, 7566);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、明日あたしたち\\n日直当番よね？\\nめんどい仕事は\\nあんたに任せるわ～', 1, 1, 2, 0, 0, 127201, 2, 7567);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('寮生活は楽しいけど\\n就寝時間が早すぎよね\\nいきなり消灯されると\\nビックリするわ', 1, 1, 2, 0, 0, 127201, 3, 7568);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('校則で禁止だけど、\\nにけつでほうき通学\\nとか青春っぽくない？', 1, 1, 2, 0, 0, 127201, 4, 7569);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('制服って好きな人とも\\n自然にお揃いになれて\\nいいわよね…って別に\\nあんたとって訳じゃ…', 4, 1, 2, 0, 0, 127201, 101, 7570);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたネクタイ\\n曲がってるわよ～？\\nほら直したげるから\\nこっち向いて？', 8, 1, 2, 0, 0, 127201, 102, 7571);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよ～！\\n今日も元気に登校よ！\\n忘れ物ないようにね！', 1, 1, 2, 0, 1, 127201, 1, 7572);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('午前の授業疲れたわ～\\nしっかりお昼を食べて\\n午後も頑張るわよ！', 1, 1, 2, 0, 2, 127201, 2, 7573);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう…学校の怪談\\n思い出しちゃった…\\n…別に怖くないけど！', 1, 1, 2, 0, 3, 127201, 3, 7574);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか～\\n…気持ち良すぎて\\n制服のまま\\n寝ちゃいそうね…', 1, 1, 3, 0, 0, 127201, 2, 7576);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいくて癒されるわ\\n寮に持ち込んでも\\n大丈夫かしら…？', 1, 1, 3, 0, 0, 127201, 3, 7577);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('集中力の高まる香りで\\n勉強の効率爆上がりね\\n次のテストで\\nいい点取るわよ～！', 1, 1, 3, 0, 0, 127201, 4, 7578);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うう、ちょっと冷えて\\n来たわね…\\nスカートの下に\\nジャージ穿こうかしら', 1, 1, 3, 0, 0, 127201, 5, 7579);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐっ…もぐっ…\\n食べとかないと教室で\\nお腹なっちゃうわ～', 1, 1, 3, 0, 0, 127201, 7, 7581);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('図書室で借りた本\\n明日返却日なのよね…\\n今日中に読むわよ！', 1, 1, 3, 0, 0, 127201, 8, 7582);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつに背中を\\n預けるのもいい気分だ\\nいつかは、全部…', 12, 1, 1, 0, 0, 104301, 103, 7584);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('な、なんだよ？\\nじっと見るんじゃねぇ\\n尻尾が揺れちまうだろ', 12, 1, 2, 0, 0, 104301, 103, 7585);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法の練習！\\nむむむ～…\\nそれっ…！', 1, 1, 1, 0, 0, 127301, 1, 7586);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そだ！\u3000これ着て\\nルー学行こっかな？\u3000\\n制服自慢しちゃお♪', 1, 1, 1, 0, 0, 127301, 2, 7587);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('赤点回避の魔法とか\\nあったら最高じゃね？\\n誰かうちに教えて～', 1, 1, 1, 0, 0, 127301, 3, 7588);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('制服が一番映える\\n場所ってどこだろ？\\n教室？\u3000遊園地？', 1, 1, 1, 0, 0, 127301, 4, 7589);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ベンキョーつらたん…\\n今度キャルっちに\\n助けてもらお', 1, 1, 1, 0, 0, 127301, 5, 7590);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部活か…\\nヒデサイと一緒に\\nやったら楽し～かも♪', 4, 1, 1, 0, 0, 127301, 101, 7591);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('男子の制服\\nもにカワだった…\\n今度ヒデサイに\\n借りよっかな？', 8, 1, 1, 0, 0, 127301, 102, 7592);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょすー、うちの\\nさいきょー魔法で\\nテンアゲしてあげる～', 1, 1, 2, 0, 0, 127301, 1, 7593);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('九九って呪文ぽくね？\\nほら、例えばヒチシ…\\nヒチシ、なんだっけ？', 1, 1, 2, 0, 0, 127301, 2, 7594);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイセンセー\\nうちにベンキョー\\n教えて！', 1, 1, 2, 0, 0, 127301, 3, 7595);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学割マジ助かるー\\nヒデサイ、一緒に\\nどんどん使ってこー♪', 1, 1, 2, 0, 0, 127301, 4, 7596);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度ヒデサイに\\nお弁当作ったげる\\n屋上で一緒に食べよ♪', 4, 1, 2, 0, 0, 127301, 101, 7597);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒデサイのバイブス\\n上がる言葉教えてよ\\nつらたんな時、うちが\\nいっぱい言ったげるよ', 8, 1, 2, 0, 0, 127301, 102, 7598);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちょすちょす～\\n今日も朝から\\nバイブス十分♪', 1, 1, 2, 0, 1, 127301, 1, 7599);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼どうしよっかな\\nたまにはガッツリ\\nいっちゃう系？', 1, 1, 2, 0, 2, 127301, 2, 7600);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やべ、宿題まだ\\nできてないし…\\nヒデサイ助けて～', 1, 1, 2, 0, 3, 127301, 3, 7601);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('充電ちう～\\n…ガッコーのイスも\\nこれにして～', 1, 1, 3, 0, 0, 127301, 2, 7603);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいし、\\n癒されるし、キュン死\\nしちゃうじゃん…！', 1, 1, 3, 0, 0, 127301, 3, 7604);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リフレッシュの\\n魔法発見！\\nいい香り～♪', 1, 1, 3, 0, 0, 127301, 4, 7605);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽかぽかサイコー♪\\n今日はもーずーっと\\nここにいたいかも～', 1, 1, 3, 0, 0, 127301, 5, 7606);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('超おいし～♪\\n学食にあったら\\n毎日リピする～', 1, 1, 3, 0, 0, 127301, 7, 7608);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nねむみパない…\\n続きはまた今度～', 1, 1, 3, 0, 0, 127301, 8, 7609);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度は子どもたちも\\nサラサリアに連れて\\n行ってあげたいわ', 1, 1, 1, 0, 0, 127501, 1, 7611);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('子どもたちから\\nお姫さまみたいって\\n言われちゃった♪', 1, 1, 1, 0, 0, 127501, 2, 7612);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この剣…火を点けたり\\nするのに便利なのよ\\nコントロールも効くし', 1, 1, 1, 0, 0, 127501, 3, 7613);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのサラサリアの\\nカラっとした暑さが\\nちょっと恋しいわ…', 1, 1, 1, 0, 0, 127501, 4, 7614);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('買ってきたお土産、\\nお世話になってる\\nみんなに配りましょ♪', 1, 1, 1, 0, 0, 127501, 5, 7615);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと一緒なら\\nどこの国でだって\\n暮らしていけそうね♪', 4, 1, 1, 0, 0, 127501, 101, 7616);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今の事業を大きくして\\nあんたと世界中の国を\\n飛び回ったり…なんて\\nすてきじゃない？', 8, 1, 1, 0, 0, 127501, 102, 7617);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアで食べた\\n料理が恋しい…？\\nもう…また今度\\n作ってあげるわよ', 1, 1, 2, 0, 0, 127501, 1, 7618);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度旅行するなら\\nどこに行こうかしら？\\n希望があれば教えてね', 1, 1, 2, 0, 0, 127501, 2, 7619);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアの香辛料、\\nランドソルでも\\n人気が出そうよね\\nいいビジネスの予感！', 1, 1, 2, 0, 0, 127501, 3, 7620);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなにじっと\\n見られるとさすがに\\n恥ずかしいってば…', 1, 1, 2, 0, 0, 127501, 4, 7621);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お嫁さんは憧れるけど\\nお婿さんになって\\nもらうのもありよね…\\nあんたはどう思う？', 4, 1, 2, 0, 0, 127501, 101, 7622);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やっぱり、あんたには\\nいつもあたしの隣に\\n居てほしいな…', 8, 1, 2, 0, 0, 127501, 102, 7623);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('陽射しが強くなる前に\\n雑多な用事は\\n片付けちゃいましょ', 1, 1, 2, 0, 1, 127501, 1, 7624);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアで食べた\\n料理を再現してみたの\\n味見してくれる？', 1, 1, 2, 0, 2, 127501, 2, 7625);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑さに負けないように\\n睡眠はちゃんと\\n取っておかないと', 1, 1, 2, 0, 3, 127501, 3, 7626);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こっちでもあっちでも\\n忙しいのは変わらない\\nわね…ちょっと休憩～', 1, 1, 3, 0, 0, 127501, 2, 7628);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアで見た\\nぬいぐるみも\\nかわいかったわね', 1, 1, 3, 0, 0, 127501, 3, 7629);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お香って地域ごとの\\n特色が出るわよね\\nこの香りは…\\nちょっと神秘的？', 1, 1, 3, 0, 0, 127501, 4, 7630);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂漠地方も夜は冷える\\nのよね。温かいものが\\nあると安心するわ…♪', 1, 1, 3, 0, 0, 127501, 5, 7631);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ慣れた味って\\nどうしてほっと\\nするのかしら…', 1, 1, 3, 0, 0, 127501, 7, 7633);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今後の取引相手に\\nなるかもしれないし\\n向こうの文化も\\n勉強しておかないと…', 1, 1, 3, 0, 0, 127501, 8, 7634);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('犯人はこの中にいる！\\n探偵として一度は\\n言ってみたいセリフさ', 12, 1, 1, 0, 0, 101401, 103, 7636);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんの情報を\\n仕入れておかないと…\\n理想の私を、ずっと\\n見ていてほしいからね', 12, 1, 2, 0, 0, 101401, 103, 7637);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('久々の長旅で\\n里心がついちまったね\\nしばらくランドソルで\\nのんびりしようか', 1, 1, 1, 0, 0, 127601, 1, 7638);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまには違う服装\\n違う得物を使うのも\\n悪くないね', 1, 1, 1, 0, 0, 127601, 2, 7639);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアにいた時は\\n砂まみれで大丈夫かと\\n思ってたけど、今じゃ\\n懐かしく感じるよ', 1, 1, 1, 0, 0, 127601, 3, 7640);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魔法の絨毯、あれは\\n楽だし速いし便利\\nだったねえ…土産に\\n一枚欲しかったな', 1, 1, 1, 0, 0, 127601, 4, 7641);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('砂上での戦いは\\nなかなかいい鍛錬に\\nなったね…今度は\\n修行しに行くとしよう', 1, 1, 1, 0, 0, 127601, 5, 7642);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サラサリアの人たちも\\n気のいい連中だったが\\n元気にやってるかねえ', 4, 1, 1, 0, 0, 127601, 101, 7643);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅の恥はかき捨てって\\nいうけど、悪い旅じゃ\\nなかったね。次は\\nアイツとどこに行こう', 8, 1, 1, 0, 0, 127601, 102, 7644);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この格好を冷やかしに\\n来たのかい？\\n生憎、もうすっかり\\n慣れちまったよ', 1, 1, 2, 0, 0, 127601, 1, 7645);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ギルドの連中に\\n土産をわたしに\\n行くところなんだ\\n付き合っておくれよ', 1, 1, 2, 0, 0, 127601, 2, 7646);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('久々に水場で\\n釣りがしたいねえ…\\nもちろんお前さんも\\nくるんだろう？', 1, 1, 2, 0, 0, 127601, 3, 7647);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっと\\nサラサリアの連中から\\n便りが来てるよ\\nさ、一緒に読もうか', 1, 1, 2, 0, 0, 127601, 4, 7648);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近サラサリアの踊り\\nを練習してるんだ\\nあとで振付けを\\n見ておくれよ', 4, 1, 2, 0, 0, 127601, 101, 7649);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんだいお前さん？\\n…なんだか若奥さん\\nっぽいって？\u3000まあ、\\nそりゃあ、ねえ…', 8, 1, 2, 0, 0, 127601, 102, 7650);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい時間だね\\n日が昇りきる前に\\nやることをすませ\\nとかないと', 1, 1, 2, 0, 1, 127601, 1, 7651);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼はどうしようかね\\nサラサリア風の\\n食事でもつくろうか', 1, 1, 2, 0, 2, 127601, 2, 7652);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さて、早めに寝ようか\\n砂漠の夜は冷えるから\\n…っと、まだ旅行中の\\n気分でいたよ', 1, 1, 2, 0, 3, 127601, 3, 7653);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('良い座り心地だ\\nサラサリア宮殿の\\n応接間を\\n思い出すねえ…', 1, 1, 3, 0, 0, 127601, 2, 7655);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ランプの魔神に\\nあげたら喜ぶかねえ？\\n次に会う時までに\\n見繕ってみようか', 1, 1, 3, 0, 0, 127601, 3, 7656);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この香り…\\nサラサリア土産の\\n香木かい？', 1, 1, 3, 0, 0, 127601, 4, 7657);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旅先での焚火を\\n思い出すよ\\nなんだかほっとするね', 1, 1, 3, 0, 0, 127601, 5, 7658);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふ、慣れてる味も\\nいいけど、むこうの\\n味付けが懐かしく\\nなっちまうね', 1, 1, 3, 0, 0, 127601, 7, 7660);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\n千夜一夜物語か\\nおもしろいもんだねえ', 1, 1, 3, 0, 0, 127601, 8, 7661);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('立派なギルドハウス♪\\n帰る場所が素敵だと\\n冒険に出るのも\\n楽しくなりそうです♪', 1, 1, 1, 0, 0, 126001, 1, 7663);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お掃除でも…と\\n思いましたけど、\\nさすがお兄さんのお家\\nきれいにしてますね♪', 1, 1, 1, 0, 0, 126001, 2, 7664);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたしたちもいつか\\n立派なギルドハウスが\\n持てる冒険者に\\nなりたいです…♪', 1, 1, 1, 0, 0, 126001, 3, 7665);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたし冒険者ですけど\\n家を守ってお兄さんの\\n帰りを待つのも\\n悪くない…かも？', 1, 1, 1, 0, 0, 126001, 4, 7666);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お菓子焼こうかな…♪\\nちょっと多めに作って\\nお兄さんにも\\n食べてもらおうっと♪', 1, 1, 1, 0, 0, 126001, 5, 7667);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このお家、とっても\\n大好きになりました♪\\nだからその…もう少し\\nいてもいいですか…？', 4, 1, 1, 0, 0, 126001, 101, 7668);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんに\\n感謝の手紙を書いて\\n枕元に隠して\\nおこうかな…♪', 8, 1, 1, 0, 0, 126001, 102, 7669);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…お兄さん\\nお暇なんですか？\\nじゃあ一緒に冒険へ\\n出かけましょう♪', 1, 1, 2, 0, 0, 126001, 1, 7670);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんは苦手な食材\\nとかありますか？\\nあの、もしよければ\\n今から手料理を…♪', 1, 1, 2, 0, 0, 126001, 2, 7671);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まったり過ごす\\nお家時間もいいですね\\n冒険者には羽休めも\\n大事ですから♪', 1, 1, 2, 0, 0, 126001, 3, 7672);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつでもお兄さんを\\n守れるように\\nこの姿でいることに\\n慣れておきますね…！', 1, 1, 2, 0, 0, 126001, 4, 7673);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さん眠そうです…\\nちょっとお昼寝\\nしちゃいましょうか♪\\nはい、膝枕…♪', 4, 1, 2, 0, 0, 126001, 101, 7674);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さん怪我を…！？\\nわたしが治療を…\\nふー…ふー…', 8, 1, 2, 0, 0, 126001, 102, 7675);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\n朝、元気に挨拶すれば\\n幸せな一日が過ごせる\\nそうですよ♪', 1, 1, 2, 0, 1, 126001, 1, 7676);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ごはんの時間です\\n…手がふさがってる？\\nわかりました、じゃあ\\nあ～んしますね♪', 1, 1, 2, 0, 2, 126001, 2, 7677);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわぁ…眠くなって\\nきちゃいました…\\nお兄さん…お泊りして\\nいいですか…？', 1, 1, 2, 0, 3, 126001, 3, 7678);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふにゃ～～…♪\\nこんな姿、他の人には\\n見せられません…♪\\nもふもふ～～…♪', 1, 1, 3, 0, 0, 126001, 2, 7680);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんこういうの\\n好きなのかな～…\\nふふっ、わたしも♪\\nぎゅ～～～っ♪', 1, 1, 3, 0, 0, 126001, 3, 7681);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アロマの癒し効果…\\n上手くアレンジして\\nみなさんの治療に\\n活かせないかな～？', 1, 1, 3, 0, 0, 126001, 4, 7682);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は～気持ちいい～♪\\n身体が暖まると\\n心もぽかぽかです♪', 1, 1, 3, 0, 0, 126001, 5, 7683);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うふふ、おいしい♪\\nプレシアちゃんなら\\n無限にぱくぱく～って\\nしちゃいそうです…♪', 1, 1, 3, 0, 0, 126001, 7, 7685);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本はわたしを\\n知らない世界に\\n連れていってくれる…\\nまるでお兄さんです♪', 1, 1, 3, 0, 0, 126001, 8, 7686);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('話題の新刊…\\nあの人も読んでるかな\\n今度会う時、感想\\n聞いてみたいな…♪', 12, 1, 1, 0, 0, 103801, 103, 7688);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うにゃっ…あ、熱を\\n測ってくれたんですか\\nありがとうございます\\nバッチリ元気ですよ♪', 12, 1, 2, 0, 0, 103801, 103, 7689);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄の、けはい…\\nん、みつけた\\nぎゅ', 1, 1, 1, 0, 0, 126101, 1, 7690);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きょろきょろ\\nここも\\nぱとろる、するよ', 1, 1, 1, 0, 0, 126101, 2, 7691);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おうち\\nにぎやか\\nさみしく、ない', 1, 1, 1, 0, 0, 126101, 3, 7692);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きょだい、おにぎり\\nきょだい、肉まん\\nきょだい…お兄？', 1, 1, 1, 0, 0, 126101, 4, 7693);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はっぴーちゃん\\nどこ？\\nお兄、たべた？', 1, 1, 1, 0, 0, 126101, 5, 7694);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…この、へや\\nお兄の、におい\\nすんでる\\nすめる？', 4, 1, 1, 0, 0, 126101, 101, 7695);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おそうじ、にがて\\nでも\\nれんしゅう\\nきゅっきゅ', 8, 1, 1, 0, 0, 126101, 102, 7696);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みみ、さわり、たい？\\nんー…だめ…\\nむずむず\\nなので', 1, 1, 2, 0, 0, 126101, 1, 7697);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くろぷれしあ\\nかっこいい？\\nん…あざます', 1, 1, 2, 0, 0, 126101, 2, 7698);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄の、おうち\\nきょうみ、ましまし\\nたんけん\\nするね', 1, 1, 2, 0, 0, 126101, 3, 7699);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なでなで、される…と\\nねむ…く…\\nぶぅ…ぶぅ…ぶぅ…', 1, 1, 2, 0, 0, 126101, 4, 7700);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かみ、りぼん\\nおてつだい\\nよろ\\nです', 4, 1, 2, 0, 0, 126101, 101, 7701);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここ\\nすむ\\nね？\\nまいにち、いっしょ', 8, 1, 2, 0, 0, 126101, 102, 7702);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐっもにん\\nあさごはん\\nあさごはん', 1, 1, 2, 0, 1, 126101, 1, 7703);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄\\nおつかれ？\\nれっつ、まいぺーす', 1, 1, 2, 0, 2, 126101, 2, 7704);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひとりで、ねれる\\nでも\\nひとりじゃ、なくても\\nねれる、よ…？', 1, 1, 2, 0, 3, 126101, 3, 7705);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふかふか\\nパパの、おなか\\nみたい', 1, 1, 3, 0, 0, 126101, 2, 7707);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんにちは\\nぷれしあ、です\\nおともだち、なろ？', 1, 1, 3, 0, 0, 126101, 3, 7708);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい、におい\\nでも、お兄\\nもっと、いい、におい', 1, 1, 3, 0, 0, 126101, 4, 7709);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とりま\\nお肉、やこ', 1, 1, 3, 0, 0, 126101, 5, 7710);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nむげん肉まん、も\\nきぼう', 1, 1, 3, 0, 0, 126101, 7, 7712);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぜんぶ、よんだ\\nもっと、ぶあついほん\\nでも、いーよ？', 1, 1, 3, 0, 0, 126101, 8, 7713);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('幸せなクリスマスを\\n過ごすため\\nギルドハウスを\\nきれいにしなくちゃ♪', 1, 1, 1, 0, 0, 127901, 1, 7715);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('えへへ♪\\n彼へのプレゼント…\\n枕元にそっと\\nおいておきましょう☆', 1, 1, 1, 0, 0, 127901, 2, 7716);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスといえば\\n七面鳥の丸焼き…☆\\nよだれを拭いて\\nいざ準備です♪', 1, 1, 1, 0, 0, 127901, 3, 7717);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼に用意した\\nプレゼント…\\n大きすぎて\\nくつ下に入りません…', 1, 1, 1, 0, 0, 127901, 4, 7718);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントは\\n貰う方も、贈る方も\\nどちらも幸せを\\n感じますね…☆', 1, 1, 1, 0, 0, 127901, 5, 7719);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜景が見える\\nレストランであの人と\\nクリスマスデート…\\n憧れちゃいますね☆', 4, 1, 1, 0, 0, 127901, 101, 7720);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('プレゼントはわたし…\\n恥ずかしいですけど\\nこの贈り物、彼に\\n喜んでほしいです…☆', 8, 1, 1, 0, 0, 127901, 102, 7721);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オーナメントを\\nたくさん用意したので\\n二人でツリーに\\n飾りつけましょう☆', 1, 1, 2, 0, 0, 127901, 1, 7722);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あはは、お腹\\n空いちゃいました？\\nパーティーまで\\n我慢してください♪', 1, 1, 2, 0, 0, 127901, 2, 7723);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ジングルベ～ル♪\\nあなたも一緒に\\nクリスマスソング\\n歌っちゃいましょう♪', 1, 1, 2, 0, 0, 127901, 3, 7724);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('サプライズプレゼント\\nの用意をして…って\\nあなた！？\u3000い、今の\\n聞いてませんよね…？', 1, 1, 2, 0, 0, 127901, 4, 7725);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('クリスマスの夜は\\nパーティーしましょう\\nできれば…その…\\n二人っきりで…☆', 4, 1, 2, 0, 0, 127901, 101, 7726);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたと過ごした\\n最高のクリスマス…\\nずっとずっと心の奥に\\nしまっておきますね', 8, 1, 2, 0, 0, 127901, 102, 7727);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます！\\n皆の願いが叶うような\\n素敵な一日に\\nしましょうね☆', 1, 1, 2, 0, 1, 127901, 1, 7728);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ですね！\\nディナーの買い出しが\\n済んだら、少しお昼寝\\nしちゃいましょうか☆', 1, 1, 2, 0, 2, 127901, 2, 7729);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ就寝の\\n時間ですね～\\n枕元にくつ下の準備を\\nお忘れなく～☆', 1, 1, 2, 0, 3, 127901, 3, 7730);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふ～気持ちいい…☆\\nお家でまったり過ごす\\nクリスマスも\\nいいですよね…♪', 1, 1, 3, 0, 0, 127901, 2, 7732);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいですね～♪\\nサンタさんからの\\n贈り物でしょうか～？', 1, 1, 3, 0, 0, 127901, 3, 7733);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('すう～…はあ～…\\nすごく素敵な香り…\\n炊き立てのご飯と\\nいい勝負です…♪', 1, 1, 3, 0, 0, 127901, 4, 7734);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かいですけど…\\nあの日の山小屋を\\n思い出して\\n恥ずかしいですね…☆', 1, 1, 3, 0, 0, 127901, 5, 7735);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むしゃむしゃもぐもぐ\\n止まりませんよ\\nクリスマスですから\\nむしゃむしゃもぐもぐ', 1, 1, 3, 0, 0, 127901, 7, 7737);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('物語に出てくる\\nサンタさんみたいに\\nわたしも幸せを\\n運びたいです…☆', 1, 1, 3, 0, 0, 127901, 8, 7738);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっ！\\nこ…これは素敵な\\nサプライズプレゼント\\nですね…☆', 1, 1, 3, 0, 0, 127901, 14, 7740);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これを着ればわたしも\\n立派なサンタさんに\\nなれますかね…？', 1, 1, 3, 0, 0, 127901, 15, 7741);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここが今のあたしの\\n居場所ってやつです\\nふふっ、なかなか\\n悪くねー気分ですよ', 12, 1, 1, 0, 0, 106601, 103, 7742);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これからはボス代行\\nとしてブイブイ\\nいわせてやるです\\nついてくるですよ！', 12, 1, 2, 0, 0, 106601, 103, 7743);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('陛下～♪\\n貴女のクレジッタが\\nおめかしして\\nはせ参じましたわ～♪', 1, 1, 1, 0, 0, 128001, 1, 7744);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パーティーとは景気の\\n良さを見せつける場…\\n倹約などは\\nもっての外でしてよ！', 1, 1, 1, 0, 0, 128001, 2, 7745);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この天井の高さなら\\n搬入できそうですわね\\n陛下用の特注ケーキ♪', 1, 1, 1, 0, 0, 128001, 3, 7746);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ぶぇっくしゅ！\\nふう…少し背中を\\n開けすぎたかしら…？', 1, 1, 1, 0, 0, 128001, 4, 7747);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは秘書の目も\\n届きませんから\\nチクりメモの心配も\\nありませんのよね～♪', 1, 1, 1, 0, 0, 128001, 5, 7748);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いくらでも二度見して\\nよろしくてよ？\\n本当にわたくしだと\\n心から納得できるまで', 4, 1, 1, 0, 0, 128001, 101, 7749);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('袖の下以外の贈り物も\\nなかなかどうして…\\n悪くないものですのね', 8, 1, 1, 0, 0, 128001, 102, 7750);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こう見えてダンスの\\nたしなみはありますの\\nお相手してあげても\\nよろしくってよ', 1, 1, 2, 0, 0, 128001, 1, 7751);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ドレスはもちろん\\n特注品ですわ♪\\nもしや貸衣装だと\\n思いまして？', 1, 1, 2, 0, 0, 128001, 2, 7752);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('バッグの中身？\\n仕事に必要なものと…\\n心を潤わせるための\\n宝石がいくつか♪', 1, 1, 2, 0, 0, 128001, 3, 7753);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やる気というものは\\n仕事に必要な条件です\\nいわばドレスコードの\\nようなものですわね', 1, 1, 2, 0, 0, 128001, 4, 7754);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('全ての仕事は自分の\\n血となり肉となり\\nお金にもなるもの\\nなのです。経験談です', 4, 1, 2, 0, 0, 128001, 101, 7755);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今年の教訓を活かして\\n来年は更に素晴らしい\\nクリスマスにして\\n差し上げますわ！', 8, 1, 2, 0, 0, 128001, 102, 7756);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます\\n今日という稼ぎ時の\\nはじまりですわよ！', 1, 1, 2, 0, 1, 128001, 1, 7757);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('安くて早くておいしい\\nそれがランチに必須の\\n栄養素ですわ！', 1, 1, 2, 0, 2, 128001, 2, 7758);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('宵越しの仕事は\\n安眠の敵！\\n熟睡したいのであれば\\n今が勝負時ですわよ！', 1, 1, 2, 0, 3, 128001, 3, 7759);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たまにはこうして\\n休息を取ることも…\\n…はっ！？\\nドレスにシワが～っ！', 1, 1, 3, 0, 0, 128001, 2, 7761);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…わたくしの勘が\\n言っていますわ\\nこの愛らしさ！\\n爆売れ確・定！', 1, 1, 3, 0, 0, 128001, 3, 7762);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りですわね…\\nお金の匂いには\\n敵いませんけれども♪', 1, 1, 3, 0, 0, 128001, 4, 7763);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('……ハッ！？\\n完全にボーッとして\\nしまいましたわ…！\\nぬくもり…恐ろしい！', 1, 1, 3, 0, 0, 128001, 5, 7764);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('考えませんわ…\\n考えませんわよ！\\nカロリーのことはっ！', 1, 1, 3, 0, 0, 128001, 7, 7766);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビジネス本以外の本を\\n読むのも、たまには\\n悪くありませんわね…', 1, 1, 3, 0, 0, 128001, 8, 7767);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よくできていますわね\\nこの絵本！\\n子ども向けだと甘く\\n見ていましたわ…！', 1, 1, 3, 0, 0, 128001, 14, 7769);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この視界の狭さ…\\n思い出しますわね\\nティッシュ配りの\\nアルバイト時代を…', 1, 1, 3, 0, 0, 128001, 15, 7770);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふふ…こっそり\\nスイーツを食べる\\nリノちゃん見～っけ♪', 1, 1, 1, 0, 0, 128101, 1, 7771);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんの抜き打ち\\nお部屋チェック～♪\\n…ケーキの食べこぼし\\nこれはリノちゃんだね', 1, 1, 1, 0, 0, 128101, 2, 7772);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装は目立つから\\nどこにいても弟くんに\\n気付いてもらえるね！', 1, 1, 1, 0, 0, 128101, 3, 7773);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くん、協力して！\\nリノちゃんにお勉強\\nしなさいって圧を\\nかけるんだよっ…♪', 1, 1, 1, 0, 0, 128101, 4, 7774);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絆の力を感じるよ\\nこれならもっと万全な\\n弟くんのお世話が\\nできそうだねっ！', 1, 1, 1, 0, 0, 128101, 5, 7775);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんもたまには\\nリノちゃんみたいに\\n甘えてみようかな…', 4, 1, 1, 0, 0, 128101, 101, 7776);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんとリノちゃん\\nどっちも大切な\\n私のきょうだいだよ', 8, 1, 1, 0, 0, 128101, 102, 7777);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('分かってるよ♪\\nお姉ちゃんの膝枕を\\nご所望だねっ？\u3000え？\\n違う？\u3000違わないよ？', 1, 1, 2, 0, 0, 128101, 1, 7778);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リノちゃんがね\\nお姉ちゃんチョップを\\n防ぐ妹白刃取りを\\n訓練してるんだよね', 1, 1, 2, 0, 0, 128101, 2, 7779);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃん頭突きは\\n封印しないとね…\\nだって、今使うと\\n頭飾りで威力が…ね', 1, 1, 2, 0, 0, 128101, 3, 7780);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ♪\\n目をつぶってても\\n弟くんは見えてるよ\\n…そこでしょ？', 1, 1, 2, 0, 0, 128101, 4, 7781);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんも\\nリノちゃんみたいに\\nかわいさいっぱいに\\n振舞っちゃうぞ♪', 4, 1, 2, 0, 0, 128101, 101, 7782);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弟くんっ♪\\nいつもお姉ちゃんの\\n声が届く範囲にいてね\\n…絶対だよ', 8, 1, 2, 0, 0, 128101, 102, 7783);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう、弟くん！\\nリノちゃんが起こして\\nくれたんだね♪\\n…先を越されちゃった', 1, 1, 2, 0, 1, 128101, 1, 7784);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんランチの\\n時間だぞ♪\\nさ、食べさせてあげる\\nお口を開けて…♪', 1, 1, 2, 0, 2, 128101, 2, 7785);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやすみの時間だよ\\n…弟くんは真ん中ね\\n左右には私たち姉妹が\\nいるから安心だよ♪', 1, 1, 2, 0, 3, 128101, 3, 7786);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんは全力で\\nリラックスしてても\\n弟くんの声一つで\\nすぐにでも動けるよ♪', 1, 1, 3, 0, 0, 128101, 2, 7788);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('リノちゃんこういうの\\n好きそうだよね\\n今度プレゼントして\\nみようかな？', 1, 1, 3, 0, 0, 128101, 3, 7789);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい匂いがするね～\\nあれ？\\nリノちゃんのケーキの\\n甘い匂いも混ざってる', 1, 1, 3, 0, 0, 128101, 4, 7790);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんの\\n弟くんへの愛も\\n熱く燃えあがるね…！', 1, 1, 3, 0, 0, 128101, 5, 7791);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('たくさん食べて\\n栄養を補給して\\nお姉ちゃん力に\\n全て変換するよっ！', 1, 1, 3, 0, 0, 128101, 7, 7793);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ことわざ辞典…\\nリノちゃんにこれを\\n読ませようかな', 1, 1, 3, 0, 0, 128101, 8, 7794);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろ～り、そろり…\\nお姉ちゃんが居ぬ間に\\nスイーツを～…♪', 1, 1, 1, 0, 0, 128201, 1, 7797);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか\\nお姉ちゃんに似合う服\\n作ってみたいですね', 1, 1, 1, 0, 0, 128201, 2, 7798);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいたっ！？\\nひらひらしたとこ\\n踏んづけちゃいました', 1, 1, 1, 0, 0, 128201, 3, 7799);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんと\\nお兄ちゃんの二人から\\n勉強しろって圧力が～', 1, 1, 1, 0, 0, 128201, 4, 7800);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私の中にも秘めた力が\\n眠っているはず…\\nそう、妹パワーが', 1, 1, 1, 0, 0, 128201, 5, 7801);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私もお兄ちゃんを\\n甘やかしてみたいです\\n…お姉ちゃんみたいに', 4, 1, 1, 0, 0, 128201, 101, 7802);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんの部屋を\\nこっそり拝見～♪\\nはっ！？\u3000これは\\nお姉ちゃんの視線…！', 8, 1, 1, 0, 0, 128201, 102, 7803);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃん頭突きは\\n大地を揺らす威力です\\n私とお兄ちゃんは\\n挨拶感覚で喰らいます', 1, 1, 2, 0, 0, 128201, 1, 7804);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんチョップは\\n雲を裂く切れ味です\\n早く妹白刃取りを\\n完成させないと…', 1, 1, 2, 0, 0, 128201, 2, 7805);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんみたいに\\n大人っぽく着こなす\\nには一体どうしたら…', 1, 1, 2, 0, 0, 128201, 3, 7806);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('弓のデザインも\\nかわいいんですよっ♪\\n常に持ち歩きたいです\\nけど…危ないですよね', 1, 1, 2, 0, 0, 128201, 4, 7807);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きれいな服を着てると\\nお姫さま気分に\\nなれますね…あとは\\n王子さまがいれば…♪', 4, 1, 2, 0, 0, 128201, 101, 7808);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄ちゃんっ！\\n私は褒められて伸びる\\nタイプなのでもっと\\nナデナデしてください', 8, 1, 2, 0, 0, 128201, 102, 7809);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('妹モーニングコール♪\\nお姉ちゃんより先に\\n起こしに来れました！', 1, 1, 2, 0, 1, 128201, 1, 7810);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ああっ、お姉ちゃん！\\nお兄ちゃんにアーン\\nするなんてずるいです\\n私もしたいですっ！', 1, 1, 2, 0, 2, 128201, 2, 7811);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやすみの時間ですね\\nえへへ、きょうだいで\\n並んで寝るのって\\n楽しいですよね！', 1, 1, 2, 0, 3, 128201, 3, 7812);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スイーツを食べた後は\\nお腹を休めましょう～\\n平気平気…ちゃぁんと\\n運動もしますからぁ…', 1, 1, 3, 0, 0, 128201, 2, 7814);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お姉ちゃんも\\nこういうかわいいもの\\n好きなんですかね', 1, 1, 3, 0, 0, 128201, 3, 7815);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('くんくん…\\nなんの匂いでしょうか\\n新しいスイーツ？', 1, 1, 3, 0, 0, 128201, 4, 7816);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きょうだい３人\\n肩を寄せて暖まるとか\\nよくないですかっ？', 1, 1, 3, 0, 0, 128201, 5, 7817);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつも元気な妹で\\nいるためには\\nよく食べるのが大事！', 1, 1, 3, 0, 0, 128201, 7, 7819);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんか姉に関する本が\\nちらほらと混ざって…\\nこれお姉ちゃんの\\n仕業ですね！？', 1, 1, 3, 0, 0, 128201, 8, 7820);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふんふ～ん\\nお正月で世間は\\n浮かれてるですねえ\\nま、いいですけど♪', 1, 1, 1, 0, 0, 128301, 1, 7823);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('は～、お正月は\\nだらだらできて\\n最高ですね\\n…いつも通りですけど', 1, 1, 1, 0, 0, 128301, 2, 7824);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ビッグな幹部は\\nビッグなお年玉が\\nもらえるはずです\\n楽しみですね', 1, 1, 1, 0, 0, 128301, 3, 7825);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度ドラちゃんに\\nお年玉を持っていって\\nやりたいですね', 1, 1, 1, 0, 0, 128301, 4, 7826);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そういえばアユアユと\\n約束してたですよ…\\nそろそろ出かける\\nですかね', 1, 1, 1, 0, 0, 128301, 5, 7827);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お年玉がもらえたら\\n何に使うか…\\n今のうちに\\n考えとくです', 4, 1, 1, 0, 0, 128301, 101, 7828);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年神の報酬の駄菓子が\\nたまってきたですね…\\nガキどもにでも\\n配っちまうですよ', 8, 1, 1, 0, 0, 128301, 102, 7829);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしのレアな\\n晴れ着姿、今のうちに\\nしっかり目に焼き付け\\nとくがいいですよ', 1, 1, 2, 0, 0, 128301, 1, 7830);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お兄さんは今日も\\nヒマそうですねぇ…\\nしょうがないから\\nかまってやるですよ', 1, 1, 2, 0, 0, 128301, 2, 7831);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そういえばカヤぴぃ\\n見なかったですか？\\n喧嘩屋初売りセール\\nとか言ってたですけど', 1, 1, 2, 0, 0, 128301, 3, 7832);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月ならではの\\n大きなシノギ…\\nなにかないですかね？', 1, 1, 2, 0, 0, 128301, 4, 7833);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいとこに来たですよ\\nさっき走ったら帯が\\n曲がっちゃったです\\n直すの手伝うです！', 4, 1, 2, 0, 0, 128301, 101, 7834);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('年神の仕事ですか？\\nこれからいくとこです\\nお兄さんも一緒に\\n来やがるですよ！', 8, 1, 2, 0, 0, 128301, 102, 7835);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁあ…\\nどうしたですか？\\nお正月に早起きなんて\\n無粋ってヤツですよ…', 1, 1, 2, 0, 1, 128301, 1, 7836);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('小腹が減ったですね\\n一緒におせちでも\\nつつきにいくですよ！', 1, 1, 2, 0, 2, 128301, 2, 7837);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜はあたしの時間\\nと言いたいとこですが\\n初夢のために早く\\n寝とくですかね…', 1, 1, 2, 0, 3, 128301, 3, 7838);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('正月は食っちゃ寝\\nするのが仕事…\\nって聞いたこと\\nあるですよ', 1, 1, 3, 0, 0, 128301, 2, 7840);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふふっ、晴れ着の\\nあたしの次くらいには\\nかわいいですね', 1, 1, 3, 0, 0, 128301, 3, 7841);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんかいい匂い…？\\nよく知らんですけど\\n晴れ着からも同じ\\n匂いがしてるですね…', 1, 1, 3, 0, 0, 128301, 4, 7842);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふ～あったまるです…\\nお正月の唯一の弱点は\\n寒いことですからね…', 1, 1, 3, 0, 0, 128301, 5, 7843);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…正月太り？\\nあたしには関係ない\\n言葉ですね', 1, 1, 3, 0, 0, 128301, 7, 7845);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったあった…\\nトーゴクには\\nドラゴンの神宮も\\nあるんですね', 1, 1, 3, 0, 0, 128301, 8, 7846);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月のトラブルも\\nハツネちゃんが\\nめでたく解決\\nしてみせるのだ～！', 1, 1, 1, 0, 0, 128401, 1, 7848);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ、新年会に\\nサプライズ大作戦を\\nしかけちゃおう！', 1, 1, 1, 0, 0, 128401, 2, 7849);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('イノリちゃんも\\nカスミンも振袖姿が\\nかわいかったな～', 1, 1, 1, 0, 0, 128401, 3, 7850);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリンに\\nお年玉あげたいし\\n彼にバイトを紹介\\nしてもらおうかな？', 1, 1, 1, 0, 0, 128401, 4, 7851);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度はどんな凧を\\n飛ばそうかな？\\nみんなが驚くような\\n凧がいいよね～', 1, 1, 1, 0, 0, 128401, 5, 7852);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひらめいた！\\n彼への年賀状は\\nきらーんっ☆って\\n感じにしよう！', 4, 1, 1, 0, 0, 128401, 101, 7853);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('来年も彼の隣で\\n初日の出が\\n見られるといいな～', 8, 1, 1, 0, 0, 128401, 102, 7854);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はキミが\\nギルドハウスに来る\\n予知夢を見たんだよ～\\nふふ、正夢になったね', 1, 1, 2, 0, 0, 128401, 1, 7855);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この振袖どうかな？\\nすっごくかわいいよね\\nえへへ、ありがとう～', 1, 1, 2, 0, 0, 128401, 2, 7856);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ハツネちゃんおみくじ\\n開始！\u3000きらーんっ☆\\nキミは大吉なのだ～\\nどう元気出たかな？', 1, 1, 2, 0, 0, 128401, 3, 7857);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度エルフの森にある\\n薬草を使って七草粥を\\n作ろうと思うんだ～\\nぜひ食べてほしいな♪', 1, 1, 2, 0, 0, 128401, 4, 7858);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月っぽい遊びを\\n色々と用意したのだ～\\nたまにはギルドハウス\\nでゆっくり過ごそうよ', 4, 1, 2, 0, 0, 128401, 101, 7859);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして眠たいの？\\n…じゃあ、また膝枕\\nしてあげてもいいよ？', 8, 1, 2, 0, 0, 128401, 102, 7860);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いっぱい寝たから\\n元気いっぱいだよ～\\n今日もがんばろう！', 1, 1, 2, 0, 1, 128401, 1, 7861);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼だね～\\nおせちがあるから\\nキミも食べるでしょ？', 1, 1, 2, 0, 2, 128401, 2, 7862);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そろそろ寝る時間だね\\n今日はどんな夢を\\n見られるかな～', 1, 1, 2, 0, 3, 128401, 3, 7863);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい座り心地～\\n寝正月で過ごすのも\\n最高なのだ～', 1, 1, 3, 0, 0, 128401, 2, 7865);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいな～\\n癒されてぐっすり\\n眠れそうだよ～', 1, 1, 3, 0, 0, 128401, 3, 7866);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香り～\\nリラックスすると\\n眠たくなっちゃうよ…', 1, 1, 3, 0, 0, 128401, 4, 7867);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカいい気持ち～\\n初日の出の温もりを\\n思い出しちゃうな～♪', 1, 1, 3, 0, 0, 128401, 5, 7868);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ、おいし～\\nでもいっぱい食べたら\\n眠くなっちゃった…', 1, 1, 3, 0, 0, 128401, 7, 7870);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ\\nお正月料理も\\n色々あるんだね～\\n今度作ってみようかな', 1, 1, 3, 0, 0, 128401, 8, 7871);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('最近カレを見てたら\\n何故かおいしそうに\\n思えてくるんだよな…', 12, 1, 1, 0, 0, 106501, 103, 7873);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手握っててくれるか？\\nじゃないとオレ…\\n力が抑えきれない…', 12, 1, 2, 0, 0, 106501, 103, 7874);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('つかの間の平和を享受\\nしながらぬくぬくと\\n読書に耽る…\\nふふ、最高だね', 1, 1, 1, 0, 0, 128501, 1, 7875);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月飾りなんて\\n置いたらはしゃいでる\\nように見えるかな…？', 1, 1, 1, 0, 0, 128501, 2, 7876);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ま、まずい…\\n一人遊びしすぎて\\nお正月遊びをほぼ\\n極めつつある…', 1, 1, 1, 0, 0, 128501, 3, 7877);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミステリーは\\n時と場所を選ばない\\nつまり…新年でも\\n探偵は休まないよ！', 1, 1, 1, 0, 0, 128501, 4, 7878);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お世話になった人に\\n年賀状でも書こうかな\\n助手くん、喜んで\\nくれるかな…えへへっ', 1, 1, 1, 0, 0, 128501, 5, 7879);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('絵馬に願い事を書こう\\n助手くんと一緒に\\nいられますように…♪\\n…は、恥ずかしいな', 4, 1, 1, 0, 0, 128501, 101, 7880);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くんはもっと\\n派手な着物のほうが\\n好みだったかな…？\\nき、気になる…', 8, 1, 1, 0, 0, 128501, 102, 7881);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やあ。助手くんも\\nお正月休みを\\n持て余してるのかい？\\nふふ、似た者同士だね', 1, 1, 2, 0, 0, 128501, 1, 7882);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('助手くん助手くん！\\n凧あげしにいこう！\\n…そ、捜査の一環で', 1, 1, 2, 0, 0, 128501, 2, 7883);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('着物は転びそうで\\n怖いんだよなあ…\\nお、押さないでね？\\nフリじゃないよ！？', 1, 1, 2, 0, 0, 128501, 3, 7884);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひ、人目を憚る\\n本を読むなら\\nみんなが帰省中の今！\\nはっ！\u3000助手くん！？', 1, 1, 2, 0, 0, 128501, 4, 7885);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ね、ねえ…助手くん…\\n一緒に初詣いかない？\\nあ、いや！\u3000深い\\n意味はないんだけど！', 4, 1, 2, 0, 0, 128501, 101, 7886);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あはは…助手くんと\\n一緒だと家でごろごろ\\nしてるだけでも\\n楽しいや…♪', 8, 1, 2, 0, 0, 128501, 102, 7887);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁ～…\\nお正月休みのおかげで\\n昼夜逆転中だよ…', 1, 1, 2, 0, 1, 128501, 1, 7888);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お正月も依頼が\\nひっきりなしだね\\nさあ、街へ出よう！\\nもちろん君も一緒にね', 1, 1, 2, 0, 2, 128501, 2, 7889);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('も、もっと\\n近くにきてもいいよ？\\n冬の夜は…寒いからね', 1, 1, 2, 0, 3, 128501, 3, 7890);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ううぅ～…！\\nこのままじゃ\\n寝正月だぁ…！', 1, 1, 3, 0, 0, 128501, 2, 7892);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなが帰省中でも\\nこれがあれば\\n寂しくない…かな', 1, 1, 3, 0, 0, 128501, 3, 7893);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…♪\\nお正月休みの\\nリフレッシュに\\nちょうどいいや♪', 1, 1, 3, 0, 0, 128501, 4, 7894);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…あったまるな\\n冬は寒いから\\n助かるよ…', 1, 1, 3, 0, 0, 128501, 5, 7895);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん、おいしい♪\\n読書のお供に\\nちょうどいい', 1, 1, 3, 0, 0, 128501, 7, 7897);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('時間に余裕があると\\n読書が進むよ\\nいざ、本棚読破だ♪', 1, 1, 3, 0, 0, 128501, 8, 7898);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この新しい力…\\nさらに使いこなせる\\nようになるには…', 1, 1, 1, 0, 0, 128801, 1, 7900);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('私に眠る属性の力…\\n風の力以外には\\nどんな力があるのかな', 1, 1, 1, 0, 0, 128801, 2, 7901);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今の私なら\\nどこまでいけるのか…\\nやれるだけ\\nやってみよう', 1, 1, 1, 0, 0, 128801, 3, 7902);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風の力の制御…\\n段々とコツが\\n掴めてきたな', 1, 1, 1, 0, 0, 128801, 4, 7903);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('風の力か…\\n応用の幅は広そうだ\\n何ができそうか\\n色々試してみよう', 1, 1, 1, 0, 0, 128801, 5, 7904);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度、私とキミで\\n料理対決でもする？\\n簡単には負けないよ', 4, 1, 1, 0, 0, 128801, 101, 7905);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この胸に溢れる\\n温かな気持ちは…\\nきっと彼への…', 8, 1, 1, 0, 0, 128801, 102, 7906);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('一段と剣技が\\n冴えてきたような…\\nいや…油断禁物だ', 1, 1, 2, 0, 0, 128801, 1, 7907);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かっこいいって？\\nありがとう…そんなに\\n真っすぐ褒められると\\n照れてしまうな…', 1, 1, 2, 0, 0, 128801, 2, 7908);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どれほど厚い壁が\\n立ち塞がろうと\\n打ち破ってみせる', 1, 1, 2, 0, 0, 128801, 3, 7909);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('手が空いてるなら\\n剣の稽古に少し\\n付き合ってくれるかな', 1, 1, 2, 0, 0, 128801, 4, 7910);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('試練を乗り越えて…\\n私の中にあるものが\\nはっきりと分かったよ', 4, 1, 2, 0, 0, 128801, 101, 7911);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キミから流れてくる\\n力の温かさ…これが\\n私たちの絆なんだ', 8, 1, 2, 0, 0, 128801, 102, 7912);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝だよ、そろそろ\\n起きる時間だ\\nそれとも私に起こして\\nほしいのかな？', 1, 1, 2, 0, 1, 128801, 1, 7913);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼食は私が作るよ\\nリクエストはある？\\nできる範囲で応えるよ', 1, 1, 2, 0, 2, 128801, 2, 7914);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おやすみ。また明日も\\n一緒に冒険しよう\\n約束だよ？', 1, 1, 2, 0, 3, 128801, 3, 7915);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休める時は休む…\\n戦い続けるには\\n必要なことだからね', 1, 1, 3, 0, 0, 128801, 2, 7917);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心の安らぎの大切さ…\\nそれを知れたのは\\nキミたちのおかげだね', 1, 1, 3, 0, 0, 128801, 3, 7918);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気持ちが落ち着くな…\\nこの香り、風の力で\\n纏えたりしないかな', 1, 1, 3, 0, 0, 128801, 4, 7919);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖まった空気の流れ…\\n以前より風の変化に\\n気づくようになったな', 1, 1, 3, 0, 0, 128801, 5, 7920);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この味付け…\\n今度試してみようか\\n味見は任せたからね', 1, 1, 3, 0, 0, 128801, 7, 7922);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心技体、すべてを\\n鍛えるには座学も\\n必要だからね', 1, 1, 3, 0, 0, 128801, 8, 7923);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('瞑想するのに\\nいいところはあるかな\\n集中できて…お昼寝は\\n我慢できるところ', 1, 1, 1, 0, 0, 128901, 1, 7925);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここにはあったかい\\n空気が流れてるなぁ…\\nみんなが受け入れて\\nくれるおかげだね', 1, 1, 1, 0, 0, 128901, 2, 7926);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まるで心の中に\\n光が満ちてるみたい…\\nこの気持ち、みんなに\\nおすそ分けしたいな♪', 1, 1, 1, 0, 0, 128901, 3, 7927);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装は属性の力を\\n反映しやすいんだよね\\nキラキラしてるのも\\n納得だよ', 1, 1, 1, 0, 0, 128901, 4, 7928);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('エルフの里のみなさん\\n元気かなぁ…\\nまた会いに行きたいな', 1, 1, 1, 0, 0, 128901, 5, 7929);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ変身できてる…\\nわたしと騎士クンの\\n修行の成果\\n出てるなぁ…ふふっ♪', 4, 1, 1, 0, 0, 128901, 101, 7930);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服を脱いだら\\nどうなるのかな…\\nた、試す勇気は\\nないけど…', 8, 1, 1, 0, 0, 128901, 102, 7931);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぅ…あ、騎士クン\\nちょうど瞑想してたの\\n一緒に…する？', 1, 1, 2, 0, 0, 128901, 1, 7932);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不思議だけど\\nいつの間にか\\n出たり消えたりするの\\n…背中の輪っか！', 1, 1, 2, 0, 0, 128901, 2, 7933);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服って肌触りが\\nとってもいいんだよ\\nさ、触ってみる？\\nスベスベだよ？', 1, 1, 2, 0, 0, 128901, 3, 7934);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アストラルの力…\\nすごく持続できてるね\\n修行の成果が出てるよ', 1, 1, 2, 0, 0, 128901, 4, 7935);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この力があれば\\n暗いところで\\n落とし物をしても\\n見つけやすいかも…？', 4, 1, 2, 0, 0, 128901, 101, 7936);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冒険の準備なら\\nできてるよ\\nいつでも声をかけてね\\n…楽しみにしてる！', 8, 1, 2, 0, 0, 128901, 102, 7937);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう騎士クン\\n一緒にお散歩とか…\\nどうかな？', 1, 1, 2, 0, 1, 128901, 1, 7938);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯のあとの\\n瞑想って難しいんだよ\\n眠くなっちゃって…', 1, 1, 2, 0, 2, 128901, 2, 7939);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜ふかしさんは\\nほどほどにね？\\n一日頑張った自分を\\n休ませてあげないと', 1, 1, 2, 0, 3, 128901, 3, 7940);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('のんびりしてたら\\nケーキが食べたく\\nなっちゃうなぁ…\\nでも太る…よね…？', 1, 1, 3, 0, 0, 128901, 2, 7942);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わあ、かわいい…！\\n見てるだけで\\nにやけちゃう…♪', 1, 1, 3, 0, 0, 128901, 3, 7943);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…花の香りかな\\n知ってる花かも…？\\n当ててみようっ', 1, 1, 3, 0, 0, 128901, 4, 7944);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったかいと\\nどうしてこんなに\\n落ち着くんだろう…', 1, 1, 3, 0, 0, 128901, 5, 7945);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ過ぎたらお腹が\\n目立っちゃうかもって\\n分かってるのに…！\\n止められないよ～っ！', 1, 1, 3, 0, 0, 128901, 7, 7947);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こ、恋の精霊とか\\nいたりするのかな…？\\nはっ！\u3000ダメダメっ！\\n実力で頑張らないと', 1, 1, 3, 0, 0, 128901, 8, 7948);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お部屋の中でも\\n修行、修行っ♪\\nでも燃やさないように\\n注意しなきゃだね', 1, 1, 1, 0, 0, 128701, 1, 7950);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うーん…この衣装\\n厚着か薄着か\\nどっちなんだろう…？', 1, 1, 1, 0, 0, 128701, 2, 7951);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつもの肉球がない分\\nお片付けしやすいな♪\\n騎士くんのお部屋\\nピカピカにしとこー！', 1, 1, 1, 0, 0, 128701, 3, 7952);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お休みは騎士くんと\\nＢＢＱに行きたいなー\\nあたしと一緒なら\\n火の心配はいらないよ', 1, 1, 1, 0, 0, 128701, 4, 7953);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿ならもっと\\n人を助けられる…！\\nえへへっ！\\n燃えてきたーーっ！', 1, 1, 1, 0, 0, 128701, 5, 7954);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くんが帰ったら\\nアイラみたいな笑顔で\\nお疲れさまさまって\\nお出迎えしよっと…♪', 4, 1, 1, 0, 0, 128701, 101, 7955);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿の時、いつも\\n胸が熱く燃えてるのは\\nずっと騎士くんのこと\\n考えてるからかな…？', 8, 1, 1, 0, 0, 128701, 102, 7956);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くん騎士くん！\\nあたしに触れると\\nやけどしちゃうよ…？\\nなんちゃってー♪', 1, 1, 2, 0, 0, 128701, 1, 7957);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おっ、騎士くん\\n修行に行きたいの？\\nえへへっ、いいねー♪\\n二人で燃えちゃおー！', 1, 1, 2, 0, 0, 128701, 2, 7958);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そうだ騎士くん\\nじゃんけんしよっか？\\nグローブ外してるから\\nチョキも出せるよっ♪', 1, 1, 2, 0, 0, 128701, 3, 7959);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この姿でいられる時間\\nすごく増えてきた…！\\nえへへ！\u3000あたしたち\\n修行の成果出てるね！', 1, 1, 2, 0, 0, 128701, 4, 7960);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('じっと見つめないでよ\\n顔が真っ赤に…やば！\\nほんとに顔から\\n火噴いちゃいそう…！', 4, 1, 2, 0, 0, 128701, 101, 7961);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火には強くなれても\\n騎士くんに触られた\\nほっぺはずーっと\\n熱くてたまんないや…', 8, 1, 2, 0, 0, 128701, 102, 7962);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよー騎士くん！\\n今日も一日\\n燃え滾っていくよー！\\nファイヤーッ！！', 1, 1, 2, 0, 1, 128701, 1, 7963);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士くんお昼だよ！\\nちゃんとご飯食べて\\n午後からの修行も\\n乗り切ろうねー！', 1, 1, 2, 0, 2, 128701, 2, 7964);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日もお疲れさま！\\nそうだ、寝る前に\\nキャンプファイヤー\\n囲んじゃおっか♪', 1, 1, 2, 0, 3, 128701, 3, 7965);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぼふーんっ！\\nえへへ、気持ちいい…\\n修行の前に\\nちょっと休憩ー♪', 1, 1, 3, 0, 0, 128701, 2, 7967);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいな～♪\\nなでなでなでなでなで\\nなでなでなでなでっ！\\nあははっ、摩擦熱！', 1, 1, 3, 0, 0, 128701, 3, 7968);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ん～いい香り♪\\n少し熱したほうが\\n香りが広がるね…って\\n蒸発しちゃった！！！', 1, 1, 3, 0, 0, 128701, 4, 7969);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外でも自分の火で\\nあったまれるけど\\nお部屋でぬくぬく\\nするのが一番だよね♪', 1, 1, 3, 0, 0, 128701, 5, 7970);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐっ！\\nお腹が減っては\\n人助けはできずっ！\\nもぐもぐもぐっ！', 1, 1, 3, 0, 0, 128701, 7, 7972);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nなるほどなるほど…\\n…これが上手な\\nＢＢＱのやり方か…', 1, 1, 3, 0, 0, 128701, 8, 7973);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…壁も扉も柱も\\n全て記録で見たまま\\n本当に…来ているのね', 1, 1, 1, 0, 0, 129001, 1, 7975);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…騒がしい場所\\n騎士クンが受け入れて\\nくれるのをいいことに', 1, 1, 1, 0, 0, 129001, 2, 7976);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここが…騎士クンの\\n守りたかった場所\\n騎士クンの思い出が\\n詰まった場所…ね', 1, 1, 1, 0, 0, 129001, 3, 7977);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('視線を感じる…\\nこちらの様子を\\n探るような…心の動き\\n取るに足らないけれど', 1, 1, 1, 0, 0, 129001, 4, 7978);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…そこかしこで…\\n言葉にもしたくない\\n相手が過ごしていた\\n記録を思い出す…', 1, 1, 1, 0, 0, 129001, 5, 7979);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('人は多いけれど…\\n雪深い山中よりは\\n過ごしやすい…か', 4, 1, 1, 0, 0, 129001, 101, 7980);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('自覚したことは\\nあまりなかったけれど\\nひどく…諦めの悪い女\\nなのかもしれない', 8, 1, 1, 0, 0, 129001, 102, 7981);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お招きありがとう\\nそれで…何をして\\nいればいい…かな？', 1, 1, 2, 0, 0, 129001, 1, 7982);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここは…明るいね\\nわたしの城と比べると\\nなんだか眩しいくらい', 1, 1, 2, 0, 0, 129001, 2, 7983);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仮面はもう必要ないよ\\nだって…わたしの顔を\\n騎士クンに見て\\nもらえなくなるから', 1, 1, 2, 0, 0, 129001, 3, 7984);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クンさえよければ\\nわたしの城に専用の\\n部屋を用意するよ\\n…いつでも', 1, 1, 2, 0, 0, 129001, 4, 7985);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…騎士クンのマント\\nまた貸してほしいな\\nきれいに使うから\\n…だめ？', 4, 1, 2, 0, 0, 129001, 101, 7986);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いつか二人の願いが\\n重なり合えるって…\\n信じているね\\n…いつまでだって…', 8, 1, 2, 0, 0, 129001, 102, 7987);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはよう、騎士クン\\n…昨日は夢の中で\\nお話ししすぎちゃって\\nごめんね。ふふっ', 1, 1, 2, 0, 1, 129001, 1, 7988);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹は…空いてない？\\n食べ物はないけれど\\n空腹を忘れる魔法なら\\nかけてあげられるよ', 1, 1, 2, 0, 2, 129001, 2, 7989);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン…\\nまだ、眠らないの？\\n…そう。それなら…\\nわたしも起きているね', 1, 1, 2, 0, 3, 129001, 3, 7990);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('肩の力を抜くには…\\nまだ時間がかかりそう\\nきっと…騎士クンと\\n二人きりなら別なのに', 1, 1, 3, 0, 0, 129001, 2, 7992);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぺんぽこりん…\\nそう、確かあれも\\nこんな感じだった…', 1, 1, 3, 0, 0, 129001, 3, 7993);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花の香りは…好き\\nつかの間\\n心を穏やかに\\nしてくれるから', 1, 1, 3, 0, 0, 129001, 4, 7994);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたたかい…けれど\\n騎士クンの優しさに\\n比べれば、まだまだ', 1, 1, 3, 0, 0, 129001, 5, 7995);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おい、しい…？\\nこの感覚が、それ？\\nなぜか…納得できる', 1, 1, 3, 0, 0, 129001, 7, 7997);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('情報を入手するには\\nわざわざ本を開く\\n必要があるだなんて…\\nプレイヤーは面倒ね', 1, 1, 3, 0, 0, 129001, 8, 7998);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メルクリゾートか…\\n良い記憶はないな\\nよし忘れよう', 1, 1, 1, 0, 0, 129301, 1, 8000);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知性の戦士ユニ！\\nその恐るべき筋力！\\nふおお！\u3000うにゃー！', 1, 1, 1, 0, 0, 129301, 2, 8001);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぽーん！\\n石用の水着ください！\\nセクシーロゼッタが、\\n渚の視線を独占です！', 1, 1, 1, 0, 0, 129301, 3, 8002);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('学院から奨学金を\\n勝ち取るより某財団を\\nだまくらかした方が\\n早い気がしてきたな…', 1, 1, 1, 0, 0, 129301, 4, 8003);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わんつぅ、わんつぅ…\\nんぎゃあ足攣ったー！\\nおのれカルミナとやら\\n絶対に許さん！', 1, 1, 1, 0, 0, 129301, 5, 8004);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ところで…なぜぼくは\\nプールでもないのに\\n水着のままなんだ…\\nおのれ世界め！', 4, 1, 1, 0, 0, 129301, 101, 8005);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('彼と二人で撮った動画\\nうう、凝視に耐えん…\\nなんだこのムズ痒さは', 8, 1, 1, 0, 0, 129301, 102, 8006);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なに？\u3000水着姿で\\n寒くないのかだと？\\n普段からもっと薄着の\\n娘が沢山いるだろう', 1, 1, 2, 0, 0, 129301, 1, 8007);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シノブ君にメリゾの\\n招待状を送ったのだが\\n御尊父の暴走を\\n心配していたな…', 1, 1, 2, 0, 0, 129301, 2, 8008);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミミ君らにメリゾの\\n招待状を送ったのだよ\\n迎える準備をせねば…\\nおしゃぶり持ってる？', 1, 1, 2, 0, 0, 129301, 3, 8009);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本質の賢者…？\\nいや元気にしているが\\nなぜ君がぼくの身内を\\n知っているんだ…？', 1, 1, 2, 0, 0, 129301, 4, 8010);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着が似合ってる？\\nな、なんだね突然…\\nやめたまえよふひひ…', 4, 1, 2, 0, 0, 129301, 101, 8011);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度は夏にメリゾへ\\n行きたいものだ\\nむろん君も一緒だぞ', 8, 1, 2, 0, 0, 129301, 102, 8012);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぐああっ、朝陽が…！\\n朝陽が昇っている…！\\n夜行性ユニ死んじゃう', 1, 1, 2, 0, 1, 129301, 1, 8013);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ…もう昼か…\\nそろそろ寝ないとな\\n規則正しい生活を\\nしないと不健康だ…', 1, 1, 2, 0, 2, 129301, 2, 8014);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ひゃっはー、夜だー！\\nオレたちの時間だぜ！\\nふおおブチ上がり～！', 1, 1, 2, 0, 3, 129301, 3, 8015);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…ぼくにここで\\n寝ろということか？\\n一向に構わんが…', 1, 1, 3, 0, 0, 129301, 2, 8017);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゃっきゃっ！\\nこれかわい～！\\n…よし、今日も\\n子供の擬態完璧だな', 1, 1, 3, 0, 0, 129301, 3, 8018);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむ、良い香りだ\\nだがそれだけか…\\nとくに精神高揚効果は\\nないのか…ちぇー', 1, 1, 3, 0, 0, 129301, 4, 8019);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火を見ていると…\\n魔導罐を思いだすな…\\nかに座、元気かな…', 1, 1, 3, 0, 0, 129301, 5, 8020);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ええい、\\n固形食物はいらん！\u3000\\nポーションを出せ！', 1, 1, 3, 0, 0, 129301, 7, 8022);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('やはり書は文系に限る\\nなんと心地よい筆致…\\nぐああ突然理系文が！\\nひぃ目が理系になる！', 1, 1, 3, 0, 0, 129301, 8, 8023);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ほああ～！\\n知性の海上騎士ユニ！\\nこれは新たな可能性！', 1, 1, 3, 0, 0, 129301, 10, 8025);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これは…なんだ？\\n何が面白いんだ？\\n難しいな…', 1, 1, 3, 0, 0, 129301, 11, 8026);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('大切な人と過ごす\\n正月の思い出、か…\\n昔の私だったら\\n考えられなかったな', 12, 1, 1, 0, 0, 108901, 103, 8027);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('叶えたい願いなら\\nたくさんあるよ\\nそれでも一番を選ぶ\\nなら、やはりキミと…', 12, 1, 2, 0, 0, 108901, 103, 8028);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('神殿にあった\\n恋愛おみくじ…\\n引いてみようかな…', 12, 1, 1, 0, 0, 108801, 103, 8029);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士クン。来年も\\nまた一緒におみくじ\\n結ぼうね。約束だよ', 12, 1, 2, 0, 0, 108801, 103, 8030);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度は騎士くんと\\n一緒にうつった写真、\\nおばあちゃんに\\n送ろうっと♪', 12, 1, 1, 0, 0, 108701, 103, 8031);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、騎士くん！\\n今年も…ううん\\nこれからも、よろしく\\nおねがいします♪', 12, 1, 2, 0, 0, 108701, 103, 8032);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('旧校舎の地下牢…\\n真冬のサマー計画…\\n等身大のＰＲ…\\nうッ、頭が…！', 1, 1, 1, 0, 0, 129401, 1, 8033);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暇だし鏡でも見るか。\\nお、いい腹筋育って…\\nあ？\u3000何見てんだコラ', 1, 1, 1, 0, 0, 129401, 2, 8034);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('オレは金色の疾風！\\nんん…なんか違うな。\\n我が名は金色の…\\nあ？\u3000何見てんだコラ', 1, 1, 1, 0, 0, 129401, 3, 8035);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('モニカとユニ先輩って\\n口調と身長似てるけど\\n子供扱いに対する\\n反応は真逆だよね…', 1, 1, 1, 0, 0, 129401, 4, 8036);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('シオリン元気かな…\\n昔くちゃくちゃに\\n撫でくり回して\\n嫌がられたっけなァ…', 1, 1, 1, 0, 0, 129401, 5, 8037);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('べつにいんだけどさ…\\nあんたの知り合いって\\n普段から水着みたいな\\nカッコの女多くない？', 4, 1, 1, 0, 0, 129401, 101, 8038);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そだ、弟らがあんたに\\n会いたがってたンだ。\\n暇だったらいつでも\\nウチ来てやってよ', 8, 1, 1, 0, 0, 129401, 102, 8039);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('特別講座は色々あった\\nけど…メリゾ自体は\\nまあ悪くなかったよね', 1, 1, 2, 0, 0, 129401, 1, 8040);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着と合わせる小物に\\nセンス出るよね、\\nって話をミィコ先輩が\\nしててマジわかりみ', 1, 1, 2, 0, 0, 129401, 2, 8041);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着のミフユねえさん\\nやっぱ仕上がってたね\\nあれが竜殺しの体か…\\nバリかっけーな…', 1, 1, 2, 0, 0, 129401, 3, 8042);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はにょんっ！？\\nや、だからさ…\\n後ろから声かけんな、\\nつってンじゃん…', 1, 1, 2, 0, 0, 129401, 4, 8043);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メリゾの特別講座が\\n上手くいったのも\\n敏腕カメラマンがいた\\nお陰だよ。ありがとね', 4, 1, 2, 0, 0, 129401, 101, 8044);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ？\u3000この水着が？\\n似合っ…え、なんて？\\nごめ、聞こえんくて。\\nもっかい言ってみて', 8, 1, 2, 0, 0, 129401, 102, 8045);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もう朝とかマジないわ\\n昨日二人に付き合って\\nオールでカラオケだよ', 1, 1, 2, 0, 1, 129401, 1, 8046);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はぁ授業行かなきゃ…\\n真っ昼間から勉強とか\\nマジつらたん過ぎ…', 1, 1, 2, 0, 2, 129401, 2, 8047);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日これから夜勤で…\\nいやバイトちゃーくて\\nボランティアの話よ？\\n校則違反よくない', 1, 1, 2, 0, 3, 129401, 3, 8048);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うわ、ふっかふか…\\nオニほど安らぐわ…\\nやば、ユニってくる…', 1, 1, 3, 0, 0, 129401, 2, 8050);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちも妹いりゃ\\nこーゆーのもなァ…\\nま自分用でもいいか', 1, 1, 3, 0, 0, 129401, 3, 8051);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふーん…\\nいいじゃんこの香り\\n抜群に嗅げるわ', 1, 1, 3, 0, 0, 129401, 4, 8052);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちン家のルーツの森\\n大火災でなくなった\\nらしンだよね…\\n生まれる前の話だけど', 1, 1, 3, 0, 0, 129401, 5, 8053);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何コレありがてぇー\\n食料ほくほく過ぎて草\\n米ガチで尊いわァ…', 1, 1, 3, 0, 0, 129401, 7, 8055);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いいけど、なんでうち\\n水着で本読んでンだよ\\nどーゆープレイだよ', 1, 1, 3, 0, 0, 129401, 8, 8056);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('金色の海上騎士クロエ\\n推して参る！\u3000覇ァ！\\nあ？\u3000何見てんだコラ', 1, 1, 3, 0, 0, 129401, 10, 8058);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('何コレ、貝の椅子？\\nどーやって遊ぶんだ…\\nいや座って終わりか…\\nまァそりゃそーか…', 1, 1, 3, 0, 0, 129401, 11, 8059);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さてと…\\n明日の訓練メニュー\\n考えねえとな', 1, 1, 1, 0, 0, 129801, 1, 8060);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('また新入りの女子に\\n弁当もらっちまった…\\nありがたく食うけどよ', 1, 1, 1, 0, 0, 129801, 2, 8061);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('種族なんて関係なく\\nみんなが力を合わせて\\nランドソルを守る…\\nいい時代になったよな', 1, 1, 1, 0, 0, 129801, 3, 8062);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('誰にだって長所はある\\n新入りのいいところを\\n見つけてやるのも\\n教官の仕事だ', 1, 1, 1, 0, 0, 129801, 4, 8063);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('厳し過ぎても\\n甘過ぎてもダメ…\\n教官ってのは難しいぜ', 1, 1, 1, 0, 0, 129801, 5, 8064);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('戦いが苦手な新入りを\\nどうフォローするか…\\n後であいつと\\n相談してみるか', 4, 1, 1, 0, 0, 129801, 101, 8065);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつは優し過ぎて\\n戦いに向いてねえ\\n…そういう甘さ\\n嫌いじゃねえけどな', 8, 1, 1, 0, 0, 129801, 102, 8066);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強くなる近道はねえ\\n地道な鍛錬あるのみだ\\nさ、訓練始めるぞ！', 1, 1, 2, 0, 0, 129801, 1, 8067);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新入りにも\\nいつも言ってるが…\\n装備の手入れは\\n念入りにしろよな？', 1, 1, 2, 0, 0, 129801, 2, 8068);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('座学も受けてえのか？\\nいい心がけだな！\\nなんでも教えてやるよ\\n…魔法以外ならな', 1, 1, 2, 0, 0, 129801, 3, 8069);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新入りたちがよく\\n恋バナしててな…\\nお、おまえは…誰か\\n気になるやついるか？', 1, 1, 2, 0, 0, 129801, 4, 8070);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なあ、ストレッチ\\n手伝ってくれねえか？\\n訓練前にしっかり\\n筋肉ほぐさねえと…', 4, 1, 2, 0, 0, 129801, 101, 8071);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ずいぶん頑張って\\n鍛えたよな、おまえ\\nよし！\u3000ご褒美に\\nお菓子作ってやるよ♪', 8, 1, 2, 0, 0, 129801, 102, 8072);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('訓練日和だな！\\nさぁて…まずは\\n走り込みといくか！', 1, 1, 2, 0, 1, 129801, 1, 8073);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('昼飯はしっかり食えよ\\nでなきゃ、\\nこの後もたねえぜ？', 1, 1, 2, 0, 2, 129801, 2, 8074);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっくに消灯時間だ\\nさっさと寝な？\\n明日も早いんだからよ', 1, 1, 2, 0, 3, 129801, 3, 8075);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休むのも訓練のうちだ\\n今はのんびり\\nさせてもらうぜ', 1, 1, 3, 0, 0, 129801, 2, 8077);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい面構えだ\\n気に入ったぜ！\\nあたしの班に入るか？\\n…なんてな♪', 1, 1, 3, 0, 0, 129801, 3, 8078);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…いやされる匂いだな\\n新入りたちにも\\nすすめてみるか…', 1, 1, 3, 0, 0, 129801, 4, 8079);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あったけえからって\\n寝ないようにしねえと\\n教官としての\\n威厳に関わるからな…', 1, 1, 3, 0, 0, 129801, 5, 8080);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事も訓練の一環だ\\nとはいえ食い過ぎには\\n気をつけねえと…', 1, 1, 3, 0, 0, 129801, 7, 8082);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トーゴクの剣術…か\\nなにか訓練に\\n活かせるかもしれねえ', 1, 1, 3, 0, 0, 129801, 8, 8083);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あのおかたに近付く\\n不埒な輩には、特別な\\n訓練で地獄を見て\\nいただきましょう', 1, 1, 1, 0, 0, 129901, 1, 8085);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これだけ広ければ\\n多少派手に\\n動き回っても\\n問題なさそうですね', 1, 1, 1, 0, 0, 129901, 2, 8086);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…今誰か私を\\n「鬼」教官と\\n呼びませんでしたか？', 1, 1, 1, 0, 0, 129901, 3, 8087);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しく開発したこの薬\\n誰か試してくれる人は\\nいませんか？', 1, 1, 1, 0, 0, 129901, 4, 8088);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('厳しくすれば投げ出し\\n優しくすればサボる\\n人というのはどこまで\\n度し難いのでしょう', 1, 1, 1, 0, 0, 129901, 5, 8089);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はじめましょう\\nあのおかたの心を\\n射貫くための\\nシミュレーションを', 4, 1, 1, 0, 0, 129901, 101, 8090);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらゆる苦難と\\n忌々しい女から守る\\nためにも、私自身も\\n鍛えておかねば', 8, 1, 1, 0, 0, 129901, 102, 8091);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなた様、そんなに\\n見つめられると…え？\\nエリコはカッコいい？\\nええ、当然ですとも', 1, 1, 2, 0, 0, 129901, 1, 8092);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('不調があればすぐ\\n報告してください\\n体のケアも教官の\\n大事な役目ですので', 1, 1, 2, 0, 0, 129901, 2, 8093);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい訓練器具の\\n使い心地はどう…え？\\n重すぎる？\u3000これでも\\n軽くしたのですが…', 1, 1, 2, 0, 0, 129901, 3, 8094);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('運動後には特製の\\n栄養ドリンクをどうぞ\\nクスクス、何も\\n入れたりしてませんわ', 1, 1, 2, 0, 0, 129901, 4, 8095);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よくがんばりました\\nあなた様。あぁ…\\nお疲れになったお顔も\\n素敵ですわ', 4, 1, 2, 0, 0, 129901, 101, 8096);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなた様、二人だけの\\n遠征訓練へ\\nまいりましょう。\\n既に準備万端ですわ', 8, 1, 2, 0, 0, 129901, 102, 8097);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まだ眠いですか？\\nならばストレッチで\\n体を痛めつ…ではなく\\nほぐしていきましょう', 1, 1, 2, 0, 1, 129901, 1, 8098);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼はお弁当をご用意\\nいたしました。量も\\nスタミナも増し増し\\n残さず食べてください', 1, 1, 2, 0, 2, 129901, 2, 8099);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よい睡眠こそ健やかな\\n体に不可欠。ですので\\n私が寝ずの番をさせて\\nいただきますわ', 1, 1, 2, 0, 3, 129901, 3, 8100);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('休憩用に使おうと思い\\nましたが、心地よくて\\n立てなくなって\\nしまいますわ…', 1, 1, 3, 0, 0, 129901, 2, 8102);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('中に重しを詰めれば\\n愛でながら運動が\\n可能ですわ', 1, 1, 3, 0, 0, 129901, 3, 8103);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('香りでリラックスさせ\\n同時に暗示を\\nかけてみましょうか', 1, 1, 3, 0, 0, 129901, 4, 8104);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…くっ、眠気を誘う\\nこの暖かさ…\\n油断も隙もありません', 1, 1, 3, 0, 0, 129901, 5, 8105);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('主食はこちらで十分\\nまかなえますわね\\nそれでは私はおかずを\\n作りましょう', 1, 1, 3, 0, 0, 129901, 7, 8107);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まあ、実用書の類も\\n揃っているのですね\\nとても助かりますわ', 1, 1, 3, 0, 0, 129901, 8, 8108);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('……（そわそわ）', 1, 1, 1, 0, 0, 129601, 1, 8110);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここに寄らずの花陣…\\n作ったらダメですよね', 1, 1, 1, 0, 0, 129601, 2, 8111);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('部屋の隅が\\n落ち着きます\\nそれか、陽の当たる所', 1, 1, 1, 0, 0, 129601, 3, 8112);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('身を隠せる場所が\\nあると…\\n助かるんですけど', 1, 1, 1, 0, 0, 129601, 4, 8113);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('複雑な造りの家ですね\\n触って壊れたり─\\nしませんか？', 1, 1, 1, 0, 0, 129601, 5, 8114);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('出入りするひと\\nみんな、笑顔…\\n…変わった家ですね', 4, 1, 1, 0, 0, 129601, 101, 8115);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この家なら安全─\\nかもしれません\\n魔物が出ないので', 8, 1, 1, 0, 0, 129601, 102, 8116);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これも、視察の一環\\n遊びに来たわけじゃ\\nないです', 1, 1, 2, 0, 0, 129601, 1, 8117);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('長話─苦手です\\n疲れるので…\\nふぅ…', 1, 1, 2, 0, 0, 129601, 2, 8118);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここで友達を作れと\\nネアさんが…\\nそう、言われても…', 1, 1, 2, 0, 0, 129601, 3, 8119);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('世話をするのは\\n得意です\\n…花の、ですよ？', 1, 1, 2, 0, 0, 129601, 4, 8120);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('媛へのお土産を\\n探してるんですけど…\\n…貴方のおすすめ、\\n聞いておきます', 4, 1, 2, 0, 0, 129601, 101, 8121);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('平和でのんきで…\\n貴方らしい家です\\n一応、褒めてます', 8, 1, 2, 0, 0, 129601, 102, 8122);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花に、お水─？\\n…いりません', 1, 1, 2, 0, 1, 129601, 1, 8123);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日が高いうちは\\nむやみに外へ出ません\\n面倒事、多いので…', 1, 1, 2, 0, 2, 129601, 2, 8124);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜番。私がします\\nあまり眠らない\\n性質なので…', 1, 1, 2, 0, 3, 129601, 3, 8125);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ここなら根を張れる\\nかもしれません\\n…張りませんけど', 1, 1, 3, 0, 0, 129601, 2, 8127);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなにやわな体じゃ\\n身を守れませんよ─\\n…あ。生き物じゃ\\nないんですね', 1, 1, 3, 0, 0, 129601, 3, 8128);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花みたいに─\\nいい匂い、です', 1, 1, 3, 0, 0, 129601, 4, 8129);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('火を見てると、\\nジオ・ゲヘナを\\n思い出します…ふぅ', 1, 1, 3, 0, 0, 129601, 5, 8130);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食事も立派な戦支度\\n媛が言ってました', 1, 1, 3, 0, 0, 129601, 7, 8132);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('知識も武器の一つだと\\n媛が…でも、\\nこれでどうやって…？', 1, 1, 3, 0, 0, 129601, 8, 8133);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('天気もいいしお花畑に\\nピクニックでも\\n行こうかな♪', 1, 1, 1, 0, 0, 130701, 1, 8135);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、どこからか\\nお花の匂いが…\\nいい香りですね', 1, 1, 1, 0, 0, 130701, 2, 8136);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しいシャベルとか\\nじょうろもほしいなぁ\\nお小遣いしっかり\\nためないとね', 1, 1, 1, 0, 0, 130701, 3, 8137);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花飾りたいけど\\n花瓶はどこかな…\\nあとであの人に\\n聞いてみよっと', 1, 1, 1, 0, 0, 130701, 4, 8138);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花の観察日記\\n書かなきゃ\\n日々勉強は\\n欠かせませんよ', 1, 1, 1, 0, 0, 130701, 5, 8139);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('衣装にお花を足して\\nみたけど、あの人\\n気付いてくれるかな？', 4, 1, 1, 0, 0, 130701, 101, 8140);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この花冠、上手に\\n作れたかも…\\n日頃のお礼にあの人に\\nあげようかな…', 8, 1, 1, 0, 0, 130701, 102, 8141);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あなたは何のお花が\\n好きですか？\u3000ほら、\\n一応知っておいたら\\n役に立つかもですし', 1, 1, 2, 0, 0, 130701, 1, 8142);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そのお花、乱暴に\\n扱っちゃダメですよ\\n花粉が服について\\nとれなくなりますから', 1, 1, 2, 0, 0, 130701, 2, 8143);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('土いじりしたから\\n服が汚れてますよ\\nはたいてあげますから\\nじっとしててください', 1, 1, 2, 0, 0, 130701, 3, 8144);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そんなにすぐに芽は\\n出ませんよ\\nまあ、楽しみなのは\\n私も同じですけど…', 1, 1, 2, 0, 0, 130701, 4, 8145);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この衣装、そんなに\\n気になります？\u3000なら\\nこうしてお花を\\n着ければおそろいです', 4, 1, 2, 0, 0, 130701, 101, 8146);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花の種を私に？\\nありがとうございます\\nせっかくなので一緒に\\nお世話しませんか？', 8, 1, 2, 0, 0, 130701, 102, 8147);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花にお水をあげるの\\n手伝ってもらえます？\\nお水は朝にあげるのが\\nいいんですよ', 1, 1, 2, 0, 1, 130701, 1, 8148);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('とっておきのお花見\\nスポットに\\nご案内しますよ\\nお弁当も忘れずに！', 1, 1, 2, 0, 2, 130701, 2, 8149);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もうこんな時間\\n早く寝ましょう\\n草木も眠るなんとか\\nって言いますからね', 1, 1, 2, 0, 3, 130701, 3, 8150);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花のお手入れって\\nけっこう疲れますね…\\nここでちょっと一息\\nしちゃおっと', 1, 1, 3, 0, 0, 130701, 2, 8152);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('耳にお花を着ければ…\\nえへへ、すっごく\\nかわいくなったね！', 1, 1, 3, 0, 0, 130701, 3, 8153);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('これはラベンダー\\nこっちはミモザ\\nフローラル系の香り\\nっていいですねぇ', 1, 1, 3, 0, 0, 130701, 4, 8154);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ポカポカしますね～\\nまるで春の陽気\\nみたいです～', 1, 1, 3, 0, 0, 130701, 5, 8155);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花を一輪さすだけで\\nご飯の時間がとても\\n華やかになりますね', 1, 1, 3, 0, 0, 130701, 7, 8157);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お花の本が\\nいっぱいある！\\n今日はこれで\\nお勉強です！', 1, 1, 3, 0, 0, 130701, 8, 8158);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふんふ～ん♪\\n華やかな服を着ると\\n心がウキウキします♪', 1, 1, 1, 0, 0, 130801, 1, 8160);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花祭りで出会った\\nみなさん…\\nお元気でしょうか？\\nまたお会いしたいです', 1, 1, 1, 0, 0, 130801, 2, 8161);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はっ！\u3000そうでした\\nこの服の時は\\nメイドのお仕事は\\nお休みでした…', 1, 1, 1, 0, 0, 130801, 3, 8162);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服は替えが\\nありませんから\\n大きなドジには\\n気を付けないと…', 1, 1, 1, 0, 0, 130801, 4, 8163);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('目立ったほつれもなし\\n…うん、いい感じに\\n補修できました♪', 1, 1, 1, 0, 0, 130801, 5, 8164);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メイド姿でなくても\\n心はいつでも\\nお嬢さまの\\nメイドです♪', 4, 1, 1, 0, 0, 130801, 101, 8165);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この服を着ると心が\\n浮き立つのはあのかた\\nと一緒にいる気持ちに\\nなるからでしょうか？', 8, 1, 1, 0, 0, 130801, 102, 8166);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はい、今日は一日\\nこの服で過ごそうと\\n思います\\n変じゃないですよね？', 1, 1, 2, 0, 0, 130801, 1, 8167);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花祭りのおかげで\\n少しだけお花に\\n詳しくなった…\\nような気がします！', 1, 1, 2, 0, 0, 130801, 2, 8168);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花祭り、今度は\\nお嬢さまと救護院の\\nみんなと一緒に\\n行ってみたいですね', 1, 1, 2, 0, 0, 130801, 3, 8169);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今度キョウカちゃんと\\n花祭りの服でお花を\\n見にお出かけ\\nするんです', 1, 1, 2, 0, 0, 130801, 4, 8170);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('メイド服を全部洗濯\\nしちゃうなんて…\\nドジっちゃいましたぁ', 4, 1, 2, 0, 0, 130801, 101, 8171);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('花祭りの服は私たちの\\n思い出の服ですから…\\nこれからも\\n大切にします♪', 8, 1, 2, 0, 0, 130801, 102, 8172);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はう、そうでした\\nお花にお水を\\nあげる時間です！', 1, 1, 2, 0, 1, 130801, 1, 8173);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼ご飯は\\nバスケットを持って\\nお花畑に食べ\\nに行きませんか？', 1, 1, 2, 0, 2, 130801, 2, 8174);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふぁあ…繕い物を\\nしていたらこんな時間\\nになってしまいました\\n早く寝ないと…', 1, 1, 2, 0, 3, 130801, 3, 8175);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわふわしてて\\nきもちいいです～\\nどんな生地を\\nつかってるんだろ～？', 1, 1, 3, 0, 0, 130801, 2, 8177);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かわいいですね～\\nぬいぐるみさんにも\\n服をつくって\\nあげたいです♪', 1, 1, 3, 0, 0, 130801, 3, 8178);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りです～\\nあれ？\u3000もしかして\\n私の服についてる花と\\n同じ香りが…？', 1, 1, 3, 0, 0, 130801, 4, 8179);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暖かいですけど\\nあまり近づいちゃうと\\n頭の花飾りが乾燥\\nしちゃいそうですね…', 1, 1, 3, 0, 0, 130801, 5, 8180);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もぐもぐ…\\nいい花を咲かせるには\\nしっかりとした栄養が\\n必要だそうです！', 1, 1, 3, 0, 0, 130801, 7, 8182);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なるほどなるほど…\\nお花のお手入れは\\n奥が深いですね…', 1, 1, 3, 0, 0, 130801, 8, 8183);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('マホマホ王国にも\\nサーカス団設立や\\n夢と希望を届けますえ', 1, 1, 1, 0, 0, 131001, 1, 8185);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('せっかくの晴れ舞台や\\nかっこいいポーズも\\nできるようにしたいわ', 1, 1, 1, 0, 0, 131001, 2, 8186);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('むむむむ～っ。うーん\\nクルルはんみたいに\\n胸から宝石を出すんは\\n難しいみたいやわ', 1, 1, 1, 0, 0, 131001, 3, 8187);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あむっ…んん～♪\\nやっぱり練習のあとは\\n甘いものに限るわぁ', 1, 1, 1, 0, 0, 131001, 4, 8188);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アーサーたちの衣装も\\n今のうちに考えんと…\\n生地、足りるやろか', 1, 1, 1, 0, 0, 131001, 5, 8189);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はんとなら\\nどんなアイデアも\\n見つけられます♪', 4, 1, 1, 0, 0, 131001, 101, 8190);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うちの晴れ姿が\\n王子はんの目に一等\\n輝いて見えますように', 8, 1, 1, 0, 0, 131001, 102, 8191);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('キリっとしたうちも\\nかっこいい？\\nもう、上手やなぁ', 1, 1, 2, 0, 0, 131001, 1, 8192);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('新しい演目考えたんよ\\nなぁ王子はん、意見\\n聞かせてもらえます？', 1, 1, 2, 0, 0, 131001, 2, 8193);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('聞いてや王子はん\\n動物さんたちとさらに\\n息が合うてきたんよ\\nみんな頑張り屋さんや', 1, 1, 2, 0, 0, 131001, 3, 8194);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('演技の感想なら\\n大歓迎どすえ♪\\nたんと聞かせてや～', 1, 1, 2, 0, 0, 131001, 4, 8195);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('王子はん、本番当日は\\n最前席で見たってな\\nそしたらうち、もっと\\n頑張れますさかい♪', 4, 1, 2, 0, 0, 131001, 101, 8196);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この技をあなたに\\n捧げます…なんて♪\\n驚いたやろ？\\nどっきり作戦成功や♪', 8, 1, 2, 0, 0, 131001, 102, 8197);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('素敵なショーのためや\\n今日も焦らず一歩ずつ\\n成長していきまひょ\\nな、王子はん♪', 1, 1, 2, 0, 1, 131001, 1, 8198);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お弁当、王子はんも\\n一緒にいかがどす？\\nみんなで食べて団結や', 1, 1, 2, 0, 2, 131001, 2, 8199);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜のサーカスも\\n幻想的でとっても\\n魅力的なんよ\\n一緒にいきまひょか♪', 1, 1, 2, 0, 3, 131001, 3, 8200);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('練習が終わったあとは\\nの～んびりして\\n体力を回復せな…', 1, 1, 3, 0, 0, 131001, 2, 8202);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この子たちとなら\\n空中ブランコや\\n玉乗りもええなぁ', 1, 1, 3, 0, 0, 131001, 3, 8203);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りやなぁ\\n本番前の緊張も\\n和らげてくれそうやわ', 1, 1, 3, 0, 0, 131001, 4, 8204);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('このあったかい感じ…\\nスポットライトの熱を\\n思い出すわぁ', 1, 1, 3, 0, 0, 131001, 5, 8205);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ちゃんと食べへんと\\nいい演技はできまへん\\n団長はんも言うてたわ', 1, 1, 3, 0, 0, 131001, 7, 8207);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('動物さんたちのことも\\nもっと勉強せな\\n大事な仲間やさかい', 1, 1, 3, 0, 0, 131001, 8, 8208);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('器用じゃないが、\\n情には厚いよ\\nこういう女を「一途」\\nってそう言うんだろ？', 12, 1, 1, 0, 0, 105601, 103, 8210);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('斬れないものはないと\\n思ってきたさ。だけど\\n…この気持ちだけは\\n斬れないね、絶対に', 12, 1, 2, 0, 0, 105601, 103, 8211);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('んしょ、んしょっ…！\\n日頃の感謝を込めて\\nヒーローさんのお家を\\nきれいにしますです♪', 1, 1, 1, 0, 0, 130901, 1, 8212);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\n新アトラクションは\\nこのギルドハウスを\\nモチーフに…', 1, 1, 1, 0, 0, 130901, 2, 8213);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ごそごそ、こそこそ…\\nヒーローさんに内緒で\\nどこかにお礼の宝石を\\n隠しておきましょう…', 1, 1, 1, 0, 0, 130901, 3, 8214);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パークの運営が\\n落ち着いたら\\nわたしもギルド活動？\\nしてみたいですます♪', 1, 1, 1, 0, 0, 130901, 4, 8215);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こんなすてきな\\nおうちに住めたら…\\nいえ！\u3000うさぎ小屋で\\n十分です～っ', 1, 1, 1, 0, 0, 130901, 5, 8216);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさんのおうち\\nだって意識したら\\nアトラクションよりも\\nドキドキしてきます…', 4, 1, 1, 0, 0, 130901, 101, 8217);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさんのことを\\n考えると顔が赤く…\\nこれってもしかして\\nひょっとして…？', 8, 1, 1, 0, 0, 130901, 102, 8218);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あっ、ヒーローさん！\\n話しかけてくれた記念\\nということで、宝石\\n受け取ってください♪', 1, 1, 2, 0, 0, 130901, 1, 8219);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('元気がない時は\\n語尾にぴょんですっ！\\nさあヒーローさんも\\nやってみるぴょん♪', 1, 1, 2, 0, 0, 130901, 2, 8220);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさんへのご恩\\nおばあちゃんうさぎに\\nなるまでに、お返し\\nできるでしょうか…？', 1, 1, 2, 0, 0, 130901, 3, 8221);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさん！\\n二人で一緒に\\nパレードの練習\\nしませんか～♪', 1, 1, 2, 0, 0, 130901, 4, 8222);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あはは♪\\nヒーローさんは\\n人を笑顔にする力が\\nありますです♪', 4, 1, 2, 0, 0, 130901, 101, 8223);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさんに\\n一日一恩返しですっ！\\n返し終わるまで\\nやめませんですます♪', 8, 1, 2, 0, 0, 130901, 102, 8224);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おはようございます♪\\nんしょ、んしょっ…！\\n気持ちよく起きられた\\n記念に宝石どうぞ♪', 1, 1, 2, 0, 1, 130901, 1, 8225);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼にフードコートで\\nかばばん君バーガー\\n買ってきましたよ！\\n一緒に食べますです♪', 1, 1, 2, 0, 2, 130901, 2, 8226);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日も一日\\nお疲れさまですっ♪\\nマッサージしますから\\n寝そべってください♪', 1, 1, 2, 0, 3, 130901, 3, 8227);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はふぅ～…♪\\nお仕事の疲れも\\nぴょんぴょ～んって\\n飛んでっちゃいます♪', 1, 1, 3, 0, 0, 130901, 2, 8229);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わぁっ、とっても\\nかわいいですますっ！\\nギルドハウスの\\nマスコットですね♪', 1, 1, 3, 0, 0, 130901, 3, 8230);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒーローさんの好きな\\n香り…これを宝石に\\nつければ、受け取って\\nもらえるでしょうか？', 1, 1, 3, 0, 0, 130901, 4, 8231);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はあ、気持ちいい♪\\nヒーローさんの\\n好きな温度に\\n調整しときますです♪', 1, 1, 3, 0, 0, 130901, 5, 8232);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('支配人は体が資本っ！\\nたくさん食べ…すぎて\\n動けなくなっちゃい\\nましたぁ～…！', 1, 1, 3, 0, 0, 130901, 7, 8234);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('パークの\\nガイドブックとか\\nあったらいいですね♪', 1, 1, 3, 0, 0, 130901, 8, 8235);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('外あつすぎ溶けるわ～\\nやっぱ部屋ん中で\\n水着がラクだねー', 1, 1, 1, 0, 0, 131101, 1, 8237);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ン～\\nカリザきゅんどこー？\\nもしかして逃げた？', 1, 1, 1, 0, 0, 131101, 2, 8238);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソラちゃんと\\nリリちゃん誘って\\nそろそろイイコト\\nしよっかなー？', 1, 1, 1, 0, 0, 131101, 3, 8239);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おねえちゃんに\\n頼まれたシゴトは\\nまた今度にすっかー\\n夏休みだしー♪', 1, 1, 1, 0, 0, 131101, 4, 8240);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士きゅんの\\nプリンセスフォームも\\n見てみたいんだよなー\\nンフ♡', 1, 1, 1, 0, 0, 131101, 5, 8241);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スライムを\\nこーしてあーしたら\\n騎士きゅんの泳ぐ\\n練習に使えるっぽ？', 4, 1, 1, 0, 0, 131101, 101, 8242);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('おかえり～♡\\nって水着で迎えたら\\n騎士きゅん喜んで\\nくれるかなー？', 8, 1, 1, 0, 0, 131101, 102, 8243);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士きゅん\\nこのサングラス\\nかけてみる？\\nぜってー似合うよー', 1, 1, 2, 0, 0, 131101, 1, 8244);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日焼け痛かったら\\nいつでも言ってねー\\nスライムでひんやり\\nしてあげるよ～♪', 1, 1, 2, 0, 0, 131101, 2, 8245);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今から外で\\n焼いてこっかなー\\n騎士きゅんもどー？', 1, 1, 2, 0, 0, 131101, 3, 8246);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スライムマッサージ\\nしてあげよっかー\\nほーれ、もみもみ～♡', 1, 1, 2, 0, 0, 131101, 4, 8247);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士きゅんが選んだ\\n水着も着てみたーい\\nネアおねえちゃんに\\nどんなの着てほしい？', 4, 1, 2, 0, 0, 131101, 101, 8248);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士きゅ～ん\\n尻相撲しよっかー♪\\nおねえちゃんに\\n勝てたらご褒美だぞ～', 8, 1, 2, 0, 0, 131101, 102, 8249);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑すぎてムダに\\n早起きしちった～\\n二度寝すっか～\\n…ふぁあ…', 1, 1, 2, 0, 1, 131101, 1, 8250);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏バテしても\\nスイカとかかき氷なら\\n全然ウェルカム\\nなんだよなー', 1, 1, 2, 0, 2, 131101, 2, 8251);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はこのまま\\n水着で寝るかー\\n夢ん中で泳ごー', 1, 1, 2, 0, 3, 131101, 3, 8252);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いったんキューケイ…\\nンー…よし\\n充電カンリョ～♪', 1, 1, 3, 0, 0, 131101, 2, 8254);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('仲間になりたそうに\\nこっち見てんねー\\nきゃわいいしおっけ～', 1, 1, 3, 0, 0, 131101, 3, 8255);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ン～いいニオーイ\\nお日様あたった\\n騎士きゅんの\\n次くらいかな～', 1, 1, 3, 0, 0, 131101, 4, 8256);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('カラダ冷えてきたから\\nたすかるーおかげで\\nまだまだ水着イケるわ', 1, 1, 3, 0, 0, 131101, 5, 8257);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('うめ～\\nとまんねぇ～\\n夏バテどこいった～？', 1, 1, 3, 0, 0, 131101, 7, 8259);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふむふむ…\\nこれは意外と\\nぬるっと読めるっぽー', 1, 1, 3, 0, 0, 131101, 8, 8260);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ンフフ～\\n海の戦士ってカンジ？\\nアリよりのアリだね～', 1, 1, 3, 0, 0, 131101, 10, 8262);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あーやべ\\n一瞬で寝そー\\nヤバだわ～', 1, 1, 3, 0, 0, 131101, 11, 8263);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('服や紙が易々と\\n燃えぬとは\\nランドソルとはまこと\\n住み易き国で候', 1, 1, 1, 0, 0, 129701, 1, 8264);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('どの世界にあっても\\n民は活力に溢れ\\n街は賑わうもの…\\n善哉、善哉', 1, 1, 1, 0, 0, 129701, 2, 8265);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('食べ歩きに世界征服…\\nギルドとはかくも\\n自由気儘な徒党に\\nありんすなぁ', 1, 1, 1, 0, 0, 129701, 3, 8266);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('連絡は…今日もなし\\n我が妹子は相変わらず\\n放埓なことよ喃', 1, 1, 1, 0, 0, 129701, 4, 8267);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('モネは相変わらず\\n警戒しきりなれど…\\nそのようなところも\\n愛らしくあり申す', 1, 1, 1, 0, 0, 129701, 5, 8268);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんと長閑な世にや\\nありけむ…この平和は\\n騎士殿たちの努力の\\n賜物にありんす喃', 4, 1, 1, 0, 0, 129701, 101, 8269);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('『王家の装備』は\\n使わぬのかと？\\n…フフ。すでに\\n用いており申す', 8, 1, 1, 0, 0, 129701, 102, 8270);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今ばかりは媛という\\n立場は置いて\\nこの地の者らと\\n歓談したく候', 1, 1, 2, 0, 0, 129701, 1, 8271);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強さの秘密？\u3000…フフ\\n女子の秘密を暴くのは\\n野暮にござんす\\nご寛恕いただきたく候', 1, 1, 2, 0, 0, 129701, 2, 8272);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('此方の家屋、\\n見目以上に\\n堅牢であり申す\\n何ぞ仕掛けがありや？', 1, 1, 2, 0, 0, 129701, 3, 8273);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('心地よい時間とは\\n疾く過ぎ去りゆくもの\\n此処で過ごすと改めて\\n実感できる喃', 1, 1, 2, 0, 0, 129701, 4, 8274);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('視線が気になる？\\nこれはすみませぬ\\nなにぶん、お前さまは\\n見ていて飽きませぬ故', 4, 1, 2, 0, 0, 129701, 101, 8275);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お前さまの前では\\n誰もが心を開く…\\nなんとまぁ罪作りな\\n色男にありんすな？', 8, 1, 2, 0, 0, 129701, 102, 8276);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よく眠れましたかの？\\n寝る子は良く育つ、と\\n古くより申します由', 1, 1, 2, 0, 1, 129701, 1, 8277);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美食殿の作法に倣い\\n皆で共に昼餉を頂くと\\n致しんしょう', 1, 1, 2, 0, 2, 129701, 2, 8278);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('逢魔ヶ時は望まぬ客も\\n参るもの…お前さまも\\n気をつけなんし', 1, 1, 2, 0, 3, 129701, 3, 8279);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わっちの蛇に\\n勝るとも劣らぬ\\n座り心地で候', 1, 1, 3, 0, 0, 129701, 2, 8281);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('魂、万物に宿る\\nとの云いあらば\\n情愛を注いでやるのが\\nよかろうの', 1, 1, 3, 0, 0, 129701, 3, 8282);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いと香しき哉…\\n騎士殿は香の道にも\\n詳しくあられるか', 1, 1, 3, 0, 0, 129701, 4, 8283);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ジオ・ゲヘナの\\n灼熱と比ぶれば\\nそよ風と変わり\\nござんせん', 1, 1, 3, 0, 0, 129701, 5, 8284);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('美味なる哉…この味\\nぺコリーヌ姫が好むも\\n道理にありんす', 1, 1, 3, 0, 0, 129701, 7, 8286);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トーゴクに、オーマ…\\n書で見るだけでも\\n心惹かれる土地よの', 1, 1, 3, 0, 0, 129701, 8, 8287);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('暑い日には\\n冷たいものですよねー\\nかき氷とか食べて\\nすっきりしたいです★', 1, 1, 1, 0, 0, 131201, 1, 8289);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海への行き来は\\nテレポーテーションに\\nお任せです★', 1, 1, 1, 0, 0, 131201, 2, 8290);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('トロピカルジュースが\\n飲みたいでーす♪\\n海の家で見たんですよ\\nカップル用ジュース★', 1, 1, 1, 0, 0, 131201, 3, 8291);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ご飯どうしようかなー\\nあ、海鮮ラーメンとか\\n美味しそうかも★', 1, 1, 1, 0, 0, 131201, 4, 8292);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水鉄砲、普通に撃つと\\n少し物足りないかも…\\nどるるるる～ん★って\\n感じが欲しいですよね', 1, 1, 1, 0, 0, 131201, 5, 8293);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('コイビトっぽいこと\\nアオハルっぽいこと\\nいっぱいしたいです★\\n修羅場とかも♪', 4, 1, 1, 0, 0, 131201, 101, 8294);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さんが溺れたら\\n絶対助けに行きますね\\n人工呼吸でもなんでも\\nしてあげますから★', 8, 1, 1, 0, 0, 131201, 102, 8295);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('騎士さーん\\n日焼け止めの塗り直し\\nお願いします★\\n優しくしてくださいね', 1, 1, 2, 0, 0, 131201, 1, 8296);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海で食べたフルーツ？\\nはい、まだありますよ\\nこっちでもあーんして\\n食べさせましょうか★', 1, 1, 2, 0, 0, 131201, 2, 8297);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ぺんぽこりんは\\nどうしたのかって？\\nどうしたんでしょうね\\nどーでもいいです★', 1, 1, 2, 0, 0, 131201, 3, 8298);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今日はどんな\\nイイコトしましょうか\\n思い出作り？\\n人助けもいいですね★', 1, 1, 2, 0, 0, 131201, 4, 8299);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ヒモを引っ張ったら…\\n「セ・キ・ニ・ン」\\n取ってもらいますよ？\\nなーんてウソですけど', 4, 1, 2, 0, 0, 131201, 101, 8300);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('みんなでイイコトも\\n楽しいですけど～\\n…二人でイイコト\\nしちゃいますか？', 8, 1, 2, 0, 0, 131201, 102, 8301);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('朝ですよー！\\n今日も一日、\\nイイコト日和ですね♪', 1, 1, 2, 0, 1, 131201, 1, 8302);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('日差しにご注意ですね\\n日焼け止め…誰かに\\n塗ってほしいなー？\\n…ちらっ★', 1, 1, 2, 0, 2, 131201, 2, 8303);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜の海って\\n惹かれちゃいますよね\\n…ロマンチックです★', 1, 1, 2, 0, 3, 131201, 3, 8304);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('う～ん、まったり～\\nこれぞ新ジャンル\\nおうちバカンス★', 1, 1, 3, 0, 0, 131201, 2, 8306);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('よーしよーし★\\nわたしとイイコト\\n一緒にしましょうねー', 1, 1, 3, 0, 0, 131201, 3, 8307);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('いい香りですねー\\nリラックスタイムに\\nちょうどよさそう★', 1, 1, 3, 0, 0, 131201, 4, 8308);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水遊びのあとは\\nしっかり体を\\n温めないとですよね★', 1, 1, 3, 0, 0, 131201, 5, 8309);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('栄養補給もバッチリ★\\n遊びもイイコトも\\nお腹が減ってたら\\nできませんからねー？', 1, 1, 3, 0, 0, 131201, 7, 8311);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('今だと海関連の本とか\\n興味あるんですよねー\\n魚とか海難救助とか★', 1, 1, 3, 0, 0, 131201, 8, 8312);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('かっこいー★\\n名前はー…\\nぷんぷくぽんとか？', 1, 1, 3, 0, 0, 131201, 10, 8314);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('映えますねー\\n写真撮ったら\\n素敵な思い出に\\nなりそうです★', 1, 1, 3, 0, 0, 131201, 11, 8315);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海でもないのに\\nこの姿でいるのは…\\nやはり、場違いでは\\nありませんか…？', 1, 1, 1, 0, 0, 131601, 1, 8316);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('スイカとは割ることと\\n見つけたり！\\n…ですが目隠しすれば\\n見当たらないもの…', 1, 1, 1, 0, 0, 131601, 2, 8317);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まぁ、膝に砂が…\\n気がつきませんでした\\nまるでわんぱくな\\nお子様のよう…ふふっ', 1, 1, 1, 0, 0, 131601, 3, 8318);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('家の中でスイカを割る\\nわけにはまいりません\\nここは潔く包丁で\\n切りましょう', 1, 1, 1, 0, 0, 131601, 4, 8319);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ミソラ様やネア様の\\n大胆さを見習って…\\nき、騎士きゅーん…★\\n難しいですね…', 1, 1, 1, 0, 0, 131601, 5, 8320);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('きゅ、急に暗く…！？\\n…失礼しました\\n鉢巻きが下がってきた\\nだけでした…ううぅ', 4, 1, 1, 0, 0, 131601, 101, 8321);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('わたくしに剣の才は\\nあるのでしょうか…\\nいえ、何事もまずは\\nやってみなくては', 8, 1, 1, 0, 0, 131601, 102, 8322);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なにか羽織った方が\\nよろしいですよね…？\\nそのままでいい？\\nそれはそれで…その…', 1, 1, 2, 0, 0, 131601, 1, 8323);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あの、兄様…？\\nスイカの種を飛ばす\\n遊びもあるというのは\\n…本当なのでしょうか', 1, 1, 2, 0, 0, 131601, 2, 8324);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('強くなるための修行は\\nまだ始まったばかり\\nまずは己の目指すべき\\n道を見定めなくては', 1, 1, 2, 0, 0, 131601, 3, 8325);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('同じ薄着であっても\\n黒い天使の姿より…\\n気が楽です', 1, 1, 2, 0, 0, 131601, 4, 8326);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はい、ただいまー！\\n…あっ！\\n海の家でのお手伝いの\\nくせが、つい…', 4, 1, 2, 0, 0, 131601, 101, 8327);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様さえよろしければ\\nまた一緒に海へ…\\nあ…申し訳ありません\\n浮ついてしまいました', 8, 1, 2, 0, 0, 131601, 102, 8328);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('本日もイイコトをして\\n清々しい一日を\\n過ごしたいものです\\nまさに一日一善ですね', 1, 1, 2, 0, 1, 131601, 1, 8329);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼時になると\\n海の家の料理を\\n思い出してしまいます\\n焼きそばにかき氷…♪', 1, 1, 2, 0, 2, 131601, 2, 8330);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('兄様…よろしければ\\n浜辺を歩きませんか？\\nきっと、月が\\nきれいでしょうから', 1, 1, 2, 0, 3, 131601, 3, 8331);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ふわふわ心地よすぎて\\n眠くなってしまいます\\n水着姿では\\nいけません…ふぁ…', 1, 1, 3, 0, 0, 131601, 2, 8333);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('なんてよい手触り…\\n癖になってしまいます\\nふふ、よしよし…♪', 1, 1, 3, 0, 0, 131601, 3, 8334);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('爽やかな香り…♪\\n日焼け止めクリームを\\n思い出してしまいます', 1, 1, 3, 0, 0, 131601, 4, 8335);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('冷たい水で冷えた体が\\n温まります…♪\\nまるで兄様のようです', 1, 1, 3, 0, 0, 131601, 5, 8336);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お腹が空いては\\n修行ができません…！\\n動きに障りない程度に\\n栄養の補給を…！', 1, 1, 3, 0, 0, 131601, 7, 8338);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('剣術とスイカ割りが\\n上達する指南書…\\n見つかりませんね…', 1, 1, 3, 0, 0, 131601, 8, 8339);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('さあ、ともに大海原を\\n参りましょう！\\nなんて…ふふっ♪', 1, 1, 3, 0, 0, 131601, 10, 8341);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('まるでおとぎ話の\\n登場人物になった\\nような心持ちです…♪', 1, 1, 3, 0, 0, 131601, 11, 8342);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あたしはなんで水着で\\n室内をうろついてるの\\nかしら…不思議だわ', 1, 1, 1, 0, 0, 131701, 1, 8343);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あ、天井が汚れてる\\n仕方ないわね\\nひとっ飛びしますか', 1, 1, 1, 0, 0, 131701, 2, 8344);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('はい、お疲れさま♪\\n出迎えの言葉は\\nやっぱこれよね♪', 1, 1, 1, 0, 0, 131701, 3, 8345);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('そういえばあたしって\\n羽があるけど\\n泳げるのかしら…', 1, 1, 1, 0, 0, 131701, 4, 8346);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あいつのために\\n浮き輪も用意したし\\n抜かりはないわよ', 1, 1, 1, 0, 0, 131701, 5, 8347);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('海までのガイド計画も\\nまとまったわね\\nふふっ…楽しみだわ', 4, 1, 1, 0, 0, 131701, 101, 8348);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('この水着、あいつが\\n選んでくれたのよね\\n…大事にしないと', 8, 1, 1, 0, 0, 131701, 102, 8349);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('ネビアは最近どう？\\n迷惑かけてない？\\n…かけてるのね', 1, 1, 2, 0, 0, 131701, 1, 8350);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんた…部屋の片付け\\nくらい自分でしなさい\\n散らかってたわよ？\\n…片付けておいたけど', 1, 1, 2, 0, 0, 131701, 2, 8351);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('もしかして暇なの？\\nだったら記憶でも\\n見せましょうか？\\n凄く恥ずかしいやつ♪', 1, 1, 2, 0, 0, 131701, 3, 8352);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夏ってこんなに\\n暑いのね…\\n海にばかり行く\\n気持ちが分かったわ', 1, 1, 2, 0, 0, 131701, 4, 8353);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたの水着って\\n新しいの買わないの？\\nなんならあたしが\\n選んであげるわよ♪', 4, 1, 2, 0, 0, 131701, 101, 8354);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('気軽に触れ合える\\n距離にいる…\\nあたしにとって\\nとても大事なことよ', 8, 1, 2, 0, 0, 131701, 102, 8355);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あらおはよう\\n夏の朝は暑いわね\\nシャワーでも浴びて\\nさっぱりしなさい', 1, 1, 2, 0, 1, 131701, 1, 8356);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('お昼は何を食べるの？\\nガイド妖精として\\n提案しましょうか？', 1, 1, 2, 0, 2, 131701, 2, 8357);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('夜更かしは厳禁よ\\n無理やり眠らせて\\nあげましょうか？', 1, 1, 2, 0, 3, 131701, 3, 8358);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('アメスさまだって\\nゴロゴロするときは\\nあるのよ～', 1, 1, 3, 0, 0, 131701, 2, 8360);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('…ふふっ♪\\n何よ、あたしが\\nかわいいものを\\n愛でちゃだめなの？', 1, 1, 3, 0, 0, 131701, 3, 8361);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('こういういい香り…\\n塔の中じゃなかなか\\n楽しめないのよね', 1, 1, 3, 0, 0, 131701, 4, 8362);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('水着を着てるのに\\n温まるのって\\n矛盾してない？\\n気にしすぎかしら', 1, 1, 3, 0, 0, 131701, 5, 8363);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('あんたと行動するなら\\n沢山食べられるように\\nならなきゃね…！', 1, 1, 3, 0, 0, 131701, 7, 8365);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('文字を読むのと\\nデータを読むのは\\nまったく違うわ', 1, 1, 3, 0, 0, 131701, 8, 8366);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('へぇ、面白いじゃない\\nこういう経験、昔じゃ\\nできなかったわ', 1, 1, 3, 0, 0, 131701, 10, 8368);
insert into v1_020bd759390adf334c8839c050d449f884f97e100e3725b5c0ab996aba8f10ce values ('面白いクッションね\\nところであんた…\\nあたしで遊んでない？\\n気のせいならいいけど', 1, 1, 3, 0, 0, 131701, 11, 8369);
